/// File holding the current in-progress flight, written on flight_start and
/// removed on flight_end / flight_cancel. Lets us resume after a client crash.
const ACTIVE_FLIGHT_FILE: &str = "active_flight.json";
/// Persisted activity-log dump — survives app restarts so the pilot
/// sees the full flight history when they re-open Tauri mid-flight.
/// Capped at `ACTIVITY_LOG_CAPACITY` entries (same as in-memory).
const ACTIVITY_LOG_FILE: &str = "activity_log.json";

/// Anything older than this is considered stale and discarded on resume.
const RESUME_MAX_AGE_HOURS: i64 = 12;

/// Phase-dependent position-post cadence. Ground manoeuvres (taxi, takeoff,
/// landing rollout) and the approach are where pilots want a precise trail
/// on the live map; cruise is straight-and-level so a sparse sample is fine
/// and saves API budget. Spec §10 ("configurable intervals") — these are
/// the defaults; a future settings panel can override.
/// v0.5.21: MQTT live-tracking publish interval. Constant 3 s
/// regardless of phase — gives the live-tracking server 10x more
/// position points in cruise (was 30 s) for smoother live maps and
/// finer post-flight analytics. Decoupled from phpVMS POST cadence
/// (which stays phase-aware via `position_interval`) so the phpVMS
/// DB doesn't get hammered.
///
/// Per-pilot bandwidth at 3 s: ~1.3 MB/h with WSS+TLS overhead;
/// for a 5 h flight that's less than 1 minute of YouTube traffic.
/// VPS handles it trivially even with 200 concurrent pilots.
const MQTT_PUBLISH_INTERVAL_SECS: u64 = 3;

/// v0.5.35: Adaptive Tick-Cadence. Standardmäßig 3s, aber im
/// Approach/Final/Landing/Takeoff schneller — sonst verfehlt das
/// Sampling den Touchdown bei langsamen GA-Flugzeugen.
///
/// v0.5.45: Schwellen verschoben damit der mittlere Approach
/// (1000-2000 ft AGL) nicht mehr auf 3s default faellt. Volanta/DLHv
/// messen konstant bei 1 Hz oder hoeher — bei -800 fpm und 3s
/// Lücke verlieren wir 42 ft Δ AGL zwischen Samples (User-Report
/// DLH 1731 / CFG 9746 LDZA→EDDM, Sample-Cadence 3.5s im Final).
///
/// Neue Skala:
///   AGL <100 ft   → 500 ms (2 Hz)   — Flare / Wheels-Up
///   AGL <500 ft   → 750 ms (1.3 Hz) — kurz vor TD
///   AGL <1500 ft  → 1000 ms (1 Hz)  — Final-Approach (war: 1000-500ft = 1s)
///   AGL <2000 ft  → 1500 ms         — kurz vor Final
///   sonst         → 3000 ms (default)
fn adaptive_tick_interval(phase: FlightPhase, agl_ft: Option<f64>) -> Duration {
    if let (Some(agl), true) = (
        agl_ft,
        matches!(
            phase,
            FlightPhase::Approach
                | FlightPhase::Final
                | FlightPhase::Landing
                | FlightPhase::Takeoff
                | FlightPhase::TakeoffRoll
        ),
    ) {
        if agl < 100.0 {
            return Duration::from_millis(500); // 2 Hz im Flare / Wheels-Up
        }
        if agl < 500.0 {
            return Duration::from_millis(750); // 1.3 Hz kurz vor TD
        }
        if agl < 1500.0 {
            return Duration::from_secs(1); // 1 Hz im Final-Approach
        }
        if agl < 2000.0 {
            return Duration::from_millis(1500); // 0.67 Hz im spaeten Approach
        }
    }
    Duration::from_secs(MQTT_PUBLISH_INTERVAL_SECS)
}

/// v0.5.x/v0.6.1 — phase-aware POST-Cadence an phpVMS.
///
/// **Wichtig:** Die *Streamer-Tick*-Cadence ist seit v0.6.0 davon
/// entkoppelt — der Streamer tickt adaptiv nach AGL (500ms-3s) und
/// pusht jede Position in die Memory-Outbox. Diese Funktion steuert
/// nur wie oft der **phpVMS-Worker** seine gepufferten Positions als
/// Batch an phpVMS abliefert.
///
/// Warum phase-aware: im Cruise ist 1 POST alle 30s genug (langer
/// gerader Leg, sparse samples reichen für die Live-Map). Im Pushback
/// muss alle 4s gepostet werden weil die Phase in 8-15s vorbei sein
/// kann — sonst springt das Dashboard direkt von Boarding auf Taxi
/// ohne Pushback-Snapshot. Im Approach/Final 8s damit der inbound-
/// Track präzise ist.
fn position_interval(phase: FlightPhase) -> Duration {
    let secs = match phase {
        // Brief, critical events — sample a touch faster so the touchdown
        // point and the actual liftoff don't get smeared between two posts.
        FlightPhase::Takeoff | FlightPhase::Landing => 5,
        // Boarding + Pushback need fast ticks because a real pushback
        // can be over in 8–15 s; if the streamer only fires every 10 s
        // we miss the entire phase between two snapshots and the
        // dashboard jumps straight from Boarding to Taxi.
        FlightPhase::Boarding | FlightPhase::Pushback => 4,
        // On the ground (taxi, takeoff roll) — 10 s is plenty;
        // movements are slow and the live map just needs a clean trail.
        FlightPhase::TaxiOut | FlightPhase::TakeoffRoll | FlightPhase::TaxiIn => 10,
        // Approach / final — pilot wants the inbound track precise (ILS,
        // localizer, glideslope) without overdoing samples.
        FlightPhase::Approach | FlightPhase::Final => 8,
        // Climb / descent: moderate change rate.
        FlightPhase::Climb | FlightPhase::Descent => 10,
        // Cruise: long straight legs, sparse samples are enough.
        // v0.13.8: 30s -> 60s. Eine halbe Stunde Cruise erzeugte vorher
        // ~60 Positions, jetzt ~30 — phpVMS-PIREP-Render-Performance
        // war ein realer Pilot-Befund. Live-Map zeigt jetzt Updates
        // alle 60s im Cruise; bei 480kt GS sind das ~8 nm zwischen
        // Punkten, fuer den Strack-Verlauf voellig ausreichend. VPS-
        // Recorder bekommt weiterhin alle Snapshots (separater MQTT-
        // Stream), nur phpVMS sieht die ausgedünnte Variante.
        FlightPhase::Cruise => 60,
        // v0.5.11: Holding — same cadence as Cruise (slow track update,
        // we're circling at constant altitude).
        FlightPhase::Holding => 60,
        // Parked / pre-/post-flight — keep a 30 s heartbeat so phpVMS
        // sees the PIREP is alive while the pilot files.
        FlightPhase::Preflight
        | FlightPhase::BlocksOn
        | FlightPhase::Arrived
        | FlightPhase::PirepSubmitted => 30,
    };
    Duration::from_secs(secs)
}

/// Minimum great-circle distance between two consecutive samples before we
/// add it to the running total. Filters out GPS jitter while parked.
const DISTANCE_EPSILON_M: f64 = 5.0;

/// v0.12.1 (Stream A LE1): minimum real position displacement (metres)
/// from the Boarding reference point before the Boarding→Pushback/TaxiOut
/// transition may fire. A sim-reload velocity glitch can spike
/// `groundspeed_kt` but cannot move `lat`/`lon` — so genuine displacement
/// is the trustworthy signal. 5 m is small enough not to delay a real
/// pushback, large enough to clear GPS jitter (< 1 m parked).
const MIN_BOARDING_MOVEMENT_M: f64 = 5.0;

/// v0.12.1 (Stream A LE2): a gap between two processed `step_flight`
/// snapshots longer than `RELOAD_GAP_FACTOR × position_interval(phase)`
/// is treated as a sim reload/reposition — the first snapshot after the
/// gap carries glitch-prone velocity values and must not drive a
/// velocity-derived phase transition.
const RELOAD_GAP_FACTOR: f64 = 2.5;

/// v0.12.1 (Stream A LE2): true if `gap_secs` between two processed
/// snapshots is long enough to count as a sim reload/reposition.
fn is_reload_gap(gap_secs: f64, interval_secs: f64) -> bool {
    gap_secs > RELOAD_GAP_FACTOR * interval_secs
}

/// v0.12.1 (Stream A LE2): the Pushback→TaxiOut "powered taxi" signal.
/// Gated by `!reload_gap_suspect` so a sim-reload glitch tick (which can
/// spike `groundspeed_kt`) cannot drive the velocity-derived TaxiOut
/// transition — same rule the Boarding branch already applies.
///
/// v0.15.13: zusätzlich VORWÄRTS-Bedingung (`velocity_body_z_fps`). Beim
/// Pushback startet der Pilot häufig die Triebwerke MITTEN im Schieben — die
/// alte Bedingung (Triebwerk + gs>3) flippte dann sofort auf TaxiOut, obwohl
/// der Tug noch RÜCKWÄRTS schob (Live-Log BTX2222: Pushback nur 7 s statt
/// ~78 s, weil das Triebwerk bei vbz=−6,5 ansprang). Solange vbz rückwärts/≈0
/// ist, bleibt es Pushback. Liefert der Sim kein vbz (`None`), gilt das alte
/// Verhalten (sonst blieben solche Aircraft für immer in Pushback hängen).
fn powered_taxi_move(
    reload_gap_suspect: bool,
    on_ground: bool,
    engines_running: bool,
    groundspeed_kt: f32,
    velocity_body_z_fps: Option<f32>,
) -> bool {
    !reload_gap_suspect
        && on_ground
        && engines_running
        && groundspeed_kt > 3.0
        && moving_forward(velocity_body_z_fps)
}

/// v0.12.1 (Stream A LE1): pure decision for the Boarding→Pushback/TaxiOut
/// trigger. Real movement = on the surface, groundspeed over threshold
/// for two consecutive ticks (de-bounce), AND genuine position
/// displacement past `MIN_BOARDING_MOVEMENT_M`. A velocity glitch can
/// satisfy the speed checks but never the displacement one.
fn boarding_real_movement(
    on_surface: bool,
    gs_over_threshold: bool,
    prev_gs_over_threshold: bool,
    moved_m: f64,
) -> bool {
    on_surface
        && gs_over_threshold
        && prev_gs_over_threshold
        && moved_m > MIN_BOARDING_MOVEMENT_M
}

/// v0.15.13: Schwelle (fps) ab der die körperfeste Längs-Geschwindigkeit
/// `velocity_body_z_fps` als klare Vorwärts-/Rückwärtsbewegung zählt (Rauschen
/// am Stand liegt darunter). >0 = vorwärts, <0 = rückwärts. Bestätigt am Live-
/// Log BTX2222 (X-Plane/ToLiss): −6,5 fps beim Tug-Push, +9..+14 fps beim
/// Vorwärts-Taxi, |vbz| ≈ Groundspeed über ALLE Heading-Werte (= körperfest,
/// nicht erdfest). MSFS „VELOCITY BODY Z" ist ohnehin körperfest, vorwärts +.
const TAXI_DIRECTION_FPS: f32 = 1.0;

/// Bewegt sich das Flugzeug RÜCKWÄRTS (Tug-Pushback)? `None` (Sim liefert kein
/// vbz) → `false` (unbekannt nicht als Rückwärts werten).
fn moving_backward(velocity_body_z_fps: Option<f32>) -> bool {
    matches!(velocity_body_z_fps, Some(v) if v < -TAXI_DIRECTION_FPS)
}

/// Bewegt sich das Flugzeug klar VORWÄRTS? `None` → `true` (kein vbz → altes
/// Verhalten beibehalten, damit Sims/Aircraft ohne diesen Wert nicht in
/// Pushback hängen bleiben).
fn moving_forward(velocity_body_z_fps: Option<f32>) -> bool {
    match velocity_body_z_fps {
        Some(v) => v > TAXI_DIRECTION_FPS,
        None => true,
    }
}

#[cfg(test)]
mod v0_15_13_pushback_direction_tests {
    use super::{moving_backward, moving_forward, powered_taxi_move};

    #[test]
    fn vbz_direction_classification() {
        assert!(moving_backward(Some(-6.5))); // Tug schiebt rückwärts
        assert!(!moving_backward(Some(9.4))); // Vorwärts-Taxi
        assert!(!moving_backward(Some(0.0))); // Stand
        assert!(!moving_backward(None)); // unbekannt → nicht rückwärts
        assert!(moving_forward(Some(9.4)));
        assert!(!moving_forward(Some(-6.5)));
        assert!(!moving_forward(Some(0.0)));
        assert!(moving_forward(None)); // Fallback: altes Verhalten
    }

    #[test]
    fn powered_taxi_stays_pushback_while_rolling_backward() {
        // BTX2222: Triebwerk startet beim Schieben, gs=3.9, vbz=-6.52 → KEIN Taxi.
        assert!(!powered_taxi_move(false, true, true, 3.9, Some(-6.52)));
    }

    #[test]
    fn powered_taxi_fires_on_genuine_forward_roll() {
        // echtes Vorwärts-Taxi: gs=5.6, vbz=+9.44, Triebwerke an → TaxiOut.
        assert!(powered_taxi_move(false, true, true, 5.6, Some(9.44)));
    }

    #[test]
    fn powered_taxi_falls_back_when_no_vbz() {
        // Sim ohne vbz → altes Verhalten (Triebwerk + gs>3 reicht).
        assert!(powered_taxi_move(false, true, true, 5.0, None));
    }

    #[test]
    fn powered_taxi_needs_engines_speed_and_ground() {
        assert!(!powered_taxi_move(false, true, false, 5.0, Some(9.0))); // Triebwerke aus
        assert!(!powered_taxi_move(false, true, true, 2.0, Some(9.0))); // zu langsam
        assert!(!powered_taxi_move(true, true, true, 5.0, Some(9.0))); // reload glitch
        assert!(!powered_taxi_move(false, false, true, 5.0, Some(9.0))); // nicht am Boden
    }
}

/// v0.12.1 (Stream E LE14): does the first post-resume sim position look
/// like a glitchy crash-reload rather than the flight we persisted?
/// Suspicious when:
///   1. the persisted phase was airborne but the sim now reports on-ground
///      (classic sim-crash → reload-on-a-runway), OR
///   2. the sim position is implausibly far from the last known position.
/// A separate altitude-delta condition was deliberately dropped (QS-R5):
/// a pilot legitimately restarting the app mid-climb/descent would almost
/// always show an altitude delta — too restrictive.
fn is_resume_position_suspect(
    persisted_phase: FlightPhase,
    persisted_pos: Option<(f64, f64)>,
    snap_on_ground: bool,
    snap_lat: f64,
    snap_lon: f64,
) -> bool {
    let persisted_airborne = matches!(
        persisted_phase,
        FlightPhase::Climb
            | FlightPhase::Cruise
            | FlightPhase::Holding
            | FlightPhase::Descent
            | FlightPhase::Approach
            | FlightPhase::Final
    );
    if persisted_airborne && snap_on_ground {
        return true;
    }
    if let Some((plat, plon)) = persisted_pos {
        let drift_nm = ::geo::distance_m(plat, plon, snap_lat, snap_lon) / 1852.0;
        if drift_nm > RESUME_DRIFT_WARN_NM {
            return true;
        }
    }
    false
}

/// v0.13.9 Stream F (LE27): Mid-Session Sim-Crash-Recovery Detection.
///
/// Pure Funktion — verglich zwei aufeinanderfolgende Snapshots im Streamer-
/// Tick und gibt `true` zurueck wenn die Kombination ein Sim-Reload-Artefakt
/// anzeigt:
///
/// 1. Aktuelle FlightPhase ist airborne-Set (Climb/Cruise/Holding/
///    Descent/Approach/Final).
/// 2. Vorheriger Snapshot war `on_ground=false`.
/// 3. Neuer Snapshot ist `on_ground=true`.
/// 4. |Altitude-Differenz| > Schwelle (default 5000 ft).
///
/// Der 5000-ft-Wert ist konservativ: Max realer Descent (Airbus 'Open
/// Descent' / Boeing 'VS-Mode') liegt bei ~4000 fpm, also ~4000 ft pro
/// Minute. Im laengsten Tick-Intervall (30 s Cruise) waeren das maximal
/// 2000 ft realer Drop. Ein 5000-ft-Drop in einem Tick ist physikalisch
/// unmoeglich = eindeutig Reload-Artefakt.
///
/// Position-Distance wird NICHT geprueft weil XP12-Crash-Recovery den
/// Aircraft am naechstgelegenen Airport spawnt (typisch 10-20 km vom
/// Cruise-Punkt, < `RESUME_DRIFT_WARN_NM` von 50 nm) — Distance-Trigger
/// wuerde Faelle wie Michel 2026-05-25 verpassen.
fn is_mid_session_sim_crash_recovery(
    current_phase: FlightPhase,
    prev_on_ground: bool,
    prev_altitude_msl_ft: f64,
    curr_on_ground: bool,
    curr_altitude_msl_ft: f64,
) -> bool {
    let was_airborne_phase = matches!(
        current_phase,
        FlightPhase::Climb
            | FlightPhase::Cruise
            | FlightPhase::Holding
            | FlightPhase::Descent
            | FlightPhase::Approach
            | FlightPhase::Final
    );
    if !was_airborne_phase {
        return false;
    }
    if prev_on_ground || !curr_on_ground {
        return false;
    }
    let alt_drop_ft = (prev_altitude_msl_ft - curr_altitude_msl_ft).abs();
    alt_drop_ft > 5000.0
}

/// Kilograms → pounds. We collect fuel in kg internally because every
/// SimConnect adapter normalises to SI, but phpVMS-Core's `acars` table
/// and the PIREP `file` endpoint expect pounds — convert at the boundary.
const KG_TO_LB: f64 = 2.20462262;

/// Universal "we're done here" fallback for the FSM. Catches helicopters
/// (no taxi-out / taxi-in / parking-brake convention), short hops,
/// emergency landings near the destination, and anything else where the
/// normal Pushback → Cruise → BlocksOn chain doesn't fire cleanly.
///
/// When the aircraft is on-ground with engines off, sitting within
/// `ARRIVED_FALLBACK_RADIUS_NM` of the destination airport, the FSM jumps
/// straight to `Arrived` regardless of what phase it's currently in (apart
/// from pre-block-off phases — we won't accidentally end a flight that
/// hasn't started yet).
const ARRIVED_FALLBACK_RADIUS_NM: f64 = 2.0;
/// Wall-clock dwell the engines-off condition
/// (`arrived_fallback_conditions_basic`) must hold, uninterrupted, before
/// the fallback fires. `engines_running` is an unsmoothed per-tick SimVar
/// read (`GENERAL ENG COMBUSTION:N` / N1-fallback) with no read-side
/// debouncing, so a lone stray sample shouldn't end the flight — but once
/// it has genuinely held for a few seconds there is nothing left to wait
/// for (the shutdown-pacing concern the old 30 s dwell was also covering
/// is already handled by requiring `engines_running == 0` in the first
/// place, not by waiting longer after it's confirmed).
///
/// Deliberately wall-clock, NOT a tick count: `adaptive_tick_interval`
/// drops the streamer's tick cadence to 500 ms whenever the phase
/// is Approach/Final/Landing/Takeoff/TakeoffRoll below 100 ft AGL — which
/// is exactly the "stuck on Final while already on the ground" state this
/// fallback exists to rescue. A fixed *tick-count* threshold would confirm
/// up to ~6x faster than intended in that window (an earlier version of
/// this fix made exactly that mistake — caught in code review before
/// release); wall-clock time is cadence-independent by construction.
///
/// Lowered from 30 s (set at v0.1.20, never re-tuned) after a field report
/// (GSG22 EDLN→EDDL, PIREP XrRp6eMQYvJJlExP): the pilot perceived the app
/// as frozen on "Final" for 3-4 min after touchdown. Flight-log analysis
/// showed the vast majority of that was real taxi-in + the pilot's own
/// shutdown pacing; the only software-attributable wait was this dwell.
/// 9 s still comfortably rules out a single bad sample (≥3 ticks at the
/// normal 3 s ground cadence; far more during the sub-second flare
/// cadence).
const ARRIVED_FALLBACK_DWELL_SECS: i64 = 9;
/// v0.17.x (#Premium, Aircraft-Scan): längerer Dwell für den engines-
/// UNABHÄNGIGEN Stillstands-Fallback (Groundspeed < 1 kt + Parkbremse am
/// Ziel). Fängt Addons ab, deren `engines_running`-SimVar nach dem Shutdown
/// klemmt: der Contrail-FA50-Trijet meldet dauerhaft 3 laufende Triebwerke,
/// sodass der engines-off-Pfad NIE feuert und Auto-File hängt (Michel D.,
/// D-BETI).
///
/// v0.18.x QA-Härtung (Einwand Thomas: lange Rollhalte an großen Hubs, z. B.
/// Warten auf weitere Rollfreigabe, wo Piloten realistisch die Parkbremse
/// ziehen): 2 Minuten reichten dafür nicht als Sicherheitsmarge. ZWEI
/// unabhängige Gegenmaßnahmen, nicht nur eine:
///   1. Dieser Pfad läuft nur noch für Flugzeuge mit bestätigt kaputtem
///      Triebwerkszähler (`AircraftProfile::engine_count_unreliable`), NICHT
///      mehr fleet-weit — ein Rollhalt in einem Fenix/PMDG/FBW/etc. kann
///      diesen Pfad gar nicht mehr erreichen, weil der harte engines-off-Test
///      (`ARRIVED_FALLBACK_DWELL_SECS`) für die die einzige Rolle spielt.
///   2. Für die verbleibenden, eng begrenzten Fälle (aktuell nur FA50) ist der
///      Dwell auf 5 Minuten verlängert — deutlich länger als ein typischer
///      Rollhalt, aber am echten Zielflughafen nach Blockzeit ohne
///      spürbaren Nachteil für den Piloten.
const ARRIVED_STANDSTILL_DWELL_SECS: i64 = 300;

// ---- Touch-and-Go / Go-Around detection (Stage 3) ----
//
// These thresholds were chosen by working backwards from real-world
// pilot intent rather than from sim-specific telemetry shapes:
//
// * 100 ft AGL threshold for T&G — comfortably above gear-strut /
//   bounce-rebound height (which is at most ~40 ft on the worst
//   bounces), but low enough that a deliberate climb-out from a
//   training landing crosses it quickly.
// * 30 s observation window — even a slow GA-pattern aircraft
//   (172, J3 Cub) climbs past 100 ft in less than that.
// * 200 ft recovery for GA — a missed approach typically initiates
//   at ≥200 ft above the lowest observed altitude, and 200 ft is
//   the standard Cat I missed-approach decision height. Sustained
//   8 s prevents the detector firing on a single climb-correction.
// * +500 fpm V/S filter on GA — pilots really go around with positive
//   V/S, no false positives from a flare round-out.

/// Time after a touchdown during which we watch for the aircraft
/// climbing back out (= touch-and-go). After this window expires
/// the touchdown is finalised as a regular landing.
const TOUCH_AND_GO_WATCH_SECS: i64 = 30;
/// Aircraft must climb above this AGL after a touchdown to count
/// as a touch-and-go (not a tall bounce or runway-end pop-up).
const TOUCH_AND_GO_AGL_THRESHOLD_FT: f32 = 100.0;
/// Aircraft must be above the AGL threshold for this long for the
/// T&G to be confirmed — short spike doesn't count.
const TOUCH_AND_GO_DWELL_SECS: i64 = 1;
/// AGL increase from `lowest_agl_during_approach_ft` that signals a
/// possible go-around in progress.
///
/// v0.5.35: 200 → 150 ft. Reason: bei sparse Sampling kann der erste
/// Frame nach der lowest_agl-Marke schon 60+ Sekunden später sein —
/// in der Zeit klettert ein C152 leicht 200+ ft. Niedrigerer Threshold
/// fängt mehr GA-Versuche ein. Dwell-Check filtert noch False Positives.
const GO_AROUND_AGL_RECOVERY_FT: f32 = 150.0;

// ---- Holding-pattern detection (v0.5.11) ------------------------------
//
// A holding pattern is a circle at constant altitude. We detect it via
// sustained turn (banked) + level flight (low VS). Real ICAO holds:
//   * 1-min legs at <FL140, 1.5-min legs above → 4-6 min full circuit
//   * Standard 3°/sec turn rate = full 360° in 2 min
//   * Constant altitude (±100 ft)
//
// Entry threshold: 90 s of sustained bank > 15° + |VS| < 200 fpm.
// This filters out:
//   * 90° heading change at standard rate (~30 s) — won't trigger
//   * Procedure turn / teardrop entry (~60 s) — won't trigger
//   * Long ATC vector with sustained 30° bank (~2 min) — WILL trigger,
//     which is fine: the FSM simply shows "Holding" briefly and then
//     exits when bank levels off
//
// Exit threshold: 30 s of sustained bank < 5° (level flight). Or
// active descent (< -300 fpm + AGL < 5000) which means ATC cleared
// us out of the hold for the approach.
const HOLDING_ENTRY_DWELL_SECS: i64 = 90;
const HOLDING_EXIT_DWELL_SECS: i64 = 30;
const HOLDING_BANK_THRESHOLD_DEG: f32 = 15.0;
const HOLDING_VS_THRESHOLD_FPM: f32 = 200.0;
/// Sustained climb time required before we classify a Go-Around.
const GO_AROUND_DWELL_SECS: i64 = 8;
/// v0.7.17 (B-010): Sustained sink-rate dwell before Climb → Descent.
///
/// Quelle: GSG 105 Cessna LDDU→LDSP zeigte 6 sec Descent-Phase weil
/// ein Trim-/Turbulenz-Spike single-tick die FSM kippte. 15 s ist
/// laenger als jede plausible Trim-Korrektur oder Turbulenz-Pause,
/// aber kurz genug damit ein echter Top-of-Descent nicht spuerbar
/// verzoegert wird (-500 fpm × 15 s = 125 ft Verlust, vernachlaessigbar
/// gegen typische 25.000-ft-TOD-Strecken).
const DESCENT_DWELL_SECS: i64 = 15;
/// En-Route-Versöhner (Korpus-Audit 2026-07, 632 Flüge): Sicherheitsnetz
/// für die GANZE Fehlerklasse "alte FSM hängt auf einer Luft-Phase fest",
/// nicht für einen einzelnen Übergangs-Arm. Historie derselben Klasse,
/// jedes Mal als Einzelfix hinterher: v0.5.40 (Pushback klemmt,
/// pushback_state konstant 3), v0.13.17 (Boden-Phasen klemmen, tote
/// Engine-SimVars), v0.19.1 (Final→Landing, Anzeige-only), GSG-105
/// (Descent-Falle, es gibt keinen Descent→Climb-Weg zurück), zuletzt
/// GSG22 EDLN→EDDL + eine C172 (Climb→Descent mathematisch unerreichbar:
/// `lost_from_peak > 500..1200 ft` kann bei < 1000 ft Climb-Peak nie
/// eintreten — Ansatz-Problem, kein Schwellenwert-Problem).
///
/// Mechanik: weicht v1 in einer Luft-Phase (Climb/Cruise/Descent/
/// Approach/Final — NICHT Holding, das v2 bewusst nicht modelliert) so
/// lange von v2s aufgelöster Phase ab, ohne sich selbst zu bewegen, wird
/// v1s echter Zustand auf v2s Phase gezogen — über den normalen
/// `next_phase`-Commit, also mit echtem `PhaseChanged`-Event (Treibstoff-
/// Snapshot, METAR-Abruf, ACARS-Log, Auto-File-Kette ziehen alle nach;
/// das unterscheidet ihn von der reinen Anzeige-Korrektur aus v0.19.1).
/// Es wird KEINE neue Heuristik erfunden: Ziel ist v2s bereits
/// review-gehärtete Resolver-Phase (phase_v2.rs), keine Roh-Segmente.
///
/// Der PRIMÄRE Schutz vor Fehl-Zügen ist NICHT der Dwell, sondern das
/// Kinematik-Widerspruchs-Gate [`segment_contradicts_v1`]: gefeuert wird
/// ausschließlich, wenn die Fenster-Evidenz v1s aktuelle Phase aktiv
/// WIDERLEGT (Climb während anhaltenden Sinkens/am Boden, Descent während
/// anhaltenden Steigens, …). Bloßes v1≠v2 genügt NICHT — QS-Runde 1
/// bewies empirisch, dass v1 und v2 bei Level-Flug GEWOLLT und dauerhaft
/// auseinanderliegen (v2 promotet Climb→Cruise ref-los erst nach 240 s
/// Level; v2 hält bei Zwischen-Level-Offs bewusst Descent, wo v1s B-003
/// sofort Cruise recovert; v1 latcht Cruise bei Climb-Restrictions
/// single-tick, wo v2 korrekt Climb hält) — ein rein v1≠v2-basierter
/// Versöhner oszillierte auf JEDEM gesunden Normalflug (Zug → v1s
/// Primär-Arm latcht zurück → Zug → …). `Level`/`Insufficient`
/// widersprechen deshalb NIE einer Luft-Phase.
///
/// Der Dwell obendrauf ist ASYMMETRISCH nach Zug-Richtung im natürlichen
/// Flugbogen (Climb→Cruise→Descent→Approach→Final→Landing, s.
/// `enroute_phase_rank`):
///
/// * **Rückwärts** (v2 hinter v1) — 90 s: die vorsichtigere Richtung
///   (Defense-in-Depth über das Widerspruchs-Gate hinaus); länger als
///   v2s komplettes Evidenz-Fenster (60 s) + Hysterese-Reserve, damit
///   ein nachhinkendes v2 eine gesunde, frisch transitionierte v1 nie
///   zurückzieht (die Uhr resettet bei jeder v1-Transition ohnehin).
/// * **Vorwärts** (v2 vor v1) — 45 s: ein v2, das VORAUS ist, hat MEHR
///   bestätigte Evidenz, nicht weniger. Replay-Befund BE24 (der Feld-
///   Report-Flug): die ehrliche Divergenz-Spanne vor dem Touchdown
///   betrug nur 82 s — mit einem symmetrischen 90-s-Dwell käme die
///   Rettung erst NACH dem Aufsetzen, mit 45 s noch in der Luft (v1
///   erlebt Final/Landing als echte Phasen und erfasst den Touchdown
///   über die eigene Landing-Kante statt Sampler-Carry-Over).
const ENROUTE_RECONCILE_DWELL_SECS: i64 = 90;
/// Vorwärts-Dwell des En-Route-Versöhners — siehe
/// [`ENROUTE_RECONCILE_DWELL_SECS`].
const ENROUTE_RECONCILE_FORWARD_DWELL_SECS: i64 = 45;
/// v0.7.17 (B-010): Gewichts-Schwelle Light-GA vs. Medium/Heavy.
///
/// 5700 kg = MTOM-Grenze EASA CS-23/CS-25 (Single/Twin-Prop GA vs.
/// Regional/Airline). Light-GA-Flugzeuge fliegen Patterns / Local
/// Sightseeing oft komplett unter 3000 ft AGL — die Standard-
/// Schwellen `lost_from_peak > 500/800` triggern Spurious-Descent
/// bei jedem Pattern-Leg. Light-GA bekommt deshalb groesszuegigere
/// Werte.
const LIGHT_GA_MTOM_KG: f32 = 5700.0;
/// Minimum positive V/S at which the GA detector accepts a sample
/// as "actually climbing" (filters out flare round-out / level-off).
///
/// v0.5.35: 500 → 300 fpm. Slow GA aircraft (Cessna 152, Piper Cub,
/// taildraggers) klettern bei einem GA selten >500 fpm — der frühere
/// Threshold übersah ihre Go-Arounds komplett.
const GO_AROUND_MIN_VS_FPM: f32 = 300.0;
/// AGL threshold above which we mark the flight as having actually
/// flown. Powers the `was_airborne` gate that prevents both the
/// Arrived-fallback and the divert-detection from firing pre-flight
/// (GSX repositioning, ground-handling wackeln, etc.). 50 ft is well
/// above gear-strut oscillation and runway-end short-hop noise.
const WAS_AIRBORNE_AGL_FT: f32 = 50.0;
/// Upper bound on AGL we'll trust for the `was_airborne` mark. Live bug
/// 2026-05-03 (PMDG B738, GSX pushback): MSFS reported AGL=53819 ft
/// for ~60 s right after the SimConnect handshake while the terrain
/// engine was still loading — the aircraft was sitting on a stand
/// at EDDH but the SimVar said it was at FL538 with on_ground=false.
/// `was_airborne` flipped true from that loading glitch, and 30 min
/// later the universal Arrived-fallback (gated by was_airborne)
/// fired during the GSX pushback because pushback motion happens to
/// match the conditions. The fix is to ignore obvious garbage AGL
/// values: real pre-flight terrain data is bounded; nothing in the
/// real world makes a parked aircraft suddenly "airborne at FL538".
const WAS_AIRBORNE_AGL_MAX_FT: f32 = 30000.0;
/// Minimum number of consecutive ticks the airborne conditions must
/// hold before we flip `was_airborne`. Gates against single-tick
/// glitches where MSFS briefly reports !on_ground during scenery
/// load even with sane AGL. 2 ticks ≈ 5-10 s at the streamer cadence.
const WAS_AIRBORNE_DWELL_TICKS: u8 = 2;

/// If at the moment the FSM reaches Arrived the aircraft is farther
/// than this from the planned `arr_airport`, we treat it as a divert
/// candidate and surface a banner asking the pilot to confirm the
/// actual destination. Same threshold as ARRIVED_FALLBACK_RADIUS_NM
/// so we don't paint divert banners on perfectly-normal arrivals
/// where the FSM happened to fire from the slightly-larger fallback
/// instead of the strict on-block path.
const DIVERT_DETECT_RADIUS_NM: f64 = 2.0;
/// How far from the actual touchdown point we'll search the local
/// runways DB for a matching airport. 50 nmi covers any sensible
/// real-world divert (typical divert distances: 20-100 nmi). Larger
/// than 50 likely means we either missed the airport in our DB or
/// the pilot landed somewhere genuinely off-grid (private strip).
const DIVERT_NEAREST_SEARCH_RADIUS_NM: f64 = 50.0;

// ---- v0.16.24: approach-phase divert navdata pre-fetch -----------------
//
// During a descending approach we watch whether the nearest airport has
// diverged from the planned `arr_airport`. Once the aircraft is on a
// stable, committed approach to a DIFFERENT field (descending, low, near
// that field, stable for a few seconds) we pre-fetch its Navigraph navdata
// so the cache is warm at touchdown — instead of falling back to the
// coarse OurAirports CSV. Bounded (only fires on divergence, idempotent per
// ICAO) and debounced (stability dwell) so an airport merely overflown
// mid-descent doesn't trigger a fetch.

/// AGL ceiling (ft) below which we consider the aircraft committed enough
/// to an approach to bother pre-fetching. Above this the nearest field is
/// still ambiguous (en-route over a busy area). 5000 ft AGL is the same
/// gate the FSM uses to enter Approach.
const DIVERT_PREFETCH_MAX_AGL_FT: f64 = 5000.0;
/// Horizontal radius (nm) within which the diverged nearest field must lie
/// before we treat the approach as committed to it. 10 nm ≈ a typical
/// final-approach intercept distance; tighter than the 50 nm divert search
/// so a field merely passed at altitude doesn't qualify.
const DIVERT_PREFETCH_MAX_DIST_NM: f64 = 10.0;
/// The aircraft must be descending at least this fast (negative fpm) — a
/// level overflight of an airport mid-cruise never qualifies.
const DIVERT_PREFETCH_MIN_SINK_FPM: f64 = -200.0;
/// How long the diverged nearest field must remain the stable candidate
/// before the pre-fetch fires. Debounces an airport that is briefly nearest
/// while the aircraft tracks past it on a vector.
const DIVERT_PREFETCH_STABLE_SECS: i64 = 10;
/// The diverged field must be at least this far from the planned
/// `arr_airport` to count as a real divert (same threshold the
/// parked-Arrived divert detection uses). Below this it's the same airport
/// area and the planned navdata already covers it.
const DIVERT_PREFETCH_PLANNED_DIVERGE_NM: f64 = 5.0;

/// How often we POST `/pireps/{id}/update` purely to bump `pireps.updated_at`
/// and keep phpVMS's `RemoveExpiredLiveFlights` cron from soft-deleting
/// the in-flight PIREP. The cron runs hourly and looks at `updated_at`,
/// NOT at the latest position row — without this heartbeat, a long
/// cruise leg with no phase changes gets killed after `acars.live_time`
/// hours (default 2h on most installs). vmsACARS uses 30 s by default
/// (`acars_update_timer`); we match.
const HEARTBEAT_INTERVAL: Duration = Duration::from_secs(30);

/// v0.4.1: nach wie vielen Sekunden ohne brauchbaren Sim-Snapshot
/// wir den Flug als „pausiert" markieren (Sim-Crash, Quit, Timeout).
/// 30 s ist ein guter Kompromiss: lang genug dass kurze FPS-Drops oder
/// Pause-Menü-Ausflüge keinen False-Positive triggern, kurz genug dass
/// der Pilot den Disconnect zeitnah mitkriegt und re-positionieren kann
/// bevor phpVMS' Live-Tracking-Cron (default ~2h) den PIREP killt.
const SIM_DISCONNECT_THRESHOLD_S: i64 = 30;

/// v0.12.5 (Spec docs/spec/v0.12.5-divert-and-manual-pirep.md, LE9):
/// Maximales Alter eines Sim-Snapshots, ab dem das Resume-Sim-Gate den
/// Flug scharfschaltet. Bewusst ENGER als `SIM_DISCONNECT_THRESHOLD_S` —
/// letzteres ist Disconnect-Erkennung im laufenden Flug, hier geht es ums
/// Scharfschalten NACH Resume: ein alter, vor dem Neustart persistierter
/// Snapshot darf nicht zählen. ≤ 5 s ⇒ frisch genug, dass der Sim jetzt
/// gerade Daten liefert.
const SIM_GATE_FRESH_SECS: i64 = 5;

/// Spec sim-disconnect-auto-resume F2 (Drift-Stufen):
///
/// Schwellen fuer die Activity-Log-Eskalation beim Resume. Drift NM
/// gemessen zwischen `paused_last_known` und dem ersten Post-Resume-
/// Snapshot. Kein Level blockiert Auto-Resume (Spec-Prinzip P2:
/// informieren statt blockieren).
///
///   <  1 NM : `▶ Flug automatisch fortgesetzt` (kein Distanz-Suffix)
///   1-50    : Info-Level mit `repositioniert X nm`
///   50-200  : Warn-Level (auffaellige Reposition)
///   > 200   : Warn-Level mit Hinweis „pruefe ob der richtige Flug geladen ist"
///
/// Schwellen sind empirisch — typischer Autosave bei MSFS ist ~10 min
/// alt, was bei 480 kt etwa 80 NM Drift produziert (= Warn-Range,
/// erwartbar). >200 NM ist verdaechtig: entweder Bid-Reload am
/// Departure-Airport (= falscher Flug?) oder grosser Slew-Move.
const RESUME_DRIFT_TOAST_NM: f64 = 1.0;
const RESUME_DRIFT_WARN_NM: f64 = 50.0;
const RESUME_DRIFT_EXTREME_NM: f64 = 200.0;

/// v0.13.0 Stream F (LE22-LE26): Pilot-getriggerter Re-Check-Workflow.
/// Wenn `resume_position_suspect=true`, kann der Pilot sich erst manuell im
/// Sim wieder zur gespeicherten Position bringen und dann via
/// `flight_resume_check_position`-Command einen Re-Check auslösen. Wenn
/// die aktuelle Drift kleiner als diese Schwelle ist UND keine
/// airborne↔on_ground-Inkonsistenz besteht, gilt der Resume als sauber
/// (kein untrusted-Stempel) und der Flug läuft normal weiter.
const RESUME_DRIFT_CLEAN_NM: f64 = 5.0;

/// How close (in nautical miles) the aircraft must be to the departure airport
/// to start the flight. Generous enough to cover taxi positions and remote
/// stands; tight enough to reject "I'm at EDDF instead of EDDP".
const MAX_START_DISTANCE_NM: f64 = 5.0;

/// Symmetric to MAX_START_DISTANCE_NM but applied at touchdown / file:
/// the pilot has to actually be on (or at) the planned arrival airport,
/// not somewhere random. Diverts are still possible via
/// `flight_end_manual` with a divert ICAO + reason. EDDP→EDDP plans are
/// fine — same airport, same check.
const MAX_FILE_DISTANCE_NM: f64 = 5.0;

// v0.12.10: `clean_atc_model` ist nach `sim-core` gezogen, damit der
// MSFS-Telemetrie-Adapter den `ATC MODEL` schon bei der Erfassung
// bereinigt (BlackSquare-Caravan-Bug: roher Token `ATCCOM.AC_MODEL
// C208.0.text` landete ungereinigt in `aircraft_icao` → „Type ?" →
// kaputtes phpVMS-Filing). Re-Import hier, damit die bestehenden
// Aufruf-Stellen unverändert weiterlaufen.
use sim_core::clean_atc_model;

/// Loose check: does the aircraft title from MSFS appear to mention the given
/// ICAO code? Used as a permissive backup when ATC MODEL parses to one code
/// but the title says something completely different.
///
/// "Mention" includes the ICAO code AND any of its known long-form
/// aliases — e.g. for `icao = "A359"` the title "Airbus A350-900"
/// counts as a match. Without this, a pilot on a real GSG flight
/// (Emirates UAE770 EK770, A359 bid, A350-900 sim) got blocked
/// with "Aircraft mismatch" even though it's the same aircraft.
// v0.8.3: `title_mentions_icao(&str, &str)` (Test-Wrapper ohne VPS-
// Override) entfernt — wurde von keinem Test mehr aufgerufen seit die
// `_with_extra`-Variante alleinige Single-Source-of-Truth ist. Wer die
// Default-Variante braucht, ruft `_with_extra(title, icao, &HashMap::new())`.

/// v0.8.0: title-substring-Check mit VPS-Alias-Override. Long-form
/// strings aus dem Sim ("mg hjet ha420 [Preset Default]") werden
/// gegen die hardcoded + VPS-Alias-Liste auf substring-Match geprüft.
fn title_mentions_icao_with_extra(
    title: &str,
    icao: &str,
    vps_aliases: &HashMap<String, Vec<String>>,
) -> bool {
    let title_upper = title.to_uppercase();
    let icao_upper = icao.to_uppercase();
    if title_upper.contains(&icao_upper) {
        return true;
    }
    if aircraft_aliases(&icao_upper)
        .iter()
        .any(|alias| title_upper.contains(alias))
    {
        return true;
    }
    if let Some(extra) = vps_aliases.get(&icao_upper) {
        if extra.iter().any(|alias| title_upper.contains(alias.as_str())) {
            return true;
        }
    }
    false
}

/// Bidirectional alias table for aircraft type identification.
/// phpVMS stores `aircraft.icao` as the ICAO 4-letter type code
/// (`A359`, `B738`, `B77W`), but MSFS's `ATC MODEL` and `TITLE`
/// SimVars often expose the marketing/long form (`A350-900`,
/// `737-800`, `777-300ER`). Both sides refer to the same airframe;
/// our match logic must accept either.
///
/// Returns the list of long-form aliases for the given ICAO code,
/// PLUS the inverse — if `icao` looks like a marketing form, the
/// aliases include the corresponding ICAO code so a sim that
/// reports the ICAO can still match a long-form title and vice
/// versa. Empty list = no known aliases (fall through to
/// strict-string comparison).
///
/// Live bug 2026-05-04: Emirates A359 bid blocked because sim
/// loaded "A350-900 (No Cabin)" — same aircraft, different name.
fn aircraft_aliases(code: &str) -> &'static [&'static str] {
    // Match against the uppercased input. Long-form aliases are
    // partial substrings (we only need ONE to be present in the
    // sim title) — so "A350-900" alone catches "Airbus A350-900",
    // "A350-900 No Cabin", "Asobo A350-900", etc.
    match code {
        // ---- Airbus ----
        // A220 family
        "BCS1" => &["A220-100", "CS100"],
        "BCS3" => &["A220-300", "CS300"],
        // A320 family
        "A318" => &["A318"],
        "A319" => &["A319"],
        "A20N" => &["A320NEO", "A320-NEO", "A320 NEO"],
        "A320" => &["A320"],
        "A21N" => &["A321NEO", "A321-NEO", "A321 NEO"],
        "A321" => &["A321"],
        // A330 family
        "A332" => &["A330-200"],
        "A333" => &["A330-300"],
        "A338" => &["A330-800"],
        "A339" => &["A330-900"],
        // A330-Frachter — VA-/SimBrief-Alias. Qatar Cargo / Turkish
        // Cargo / Etihad Cargo flogen A330-200F.
        "A332F" => &["A330-200F", "A330-200 FREIGHTER", "A332F"],
        // A340 family
        "A342" => &["A340-200"],
        "A343" => &["A340-300"],
        "A345" => &["A340-500"],
        "A346" => &["A340-600"],
        // A350 family — the bug
        // v0.7.4 (Round-1 Review): "A350"-Substring-Alias entfernt
        // weil A359-Bid faelschlich auch A350-1000 matchte. Spec
        // §3.3 "Anti-Patterns": Aliase muessen spezifisch genug sein
        // dass nur die echte Familie matched. "A350-900" reicht weil
        // alle bekannten Sim-Adapter (Asobo/iniBuilds/etc.) den
        // Variant-Suffix immer mitliefern.
        "A359" => &["A350-900"],
        "A35K" => &["A350-1000"],
        // A380
        "A388" => &["A380-800", "A380"],

        // ---- Boeing ----
        // 717
        "B712" => &["717-200", "717"],
        // 737 NG family
        "B736" => &["737-600"],
        "B737" => &["737-700"],
        "B738" => &["737-800"],
        "B739" => &["737-900"],
        // 737 MAX
        "B37M" => &["737 MAX 7", "737-7", "737MAX-7"],
        "B38M" => &["737 MAX 8", "737-8", "737MAX-8"],
        "B39M" => &["737 MAX 9", "737-9", "737MAX-9"],
        "B3XM" => &["737 MAX 10", "737-10"],
        // 747
        "B741" => &["747-100"],
        "B742" => &["747-200"],
        "B744" => &["747-400"],
        "B748" => &["747-8"],
        // 747-Frachter — VA-/SimBrief-Alias (nicht streng ICAO Doc 8643).
        // Spec docs/spec/aircraft-type-match.md §4 + §7.3: Cargo-Bid
        // strict gegen Frachter-Title; B744 (Pax-Bid) akzeptiert via
        // Long-Form-Substring "747-400" auch -400F-Frachter (Cargo-
        // Pragmatismus). Lufthansa Cargo / Atlas / Cargolux flogen
        // historisch B744F + heute B748F.
        // v0.7.4: " FREIGHTER" Long-Form ergaenzt (Round-1 Review)
        // weil manche Sim-Addons den Title als "747-400 Freighter"
        // ohne den F-Suffix-Kompakt schreiben.
        "B74F"  => &["747-400F", "747-400 FREIGHTER", "B74F"],
        "B748F" => &["747-8F", "747-8 FREIGHTER", "B748F"],
        // 757
        "B752" => &["757-200"],
        "B753" => &["757-300"],
        // 757-Frachter — VA-/SimBrief-Alias. DHL/UPS/FedEx-Klassiker.
        "B752F" => &["757-200F", "757-200 FREIGHTER", "B752F"],
        // 767
        "B762" => &["767-200"],
        "B763" => &["767-300"],
        "B764" => &["767-400"],
        // 767-Frachter — VA-/SimBrief-Alias. FedEx/UPS-Klassiker.
        "B762F" => &["767-200F", "767-200 FREIGHTER", "B762F"],
        "B763F" => &["767-300F", "767-300 FREIGHTER", "B763F"],
        // 777
        "B772" => &["777-200"],
        "B77L" => &["777-200LR", "777-200 LR"],
        "B773" => &["777-300"],
        "B77W" => &["777-300ER", "777-300 ER"],
        "B77F" => &["777F", "777-200F"],
        // 787
        "B788" => &["787-8"],
        "B789" => &["787-9"],
        "B78X" => &["787-10"],

        // ---- McDonnell Douglas ----
        // MD-11 family (Pax + Frachter — Live-Bug 2026-05-10:
        // Martinair Cargo MPH62 Bid mit ICAO "MD11" wurde geblockt
        // weil TFDi Design im Sim "MD-11F" meldet. Cargo-Bids fliegen
        // legitim auch die F-Variante; "MD11" alias matched daher
        // sowohl "MD-11" als auch "MD11F"-Substring im Title).
        "MD11"  => &["MD-11", "MD11"],
        "MD11F" => &["MD-11F", "MD11F"],

        // ---- Embraer ----
        "E170" => &["170"],
        "E175" => &["175"],
        "E190" => &["190"],
        "E195" => &["195"],
        "E290" => &["E190-E2", "E2-190"],
        "E295" => &["E195-E2", "E2-195"],

        // ---- Honda Aircraft Company ----
        // HondaJet HA-420 — Live-Bug 2026-05-13 (GSG / Michel D., MSFS):
        // Bid hat ICAO "HDJT" (offizieller Doc-8643 Type-Designator),
        // MSFS ATC-MODEL liefert aber "HA420" (Hersteller-Marketing-
        // Designation) und der TITLE ist typisch "mg hjet ha420
        // [Preset Default]". Ohne Alias schlägt der Pre-Flight-Check
        // mit "Aircraft mismatch: bid wants HDJT, sim has HA420" fehl.
        // Bidirektional eingetragen damit beide Vergleichsrichtungen
        // (bid-vs-sim und sim-vs-bid) matchen.
        "HDJT" => &["HA420", "HA-420", "HONDAJET", "HJET"],
        "HA420" => &["HDJT", "HA-420", "HONDAJET", "HJET"],

        // No alias known — fall through to strict comparison.
        _ => &[],
    }
}

/// Symmetric: do these two aircraft type strings refer to the
/// same airframe? Tries both directions: are `actual`'s long-form
/// aliases mentioned by `expected`? And are `expected`'s aliases
/// mentioned by `actual`? Plus strict equality fallback.
/// Test-/Compatibility-Wrapper ohne VPS-Override.
#[cfg(test)]
fn aircraft_types_match(expected: &str, actual: &str) -> bool {
    aircraft_types_match_with_extra(expected, actual, &HashMap::new())
}

/// v0.8.0: alias-aware comparison with VPS-managed override-table
/// merged on top of the hardcoded `aircraft_aliases()`. The
/// `vps_aliases` map is the result of fetching
/// `/api/aircraft-aliases` from the recorder; key = bid-ICAO
/// uppercase, value = list of additional alias substrings the sim
/// might report. VPS aliases are ADDITIVE — a hardcoded mismatch
/// (e.g. an A330 family) is never relaxed by an empty VPS table.
fn aircraft_types_match_with_extra(
    expected: &str,
    actual: &str,
    vps_aliases: &HashMap<String, Vec<String>>,
) -> bool {
    let exp = expected.to_uppercase();
    let act = actual.to_uppercase();
    if exp == act {
        return true;
    }
    // Either side might be the short ICAO form, the other the
    // long marketing form. Check both directions against the
    // hardcoded table first (= offline-safe baseline).
    if aircraft_aliases(&exp).iter().any(|alias| act.contains(alias))
        || aircraft_aliases(&act).iter().any(|alias| exp.contains(alias))
    {
        return true;
    }
    // VPS-pflegbare Overrides — additive zur hardcoded Tabelle.
    if let Some(extra) = vps_aliases.get(&exp) {
        if extra.iter().any(|alias| act.contains(alias.as_str())) {
            return true;
        }
    }
    if let Some(extra) = vps_aliases.get(&act) {
        if extra.iter().any(|alias| exp.contains(alias.as_str())) {
            return true;
        }
    }
    false
}

/// v0.13.16: zentraler, alias-bewusster Aircraft-Typ-Vergleich. Genutzt
/// sowohl vom `flight_start`/`flight_start_manual`-Mismatch-Gate ALS AUCH
/// vom Auto-Start-Watcher (Option C), damit beide identisch entscheiden —
/// inklusive VPS-Aliase und Title-Substring-Fallback.
///
/// **Permissiv, wenn eine Seite unbekannt ist** (analog zum Gate, das nur
/// bei beidseitig bekanntem Typ blockt): kann der erwartete oder der Sim-
/// Typ nicht aufgelöst werden ⇒ kein Block (`true`). So verhindert ein
/// fehlgeschlagener `get_aircraft` im Watcher-Vorabcheck nie einen
/// legitimen Start.
fn aircraft_type_matches_sim(
    expected_icao: Option<&str>,
    sim_icao: Option<&str>,
    sim_title: &str,
    vps_aliases: &HashMap<String, Vec<String>>,
) -> bool {
    match (expected_icao, sim_icao) {
        (Some(expected), Some(actual)) => {
            aircraft_types_match_with_extra(expected, actual, vps_aliases)
                || title_mentions_icao_with_extra(sim_title, expected, vps_aliases)
        }
        _ => true,
    }
}

/// Shared application state — wraps the currently-authenticated client (if any)
/// and (on Windows) the MSFS adapter.
/// Cap on retained activity-log entries. The frontend displays the most
/// recent N — older lines fall off so the buffer doesn't grow forever
/// during a long flight (~5 h cruise = ~600 phase-tagged position posts
/// in the log; 1000 leaves comfortable headroom for transitions, errors
/// and bid-list updates on top).
const ACTIVITY_LOG_CAPACITY: usize = 1000;

/// Severity of an activity-log entry. Drives the frontend's icon/colour.
#[derive(Debug, Clone, Copy, Serialize, Deserialize)]
#[serde(rename_all = "lowercase")]
enum ActivityLevel {
    Info,
    Warn,
    Error,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
struct ActivityEntry {
    timestamp: DateTime<Utc>,
    level: ActivityLevel,
    /// Stable English label for the event (e.g. "PIREP prefiled").
    /// Frontend may translate via i18n if a key matches; otherwise
    /// renders as-is.
    message: String,
    /// Optional context — flight phase, PIREP id, error code, etc.
    #[serde(skip_serializing_if = "Option::is_none")]
    detail: Option<String>,
}

#[derive(Default)]
struct AppState {
    client: Mutex<Option<Client>>,
    #[cfg(target_os = "windows")]
    msfs: Mutex<MsfsAdapter>,
    /// X-Plane adapter — cross-platform (UDP). Co-exists with the
    /// MSFS adapter; only one is `started` at a time, dictated by
    /// the persisted `SimKind`.
    xplane: Mutex<sim_xplane::XPlaneAdapter>,
    active_flight: Mutex<Option<Arc<ActiveFlight>>>,
    /// Ring buffer of pilot-visible activity events. Surfaced via the
    /// `activity_log_get` Tauri command; the dashboard renders them in
    /// the new "ACARS-Log" tab — same idea as the smartcars activity
    /// feed (login → bids loaded → prefiled → boarding → …).
    activity_log: Mutex<VecDeque<ActivityEntry>>,
    /// Atomic guard for `flight_start` / `flight_adopt`. Both functions await
    /// network calls *between* checking that no flight is active and writing
    /// the new ActiveFlight into state. Without this guard, two concurrent
    /// invokes (StrictMode double-mount, double-click, resume-banner re-render)
    /// would both pass the initial check and the second would silently
    /// overwrite the first — losing the streamer reference and leaving
    /// phpVMS with two adopt attempts. Acquire with `compare_exchange`,
    /// release in *every* exit path (success and error).
    flight_setup_in_progress: AtomicBool,
    /// In-process airport-coords cache. Keyed by ICAO uppercase. Populated on
    /// first lookup so we don't re-fetch on every snapshot tick.
    airports: Mutex<HashMap<String, Airport>>,
    /// v0.8.0 — VPS-managed aircraft-type-aliases. Refreshed on each
    /// flight_start (so a freshly-added alias takes effect at the next
    /// Flight without app-restart) AND lazily warmed by the auto-start
    /// watcher when empty (v0.15.16 — vorher war der Cache vor dem ersten
    /// Flug leer, sodass der Auto-Start-Typcheck aliased Flugzeuge wie
    /// E55P↔"PHENOM 300" nie matchte).
    /// Merged additively with the hardcoded `aircraft_aliases` table —
    /// VPS-Liste wins on conflict (= VA-Admin kann fehlerhaft hardcoded
    /// Aliases übersteuern). Empty when VPS unreachable or pre-fetch
    /// not yet completed.
    /// HashMap<bid-ICAO uppercase, Vec<alias substring uppercase>>.
    aircraft_aliases_vps: Mutex<HashMap<String, Vec<String>>>,
    /// Auto-start watcher state. When true, a background task polls
    /// `current_snapshot()` and the user's bids; if the aircraft is
    /// parked at one of the bid's departure airports AND the loaded
    /// aircraft matches the bid's planned aircraft, it auto-fires
    /// `flight_start` for that bid. Persisted via the same
    /// `aeroacars.autoStart` localStorage key the React side reads.
    auto_start_enabled: AtomicBool,
    /// v0.12.6: Auto-File-Setting, vom Frontend (localStorage) bei Mount
    /// + Toggle via `set_auto_file_enabled` in den Backend-State
    /// gespiegelt. Der Position-Streamer filet den PIREP beim Latch auf
    /// `Arrived` selbst, wenn dieses Flag an ist — fenster-unabhängig.
    /// Vorher lief Auto-File nur als Frontend-`useEffect`, der bei
    /// Hintergrund-Fenster / nicht-aktivem Cockpit-Tab nicht feuerte.
    /// Default `true` (in `.setup()` gesetzt) — passend zum Frontend.
    auto_file_enabled: AtomicBool,
    /// Marker so the watcher doesn't re-trigger after a successful
    /// auto-start while the resulting flight is still active. Set to
    /// the Bid ID we last fired for; cleared when the flight ends.
    /// Without this, a user that cancels the auto-started flight
    /// while still parked at the gate would get an instant re-trigger.
    auto_start_last_bid_id: Mutex<Option<i64>>,
    /// v0.3.0: Letzter Auto-Start-Skip-Grund. Wenn die UI fragt, wir
    /// den ausgeben können statt der Pilot grübelt warum nichts
    /// passiert. Format: "engines_on" / "moving" / "airborne" /
    /// "no_matching_bid" / "no_bids" — mit Timestamp damit die UI
    /// erkennen kann ob's gerade aktuell ist oder uralt.
    auto_start_skip_reason: Mutex<Option<(DateTime<Utc>, String)>>,
    /// v0.15.13: letzter fehlgeschlagener Auto-Start-Versuch
    /// `(Zeitpunkt, bid_id, error_code)`. Verhindert den Retry-Sturm: nach
    /// einem `flight_start`-Fehler feuert der Watcher denselben Bid erst nach
    /// `AUTO_START_FAIL_COOLDOWN_SECS` wieder (vorher: 3-s-Dauer-Retry, der
    /// GlitchTip mit `missing_aircraft` / `flight_already_active` flutete —
    /// #10, 189×). Drosselt zugleich das Activity-/GlitchTip-Log, da der
    /// Fehler-Pfad nur noch ~1×/Cooldown durchlaufen wird. Selbst-korrigierend:
    /// nach dem Cooldown versucht der Watcher erneut (Pilot kann inzwischen das
    /// Flugzeug zuweisen / Sim fertig laden).
    auto_start_fail: Mutex<Option<(DateTime<Utc>, i64, String)>>,
    /// When `true`, intercept the main window's CloseRequested event
    /// and `hide()` the window instead of letting it close. The user
    /// gets to it again via the system-tray icon (Win) / menubar
    /// item (Mac). When `false`, close behaves normally and the app
    /// quits. Toggle lives in Settings → Verhalten; persisted via
    /// the React side's `aeroacars.minimizeToTray` localStorage key
    /// and synced into here on every mount + change.
    minimize_to_tray_enabled: AtomicBool,
    /// v0.4.0: Cached pilot identity (e.g. `("GSG0001", "Thomas K")`)
    /// für Discord-Webhook-Posts. Wird beim Profile-Refresh gefüllt
    /// (`get_profile()` returns it), bleibt für die Lebenszeit der
    /// AeroACARS-Session. Wenn kein Profile geladen → `None`, der
    /// Discord-Embed fällt auf "AeroACARS Pilot" zurück.
    cached_pilot: Mutex<Option<(String, String)>>,
    /// v0.7.8 v1.5: gecachter Pilot-personalisierter Callsign-Suffix
    /// (`Profile.callsign`, z.B. "4TK"). Wird beim Login + jedem
    /// `phpvms_refresh_profile` aktualisiert. Von `flight_start` gelesen
    /// und in `ActiveFlight.pilot_callsign` durchgereicht fuer die
    /// SimBrief-direct-Match-Verifikation (Spec §6.1).
    cached_pilot_callsign: Mutex<Option<String>>,
    /// v0.5.11: MQTT live-tracking publisher handle. Connects to
    /// the aeroacars-live VPS (live.kant.ovh) via auto-provisioning
    /// the first time AeroACARS sees a logged-in pilot's API key.
    /// Pure background feature — pilot-invisible, no UI. Failure is
    /// non-fatal: AeroACARS works exactly as before if MQTT is
    /// unreachable. tokio::sync::Mutex (not std) because Handle is
    /// only ever accessed from async contexts (hook points run
    /// inside the streamer's async tasks).
    mqtt: tokio::sync::Mutex<Option<aeroacars_mqtt::Handle>>,
    /// v0.7.8: SimBrief-Identifier (Username + User-ID) fuer den
    /// SimBrief-direct OFP-Refresh-Pfad. Wenn mindestens eines gesetzt
    /// ist, kann `flight_refresh_simbrief` den neuen OFP direkt von
    /// simbrief.com holen ohne Bid-Pointer (= W5-Workaround).
    /// User-ID > Username Prioritaet wenn beide da.
    /// Persistenz: Frontend localStorage, Backend-State wird per
    /// `set_simbrief_settings` befuellt (mount + change) und beim
    /// App-Start/Login via App.tsx zurueck-gesynct.
    /// Spec docs/spec/ofp-refresh-simbrief-direct-v0.7.8.md §4.
    simbrief_settings: Mutex<SimBriefSettings>,
    /// v0.7.9: gesetzt vom letzten `flight_refresh_simbrief` wenn
    /// `DirectOutcome::MatchWithCallsignWarning` zurueckkam. Frontend
    /// rendert daraus einen gelben Warning-Notice "OFP geladen, aber
    /// Callsign weicht ab". Wird beim naechsten erfolgreichen Refresh
    /// (Match ohne Warning) oder durch expliziten Dismiss-Command
    /// geloescht.
    ofp_callsign_warning: Mutex<Option<OfpCallsignWarning>>,
    /// v0.16.0 (#LAN-Remote): handle to the running LAN remote-control
    /// server, or `None` while stopped. Holds the graceful-shutdown
    /// trigger + the bound port. Same `tokio::sync::Mutex<Option<…>>`
    /// pattern as `mqtt` above — only ever touched from async command
    /// contexts. Started/stopped via the `remote_server_*` commands;
    /// since v0.16.16 the toggle persists, so the setup hook auto-starts
    /// the server at boot when the pilot left it switched ON.
    remote_server: tokio::sync::Mutex<Option<remote::RemoteServerHandle>>,
    /// v0.16.0 (#LAN-Remote): always-live event tap. The three Tauri push
    /// emit sites (`integrity-flag`, `pirep_auto_filed`,
    /// `pirep_cancelled_remotely`) ALSO fan their payload out here; the WS
    /// handler subscribes so a paired tablet sees the same events. The bus
    /// exists even when the server is stopped (cheap no-op sends), so the
    /// emit sites never branch on server-running state. A `Default` newtype
    /// (broadcast::Sender has no `Default`) keeps `#[derive(Default)]` on
    /// AppState intact.
    remote_events: remote::RemoteEventBus,
}

/// v0.7.9: Warning-State wenn SimBrief-OFP DEP+ARR matched aber Callsign
/// abweicht. Statt Hard-Block (v0.7.8) wird der OFP geladen und der Pilot
/// sieht einen gelben Hinweis-Notice.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct OfpCallsignWarning {
    /// SimBrief-Callsign aus dem geladenen OFP, z.B. "EWG4PY".
    pub sb_callsign: String,
    /// Joined-Liste der akzeptierten Active-Callsigns, z.B. "EWL9725 / 9725".
    pub active_callsigns: String,
    /// Zeitstempel wann das Warning gesetzt wurde.
    pub issued_at: DateTime<Utc>,
}

/// v0.7.8: SimBrief-Identifier-Settings. Beide Felder optional, aber
/// mindestens eines muss gesetzt sein damit SimBrief-direct funktioniert.
/// Wenn beide gefuellt → User-ID gewinnt (robuster, unveraenderlich).
/// Spec docs/spec/ofp-refresh-simbrief-direct-v0.7.8.md §4.1.
#[derive(Debug, Clone, Default, Serialize, Deserialize)]
pub struct SimBriefSettings {
    /// SimBrief-Profile-Name (z.B. "thomaskant"). Sichtbar in
    /// simbrief.com/dashboard/?username=X.
    #[serde(default, skip_serializing_if = "Option::is_none")]
    pub username: Option<String>,
    /// SimBrief-User-ID (numerisch als String, z.B. "612345").
    /// Aus SimBrief Account Settings. Robuster als Username weil
    /// unveraenderlich.
    #[serde(default, skip_serializing_if = "Option::is_none")]
    pub user_id: Option<String>,
}

/// RAII guard for `AppState::flight_setup_in_progress`. Acquire it at the
/// start of `flight_start` / `flight_adopt`; the in-progress flag is cleared
/// automatically when the guard goes out of scope (any return path), unless
/// `disarm()` was called to keep the slot reserved (e.g. because the new
/// ActiveFlight has been written into state and the `active_flight` mutex
/// now serves as the conflict guard).
struct FlightSetupGuard<'a> {
    flag: &'a AtomicBool,
    armed: bool,
}

impl<'a> FlightSetupGuard<'a> {
    fn try_acquire(flag: &'a AtomicBool) -> Result<Self, UiError> {
        flag.compare_exchange(false, true, Ordering::SeqCst, Ordering::SeqCst)
            .map_err(|_| {
                UiError::new(
                    "flight_setup_in_progress",
                    "another flight start or adopt is already in progress — please wait",
                )
            })?;
        Ok(Self { flag, armed: true })
    }

    /// Tell the guard to NOT release the in-progress flag on drop. Use this
    /// once we've successfully written the new ActiveFlight into state — at
    /// that point the `active_flight` mutex is the source of truth.
    fn disarm(mut self) {
        self.armed = false;
        // Manually release the in-progress flag right now; from here the
        // `active_flight` mutex blocks duplicate setups.
        self.flag.store(false, Ordering::SeqCst);
    }
}

impl Drop for FlightSetupGuard<'_> {
    fn drop(&mut self) {
        if self.armed {
            self.flag.store(false, Ordering::SeqCst);
        }
    }
}

/// In-memory record of an in-progress flight. Held inside an `Arc` so the
/// background streaming task can hold a reference without going through the
/// AppState mutex.
struct ActiveFlight {
    pirep_id: String,
    bid_id: i64,
    /// v0.7.7: phpVMS-Flight-Identifier aus `Bid.flight_id`. Sibling von
    /// `bid_id`. Wird beim `flight_start` aus dem Bid extrahiert BEVOR
    /// `prefile_pirep` feuert — sonst ist der Schluessel verloren wenn
    /// phpVMS-7 den Bid nach Prefile entfernt (W5). v0.7.8 nutzt den
    /// `flight_id` als zentralen Pointer fuer den OFP-Refresh-Pfad
    /// (entweder PAX-Studio-Endpoint /api/paxstudio/flights/{flight_id}/
    /// simbrief ODER SimBrief-direct mit Flight-Match-Verifikation).
    /// Empty string fuer pre-v0.7.7-Resume-Files — v0.7.8 muss diesen
    /// Fall als "legacy active flight, direct refresh unavailable"
    /// behandeln. Spec docs/spec/ofp-refresh-during-boarding.md §6.1.
    flight_id: String,
    /// v0.7.8 v1.5: `Bid.flight.callsign` falls phpVMS das fuellt
    /// (z.B. "CFG4TK"). Match-Kandidat 3 in
    /// `ofp_matches_active_flight`. None wenn phpVMS-VA das Feld nicht
    /// nutzt. Spec §6.1.2.
    bid_callsign: Option<String>,
    /// v0.7.8 v1.5: `Profile.callsign` des Piloten (= persoenliches
    /// Suffix wie "4TK"). Match-Kandidaten 4 ("CFG4TK") + 5 ("4TK") in
    /// `ofp_matches_active_flight`. None wenn pre-2024-phpVMS-Profile
    /// ohne callsign-Feld. Spec §6.1.2.
    pilot_callsign: Option<String>,
    started_at: DateTime<Utc>,
    /// ICAO of the operating airline (e.g. "DLH"). Combined with
    /// `flight_number` to produce the full callsign on the dashboard
    /// ("DLH155" instead of just "155"). Empty string when unknown.
    airline_icao: String,
    /// v0.4.0: phpVMS-hosted Airline-Logo-URL (von `bid.flight.airline.logo`,
    /// z.B. `https://german-sky-group.eu/storage/uploads/airlines/4/.../logo.png`).
    /// Discord-Webhook-Embeds nutzen das als großes Bild unten —
    /// Pilot sieht in seinem Channel das Logo der gerade geflogenen
    /// Airline ohne dass wir es im Repo selbst hosten müssen.
    /// `None` wenn die VA das Logo-Feld nicht gepflegt hat.
    airline_logo_url: Option<String>,
    /// Registration phpVMS assigned to this flight (e.g. "D-AIUV").
    /// Looked up via `get_aircraft(bid.flight.aircraft_id)` at start
    /// time. Compared against the live `ATC ID` SimVar in the activity
    /// log so the pilot sees immediately if they loaded the wrong tail
    /// number in MSFS. Empty string when unknown (fresh-PIREP / disk-
    /// resume edge cases where we couldn't match a bid).
    planned_registration: String,
    /// Aircraft ICAO der Bid (z.B. "B738"). Wird im PIREP-Custom-Field
    /// "Aircraft Type" rausgegeben damit der VA-Admin auf der phpVMS-
    /// Detail-Seite ohne extra Lookup weiß was geflogen wurde.
    /// v0.3.0: vorher nur `planned_registration`, neuer `aircraft_icao`
    /// kommt aus dem gleichen `client.get_aircraft(id)`-Call.
    aircraft_icao: String,
    /// Aircraft-Name (z.B. "Boeing 737-800"). Komplettiert die ICAO-
    /// Anzeige. Empty wenn nicht ermittelbar.
    aircraft_name: String,
    flight_number: String,
    dpt_airport: String,
    arr_airport: String,
    /// Final loads (per fare-class id) captured at flight start so we can
    /// include them in the filed PIREP — even if the bid is gone by then.
    fares: Vec<(i64, i32)>,
    /// Mutable running stats updated by the streamer task.
    stats: Mutex<FlightStats>,
    stop: AtomicBool,
    /// True until the resume banner is dismissed (confirmed or cancelled).
    /// Drives the resume modal on the dashboard.
    was_just_resumed: AtomicBool,
    /// Compare-and-swap guard for `spawn_position_streamer`. Several UI paths
    /// (resume confirm, StrictMode double-mount, retry on transient error)
    /// could end up calling spawn more than once for the same ActiveFlight;
    /// this flag ensures only ONE streamer task is ever live per flight.
    streamer_spawned: AtomicBool,
    /// Set once we've detected that phpVMS soft-deleted the PIREP under us
    /// (any live POST endpoint returning 404). Idempotency guard so the
    /// "PIREP cancelled remotely" activity entry / UI event fire exactly
    /// once even if positions and the heartbeat both get 404s in the
    /// same cycle.
    cancelled_remotely: AtomicBool,
    /// v0.6.0: Memory-Outbox für phpVMS-Position-POSTs. Streamer-Tick
    /// pusht jede Position rein (= ein schneller Mutex-Push, blockt nie).
    /// `spawn_phpvms_position_worker` zieht periodisch raus und batched.
    /// Bei Quit wird der Inhalt ins file-backed `position_queue.json`
    /// persistiert damit ein Restart die ungesendeten Punkte nachholt.
    /// **Ersetzt das alte Critical-Window + Drain-Pattern komplett.**
    position_outbox: Mutex<std::collections::VecDeque<api_client::PositionEntry>>,
    /// v0.6.0: Guard fuer `spawn_phpvms_position_worker` (analog zu
    /// streamer_spawned). Wird im worker-loop selbst gesetzt damit
    /// nicht mehrere parallele Worker laufen.
    phpvms_worker_spawned: AtomicBool,
    /// v0.18.x: Guard fuer `spawn_touchdown_sampler` (analog zu
    /// streamer_spawned/phpvms_worker_spawned). Fehlte bisher — `flight_
    /// resume_confirm` ist ueber die LAN-Fernbedienung (remote/bridge.rs)
    /// erreichbar, und der Frontend-Doppelklick-Schutz (`confirmingRef` in
    /// ResumeFlightBanner.tsx) lebt nur im Hauptfenster, NICHT im separaten
    /// React-Baum der Remote-Weboberflaeche auf einem Tablet/2. PC. Ein
    /// Pilot mit aktivierter Fernbedienung (Thomas K., 05.07.2026) haette
    /// so zwei parallele Touchdown-Sampler fuer denselben Flug bekommen
    /// koennen — jeder mit eigenem lokalem `prev_in_air`-Zustand, beide
    /// schreiben unkoordiniert in dieselben `stats`-Felder (peak_vs_fpm,
    /// sampler_touchdown_at, …). Ohne diesen Guard waere das der einzige
    /// der drei Resume-Spawns ohne Schutz geblieben.
    touchdown_sampler_spawned: AtomicBool,
    /// v0.6.2 — Connection-Health-State zum phpVMS-Server. Vom phpVMS-
    /// Worker gesetzt nach jedem POST:
    ///   - 0 = Live (letzter POST war Erfolg)
    ///   - 1 = Failing (letzter POST hat geschlagen / timeout)
    /// Frontend nutzt das zusammen mit `queued_position_count` für eine
    /// klare 3-Status-Indikator-Anzeige (Live / Sync / Offline) — vor
    /// v0.6.2 zeigte der Indikator „queued offline" für jeden Backlog,
    /// auch ohne echten Connection-Loss → Pilot-Verwirrung.
    connection_state: std::sync::atomic::AtomicU8,

    /// v0.8.0 VPS-Navdata — geladene Airport-Daten (dep/arr/alt) für
    /// die Runway-Awareness-Features. Beim Flugstart parallel vom VPS
    /// gezogen (`fetch_navdata_for_flight`). Cache-Lifetime = Lifetime
    /// des aktiven Flugs (= bis PIREP filed). HashMap-Key ist das ICAO
    /// in UPPERCASE. Empty wenn VPS nicht erreichbar — die
    /// LandingRecord-Felder bleiben dann None und der Pilot-Client
    /// fällt automatisch auf OurAirports zurück
    /// (`runway::lookup_runway_with_fallback`).
    ///
    /// Aktiver Cycle steht zusätzlich in `navdata_cycle` — wird ins
    /// Activity-Log + TouchdownPayload weitergegeben.
    navdata: Mutex<NavdataCache>,
}

/// Pro-Flug-Cache der NavAirport-Daten. Default = leer = OurAirports-
/// Fallback aktiv für alle ICAOs.
#[derive(Debug, Default)]
struct NavdataCache {
    /// ICAO (uppercase) → NavAirport.
    airports: std::collections::HashMap<String, aeroacars_mqtt::navdata::NavAirport>,
    /// AIRAC-Cycle ("2604"). Wird beim ersten erfolgreichen Fetch
    /// gesetzt — alle weiteren Fetches im selben Flug schreiben denselben
    /// Wert (Recorder garantiert dass GET /airport/X dieselbe Cycle-ID
    /// liefert wie der zuletzt aktivierte Cycle).
    cycle: Option<String>,
}

impl NavdataCache {
    fn get(&self, icao: &str) -> Option<&aeroacars_mqtt::navdata::NavAirport> {
        self.airports.get(&icao.trim().to_uppercase())
    }
}

/// v0.8.0: Lädt Navdata für bis zu 3 ICAOs (dep/arr/alt) parallel vom
/// VPS und schreibt sie in `flight.navdata`. Best-effort — bei Netzwerk-
/// Fehlern bleibt der Cache leer und der Pilot-Client fällt auf
/// OurAirports zurück. Wird vom flight_start-Pfad in einer Background-
/// Task aufgerufen, blockiert den Flugstart nicht.
///
/// Behavior:
///   * Skippt leere ICAO-Strings (z.B. wenn der Bid keinen Alternate hat).
///   * Dedupe per uppercase-ICAO (dep == arr im local-pattern-flight).
///   * 404 vom VPS → ICAO nicht im aktiven Cycle → silently skip.
///   * 401/403 → loggt warn! (Token fehlt/invalid) — alle weiteren
///     Fetches landen ebenfalls in 401, restliche ICAOs werden trotzdem
///     versucht damit der Logger sie alle protokolliert.
///   * Network-Fehler → loggt warn!, restliche ICAOs werden trotzdem versucht.
///
/// `auth_token` ist der Pilot-Bearer-Token (typisch
/// `ProvisionResponse.password` aus dem MQTT-Provisioning). `None` ist
/// nur für Tests/Mocks vorgesehen — gegen den echten VPS liefert das
/// 401 und der OurAirports-Fallback greift transparent.
async fn fetch_navdata_for_flight(
    app: AppHandle,
    flight: Arc<ActiveFlight>,
    icaos: Vec<String>,
    base_override: Option<String>,
    auth_token: Option<String>,
) {
    let mut wanted: Vec<String> = icaos
        .into_iter()
        .map(|s| s.trim().to_uppercase())
        .filter(|s| !s.is_empty() && s.len() == 4)
        .collect();
    wanted.sort();
    wanted.dedup();
    if wanted.is_empty() {
        return;
    }

    // v0.8.0: parallel den Aircraft-Aliases-Fetch starten. Damit ist
    // der AppState-Cache spätestens am Touchdown-Edge warm — und ein
    // frisch vom VA-Admin im Webapp-Tab hinzugefügter Alias greift
    // beim nächsten Flight ohne Pilot-Client-Restart.
    let aliases_handle = {
        let app_aliases = app.clone();
        let base_aliases = base_override.clone();
        let token_aliases = auth_token.clone();
        tokio::spawn(async move {
            fetch_aircraft_aliases_into_state(app_aliases, base_aliases, token_aliases).await;
        })
    };

    let mut handles = Vec::with_capacity(wanted.len());
    for icao in wanted {
        let base = base_override.clone();
        let token = auth_token.clone();
        handles.push(tokio::spawn(async move {
            let res = aeroacars_mqtt::navdata::get_airport(
                &icao,
                base.as_deref(),
                token.as_deref(),
            )
            .await;
            (icao, res)
        }));
    }

    for h in handles {
        let (icao, res) = match h.await {
            Ok(t) => t,
            Err(e) => {
                tracing::warn!(error = %e, "navdata fetch task join failed");
                continue;
            }
        };
        match res {
            Ok(airport) => {
                let cycle = airport.cycle.clone();
                let mut cache = flight.navdata.lock().expect("navdata lock");
                cache.airports.insert(icao.clone(), airport);
                if cache.cycle.is_none() {
                    cache.cycle = Some(cycle.clone());
                }
                tracing::info!(
                    icao = %icao,
                    cycle = %cycle,
                    "navdata: VPS-Daten geladen"
                );
            }
            Err(aeroacars_mqtt::navdata::NavdataError::NotFound(_)) => {
                tracing::debug!(
                    icao = %icao,
                    "navdata: ICAO nicht im aktiven Cycle, OurAirports-Fallback aktiv"
                );
            }
            Err(e) => {
                tracing::warn!(
                    icao = %icao,
                    error = %e,
                    "navdata: VPS-Fetch fehlgeschlagen, OurAirports-Fallback"
                );
            }
        }
    }

    // Wait for the aliases-fetch to settle so any debug-logs are
    // ordered before the Activity-Log line below. Join errors are
    // harmless — the cache stays empty and the hardcoded table covers.
    let _ = aliases_handle.await;

    // Surface the final state in the Activity-Log so the pilot sees
    // which source backs the runway assessment for this flight.
    let (cycle, loaded): (Option<String>, Vec<String>) = {
        let cache = flight.navdata.lock().expect("navdata lock");
        (
            cache.cycle.clone(),
            cache.airports.keys().cloned().collect(),
        )
    };
    let state = app.state::<AppState>();
    if let Some(c) = cycle.as_deref() {
        let mut sorted = loaded.clone();
        sorted.sort();
        log_activity(
            &state,
            ActivityLevel::Info,
            format!("Navdata AIRAC {} geladen für {}", c, sorted.join("/")),
            None,
        );
    } else {
        log_activity(
            &state,
            ActivityLevel::Warn,
            "Navdata: OurAirports-Fallback aktiv (VPS nicht erreichbar)".to_string(),
            None,
        );
    }
}

/// v0.8.0: Lädt die VPS-managed Aircraft-Aliases und schreibt sie in
/// `AppState.aircraft_aliases_vps`. Best-effort — bei Netzwerk-Fehlern
/// bleibt nur die hardcoded `aircraft_aliases`-Tabelle aktiv. Wird
/// neben dem navdata-Fetch beim flight_start aufgerufen damit ein
/// frisch im VPS-Admin-Tab hinzugefügter Alias beim nächsten Flight
/// greift ohne App-Restart.
async fn fetch_aircraft_aliases_into_state(
    app: AppHandle,
    base_override: Option<String>,
    auth_token: Option<String>,
) {
    let res = aeroacars_mqtt::navdata::get_aircraft_aliases(
        base_override.as_deref(),
        auth_token.as_deref(),
    )
    .await;
    match res {
        Ok(list) => {
            let state = app.state::<AppState>();
            let mut cache = state
                .aircraft_aliases_vps
                .lock()
                .expect("aircraft_aliases_vps lock");
            cache.clear();
            for entry in list {
                let icao_up = entry.icao.trim().to_uppercase();
                let aliases: Vec<String> = entry
                    .aliases
                    .into_iter()
                    .map(|a| a.alias.trim().to_uppercase())
                    .filter(|s| !s.is_empty())
                    .collect();
                if !aliases.is_empty() {
                    cache.insert(icao_up, aliases);
                }
            }
            tracing::info!(
                count = cache.len(),
                "aircraft_aliases: VPS-Liste geladen"
            );
        }
        Err(e) => {
            tracing::debug!(
                error = %e,
                "aircraft_aliases: VPS-Fetch fehlgeschlagen, nur hardcoded Tabelle aktiv"
            );
        }
    }
}

/// Helper für die ActiveFlight-Init-Sites: spawnt den Navdata-Fetch in
/// einer Background-Task ohne den flight_start zu blockieren. Token
/// kommt aus dem MQTT-Provisioning (`MQTT_KEYRING_PASSWORD`) — dasselbe
/// Token autoirisiert auch den MQTT-Login. Bei Token-Fehlen sendet der
/// Fetcher kein Auth-Header und lädt damit bei keinem produktiven VPS
/// (= 401), aber der OurAirports-Fallback greift transparent.
///
/// `icaos` enthält die zu ladenden Airports (typisch dep/arr/alt).
/// Leere Strings + Nicht-4-Zeichen-ICAOs werden gefiltert.
///
/// **Per-ICAO Idempotency-Guard** (v0.8.0 QS): es werden nur die
/// ICAOs gefetcht, die nicht bereits im Cache sind. So bleibt der
/// Helper safe to call mehrfach — ein nach-Plan-Init-Aufruf der
/// erstmals den Alternate kennt, fetcht nur den Alternate; alle
/// schon geladenen Airports werden übersprungen.
fn spawn_navdata_fetch(app: &AppHandle, flight: &Arc<ActiveFlight>, icaos: Vec<String>) {
    // Normalize + filter against the per-flight cache. Only ICAOs that
    // are missing trigger an actual HTTP roundtrip.
    let missing: Vec<String> = {
        let cache = flight.navdata.lock().expect("navdata lock");
        let mut want: Vec<String> = icaos
            .into_iter()
            .map(|s| s.trim().to_uppercase())
            .filter(|s| !s.is_empty() && s.len() == 4)
            .filter(|s| !cache.airports.contains_key(s))
            .collect();
        want.sort();
        want.dedup();
        want
    };
    if missing.is_empty() {
        tracing::debug!(
            pirep_id = %flight.pirep_id,
            "navdata: all requested ICAOs already cached, skipping fetch"
        );
        return;
    }
    let icaos = missing;
    let token = secrets::load_api_key(MQTT_KEYRING_PASSWORD)
        .ok()
        .flatten();
    let app_clone = app.clone();
    let flight_arc = Arc::clone(flight);
    tokio::spawn(async move {
        fetch_navdata_for_flight(app_clone, flight_arc, icaos, None, token).await;
    });
}

/// v0.16.24: on-demand navdata fetch for the ACTUAL landing airport when
/// the touchdown runway correlation fell back to OurAirports (= the real
/// field wasn't in the per-flight navdata cache at touchdown — typically a
/// divert the approach pre-fetch didn't catch). Fires `spawn_navdata_fetch`
/// for that airport so the cache is (hopefully) warm by the time
/// `build_landing_record` re-correlates at PIREP-filing time
/// (finalize-with-best). Cheap + safe to call every tick: it only acts
/// while `runway_fallback_at_touchdown` is set, and `spawn_navdata_fetch`'s
/// per-ICAO guard makes a duplicate a no-op. Once the fetch lands the field
/// is cached, so even a re-run does nothing.
fn maybe_fetch_actual_landing_navdata(app: &AppHandle, flight: &Arc<ActiveFlight>) {
    let icao = {
        let mut stats = flight.stats.lock().expect("flight stats");
        if !stats.runway_fallback_at_touchdown {
            return;
        }
        let Some(icao) = stats.runway_correlation_icao.clone() else {
            return;
        };
        // One-shot per ICAO: a divert airport not in the active AIRAC cycle
        // returns 404 and never populates the cache, so without this guard
        // we'd re-issue the GET every tick until filing. Fire exactly once
        // per actual-landing ICAO. (Re-targets cleanly if the correlation
        // later resolves a different field — e.g. a touch-and-go elsewhere.)
        if stats.divert_ondemand_fetch_attempted.as_deref() == Some(icao.as_str()) {
            return;
        }
        stats.divert_ondemand_fetch_attempted = Some(icao.clone());
        icao
    };
    // Don't re-issue for the planned airport — that's already fetched at
    // flight start; a fallback there means a genuine VPS/cycle gap that a
    // retry won't fix.
    if icao != flight.arr_airport.trim().to_uppercase() {
        spawn_navdata_fetch(app, flight, vec![icao]);
    }
}

/// Connection-State-Konstanten für ActiveFlight.connection_state.
const CONN_STATE_LIVE: u8 = 0;
const CONN_STATE_FAILING: u8 = 1;
/// v0.7.17 (B-007): phpVMS hat 401/403 geliefert — Pilot-Account ist
/// gesperrt, inaktiv, oder der API-Key wurde server-side revoked. Der
/// Worker stoppt nach diesem State (kein endloses Retry-Spam mehr),
/// die UI zeigt einen klaren Hinweis. Pilot muss VA-Admin kontaktieren
/// und sich danach neu einloggen.
const CONN_STATE_BLOCKED: u8 = 2;

/// On-disk representation of an active flight, used for resume after a client
/// crash. Not the same as `ActiveFlight` because we only persist serializable,
/// non-Mutex fields.
#[derive(Debug, Clone, Serialize, Deserialize)]
struct PersistedFlight {
    pirep_id: String,
    bid_id: i64,
    /// v0.7.7: phpVMS-Flight-Identifier (siehe `ActiveFlight.flight_id`).
    /// `#[serde(default)]` damit pre-v0.7.7-Resume-Files weiter
    /// deserialisierbar bleiben — Default ist `String::new()`.
    #[serde(default)]
    flight_id: String,
    /// v0.7.8 v1.5: Bid.flight.callsign Persistenz fuer Resume.
    /// serde(default) → None bei pre-v0.7.8-Resume-Files.
    #[serde(default)]
    bid_callsign: Option<String>,
    /// v0.7.8 v1.5: Profile.callsign Persistenz fuer Resume.
    /// serde(default) → None bei pre-v0.7.8-Resume-Files.
    #[serde(default)]
    pilot_callsign: Option<String>,
    started_at: DateTime<Utc>,
    #[serde(default)]
    airline_icao: String,
    /// v0.4.0: phpVMS-Airline-Logo-URL (für Discord-Webhook-Embeds).
    /// `#[serde(default)]` damit Snapshots aus älteren Builds beim
    /// Resume nicht crashen — fehlendes Feld wird zu `None`.
    #[serde(default)]
    airline_logo_url: Option<String>,
    #[serde(default)]
    planned_registration: String,
    flight_number: String,
    dpt_airport: String,
    arr_airport: String,
    fares: Vec<(i64, i32)>,
    /// Snapshot of running flight statistics (distance, fuel, phase
    /// FSM state, captured timestamps). Written by the position
    /// streamer every `STATS_PERSIST_EVERY_TICKS` posts; read by
    /// `try_resume_flight` so a Tauri restart mid-flight doesn't lose
    /// fuel-burn or distance numbers — that was the root cause of the
    /// "0 distance / 0 fuel" PIREPs we saw before Phase H.4.
    #[serde(default)]
    stats: PersistedFlightStats,
}

/// Persistable subset of `FlightStats`. The activity-log edge-detector
/// state (`last_logged_*`) is intentionally NOT persisted — after a
/// resume we restart the diff detection cleanly.
#[derive(Debug, Clone, Default, Serialize, Deserialize)]
struct PersistedFlightStats {
    #[serde(default)]
    distance_nm: f64,
    #[serde(default)]
    position_count: u32,
    #[serde(default)]
    phase: FlightPhase,
    #[serde(default)]
    block_off_at: Option<DateTime<Utc>>,
    #[serde(default)]
    takeoff_at: Option<DateTime<Utc>>,
    #[serde(default)]
    landing_at: Option<DateTime<Utc>>,
    #[serde(default)]
    block_on_at: Option<DateTime<Utc>>,
    #[serde(default)]
    takeoff_weight_kg: Option<f64>,
    #[serde(default)]
    takeoff_fuel_kg: Option<f32>,
    /// v0.5.16: pitch / bank at takeoff (rotation moment).
    #[serde(default)]
    takeoff_pitch_deg: Option<f32>,
    #[serde(default)]
    takeoff_bank_deg: Option<f32>,
    #[serde(default)]
    landing_rate_fpm: Option<f32>,
    #[serde(default)]
    landing_g_force: Option<f32>,
    #[serde(default)]
    landing_pitch_deg: Option<f32>,
    /// v0.5.16: bank angle at touchdown for wing-strike detection.
    #[serde(default)]
    landing_bank_deg: Option<f32>,
    #[serde(default)]
    landing_speed_kt: Option<f32>,
    /// v0.5.17: groundspeed at touchdown.
    #[serde(default)]
    landing_groundspeed_kt: Option<f32>,
    #[serde(default)]
    landing_weight_kg: Option<f64>,
    #[serde(default)]
    landing_heading_deg: Option<f32>,
    #[serde(default)]
    landing_fuel_kg: Option<f32>,
    #[serde(default)]
    block_fuel_kg: Option<f32>,
    #[serde(default)]
    last_fuel_kg: Option<f32>,
    /// v0.16.10: FOB-Baseline für den Fuel-Used-Fallback (PMDG liefert
    /// FUEL TOTAL QUANTITY USED nicht — Live-Befund GLO4587). Persistiert
    /// damit Resume die Baseline behält; `#[serde(default)]` hält alte
    /// Resume-Files ladbar (None → Re-Latch beim ersten Tick).
    #[serde(default)]
    initial_fob_kg: Option<f32>,
    #[serde(default)]
    last_lat: Option<f64>,
    #[serde(default)]
    last_lon: Option<f64>,
    #[serde(default)]
    landing_peak_vs_fpm: Option<f32>,
    #[serde(default)]
    landing_peak_g_force: Option<f32>,
    /// v0.7.1 (Spec F4 + P2.2-D): Confidence + Source werden ATOMAR
    /// mit landing_rate_fpm via `finalize_landing_rate`-Helper gesetzt.
    /// Damit koennen sie nicht zum finalen PIREP-Wert auseinanderlaufen.
    /// "High" | "Medium" | "Low" | "VeryLow"
    #[serde(default)]
    landing_confidence: Option<String>,
    /// "vs_at_impact" | "smoothed_500ms" | "smoothed_1000ms" | "pre_flare_peak"
    #[serde(default)]
    landing_source: Option<String>,
    #[serde(default)]
    bounce_count: u8,
    #[serde(default)]
    landing_score: Option<LandingScore>,
    #[serde(default)]
    landing_score_announced: bool,
    #[serde(default)]
    dep_gate: Option<String>,
    #[serde(default)]
    arr_gate: Option<String>,
    #[serde(default)]
    approach_runway: Option<String>,
    #[serde(default)]
    cruise_peak_msl: Option<f32>,
    #[serde(default)]
    climb_peak_msl: Option<f32>,
    #[serde(default)]
    peak_altitude_ft: Option<f32>,
    #[serde(default)]
    aircraft_banner_logged: bool,
    // ---- Tier 1/2/3 (BeatMyLanding-aligned) touchdown extras ----
    #[serde(default)]
    touchdown_sideslip_deg: Option<f32>,
    #[serde(default)]
    touchdown_profile: Vec<TouchdownProfilePoint>,
    /// v0.15.24: the in-app live-map flown track ([lon,lat]), persisted so a
    /// mid-flight app restart keeps the pre-restart trail (flight_get_track
    /// returns the full track post-restore, not just the post-restart segment).
    #[serde(default)]
    track: Vec<[f64; 2]>,
    #[serde(default)]
    runway_match: Option<runway::RunwayMatch>,
    // v0.16.24 (QS-2 FIX B): persist the runway-correlation source/geometry so
    // a DIVERT survives a suspend/resume between touchdown and PIREP filing.
    // `save_active_flight` runs right after the touchdown dump; filing is the
    // later manual `flight_end`. Without these, an app restart in between reset
    // them to None/false → the finalize gate (`runway_source ==
    // OurAirportsFallback`) and the on-demand-fetch gate
    // (`runway_fallback_at_touchdown`) were both defeated and the divert filed
    // with coarse OurAirports geometry. `#[serde(default)]` keeps OLD persisted
    // blobs (saved before this change) deserializing cleanly — missing fields →
    // None/false → identical to today's pre-change resume behaviour (never
    // worse). On-plan is unaffected: the touchdown already stamps Navigraph, and
    // even if reset, the finalize gate's "not OurAirportsFallback → provisional
    // verbatim" is the correct no-op.
    #[serde(default)]
    runway_source: Option<runway::RunwaySource>,
    #[serde(default)]
    runway_nav_cycle: Option<String>,
    #[serde(default)]
    runway_nav_geometry: Option<aeroacars_mqtt::navdata::NavRunway>,
    #[serde(default)]
    runway_correlation_icao: Option<String>,
    #[serde(default)]
    runway_fallback_at_touchdown: bool,
    #[serde(default)]
    landing_lat: Option<f64>,
    #[serde(default)]
    landing_lon: Option<f64>,
    #[serde(default)]
    landing_heading_true_deg: Option<f32>,
    /// Headwind component at touchdown (knots). Positive = wind from
    /// the front (= reduces required ground roll). Negative = tailwind.
    /// Sourced from `AIRCRAFT WIND Z` (negated, since +Z is tailwind
    /// in MSFS body-axis convention).
    #[serde(default)]
    landing_headwind_kt: Option<f32>,
    /// Crosswind component at touchdown (knots). Positive = from the
    /// right side; negative = from the left. Sourced from
    /// `AIRCRAFT WIND X` (positive X is crosswind from right per MSFS).
    #[serde(default)]
    landing_crosswind_kt: Option<f32>,
    // ---- Landing Analyzer (Stage 1) ----
    #[serde(default)]
    approach_vs_stddev_fpm: Option<f32>,
    #[serde(default)]
    approach_bank_stddev_deg: Option<f32>,
    #[serde(default)]
    rollout_distance_m: Option<f64>,
    // ---- Landing Analyzer (Stage 2): SimBrief OFP plan ----
    #[serde(default)]
    planned_block_fuel_kg: Option<f32>,
    #[serde(default)]
    planned_burn_kg: Option<f32>,
    #[serde(default)]
    planned_reserve_kg: Option<f32>,
    #[serde(default)]
    planned_zfw_kg: Option<f32>,
    #[serde(default)]
    planned_tow_kg: Option<f32>,
    #[serde(default)]
    planned_ldw_kg: Option<f32>,
    #[serde(default)]
    planned_route: Option<String>,
    /// v0.15.x: Navlog-Fixes mit-persistieren, damit ein Resume die
    /// Map-Strecke (Wegpunkte) behält statt auf die Great-Circle-Linie zu fallen.
    #[serde(default)]
    planned_waypoints: Vec<api_client::RouteFix>,
    #[serde(default)]
    planned_alternate: Option<String>,
    // v0.3.0: MAX-Werte aus dem OFP für Overweight-Detection.
    #[serde(default)]
    planned_max_zfw_kg: Option<f32>,
    #[serde(default)]
    planned_max_tow_kg: Option<f32>,
    #[serde(default)]
    planned_max_ldw_kg: Option<f32>,
    // ---- Touch-and-Go + Go-Around tracking (v0.1.26) ----
    // Persisted so a Tauri restart mid-flight (or a planned resume
    // after the pilot closed the app for lunch) doesn't wipe the
    // training-flight audit trail. `pending_acars_logs` is NOT
    // persisted on purpose — it's a transient queue between FSM
    // tick and streamer tick; if the streamer didn't drain it
    // before shutdown, those log lines are simply lost. Resume
    // semantics for the GA detector: lowest_agl is preserved so a
    // pilot who quits the app on short final and resumes can still
    // get their GA correctly classified.
    #[serde(default)]
    touchdown_events: Vec<TouchdownEvent>,
    #[serde(default)]
    touch_and_go_pending_since: Option<DateTime<Utc>>,
    #[serde(default)]
    go_around_count: u32,
    #[serde(default)]
    lowest_agl_during_approach_ft: Option<f32>,
    #[serde(default)]
    go_around_climb_pending_since: Option<DateTime<Utc>>,
    // v0.7.17 (B-010): Descent-Dwell-Timer persistieren damit Resume
    // mitten in einem Climb-Trim-Spike nicht den Timer verliert.
    #[serde(default)]
    descent_pending_since: Option<DateTime<Utc>>,
    // v0.5.11 holding-pattern tracking
    #[serde(default)]
    holding_pending_since: Option<DateTime<Utc>>,
    #[serde(default)]
    holding_exit_pending_since: Option<DateTime<Utc>>,
    #[serde(default)]
    previous_phase_before_holding: Option<FlightPhase>,

    // v0.5.45: Sampler-State persistieren damit App-Resume nach einem
    // bereits-detektierten Touchdown nicht ein zweites Mal capturet
    // (User-Report GSG 302 X-Plane DA40 Bush-Strip 2026-05-09: 1×
    // flight_resumed nach erstem TD → Sampler hat beim echten Landing
    // nochmal gefeuert weil Guard-State nach Resume None war).
    #[serde(default)]
    sampler_touchdown_at: Option<DateTime<Utc>>,
    #[serde(default)]
    sampler_takeoff_at: Option<DateTime<Utc>>,
    #[serde(default)]
    touchdown_window_dumped_at: Option<DateTime<Utc>>,
    #[serde(default)]
    landing_score_finalized: bool,
    /// v0.7.7: aktuelle SimBrief-OFP-ID — siehe FlightStats. `#[serde(default)]`
    /// damit pre-v0.7.7-Resume-Files weiter parseable bleiben.
    #[serde(default)]
    simbrief_ofp_id: Option<String>,
    /// v0.7.7: raw SimBrief `<params><time_generated>` — siehe FlightStats.
    #[serde(default)]
    simbrief_ofp_generated_at: Option<String>,
    /// Spec sim-disconnect-auto-resume F2 (Pause-Akkumulator):
    /// Summe aller Pause-Sekunden seit Flugstart. `#[serde(default)]`
    /// damit pre-Spec `active_flight.json` weiter ladbar bleibt — alte
    /// Resume-Files defaulten auf 0 (keine bekannten Pausen, ist OK).
    #[serde(default)]
    pause_total_duration_secs: i64,
    /// Spec sim-disconnect-auto-resume F2: Liste der einzelnen Pause-
    /// Bloecke (Audit-/Debug-Daten). `#[serde(default)]` damit alte
    /// Resume-Files weiter laden — defaulten auf leeren Vec.
    #[serde(default)]
    pause_segments: Vec<PauseSegment>,
    /// Spec v0.7.15 F5/F6: aktuelle Pause-Reason fuer App-Restart-
    /// Persistenz. `#[serde(default)]` → None bei pre-v0.7.15 Files.
    #[serde(default)]
    current_pause_reason: Option<PauseReason>,
    /// v0.16.12 (#phase-v2): geplante Cruise-Altitude (ft) — persistiert,
    /// damit die Schatten-Engine nach einem Resume ihren `cruise_ref`
    /// behält. `#[serde(default)]` → None bei pre-v0.16.12-Files.
    #[serde(default)]
    planned_cruise_alt_ft: Option<f64>,
    /// v0.16.12 (#phase-v2): akkumulierte Schatten-Divergenz-Sekunden —
    /// persistiert, damit das Flug-Aggregat einen App-Restart überlebt.
    #[serde(default)]
    shadow_divergence_secs: f64,
}

