#[derive(Debug, Clone, Serialize, Deserialize)]
struct SiteConfig {
    url: String,
}

#[derive(Serialize)]
pub struct LoginResult {
    profile: Profile,
    base_url: String,
}

/// Errors returned to the UI in a serializable shape.
/// `code` is a stable, machine-readable identifier the frontend uses for i18n.
/// `details` carries optional structured payload (e.g. list of missing
/// validation fields) so the UI can render a richer error than just a string.
#[derive(Debug, Serialize)]
pub struct UiError {
    // v0.16.0 (#LAN-Remote): `pub(crate)` so the `remote` module can read
    // `code`/`message` when building the HTTP 422 `{code,message}` body
    // for the LAN bridge. Still serializes identically to the Tauri IPC
    // reject shape.
    pub(crate) code: String,
    pub(crate) message: String,
    #[serde(skip_serializing_if = "Option::is_none")]
    details: Option<serde_json::Value>,
}

impl UiError {
    fn new(code: impl Into<String>, message: impl Into<String>) -> Self {
        Self {
            code: code.into(),
            message: message.into(),
            details: None,
        }
    }

    fn with_details(mut self, details: serde_json::Value) -> Self {
        self.details = Some(details);
        self
    }
}

impl From<ApiError> for UiError {
    fn from(err: ApiError) -> Self {
        Self {
            code: err.code().to_string(),
            message: err.to_string(),
            details: None,
        }
    }
}

// ---- Helpers ----

/// Translate a flaps detent (0..5) into the Airbus-style label most
/// virtual airlines (and the activity-log readers) recognise. ONLY
/// used when no PMDG snapshot is available — for PMDG aircraft we
/// take the cockpit-exact Boeing label directly from
/// `pmdg.flap_handle_label` (see flap-detent change-detection block).
fn detent_label(detent: u8) -> &'static str {
    match detent {
        0 => "UP",
        1 => "1",
        2 => "1+F",
        3 => "2",
        4 => "3",
        _ => "FULL",
    }
}

/// Order Boeing flap-handle labels for direction-of-change detection.
/// Boeing 737 detents: UP/1/2/5/10/15/25/30/40 (rank 0..8).
/// Boeing 777 detents: UP/1/5/15/20/25/30 (rank 0..6, sharing the
/// numeric ordering with NG3 — both share the rank table since UP=0,
/// 1=1, 5=3, 15=5 etc., and the comparison only cares about
/// monotonicity, not exact values).
fn boeing_detent_rank(label: &str) -> u8 {
    match label {
        "UP" => 0,
        "1" => 1,
        "2" => 2,
        "5" => 3,
        "10" => 4,
        "15" => 5,
        "20" => 6,
        "25" => 7,
        "30" => 8,
        "40" => 9,
        _ => 0,
    }
}

// (Old position-derived sideslip helper deleted — replaced by direct
// `atan2(VEL_BODY_X, VEL_BODY_Z)` computation at the touchdown edge,
// matching GEES. The native body-frame velocities are accurate to
// the floating-point precision MSFS reports them at, no need to
// reconstruct anything from successive lat/lon.)

/// Push the current snapshot's V/S + bank into the approach buffer.
/// Called every step_flight tick during Approach + Final phases. The
/// buffer is capped at APPROACH_BUFFER_MAX so a 30-min hold doesn't
/// blow up memory; oldest entries get dropped first.
/// v0.5.25: erweitertes Approach-Sample mit allen Feldern die für
/// korrekte Stable-Approach-Gate-Analyse gebraucht werden:
///   * `agl_ft`: für Window-Filter (= nur AGL ≤ 1000 ft zählt fuer
///     den Stable-Approach-Gate-Score, ueber 1000 ft ist Vectoring
///     legitim und sollte nicht Pilot-bestrafen)
///   * `gs_kt`: für Soll-Glide-Slope-Berechnung
///     (target_vs ≈ gs_kt × 5.31 für 3°-Glide-Slope)
///   * `selected_runway`: für Late-RWY-Change-Detection. Wenn ATC
///     mid-final die Bahn wechselt, war Pilot zu Maneuver gezwungen,
///     das ist nicht "instabil"
///
/// Andere Naming-Konvention als das `ApproachSample` aus dem
/// `storage`-Crate (welches nur (vs_fpm, bank_deg) ist und an die
/// PIREP-Notes-Sparkline serialisiert wird) — dieses hier ist das
/// reichere internal Buffer-Sample.
#[derive(Debug, Clone)]
pub struct ApproachBufferSample {
    pub at: DateTime<Utc>,
    pub agl_ft: f32,
    pub msl_ft: f32,
    pub gs_kt: f32,
    pub ias_kt: f32,
    pub vs_fpm: f32,
    pub bank_deg: f32,
    pub heading_true_deg: f32,
    pub gear_position: f32,
    pub flaps_position: f32,
    pub selected_runway: Option<String>,
    pub stall_warning: bool,
}

fn push_approach_sample(stats: &mut FlightStats, snap: &SimSnapshot, now: DateTime<Utc>) {
    stats.approach_buffer.push_back(ApproachBufferSample {
        // Tick-Zeit vom Caller (step_flight_at) — nicht Utc::now(): sonst
        // trügen Replay-Läufe Wall-Clock-Timestamps im Approach-Buffer,
        // während landing_at historisch ist → approach_buffer_window
        // fände ein leeres Fenster (QS-Runde 1, Replay-Fidelity).
        at: now,
        agl_ft: snap.altitude_agl_ft as f32,
        msl_ft: snap.altitude_msl_ft as f32,
        gs_kt: snap.groundspeed_kt,
        ias_kt: snap.indicated_airspeed_kt,
        vs_fpm: snap.vertical_speed_fpm,
        bank_deg: snap.bank_deg,
        heading_true_deg: snap.heading_deg_true,
        gear_position: snap.gear_position,
        flaps_position: snap.flaps_position,
        selected_runway: snap.selected_runway.clone(),
        stall_warning: snap.stall_warning,
    });
    while stats.approach_buffer.len() > APPROACH_BUFFER_MAX {
        stats.approach_buffer.pop_front();
    }
}

/// v0.16.6: phase-independent gate for `push_approach_sample` — ONE central
/// per-tick call in `step_flight` (right before the phase `match`) replaces
/// the two arm-local calls that used to sit at the top of the Approach and
/// Final arms.
///
///   * `Approach` / `Final` → ALWAYS push, exactly like the old arm-local
///     calls (they were the unconditional first statement of each arm and
///     nothing executes between the central call site and the old ones, so
///     cadence and ordering are bit-identical for normal flights).
///   * Any other phase → push only on a genuine descending low-level
///     segment: the flight has been airborne, is currently airborne, is
///     below 2000 ft AGL and sinking faster than −100 fpm. Short/low VFR
///     bush hops (GSG312 97OG) land via the 50 Hz sampler while the FSM is
///     still stuck in Takeoff/Climb — without this the approach buffer
///     stayed empty and the stability stats (approach_vs_stddev /
///     stable_* flags) were silently missing from the PIREP. Level or
///     climbing low-level flight does NOT sample (V/S gate); the
///     sampler-path evaluation additionally windows the buffer to the last
///     `SAMPLER_STABILITY_WINDOW_SECS` before touchdown so a long low-level
///     cruise can't poison the gate stats anyway.
fn should_push_approach_sample(
    phase: FlightPhase,
    was_airborne: bool,
    on_ground: bool,
    agl_ft: f64,
    vs_fpm: f32,
) -> bool {
    matches!(phase, FlightPhase::Approach | FlightPhase::Final)
        || (was_airborne && !on_ground && agl_ft < 2000.0 && vs_fpm < -100.0)
}

/// Track the lowest AGL observed during the current Approach/Final
/// segment. The go-around detector compares the *current* AGL against
/// this minimum to decide whether a sustained climb-back has begun.
///
/// Reset to `None` when a go-around is classified (climb starts a
/// fresh approach window) and when the FSM exits Final into Landing
/// (a successful touchdown invalidates the approach minimum).
fn update_lowest_approach_agl(stats: &mut FlightStats, snap: &SimSnapshot) {
    let agl = snap.altitude_agl_ft as f32;
    // Only track positive AGL — a brief negative reading from a sim
    // glitch (terrain mesh hiccup) would poison the minimum and make
    // every subsequent sample look like a 200 ft go-around climb.
    if agl < 0.0 {
        return;
    }
    stats.lowest_agl_during_approach_ft = Some(
        stats
            .lowest_agl_during_approach_ft
            .map_or(agl, |prev| prev.min(agl)),
    );
}

/// Detect a go-around in progress: aircraft has climbed
/// `GO_AROUND_AGL_RECOVERY_FT` above the lowest AGL seen during this
/// approach, sustained `GO_AROUND_DWELL_SECS` of positive V/S above
/// `GO_AROUND_MIN_VS_FPM`, while airborne with engines running.
///
/// Returns `Some(FlightPhase::Climb)` when classified — the caller
/// should swap `next_phase` to that value so the FSM bumps back to
/// Climb. Side effects on confirmation: bumps `stats.go_around_count`,
/// pushes a human-readable line into `stats.pending_acars_logs`,
/// clears the lowest-AGL tracker (next descent starts a fresh
/// window), and clears the dwell timer.
fn check_go_around(
    stats: &mut FlightStats,
    snap: &SimSnapshot,
    now: DateTime<Utc>,
) -> Option<FlightPhase> {
    let lowest = stats.lowest_agl_during_approach_ft?;
    let agl = snap.altitude_agl_ft as f32;
    // Need at least *some* descent to have happened — otherwise a
    // pilot intercepting the glideslope from above would trip the
    // detector the moment we entered Approach.
    if lowest > 1500.0 {
        return None;
    }
    let conds = agl > lowest + GO_AROUND_AGL_RECOVERY_FT
        && snap.vertical_speed_fpm > GO_AROUND_MIN_VS_FPM
        && !snap.on_ground
        && snap.engines_running > 0;
    if conds {
        let pending = stats.go_around_climb_pending_since.get_or_insert(now);
        if (now - *pending).num_seconds() >= GO_AROUND_DWELL_SECS {
            stats.go_around_count = stats.go_around_count.saturating_add(1);
            tracing::info!(
                count = stats.go_around_count,
                agl_ft = agl,
                lowest_ft = lowest,
                vs_fpm = snap.vertical_speed_fpm,
                "go-around classified — phase reverting to Climb"
            );
            stats.pending_acars_logs.push(format!(
                "Go-around #{} at {:.0} ft AGL (V/S {:.0} fpm)",
                stats.go_around_count, agl, snap.vertical_speed_fpm
            ));
            stats.lowest_agl_during_approach_ft = None;
            stats.go_around_climb_pending_since = None;
            // v0.5.11: reset climb_peak_msl so the missed-approach
            // climb back up tracks fresh peaks. Without this, the
            // prior peak (the cruise altitude) stays as reference,
            // and the moment the aircraft descends back through it
            // for the second approach attempt, the low-altitude
            // Climb→Descent trigger could fire prematurely against
            // a stale peak.
            stats.climb_peak_msl = None;
            return Some(FlightPhase::Climb);
        }
    } else {
        // Conditions broke — reset dwell so the next sustained climb
        // starts a fresh timer. Without this, brief bumps would
        // accumulate seconds and falsely confirm the go-around.
        stats.go_around_climb_pending_since = None;
    }
    None
}

/// v0.7.17 (B-010): Climb → Descent Transition Decision.
///
/// Bug-Symptom (GSG 105 Cessna LDDU→LDSP, X-Plane 12):
/// ```text
/// 17:49:35  Climb→Descent    AGL 3575 ft
/// 17:49:41  Descent→Approach AGL 3540 ft   (nur 6 s Descent!)
/// ```
/// Ein einzelner Turbulenz-/Trim-Spike kippte single-tick die FSM.
/// AGL stieg sogar zwischen zwei Phasen-Wechseln — physikalisch
/// unmoeglich fuer einen echten Descent.
///
/// **Fix:** zwei orthogonale Anpassungen:
///
/// 1. **Dwell-Timer:** Descent-Bedingung muss `DESCENT_DWELL_SECS`
///    durchgehend halten bevor wir die FSM umschalten. Bricht die
///    Bedingung zwischendrin → Timer reset.
///
/// 2. **Light-GA-Schwellen:** Wenn `total_weight_kg < LIGHT_GA_MTOM_KG`
///    (= unter 5700 kg, CS-23-Klasse) → groesszuegigere
///    `lost_from_peak`-Schwellen (1000/1200 statt 500/800 ft). Cessna
///    im 1500-ft-Pattern verliert leicht 300-500 ft auf einem Sightseeing-
///    Leg — das ist kein Descent.
///
/// Returns `Some(FlightPhase::Descent)` wenn beide Bedingungen erfuellt
/// sind (Triggerung + Dwell durchgehalten). Side-effect: setzt /
/// loescht `stats.descent_pending_since`.
fn check_descent_transition(
    stats: &mut FlightStats,
    snap: &SimSnapshot,
    now: DateTime<Utc>,
    lost_from_peak: f32,
) -> Option<FlightPhase> {
    let is_light_ga = snap
        .total_weight_kg
        .map(|w| w < LIGHT_GA_MTOM_KG)
        .unwrap_or(false);
    let low_alt_thresh = if is_light_ga { 1000.0 } else { 500.0 };
    let near_ground_thresh = if is_light_ga { 1200.0 } else { 800.0 };
    let standard_tod = snap.vertical_speed_fpm < -500.0
        && lost_from_peak > 200.0;
    let low_altitude_descent = snap.vertical_speed_fpm < -100.0
        && snap.altitude_agl_ft < 3000.0
        && lost_from_peak > low_alt_thresh;
    let near_ground_descent = snap.altitude_agl_ft < 2000.0
        && lost_from_peak > near_ground_thresh
        && snap.vertical_speed_fpm < 0.0;
    let descent_conds = standard_tod || low_altitude_descent || near_ground_descent;
    if descent_conds {
        let pending = stats.descent_pending_since.get_or_insert(now);
        if (now - *pending).num_seconds() >= DESCENT_DWELL_SECS {
            stats.descent_pending_since = None;
            return Some(FlightPhase::Descent);
        }
        None
    } else {
        // Bedingung gebrochen — Timer reset damit der naechste sustained
        // Sink-Run einen frischen 15-s-Countdown bekommt.
        stats.descent_pending_since = None;
        None
    }
}

/// En-Route-Versöhner: Eignungs-Prüfung (rein, testbar) — dürfen dieses
/// v1/v2-Phasen-Paar überhaupt versöhnt werden? Siehe Doc an
/// `ENROUTE_RECONCILE_DWELL_SECS` für die Gesamt-Mechanik.
///
/// * v1 muss in einer Luft-Phase stehen — `Holding` ausgenommen: v2
///   modelliert es bewusst nicht (dokumentierter Diff), dort DARF v1
///   abweichen. Boden-/Terminal-Phasen ebenfalls nicht: dort ist v1
///   autoritativ (v2 synct sich 1:1 von ihr).
/// * v2 muss selbst im Luft-Band oder auf `Landing` stehen — `Landing`
///   ist v2s Ground-Evidenz-Selbstbeförderung (v0.19.1) und genau der
///   Endzustand, in den eine durchgehend festgehangene v1 gezogen werden
///   muss, damit ihre eigene Landing→TaxiIn→BlocksOn→Arrived-Kette
///   normal weiterlaufen kann. Alles andere (Preflight etc.) wäre bei
///   einer luft-phasigen v1 ein Rückwärts-Sync und ist tabu.
/// * Gleichstand ist keine Divergenz.
fn enroute_reconcile_eligible(v1: FlightPhase, v2: FlightPhase) -> bool {
    let v1_air = matches!(
        v1,
        FlightPhase::Climb
            | FlightPhase::Cruise
            | FlightPhase::Descent
            | FlightPhase::Approach
            | FlightPhase::Final
    );
    let v2_target = matches!(
        v2,
        FlightPhase::Climb
            | FlightPhase::Cruise
            | FlightPhase::Descent
            | FlightPhase::Approach
            | FlightPhase::Final
            | FlightPhase::Landing
    );
    v1_air && v2_target && v1 != v2
}

/// Position im natürlichen Flugbogen für die Zug-Richtungs-Frage des
/// En-Route-Versöhners (vorwärts = kürzerer Dwell, rückwärts = längerer —
/// siehe [`ENROUTE_RECONCILE_DWELL_SECS`]). `None` für Phasen außerhalb
/// des Bogens — der Aufrufer behandelt jede Richtung, die sich nicht aus
/// zwei gültigen Rängen ergibt, als "rückwärts" (= konservativer, langer
/// Dwell). Hinter [`enroute_reconcile_eligible`] kommt das nicht vor.
fn enroute_phase_rank(p: FlightPhase) -> Option<u8> {
    match p {
        FlightPhase::Climb => Some(0),
        FlightPhase::Cruise => Some(1),
        FlightPhase::Descent => Some(2),
        FlightPhase::Approach => Some(3),
        FlightPhase::Final => Some(4),
        FlightPhase::Landing => Some(5),
        _ => None,
    }
}

/// Zieht v2 VORWÄRTS im Flugbogen? Nur dann gilt der kürzere Dwell —
/// alles Unklare fällt auf den langen Rückwärts-Dwell zurück.
fn enroute_reconcile_is_forward(v1: FlightPhase, v2: FlightPhase) -> bool {
    matches!(
        (enroute_phase_rank(v1), enroute_phase_rank(v2)),
        (Some(a), Some(b)) if b > a
    )
}

/// Kinematik-Widerspruchs-Gate des En-Route-Versöhners (rein, testbar) —
/// das PRIMÄRE Feuer-Kriterium, siehe [`ENROUTE_RECONCILE_DWELL_SECS`].
/// True nur, wenn die Fenster-Evidenz v1s Phase aktiv WIDERLEGT:
///
/// * `Climb` ⊥ Descending/Ground — die GSG22-Klasse (Climb festgefahren,
///   Flieger sinkt/rollt längst; ein gesunder Steigflug hat nie 45 s+
///   Fenster-Mehrheit „sinkend").
/// * `Cruise` ⊥ Ground — Absurditäts-Guard; ein sinkendes Cruise wird
///   BEWUSST NICHT gezogen: v1s eigener −500-fpm-Trigger deckt jeden
///   echten TOD ab (Korpus: 0 von 632 Flügen in Cruise festgefahren),
///   und ATC-Step-Downs sind bei v1 by design Cruise — ein Zug erzeugte
///   dort nur den in QS-Runde 1 bewiesenen Pull/Recovery-Zyklus.
/// * `Descent` ⊥ Climbing/Ground — die GSG-105-Klasse (Descent-Falle:
///   v1 hat keinen Descent→Climb-Weg zurück). `Level` widerspricht NICHT
///   (Zwischen-Level-Off; v1s B-003-Recovery übernimmt bei |V/S| < 200).
/// * `Approach`/`Final` ⊥ Climbing/Ground — verpasster Go-Around (v1s
///   eigener GA-Detektor braucht `engines_running` > 0 und ist bei toten
///   Engine-SimVars blind) bzw. verpasste Touchdown-Kante.
///
/// `Level` und `Insufficient` widersprechen NIE — Level-Flug ist mit
/// jeder Luft-Phase vereinbar (TOC-Wartezeit, Restrictions, Step-Downs),
/// und ohne Evidenz wird nicht geurteilt.
fn segment_contradicts_v1(v1: FlightPhase, segment: phase_v2::Segment) -> bool {
    use phase_v2::Segment;
    match v1 {
        FlightPhase::Climb => {
            matches!(segment, Segment::Descending | Segment::Ground)
        }
        FlightPhase::Cruise => matches!(segment, Segment::Ground),
        FlightPhase::Descent | FlightPhase::Approach | FlightPhase::Final => {
            matches!(segment, Segment::Climbing | Segment::Ground)
        }
        _ => false,
    }
}

/// `landing_at`-Rettung aus dem 50-Hz-Sampler, wenn der FSM-Pfad die
/// Final→Landing-Kante übersprungen hat (v0.5.4, historisch inline im
/// universellen Arrived-Fallback; QS-Runde 1: auch der En-Route-Versöhner
/// braucht sie bei einem Zug direkt auf `Landing`, sonst hinterlässt der
/// Zug `landing_at=None` — aufgeblähte flight_time, kein LandingRecord,
/// toter Landing-Arm-Analyzer). Der Sampler latcht den Touchdown
/// phasenunabhängig (v0.15.20), hier werden Zeitstempel + VS/G nur in die
/// FSM-Felder übernommen — niemals überschreibend (`get_or_insert`-
/// Semantik pro Feld).
fn rescue_landing_at_from_sampler(stats: &mut FlightStats, now: DateTime<Utc>) {
    if stats.landing_at.is_some() || stats.takeoff_at.is_none() {
        return;
    }
    if let Some(sampler_at) = stats.sampler_touchdown_at {
        stats.landing_at = Some(sampler_at);
        if let Some(vs) = stats.sampler_touchdown_vs_fpm {
            if stats.landing_rate_fpm.is_none() {
                finalize_landing_rate(stats, vs, None, Some("sampler_carry_over"));
            }
        }
        if let Some(g) = stats.sampler_touchdown_g_force {
            if stats.landing_g_force.is_none() {
                stats.landing_g_force = Some(g);
            }
            if stats.landing_peak_g_force.is_none() {
                stats.landing_peak_g_force = Some(g);
            }
        }
        tracing::info!(
            "landing_at rescued from sampler: vs={:?} g={:?}",
            stats.sampler_touchdown_vs_fpm,
            stats.sampler_touchdown_g_force
        );
    } else {
        stats.landing_at = Some(now);
    }
}

/// v0.5.11: detect entry into a holding pattern.
///
/// Triggered from Cruise or Approach when the aircraft sustains a
/// turn at constant altitude for `HOLDING_ENTRY_DWELL_SECS`.
/// Returns `true` once the dwell elapses; the caller then transitions
/// the FSM to `FlightPhase::Holding`.
///
/// Detection criteria each tick:
///   * |bank| > 15° (banked turn — standard rate is ~25-30°)
///   * |VS| < 200 fpm (level — real holds are within ±100 ft)
///
/// Once both fail (e.g. straight-and-level resumed), the dwell timer
/// resets so brief intermediate level segments during a 360° turn
/// don't accidentally fire (banked → level → banked is normal at
/// hold turn entry/exit).
fn check_holding_entry(
    stats: &mut FlightStats,
    snap: &SimSnapshot,
    now: DateTime<Utc>,
) -> bool {
    let in_hold_pattern = snap.bank_deg.abs() > HOLDING_BANK_THRESHOLD_DEG
        && snap.vertical_speed_fpm.abs() < HOLDING_VS_THRESHOLD_FPM;
    if in_hold_pattern {
        let pending = stats.holding_pending_since.get_or_insert(now);
        if (now - *pending).num_seconds() >= HOLDING_ENTRY_DWELL_SECS {
            tracing::info!(
                bank_deg = snap.bank_deg,
                vs_fpm = snap.vertical_speed_fpm,
                agl_ft = snap.altitude_agl_ft,
                "holding pattern detected — entering Holding phase"
            );
            stats.holding_pending_since = None;
            return true;
        }
    } else {
        stats.holding_pending_since = None;
    }
    false
}

// ---- v0.5.11: AGL-derivative touchdown VS estimator -------------------
//
// Pilot's deep analysis pinpointed the bug class in v0.5.5+:
// "approach_vs_min_fpm" picks the most-negative VS across the WHOLE
// approach. A pre-flare descent at -1346 fpm @ 943 ft AGL would win
// over the actual gentle touchdown at -200 fpm @ 0 ft. Result:
// "phantom hard landing" reports.
//
// Correct approach: ONLY count samples close to the ground for
// touchdown VS. The window-tier strategy (LandingRate-1.lua, Volanta)
// uses geometric AGL change over a tight time window centred on the
// actual touchdown moment. Pre-flare descent gets ignored entirely.
//
// Window tiers (most preferred first):
//   1. 750 ms   — dense plugin-fed samples (≥5 samples)
//   2. 1000 ms  — typical RREF cadence
//   3. 1500 ms  — slower RREF (still inside flare)
//   4. 2000 ms  — wider for very sparse RREF
//   5. 3000 ms  — last "real" tier
//   6. 12000 ms — sparse fallback (the famous 9-sec gap in pilot
//                 reports). Lower confidence but better than nothing.
//
// All tiers must satisfy:
//   * Last sample AGL ≤ 5 ft  (genuine touchdown frame, not Sim-glitch)
//   * Earliest sample AGL ≤ 250 ft (= we're below pattern altitude)
//   * Sample count ≥ MIN_SAMPLES (5 for short tiers, 3 for sparse)
//   * Result < 0 fpm (no positive "landing rate" is physical)

const TD_WINDOW_TIERS_MS: &[(i64, usize)] = &[
    (750, 5),
    (1000, 5),
    (1500, 5),
    (2000, 4),
    (3000, 3),
    (12000, 3),
];
const TD_AGL_MAX_AT_TOUCHDOWN_FT: f32 = 5.0;
const TD_AGL_MAX_AT_WINDOW_START_FT: f32 = 250.0;

/// Result of a touchdown VS estimation, including diagnostics so the
/// rest of the system can log which window won and its sample
/// density.
#[derive(Debug, Clone, Copy)]
pub struct TouchdownVsEstimate {
    /// Negative fpm (descent rate). Always strictly < 0.
    pub fpm: f32,
    pub source: &'static str,
    pub window_ms: i64,
    pub sample_count: usize,
}

/// Estimate touchdown VS from snapshot_buffer AGL samples.
///
/// Walks the window tiers in order (shortest first); returns the
/// first tier that satisfies all guards. Returns `None` when no
/// window has enough samples or all windows give a non-negative
/// (= unphysical) result.
fn estimate_xplane_touchdown_vs_from_agl(
    buffer: &std::collections::VecDeque<TelemetrySample>,
    touchdown_at: DateTime<Utc>,
) -> Option<TouchdownVsEstimate> {
    for (window_ms, min_samples) in TD_WINDOW_TIERS_MS {
        let win_start = touchdown_at - chrono::Duration::milliseconds(*window_ms);
        let samples: Vec<&TelemetrySample> = buffer
            .iter()
            .filter(|s| s.at >= win_start && s.at <= touchdown_at)
            .collect();
        if samples.len() < *min_samples {
            continue;
        }
        // Touchdown sample (latest) must really be at the ground.
        // v0.5.12: accept on_ground=true OR AGL ≤ 5 ft. MSFS reports
        // AGL ≈ 9.4 ft (sometimes 13 ft) even when on_ground=true at
        // the physical contact frame — this is a sim quirk, not a
        // pre-touchdown sample. Strict AGL ≤ 5 ft alone would reject
        // every MSFS touchdown.
        let last = samples.last()?;
        let is_at_touchdown =
            last.on_ground || last.agl_ft <= TD_AGL_MAX_AT_TOUCHDOWN_FT;
        if !is_at_touchdown {
            continue;
        }
        // Window-start sample must already be near the ground (i.e.
        // we're not picking up a high-altitude pre-flare descent).
        let first = samples.first()?;
        if first.agl_ft > TD_AGL_MAX_AT_WINDOW_START_FT {
            continue;
        }
        // Geometric descent rate via avg-AGL midpoint trick
        // (LandingRate-1.lua method). For a linear descent the avg
        // is the time-midpoint; the rate from midpoint → now over
        // (timespan / 2) is the geometric descent rate.
        let avg_agl: f32 =
            samples.iter().map(|s| s.agl_ft).sum::<f32>() / samples.len() as f32;
        let timespan_sec =
            (last.at - first.at).num_milliseconds() as f32 / 1000.0;
        if timespan_sec < 0.2 {
            continue;
        }
        let agl_midpoint = last.agl_ft - avg_agl;
        let fpm = (agl_midpoint / (timespan_sec / 2.0)) * 60.0;
        // Reject positive (climbing) results — physically wrong for
        // a touchdown estimate.
        if !fpm.is_finite() || fpm >= 0.0 {
            continue;
        }
        return Some(TouchdownVsEstimate {
            fpm,
            source: match *window_ms {
                750 => "agl_750ms",
                1000 => "agl_1000ms",
                1500 => "agl_1500ms",
                2000 => "agl_2000ms",
                3000 => "agl_3000ms",
                12000 => "agl_sparse_12s",
                _ => "agl_unknown",
            },
            window_ms: *window_ms,
            sample_count: samples.len(),
        });
    }
    None
}

/// Discard non-negative VS values. Used as a safety filter on every
/// fallback source (sampler, plugin, buffer-min). A positive
/// "landing rate" is physically impossible — the airframe is by
/// definition descending (or settled at 0) at the touchdown frame.
/// Plugin / buffer values can briefly read positive due to gear
/// oscillation rebound; we never want those as the published
/// landing rate.
fn negative_only(value: Option<f32>) -> Option<f32> {
    value.filter(|v| v.is_finite() && *v < 0.0)
}

// ======================================================================
// v0.16.21 — MSFS touchdown V/S SimVar-lag de-lag (g-force-gated)
// ======================================================================
//
// PROBLEM. MSFS exposes no un-lagged raw V/S at the touchdown frame.
// The scored `vs_at_edge_fpm` (read by `canonical_landing_rate_fpm`)
// is derived from the display VSI, which LAGS the airframe through the
// flare and therefore OVER-reads the touchdown sink on landings with a
// flare. Real example JBU322: scored -441 fpm, but the true rate from
// the geometric AGL derivative was ~-251 fpm (peak_g 1.25 — physically
// inconsistent with -441). EWG906: -422 → -261 (peak_g 1.21).
//
// We already compute the un-lagged truth: `estimate_xplane_touchdown_
// vs_from_agl` (the geometric AGL-midpoint derivative, pre-contact,
// AGL-gated, never reads the impact frame). On X-Plane it's already the
// scored source; on MSFS it has only been a fallback when the latched
// SimVar is null.
//
// WHY A NAIVE DIVERGENCE THRESHOLD IS UNSAFE. A 278-landing VPS corpus
// of `msfs_simvar_latched` touchdowns shows that V/S divergence ALONE
// (edge vs AGL) CANNOT distinguish "soft landing + lagged V/S" from
// "firm landing + lagged V/S": 22 genuine firm/hard landings diverge by
// the same 100-250 fpm as the soft lag artifacts. Softening on
// divergence alone would wrongly relax those firm landings.
//
// THE LAG-INDEPENDENT ARBITER IS THE G-FORCE. peak_g correlates 0.93
// with |AGL estimate| but only 0.80 with |lagged edge| (measured on the
// corpus). A real hard landing has HIGH g corroborating the high V/S; a
// lag artifact has LOW g that contradicts it and instead agrees with
// the shallow AGL estimate.
//
// FITTED G↔|V/S| MODEL. Calibrated on the corpus of MSFS simvar-latched
// landings in the VPS flight-logs (278 at fit time, 2026-06: ssh live,
// /var/lib/aeroacars-recorder/flight-logs/gsg/*/*.jsonl.gz), fitting
// peak_g_post_500ms against the un-lagged truth |vs_estimate_msfs| via
// ordinary least squares. To recalibrate (e.g. after an MSFS Sim Update
// shifts the VSI lag profile), re-extract those two fields from the logs
// and refit; the `vs_lag_signature` forensic key + the health-report make
// the gate's fire-rate observable so drift is visible before it matters:
//
//     g_implied(|vs_fpm|) = 1.0019 + 0.0009421 * |vs_fpm|
//
// i.e. baseline ~1.0 g at zero sink + ~0.942 g per 1000 fpm. Residual
// stddev 0.061 g. r(peak_g, |agl|)=0.930 vs r(peak_g, |edge|)=0.799.
//
// HOW THE ANCHORS RESOLVE under this model (g_implied for each source):
//   JBU322  edge-441 g_impl 1.42 | agl-251 g_impl 1.24 | peak_g 1.25
//           → measured g sits at the AGL prediction, far below the edge
//             prediction ⇒ lag artifact ⇒ FIRE (→ -251).
//   EWG906  edge-422 g_impl 1.40 | agl-263 g_impl 1.25 | peak_g 1.21-1.25
//           → same ⇒ FIRE (→ -263).
//   DANGER  JrMr edge-614 agl-470 peak_g 1.465 ; 8ZOp edge-764 agl-518
//           peak_g 1.609 ; pJ4v edge-782 agl-618 peak_g 1.720
//           → measured g HIGH, corroborates the high edge V/S ⇒ the
//             hard-G lock (peak_g ≥ 1.40) blocks the override ⇒ NO FIRE,
//             score band unchanged.
//
// On the corpus this gate fires on 27/278 landings (18 with a score-
// band change), ZERO of which have peak_g ≥ 1.35 — so not a single
// genuine firm/hard landing is softened. All 44 corpus landings with
// peak_g ≥ 1.35 are left untouched.
const MSFS_DELAG_G_BASELINE: f32 = 1.0019;
const MSFS_DELAG_G_PER_FPM: f32 = 0.000_942_1;
/// The edge's implied g must exceed the measured g by at least this
/// margin for the override to fire (the edge over-reads vs physics).
/// 0.10 g ≈ 1.6× the 0.061 g fit residual — comfortably outside noise.
const MSFS_DELAG_G_EDGE_MARGIN: f32 = 0.10;
/// The measured g must also be CONSISTENT with the AGL estimate being
/// the truth: at most this far above its AGL-implied g. Keeps a case
/// where g is high relative to BOTH sources (a true firm landing the
/// AGL estimate happened to read shallow on) from being softened.
const MSFS_DELAG_G_AGL_TOLERANCE: f32 = 0.05;
/// Hard lock: never de-lag a landing whose measured peak g is at/above
/// the Firm g-threshold. A real firm/hard impact ALWAYS shows up in g
/// (g is lag-free); this is the structural guard that protects every
/// one of the 22 genuine firm landings the corpus warned about.
const MSFS_DELAG_G_HARD_LOCK: f32 = TOUCHDOWN_G_FIRM; // 1.40
/// Divergence (lag signature): the lagged edge must be more-negative
/// than the AGL estimate by at least this absolute amount …
const MSFS_DELAG_MIN_ABS_DIVERGENCE_FPM: f32 = 60.0;
/// … AND the AGL estimate must be at most this fraction of |edge|
/// (a relative divergence floor — guards against tiny relative gaps
/// on already-shallow landings).
const MSFS_DELAG_MAX_AGL_REL: f32 = 0.92;
/// Structural accident guard: |edge| at/above this is the accident
/// band — NEVER softened, so a real crash can never be un-flagged.
const MSFS_DELAG_MAX_EDGE_ABS_FPM: f32 = 1000.0;
/// Prefer a SHORT window for the de-lag estimate. A long-float window
/// (≥2 s) averages too much of the shallow late flare and reads too
/// close to zero — over-softening. We only de-lag using the ≤1500 ms
/// tiers; if none qualifies we fall back to no override.
const MSFS_DELAG_MAX_WINDOW_MS: i64 = 1500;

#[inline]
fn msfs_delag_g_implied(vs_abs_fpm: f32) -> f32 {
    MSFS_DELAG_G_BASELINE + MSFS_DELAG_G_PER_FPM * vs_abs_fpm
}

/// Short-window variant of the AGL-derivative touchdown estimator used
/// ONLY for the de-lag override. Identical algorithm + guards to
/// `estimate_xplane_touchdown_vs_from_agl`, but restricted to the
/// ≤`MSFS_DELAG_MAX_WINDOW_MS` tiers so we never average a long float
/// down toward zero. Returns `None` if no short tier qualifies.
fn estimate_msfs_touchdown_vs_short_window(
    buffer: &std::collections::VecDeque<TelemetrySample>,
    touchdown_at: DateTime<Utc>,
) -> Option<f32> {
    let est = estimate_xplane_touchdown_vs_from_agl(buffer, touchdown_at)?;
    if est.window_ms <= MSFS_DELAG_MAX_WINDOW_MS && est.fpm.is_finite() && est.fpm < 0.0 {
        Some(est.fpm)
    } else {
        None
    }
}

/// Result of the de-lag decision: the corrected V/S plus a human-
/// readable signature for the forensic key.
struct MsfsDelagResult {
    corrected_fpm: f32,
    raw_edge_fpm: f32,
    signature: String,
}

/// Decide whether the MSFS touchdown V/S `analysis["vs_at_edge_fpm"]`
/// is a lag artifact that should be replaced by the un-lagged AGL
/// estimate, GATED on the g-force being too low to justify the lagged
/// edge V/S. Returns `Some` only when ALL gates pass; the caller then
/// overrides the analysis edge AND routes the landing class through the
/// corrected value. Pure + side-effect-free so it is unit-testable on
/// every platform.
///
/// `peak_g` is the lag-free impact g (peak_g_post_500ms). `edge_fpm` is
/// the current `analysis["vs_at_edge_fpm"]`. `agl_fpm` is the short-
/// window AGL estimate (already filtered to a short tier by the caller).
fn decide_msfs_touchdown_delag(
    simulator: Simulator,
    category: aircraft_category::AircraftCategory,
    edge_fpm: Option<f32>,
    agl_fpm: Option<f32>,
    peak_g: Option<f32>,
) -> Option<MsfsDelagResult> {
    // Gate 1: MSFS only — X-Plane (raw local_vy) and Other untouched.
    if !matches!(simulator, Simulator::Msfs2020 | Simulator::Msfs2024) {
        return None;
    }
    // Gate 2: fixed-wing only — heli / seaplane touch down near-zero
    // V/S, the de-lag would over-soften toward 0.
    if category != aircraft_category::AircraftCategory::FixedWing {
        return None;
    }
    // Gate 3: canonical only uses negative edge; |edge| < accident band.
    let edge = edge_fpm?;
    if !(edge < 0.0 && edge.is_finite()) {
        return None;
    }
    if edge.abs() >= MSFS_DELAG_MAX_EDGE_ABS_FPM {
        return None; // structural accident guard — never soften a crash
    }
    // Gate 4: AGL estimate present, finite, negative.
    let agl = agl_fpm?;
    if !(agl < 0.0 && agl.is_finite()) {
        return None;
    }
    // Gate 5: divergence present AND only-soften-toward-zero (AGL
    // strictly shallower than edge). Both an absolute and a relative
    // margin (the lag signature). The first check is a hard invariant
    // (never soften away from zero); the abs/rel margins below are what
    // actually decide whether the divergence is large enough to act on.
    if agl.abs() >= edge.abs() {
        return None; // assert we only ever soften toward zero
    }
    if (edge.abs() - agl.abs()) < MSFS_DELAG_MIN_ABS_DIVERGENCE_FPM {
        return None;
    }
    if agl.abs() > MSFS_DELAG_MAX_AGL_REL * edge.abs() {
        return None;
    }
    // Gate 6: the g-force consistency gate — the core safety gate, run
    // last so it has the final say over the divergence gates above.
    let g = peak_g?;
    if !g.is_finite() {
        return None;
    }
    // 6a: hard lock — a real firm/hard impact ALWAYS shows in g.
    if g >= MSFS_DELAG_G_HARD_LOCK {
        return None;
    }
    let g_implied_by_edge = msfs_delag_g_implied(edge.abs());
    let g_implied_by_agl = msfs_delag_g_implied(agl.abs());
    // 6b: the edge over-reads vs the physics — measured g is well below
    // the g the lagged edge would imply.
    if g >= g_implied_by_edge - MSFS_DELAG_G_EDGE_MARGIN {
        return None;
    }
    // 6c: the measured g is CONSISTENT with the AGL estimate being the
    // true rate (not high relative to both sources).
    if g > g_implied_by_agl + MSFS_DELAG_G_AGL_TOLERANCE {
        return None;
    }
    let signature = format!(
        "edge {:.0} vs agl {:.0}, peak_g {:.2} implies ~{:.0} fpm (edge would imply ~{:.0}), delagged",
        edge,
        agl,
        g,
        // invert the model: |vs| ≈ (g - baseline) / slope
        ((g - MSFS_DELAG_G_BASELINE) / MSFS_DELAG_G_PER_FPM).max(0.0),
        edge.abs(),
    );
    Some(MsfsDelagResult {
        corrected_fpm: agl,
        raw_edge_fpm: edge,
        signature,
    })
}

/// Apply the de-lag decision to a `landing_analysis` JSON in place.
/// When the gate fires: overrides `vs_at_edge_fpm` with the AGL
/// estimate and adds additive forensic keys (`vs_at_edge_fpm_raw`,
/// `vs_at_edge_source`, `vs_lag_signature`). Returns the corrected V/S
/// so the caller can also route the landing CLASS through it (keeping
/// the class label consistent with the corrected numeric score).
///
/// Reads `vs_at_edge_fpm` + `peak_g_post_500ms` from `analysis` and the
/// short-window AGL estimate from `buffer`. No-op (returns `None`,
/// leaving today's behaviour untouched) whenever any gate fails.
fn apply_msfs_touchdown_delag(
    analysis: &mut serde_json::Value,
    buffer: &std::collections::VecDeque<TelemetrySample>,
    touchdown_at: DateTime<Utc>,
    simulator: Simulator,
    category: aircraft_category::AircraftCategory,
) -> Option<f32> {
    let edge_fpm = analysis
        .get("vs_at_edge_fpm")
        .and_then(|v| v.as_f64())
        .map(|x| x as f32);
    let peak_g = analysis
        .get("peak_g_post_500ms")
        .and_then(|v| v.as_f64())
        .map(|x| x as f32);
    let agl_fpm = estimate_msfs_touchdown_vs_short_window(buffer, touchdown_at);

    let result =
        decide_msfs_touchdown_delag(simulator, category, edge_fpm, agl_fpm, peak_g)?;

    if let Some(obj) = analysis.as_object_mut() {
        obj.insert(
            "vs_at_edge_fpm".into(),
            serde_json::json!(result.corrected_fpm),
        );
        obj.insert(
            "vs_at_edge_fpm_raw".into(),
            serde_json::json!(result.raw_edge_fpm),
        );
        obj.insert(
            "vs_at_edge_source".into(),
            serde_json::json!("msfs_g_consistency_delag"),
        );
        obj.insert(
            "vs_lag_signature".into(),
            serde_json::json!(result.signature),
        );
    }
    Some(result.corrected_fpm)
}

// ---- v0.5.13: Lua-style adaptive 30-sample AGL-Δ estimator ------------
//
// Direct port of LandingRate-1.lua's algorithm (Dan Berry, 2014+,
// X-Plane.org "A New Landing Rate Display"). Matches what Volanta uses
// internally for X-Plane touchdown capture.
//
// Key insight: instead of fixed time windows (750ms/1s/1.5s/...) that
// can pick up pre-flare contamination on sparse RREF feeds, take a
// FIXED COUNT of recent samples (30) and adapt the time window to
// however dense the buffer is.
//
// Effect:
//   * High-fps sim (60+ fps): 30 samples ≈ 0.5 s window — tight, captures
//     just the flare's final phase
//   * Mid-fps sim (30 fps): 30 samples ≈ 1 s window — Lua's reference point
//   * Low-fps sim (10 fps): 30 samples ≈ 3 s window — wider window to
//     compensate for sparse data
//
// AGL guards (TD ≤ 5 ft / on_ground=true, window-start ≤ 250 ft) are
// identical to the time-tier estimator — they're what prevents
// pre-flare descent contamination, regardless of window size.
//
// Used ONLY for the X-Plane priority path. MSFS keeps the older
// time-tier `estimate_xplane_touchdown_vs_from_agl` as fallback (when
// the latched MSFS SimVar is null) — that path is GEES-aligned and
// validated against pilot reports; we don't change MSFS behaviour.
const LUA_STYLE_SAMPLE_COUNT: usize = 30;
const LUA_STYLE_MIN_SAMPLES: usize = 5;

fn estimate_xplane_touchdown_vs_lua_style(
    buffer: &std::collections::VecDeque<TelemetrySample>,
    touchdown_at: DateTime<Utc>,
) -> Option<TouchdownVsEstimate> {
    // Collect samples up to (and including) touchdown_at, in chronological order.
    let mut samples: Vec<&TelemetrySample> =
        buffer.iter().filter(|s| s.at <= touchdown_at).collect();
    samples.sort_by_key(|s| s.at);
    let n = samples.len();
    if n < LUA_STYLE_MIN_SAMPLES {
        return None;
    }
    let take = n.min(LUA_STYLE_SAMPLE_COUNT);
    let recent = &samples[n - take..];

    // Touchdown sample (latest) must really be at the ground.
    let last = *recent.last()?;
    let is_at_touchdown =
        last.on_ground || last.agl_ft <= TD_AGL_MAX_AT_TOUCHDOWN_FT;
    if !is_at_touchdown {
        return None;
    }
    // Window-start sample must already be in approach footprint
    // (no high-altitude pre-flare contamination).
    let first = *recent.first()?;
    if first.agl_ft > TD_AGL_MAX_AT_WINDOW_START_FT {
        return None;
    }

    let avg_agl: f32 =
        recent.iter().map(|s| s.agl_ft).sum::<f32>() / take as f32;
    let timespan_sec =
        (last.at - first.at).num_milliseconds() as f32 / 1000.0;
    if timespan_sec < 0.2 {
        return None;
    }
    let agl_midpoint = last.agl_ft - avg_agl;
    let fpm = (agl_midpoint / (timespan_sec / 2.0)) * 60.0;
    if !fpm.is_finite() || fpm >= 0.0 {
        return None;
    }
    Some(TouchdownVsEstimate {
        fpm,
        source: "lua_30_sample",
        window_ms: (timespan_sec * 1000.0) as i64,
        sample_count: take,
    })
}

/// Compute population standard deviations of V/S and bank over the
/// approach buffer. Returns `(None, None)` when fewer than 3 samples
/// (insufficient signal). Single-pass formula (Welford's algorithm
/// would be marginally more numerically stable but at this scale it
/// makes no difference).
/// v0.5.46: Window-Filter analog zu compute_approach_stability_v2.
/// Adrian (User-Feedback 2026-05-09): "bei der Anflugstabilität wird noch
/// der gerade Teil auf dem LOC ausgewertet, bevor es auf den G/S geht.
/// Daher gibt es hier so schlechte Werte." Dazu Flare die letzten 3 sec
/// vor TD (Pilot-Pull) faelschlich als Instabilitaet gewertet.
///
/// Filter:
///   - AGL <= 1500 ft (LOC-Intercept ueber 1500ft ausgeschlossen)
///   - ts <= TD - 3s wenn td_ts gegeben (Flare-Last-3s ausgeschlossen)
const APPROACH_STABILITY_AGL_CAP_FT: f32 = 1500.0;
const APPROACH_FLARE_CUTOFF_MS: i64 = 3000;

/// v0.16.6: sampler-path stability-evaluation window. When a validated 50 Hz
/// sampler touchdown evaluates approach stability (bush flights — the FSM
/// never reaches Landing), only approach-buffer samples within this many
/// seconds BEFORE the touchdown count. The phase-independent sampling
/// (`should_push_approach_sample`) feeds the buffer on ANY descending
/// low-level segment, so a 38-min Oregon-bush-tour leg flown at 1500 ft AGL
/// would otherwise poison the 1000-ft gate with manoeuvring that has nothing
/// to do with the actual approach. 180 s covers even a slow C152 final from
/// well outside the gate. FSM-path flights pass `window = None` and are
/// unaffected.
const SAMPLER_STABILITY_WINDOW_SECS: i64 = 180;

/// v0.16.6: time-window filter for the approach buffer — keeps only samples
/// within `dur` before `td` (samples after `td` are dropped too). Shared by
/// `compute_approach_stability_v2` (window = Some) and the sampler-path
/// `compute_approach_stddev` call, so both stats families see the SAME
/// windowed sample set.
fn approach_buffer_window(
    buf: &std::collections::VecDeque<ApproachBufferSample>,
    td: DateTime<Utc>,
    dur: chrono::Duration,
) -> std::collections::VecDeque<ApproachBufferSample> {
    buf.iter()
        .filter(|s| s.at <= td && (td - s.at) <= dur)
        .cloned()
        .collect()
}

/// v0.12.1 (Stream C LE12): the `max V/S deviation < 500 ft` metric
/// ignores samples below this height. A V/S excursion at < 50 ft is the
/// flare / ground-effect, not approach instability — counting it produced
/// a spurious 826 fpm "deviation" on GSG225 from a small flare balloon.
/// The 3-second time-based flare cutoff doesn't reach far enough back
/// when the pilot flares early/long; this height floor is the backstop.
const MAX_VS_DEV_FLOOR_FT: f32 = 50.0;

/// v0.12.1 (Stream C LE11): if flaps read 0 across the whole approach
/// gate while the gear is down AND the gate-entry speed is below this
/// IAS, the flaps dataref is untrustworthy (study-level X-Plane add-ons
/// such as the Hot-Start CL650 don't drive the standard flap dataref) —
/// a genuine flapless landing would be considerably faster. The
/// LANDING-CONFIG check then reports "not assessable" instead of a
/// false "INCOMPLETE".
const FLAPS_UNREADABLE_MAX_IAS_KT: f32 = 160.0;

fn compute_approach_stddev(
    buf: &std::collections::VecDeque<ApproachBufferSample>,
    td_ts: Option<DateTime<Utc>>,
) -> (Option<f32>, Option<f32>) {
    let filtered: Vec<&ApproachBufferSample> = buf.iter()
        .filter(|s| {
            let in_agl_band = s.agl_ft > 0.0 && s.agl_ft <= APPROACH_STABILITY_AGL_CAP_FT;
            let pre_flare = match td_ts {
                Some(td) => (td - s.at).num_milliseconds() >= APPROACH_FLARE_CUTOFF_MS,
                None => true,
            };
            in_agl_band && pre_flare
        })
        .collect();
    let n = filtered.len();
    if n < 3 {
        return (None, None);
    }
    let mut sum_vs = 0.0_f64;
    let mut sum_bank = 0.0_f64;
    for s in &filtered {
        sum_vs += s.vs_fpm as f64;
        sum_bank += s.bank_deg as f64;
    }
    let mean_vs = sum_vs / n as f64;
    let mean_bank = sum_bank / n as f64;
    let mut sq_vs = 0.0_f64;
    let mut sq_bank = 0.0_f64;
    for s in &filtered {
        let dv = s.vs_fpm as f64 - mean_vs;
        let db = s.bank_deg as f64 - mean_bank;
        sq_vs += dv * dv;
        sq_bank += db * db;
    }
    let var_vs = sq_vs / n as f64;
    let var_bank = sq_bank / n as f64;
    (Some(var_vs.sqrt() as f32), Some(var_bank.sqrt() as f32))
}

/// v0.5.26: ICAO-Kategorie-basierte Default-Limits fuer Wing-Strike +
/// Vref. Wenn DBasic Tech-Limits-DB nicht verfuegbar oder PMDG-FMC-
/// Vref nicht gesetzt, nutzen wir diese Conservative-Defaults.
///
/// Quellen: aircraft type certification data sheets (TCDS), FCOMs.
/// Werte sind „typisch" fuer Standard-MTOW-Konfiguration. Pilot/VA
/// kann via DBasic-Override fuer spezifische Variante setzen.
struct AircraftLimits {
    max_bank_landing_deg: f32,
    typical_vref_kt: Option<f32>,
}

fn aircraft_limits_for(icao: &str) -> AircraftLimits {
    let upper = icao.to_uppercase();
    let upper_str = upper.as_str();
    match upper_str {
        // Heavy / Wide-Body
        "B741" | "B742" | "B743" | "B744" | "B748" => AircraftLimits { max_bank_landing_deg: 9.0, typical_vref_kt: Some(160.0) },
        "B772" | "B773" | "B77L" | "B77W" | "B778" | "B779" => AircraftLimits { max_bank_landing_deg: 8.0, typical_vref_kt: Some(150.0) },
        "B788" | "B789" | "B78X" => AircraftLimits { max_bank_landing_deg: 8.0, typical_vref_kt: Some(145.0) },
        "A332" | "A333" | "A338" | "A339" => AircraftLimits { max_bank_landing_deg: 8.0, typical_vref_kt: Some(140.0) },
        "A359" | "A35K" => AircraftLimits { max_bank_landing_deg: 8.0, typical_vref_kt: Some(140.0) },
        "A388" => AircraftLimits { max_bank_landing_deg: 7.0, typical_vref_kt: Some(145.0) },
        // Narrow-Body Jets
        "A318" | "A319" | "A320" | "A20N" => AircraftLimits { max_bank_landing_deg: 8.0, typical_vref_kt: Some(135.0) },
        "A321" | "A21N" => AircraftLimits { max_bank_landing_deg: 7.0, typical_vref_kt: Some(140.0) }, // A321 tail-strike-prone
        "B736" | "B737" | "B738" | "B739" | "B73X" => AircraftLimits { max_bank_landing_deg: 8.0, typical_vref_kt: Some(140.0) },
        "B38M" | "B39M" => AircraftLimits { max_bank_landing_deg: 8.0, typical_vref_kt: Some(140.0) },
        "B752" | "B753" => AircraftLimits { max_bank_landing_deg: 8.0, typical_vref_kt: Some(140.0) },
        "B762" | "B763" | "B764" => AircraftLimits { max_bank_landing_deg: 8.0, typical_vref_kt: Some(140.0) },
        // Regional Jets
        "E170" | "E175" | "E190" | "E195" | "E290" | "E295" => AircraftLimits { max_bank_landing_deg: 8.0, typical_vref_kt: Some(130.0) },
        "CRJ7" | "CRJ9" | "CRJX" => AircraftLimits { max_bank_landing_deg: 8.0, typical_vref_kt: Some(135.0) },
        // Business Jets
        "CL30" | "CL35" | "CL60" | "CL64" | "CL65" => AircraftLimits { max_bank_landing_deg: 6.0, typical_vref_kt: Some(115.0) },
        "GLF5" | "GLF6" | "GLEX" | "G280" | "GL5T" | "GL7T" => AircraftLimits { max_bank_landing_deg: 7.0, typical_vref_kt: Some(120.0) },
        "C25A" | "C25B" | "C25C" | "C525" | "C56X" | "C68A" => AircraftLimits { max_bank_landing_deg: 8.0, typical_vref_kt: Some(105.0) },
        // Turboprops — Regional/Commuter
        "DH8A" | "DH8B" | "DH8C" | "DH8D" | "AT43" | "AT72" | "AT75" | "AT76" => AircraftLimits { max_bank_landing_deg: 8.0, typical_vref_kt: Some(110.0) },
        // Beechcraft King Air family (turboprop). v0.8.3: duplicate B190
        // removed, BE9L/BE10/BE20/BE30 hinzugefuegt — vorher fielen alle
        // King-Air-Varianten ausser B190/B350 auf den 8°/None-Fallback.
        "B190" | "B350" | "BE9L" | "BE10" | "BE20" | "BE30" => AircraftLimits { max_bank_landing_deg: 10.0, typical_vref_kt: Some(95.0) },
        // GA Twins (piston). v0.8.3: BE58 (Baron) + PA34 (Seneca) +
        // AEST (Aerostar) hinzugefuegt — Reports zeigten GSG-Piloten mit
        // Baron/Seneca landeten mit Airliner-Bank-Limits (8° statt 15°).
        "BE58" | "BE76" | "PA34" | "PA44" | "AEST" => AircraftLimits { max_bank_landing_deg: 15.0, typical_vref_kt: Some(85.0) },
        // GA Singles
        "C172" | "C152" | "C150" | "C162" => AircraftLimits { max_bank_landing_deg: 15.0, typical_vref_kt: Some(65.0) },
        "C182" | "C206" | "C208" => AircraftLimits { max_bank_landing_deg: 12.0, typical_vref_kt: Some(75.0) },
        "DA40" | "DA42" | "DA62" => AircraftLimits { max_bank_landing_deg: 12.0, typical_vref_kt: Some(75.0) },
        "P28A" | "PA28" | "PA32" | "PA46" | "P28R" | "PA24" => AircraftLimits { max_bank_landing_deg: 12.0, typical_vref_kt: Some(75.0) },
        "SR20" | "SR22" | "SR2T" => AircraftLimits { max_bank_landing_deg: 12.0, typical_vref_kt: Some(80.0) },
        // Beechcraft Bonanza family (single-engine piston, Svenny's Bird).
        // v0.8.3: zuvor war BE36 nicht aufgelistet → Airliner-Fallback.
        "BE33" | "BE35" | "BE36" => AircraftLimits { max_bank_landing_deg: 15.0, typical_vref_kt: Some(75.0) },
        // Mooney + andere High-Performance Singles
        "M20P" | "M20T" | "MU2" => AircraftLimits { max_bank_landing_deg: 12.0, typical_vref_kt: Some(80.0) },
        // Fallback fuer unbekannte
        _ => AircraftLimits { max_bank_landing_deg: 8.0, typical_vref_kt: None },
    }
}

/// v0.5.25 Approach-Stability v2 — kompletter Result-Struct.
#[derive(Debug, Clone, Default)]
pub struct ApproachStabilityV2 {
    pub vs_deviation_fpm: Option<f32>,
    pub max_vs_deviation_below_500_fpm: Option<f32>,
    pub bank_stddev_filtered_deg: Option<f32>,
    pub runway_changed_late: bool,
    pub stable_at_gate: Option<bool>,
    pub window_sample_count: u32,
    /// V/S-Jerk: mean |Δvs| sample-to-sample. Sim/Aircraft-agnostic.
    pub vs_jerk_fpm: Option<f32>,
    /// IAS-Stddev im Gate (Speed-Stability).
    pub ias_stddev_kt: Option<f32>,
    /// Mind. ein Sample im Gate hatte V/S < -1000 fpm.
    pub excessive_sink: bool,
    /// Gear+Flaps am 1000-ft-Sample in Landing-Konfig?
    pub stable_config: Option<bool>,
    /// HAT (statt AGL) als Window-Filter genutzt?
    pub used_hat: bool,
    /// v0.5.26: Stable bei DA (200 ft AGL/HAT) erreicht?
    pub stable_at_da: Option<bool>,
    /// v0.5.26: Anzahl Stall-Warning-Samples im gesamten Approach-Buffer.
    pub stall_warning_count: u32,
}

/// v0.5.25: Stable-Approach-Gate-konformes Stability-Maß.
///
/// FAA AC 120-71B / EASA SUPP-32 definieren Stable-Approach-Gate als
/// 1000 ft HAT (Height Above Touchdown). Innerhalb des Gates muessen
/// alle Parameter im Toleranzband sein, sonst go-around.
///
/// Window-Logik:
///   * Wenn `arr_airport_elevation_ft` bekannt: HAT = msl_ft − elevation,
///     Filter auf HAT ≤ 1000 ft (= ueber Mountain-Airports korrekt)
///   * Sonst: Fallback auf AGL ≤ 1000 ft (= AGL fluktuiert ueber Berg-
///     ruecken aber funktioniert für Flachland-Airports)
///
/// Stability-Metrics (alle im Gate-Window):
///   1. V/S-Jerk = mean |vs[i]−vs[i−1]| (PRIMAER, sim/aircraft-agnostic)
///   2. Bank-σ filtered (Vector-Windows ausgenommen, 5s nach RWY-Change)
///   3. IAS-σ (Speed-Stability)
///   4. Excessive-Sink-Flag (≥1 Sample mit V/S < -1000 fpm)
///   5. Stable-Config-Flag (Gear≥99% AND Flaps≥70% am gate-Eintritt)
///
/// Sekundaer (informativ, NICHT score-relevant):
///   6. V/S-Deviation vs 3°-ILS-Profil (target_vs = -gs_kt × 5.31)
///      — falsch fuer GA-Visual-Approach, deshalb nur informativ
fn compute_approach_stability_v2(
    buf: &std::collections::VecDeque<ApproachBufferSample>,
    arr_elevation_ft: Option<f32>,
    td_ts: Option<DateTime<Utc>>,
    // v0.15.17: echter Gleitpfad-Winkel aus den Navdaten (Navigraph). Steile
    // Anflüge (z.B. EGLC 5,5°) haben physikalisch höhere Sink-Raten — ein fixer
    // 3°-Vergleich wertet sie sonst fälschlich als „excessive/unstable" (Live-
    // Report Michael, London City). `None` (Runway nicht aufgelöst / nur
    // OurAirports-Fallback / kein ILS) → Faktor 1,0 → IDENTISCH zum bisherigen
    // 3°-Verhalten (Audit-Invariante: keine Regression ohne Daten).
    glideslope_angle_deg: Option<f64>,
    // v0.16.6: optionales Zeit-Fenster (touchdown_ts, duration) — nur Samples
    // innerhalb `duration` VOR dem Touchdown (und keine danach) werden
    // gewertet. Genutzt vom Sampler-Pfad (Bush-Flüge, FSM erreicht Landing
    // nie): dort kann der Buffer durch das phasen-unabhängige Sampling einen
    // 38-min-Low-Level-Cruise enthalten, der das 1000-ft-Gate sonst mit
    // Manöver-Rauschen vergiftet. `None` = EXAKT das bisherige Verhalten
    // (FSM-Pfad + alle bestehenden Tests — Audit-Invariante).
    window: Option<(DateTime<Utc>, chrono::Duration)>,
) -> ApproachStabilityV2 {
    // Fenster-Filter zuerst, dann identische Auswertung via Rekursion mit
    // `None` — so existiert die eigentliche Mess-Logik nur einmal.
    if let Some((td, dur)) = window {
        let filtered = approach_buffer_window(buf, td, dur);
        return compute_approach_stability_v2(
            &filtered,
            arr_elevation_ft,
            td_ts,
            glideslope_angle_deg,
            None,
        );
    }

    let mut out = ApproachStabilityV2::default();

    // Skalierungsfaktor relativ zum 3°-Standard. tan-basiert (physikalisch
    // korrekt: V/S ∝ tan(Gleitwinkel)). Plausibilitäts-Clamp 2,0–7,5° — alles
    // außerhalb gilt als unzuverlässige Navdaten → Fallback 3° (Faktor 1,0).
    // Bei exakt 3,0° ist der Faktor exakt 1,0 → bit-identisch zur alten Logik.
    let gs_factor: f64 = glideslope_angle_deg
        .filter(|g| (2.0..=7.5).contains(g))
        .map(|g| g.to_radians().tan() / 3.0_f64.to_radians().tan())
        .unwrap_or(1.0);

    // 1) Window-Filter: HAT bevorzugt, AGL als Fallback.
    let use_hat = arr_elevation_ft.is_some();
    out.used_hat = use_hat;
    let height_for = |s: &ApproachBufferSample| -> f32 {
        match arr_elevation_ft {
            Some(elev) => s.msl_ft - elev,
            None => s.agl_ft,
        }
    };
    // v0.5.46: zusaetzlicher Flare-Cutoff (Adrian-Feedback).
    // Pilot-Pull in den letzten 3 sec vor TD ist ein Manoever, kein
    // Stabilitaets-Indikator. Wenn td_ts None (= Berechnung mid-flight
    // bevor TD erreicht), nur Hoehen-Filter.
    let gate_samples: Vec<&ApproachBufferSample> = buf.iter()
        .filter(|s| {
            let h = height_for(s);
            let in_height_band = h > 0.0 && h <= 1000.0;
            let pre_flare = match td_ts {
                Some(td) => (td - s.at).num_milliseconds() >= APPROACH_FLARE_CUTOFF_MS,
                None => true,
            };
            in_height_band && pre_flare
        })
        .collect();
    out.window_sample_count = gate_samples.len() as u32;
    if gate_samples.len() < 3 {
        return out;
    }

    // 2) RWY-Change-Detection ueber GANZEN Buffer.
    let runway_changes: Vec<DateTime<Utc>> = {
        let mut changes = Vec::new();
        let mut prev_rwy: Option<&str> = None;
        for s in buf.iter() {
            let curr = s.selected_runway.as_deref();
            if let (Some(p), Some(c)) = (prev_rwy, curr) {
                if p != c {
                    changes.push(s.at);
                    if height_for(s) < 1500.0 {
                        out.runway_changed_late = true;
                    }
                }
            }
            if curr.is_some() {
                prev_rwy = curr;
            }
        }
        changes
    };
    let in_vector_window = |t: DateTime<Utc>| -> bool {
        runway_changes.iter().any(|&change| {
            (t - change).num_milliseconds().abs() <= 5_000
        })
    };

    // 3) V/S-Jerk (PRIMAER): mean |Δvs| sample-to-sample.
    //    Sim/Aircraft-agnostic — funktioniert für Jet, Turboprop, GA gleich.
    if gate_samples.len() >= 2 {
        let mut jerk_sum = 0.0_f64;
        for w in gate_samples.windows(2) {
            jerk_sum += (w[1].vs_fpm - w[0].vs_fpm).abs() as f64;
        }
        out.vs_jerk_fpm = Some((jerk_sum / (gate_samples.len() - 1) as f64) as f32);
    }

    // 4) IAS-Stddev (Speed-Stability).
    let n = gate_samples.len() as f64;
    let mean_ias = gate_samples.iter().map(|s| s.ias_kt as f64).sum::<f64>() / n;
    let var_ias = gate_samples.iter()
        .map(|s| (s.ias_kt as f64 - mean_ias).powi(2))
        .sum::<f64>() / n;
    out.ias_stddev_kt = Some(var_ias.sqrt() as f32);

    // 5) Excessive-Sink-Flag. v0.15.17: Schwelle mit dem Gleitwinkel skaliert —
    // bei 3° bleibt's −1000 fpm, bei 5,5° (z.B. EGLC) ~−1834 fpm, sodass ein
    // korrekt geflogener Steilanflug nicht fälschlich „excessive" ist.
    let excessive_sink_threshold = -1000.0 * gs_factor;
    out.excessive_sink = gate_samples
        .iter()
        .any(|s| f64::from(s.vs_fpm) < excessive_sink_threshold);

    // 6) Stable-Config: Gear+Flaps am 1000-ft-Sample (= aeltester
    //    Sample im Gate, = der mit hoechster Hoehe).
    if let Some(gate_entry) = gate_samples.iter()
        // NaN-safe: a missing/unreadable SimVar height yields NaN, and
        // `partial_cmp` returns None on NaN — `.unwrap()` would PANIC mid-scoring.
        // Treat NaN as Equal (no reorder) instead, like the sort at the IAS path.
        .max_by(|a, b| height_for(a).partial_cmp(&height_for(b)).unwrap_or(std::cmp::Ordering::Equal))
    {
        let gear_ok = gate_entry.gear_position >= 0.99;
        // v0.12.1 (Stream C LE11): detect an unreadable flaps dataref.
        // Study-level X-Plane add-ons (Hot-Start CL650 etc.) don't drive
        // the standard flap dataref → flaps_position stays 0 the whole
        // approach. If gear is down and the gate-entry speed is in the
        // landing range, flaps-0 is a broken reading, not "pilot forgot
        // flaps" — report the config as not-assessable (None) rather than
        // a false "INCOMPLETE" fail. A genuine flapless approach would be
        // far faster than FLAPS_UNREADABLE_MAX_IAS_KT.
        let flaps_all_zero = gate_samples.iter().all(|s| s.flaps_position < 0.01);
        let flaps_unreadable = flaps_all_zero
            && gear_ok
            && gate_entry.ias_kt < FLAPS_UNREADABLE_MAX_IAS_KT;
        if flaps_unreadable {
            out.stable_config = None;
        } else {
            let flaps_ok = gate_entry.flaps_position >= 0.70;
            out.stable_config = Some(gear_ok && flaps_ok);
        }
    }

    // 7) V/S-Deviation vs 3° ILS-Profil (sekundaer, nur informativ).
    let mut sum_dev = 0.0_f64;
    let mut max_dev_below_500 = 0.0_f32;
    for s in &gate_samples {
        // v0.15.17: Ziel-V/S am ECHTEN Gleitwinkel (gs_factor); bei 3° = ×1,0.
        let target_vs = -(s.gs_kt as f64) * 5.31 * gs_factor;
        let dev = (s.vs_fpm as f64 - target_vs).abs();
        sum_dev += dev;
        // v0.12.1 (Stream C LE12): the "< 500 ft" band excludes the
        // flare / ground-effect regime — a V/S excursion below
        // MAX_VS_DEV_FLOOR_FT is the flare, not approach instability.
        let h = height_for(s);
        if h <= 500.0 && h >= MAX_VS_DEV_FLOOR_FT {
            let dev_f32 = dev as f32;
            if dev_f32 > max_dev_below_500 {
                max_dev_below_500 = dev_f32;
            }
        }
    }
    let mean_dev = sum_dev / gate_samples.len() as f64;
    out.vs_deviation_fpm = Some(mean_dev as f32);
    if max_dev_below_500 > 0.0 {
        out.max_vs_deviation_below_500_fpm = Some(max_dev_below_500);
    }

    // 8) Bank-Stddev filtered.
    let bank_filtered: Vec<f32> = gate_samples
        .iter()
        .filter(|s| !in_vector_window(s.at))
        .map(|s| s.bank_deg)
        .collect();
    if bank_filtered.len() >= 3 {
        let n = bank_filtered.len() as f64;
        let mean = bank_filtered.iter().map(|&b| b as f64).sum::<f64>() / n;
        let var = bank_filtered.iter()
            .map(|&b| (b as f64 - mean).powi(2))
            .sum::<f64>() / n;
        out.bank_stddev_filtered_deg = Some(var.sqrt() as f32);
    }

    // 9) Composite Stable-At-Gate Indikator.
    //    PRIMARY-Maße: jerk < 100 AND bank_sd < 5 AND ias_sd < 10
    //                AND no_excessive_sink AND stable_config
    let jerk_ok = out.vs_jerk_fpm.map(|j| j < 100.0).unwrap_or(false);
    let bank_ok = out.bank_stddev_filtered_deg.map(|b| b < 5.0).unwrap_or(true);
    let ias_ok = out.ias_stddev_kt.map(|i| i < 10.0).unwrap_or(true);
    let config_ok = out.stable_config.unwrap_or(true); // None = unbekannt, kein blocker
    let stable = jerk_ok && bank_ok && ias_ok && !out.excessive_sink && config_ok;
    out.stable_at_gate = Some(stable);

    // 10) v0.5.26: Stable-At-DA (200 ft) — gleicher Composite-Check
    //     aber mit den Samples die im 200-ft-Gate lagen (= subset).
    let da_samples: Vec<&ApproachBufferSample> = buf.iter()
        .filter(|s| {
            let h = height_for(s);
            h > 0.0 && h <= 200.0
        })
        .collect();
    if da_samples.len() >= 3 {
        let n_da = da_samples.len() as f64;
        // V/S-Jerk im 200-ft-Gate
        let mut jerk_sum = 0.0_f64;
        for w in da_samples.windows(2) {
            jerk_sum += (w[1].vs_fpm - w[0].vs_fpm).abs() as f64;
        }
        let da_jerk = jerk_sum / (da_samples.len() - 1) as f64;
        // Bank-σ im 200-ft-Gate (gefiltert)
        let da_bank: Vec<f32> = da_samples.iter()
            .filter(|s| !in_vector_window(s.at))
            .map(|s| s.bank_deg)
            .collect();
        let da_bank_sd = if da_bank.len() >= 3 {
            let mean = da_bank.iter().map(|&b| b as f64).sum::<f64>() / da_bank.len() as f64;
            let var = da_bank.iter()
                .map(|&b| (b as f64 - mean).powi(2))
                .sum::<f64>() / da_bank.len() as f64;
            var.sqrt() as f32
        } else { 0.0 };
        let da_ias_mean = da_samples.iter().map(|s| s.ias_kt as f64).sum::<f64>() / n_da;
        let da_ias_var = da_samples.iter()
            .map(|s| (s.ias_kt as f64 - da_ias_mean).powi(2))
            .sum::<f64>() / n_da;
        let da_ias_sd = da_ias_var.sqrt() as f32;
        // v0.15.18: dieselbe Gleitwinkel-Skalierung wie das 1000-ft-Gate
        // (excessive_sink_threshold oben). Der v0.15.17-London-Fix skalierte
        // NUR das 1000-ft-Gate — das 200-ft-DA-Gate blieb fix bei −1000 fpm.
        // Auf einem korrekt geflogenen Steilanflug (z.B. ENTC/4°, EGLC/5,5°)
        // liegt die Soll-Sinkrate am DA-Gate physikalisch schon über −1000 fpm
        // (4° @143 kt ≈ −1013 fpm), sodass `stable_at_da` dort mathematisch NIE
        // erreichbar war. Jetzt winkel-korrekt → identisch zum 1000-ft-Gate.
        let da_excess_sink = da_samples
            .iter()
            .any(|s| f64::from(s.vs_fpm) < excessive_sink_threshold);
        // Strenger Cutoff bei DA: jerk < 80, bank < 3°, ias < 8 kt
        let da_stable = da_jerk < 80.0
            && da_bank_sd < 3.0
            && da_ias_sd < 8.0
            && !da_excess_sink;
        out.stable_at_da = Some(da_stable);
    }

    // 11) v0.5.26: Stall-Warning-Counter ueber gesamten Buffer.
    out.stall_warning_count = buf.iter().filter(|s| s.stall_warning).count() as u32;

    out
}

/// Map a numeric landing score (0-100, finer granularity than the
/// 5-tier `LandingScore`) to a letter grade. Same A+/A/B+/B/C/D/F
/// scale as the Landing Analyzer reference tool. Boundaries chosen
/// so a clean butter touchdown (LandingScore::Smooth = 100) earns
/// A+, an Acceptable (80) earns B, Firm (60) earns C, etc.
fn letter_grade(numeric: i32) -> &'static str {
    match numeric {
        95..=100 => "A+",
        88..=94 => "A",
        82..=87 => "B+",
        75..=81 => "B",
        65..=74 => "C",
        50..=64 => "D",
        _ => "F",
    }
}

/// Render the full callsign as "DLH 155" (airline + space + number) when
/// the airline ICAO is known, falling back to bare "155" otherwise.
fn format_callsign(airline_icao: &str, flight_number: &str) -> String {
    if airline_icao.is_empty() {
        flight_number.to_string()
    } else {
        format!("{} {}", airline_icao, flight_number)
    }
}

/// Render an Option<f32> as kg with sensible "n/a" fallback for the
/// activity-log detail string. Used by the fuel/weight diagnostics.
fn fmt_kg(v: Option<f32>) -> String {
    match v {
        Some(n) if n > 0.0 => format!("{:.0} kg", n),
        Some(_) | None => "n/a".to_string(),
    }
}
fn fmt_kg_f64(v: Option<f64>) -> String {
    match v {
        Some(n) if n > 0.0 => format!("{:.0} kg", n),
        Some(_) | None => "n/a".to_string(),
    }
}

/// Emit a fuel/weight diagnostic line into the activity log at the
/// phase transitions where AeroACARS captures values into PIREP
/// fields. Lets the pilot verify after the fact what the app saw.
///
/// The four meaningful transitions:
///   * Pushback / TaxiOut → "Block fuel" capture window closes (well,
///     it's a running peak, but this is when the pilot rolls off the
///     stand and the value should be locked in).
///   * Takeoff           → TOW + takeoff fuel snapshotted into stats.
///   * Landing           → LDW + landing fuel snapshotted.
///   * BlocksOn          → final fuel + computed Fuel Used.
///
/// Other phases produce no entry.
fn log_fuel_weight_at_phase(
    app: &AppHandle,
    flight: &ActiveFlight,
    phase: FlightPhase,
    snap: &SimSnapshot,
) {
    // Take ALL values out under the lock, then drop it before calling
    // log_activity_handle (which reaches into AppState for the activity
    // log mutex — never hold two mutexes across an external call).
    let (
        block_fuel,
        takeoff_fuel,
        takeoff_weight,
        landing_fuel,
        landing_weight,
        last_fuel,
    ) = {
        let stats = flight.stats.lock().expect("flight stats");
        (
            stats.block_fuel_kg,
            stats.takeoff_fuel_kg,
            stats.takeoff_weight_kg,
            stats.landing_fuel_kg,
            stats.landing_weight_kg,
            stats.last_fuel_kg,
        )
    };

    let (message, detail) = match phase {
        FlightPhase::Pushback | FlightPhase::TaxiOut => {
            // Block fuel is a running peak — at this point we expect
            // it to roughly match `snap.fuel_total_kg` unless the
            // pilot just defueled. ZFW/payload/empty come straight
            // from the SimVar block.
            (
                "Fuel & Weight @ Block-off".to_string(),
                Some(format!(
                    "Block fuel {} | Live fuel {:.0} kg | ZFW {} | Payload {} | OEW {} | Total {}",
                    fmt_kg(block_fuel),
                    snap.fuel_total_kg,
                    fmt_kg(snap.zfw_kg),
                    fmt_kg(snap.payload_kg),
                    fmt_kg(snap.empty_weight_kg),
                    fmt_kg(snap.total_weight_kg),
                )),
            )
        }
        FlightPhase::Takeoff => {
            (
                "Fuel & Weight @ Takeoff".to_string(),
                Some(format!(
                    "Takeoff fuel {} | TOW {} | Block fuel was {}",
                    fmt_kg(takeoff_fuel),
                    fmt_kg_f64(takeoff_weight),
                    fmt_kg(block_fuel),
                )),
            )
        }
        FlightPhase::Landing => {
            (
                "Fuel & Weight @ Landing".to_string(),
                Some(format!(
                    "Landing fuel {} | LDW {} | TOW was {}",
                    fmt_kg(landing_fuel),
                    fmt_kg_f64(landing_weight),
                    fmt_kg_f64(takeoff_weight),
                )),
            )
        }
        FlightPhase::BlocksOn => {
            // Fuel Used = block fuel (peak before takeoff) minus
            // current fuel. Only show when both are valid and
            // block > current — otherwise the math is meaningless
            // (e.g. defuel during taxi, fuel SimVar missing).
            let fuel_used = match (block_fuel, last_fuel) {
                (Some(b), Some(c)) if b > 0.0 && b > c => Some(b - c),
                _ => None,
            };
            (
                "Fuel & Weight @ Block-on".to_string(),
                Some(format!(
                    "Final fuel {} | Fuel used {} | Landing fuel was {}",
                    fmt_kg(last_fuel),
                    fmt_kg(fuel_used),
                    fmt_kg(landing_fuel),
                )),
            )
        }
        // No diagnostic for other phase transitions.
        _ => return,
    };

    log_activity_handle(app, ActivityLevel::Info, message, detail);
}

// ---- Activity log ----

/// How many position-streamer ticks between persistence flushes. Stats
/// are snapshotted to disk every Nth post so a Tauri crash mid-flight
/// can resume with reasonably fresh distance/fuel/phase data instead of
/// the zeros we wrote at flight_start. 5 ticks ≈ every ~25–150 s
/// depending on phase cadence — fine for the cost of a small JSON write.
const STATS_PERSIST_EVERY_TICKS: u32 = 5;

/// Touchdown analyzer window in seconds — how long after the first
/// on-ground tick we keep refining peak G-force and peak descent rate
/// before locking in the final score. 5 s is enough to catch the spike
/// (which can lag the initial contact by a tick or two) without bleeding
/// into the rollout. Bounded above by `TOUCHDOWN_BUFFER_SECS` (the ring
/// buffer's reach) and below by `TOUCHDOWN_G_WINDOW_MS`.
const TOUCHDOWN_WINDOW_SECS: i64 = 5;

/// V/S sampling window around the on-ground edge, in milliseconds.
/// We pick the worst-case (most negative) V/S from buffered samples
/// within ±`/2` of the touchdown timestamp instead of using a single
/// tick. 500 ms matches BeatMyLanding's `TouchdownWindowMs` — large
/// enough that the actual contact frame falls inside even when the
/// edge detection is one tick late, small enough not to pull in
/// pre-flare descent or post-bounce rebound values.
const TOUCHDOWN_VS_WINDOW_MS: i64 = 500;

/// Peak-G search window, in milliseconds AFTER the on-ground edge.
/// G spike from gear strut compression typically peaks 100–300 ms
/// after first contact and is over within ~600 ms. We use 800 ms —
/// tighter than BeatMyLanding's `MaxGWindowMs` (1500) because the
/// later ms reach into strut REBOUND territory which inflates G with
/// pseudo-impact spikes, hurting the score on otherwise-clean
/// landings (the 1.24 G "acceptable" downgrade we kept seeing on
/// pilot reports of butter touchdowns).
const TOUCHDOWN_G_WINDOW_MS: i64 = 800;

/// Maximum window in seconds during which we still count subsequent
/// liftoffs as bounces of the original touchdown (rather than a fresh
/// landing event). Matches BeatMyLanding's `BounceWindow`.
const BOUNCE_WINDOW_SECS: i64 = 8;

/// AGL altitude (ft) the aircraft must climb above before we can
/// detect a bounce. Below this, on-ground flickers are noise (gear
/// strut oscillation, sloppy SimVar updates).
///
/// v0.8.3 (#3): von 35 ft auf 15 ft gesenkt. Vorher war der Wert an
/// BeatMyLanding's `BounceRadioAltThresholdFeet` (35) ausgerichtet, was
/// zur Folge hatte dass Standard-Bounces von 5-15 ft (= das was Piloten
/// als „typischer Hopser" wahrnehmen) NIE gezaehlt wurden. In 14 Tagen
/// Produktion: 183 Touchdowns, **5** Bounces erkannt (2.7 %), null aus
/// X-Plane, alle 5 nur bei extrem harten MSFS-Landungen (vs <= -500 fpm).
/// Reported von Adrian (2026-05-14 PR-Kontext, Beispiel #167).
///
/// Neuer Wert 15 ft = `touchdown_v2::BOUNCE_SCORED_MIN_AGL_FT`, damit
/// der live-Streamer-Tally und der Forensics-Override-Pfad gegen
/// dieselbe Schwelle messen. Forensic-only Bounces unter 15 ft fliessen
/// weiterhin nur in den touchdown_v2-Pfad ein (5-ft Forensic-Threshold),
/// werden nicht in `stats.bounce_count` gezaehlt. f64 to match
/// `SimSnapshot::altitude_agl_ft`.
const BOUNCE_AGL_THRESHOLD_FT: f64 = 15.0;

/// AGL altitude (ft) the aircraft must come back below to count one
/// bounce. The detector arms when AGL crosses up through THRESHOLD
/// and fires when it crosses back down through RETURN. Matches
/// BeatMyLanding's `BounceRadioAltReturnFeet`.
const BOUNCE_AGL_RETURN_FT: f64 = 5.0;

/// Max samples retained in `FlightStats::approach_buffer`. Position
/// streamer ticks every 5-8 s during Approach/Final, so 120 samples
/// ≈ 10-15 min — plenty to cover even a long ILS approach.
const APPROACH_BUFFER_MAX: usize = 120;

/// Primary rollout-end trigger: groundspeed at which we consider the
/// pilot has finished using the runway and is about to clear at a
/// high-speed taxiway exit. Real pilots almost never decelerate to a
/// full stop on the runway — they brake to ~40 kt and turn off at the
/// next exit. Using a 40 kt threshold gives a "runway distance used"
/// metric that matches what other ACARS tools (BeatMyLanding,
/// vmsACARS) and FOQA reports show.
///
/// Source for 40 kt: ICAO Doc 9981 (Procedures for Air Navigation
/// Services — Aerodromes) recommends rapid-exit taxiways be designed
/// for a 65 km/h (≈ 35 kt) exit speed; FAA AC 150/5300-13B uses 60 kt
/// for high-speed RETs but pilots routinely brake further to ~40 kt
/// before committing to the turn.
const ROLLOUT_EXIT_GS_KT: f32 = 40.0;

/// Secondary trigger: full stop on the runway (rare in practice — long
/// rwys at uncontrolled fields, GA touch-and-go's gone wrong). Kept
/// as a hard floor so a pilot who really does brake to a stop still
/// gets a finalised metric.
const ROLLOUT_STOP_GS_KT: f32 = 5.0;

/// Tertiary trigger: heading has rotated this many degrees from the
/// touchdown heading, meaning the aircraft has clearly turned onto a
/// taxiway and is no longer using the runway. Stops the accumulator
/// from counting the taxi-out distance against the rollout figure.
/// Computed signed (wraparound-safe) and compared in absolute value.
const ROLLOUT_HEADING_DEVIATION_DEG: f32 = 30.0;

/// Hard-landing thresholds, ordered worst-first. The first row that
/// the peak |V/S| or G-force breaches wins; combined with
/// `bounce_count` this maps to a `LandingScore`.
///
/// Sources verified rather than guessed (the older 60 / 240 / 600 fpm
/// table downgraded clean -91 fpm landings to Acceptable, which the
/// pilot rightly called out as unrealistic):
///
///   * **Boeing 737 FCOM**: Hard-Landing-Inspection > 600 fpm OR
///     > 1.7 G. Severe > 1000 fpm OR > 2.6 G.
///   * **Airbus A320 FCOM**: Max recommended TD sink 360 fpm; hard-
///     landing inspection ≈ 600 fpm OR 2.6 G.
///   * **vmsACARS default rules.yml** (extracted from the shipped PHP
///     module): single `HARD_LANDING` rule at parameter = 500 fpm.
///   * **Lufthansa FOQA category bands** (publicly documented):
///       Soft   < 200 fpm
///       Normal 200–400 fpm
///       Firm   400–600 fpm
///       Hard   > 600 fpm
///       Heavy  > 1000 fpm
///   * **Community ACARS conventions** (Smartcars, BeatMyLanding
///     toast colour bands, LandingRate.com): butter < 200 fpm,
///     good < 400, ok < 600, bad above.
///
/// Consensus → these tiers:
///
/// ```text
///                  V/S        G
///   Smooth         < 200 fpm  < 1.20 G   (butter / greaser)
///   Acceptable     < 400 fpm  < 1.40 G   (normal LH FOQA)
///   Firm           < 600 fpm  < 1.70 G   (firm but accepted)
///   Hard           < 1000 fpm < 2.10 G   (FCOM inspection trigger)
///   Severe         ≥ 1000 fpm ≥ 2.10 G   (structural concern)
/// ```
// V/S boundaries — fpm, |abs| at touchdown:
const TOUCHDOWN_VS_SEVERE_FPM: f32 = 1000.0;
const TOUCHDOWN_VS_HARD_FPM: f32 = 600.0;
const TOUCHDOWN_VS_FIRM_FPM: f32 = 400.0;
const TOUCHDOWN_VS_SMOOTH_FPM: f32 = 200.0;
// G boundaries — peak G in the touchdown window:
const TOUCHDOWN_G_SEVERE: f32 = 2.10;
const TOUCHDOWN_G_HARD: f32 = 1.70;
const TOUCHDOWN_G_FIRM: f32 = 1.40;
const TOUCHDOWN_G_SMOOTH: f32 = 1.20;

/// AP master toggles only emit a log entry once they've held for this
/// many seconds. Stops a flickering / pulsed LVar (Fenix's momentary
/// `S_FCU_AP*` was the original culprit) from spamming the log with
/// alternating ENGAGED / OFF lines.
const AP_DEBOUNCE_SECS: i64 = 2;

// ---- v0.16.10 Premium-Cockpit-Daten — Debounce-Fenster ----
/// Generic-FMA-Zeile (Fenix/FBW/INI/…): 3 s wie beim PMDG-Pendant —
/// FMA-Sub-Modes wechseln bei Mode-Reversions gern mehrfach pro Sekunde.
const PREMIUM_FMA_DEBOUNCE_SECS: i64 = 3;
/// MASTER CAUTION / MASTER WARNING: Annunciator-Lampen flackern bei
/// Cockpit-Tests am Boden — 2 s Stabilität bevor eine Transition loggt.
const MASTER_ANNUNCIATOR_DEBOUNCE_SECS: i64 = 2;
/// Flugzeug-eigene FMGC/FWC-Phase: rein informativ, 5 s reichen.
const AIRCRAFT_PHASE_DEBOUNCE_SECS: i64 = 5;
/// Stab-out-of-trim-Annunciator: pulst während Trim-Läufen.
const STAB_TRIM_DEBOUNCE_SECS: i64 = 5;
/// Schubhebel-Detent (TOGA/FLX-MCT/CL): der Hebel wandert beim Setzen
/// durch Zwischen-Detents — 3 s Stabilität pro Gate.
const THRUST_GATE_DEBOUNCE_SECS: i64 = 3;
/// v0.16.10 QS (B1): Approach-Speeds — VLS/VAPP driften auf FBW/INI
/// laufend (Gewichts-/Konfigurations-Neuberechnung); 10 s Stabilität
/// pro 5-kt-Bucket bevor eine Änderung loggt.
const APPROACH_SPEEDS_DEBOUNCE_SECS: i64 = 10;
/// v0.16.10 QS (B1): Bucket-Breite des Approach-Speeds-Latch-Keys.
const APPROACH_SPEEDS_BUCKET_KT: f64 = 5.0;
/// v0.16.10 QS (M5): Connect-Grace — so lange nach einem Stream-
/// (Re-)Start ignorieren die Premium-Logger alle Snapshots (Addon-
/// LVars lesen direkt nach Connect 0.0 bis das WASM sie befüllt).
const PREMIUM_LOG_WARMUP_SECS: i64 = 10;
/// v0.16.10 QS (M5): Tick-Lücke ab der ein Stream-(Re-)Start
/// angenommen wird. Der Streamer tickt adaptiv alle 0,5-3 s — alles
/// darüber heißt Sim-Disconnect/Pause/App-Resume.
const PREMIUM_LOG_STREAM_GAP_SECS: i64 = 15;
/// v0.16.10 QS (Minor 6): Umkehrschub-/Ground-Spoiler-Logger brauchen
/// Groundspeed über dieser Schwelle an der Rising-Edge — ein Lever-
/// Check beim Taxi (Reverser kurz gezogen, Spoiler-Test) soll keine
/// "Umkehrschub aktiviert"-Zeile erzeugen.
const REVERSER_SPOILER_MIN_GS_KT: f32 = 40.0;
/// Below-G/S-Alert: re-arm sobald der Alert so lange geklärt ist
/// (einmal-pro-Approach-Latch, ein neuer Sinkflug unter den G/S soll
/// wieder loggen dürfen).
const BELOW_GS_REARM_SECS: i64 = 30;

/// v0.16.10: Generischer Latch+Debounce-Tracker für Premium-Activity-
/// Log-Zeilen. Gleiches Idiom wie der AP-Master-Debounce
/// (`AP_DEBOUNCE_SECS`-Block in `detect_telemetry_changes`), nur
/// wiederverwendbar statt drei Felder pro Logger:
///   * der ERSTE beobachtete Wert latcht IMMER stumm (kein Eintrag
///     beim Sim-Connect / App-Resume),
///   * eine Änderung wird erst publiziert wenn der neue Wert
///     `debounce_secs` stabil gehalten wurde — ein LVar-Puls kürzer
///     als das Fenster produziert GAR KEINEN Eintrag,
///   * Rückkehr zum gelatchten Wert räumt den Pending-State ab.
#[derive(Debug, Clone, Default)]
struct DebouncedLogState<T: PartialEq + Clone> {
    last_logged: Option<T>,
    pending: Option<T>,
    pending_since: Option<DateTime<Utc>>,
}

impl<T: PartialEq + Clone> DebouncedLogState<T> {
    /// Feed den aktuell beobachteten Wert; `true` ⇒ Transition ist
    /// debounced-stabil und soll JETZT geloggt werden (der Wert ist
    /// dann bereits als `last_logged` committed).
    fn update(&mut self, value: T, now: DateTime<Utc>, debounce_secs: i64) -> bool {
        if self.last_logged.as_ref() == Some(&value) {
            // Wert stimmt wieder mit dem gelatchten überein → Pending-
            // Änderung (falls vorhanden) war ein Puls, verwerfen.
            self.pending = None;
            self.pending_since = None;
            return false;
        }
        if self.last_logged.is_none() {
            // Erster Wert überhaupt — stumm latchen.
            self.last_logged = Some(value);
            self.pending = None;
            self.pending_since = None;
            return false;
        }
        if self.pending.as_ref() != Some(&value) {
            // Neue (oder andere) Änderung — Debounce-Timer starten.
            self.pending = Some(value);
            self.pending_since = Some(now);
            return false;
        }
        match self.pending_since {
            Some(since) if (now - since).num_seconds() >= debounce_secs => {
                self.last_logged = Some(value);
                self.pending = None;
                self.pending_since = None;
                true
            }
            _ => false,
        }
    }

    /// v0.16.10 QS (B1): wie `update`, aber der ERSTE beobachtete Wert
    /// loggt SOFORT statt stumm zu latchen — für Zeilen, deren erstes
    /// Auftauchen selbst das informative Ereignis ist (Approach-Speeds:
    /// der erste Some-Wert = FMS-Perf-Eingabe-Zeitstempel).
    fn update_first_logs(&mut self, value: T, now: DateTime<Utc>, debounce_secs: i64) -> bool {
        if self.last_logged.is_none() {
            self.last_logged = Some(value);
            return true;
        }
        self.update(value, now, debounce_secs)
    }
}

/// v0.16.10 QS (M5): Connect-Grace-Gate für die Premium-Logger.
/// Liefert `true` solange Snapshots IGNORIERT werden sollen. Mechanik:
///   * jede Tick-Lücke > `PREMIUM_LOG_STREAM_GAP_SECS` (oder der
///     allererste Tick) gilt als Stream-(Re-)Start und öffnet ein
///     `PREMIUM_LOG_WARMUP_SECS`-Fenster,
///   * innerhalb des Fensters latcht und loggt NICHTS (die Addon-LVars
///     lesen nach Connect/Resume 0.0 bis das WASM sie befüllt),
///   * nach dem Fenster latcht der erste — jetzt echte — Wert über die
///     bestehende First-Silent-Semantik der Tracker.
fn premium_log_warmup_active(
    last_tick_at: &mut Option<DateTime<Utc>>,
    warmup_until: &mut Option<DateTime<Utc>>,
    now: DateTime<Utc>,
) -> bool {
    let stream_restarted = match last_tick_at.replace(now) {
        None => true,
        Some(prev) => (now - prev).num_seconds() > PREMIUM_LOG_STREAM_GAP_SECS,
    };
    if stream_restarted {
        *warmup_until = Some(now + chrono::Duration::seconds(PREMIUM_LOG_WARMUP_SECS));
    }
    match *warmup_until {
        Some(until) if now < until => true,
        Some(_) => {
            *warmup_until = None;
            false
        }
        None => false,
    }
}

/// Suppress repeated "same" activity entries fired within this window.
/// React StrictMode in dev double-mounts effects, so the login + session-
/// restore commands run twice on startup; we don't want the user to see
/// every event duplicated. Five seconds is wide enough to dedupe those
/// without merging genuine repeats during a long flight.
const ACTIVITY_DEDUPE_WINDOW_SECS: i64 = 5;

fn would_dedupe(log: &VecDeque<ActivityEntry>, now: DateTime<Utc>, message: &str) -> bool {
    log.back().is_some_and(|prev| {
        prev.message == message
            && (now - prev.timestamp).num_seconds() < ACTIVITY_DEDUPE_WINDOW_SECS
    })
}

/// Push an entry into the in-memory activity log. Caps the buffer at
/// `ACTIVITY_LOG_CAPACITY` so a long-running session doesn't leak memory.
/// Also mirrors the entry to `tracing` at the matching level so command-
/// line debugging stays consistent. Identical messages within
/// `ACTIVITY_DEDUPE_WINDOW_SECS` of each other collapse to a single line.
fn log_activity(
    state: &tauri::State<'_, AppState>,
    level: ActivityLevel,
    message: impl Into<String>,
    detail: Option<String>,
) {
    let now = Utc::now();
    let message = message.into();
    {
        let log = state.activity_log.lock().expect("activity_log lock");
        if would_dedupe(&log, now, &message) {
            return;
        }
    }
    let entry = ActivityEntry {
        timestamp: now,
        level,
        message,
        detail,
    };
    match level {
        ActivityLevel::Info => {
            tracing::info!(message = %entry.message, detail = ?entry.detail, "activity")
        }
        ActivityLevel::Warn => {
            tracing::warn!(message = %entry.message, detail = ?entry.detail, "activity");
            sentry_init::capture_activity(&entry.message, entry.detail.as_deref(), sentry::Level::Warning);
        }
        ActivityLevel::Error => {
            tracing::error!(message = %entry.message, detail = ?entry.detail, "activity");
            sentry_init::capture_activity(&entry.message, entry.detail.as_deref(), sentry::Level::Error);
        }
    }
    let mut log = state.activity_log.lock().expect("activity_log lock");
    log.push_back(entry);
    while log.len() > ACTIVITY_LOG_CAPACITY {
        log.pop_front();
    }
    save_activity_log(&log);
}

/// Same as `log_activity` but takes an `AppHandle` for use inside the
/// streamer task (which has no `tauri::State` handle).
fn log_activity_handle(
    app: &AppHandle,
    level: ActivityLevel,
    message: impl Into<String>,
    detail: Option<String>,
) {
    let now = Utc::now();
    let message = message.into();
    let state = app.state::<AppState>();
    {
        let log = state.activity_log.lock().expect("activity_log lock");
        if would_dedupe(&log, now, &message) {
            return;
        }
    }
    let entry = ActivityEntry {
        timestamp: now,
        level,
        message,
        detail,
    };
    match level {
        ActivityLevel::Info => {
            tracing::info!(message = %entry.message, detail = ?entry.detail, "activity")
        }
        ActivityLevel::Warn => {
            tracing::warn!(message = %entry.message, detail = ?entry.detail, "activity");
            sentry_init::capture_activity(&entry.message, entry.detail.as_deref(), sentry::Level::Warning);
        }
        ActivityLevel::Error => {
            tracing::error!(message = %entry.message, detail = ?entry.detail, "activity");
            sentry_init::capture_activity(&entry.message, entry.detail.as_deref(), sentry::Level::Error);
        }
    }
    let mut log = state.activity_log.lock().expect("activity_log lock");
    log.push_back(entry);
    while log.len() > ACTIVITY_LOG_CAPACITY {
        log.pop_front();
    }
    save_activity_log(&log);
}

/// `GET` the entire activity log. Frontend polls this every couple of
/// seconds; `ACTIVITY_LOG_CAPACITY` keeps the payload bounded.
#[tauri::command]
fn activity_log_get(state: tauri::State<'_, AppState>) -> Vec<ActivityEntry> {
    let log = state.activity_log.lock().expect("activity_log lock");
    log.iter().cloned().collect()
}

/// Wipe the activity log. Useful when the pilot starts a fresh session
/// and doesn't want the previous flight's chatter cluttering the panel.
#[tauri::command]
fn activity_log_clear(state: tauri::State<'_, AppState>) {
    let mut log = state.activity_log.lock().expect("activity_log lock");
    log.clear();
    // Also persist the cleared state — otherwise a restart would
    // restore the pre-clear contents from disk.
    save_activity_log(&log);
}

// v0.13.7: activity_log_add Tauri-Command entfernt — wurde von v0.7.17 fuer
