#[tauri::command]
fn flight_status(
    app: AppHandle,
    state: tauri::State<'_, AppState>,
) -> Option<ActiveFlightInfo> {
    let guard = state.active_flight.lock().expect("active_flight lock");
    let flight = guard.as_ref()?;
    // v0.12.1 (Stream E): while the resume banner is up, check on every
    // poll whether the current sim position matches the persisted flight.
    // If the sim crashed and reloaded the aircraft on the ground (or far
    // away), the banner must NOT auto-confirm — the pilot has to click.
    let resume_position_suspect = if flight.was_just_resumed.load(Ordering::Relaxed) {
        match current_snapshot(&app) {
            Some(snap) => {
                let (phase, pos) = {
                    let stats = flight.stats.lock().expect("flight stats");
                    let pos = match (stats.last_lat, stats.last_lon) {
                        (Some(la), Some(lo)) => Some((la, lo)),
                        _ => None,
                    };
                    (stats.phase, pos)
                };
                is_resume_position_suspect(
                    phase,
                    pos,
                    snap.on_ground,
                    snap.lat,
                    snap.lon,
                )
            }
            None => false,
        }
    } else {
        false
    };
    Some(flight_info(flight.as_ref(), resume_position_suspect))
}

#[derive(Serialize)]
struct FlightLogStatsDto {
    count: u32,
    total_bytes: u64,
}

/// Disk usage of the per-flight JSONL recorder files. Powers the
/// Settings → Speicher section so the user knows how much is on disk
/// before they hit "alle löschen".
#[tauri::command]
fn flight_logs_stats(app: AppHandle) -> Result<FlightLogStatsDto, UiError> {
    let dir = app
        .path()
        .app_data_dir()
        .map_err(|_| UiError::new("no_app_data_dir", "no app data dir"))?;
    let s = recorder::flight_logs_stats(dir).map_err(|e| {
        UiError::new("flight_logs_stats_failed", format!("could not read flight logs dir: {e}"))
    })?;
    Ok(FlightLogStatsDto {
        count: s.count,
        total_bytes: s.total_bytes,
    })
}

#[derive(Serialize)]
struct DeletedDto {
    deleted: u32,
}

/// Delete every per-flight JSONL recorder file. Triggered manually from
/// Settings — never automatically — so the active flight's log (if it
/// exists) gets removed too. The streamer just recreates it on the
/// next event append.
#[tauri::command]
fn flight_logs_delete_all(app: AppHandle) -> Result<DeletedDto, UiError> {
    let dir = app
        .path()
        .app_data_dir()
        .map_err(|_| UiError::new("no_app_data_dir", "no app data dir"))?;
    let n = recorder::flight_logs_delete_all(dir).map_err(|e| {
        UiError::new("flight_logs_delete_failed", format!("could not delete flight logs: {e}"))
    })?;
    tracing::info!(deleted = n, "flight logs purged (manual)");
    Ok(DeletedDto { deleted: n })
}

/// Delete per-flight JSONL files older than `older_than_days` (mtime).
/// Called from the JS layer once per app launch when the user has the
/// auto-purge toggle on (default 30 days).
#[tauri::command]
fn flight_logs_purge_older_than(app: AppHandle, older_than_days: u32) -> Result<DeletedDto, UiError> {
    let dir = app
        .path()
        .app_data_dir()
        .map_err(|_| UiError::new("no_app_data_dir", "no app data dir"))?;
    let n = recorder::flight_logs_purge_older_than(dir, older_than_days).map_err(|e| {
        UiError::new("flight_logs_purge_failed", format!("could not purge flight logs: {e}"))
    })?;
    if n > 0 {
        tracing::info!(deleted = n, days = older_than_days, "flight logs purged (auto)");
    }
    Ok(DeletedDto { deleted: n })
}

#[derive(Serialize)]
pub struct ResumableFlight {
    pirep_id: String,
    flight_number: String,
    dpt_airport: String,
    arr_airport: String,
    status: Option<String>,
}

/// Look on phpVMS for in-progress PIREPs the user could resume. Used to drive
/// the auto-detection banner on dashboard mount: if the answer is non-empty,
/// the UI offers to adopt with a 10s countdown.
///
/// Skipped (returns empty) if a flight is already attached locally —
/// either in memory (Disk-Resume already finished) OR still pending on
/// disk (Disk-Resume hasn't finished its async backfill yet but will
/// install the same PIREP shortly). Without the disk-file check, the
/// frontend's mount-time discovery race could find a separate
/// in-progress PIREP on phpVMS and offer it as a discovered flight,
/// then `flight_adopt` would crash with "another flight is already
/// active" the moment Disk-Resume committed.
#[tauri::command]
async fn flight_discover_resumable(
    app: AppHandle,
    state: tauri::State<'_, AppState>,
) -> Result<Vec<ResumableFlight>, UiError> {
    {
        let guard = state.active_flight.lock().expect("active_flight lock");
        if guard.is_some() {
            return Ok(Vec::new());
        }
    }
    if let Some(persisted) = read_persisted_flight(&app) {
        let age = Utc::now() - persisted.started_at;
        if age <= chrono::Duration::hours(RESUME_MAX_AGE_HOURS) {
            tracing::debug!(
                pirep_id = %persisted.pirep_id,
                "discover_resumable: disk-resume pending — returning empty so the disk flight wins"
            );
            return Ok(Vec::new());
        }
    }
    let client = current_client(&state)?;
    // v0.16.17: server-seitig auf IN_PROGRESS gefiltert (?state=0) statt
    // page-1-fetch-then-filter — sonst sind Orphans älter als ~20 Flüge
    // unsichtbar (paginate() liefert 20/Seite, newest first).
    let pireps = client.get_user_pireps_in_progress().await?;
    Ok(pireps
        .into_iter()
        .filter(|p| p.state == Some(0)) // defensiv — Server hat bereits gefiltert
        .filter_map(|p| {
            Some(ResumableFlight {
                pirep_id: p.id,
                flight_number: p.flight_number?,
                dpt_airport: p.dpt_airport_id.unwrap_or_default(),
                arr_airport: p.arr_airport_id.unwrap_or_default(),
                status: p.status,
            })
        })
        .collect())
}

/// Adopt a specific in-progress PIREP — creates the local ActiveFlight,
/// persists it to disk, starts the position streamer. Used by the resume
/// banner after the 10s countdown elapses (or the user clicks Resume now).
#[tauri::command]
async fn flight_adopt(
    app: AppHandle,
    state: tauri::State<'_, AppState>,
    pirep_id: String,
) -> Result<ActiveFlightInfo, UiError> {
    // Reserve the setup slot atomically — released automatically (via the
    // guard's Drop) on any error path, or disarmed once we've committed the
    // new ActiveFlight into state. Without this, two concurrent adopts
    // would both see active_flight=None and one would silently overwrite
    // the other (we observed this in production logs: StrictMode +
    // resume-banner re-render produced four "flight adopted" lines for a
    // single PIREP).
    let setup_guard = FlightSetupGuard::try_acquire(&state.flight_setup_in_progress)?;

    {
        let guard = state.active_flight.lock().expect("active_flight lock");
        if guard.is_some() {
            return Err(UiError::new(
                "flight_already_active",
                "another flight is already active",
            ));
        }
    }

    let client = current_client(&state)?;
    // v0.16.17: server-seitig auf IN_PROGRESS gefiltert (?state=0) — der
    // gesuchte PIREP kann älter als die ersten 20 paginierten Einträge sein.
    // Der state-Check im find() bleibt als defensive Doppelprüfung.
    let pireps = client.get_user_pireps_in_progress().await?;
    let pirep = pireps
        .into_iter()
        .find(|p| p.id == pirep_id && p.state == Some(0))
        .ok_or_else(|| {
            UiError::new(
                "pirep_not_resumable",
                "PIREP not found or no longer in progress",
            )
        })?;

    // Best-effort: look for a matching bid so we can carry fares forward to
    // the eventual file. If no bid matches, file with no fares — phpVMS keeps
    // whatever was set during prefile.
    let flight_number = pirep
        .flight_number
        .clone()
        .ok_or_else(|| UiError::new("pirep_invalid", "PIREP has no flight number"))?;
    let dpt_airport = pirep.dpt_airport_id.clone().unwrap_or_default();
    let arr_airport = pirep.arr_airport_id.clone().unwrap_or_default();

    let bids = client.get_bids().await.unwrap_or_default();
    let matching_bid = bids
        .iter()
        .find(|b| b.flight.flight_number == flight_number);
    let bid_id = matching_bid.map(|b| b.id).unwrap_or(0);
    let fares: Vec<(i64, i32)> = matching_bid
        .and_then(|b| b.flight.simbrief.as_ref())
        .and_then(|sb| sb.subfleet.as_ref())
        .map(|sf| {
            sf.fares
                .iter()
                .filter_map(|f| f.count.map(|c| (f.id, c)))
                .collect()
        })
        .unwrap_or_default();

    let airline_icao = matching_bid
        .and_then(|b| b.flight.airline.as_ref())
        .map(|a| a.icao.clone())
        .unwrap_or_default();
    let airline_logo_url = matching_bid
        .and_then(|b| b.flight.airline.as_ref())
        .and_then(|a| a.logo.clone())
        .filter(|s| !s.is_empty());

    // Look up planned registration so the activity log can compare it
    // against the live `ATC ID` SimVar — pilot sees instantly if the
    // wrong tail number is loaded in MSFS.
    // Bid.flight has no direct aircraft_id; the chosen aircraft lives
    // on the SimBrief OFP. If the pilot hasn't generated an OFP, we
    // simply leave planned_registration empty.
    // v0.3.0: zusätzlich Aircraft-ICAO + Name aus dem gleichen Call
    // ziehen. Damit der PIREP-Custom-Field "Aircraft Type" gefüllt
    // werden kann ohne extra Lookup auf der phpVMS-Detail-Seite.
    let aircraft_details = match matching_bid
        .and_then(|b| b.flight.simbrief.as_ref())
        .and_then(|sb| sb.aircraft_id)
    {
        Some(id) => client.get_aircraft(id).await.ok(),
        None => None,
    };
    let planned_registration = aircraft_details
        .as_ref()
        .and_then(|a| a.registration.clone())
        .unwrap_or_default()
        .trim()
        .to_string();
    let aircraft_icao = aircraft_details
        .as_ref()
        .and_then(|a| a.icao.clone())
        .unwrap_or_default()
        .trim()
        .to_string();
    let aircraft_name = aircraft_details
        .as_ref()
        .and_then(|a| a.name.clone())
        .unwrap_or_default()
        .trim()
        .to_string();

    let flight = Arc::new(ActiveFlight {
        pirep_id: pirep.id.clone(),
        bid_id,
        // v0.7.7: flight_id aus matching_bid wenn vorhanden, sonst leer.
        // Im Adopt-Pfad kann der Bid bereits weg sein (W5: phpVMS-7
        // entfernt Bid nach Prefile) — dann ist flight_id leer und
        // v0.7.8 muss diesen Fall behandeln.
        flight_id: matching_bid
            .map(|b| b.flight_id.clone())
            .unwrap_or_default(),
        // v0.7.8 v1.5: Match-Kandidaten — Adopt-Pfad, Bid kann weg sein.
        bid_callsign: matching_bid
            .and_then(|b| b.flight.callsign.clone())
            .filter(|s| !s.trim().is_empty()),
        pilot_callsign: state
            .cached_pilot_callsign
            .lock()
            .expect("cached_pilot_callsign lock")
            .clone(),
        // We don't know the original prefile time; treat "now" as the start
        // for our counters. The PIREP's actual times are intact server-side.
        started_at: Utc::now(),
        airline_icao,
        airline_logo_url,
        planned_registration,
        aircraft_icao,
        aircraft_name,
        flight_number,
        dpt_airport,
        arr_airport,
        fares,
        stats: Mutex::new(FlightStats::new()),
        stop: AtomicBool::new(false),
        // Surfaced via flight_status to trigger the resume banner.
        was_just_resumed: AtomicBool::new(true),
        streamer_spawned: AtomicBool::new(false),
        cancelled_remotely: AtomicBool::new(false),
        position_outbox: Mutex::new(std::collections::VecDeque::new()),
        phpvms_worker_spawned: AtomicBool::new(false),
        touchdown_sampler_spawned: AtomicBool::new(false),
        connection_state: std::sync::atomic::AtomicU8::new(CONN_STATE_LIVE),
        // v0.8.0: Navdata-Cache startet leer — wird von
        // `fetch_navdata_for_flight` (Slice B) parallel beim Flugstart
        // populiert. Leer = OurAirports-Fallback aktiv (= Verhalten
        // vor v0.8.0).
        navdata: Mutex::new(NavdataCache::default()),
    });

    save_active_flight(&app, &flight);
    // v0.8.0: parallel-fetch dep/arr/alt-Navdata vom VPS. Non-blocking
    // (Background-Task), Failure → OurAirports-Fallback (transparent).
    // Adopt-Pfad: matching_bid kann weg sein, dann fehlt nur der
    // Alternate — dep+arr kommen immer aus dem ActiveFlight.
    {
        let mut icaos = vec![flight.dpt_airport.clone(), flight.arr_airport.clone()];
        if let Some(alt) = matching_bid.and_then(|b| b.flight.alt_airport_id.clone()) {
            if !alt.trim().is_empty() {
                icaos.push(alt);
            }
        }
        spawn_navdata_fetch(&app, &flight, icaos);
    }
    {
        let mut guard = state.active_flight.lock().expect("active_flight lock");
        *guard = Some(Arc::clone(&flight));
    }
    // ActiveFlight is now committed — release the in-progress flag so the
    // active_flight mutex alone guards subsequent adopts.
    setup_guard.disarm();
    // Don't spawn the streamer yet — the resume banner is in countdown mode
    // and the user can still cancel. `flight_resume_confirm` spawns it.
    let _ = client;

    let info = flight_info(flight.as_ref(), false);
    log_activity(
        &state,
        ActivityLevel::Info,
        format!(
            "Adopted in-progress flight {} ({} → {})",
            format_callsign(&flight.airline_icao, &flight.flight_number),
            flight.dpt_airport,
            flight.arr_airport
        ),
        Some(format!("PIREP {}", flight.pirep_id)),
    );
    record_event(
        &app,
        &flight.pirep_id,
        &FlightLogEvent::FlightStarted {
            timestamp: Utc::now(),
            pirep_id: flight.pirep_id.clone(),
            airline_icao: flight.airline_icao.clone(),
            flight_number: flight.flight_number.clone(),
            dpt_airport: flight.dpt_airport.clone(),
            arr_airport: flight.arr_airport.clone(),
        },
    );
    Ok(info)
}

/// Start tracking a flight: prefile a PIREP and begin position streaming.
#[tauri::command]
async fn flight_start(
    app: AppHandle,
    state: tauri::State<'_, AppState>,
    bid_id: i64,
    // v0.8.3 (#7): Optional acknowledge-Flag fuer Aircraft-Mismatch.
    // Bei None / Some(false) liefert der Mismatch-Check eine WARNUNG
    // (Error-Code "aircraft_mismatch_warning"), bei Some(true) wird der
    // Check uebersprungen — analog `flight_start_manual`. Erlaubt
    // Wetlease-Workflows (PaxStudio-Loadsheet) ohne Hard-Block.
    #[allow(non_snake_case)]
    acknowledgeAircraftMismatch: Option<bool>,
) -> Result<ActiveFlightInfo, UiError> {
    let ack_aircraft_mismatch = acknowledgeAircraftMismatch.unwrap_or(false);
    // Same race protection as flight_adopt: a double-click on "Start flight"
    // would otherwise prefile two PIREPs against the same bid.
    let setup_guard = FlightSetupGuard::try_acquire(&state.flight_setup_in_progress)?;

    {
        let guard = state.active_flight.lock().expect("active_flight lock");
        if guard.is_some() {
            return Err(UiError::new(
                "flight_already_active",
                "another flight is already active",
            ));
        }
    }

    // v0.13.16: VPS-Aircraft-Aliase JETZT auffrischen — nebenläufig, damit
    // ein vom VA-Admin frisch eingetragener Alias (z.B. E55P→PHENOM 300)
    // schon auf DIESEN Startversuch wirkt statt erst nächste Session. Vorher
    // wurden die Aliase nur lazy in `spawn_navdata_fetch` NACH dem Mismatch-
    // Gate gezogen (und bei bereits gecachten Airports ganz übersprungen).
    // Der Fetch überlappt mit get_bids/get_airport/get_aircraft unten → quasi
    // keine Mehrlatenz; awaited direkt vor dem Gate. Best-effort + 5 s-Timeout:
    // hängt den Start nie, bei Fehler/Timeout bleibt der vorhandene Cache gültig.
    let alias_refresh = {
        let app_aliases = app.clone();
        let token = secrets::load_api_key(MQTT_KEYRING_PASSWORD).ok().flatten();
        tokio::spawn(async move {
            let _ = tokio::time::timeout(
                Duration::from_secs(5),
                fetch_aircraft_aliases_into_state(app_aliases, None, token),
            )
            .await;
        })
    };

    let client = current_client(&state)?;
    let bids = client.get_bids().await?;
    let bid = bids
        .into_iter()
        .find(|b| b.id == bid_id)
        .ok_or_else(|| UiError::new("bid_not_found", "bid not found in current bids"))?;

    // ---- Pre-flight gating: must be on the ground at the departure airport ----
    let snapshot = current_snapshot(&app).ok_or_else(|| {
        UiError::new("no_sim_snapshot", "no sim snapshot yet — is the simulator connected?")
    })?;
    if !snapshot.on_ground {
        return Err(UiError::new(
            "not_on_ground",
            "you must be on the ground to start a flight",
        ));
    }

    // Cached or live fetch of the departure airport. The lock is taken in a
    // narrow scope each time so the MutexGuard never crosses an `await`.
    let dpt_icao = bid.flight.dpt_airport_id.trim().to_uppercase();
    let cached_dpt: Option<Airport> = {
        let guard = state.airports.lock().expect("airports lock");
        guard.get(&dpt_icao).cloned()
    };
    let dpt_airport = match cached_dpt {
        Some(a) => a,
        None => {
            let fetched = client.get_airport(&dpt_icao).await?;
            let mut guard = state.airports.lock().expect("airports lock");
            guard.insert(dpt_icao.clone(), fetched.clone());
            fetched
        }
    };
    if let (Some(lat), Some(lon)) = (dpt_airport.lat, dpt_airport.lon) {
        let distance_nm =
            ::geo::distance_m(snapshot.lat, snapshot.lon, lat, lon) / 1852.0;
        if distance_nm > MAX_START_DISTANCE_NM {
            return Err(UiError::new(
                "not_at_departure",
                format!(
                    "you are {:.1} nm from {} — start the flight at the departure airport",
                    distance_nm, dpt_icao
                ),
            ));
        }
        tracing::info!(
            dpt = %dpt_icao,
            distance_nm,
            "preflight gate passed"
        );
    } else {
        tracing::warn!(
            dpt = %dpt_icao,
            "no coordinates for departure airport — skipping distance check"
        );
    }

    let airline_id = bid.flight.airline.as_ref().map(|a| a.id).ok_or_else(|| {
        UiError::new("missing_airline", "bid has no airline relation")
    })?;
    let aircraft_id = bid
        .flight
        .simbrief
        .as_ref()
        .map(|sb| sb.aircraft_id)
        .flatten()
        .ok_or_else(|| {
            UiError::new(
                "missing_aircraft",
                "no aircraft on this bid — please prepare a SimBrief OFP first",
            )
        })?;

    // ---- Aircraft-mismatch gate (spec §7) ----
    // Compare the aircraft type the bid expects (from get_aircraft) to what's
    // loaded in the simulator (parsed ATC MODEL or, as a backup, the TITLE).
    // Permissive: only block when both sides resolve to clearly different codes.
    let expected_aircraft = client.get_aircraft(aircraft_id).await?;
    let expected_icao = expected_aircraft
        .icao
        .as_ref()
        .map(|s| s.trim().to_uppercase())
        .filter(|s| !s.is_empty());
    let sim_icao = snapshot
        .aircraft_icao
        .as_deref()
        .and_then(clean_atc_model);
    let sim_title = snapshot
        .aircraft_title
        .as_deref()
        .unwrap_or("")
        .to_string();
    if let (Some(expected), Some(actual)) = (expected_icao.as_ref(), sim_icao.as_ref()) {
        // v0.13.16: sicherstellen, dass der frische VPS-Alias-Pull (oben
        // nebenläufig gestartet) abgeschlossen ist, BEVOR das Gate
        // `aircraft_aliases_vps` liest.
        let _ = alias_refresh.await;
        // v0.8.0: VPS-Aliases-Snapshot fuer alias-aware compare —
        // erlaubt VA-Admin pro Recorder neue Bid↔Sim-Alias-Paare zu
        // pflegen ohne Pilot-Client-Release.
        let vps_aliases = state
            .aircraft_aliases_vps
            .lock()
            .expect("aircraft_aliases_vps lock")
            .clone();
        // v0.13.16: alias-bewusster Vergleich über den gemeinsamen Helper
        // (identisch zum Auto-Start-Watcher). Matcht z.B. "A359" (ICAO)
        // gegen "A350-900" (Sim-Langform) und nutzt VPS-Aliase + Title-
        // Substring-Fallback. Live bug 2026-05-04: Emirates UAE770 A359-Bid
        // geblockt weil Sim "A350-900 (No Cabin)" lud — gleicher Flieger.
        if !aircraft_type_matches_sim(
            Some(expected.as_str()),
            Some(actual.as_str()),
            &sim_title,
            &vps_aliases,
        ) {
            let registration = expected_aircraft
                .registration
                .as_deref()
                .unwrap_or("?");
            // v0.8.3 (#7): von Hard-Block zu Warning-with-Acknowledge.
            // Vorher: Aircraft-Mismatch im Standard-Flow (SimBrief) war
            // ein harter „aircraft_mismatch"-Error, der den Flugstart
            // abbrach. Pilot konnte nur via VFR-Mode (`flight_start_manual`)
            // umgehen. Problem: Wetlease-Flows (PaxStudio-Loadsheet
            // erlaubt jedes aktive Aircraft) hatten keine Chance — Pilot
            // musste auf manual switchen.
            //
            // Neuer Default: Warnung mit „Trotzdem starten"-Button,
            // identisch zu `flight_start_manual`. Auf Zweit-Aufruf mit
            // acknowledgeAircraftMismatch=true wird der Check
            // uebersprungen. phpVMS macht sowieso nur einen laxen
            // Title-Substring-Check beim PIREP-File — kein Bedarf,
            // strenger zu sein als der Server.
            if !ack_aircraft_mismatch {
                tracing::warn!(
                    expected = %expected,
                    actual = %actual,
                    title = %sim_title,
                    registration = %registration,
                    "aircraft type mismatch — returning warning (acknowledge to proceed)"
                );
                return Err(UiError::new(
                    "aircraft_mismatch_warning",
                    format!(
                        "Aircraft passt nicht: gewaehlt {expected} ({registration}), Sim hat {actual}. Wetlease? Dann 'Trotzdem starten'. Falsches Flugzeug geladen? Im Sim umladen.",
                    ),
                ));
            }
            tracing::warn!(
                expected = %expected,
                actual = %actual,
                title = %sim_title,
                registration = %registration,
                "aircraft mismatch acknowledged by pilot — proceeding (Wetlease or manual override)"
            );
        }
    }

    let body = PrefileBody {
        // v0.16.18: Flight-ID aus dem Bid mitschicken — phpVMS haengt den
        // PIREP damit an den geplanten Flug (Event-/Tour-Matching, SkyAdventures).
        flight_id: Some(bid.flight.id.clone()),
        airline_id,
        aircraft_id: aircraft_id.to_string(),
        flight_number: bid.flight.flight_number.clone(),
        dpt_airport_id: bid.flight.dpt_airport_id.clone(),
        arr_airport_id: bid.flight.arr_airport_id.clone(),
        alt_airport_id: bid.flight.alt_airport_id.clone(),
        flight_type: bid.flight.flight_type.clone(),
        route_code: bid.flight.route_code.clone(),
        route_leg: bid.flight.route_leg.clone(),
        level: bid.flight.level.filter(|&l| l > 0),
        planned_distance: bid.flight.distance.as_ref().and_then(|d| d.nmi),
        planned_flight_time: bid.flight.flight_time,
        route: bid.flight.route.clone().filter(|s| !s.is_empty()),
        source_name: format!("AeroACARS/{}", env!("CARGO_PKG_VERSION")),
        notes: None,
    };

    // Before trying a fresh prefile, see if the user already has an in-progress
    // PIREP for this flight. This handles the "client crashed / persistence
    // file gone, but phpVMS still has the active PIREP" case — we adopt the
    // existing PIREP instead of trying to create a new one (which would fail
    // with aircraft-not-available because the aircraft is already "in use" by
    // the orphaned PIREP).
    //
    // v0.16.17: server-seitig auf IN_PROGRESS gefiltert (?state=0) — das
    // paginierte get_user_pireps() sah nur die letzten 20 PIREPs, ältere
    // Leichen blieben unsichtbar und blockierten Aircraft dauerhaft.
    let existing = match client.get_user_pireps_in_progress().await {
        Ok(list) => list,
        Err(e) => {
            tracing::warn!(error = %e, "could not list user PIREPs to check for resume");
            Vec::new()
        }
    };
    // v0.16.17 Selbstheilung: >24-h-alte Orphans best-effort wegcanceln,
    // BEVOR der Adopt-/Collision-Check läuft — gibt die Überlebenden zurück.
    let existing = sweep_stale_orphans_before_prefile(&app, &client, existing).await;
    let adoptable = existing.into_iter().find(|p| {
        // phpVMS PirepState IN_PROGRESS = 0 — Server hat bereits gefiltert,
        // der Check bleibt als defensive Doppelprüfung.
        p.state == Some(0)
            && p.flight_number.as_deref() == Some(body.flight_number.as_str())
            && (p.airline_id.is_none() || p.airline_id == Some(airline_id))
    });
    if let Some(p) = &adoptable {
        tracing::info!(pirep_id = %p.id, "adopting existing in-progress PIREP");
    }

    tracing::info!(
        airline_id,
        aircraft_id,
        flight_number = body.flight_number.as_str(),
        adopting = adoptable.is_some(),
        "prefiling PIREP"
    );
    let pirep = if let Some(adopt) = adoptable {
        api_client::PirepCreated { id: adopt.id }
    } else {
    match client.prefile_pirep(&body).await {
        Ok(p) => p,
        Err(ApiError::Server { status: 400, body: err_body })
            if err_body.contains("aircraft-not-available") =>
        {
            // Diagnose: fetch aircraft details to tell the user *why* it's
            // unavailable (wrong airport, "in use" by an orphan PIREP, etc.).
            let detail = match client.get_aircraft(aircraft_id).await {
                Ok(a) => {
                    let reg = a
                        .registration
                        .as_deref()
                        .or(a.name.as_deref())
                        .unwrap_or("?");
                    let where_ = a.airport_id.as_deref().unwrap_or("?");
                    let state = match a.state {
                        Some(0) => "parked",
                        Some(1) => "in use",
                        Some(2) => "in flight",
                        _ => "unknown",
                    };
                    format!(
                        "{reg} (id {}): currently at {where_}, state '{state}'. Wanted at {dpt_icao}.",
                        a.id
                    )
                }
                Err(e) => format!(
                    "could not fetch aircraft {} details: {e}",
                    aircraft_id
                ),
            };
            tracing::warn!(aircraft_id, %detail, "aircraft not available");
            return Err(UiError::new(
                "aircraft_not_available",
                format!("Aircraft not available — {detail}"),
            ));
        }
        Err(ApiError::Server { status, body: err_body }) => {
            // Try to extract a human-readable message from a phpVMS JSON error body.
            if let Ok(json) = serde_json::from_str::<serde_json::Value>(&err_body) {
                if let Some(title) = json.get("title").and_then(|v| v.as_str()) {
                    return Err(UiError::new(
                        "phpvms_error",
                        format!("phpVMS rejected the flight (HTTP {status}): {title}"),
                    ));
                }
            }
            return Err(UiError::new(
                "phpvms_error",
                format!("phpVMS rejected the flight (HTTP {status})"),
            ));
        }
        Err(e) => return Err(e.into()),
        }
    };

    // Advance the PIREP status to BOARDING and ensure state is IN_PROGRESS so
    // it appears in phpVMS's "Aktive Flüge" view.
    //
    // phpVMS 7 PirepState values: REJECTED = -1, IN_PROGRESS = 0, PENDING = 1,
    // ACCEPTED = 2. We send 0 explicitly so this also recovers any PIREP that
    // accidentally got pushed to PENDING earlier (e.g. by a buggier client).
    let update_body = UpdateBody {
        state: Some(0),
        status: Some("BST".to_string()),
        source_name: Some(format!("AeroACARS/{}", env!("CARGO_PKG_VERSION"))),
        ..Default::default()
    };
    if let Err(e) = client.update_pirep(&pirep.id, &update_body).await {
        tracing::warn!(
            pirep_id = %pirep.id,
            error = %e,
            "could not advance PIREP status to BOARDING (flight will still be tracked)"
        );
    } else {
        tracing::info!(pirep_id = %pirep.id, "PIREP status set to BOARDING");
    }

    // Capture fares from the SimBrief OFP so we can file accurate loads
    // even if the bid is gone by the time we end the flight.
    let fares: Vec<(i64, i32)> = bid
        .flight
        .simbrief
        .as_ref()
        .and_then(|sb| sb.subfleet.as_ref())
        .map(|sf| {
            sf.fares
                .iter()
                .filter_map(|f| f.count.map(|c| (f.id, c)))
                .collect()
        })
        .unwrap_or_default();

    let planned_registration = expected_aircraft
        .registration
        .as_deref()
        .unwrap_or("")
        .trim()
        .to_string();
    // v0.3.0: Aircraft-ICAO + Name aus dem expected_aircraft ziehen für
    // den PIREP-Custom-Field "Aircraft Type".
    let aircraft_icao = expected_aircraft
        .icao
        .as_deref()
        .unwrap_or("")
        .trim()
        .to_string();
    let aircraft_name = expected_aircraft
        .name
        .as_deref()
        .unwrap_or("")
        .trim()
        .to_string();

    // ---- Stage 2: SimBrief OFP fetch for planned-fuel comparison ----
    // The bid carries a SimBrief id when the pilot has prepared an OFP.
    // We fetch the OFP XML now (best-effort, never blocks the flight) so
    // the PIREP can compare actual fuel burn against the dispatcher's
    // plan.
    //
    // v0.4.2: Fetch-Fehler werden zusätzlich ins Activity-Log geschrieben
    // (vorher nur Tracing-Log → unsichtbar für Pilot). Pilot-Report von
    // heute: Flug hatte OFP, aber Landung-Tab zeigte trotzdem keine SOLL-
    // Werte → Fetch war silently fehlgeschlagen, niemand merkte was. Mit
    // Activity-Log-Eintrag sieht der Pilot's beim nächsten Mal sofort.
    //
    // v0.7.17 (N-001): SimBrief-Direct-First. Wenn der Pilot in Settings
    // einen SimBrief-Identifier (User-ID oder Username) hat, holen wir
    // zuerst den AKTUELLSTEN SimBrief-OFP direkt von simbrief.com.
    // Damit greift die "Aktualisieren"-Geste in My-Flights wirklich —
    // bisher hat flight_start die alte Bid-OFP-ID aus phpVMS gezogen,
    // selbst wenn der Pilot in SimBrief gerade einen neuen Plan
    // generiert hatte. Fallback auf den Bid-Pointer wenn Direct
    // fehlschlaegt oder kein Identifier konfiguriert ist.
    let simbrief_settings = state
        .simbrief_settings
        .lock()
        .expect("simbrief_settings lock")
        .clone();
    let mut planned_ofp: Option<api_client::SimBriefOfp> = None;
    if has_simbrief_identifier(&simbrief_settings) {
        let active_dpt = bid.flight.dpt_airport_id.clone();
        let active_arr = bid.flight.arr_airport_id.clone();
        let active_airline_icao = bid
            .flight
            .airline
            .as_ref()
            .map(|a| a.icao.clone())
            .unwrap_or_default();
        let active_flight_number = bid.flight.flight_number.clone();
        let active_bid_callsign = bid.flight.callsign.clone();
        let active_pilot_callsign = state
            .cached_pilot_callsign
            .lock()
            .expect("cached_pilot_callsign lock")
            .clone();
        match try_simbrief_direct_with_match(
            &client,
            &simbrief_settings,
            &active_dpt,
            &active_arr,
            &active_airline_icao,
            &active_flight_number,
            active_bid_callsign.as_deref(),
            active_pilot_callsign.as_deref(),
        )
        .await
        {
            DirectOutcome::Match { ofp }
            | DirectOutcome::MatchWithCallsignWarning { ofp, .. } => {
                tracing::info!(
                    sb_id = %ofp.request_id,
                    plan_burn_kg = ofp.planned_burn_kg,
                    plan_tow_kg = ofp.planned_tow_kg,
                    "SimBrief direct OFP fetched at flight_start",
                );
                log_activity(
                    &state,
                    ActivityLevel::Info,
                    "SimBrief OFP geladen (direct, aktueller Stand)".to_string(),
                    Some(format!(
                        "Plan-Block {:.0} kg · Trip {:.0} kg · TOW {:.0} kg · OFP {}",
                        ofp.planned_block_fuel_kg,
                        ofp.planned_burn_kg,
                        ofp.planned_tow_kg,
                        ofp.request_id
                    )),
                );
                planned_ofp = Some(ofp);
            }
            DirectOutcome::Mismatch { .. } => {
                // Direct lieferte einen OFP, aber der ist fuer einen
                // anderen Flug (DEP/ARR-Mismatch). Bid-Pointer als
                // Fallback nutzen — ist wahrscheinlich der richtige
                // Plan fuer diesen konkreten Flug.
                tracing::warn!(
                    "SimBrief direct returned mismatching DEP/ARR — falling back to phpVMS bid pointer"
                );
            }
            DirectOutcome::Error(_) => {
                // Netzwerk/Auth-Fehler bei direct — Bid-Pointer als
                // Fallback. Pilot kriegt unten den Pointer-Activity-
                // Log-Eintrag, der reicht.
                tracing::warn!(
                    "SimBrief direct fetch failed at flight_start — falling back to phpVMS bid pointer"
                );
            }
        }
    }
    // Fallback (Direct nicht versucht oder fehlgeschlagen): klassischer
    // Bid-Pointer-Pfad. Identisches Verhalten wie vor v0.7.17.
    let planned_ofp = if planned_ofp.is_some() {
        planned_ofp
    } else if let Some(sb) = bid.flight.simbrief.as_ref() {
        match client.fetch_simbrief_ofp(&sb.id).await {
            Ok(Some(ofp)) => {
                tracing::info!(
                    sb_id = %sb.id,
                    plan_burn_kg = ofp.planned_burn_kg,
                    plan_block_kg = ofp.planned_block_fuel_kg,
                    plan_tow_kg = ofp.planned_tow_kg,
                    "SimBrief OFP fetched"
                );
                log_activity(
                    &state,
                    ActivityLevel::Info,
                    "SimBrief OFP geladen".to_string(),
                    Some(format!(
                        "Plan-Block {:.0} kg · Trip {:.0} kg · TOW {:.0} kg",
                        ofp.planned_block_fuel_kg,
                        ofp.planned_burn_kg,
                        ofp.planned_tow_kg
                    )),
                );
                Some(ofp)
            }
            Ok(None) => {
                tracing::warn!(sb_id = %sb.id, "SimBrief OFP fetch returned no usable data");
                log_activity(
                    &state,
                    ActivityLevel::Warn,
                    "SimBrief-OFP konnte nicht geladen werden".to_string(),
                    Some(format!(
                        "OFP-ID {} liefert keine brauchbaren Daten — Landung-Tab zeigt deshalb keine SOLL-Werte. Bitte einen frischen OFP auf simbrief.com erstellen.",
                        sb.id
                    )),
                );
                None
            }
            Err(e) => {
                tracing::warn!(sb_id = %sb.id, error = %e, "SimBrief OFP fetch failed");
                log_activity(
                    &state,
                    ActivityLevel::Warn,
                    "SimBrief-OFP-Fetch fehlgeschlagen".to_string(),
                    Some(format!(
                        "OFP-ID {} konnte nicht geladen werden ({}). Landung-Tab zeigt deshalb keine SOLL-Werte. Probier später nochmal Refresh in My-Flights, oder generier einen neuen OFP.",
                        sb.id, e
                    )),
                );
                None
            }
        }
    } else {
        // Bid hatte überhaupt keine SimBrief-Verbindung — kein Fehler,
        // aber wir sagen es dem Piloten damit er weiß warum keine
        // SOLL-Werte kommen.
        log_activity(
            &state,
            ActivityLevel::Info,
            "Kein SimBrief-OFP für diesen Flug".to_string(),
            Some("Der Bid hat keinen SimBrief-OFP gelinkt. Du kannst trotzdem fliegen — der Landung-Tab zeigt dann nur die IST-Werte ohne SOLL/Δ-Vergleich.".to_string()),
        );
        None
    };

    let flight = Arc::new(ActiveFlight {
        pirep_id: pirep.id.clone(),
        bid_id,
        // v0.7.7: flight_id aus dem Bid extrahieren BEVOR der Bid
        // serverseitig nach Prefile entfernt wird (W5). Diese Stelle
        // sitzt nach `client.prefile_pirep().await` — der Bid kann
        // theoretisch schon weg sein wenn phpVMS-7 ihn synchron loescht,
        // aber wir haben den lokalen `bid` aus dem fruehen `get_bids()`
        // (lib.rs:5151-5155) noch im Scope. flight_id aus dem lokalen
        // Bid-Snapshot ist daher zuverlaessig — egal was server-side
        // mit dem Bid passiert.
        flight_id: bid.flight_id.clone(),
        // v0.7.8 v1.5: Bid.flight.callsign + cached Profile.callsign
        // fuer SimBrief-direct Match-Kandidatenliste (Spec §6.1.2).
        bid_callsign: bid
            .flight
            .callsign
            .clone()
            .filter(|s| !s.trim().is_empty()),
        pilot_callsign: state
            .cached_pilot_callsign
            .lock()
            .expect("cached_pilot_callsign lock")
            .clone(),
        started_at: Utc::now(),
        airline_icao: bid
            .flight
            .airline
            .as_ref()
            .map(|a| a.icao.clone())
            .unwrap_or_default(),
        airline_logo_url: bid
            .flight
            .airline
            .as_ref()
            .and_then(|a| a.logo.clone())
            .filter(|s| !s.is_empty()),
        planned_registration,
        aircraft_icao,
        aircraft_name,
        flight_number: bid.flight.flight_number.clone(),
        dpt_airport: bid.flight.dpt_airport_id.clone(),
        arr_airport: bid.flight.arr_airport_id.clone(),
        fares,
        stats: Mutex::new(FlightStats::new()),
        stop: AtomicBool::new(false),
        // Fresh start triggered by user — no banner needed.
        was_just_resumed: AtomicBool::new(false),
        streamer_spawned: AtomicBool::new(false),
        cancelled_remotely: AtomicBool::new(false),
        position_outbox: Mutex::new(std::collections::VecDeque::new()),
        phpvms_worker_spawned: AtomicBool::new(false),
        touchdown_sampler_spawned: AtomicBool::new(false),
        connection_state: std::sync::atomic::AtomicU8::new(CONN_STATE_LIVE),
        // v0.8.0: Navdata-Cache startet leer — wird von
        // `fetch_navdata_for_flight` (Slice B) parallel beim Flugstart
        // populiert. Leer = OurAirports-Fallback aktiv (= Verhalten
        // vor v0.8.0).
        navdata: Mutex::new(NavdataCache::default()),
    });

    save_active_flight(&app, &flight);
    // v0.8.0: parallel-fetch dep/arr/alt-Navdata vom VPS. Non-blocking
    // (Background-Task), Failure → OurAirports-Fallback (transparent).
    // flight_start (SimBrief): Alternate kommt aus dem Bid; spätere
    // OFP-Aktualisierungen können einen anderen Alternate setzen —
    // der wird im post-OFP-spawn unten nachgeholt (per-ICAO-guard).
    {
        let mut icaos = vec![flight.dpt_airport.clone(), flight.arr_airport.clone()];
        if let Some(alt) = bid.flight.alt_airport_id.clone() {
            if !alt.trim().is_empty() {
                icaos.push(alt);
            }
        }
        spawn_navdata_fetch(&app, &flight, icaos);
    }

    {
        let mut guard = state.active_flight.lock().expect("active_flight lock");
        *guard = Some(Arc::clone(&flight));
    }
    // ActiveFlight is committed; release the setup-in-progress flag.
    setup_guard.disarm();

    // v0.16.12 (#phase-v2): geplante Cruise-Altitude aus dem phpVMS-Flight
    // als `cruise_ref` für die Schatten-Engine. phpVMS-VAs pflegen das
    // Feld mal als Flight-Level (360) und mal in Fuß (36000) — Werte
    // < 1000 werden als FL interpretiert (×100). Unabhängig vom OFP
    // gesetzt (auch Flüge ohne SimBrief haben oft ein Bid-Level).
    if let Some(level) = bid.flight.level.filter(|&l| l > 0) {
        let ft = if level < 1000 {
            f64::from(level) * 100.0
        } else {
            f64::from(level)
        };
        flight
            .stats
            .lock()
            .expect("flight stats lock")
            .planned_cruise_alt_ft = Some(ft);
    }

    // Stage 2: write the SimBrief OFP plan into FlightStats so the
    // streamer + PIREP builder can read it later. Done after commit
    // so stats already exists; the lock is short-held and never
    // crosses an await.
    if let Some(ofp) = planned_ofp {
        // Pull the navlog out before moving the rest into FlightStats so
        // we can post it to phpVMS without holding a lock across an await.
        let waypoints = ofp.waypoints.clone();
        let mut stats = flight.stats.lock().expect("flight stats lock");
        // v0.13.x: Navlog-Fixes für die In-App-Live-Map vorhalten (Dots + TOC/TOD).
        stats.planned_waypoints = waypoints.clone();
        stats.planned_block_fuel_kg = Some(ofp.planned_block_fuel_kg).filter(|&v| v > 0.0);
        stats.planned_burn_kg = Some(ofp.planned_burn_kg).filter(|&v| v > 0.0);
        stats.planned_reserve_kg = Some(ofp.planned_reserve_kg).filter(|&v| v > 0.0);
        stats.planned_zfw_kg = Some(ofp.planned_zfw_kg).filter(|&v| v > 0.0);
        stats.planned_tow_kg = Some(ofp.planned_tow_kg).filter(|&v| v > 0.0);
        stats.planned_ldw_kg = Some(ofp.planned_ldw_kg).filter(|&v| v > 0.0);
        stats.planned_route = ofp.route;
        // v0.8.0: OFP-Alternate kann sich vom Bid-Alternate
        // unterscheiden — wenn ja, fetch ihn jetzt nach. Der
        // per-ICAO-Guard im `spawn_navdata_fetch` macht das zu einem
        // No-Op wenn der Wert dem Bid-Alternate gleicht (= schon im
        // Cache).
        let ofp_alt_for_navdata = ofp.alternate.clone();
        stats.planned_alternate = ofp.alternate;
        // v0.3.0: MAX-Werte für Overweight-Detection im Live-Loadsheet
        // + Score-Penalty im Landung-Tab. Filter Null-Werte aus —
        // Custom-Subfleets ohne MAX-Daten kriegen einfach keine
        // Overweight-Anzeige.
        stats.planned_max_zfw_kg = Some(ofp.max_zfw_kg).filter(|&v| v > 0.0);
        stats.planned_max_tow_kg = Some(ofp.max_tow_kg).filter(|&v| v > 0.0);
        stats.planned_max_ldw_kg = Some(ofp.max_ldw_kg).filter(|&v| v > 0.0);
        stats.flight_plan_source = Some("simbrief");
        // v0.7.7: OFP-Identifier persistieren fuer "OFP unveraendert"-
        // Erkennung beim spaeteren `flight_refresh_simbrief`. sb.id ist
        // die SimBrief-OFP-ID die wir gerade geholt haben; ofp_generated_at
        // ist der raw <params><time_generated>-String aus dem XML.
        // Spec docs/spec/ofp-refresh-during-boarding.md §6.1.
        stats.simbrief_ofp_id = bid
            .flight
            .simbrief
            .as_ref()
            .map(|sb| sb.id.clone());
        stats.simbrief_ofp_generated_at = if ofp.ofp_generated_at.is_empty() {
            None
        } else {
            Some(ofp.ofp_generated_at.clone())
        };
        drop(stats);
        // Persist immediately so a Tauri restart mid-flight doesn't
        // lose the plan.
        save_active_flight(&app, &flight);

        // v0.8.0: post-OFP-Alternate-Fetch (per-ICAO-Guard im Helper
        // macht das zum no-op wenn der OFP-Alt dem Bid-Alt entspricht).
        if let Some(alt) = ofp_alt_for_navdata {
            if !alt.trim().is_empty() {
                spawn_navdata_fetch(&app, &flight, vec![alt]);
            }
        }

        // Push the planned waypoints to phpVMS so the live map / PIREP
        // detail can draw the planned track alongside the flown one.
        // Best-effort: failure here doesn't abort the flight setup.
        if !waypoints.is_empty() {
            // v0.16.23: shared Helper (auch von flight_refresh_route_only
            // genutzt) — garantiert bit-identische Route-Form an phpVMS.
            let route = build_route_waypoints(&waypoints);
            let pirep_id = pirep.id.clone();
            let route_client = client.clone();
            tauri::async_runtime::spawn(async move {
                match route_client.post_route(&pirep_id, &route).await {
                    Ok(()) => tracing::info!(
                        pirep_id = %pirep_id,
                        waypoint_count = route.len(),
                        "planned route uploaded"
                    ),
                    Err(e) => tracing::warn!(
                        pirep_id = %pirep_id,
                        error = %e,
                        "planned route upload failed"
                    ),
                }
            });
        }
    }

    // v0.6.0/v0.6.1 — phpVMS-Worker zuerst aufrufen als Hint an den
    // Scheduler dass sein Init-Load aus position_queue.json moeglichst
    // vor dem ersten Streamer-Tick laeuft. **Keine harte Garantie** —
    // tauri::async_runtime::spawn returnt sofort, beide tasks racen
    // dann in der Tauri-Runtime. Ordering-Korrektheit fuer den Live-
    // Map-Track auf phpVMS basiert eh auf dem `at`-Timestamp im
    // PositionEntry-Body (server-seitig sortiert), nicht auf der
    // Reihenfolge in der Memory-Outbox.
    spawn_phpvms_position_worker(app.clone(), Arc::clone(&flight), client.clone());
    spawn_position_streamer(app.clone(), Arc::clone(&flight), client.clone());
    spawn_touchdown_sampler(app.clone(), Arc::clone(&flight));

    // Fire an explicit "Phase: Boarding" entry into phpVMS' acars/logs
    // for the PIREP detail's Fluglogbuch tab. The streamer only emits
    // log lines on phase TRANSITIONS, but Boarding is the initial
    // state — there's no transition INTO it, so without this kick
    // the Fluglogbuch tab starts at "Phase: Pushback" with no record
    // of the boarding period. Best-effort, never blocks flight start.
    {
        let pirep_id = flight.pirep_id.clone();
        let log_client = client.clone();
        tauri::async_runtime::spawn(async move {
            let entry = api_client::LogEntry {
                log: "Phase: Boarding".to_string(),
                lat: None,
                lon: None,
                created_at: Some(Utc::now().to_rfc3339()),
            };
            if let Err(e) = log_client.post_acars_logs(&pirep_id, &[entry]).await {
                tracing::warn!(
                    pirep_id = %pirep_id,
                    error = %e,
                    "could not push initial Boarding ACARS log line"
                );
            }
        });
    }

    // New flight = fresh activity log. Pilots were getting confused
    // when the previous flight's events (or yesterday's) lingered at
    // the top of the log. The JSONL flight-event log on disk still
    // captures everything per-PIREP for review, but the in-app feed
    // resets here for a clean recording. Resume (`flight_adopt`)
    // skips this on purpose — there the existing log is the
    // continuation history we want to keep.
    clear_activity_log_for_new_flight(&app);

    let info = flight_info(flight.as_ref(), false);
    log_activity(
        &state,
        ActivityLevel::Info,
        format!(
            "Flight started: {} {} → {}",
            format_callsign(&flight.airline_icao, &flight.flight_number),
            flight.dpt_airport,
            flight.arr_airport
        ),
        Some(format!("PIREP prefiled as {}", flight.pirep_id)),
    );
    // Announce the initial Boarding phase explicitly. Without this
    // entry the activity log shows the flight jumping straight from
    // "Flight started" to "Phase: Pushback" later, leaving the
    // Boarding stage of the timeline unrepresented in the textual
    // log even though the UI marks it as the active checkpoint.
    log_activity(
        &state,
        ActivityLevel::Info,
        "Phase: Boarding".to_string(),
        None,
    );
    record_event(
        &app,
        &flight.pirep_id,
        &FlightLogEvent::FlightStarted {
            timestamp: Utc::now(),
            pirep_id: flight.pirep_id.clone(),
            airline_icao: flight.airline_icao.clone(),
            flight_number: flight.flight_number.clone(),
            dpt_airport: flight.dpt_airport.clone(),
            arr_airport: flight.arr_airport.clone(),
        },
    );
    Ok(info)
}

// ─── v0.5.27 VFR/Manual-Mode ───────────────────────────────────────────
//
// Fuer VFR-Fluege oder kleine Pisten wo SimBrief keinen OFP erstellen
// kann. Pilot waehlt Aircraft manuell aus dem Fleet + traegt Block-Fuel,
// erwartete Flugzeit + optional Cruise/Route/Alternate ein.

#[derive(Debug, Clone, Serialize)]
pub struct AircraftPickerEntry {
    pub id: i64,
    pub registration: String,
    pub icao: String,
    pub name: String,
    pub airport_id: String,
    /// 0=parked / 1=in_use / 2=in_flight (phpVMS AircraftState).
    pub state: i32,
    /// Searchable display-string ("CL60 D-A3MD Bombardier Challenger 605").
    pub display: String,
}

/// v0.5.30: Liste ALLER verfuegbaren Aircraft fuer den Piloten (= keine
/// Airport-/State-Einschraenkung im Frontend). Pilot waehlt frei aus
/// dem gesamten Fleet, Suche im UI filtert Live.
///
/// `icao`-Parameter wird nur fuer SORT-Priority genutzt: Aircraft am
/// Departure-Airport stehen oben in der Liste, Rest folgt alphabetisch.
/// Phpvms enforced Subfleet-Rank-Restriktion server-seitig (= nur was
/// der Pilot fliegen darf kommt vom /api/fleet zurueck).
///
/// State-Filter entfernt: Pilot sieht auch in-use / maintenance Aircraft
/// (mit visuellem Indikator). Falls ausgewaehlte Aircraft nicht
/// verfuegbar ist, lehnt phpVMS-Prefile mit klarer Fehlermeldung ab.
#[tauri::command]
async fn fleet_list_at_airport(
    state: tauri::State<'_, AppState>,
    icao: String,
) -> Result<Vec<AircraftPickerEntry>, UiError> {
    let client = current_client(&state)?;
    let icao_upper = icao.trim().to_uppercase();

    let raw = client.get_all_aircraft().await?;
    let total_before_filter = raw.len();

    // v0.5.33: Filter — nur Aircraft die der Pilot tatsaechlich
    // jetzt fliegen kann:
    //   • state == 0 (PARKED — nicht IN_USE/IN_AIR)
    //   • status == "A" (ACTIVE — nicht MAINTENANCE/STORED/RETIRED/etc.)
    // phpVMS-Enums:
    //   AircraftState:  0=PARKED, 1=IN_USE, 2=IN_AIR
    //   AircraftStatus: A=ACTIVE, M=MAINTENANCE, S=STORED, R=RETIRED,
    //                   C=SCRAPPED, W=WRITTEN_OFF
    // Aircraft ohne `state`/`status` (legacy/incomplete data) werden
    // konservativ DURCHGELASSEN — phpVMS lehnt beim Prefile ab falls
    // die Aircraft tatsaechlich nicht verfuegbar ist.
    let raw: Vec<_> = raw
        .into_iter()
        .filter(|a| {
            let state_ok = a.state.map(|s| s == 0).unwrap_or(true);
            let status_ok = a
                .status
                .as_deref()
                .map(|s| s.eq_ignore_ascii_case("A"))
                .unwrap_or(true);
            state_ok && status_ok
        })
        .collect();
    tracing::info!(
        before = total_before_filter,
        after = raw.len(),
        "fleet_list_at_airport: state==0 && status==A filter applied"
    );

    let mut entries: Vec<AircraftPickerEntry> = raw
        .into_iter()
        .map(|a| {
            let icao = a.icao.clone().unwrap_or_default();
            let reg = a.registration.clone().unwrap_or_default();
            let name = a.name.clone().unwrap_or_default();
            let display = format!(
                "{} {}{}",
                icao,
                reg,
                if !name.is_empty() && name != icao {
                    format!(" — {name}")
                } else {
                    String::new()
                },
            );
            AircraftPickerEntry {
                id: a.id,
                registration: reg,
                icao,
                name,
                airport_id: a.airport_id.unwrap_or_default(),
                state: a.state.unwrap_or(0),
                display,
            }
        })
        .collect();

    // Sortieren: Aircraft am Departure-Airport zuerst, dann nach State
    // (parked vor in-use), dann alphabetisch nach ICAO+Reg.
    entries.sort_by(|a, b| {
        let a_here = a.airport_id.eq_ignore_ascii_case(&icao_upper);
        let b_here = b.airport_id.eq_ignore_ascii_case(&icao_upper);
        match (a_here, b_here) {
            (true, false) => std::cmp::Ordering::Less,
            (false, true) => std::cmp::Ordering::Greater,
            _ => a.state.cmp(&b.state)
                .then_with(|| a.icao.cmp(&b.icao))
                .then_with(|| a.registration.cmp(&b.registration)),
        }
    });

    Ok(entries)
}

/// VFR/Manual-Mode-Flugplan vom Frontend.
#[derive(Debug, Clone, Deserialize)]
pub struct ManualFlightPlan {
    /// MUST: Aircraft-ID aus dem fleet_list_at_airport-Picker.
    pub aircraft_id: i64,
    /// MUST: geplanter Block-Fuel (Ramp Fuel) in kg. Pilot's Schaetzung
    /// fuer den Trip + Reserve. Brauchen wir fuer Fuel-Efficiency-Score.
    pub planned_block_fuel_kg: f32,
    /// MUST: Erwartete Flugzeit in Minuten. Fuer ETA-Anzeige + Janitor-
    /// Heuristik wann ein Flug "abgelaufen" ist.
    pub planned_flight_time_min: i32,
    /// Optional: geplanter Reise-Level in ft (z.B. 4500 fuer VFR).
    pub cruise_level_ft: Option<i32>,
    /// Optional: free-text Route ("direct", "via LMV VFR", waypoint-list).
    pub planned_route: Option<String>,
    /// Optional: Alternate-Airport ICAO.
    pub alt_airport_id: Option<String>,
    /// MUST (v0.5.42+): Geplantes Zero-Fuel-Weight in kg.
    /// Ohne ZFW können wir keinen Loadsheet-Score und kein Mass-Compare
    /// gegen Sim-Live-ZFW berechnen — VFR-Mode verliert sonst seinen
    /// Mehrwert ggü. einem reinen Manual-PIREP. Frontend rendert das
    /// Feld als required, Backend verifiziert nochmal defensiv.
    pub planned_zfw_kg: Option<f32>,
    /// Optional: geplanter Trip-Burn in kg (= planned_block - reserve - alternate).
    /// Wenn nicht gesetzt, fallback: 90% des block_fuel als Trip-Schaetzung.
    pub planned_burn_kg: Option<f32>,
    /// v0.5.36: Pilot hat den Aircraft-Type-Mismatch akzeptiert
    /// (= "trotzdem starten"-Button im Modal nach gelbem Warn-Banner).
    /// Default false → erste Anfrage triggert die Warnung; nach Bestätigung
    /// schickt das Frontend die gleiche Anfrage mit acknowledge=true.
    #[serde(default)]
    pub acknowledge_aircraft_mismatch: bool,
}

/// VFR/Manual-Flight-Start. Parallele Funktion zu flight_start aber
/// OHNE SimBrief-OFP-Pflicht. Pilot bringt aircraft_id + minimale
/// Plan-Daten manuell mit. Rest des Flows identisch (PIREP-Prefile,
/// Streamer-Spawn, Touchdown-Sampler, Activity-Log).
#[tauri::command]
async fn flight_start_manual(
    app: AppHandle,
    state: tauri::State<'_, AppState>,
    bid_id: i64,
    plan: ManualFlightPlan,
) -> Result<ActiveFlightInfo, UiError> {
    // v0.5.42: Validierung der Pflicht-Felder VOR dem try_acquire ziehen.
    // Vorher passierte das nach dem Lock — Effekt: wenn parallel ein anderer
    // Flow den Lock hielt (z.B. try_resume_flight beim App-Boot, Auto-Start-
    // Watcher, StrictMode-Doppelmount), bekam der User die kryptische Meldung
    // "another flight start or adopt is already in progress" obwohl tatsächlich
    // nur ein Pflichtfeld fehlte. Validation muss zuerst laufen damit
    // Form-Fehler immer als Form-Fehler erscheinen.
    if plan.planned_block_fuel_kg <= 0.0 {
        return Err(UiError::new(
            "invalid_block_fuel",
            "Block-Fuel muss > 0 kg sein",
        ));
    }
    if plan.planned_flight_time_min <= 0 {
        return Err(UiError::new(
            "invalid_flight_time",
            "Erwartete Flugzeit muss > 0 Minuten sein",
        ));
    }
    // v0.7.1 Phase 2 F1 (Spec docs/spec/v0.7.1-landing-ux-fairness.md
    // P1.1-A + P1.3-B): ZFW ist NICHT mehr Pflicht. VFR-/Manual-Mode-
    // Piloten ohne Dispatch-Daten koennen jetzt starten.
    //   - None      → Loadsheet-Sub-Score wird skipped (siehe sub_loadsheet
    //                 in landing-scoring Crate)
    //   - Some(0.0) oder negativ → Eingabefehler-Schutz, klarer Error-Code
    //                 invalid_zfw_value (Frontend mapped diesen via
    //                 ManualFlightModal knownCodes-Map auf i18n)
    //   - Some(>0)  → wie bisher, planned_tow = zfw + block_fuel
    let planned_zfw: Option<f32> = match plan.planned_zfw_kg {
        Some(v) if v > 0.0 => Some(v),
        Some(v) if v <= 0.0 => {
            return Err(UiError::new(
                "invalid_zfw_value",
                "ZFW muss > 0 sein wenn angegeben. Lass das Feld leer fuer VFR/Manual ohne Loadsheet-Wertung.",
            ));
        }
        _ => None,
    };
    let _ = planned_zfw; // Wird unten bei Manual-TOW-Zuweisung benutzt
    // Noisy-cast-Hinweis: NaN-Faelle werden vom is-pattern-match
    // in der `Some(v)` arm abgedeckt (NaN ist niemals > 0.0 noch <= 0.0,
    // also Some-NaN faellt in den catchall `_` und wird wie None behandelt).

    let setup_guard = FlightSetupGuard::try_acquire(&state.flight_setup_in_progress)?;

    {
        let guard = state.active_flight.lock().expect("active_flight lock");
        if guard.is_some() {
            return Err(UiError::new(
                "flight_already_active",
                "another flight is already active",
            ));
        }
    }

    // v0.13.16: VPS-Aircraft-Aliase nebenläufig auffrischen (analog
    // flight_start), damit ein frisch eingetragener Alias auf DIESEN
    // VFR/Manual-Startversuch wirkt. Best-effort + 5 s-Timeout, awaited
    // direkt vor dem Mismatch-Gate.
    let alias_refresh = {
        let app_aliases = app.clone();
        let token = secrets::load_api_key(MQTT_KEYRING_PASSWORD).ok().flatten();
        tokio::spawn(async move {
            let _ = tokio::time::timeout(
                Duration::from_secs(5),
                fetch_aircraft_aliases_into_state(app_aliases, None, token),
            )
            .await;
        })
    };

    let client = current_client(&state)?;
    let bids = client.get_bids().await?;
    let bid = bids
        .into_iter()
        .find(|b| b.id == bid_id)
        .ok_or_else(|| UiError::new("bid_not_found", "bid not found in current bids"))?;

    // Pre-flight gating: ground + departure-airport (gleicher Code wie flight_start)
    let snapshot = current_snapshot(&app).ok_or_else(|| {
        UiError::new("no_sim_snapshot", "no sim snapshot yet — is the simulator connected?")
    })?;
    if !snapshot.on_ground {
        return Err(UiError::new(
            "not_on_ground",
            "you must be on the ground to start a flight",
        ));
    }
    let dpt_icao = bid.flight.dpt_airport_id.trim().to_uppercase();
    let cached_dpt: Option<Airport> = {
        let guard = state.airports.lock().expect("airports lock");
        guard.get(&dpt_icao).cloned()
    };
    let dpt_airport = match cached_dpt {
        Some(a) => a,
        None => {
            let fetched = client.get_airport(&dpt_icao).await?;
            let mut guard = state.airports.lock().expect("airports lock");
            guard.insert(dpt_icao.clone(), fetched.clone());
            fetched
        }
    };
    if let (Some(lat), Some(lon)) = (dpt_airport.lat, dpt_airport.lon) {
        let distance_nm =
            ::geo::distance_m(snapshot.lat, snapshot.lon, lat, lon) / 1852.0;
        if distance_nm > MAX_START_DISTANCE_NM {
            return Err(UiError::new(
                "not_at_departure",
                format!(
                    "you are {:.1} nm from {} — start the flight at the departure airport",
                    distance_nm, dpt_icao
                ),
            ));
        }
    }

    let airline_id = bid.flight.airline.as_ref().map(|a| a.id).ok_or_else(|| {
        UiError::new("missing_airline", "bid has no airline relation")
    })?;
    let aircraft_id = plan.aircraft_id;

    // Aircraft-mismatch-Gate gegen Sim-loaded Aircraft
    let expected_aircraft = client.get_aircraft(aircraft_id).await?;
    let expected_icao = expected_aircraft
        .icao
        .as_ref()
        .map(|s| s.trim().to_uppercase())
        .filter(|s| !s.is_empty());
    let sim_icao = snapshot
        .aircraft_icao
        .as_deref()
        .and_then(clean_atc_model);
    let sim_title = snapshot
        .aircraft_title
        .as_deref()
        .unwrap_or("")
        .to_string();
    // v0.5.36: VFR/Manual-Mode → Aircraft-Mismatch ist eine WARNUNG,
    // kein Hard-Block. Pilot hat im Picker bewusst eine Aircraft gewählt;
    // wir vertrauen ihm. Auf Erst-Anfrage liefern wir den Mismatch als
    // dedicated Error-Code "aircraft_mismatch_warning" zurück damit das
    // Frontend ein gelbes Banner mit "Trotzdem starten"-Button zeigt.
    // Beim zweiten Versuch mit acknowledge=true wird der Check übersprungen.
    if let (Some(expected), Some(actual)) = (expected_icao.as_ref(), sim_icao.as_ref()) {
        // v0.13.16: frischen VPS-Alias-Pull abwarten, bevor das Gate liest.
        let _ = alias_refresh.await;
        let vps_aliases = state
            .aircraft_aliases_vps
            .lock()
            .expect("aircraft_aliases_vps lock")
            .clone();
        // v0.13.16: alias-bewusster Vergleich über den gemeinsamen Helper.
        if !aircraft_type_matches_sim(
            Some(expected.as_str()),
            Some(actual.as_str()),
            &sim_title,
            &vps_aliases,
        ) {
            if !plan.acknowledge_aircraft_mismatch {
                let registration = expected_aircraft
                    .registration
                    .as_deref()
                    .unwrap_or("?");
                return Err(UiError::new(
                    "aircraft_mismatch_warning",
                    format!(
                        "Aircraft passt nicht: gewählt {expected} ({registration}), Sim hat {actual}. Trotzdem starten? (VFR-Mode vertraut deiner Wahl — der Sim-Type beeinflusst aber Score-Limits.)",
                    ),
                ));
            }
            // Acknowledged — log it for diagnostics but proceed
            tracing::warn!(
                expected = %expected,
                actual = %actual,
                "VFR/Manual: aircraft mismatch acknowledged by pilot — proceeding"
            );
        }
    }

    // PIREP prefile (gleiche Logik wie flight_start, ohne SB-Felder)
    let body = PrefileBody {
        // v0.16.18: Flight-ID aus dem Bid mitschicken — phpVMS haengt den
        // PIREP damit an den geplanten Flug (Event-/Tour-Matching, SkyAdventures).
        flight_id: Some(bid.flight.id.clone()),
        airline_id,
        aircraft_id: aircraft_id.to_string(),
        flight_number: bid.flight.flight_number.clone(),
        dpt_airport_id: bid.flight.dpt_airport_id.clone(),
        arr_airport_id: bid.flight.arr_airport_id.clone(),
        alt_airport_id: plan.alt_airport_id.clone()
            .or(bid.flight.alt_airport_id.clone()),
        flight_type: bid.flight.flight_type.clone(),
        route_code: bid.flight.route_code.clone(),
        route_leg: bid.flight.route_leg.clone(),
        level: plan.cruise_level_ft.filter(|&l| l > 0),
        planned_distance: bid.flight.distance.as_ref().and_then(|d| d.nmi),
        planned_flight_time: Some(plan.planned_flight_time_min),
        route: plan.planned_route.clone().filter(|s| !s.is_empty()),
        source_name: format!("AeroACARS/{}", env!("CARGO_PKG_VERSION")),
        notes: Some(format!(
            "Manual/VFR-Mode (kein SimBrief-OFP). Block: {:.0} kg, ETA: {} min",
            plan.planned_block_fuel_kg, plan.planned_flight_time_min,
        )),
    };

    // v0.16.17: server-seitig auf IN_PROGRESS gefiltert (?state=0) statt
    // page-1-fetch-then-filter (siehe flight_start) + Selbstheilung: alte
    // Orphans (>24 h) werden vor dem Adopt-/Collision-Check weggeräumt.
    let existing = client.get_user_pireps_in_progress().await.unwrap_or_default();
    let existing = sweep_stale_orphans_before_prefile(&app, &client, existing).await;
    let adoptable = existing.into_iter().find(|p| {
        // state-Check defensiv — Server hat bereits gefiltert.
        p.state == Some(0)
            && p.flight_number.as_deref() == Some(body.flight_number.as_str())
            && (p.airline_id.is_none() || p.airline_id == Some(airline_id))
    });
    let pirep = if let Some(adopt) = adoptable {
        api_client::PirepCreated { id: adopt.id }
    } else {
        client.prefile_pirep(&body).await.map_err(|e| match e {
            ApiError::Server { status: 400, body: ref err_body }
                if err_body.contains("aircraft-not-available") =>
            {
                UiError::new(
                    "aircraft_not_available",
                    "Aircraft nicht verfügbar — anderer Pilot fliegt es vielleicht oder es ist in Maintenance.",
                )
            }
            other => other.into(),
        })?
    };

    let update_body = UpdateBody {
        state: Some(0),
        status: Some("BST".to_string()),
        source_name: Some(format!("AeroACARS/{}", env!("CARGO_PKG_VERSION"))),
        ..Default::default()
    };
    if let Err(e) = client.update_pirep(&pirep.id, &update_body).await {
        tracing::warn!(pirep_id = %pirep.id, error = %e, "update_pirep (set BST/state 0) failed (non-fatal)");
    }

    // Aircraft-Daten + Airline-Logo holen
    let aircraft_details = client.get_aircraft(aircraft_id).await.ok();
    let planned_registration = aircraft_details
        .as_ref()
        .and_then(|a| a.registration.clone())
        .unwrap_or_default()
        .trim()
        .to_string();
    let aircraft_icao = aircraft_details
        .as_ref()
        .and_then(|a| a.icao.clone())
        .unwrap_or_default()
        .trim()
        .to_string();
    let aircraft_name = aircraft_details
        .as_ref()
        .and_then(|a| a.name.clone())
        .unwrap_or_default()
        .trim()
        .to_string();
    let airline = bid.flight.airline.as_ref();

    // VFR/Manual-Mode: keine SimBrief-Fares verfuegbar. Empty-list ist
    // OK fuer phpVMS-PIREP-File (= keine Pax/Cargo-Loads).
    let fares: Vec<(i64, i32)> = Vec::new();

    let flight = Arc::new(ActiveFlight {
        pirep_id: pirep.id.clone(),
        bid_id,
        // v0.7.7: flight_id aus Bid (Manual-Mode-Variante).
        flight_id: bid.flight_id.clone(),
        // v0.7.8 v1.5: Match-Kandidaten (Manual-Mode-Variante).
        bid_callsign: bid
            .flight
            .callsign
            .clone()
            .filter(|s| !s.trim().is_empty()),
        pilot_callsign: state
            .cached_pilot_callsign
            .lock()
            .expect("cached_pilot_callsign lock")
            .clone(),
        started_at: Utc::now(),
        airline_icao: airline.map(|a| a.icao.clone()).unwrap_or_default(),
        airline_logo_url: airline.and_then(|a| a.logo.clone()).filter(|s| !s.is_empty()),
        planned_registration,
        aircraft_icao,
        aircraft_name,
        flight_number: bid.flight.flight_number.clone(),
        dpt_airport: bid.flight.dpt_airport_id.clone(),
        arr_airport: bid.flight.arr_airport_id.clone(),
        fares,
        stats: Mutex::new(FlightStats::new()),
        stop: AtomicBool::new(false),
        was_just_resumed: AtomicBool::new(false),
        streamer_spawned: AtomicBool::new(false),
        cancelled_remotely: AtomicBool::new(false),
        position_outbox: Mutex::new(std::collections::VecDeque::new()),
        phpvms_worker_spawned: AtomicBool::new(false),
        touchdown_sampler_spawned: AtomicBool::new(false),
        connection_state: std::sync::atomic::AtomicU8::new(CONN_STATE_LIVE),
        // v0.8.0: Navdata-Cache startet leer — wird von
        // `fetch_navdata_for_flight` (Slice B) parallel beim Flugstart
        // populiert. Leer = OurAirports-Fallback aktiv (= Verhalten
        // vor v0.8.0).
        navdata: Mutex::new(NavdataCache::default()),
    });

    save_active_flight(&app, &flight);
    // v0.8.0: parallel-fetch dep/arr/alt-Navdata vom VPS. Non-blocking
    // (Background-Task), Failure → OurAirports-Fallback (transparent).
    // Manual-Pfad: Alternate kommt aus der Plan-Eingabe.
    {
        let mut icaos = vec![flight.dpt_airport.clone(), flight.arr_airport.clone()];
        if let Some(alt) = plan.alt_airport_id.clone() {
            if !alt.trim().is_empty() {
                icaos.push(alt);
            }
        }
        spawn_navdata_fetch(&app, &flight, icaos);
    }
    {
        let mut guard = state.active_flight.lock().expect("active_flight lock");
        *guard = Some(Arc::clone(&flight));
    }
    setup_guard.disarm();

    // Manual-Plan in FlightStats schreiben (analog zu SB-OFP-Path)
    {
        let mut stats = flight.stats.lock().expect("flight stats lock");
        stats.planned_block_fuel_kg = Some(plan.planned_block_fuel_kg);
        // v0.7.1 Phase 2 F2 (Spec docs/spec/v0.7.1-landing-ux-fairness.md):
        // KEIN Fallback mehr. Wenn der Pilot keinen geplanten Trip-Burn aus
        // dem OFP hat, wird kein Fuel-Score vergeben (sub_fuel skipped).
        // Pilot wird nicht mehr fuer eine 90%-Annahme bewertet die er nie
        // selbst geplant hat.
        stats.planned_burn_kg = plan.planned_burn_kg;
        // v0.7.1 Phase 2 F1 (P1.3-B): ZFW ist Option<f32>, planned_tow nur
        // wenn ZFW vorhanden. planned_ldw bleibt None im Manual-Pfad
        // (kein Trip-Burn-Plan ohne OFP).
        stats.planned_zfw_kg = planned_zfw;
        stats.planned_tow_kg = planned_zfw.map(|zfw| zfw + plan.planned_block_fuel_kg);
        stats.planned_ldw_kg = None;
        stats.planned_route = plan.planned_route;
        stats.planned_alternate = plan.alt_airport_id;
        stats.flight_plan_source = Some("manual");
        // v0.16.12 (#phase-v2): VFR-/Manual-Reise-Level (bereits in ft)
        // als `cruise_ref` für die Schatten-Engine.
        stats.planned_cruise_alt_ft = plan
            .cruise_level_ft
            .filter(|&l| l > 0)
            .map(f64::from);
        drop(stats);
        save_active_flight(&app, &flight);
    }

    // v0.6.0/v0.6.1 — phpVMS-Worker zuerst spawnen (Hint, keine
    // Garantie — siehe ausfuehrlichen Kommentar in flight_start).
    // Ordering ist server-seitig durch PositionEntry.at sichergestellt.
    spawn_phpvms_position_worker(app.clone(), Arc::clone(&flight), client.clone());
    spawn_position_streamer(app.clone(), Arc::clone(&flight), client.clone());
    spawn_touchdown_sampler(app.clone(), Arc::clone(&flight));
    clear_activity_log_for_new_flight(&app);

    let info = flight_info(flight.as_ref(), false);
    log_activity(
        &state,
        ActivityLevel::Info,
        format!(
            "Manual-Mode-Flug gestartet: {} {} → {} (Block {:.0} kg, ETA {} min)",
            format_callsign(&flight.airline_icao, &flight.flight_number),
            flight.dpt_airport,
            flight.arr_airport,
            plan.planned_block_fuel_kg,
            plan.planned_flight_time_min,
        ),
        Some(format!("PIREP prefiled as {}", flight.pirep_id)),
    );
    log_activity(
        &state,
        ActivityLevel::Info,
        "Phase: Boarding".to_string(),
        None,
    );
    record_event(
        &app,
        &flight.pirep_id,
        &FlightLogEvent::FlightStarted {
            timestamp: Utc::now(),
            pirep_id: flight.pirep_id.clone(),
            airline_icao: flight.airline_icao.clone(),
            flight_number: flight.flight_number.clone(),
            dpt_airport: flight.dpt_airport.clone(),
            arr_airport: flight.arr_airport.clone(),
        },
    );
    Ok(info)
}

/// Minimum thresholds a flight has to pass before we'll let it file as a clean
/// ACARS PIREP. Anything below these is either a buggy run, a half-baked test,
/// or a flight that never actually flew — phpVMS shouldn't get those.
const MIN_FLIGHT_TIME_MIN: i32 = 1;
const MIN_DISTANCE_NM: f64 = 1.0;
const MIN_POSITION_COUNT: u32 = 5;

/// Names of fields that failed validation, returned to the UI as the
/// `details` payload of the `flight_validation_failed` UiError. The UI looks
/// up `flight.validation.<key>` for the localized message and decides
/// whether the user can still file as a manual PIREP.
fn validate_for_filing(
    flight: &ActiveFlight,
    stats: &FlightStats,
    elapsed_minutes: i32,
) -> Vec<&'static str> {
    let mut missing = Vec::new();
    if elapsed_minutes < MIN_FLIGHT_TIME_MIN {
        missing.push("flight_time");
    }
    if stats.distance_nm < MIN_DISTANCE_NM {
        missing.push("distance");
    }
    if stats.position_count < MIN_POSITION_COUNT {
        missing.push("position_count");
    }
    if stats.block_fuel_kg.is_none() || stats.last_fuel_kg.is_none() {
        missing.push("fuel");
    }
    // Must have actually arrived at a parking position. Anything before
    // BlocksOn means engines weren't shut down on the ground at the gate.
    if !matches!(
        stats.phase,
        FlightPhase::BlocksOn | FlightPhase::Arrived | FlightPhase::PirepSubmitted
    ) {
        missing.push("not_arrived");
    }
    // Bid is required for a clean ACARS PIREP. `flight_adopt` falls back to
    // bid_id=0 when no matching bid is found server-side, which means the
    // pilot is flying a PIREP that no longer has a booking attached. That
    // can happen legitimately (admin removed the bid) but it's never an
    // ACARS-clean situation — admin must review.
    if flight.bid_id <= 0 {
        missing.push("no_bid");
    }
    missing
}

/// Open (or create) the offline position queue under the OS-appropriate
/// app data directory. None when we can't resolve the dir — caller
/// treats that as "no queue available, drop the offline-resilience
/// feature for this tick" rather than blowing up the streamer.
fn open_position_queue(app: &AppHandle) -> Option<PositionQueue> {
    let dir = app.path().app_data_dir().ok()?;
    PositionQueue::open(dir).ok()
}

// v0.6.0: enqueue_position_offline ist entfallen — der phpVMS-Worker
// pusht failende Positionen zurück in die Memory-Outbox. Persistierung
// passiert durch persist_outbox() bei Worker-Stop / Backlog>500.
// Kein per-Position-File-IO mehr im POST-Path.

/// v0.5.49 — Persistenter PIREP-Queue für den Fall dass `client.file_pirep`
/// dauerhaft scheitert (Netz weg, phpVMS-Server down, …).
///
/// **Format:** ein JSON-File pro queued PIREP unter
/// `<app_data_dir>/pending_pireps/<pirep_id>.json`. Ein File-pro-PIREP
/// statt eine flache Queue-Datei macht es race-frei (Background-Worker
/// und neue file_pirep-Calls können sich nicht überschreiben) und
/// einfach inspizierbar (Pilot kann das Verzeichnis aufmachen).
///
/// **Worker:** läuft im Hintergrund alle 60 s, scannt das Verzeichnis,
/// versucht jeden gequeueten PIREP zu submitten, löscht das File bei
/// Success.
mod pirep_queue {
    use super::*;
    use std::path::PathBuf;

    pub const DIR_NAME: &str = "pending_pireps";

    #[derive(Debug, Clone, Serialize, Deserialize)]
    pub struct QueuedPirep {
        pub pirep_id: String,
        pub bid_id: i64,
        pub airline_icao: String,
        pub flight_number: String,
        pub dpt_airport: String,
        pub arr_airport: String,
        pub body: api_client::FileBody,
        pub queued_at: DateTime<Utc>,
        pub last_attempt_at: Option<DateTime<Utc>>,
        pub attempt_count: u32,
        pub last_error: Option<String>,
        /// v0.7.19 (QS-R2 Finding 2): phpVMS-Flight-ID als Fallback fuer
        /// `delete_bid` wenn der bid_id-Pfad 400/404/422 liefert. Leer-
        /// String fuer pre-v0.7.7-Resume-Files; wird beim Aufruf als
        /// None behandelt. #[serde(default)] damit alte queued-PIREPs
        /// (vor diesem Feld) weiter laden.
        #[serde(default)]
        pub flight_id: String,
        /// v0.12.5 (Spec v0.12.5-divert-and-manual-pirep.md, LE1b): das
        /// fertig gebaute MQTT-PIREP-Payload als JSON. Der Queue-Worker
        /// publisht das nach erfolgreichem phpVMS-`/file` via
        /// `finalize_filed_pirep` — vorher publizierte der Worker GAR
        /// KEIN MQTT-PIREP, gequeuete Diverts/Flüge fehlten dauerhaft in
        /// den VPS-Reports. `#[serde(default)]` = `Value::Null` für alte
        /// queued-Files (vor diesem Feld); der Worker behandelt Null als
        /// „kein MQTT-Publish" statt zu crashen.
        #[serde(default)]
        pub pirep_payload_json: serde_json::Value,
    }

    fn dir(app: &AppHandle) -> Option<PathBuf> {
        let base = app.path().app_data_dir().ok()?;
        let d = base.join(DIR_NAME);
        std::fs::create_dir_all(&d).ok()?;
        Some(d)
    }

    fn file_path(app: &AppHandle, pirep_id: &str) -> Option<PathBuf> {
        // pirep_id ist alphanumerisch in phpVMS — kein Sanitizing nötig,
        // aber wir bauen den Pfad sicher zusammen.
        let safe: String = pirep_id.chars()
            .filter(|c| c.is_ascii_alphanumeric() || *c == '-' || *c == '_')
            .collect();
        if safe.is_empty() { return None; }
        Some(dir(app)?.join(format!("{safe}.json")))
    }

    pub fn enqueue(app: &AppHandle, q: &QueuedPirep) -> Result<(), std::io::Error> {
        let path = file_path(app, &q.pirep_id)
            .ok_or_else(|| std::io::Error::new(std::io::ErrorKind::Other, "no app_data_dir or invalid pirep_id"))?;
        let json = serde_json::to_string_pretty(q)
            .map_err(|e| std::io::Error::new(std::io::ErrorKind::Other, e.to_string()))?;
        std::fs::write(path, json)
    }

    pub fn remove(app: &AppHandle, pirep_id: &str) {
        if let Some(path) = file_path(app, pirep_id) {
            let _ = std::fs::remove_file(path);
        }
    }

    pub fn list_all(app: &AppHandle) -> Vec<QueuedPirep> {
        let Some(d) = dir(app) else { return vec![]; };
        let Ok(rd) = std::fs::read_dir(&d) else { return vec![]; };
        let mut out = Vec::new();
        for entry in rd.flatten() {
            let p = entry.path();
            if p.extension().and_then(|s| s.to_str()) != Some("json") { continue; }
            let Ok(content) = std::fs::read_to_string(&p) else { continue; };
            if let Ok(q) = serde_json::from_str::<QueuedPirep>(&content) {
                out.push(q);
            }
        }
        out
    }

    // v0.7.13: `count(app)` entfernt — wurde fuer einen geplanten
    // "X Pireps in Queue"-Indicator vorgesehen, der nie ins UI ging.
    // `list(app)` reicht den Callern. Audit Q4-2026-05.
}

/// v0.5.49 — Auto-Retry für PIREP-File mit exponentiellem Backoff.
///
/// Versucht `client.file_pirep(pirep_id, body)` bis zu 3× — Initialversuch
/// + 2 Retries. Backoffs: 5s, 30s. Bei TRANSIENTEM Fehler (Netz weg,
/// Timeout, 5xx, 408, 429) wird retried. Bei HARD-Fehler (4xx außer
/// retry-fähig) sofort raus damit der Pilot was machen kann (z.B. 422
/// validation error — der Pilot muss den PIREP korrigieren).
///
/// Wenn auch nach 3× nicht durch: `Err(last_error)`. Der Caller in
/// `flight_end()` queued dann via `pirep_queue::enqueue` und meldet
/// Success an die UI (Pilot kann weiter, Worker erledigt's später).
async fn file_pirep_with_retry(
    client: &Client,
    pirep_id: &str,
    body: &api_client::FileBody,
) -> Result<(), ApiError> {
    const ATTEMPTS: u32 = 3;
    const BACKOFFS_SEC: [u64; 2] = [5, 30]; // wait BEFORE attempt 2 and 3
    let mut last_err: Option<ApiError> = None;
    for attempt in 0..ATTEMPTS {
        if attempt > 0 {
            let secs = BACKOFFS_SEC[(attempt as usize - 1).min(BACKOFFS_SEC.len() - 1)];
            tracing::info!(pirep_id, attempt, backoff_sec = secs, "PIREP file retry");
            tokio::time::sleep(std::time::Duration::from_secs(secs)).await;
        }
        match client.file_pirep(pirep_id, body).await {
            Ok(()) => return Ok(()),
            Err(e) if !is_transient_pirep_error(&e) => return Err(e),
            Err(e) => {
                tracing::warn!(pirep_id, attempt, error = %e, "PIREP file attempt failed (transient)");
                last_err = Some(e);
            }
        }
    }
    Err(last_err.unwrap_or(ApiError::Network("file_pirep_with_retry: no error captured".into())))
}

/// True wenn der Fehler nach Backoff retried werden soll (Netz, Timeout, 5xx, 408, 429).
/// False bei harten 4xx (validation, auth, …) oder 404 (PIREP wurde gecancelt).
fn is_transient_pirep_error(e: &ApiError) -> bool {
    match e {
        // 404 = PIREP wurde gecancelt → kein Retry, Caller muss reagieren
        ApiError::NotFound => false,
        // Auth-Fehler → kein Retry, Pilot muss neu einloggen
        ApiError::Unauthenticated | ApiError::Forbidden => false,
        // 5xx vom Server, 429 Rate-Limit, 408 Timeout → transient
        ApiError::Server { status, .. } => *status == 408 || (*status >= 500 && *status < 600),
        ApiError::RateLimited { .. } => true,
        // Network = Connect/Timeout/RST/etc. → klassisch transient
        ApiError::Network(_) => true,
        // InvalidUrl / BadResponse → wir können's nicht reparieren
        ApiError::InvalidUrl(_) | ApiError::BadResponse(_) => false,
    }
}

/// v0.5.49 — Background-Worker für den persistenten PIREP-Queue.
///
/// Spawnt beim App-Start einmal, läuft bis App-Exit. Tickt alle 60 s,
/// versucht jeden in `pending_pireps/` liegenden PIREP zu file-en, löscht
/// das File bei Success + bumpt das attempt-count + last_attempt_at bei
/// Failure damit man Pilot-seitig sehen kann wie oft retried wurde.
///
/// Skipt PIREPs mit > 50 Attempts (= circular failure, Pilot muss
/// manuell). Loggt Success/Failure als Activity-Events damit der Pilot
/// im Cockpit-Activity-Panel sehen kann was passiert.
fn spawn_pirep_queue_worker(app: AppHandle) {
    // v0.5.50 — `tauri::async_runtime::spawn` statt `tokio::spawn`.
    // Diese Funktion wird aus dem synchronen `.setup()`-Closure
    // aufgerufen — auf macOS ist da noch kein tokio-Runtime-Context
    // aktiv, weshalb `tokio::spawn` in v0.5.49 mit „no reactor running"
    // panic'd und die App sofort nach Update-Restart geschlossen wurde
    // (Pilot-Report: Mac öffnet nicht mehr nach v0.5.49-Update).
    // `tauri::async_runtime::spawn` nutzt explizit Tauris managed Runtime
    // und funktioniert auch im Setup-Context auf allen Plattformen.
    tauri::async_runtime::spawn(async move {
        const TICK: std::time::Duration = std::time::Duration::from_secs(60);
        const MAX_ATTEMPTS: u32 = 50;
        loop {
            tokio::time::sleep(TICK).await;
            let queued = pirep_queue::list_all(&app);
            // Client aus dem AppState holen — könnte fehlen wenn Pilot
            // nicht eingeloggt ist (= keine Connection). Dann skippen.
            let state = app.state::<AppState>();
            let client_opt = state
                .client
                .lock()
                .expect("client lock")
                .clone();
            let Some(client) = client_opt else { continue; };

            // v0.7.19 GAF-707 (QS-R1 Finding 1): Pending-Bid-Cleanup-Queue
            // bei jedem Tick mit drainen — unabhaengig davon ob auch
            // pireps queued sind. Sonst bleibt der Bid nach einem
            // erfolgreichen FILED + transientem delete_bid-Fail haengen
            // bis zufaellig ein anderer PIREP queued wird.
            drain_pending_bid_cleanup(&app, &client).await;

            if queued.is_empty() { continue; }
            tracing::info!(queued_count = queued.len(), "PIREP-queue worker tick");
            for mut q in queued {
                if q.attempt_count >= MAX_ATTEMPTS {
                    tracing::warn!(pirep_id = %q.pirep_id, attempts = q.attempt_count, "skipping queued PIREP (max attempts)");
                    continue;
                }
                q.attempt_count += 1;
                q.last_attempt_at = Some(Utc::now());
                match client.file_pirep(&q.pirep_id, &q.body).await {
                    Ok(()) => {
                        tracing::info!(pirep_id = %q.pirep_id, "queued PIREP filed successfully by background worker");
                        pirep_queue::remove(&app, &q.pirep_id);
                        log_activity_handle(
                            &app,
                            ActivityLevel::Info,
                            format!(
                                "Gequeueter PIREP nachträglich eingereicht: {} {} → {}",
                                format_callsign(&q.airline_icao, &q.flight_number),
                                q.dpt_airport,
                                q.arr_airport,
                            ),
                            Some(format!("Nach {} Versuch(en) — Verbindung war wieder da", q.attempt_count)),
                        );
                        // Best-effort Bid-Cleanup. v0.7.19 (QS-R1 Finding 1):
                        // transientes Scheitern landet in pending_bid_cleanup
                        // und wird im naechsten Tick erneut probiert.
                        consume_bid_best_effort(
                            &app,
                            &client,
                            &q.pirep_id,
                            q.bid_id,
                            // v0.7.19 (QS-R2 Finding 2): flight_id-Fallback
                            // aus dem persistierten QueuedPirep mitgeben.
                            Some(q.flight_id.as_str()),
                            "queued_filed",
                        ).await;
                        // Selber Tick: Pending-Bid-Cleanup-Queue drainen
                        drain_pending_bid_cleanup(&app, &client).await;
                        // v0.12.5 (LE1b): JSONL-PirepFiled-Event schreiben
                        // + MQTT-PIREP nachträglich publishen — sonst fehlt
                        // der gequeuete Flug dauerhaft in den VPS-Reports.
                        // QS-P1: `finalize_filed_pirep` schreibt das JSONL-
                        // Event IMMER (auch ohne MQTT-Handle) — Voraussetzung
                        // für den Recorder-seitigen JSONL-Gap-Fill.
                        // Null = altes queued-File ohne das Feld → skip.
                        if !q.pirep_payload_json.is_null() {
                            let mqtt = state.mqtt.lock().await;
                            finalize_filed_pirep(
                                &app,
                                mqtt.as_ref(),
                                &q.pirep_id,
                                q.pirep_payload_json.clone(),
                            );
                        }
                        // Best-effort: JSONL-Upload (wenn das Recorder-File noch da ist)
                        spawn_flight_log_upload(&app, q.pirep_id.clone());
                    }
                    Err(e) => {
                        // v0.8.3 (#1): Hard-Errors NICHT mehr endlos
                        // re-enqueuen. Vorher: jeder Fehler — auch HTTP 400
                        // "PIREP is read-only" (= phpVMS hat den PIREP
                        // bereits als ACCEPTED markiert, lehnt jedes
                        // weitere /file ab) — wurde als transient behandelt
                        // und alle 60 s nochmal probiert, bis MAX_ATTEMPTS
                        // erreicht war. Pilot sah 50 Min lang rote
                        // "PIREP file failed"-Spam-Eintraege im Activity-Log
                        // (Reported 2026-05-17 Svenny, BE36-Session 819).
                        //
                        // Jetzt: bei nicht-transienten Fehlern den Queue-
                        // Eintrag verwerfen + EINEN sauberen Activity-Log-
                        // Hinweis schreiben. Bei transienten Fehlern (Netz
                        // weg, 5xx, 408, 429) bleibt das alte Verhalten.
                        if !is_transient_pirep_error(&e) {
                            pirep_queue::remove(&app, &q.pirep_id);
                            tracing::warn!(
                                pirep_id = %q.pirep_id,
                                error = %e,
                                "queued PIREP rejected by server — removing from queue"
                            );
                            log_activity_handle(
                                &app,
                                ActivityLevel::Warn,
                                format!(
                                    "PIREP {} serverseitig abgelehnt — Queue-Eintrag entfernt",
                                    format_callsign(&q.airline_icao, &q.flight_number),
                                ),
                                Some(format!(
                                    "{}. Falls Du den Flug filen wolltest: phpVMS-Web pruefen \
                                     (PIREP evtl. bereits eingereicht oder gecancelt).",
                                    friendly_net_error(&e),
                                )),
                            );
                            // Best-effort: JSONL-Upload trotzdem versuchen
                            // — Forensik-Log ist auch dann wertvoll wenn
                            // der PIREP nicht (mehr) angenommen wurde.
                            // (Fix #6 — siehe Worker-Success-Pfad oben.)
                            spawn_flight_log_upload(&app, q.pirep_id.clone());
                            continue;
                        }
                        q.last_error = Some(friendly_net_error(&e));
                        // Update das File mit dem neuen attempt-count + Error
                        if let Err(e) = pirep_queue::enqueue(&app, &q) {
                            tracing::warn!(pirep_id = %q.pirep_id, error = %e, "pirep_queue: persisting retry state failed — attempt-count/last_error may be lost");
                        }
                        tracing::warn!(
                            pirep_id = %q.pirep_id,
                            attempt = q.attempt_count,
                            error = %e,
                            "queued PIREP file failed (transient) — will retry next tick"
                        );
                    }
                }
            }
        }
    });
}

/// v0.5.49 — Übersetzt technische Netzwerk-Fehler in für Piloten lesbare
/// Texte. Hauptzweck: Windows-Socket-Codes wie "1236" oder "10054" sind
/// für den Pilot kryptisch — wir mappen sie auf "Verbindung verloren"
/// + erwartete Selbst-Heilung.
///
/// Heuristik: wir matchen auf Teilstrings im Display-String von
/// reqwest::Error, plus die ein Windows-Code-Suffixe wie "(os error 1236)"
/// die Tokio/Reqwest auf Windows in den Error-Text schreiben.
fn friendly_net_error(e: &ApiError) -> String {
    let s = format!("{e}");
    let s_lower = s.to_lowercase();
    if s.contains("1236") || s_lower.contains("connection invalid") {
        "Verbindung wurde unterbrochen (1236 — Router-NAT-Eviction o.ä.). Wiederversuch automatisch.".to_string()
    } else if s.contains("10053") || s_lower.contains("connection abort") || s_lower.contains("software caused") {
        "Verbindung lokal abgebrochen (10053). Wiederversuch automatisch.".to_string()
    } else if s.contains("10054") || s_lower.contains("connection reset") {
        "Verbindung vom Server beendet (10054). Wiederversuch automatisch.".to_string()
    } else if s.contains("10060") || s_lower.contains("timed out") || s_lower.contains("timeout") {
        "Server-Antwort-Timeout. Wiederversuch automatisch.".to_string()
    } else if s_lower.contains("dns") || s_lower.contains("name resolution") {
        "DNS-Auflösung fehlgeschlagen. Internet-Verbindung prüfen.".to_string()
    } else if s_lower.contains("connect") {
        "Konnte phpVMS-Server nicht erreichen. Wiederversuch automatisch.".to_string()
    } else {
        format!("Netzwerk-Fehler: {s}")
    }
}

/// Open (or create) the per-flight JSONL recorder. None when we can't
/// resolve the app data dir — caller treats it as "skip recording for
/// this tick" rather than failing the streamer.
fn open_flight_recorder(app: &AppHandle, pirep_id: &str) -> Option<FlightRecorder> {
    let dir = app.path().app_data_dir().ok()?;
    FlightRecorder::open(dir, pirep_id).ok()
}

/// Open the landing-history store. None when the app data dir can't be
/// resolved — caller treats that as "skip recording, history is best-
/// effort" rather than failing the PIREP file.
fn open_landing_store(app: &AppHandle) -> Option<LandingStore> {
    let dir = app.path().app_data_dir().ok()?;
    LandingStore::open(dir).ok()
}

/// v0.7.5 Phase-Safety Hotfix (Spec docs/spec/flight-phase-state-machine.md §13.8):
/// Reine pure-function fuer den Universal Arrived-Fallback. URO913 zeigte historisch:
/// Pilot rollte mit `engines_running=0` aber `groundspeed_kt = 141 -> 42` ueber ~31.5s
/// zum Cargo-Stand → Fallback feuerte `Arrived` obwohl der Flieger noch rollte.
///
/// Ab v0.7.5: `groundspeed_kt < 1.0` Pflicht — echtes Stillstand statt nur "on ground".
///
/// Returns true wenn der ARRIVED_FALLBACK_DWELL_SECS-Dwell starten/laufen darf.
pub fn arrived_fallback_conditions_basic(
    on_ground: bool,
    engines_running: u8,
    groundspeed_kt: f32,
) -> bool {
    on_ground && engines_running == 0 && groundspeed_kt < 1.0
}

/// v0.17.x (#Premium, Aircraft-Scan): reine Bedingung für den engines-
/// UNABHÄNGIGEN Stillstands-Fallback (siehe [`ARRIVED_STANDSTILL_DWELL_SECS`]).
/// Anders als [`arrived_fallback_conditions_basic`] verlangt sie NICHT
/// `engines_running == 0` — genau dafür ist sie da: Addons, deren
/// Triebwerkszähler nach dem Shutdown klemmt (Contrail FA50 Trijet bleibt
/// bei 3), würden sonst nie Auto-File auslösen. Stattdessen: am geplanten
/// Ziel (`near_planned`), voll gestanden (< 1 kt), Parkbremse gesetzt. Der
/// Aufrufer koppelt das an den längeren Dwell, damit ein kurzer Halt mit
/// laufenden Triebwerken (Warten vor dem Gate) nicht als Ankunft durchgeht.
///
/// WICHTIG (v0.17.x QA-Review, NICHT gelockert): die Parkbremsen-Pflicht
/// bleibt bewusst hart. Der naheliegende Gedanke "was, wenn das Addon auch
/// die Parkbremse nicht treibt" wurde geprüft und verworfen — ohne die
/// Bremse ließe sich ein Rollhalt (z. B. Warten auf eine freie Bahn zum
/// Kreuzen während des Taxi-in, real mehrere Minuten) nicht mehr von einer
/// echten Ankunft unterscheiden: Position/Geschwindigkeit sind während eines
/// solchen Halts identisch mit "geparkt". Ob der Contrail FA50 die Stock-
/// `parking_brake`-SimVar tatsächlich setzt, ist noch NICHT am echten Flug
/// verifiziert (siehe QA-Notiz) — das ist die richtige Reihenfolge: erst am
/// Flugdaten-Log von D-BETI bestätigen, dann ggf. gezielt lockern (z. B. über
/// einen zusätzlichen, wirklich addon-unabhängigen Ankunfts-Indikator statt
/// über pure Standzeit).
pub fn arrived_standstill_condition(
    near_planned: bool,
    on_ground: bool,
    groundspeed_kt: f32,
    parking_brake: bool,
) -> bool {
    near_planned && on_ground && groundspeed_kt < 1.0 && parking_brake
}

#[cfg(test)]
mod arrived_standstill_tests {
    use super::arrived_standstill_condition as cond;

    #[test]
    fn fa50_stuck_engine_count_still_arrives() {
        // Contrail FA50: am Ziel voll gestanden, Parkbremse gesetzt — der
        // Stillstands-Pfad greift, obwohl engines_running (hier irrelevant)
        // klemmen würde. Das ist der Kern des Auto-File-Fixes.
        assert!(cond(true, true, 0.0, true));
    }

    #[test]
    fn requires_parking_brake() {
        // Ohne Parkbremse NICHT — verhindert Fehlauslösung z. B. beim Warten
        // auf eine freie Bahn während des Rollens (Kreuzungshalt, real auch
        // mehrere Minuten).
        assert!(!cond(true, true, 0.0, false));
    }

    #[test]
    fn requires_stationary() {
        // Noch in Bewegung (Taxi) → nein.
        assert!(!cond(true, true, 5.0, true));
    }

    #[test]
    fn requires_on_ground() {
        assert!(!cond(true, false, 0.0, true));
    }

    #[test]
    fn requires_near_planned_destination() {
        // Fernab vom geplanten Ziel läuft der Stillstands-Pfad NICHT — dort
        // greift stattdessen der strikte engines-off-Divert-Pfad.
        assert!(!cond(false, true, 0.0, true));
    }
}

/// v0.7.5 Phase-Safety Hotfix (Spec §13.9):
/// Reine pure-function: muss `holding_pending_since` resetet werden bei diesem
/// Phase-Wechsel? PTO105 (Bug-Beleg): Approach -> Holding mit nur 5.2s Aufenthalt —
/// alter Pending-State aus einer frueheren Phase wurde mitgeschleppt.
///
/// Regel: bei jedem Phase-Wechsel der NICHT `→ Holding` ist, Pending-Reset.
pub fn should_reset_holding_pending(
    prev_phase: FlightPhase,
    next_phase: FlightPhase,
) -> bool {
    next_phase != prev_phase && next_phase != FlightPhase::Holding
}

// ─── v0.7.6 P1-3: Runway-Geometry-Trust ───────────────────────────────
//
// Spec docs/spec/v0.7.6-landing-payload-consistency.md §3 P1-3.
//
// Real-Beleg fuer den Bug: GSG303 v0.7.5 (ldoGzaxbb9aNYE9n)
//   - arr_airport=OR66 aber runway_match_icao=K5S9 (3.5 km daneben)
//   - landing_float_distance_m=-613 (Touchdown 613 m vor Threshold)
//   - Score behandelt das trotzdem als "TD Zone 1, excellent stop"
//
// Trust-Check: ICAO muss matchen, Centerline-Offset darf max 200 m sein,
// Float-Distance darf max -100 m sein. Werte sind hardcoded (v1.2).

/// Maximale Centerline-Distanz (m) vom Touchdown-Punkt zur erkannten
/// Runway-Mittellinie. Daruber: vermutlich falscher Runway-Match.
pub const RUNWAY_TRUST_MAX_CENTERLINE_OFFSET_M: f32 = 200.0;

/// Minimum-Float-Distance (m). Werte unter -100 m bedeuten der
/// Touchdown war so weit vor der Threshold dass die Runway-Geometrie
/// nicht mehr stimmen kann. Liegt typische TDZ-Marker-Versetzungen
/// (e.g. EDDM 26L) komfortabel im trusted-Bereich.
pub const RUNWAY_TRUST_MIN_FLOAT_DISTANCE_M: f32 = -100.0;

/// v0.7.6 P1-3: Pure-function Trust-Check ohne FlightStats-Abhaengigkeit
/// damit die Logik 1:1 testbar ist. Returns (trusted, reason).
///
/// Reasons (in Pruefungs-Reihenfolge):
///   "no_runway_match"           — Kein Runway-Match in der DB (Privatplatz,
///                                 Off-DB-Bahn) — UI sollte hier KEINE
///                                 alarmierende Pille zeigen, einfach die
///                                 Geometry-Tiles ausblenden
///   "icao_mismatch"             — Match-ICAO existiert aber != arr/divert
///                                 (echter Bug-Indikator: falscher Flughafen)
///   "centerline_offset_too_large" — > 200 m
///   "negative_float_distance"   — < -100 m
///   None                         — alle Checks pass
///
/// **Wichtig (v1.1-Refinement):** "kein Match" und "falscher Match" sind
/// semantisch verschieden — bei Privatplaetzen / Bush-Strips ist es normal
/// dass die ourairports-DB keinen Eintrag hat, das ist KEIN Pilot-Fehler.
/// "falscher Match" dagegen ist ein echter Datenintegritaets-Bug
/// (GSG303-Klasse: arr=OR66, gematcht auf K5S9 weil 3.5 km daneben).
pub fn runway_geometry_trust_check(
    matched_icao: Option<&str>,
    arr_airport: &str,
    divert_to: Option<&str>,
    centerline_offset_m: Option<f32>,
    float_distance_m: Option<f32>,
) -> (bool, Option<&'static str>) {
    // 1) Kein Match → eigener Reason, nicht als "icao_mismatch" verkaufen.
    let matched = match matched_icao {
        Some(m) if !m.is_empty() => m,
        _ => return (false, Some("no_runway_match")),
    };
    // 2) Match existiert aber != arr/divert → echtes Mismatch.
    //
    // v0.7.6 P3 Refinement: case-insensitive Vergleich. ICAOs sind in
    // unserer DB praktisch immer uppercase, aber externe phpVMS-Daten
    // oder OFP-Imports koennten "edDM" oder "eddm" liefern und das
    // sollte keine falsche icao_mismatch-Warnung triggern.
    let icao_ok = matched.eq_ignore_ascii_case(arr_airport)
        || divert_to.is_some_and(|d| matched.eq_ignore_ascii_case(d));
    if !icao_ok {
        return (false, Some("icao_mismatch"));
    }
    // Centerline-Offset (None ist OK — bedeutet "kein Wert verfuegbar",
    // nicht "Wert zu gross"; wir bestrafen nicht das Fehlen einer
    // optionalen Diagnostik).
    if let Some(offset) = centerline_offset_m {
        if offset.abs() > RUNWAY_TRUST_MAX_CENTERLINE_OFFSET_M {
            return (false, Some("centerline_offset_too_large"));
        }
    }
    // Float-Distance (None ist OK — siehe Centerline-Begruendung)
    if let Some(float) = float_distance_m {
        if float < RUNWAY_TRUST_MIN_FLOAT_DISTANCE_M {
            return (false, Some("negative_float_distance"));
        }
    }
    (true, None)
}

/// v0.7.6 P1-2 / P2-B Helper: zentraler Read-Sites-Wrapper fuer den
/// scoring-relevanten Bounce-Count. Aktuell ist `stats.bounce_count`
/// das Feld das sowohl Streamer-Tally (35-ft armed counter) als auch
/// nach dem Analysis-Override den scored_bounce_count haelt — ein
/// Caller der das Feld direkt liest weiss nicht ob das Override schon
/// gelaufen ist oder nicht.
///
/// Dieser Helper macht die Semantik im Score-Pfad explizit: "ich will
/// den scored_bounce_count, mit Fallback auf das was im stats steht".
/// Falls in v0.8.x die FlightStats umstrukturiert werden (eigenes
/// `scored_bounce_count`-Feld), aendert sich nur diese eine Stelle.
///
/// Spec docs/spec/v0.7.6-landing-payload-consistency.md §3 P1-2,
/// Refinement nach Thomas-Review (P2-B fragility).
fn scored_bounce_count_for_score(stats: &FlightStats) -> u32 {
    // stats.bounce_count wurde von der Override-Logik (lib.rs ~9869-9891)
    // mit scored_bounce_count aus dem analysis-JSON ueberschrieben falls
    // der 50-Hz-Sampler-Buffer vollstaendig war. Ohne Override haelt das
    // Feld den Streamer-Tally (35-ft armed counter) — auch das ist eine
    // konservative Annaeherung an "echter Bounce" (35 ft >= 15 ft scored
    // threshold), sodass kein Pilot faelschlich bestraft wird wenn der
    // Sampler-Buffer fehlt.
    stats.bounce_count as u32
}

// ─── v0.7.8 SimBrief-direct: Flight-Match-Verifikation ──────────────────
//
// Spec docs/spec/ofp-refresh-simbrief-direct-v0.7.8.md §6.
//
// Wenn AeroACArS direkt von SimBrief den latest OFP holt, muss verifiziert
// werden dass dieser zum aktiven Flug gehoert. Pilot koennte zwischen
// flight_start und Refresh einen OFP fuer einen ANDEREN Flug regeneriert
// haben (z.B. PPL-Training-Run). dpt+arr+callsign-Match faengt das ab.
//
// Match-Regeln:
//   - Origin/Destination ICAO: case-insensitive exakt
//   - Callsign: normalisierter Vergleich (kein blinder Suffix-Match)
//
// Pure functions — getestet ohne Tauri-State.

/// v0.7.8: Normalisiert eine Callsign-Form auf vergleichbares Format.
/// Entfernt Whitespace + Bindestrich + Underscore, uppercase.
/// "DLH-100" → "DLH100", "GSG 100" → "GSG100", "dlh100" → "DLH100".
pub fn normalize_callsign(s: &str) -> String {
    s.chars()
        .filter(|c| !c.is_whitespace() && *c != '-' && *c != '_')
        .collect::<String>()
        .to_ascii_uppercase()
}

/// v0.7.8: Trennt normalisierte Callsign-Form in (prefix, number).
/// "DLH100" → ("DLH", "100"), "100" → ("", "100"),
/// "GSG100A" → ("GSG", "100A").
pub fn split_callsign(cs: &str) -> (String, String) {
    let split_at = cs.find(|c: char| c.is_ascii_digit()).unwrap_or(cs.len());
    let (prefix, number) = cs.split_at(split_at);
    (prefix.to_string(), number.to_string())
}

/// v0.7.8 v1.5: Baut eine Liste von Kandidaten-Callsigns auf gegen die
/// der SimBrief-OFP-Callsign matchen darf. Spec §6.1.2.
///
/// Real-World-Beispiel (GSG):
///   - airline_icao = "CFG", flight_number = "1504" (Bid)
///   - bid_callsign = Some("CFG4TK") oder None
///   - pilot_callsign = Some("4TK") (aus Profile)
///
/// Kandidaten:
///   1. "CFG1504"  (airline + flight_number)
///   2. "1504"     (number-only)
///   3. "CFG4TK"   (bid.flight.callsign wenn vorhanden)
///   4. "CFG4TK"   (airline + pilot_callsign)
///   5. "4TK"      (pilot_callsign allein)
///
/// SimBrief-Callsign muss gegen EINEN davon exakt matchen (nach
/// Normalisierung). Leere Strings werden ausgefiltert.
pub fn build_candidate_callsigns(
    airline_icao: &str,
    flight_number: &str,
    bid_callsign: Option<&str>,
    pilot_callsign: Option<&str>,
) -> Vec<String> {
    let airline = airline_icao.trim().to_ascii_uppercase();
    let flight_n = flight_number.trim();
    let mut candidates: Vec<String> = Vec::new();

    // (1) airline_icao + flight_number
    if !airline.is_empty() && !flight_n.is_empty() {
        candidates.push(normalize_callsign(&format!("{}{}", airline, flight_n)));
    }
    // (2) flight_number allein (number-only-mode)
    if !flight_n.is_empty() {
        candidates.push(normalize_callsign(flight_n));
    }
    // (3) v1.5: bid.flight.callsign direkt
    if let Some(cs) = bid_callsign.filter(|s| !s.trim().is_empty()) {
        candidates.push(normalize_callsign(cs));
    }
    // (4) v1.5: airline + pilot_callsign
    if let Some(pc) = pilot_callsign.filter(|s| !s.trim().is_empty()) {
        if !airline.is_empty() {
            candidates.push(normalize_callsign(&format!("{}{}", airline, pc)));
        }
        // (5) v1.5: pilot_callsign allein
        candidates.push(normalize_callsign(pc));
    }

    // Dedupe + Leere entfernen.
    let mut seen: std::collections::HashSet<String> = std::collections::HashSet::new();
    candidates
        .into_iter()
        .filter(|s| !s.is_empty())
        .filter(|s| seen.insert(s.clone()))
        .collect()
}

/// v0.7.8: Verifiziert ob ein SimBrief-OFP zum aktiven AeroACARS-Flug passt.
/// Match-Regeln (v1.5 — Kandidaten-Liste statt strenger 1:1-Vergleich):
///   1. Origin/Destination ICAO: case-insensitive exakt
///   2. Callsign: SimBrief-Callsign (normalisiert) muss gegen EINEN von
///      mehreren validen Kandidaten exakt matchen. Siehe
///      `build_candidate_callsigns` fuer die volle Liste.
///   3. Empty SimBrief-Callsign → toleranter Match (= dpt+arr genuegen).
///
/// **Wichtig (Spec v1.1 P1-3):** KEIN blinder Suffix-Match — Kandidaten
/// muessen exakt sein. "DLH1100" matched NICHT mit Kandidat "100".
///
/// Spec docs/spec/ofp-refresh-simbrief-direct-v0.7.8.md §6.1.
pub fn ofp_matches_active_flight(
    ofp_origin: &str,
    ofp_destination: &str,
    ofp_callsign: &str,
    active_dpt: &str,
    active_arr: &str,
    active_airline_icao: &str,
    active_flight_number: &str,
    active_bid_callsign: Option<&str>,
    active_pilot_callsign: Option<&str>,
) -> bool {
    // 1. Origin / Destination MUESSEN matchen (case-insensitive).
    let dpt_ok = ofp_origin.trim().eq_ignore_ascii_case(active_dpt.trim());
    let arr_ok = ofp_destination.trim().eq_ignore_ascii_case(active_arr.trim());
    if !dpt_ok || !arr_ok {
        return false;
    }

    let simbrief_norm = normalize_callsign(ofp_callsign);
    if simbrief_norm.is_empty() {
        // SimBrief liefert kein Callsign → toleranter Mode: dpt+arr genuegen.
        // Real selten — SimBrief-OFP traegt typisch immer einen Callsign.
        return true;
    }

    // 2. v1.5: Kandidaten-Liste bauen aus allen verfuegbaren Quellen.
    let candidates = build_candidate_callsigns(
        active_airline_icao,
        active_flight_number,
        active_bid_callsign,
        active_pilot_callsign,
    );

    // 3. Exakter Match gegen Kandidat (= verhindert "DLH1100 vs 100"-
    //    False-Positive). split_callsign-Number-Vergleich nur fuer den
    //    Number-only-Fall (SimBrief liefert "1504" oder "4TK" ohne
    //    Airline-Prefix, dann werden gegen die number-Part-Kandidaten
    //    verglichen).
    let (simbrief_prefix, simbrief_number) = split_callsign(&simbrief_norm);

    if simbrief_prefix.is_empty() {
        // SimBrief number-only: vergleiche gegen number-Parts aller
        // Kandidaten. "1504" matcht "CFG1504" (number "1504"), "4TK"
        // matcht "CFG4TK" (number "4TK").
        return candidates.iter().any(|c| {
            let (_, c_number) = split_callsign(c);
            !c_number.is_empty() && c_number == simbrief_number
        });
    }

    // SimBrief mit Prefix: exakter Match gegen Kandidaten-Liste.
    candidates.contains(&simbrief_norm)
}

/// v0.7.21 (Nachhaltiger Fix, GAF/MS713-QS): kanonischer V/S-fpm-Wert.
///
/// Hintergrund: drei verschiedene Felder im `FlightStats` haben einen
/// V/S-Anteil (`landing_rate_fpm`, `landing_peak_vs_fpm`,
/// `landing_analysis["vs_at_edge_fpm"]`). Vor v0.7.21 wurden je nach
/// Code-Stelle unterschiedliche Felder direkt referenziert — Resultat:
/// phpVMS sah einen anderen Wert als Pilot-Client/Webapp/Discord-Bot.
/// v0.7.17 B-015a hatte einen `score_basis_vs_fpm(&stats)`-Helper
/// eingefuehrt, aber dessen Anwendung war an einigen Stellen vergessen
/// worden (FileBody.landing_rate ging direkt auf `landing_rate_fpm`).
///
/// Ab v0.7.21: JEDE Anzeige-/Filing-/Publish-Stelle MUSS
/// `stats.canonical_landing_rate_fpm()` aufrufen statt einzelne Felder
/// direkt zu lesen. Der freistehende `score_basis_vs_fpm()`-Helper
/// bleibt als duenner Shim erhalten (delegiert hierhin), damit
/// bestehender Code nicht broken bricht.
///
/// Cascade-Reihenfolge (matched `scoreBasisVs()` im TS-Frontend):
///   1. `vs_at_edge_fpm` aus `stats.landing_analysis` (50-Hz-Buffer-
///      Edge, FAR 25.473 Engineering-Standard) — wenn `< 0`
///   2. `stats.landing_peak_vs_fpm` (Touchdown-Window-Peak, Streamer-
///      Tick-Cadence)
///   3. `stats.landing_rate_fpm` (Streamer-Tick-Snapshot am TD-Frame)
impl FlightStats {
    /// SSoT fuer den V/S-Wert in fpm den Pilot/PIREP/MQTT/phpVMS sehen.
    /// Direkter Zugriff auf `stats.landing_rate_fpm` /
    /// `stats.landing_peak_vs_fpm` ist in Anzeige-/Filing-Pfaden ein
    /// Bug — siehe MS713-QS-Befund 2026-05-13.
    pub fn canonical_landing_rate_fpm(&self) -> Option<f32> {
        if let Some(edge) = self
            .landing_analysis
            .as_ref()
            .and_then(|v| v.get("vs_at_edge_fpm"))
            .and_then(|v| v.as_f64())
        {
            let edge_f32 = edge as f32;
            if edge_f32 < 0.0 {
                return Some(edge_f32);
            }
        }
        self.landing_peak_vs_fpm.or(self.landing_rate_fpm)
    }
}

/// v0.7.17 → v0.7.21 Shim: leitet auf `FlightStats::canonical_landing_
/// rate_fpm()` um. Neue Anzeige-Pfade sollen direkt die Methode auf
/// `FlightStats` aufrufen — dieser freistehende Helper wird beim
/// naechsten Major-Bump entfernt.
#[inline]
fn score_basis_vs_fpm(stats: &FlightStats) -> Option<f32> {
    stats.canonical_landing_rate_fpm()
}

/// v0.7.18 (B-012) — Resolution-Source.
///
/// Spec docs/spec/v0.7.18-orphan-flight-cleanup.md §B-012. Wire-Format
/// per Serde snake_case damit Frontend + Webapp das Enum als String
/// vergleichen können.
#[derive(Debug, Clone, Copy, Serialize, Deserialize, PartialEq, Eq)]
#[serde(rename_all = "snake_case")]
pub enum TouchdownAirportSource {
    /// Touchdown-Edge konnte einer Runway zugeordnet werden — autoritativ.
    RunwayMatch,
    /// Kein Runway-Match, aber Airport innerhalb 25 nmi. `nearest_distance_nm` gesetzt.
    Nearest25Nm,
    /// Total off-airport — fallback auf `flight.arr_airport`.
    PlannedFallback,
}

/// v0.7.18 (B-012) — Resolution-Result für den Touchdown-Airport.
#[derive(Debug, Clone)]
pub struct TouchdownAirportResolution {
    pub icao: String,
    pub source: TouchdownAirportSource,
    pub distance_to_destination_nm: Option<f32>,
    pub nearest_distance_nm: Option<f32>,
}

impl TouchdownAirportSource {
    pub fn as_wire_str(self) -> &'static str {
        match self {
            Self::RunwayMatch => "runway_match",
            Self::Nearest25Nm => "nearest_25nm",
            Self::PlannedFallback => "planned_fallback",
        }
    }
}

/// v0.8.0: Resultat aller Pure-Function-Assessments für einen Touchdown.
/// Wird sowohl von `record_landing_for_filed_flight` (= LandingRecord)
/// als auch vom Streamer-Tick (= TouchdownPayload) gebraucht — einmal
/// rechnen, an beide Orte feeden.
///
/// TDZ + Aim werden für JEDE runway-match Quelle berechnet (length +
/// td_distance reichen, beides ist auch in OurAirports). DDS + TCH
/// brauchen `displaced_threshold_ft` / `tch_ft` aus der Navigraph-
/// Geometrie und sind deshalb nur bei Navigraph-Source verfügbar.
/// TCH-actual wird im Streamer-Tick beim Touchdown-Edge aus dem 50-Hz-
/// Buffer extrahiert (siehe `stats.runway_tch_actual_ft`); diese
/// Funktion klassifiziert nur den vorberechneten Wert.
#[derive(Debug, Clone, Default)]
struct AssessedTouchdown {
    td_distance_from_threshold_m: Option<f64>,
    tdz: Option<runway_assessment::TdzResult>,
    aim: Option<runway_assessment::AimResult>,
    tch: Option<runway_assessment::TchResult>,
    dds: Option<runway_assessment::DisplacedResult>,
}

fn assess_touchdown(stats: &FlightStats) -> AssessedTouchdown {
    let Some(rm) = stats.runway_match.as_ref() else {
        return AssessedTouchdown::default();
    };
    const FT_PER_M: f64 = 3.280_839_895;
    let td_m = rm.touchdown_distance_from_threshold_ft / FT_PER_M;
    let length_m = (rm.length_ft as f64) / FT_PER_M;
    let tdz = runway_assessment::classify_tdz(td_m, length_m);
    let aim = Some(runway_assessment::classify_aim(td_m, length_m));
    let dds = stats.runway_nav_geometry.as_ref().map(|g| {
        runway_assessment::classify_displaced(td_m, g.displaced_threshold_ft as f64)
    });
    // F5 TCH: nur klassifizieren wenn BOTH der nav-geometric tch_ft
    // AND der actual-measured tch_ft im Streamer-Tick vorhanden sind.
    let tch = match (stats.runway_nav_geometry.as_ref(), stats.runway_tch_actual_ft) {
        (Some(g), Some(actual)) => Some(runway_assessment::classify_tch(
            actual as f64,
            g.tch_ft as f64,
        )),
        _ => None,
    };
    AssessedTouchdown {
        td_distance_from_threshold_m: Some(td_m),
        tdz,
        aim,
        tch,
        dds,
    }
}

fn tch_class_wire(class: runway_assessment::TchClass) -> &'static str {
    use runway_assessment::TchClass::*;
    match class {
        OnProfile => "on_profile",
        SlightlyLow => "slightly_low",
        SlightlyHigh => "slightly_high",
        High => "high",
        BelowProfile => "below_profile",
    }
}

fn aim_class_wire(class: runway_assessment::AimClass) -> &'static str {
    use runway_assessment::AimClass::*;
    match class {
        Perfect => "perfect",
        ShortOfAim => "short_of_aim",
        PastAim => "past_aim",
        LongLanding => "long_landing",
        Severe => "severe",
    }
}

fn runway_source_wire(s: runway::RunwaySource) -> &'static str {
    match s {
        runway::RunwaySource::Navigraph => "navigraph",
        runway::RunwaySource::OurAirportsFallback => "ourairports_fallback",
    }
}

/// v0.7.18 (B-012) — Touchdown-Airport-Resolution.
///
/// Cascade:
///   1. `runway_match.airport_ident` — wenn TD-Edge einer Runway zugeordnet wurde.
///   2. Nearest Airport innerhalb 25 nmi.
///   3. `planned_arr_airport` als letzter Fallback.
///
/// `airport_lookup` ist eine Closure die für gegebene ICAO die Koordinaten
/// liefert. Caller wählt die Quelle (AppState.airports HashMap, Cache, etc.) —
/// die Spec gibt keinen konkreten Cache-Typ vor.
fn resolve_touchdown_airport<F>(
    runway_match: Option<&runway::RunwayMatch>,
    landing_lat: Option<f64>,
    landing_lon: Option<f64>,
    planned_arr_airport: &str,
    airport_lookup: F,
) -> TouchdownAirportResolution
where
    F: Fn(&str) -> Option<(f64, f64)>,
{
    let planned_coords = airport_lookup(planned_arr_airport);
    let dist_to_planned = |lat: f64, lon: f64| -> Option<f32> {
        planned_coords.map(|(plat, plon)| {
            (geo::distance_m(lat, lon, plat, plon) / 1852.0) as f32
        })
    };

    if let Some(rw) = runway_match {
        let dist = match (landing_lat, landing_lon) {
            (Some(la), Some(lo)) => dist_to_planned(la, lo),
            _ => None,
        };
        return TouchdownAirportResolution {
            icao: rw.airport_ident.clone(),
            source: TouchdownAirportSource::RunwayMatch,
            distance_to_destination_nm: dist,
            nearest_distance_nm: None,
        };
    }

    if let (Some(lat), Some(lon)) = (landing_lat, landing_lon) {
        const TD_NEAREST_RADIUS_NM: f64 = 25.0;
        let nearest = runway::find_nearest_airports(
            lat,
            lon,
            TD_NEAREST_RADIUS_NM * 1852.0,
            1,
        );
        if let Some(closest) = nearest.first() {
            return TouchdownAirportResolution {
                icao: closest.icao.clone(),
                source: TouchdownAirportSource::Nearest25Nm,
                distance_to_destination_nm: dist_to_planned(lat, lon),
                nearest_distance_nm: Some(
                    (closest.distance_m / 1852.0) as f32,
                ),
            };
        }
        return TouchdownAirportResolution {
            icao: planned_arr_airport.to_string(),
            source: TouchdownAirportSource::PlannedFallback,
            distance_to_destination_nm: dist_to_planned(lat, lon),
            nearest_distance_nm: None,
        };
    }

    TouchdownAirportResolution {
        icao: planned_arr_airport.to_string(),
        source: TouchdownAirportSource::PlannedFallback,
        distance_to_destination_nm: None,
        nearest_distance_nm: None,
    }
}

/// v0.12.5 (Spec v0.12.5-divert-and-manual-pirep.md, LE2b): bestimmt die
/// `divert`/`diverted_to`-Marker fürs PIREP-Payload. Pure function — damit
/// ohne ein volles `ActiveFlight` testbar.
///
/// `effective_arr_icao != planned_arr_icao` ⇒ aktiv geflogener Divert:
/// `divert = Some(true)`, `diverted_to = Some(effective)`. Sonst Fallback
/// auf den passiv erkannten `DivertHint` — die FSM hat ein Ausweichfeld
/// erkannt, der Pilot hat den Flug aber nicht als Divert gefilt.
fn divert_payload_markers(
    effective_arr_icao: &str,
    planned_arr_icao: &str,
    divert_hint: Option<&DivertHint>,
) -> (Option<bool>, Option<String>) {
    if effective_arr_icao != planned_arr_icao {
        (Some(true), Some(effective_arr_icao.to_string()))
    } else {
        (
            divert_hint.map(|_| true),
            divert_hint.and_then(|h| h.actual_icao.clone()),
        )
    }
}

/// v0.12.5 (Spec v0.12.5-divert-and-manual-pirep.md, LE1): zentraler
/// MQTT-PirepPayload-Builder — eine Stelle für alle 4 Filing-Pfade
/// (normal /file, Divert, manuell, Queue-Worker). Vorher war dieser
/// ~200-Zeilen-Block inline im `flight_end`-Command dupliziert; Divert-
/// und Manual-Pfad publizierten gar kein MQTT-PIREP → Reports verschluckt.
///
/// `effective_arr_icao` = der tatsächliche Ankunftsflughafen (bei Divert
/// das Ausweich-ICAO, sonst == `planned_arr_icao`). `planned_arr_icao` =
/// der ursprünglich geplante Zielflughafen. Ist `effective != planned`,
/// werden `divert`/`diverted_to` gesetzt; Rollout-/Runway-Geometrie wird
/// gegen `effective_arr_icao` aufgelöst.
fn build_pirep_payload(
    flight: &ActiveFlight,
    body: &api_client::FileBody,
    effective_arr_icao: &str,
    planned_arr_icao: &str,
) -> aeroacars_mqtt::PirepPayload {
    let stats = flight.stats.lock().expect("flight stats");
    let touchdown_count = stats.touchdown_events.len() as u32;
    // v0.12.5 (LE2b): divert/diverted_to via pure Helper bestimmen.
    let (divert_flag, diverted_to) = divert_payload_markers(
        effective_arr_icao,
        planned_arr_icao,
        stats.divert_hint.as_ref(),
    );
    // v0.7.1 P1.3-Fix: Sub-Scores einmal berechnen,
    // dann sowohl als sub_scores ins Payload als auch
    // als landing_score (gewichteter Aggregate) nutzen.
    let actual_burn = actual_burn_for_record(&stats);
    let mut scoring_input = landing_scoring::LandingScoringInput {
        // v0.7.17 (B-015a QS-Fix): Edge-Wert hat Vorrang.
        vs_fpm: score_basis_vs_fpm(&stats),
        peak_g_load: stats.landing_peak_g_force,
        // v0.12.3 (LE8): zentraler Scored-G-Helper —
        // EMA-Wert, sonst raw_fallback; nie None (QS-P2).
        scored_g_load: Some(score_g_for_stats(&stats).scored_g),
        // v0.7.6 P2-B: zentraler Helper statt direkten Read.
        bounce_count: Some(scored_bounce_count_for_score(&stats)),
        approach_vs_stddev_fpm: stats.approach_vs_stddev_fpm,
        approach_bank_stddev_deg: stats.approach_bank_stddev_deg,
        rollout_distance_m: stats
            .rollout_distance_m
            .map(|m| m as f32),
        planned_burn_kg: stats.planned_burn_kg,
        actual_trip_burn_kg: actual_burn,
        planned_zfw_kg: stats.planned_zfw_kg,
        planned_tow_kg: stats.planned_tow_kg,
        // v0.7.17 (N-002): aircraft-aware rollout score
        aircraft_icao: Some(flight.aircraft_icao.clone()),
        ..Default::default()
    };
    // v0.10.0 (#runway-utilization-score): LDA-basierter
    // Bahn-Auslastungs-Score. Markiert weiter unten am
    // PirepPayload via score_algorithm_version: Some(4)
    // (v0.12.0: Float-Toleranz-Refinement;
    //  v0.16.21: MSFS touchdown V/S SimVar-lag g-force-gated de-lag).
    fill_v2_rollout_fields(&mut scoring_input, &stats, effective_arr_icao);
    let payload_sub_scores =
        landing_scoring::compute_sub_scores(&scoring_input);
    let aggregate_master =
        landing_scoring::aggregate_master_score(&payload_sub_scores);
    let payload_landing_score = aggregate_master
        .map(|m| m as i32)
        .or_else(|| stats.landing_score.map(|s| s.numeric()));
    aeroacars_mqtt::PirepPayload {
        ts: Utc::now().timestamp_millis(),
        // v0.11.1: Pilot-Client-Version mitsenden
        // damit Reports-Uebersicht die Pill ohne
        // Touchdown-Join zeigen kann.
        client_version: Some(env!("CARGO_PKG_VERSION")),
        pirep_id: flight.pirep_id.clone(),
        flight_number: format_callsign(
            &flight.airline_icao,
            &flight.flight_number,
        ),
        dep: flight.dpt_airport.clone(),
        arr: effective_arr_icao.to_string(),
        block_time_min: body.flight_time,
        flight_time_min: body.flight_time,
        distance_nm: body.distance.map(|d| d as f32),
        // v0.12.5 (LE4, QS-R2-P2): `body.fuel_used` ist die phpVMS-Site-
        // Unit = POUND. Das MQTT-Feld heißt `fuel_used_kg` — also explizit
        // lb→kg zurückrechnen. Vorher floss der lb-Wert ungewandelt in ein
        // `_kg`-Feld (Recorder/Web sah ~2,2× zu viel „kg").
        fuel_used_kg: body.fuel_used.map(|lb| (lb / KG_TO_LB) as f32),
        planned_burn_kg: stats.planned_burn_kg,
        block_fuel_kg: stats.block_fuel_kg,
        takeoff_fuel_kg: stats.takeoff_fuel_kg,
        landing_fuel_kg: stats.landing_fuel_kg,
        // v0.7.6 P1-1: Trip-Burn als SSoT fuer OFP-Vergleich.
        actual_trip_burn_kg: actual_burn,
        takeoff_weight_kg: stats.takeoff_weight_kg.map(|w| w as f32),
        landing_weight_kg: stats.landing_weight_kg.map(|w| w as f32),
        planned_tow_kg: stats.planned_tow_kg,
        planned_ldw_kg: stats.planned_ldw_kg,
        peak_altitude_ft: stats.peak_altitude_ft.map(|v| v.round() as i32),
        landing_vs_fpm: body.landing_rate.map(|r| r as i32),
        // v0.7.1 P1.3-Fix: gewichteter Aggregate-Score
        // (Fuel/Loadsheet/Stability/Rollout fliessen ein),
        // mit Fallback auf Touchdown-Klassifikation.
        landing_score: payload_landing_score,
        go_around_count: Some(stats.go_around_count),
        touchdown_count: Some(touchdown_count),
        dep_gate: stats.dep_gate.clone(),
        arr_gate: stats.arr_gate.clone(),
        approach_runway: stats.approach_runway.clone(),
        // v0.12.5 (LE2b): bei Divert sind divert/diverted_to gesetzt;
        // sonst Fallback auf den passiven divert_hint (via Helper oben).
        divert: divert_flag,
        diverted_to,
        notes: None,
        // v0.7.0 — Touchdown-Forensik v2 marker (P2 fix)
        forensics_version: touchdown_v2::FORENSICS_VERSION,

        // ─── v0.7.1 Felder (Spec §5.1) ────────────────
        ux_version: 1,
        landing_confidence: stats.landing_confidence.clone(),
        landing_source: stats.landing_source.clone(),
        // F6: Flare-Felder aus dem 50-Hz-Sampler-Buffer
        // (landing_analysis ist Option<Value>)
        flare_detected: stats
            .landing_analysis
            .as_ref()
            .and_then(|v| v.get("flare_detected"))
            .and_then(|v| v.as_bool()),
        flare_reduction_fpm: stats
            .landing_analysis
            .as_ref()
            .and_then(|v| v.get("flare_reduction_fpm"))
            .and_then(|v| v.as_f64())
            .map(|x| x as f32),
        flare_quality_score: stats
            .landing_analysis
            .as_ref()
            .and_then(|v| v.get("flare_quality_score"))
            .and_then(|v| v.as_i64())
            .map(|x| x.clamp(0, 100) as u8),
        // F7: Stability-v2-Felder (P2.1-A: bestehende
        // Backend-Felder exponieren)
        approach_vs_stddev_fpm: stats.approach_vs_stddev_fpm,
        approach_bank_stddev_deg: stats.approach_bank_stddev_deg,
        approach_vs_jerk_fpm: stats.approach_vs_jerk_fpm,
        approach_ias_stddev_kt: stats.approach_ias_stddev_kt,
        approach_stable_config: stats.approach_stable_config,
        approach_excessive_sink: Some(stats.approach_excessive_sink),
        // v0.7.1 Round-2 P2-Fix: gate_window aus echten
        // Approach-Samples + TD-Timestamp gerechnet.
        gate_window: build_mqtt_gate_window_from_stats(&stats),
        // P1.5 + Phase 2 (F1/F2/F3) + P1.3-Fix:
        // bereits oben berechnet, hier nur durchreichen.
        sub_scores: payload_sub_scores,
        // v0.7.6 P1-3: Runway-Geometry-Trust. Pure-
        // function Check + reason-string ins Payload.
        runway_geometry_trusted: {
            let (trusted, _) = runway_geometry_trust_check(
                stats.runway_match.as_ref()
                    .map(|m| m.airport_ident.as_str()),
                effective_arr_icao,
                stats.divert_hint.as_ref()
                    .and_then(|h| h.actual_icao.as_deref()),
                stats.runway_match.as_ref()
                    .map(|m| m.centerline_distance_m as f32),
                stats.landing_float_distance_m,
            );
            Some(trusted)
        },
        runway_geometry_reason: {
            let (_, reason) = runway_geometry_trust_check(
                stats.runway_match.as_ref()
                    .map(|m| m.airport_ident.as_str()),
                effective_arr_icao,
                stats.divert_hint.as_ref()
                    .and_then(|h| h.actual_icao.as_deref()),
                stats.runway_match.as_ref()
                    .map(|m| m.centerline_distance_m as f32),
                stats.landing_float_distance_m,
            );
            reason.map(String::from)
        },
        // v0.7.19 GAF-707 Accident-Detection: Accident-Felder
        // gelatcht; Sentinel wird IMMER gesetzt.
        accident_classifier_version: Some(
            accident::ACCIDENT_CLASSIFIER_VERSION.into(),
        ),
        accident: if stats.accident_detected {
            Some(true)
        } else {
            None
        },
        accident_kind: stats.accident_kind.clone(),
        accident_confidence: stats
            .accident_confidence
            .clone(),
        accident_reasons: if stats
            .accident_reasons
            .is_empty()
        {
            None
        } else {
            Some(stats.accident_reasons.clone())
        },
        accident_at: stats
            .accident_at
            .map(|t| t.timestamp_millis()),
        // v0.10.0 (#runway-utilization-score): markiert
        // dass die sub_scores oben vom LDA-basierten
        // Bahn-Auslastungs-Algorithmus stammen.
        // v0.16.21: bump 3→4 — MSFS touchdown V/S SimVar-lag corrected
        // (g-force-gated AGL de-lag; MSFS only, X-Plane unchanged).
        score_algorithm_version: Some(4),
    }
}

/// v0.12.5 (Spec v0.12.5-divert-and-manual-pirep.md, LE1): zentraler
/// Filing-Abschluss — schreibt das PIREP-Forensik-Event ins JSONL und
/// publisht das PIREP via MQTT. Arbeitet bewusst auf der bereits
/// serialisierten JSON-Form (`serde_json::Value`), damit der PIREP-Queue-
/// Worker — der nur die persistierte JSON-Form besitzt — exakt denselben
/// Abschluss-Pfad nutzt wie die Live-Pfade. Vorher publizierten der
/// Divert-, der Manual- und der Queue-Pfad GAR KEIN MQTT-PIREP →
/// Reports/Logfile verschluckt (Bug A/B/C der Spec).
///
/// QS-P1: `handle` ist **`Option`**. Das `PirepFiled`-JSONL-Event MUSS
/// immer geschrieben werden — auch ohne MQTT-Verbindung — sonst kann der
/// Recorder-Importer den PIREP nicht aus dem hochgeladenen JSONL nachlegen
/// (`importer.ts` legt `pireps` nur bei `pirep_filed` an). MQTT-Publish ist
/// best-effort und entfällt sauber, wenn kein Handle da ist.
fn finalize_filed_pirep(
    app: &AppHandle,
    handle: Option<&aeroacars_mqtt::Handle>,
    pirep_id: &str,
    pirep_payload_json: serde_json::Value,
) {
    // v0.5.34: PIREP-Forensik ins JSONL — damit das Recovery-Tool
    // Pireps + abhaengige Stats rekonstruieren kann. IMMER, unabhängig
    // vom MQTT-Status (QS-P1: JSONL-Gap-Fill-Durabilität).
    record_event(
        app,
        pirep_id,
        &FlightLogEvent::PirepFiled {
            timestamp: Utc::now(),
            payload: pirep_payload_json.clone(),
        },
    );
    // MQTT-Publish nur wenn eine Verbindung steht — best-effort.
    if let Some(handle) = handle {
        handle.pirep_json(pirep_payload_json);
    }
}

/// v0.12.5 (LE7-QS): emittiert das `LandingFinalized`-JSONL-Event mit dem
/// finalen V/S + Score (Spec touchdown-forensics-v2 §7.2). Gerufen vom
/// Normal-, Divert- UND Manual-Filing-Pfad — alle drei haben eine lebende
/// `ActiveFlight`. Der PIREP-Queue-Worker kann es nicht: dort ist die
/// `ActiveFlight` beim Queueing bereits verworfen.
fn emit_landing_finalized(app: &AppHandle, flight: &ActiveFlight) {
    // Aktuell: nimmt den letzten validated TD-Score (single-shot, bis
    // Multi-TD-Episodes voll integriert sind).
    let (final_vs, final_score_label) = {
        let s = flight.stats.lock().expect("flight stats");
        (
            s.landing_rate_fpm,
            s.landing_score.map(|sc| format!("{:?}", sc)),
        )
    };
    record_event(
        app,
        &flight.pirep_id,
        &FlightLogEvent::LandingFinalized {
            timestamp: Utc::now(),
            forensics_version: touchdown_v2::FORENSICS_VERSION,
            final_vs_fpm: final_vs,
            final_score: final_score_label,
        },
    );
}

/// v0.7.1 Helper: actual_trip_burn = takeoff_fuel - landing_fuel
/// (1:1 wie in build_landing_record line 6527-6530). Damit sub_scores
/// + aggregate_master_score den gleichen Wert nutzen.
fn actual_burn_for_record(stats: &FlightStats) -> Option<f32> {
    match (stats.takeoff_fuel_kg, stats.landing_fuel_kg) {
        (Some(toff), Some(land)) if toff > land && toff > 0.0 && land >= 0.0 => {
            Some(toff - land)
        }
        _ => None,
    }
}

/// v0.12.4 (Spec docs/spec/v0.12.4-score-consistency.md, LE5): OFP-Trip-
/// Burn-Abweichung in Prozent — `(trip_burn − planned) / planned × 100`,
/// mit `trip_burn = takeoff_fuel − landing_fuel`. Positiv = Mehrverbrauch.
/// `None`, wenn `planned <= 0` oder ein Input fehlt.
///
/// **Bewusst Trip-Burn, nicht Block-Fuel:** Block-Fuel enthält den Taxi-out-
/// Sprit und ergäbe einen anderen Prozent-Wert als der v0.7.1-Sub-Score
/// (`sub_scores[fuel]`). Diese Funktion hält das MQTT-`TouchdownPayload`-Feld
/// `fuel_efficiency_pct` auf derselben Basis wie `LandingRecord`.
fn trip_burn_efficiency_pct(
    takeoff_fuel_kg: Option<f32>,
    landing_fuel_kg: Option<f32>,
    planned_burn_kg: Option<f32>,
) -> Option<f32> {
    match (takeoff_fuel_kg, landing_fuel_kg, planned_burn_kg) {
        // Guard identisch zu `actual_burn_for_record` — bei Refuel /
        // Sim-Anomalie (`takeoff <= landing`) liefern wir None statt eines
        // negativen Phantom-Trip-Burns, sonst driftet das MQTT-Feld wieder
        // vom LandingRecord + sub_scores[fuel] weg.
        (Some(takeoff), Some(landing), Some(plan))
            if plan > 0.0 && takeoff > landing && takeoff > 0.0 && landing >= 0.0 =>
        {
            let trip_burn = takeoff - landing;
            Some(((trip_burn - plan) / plan) * 100.0)
        }
        _ => None,
    }
}

#[cfg(test)]
mod trip_burn_efficiency_tests {
    use super::trip_burn_efficiency_pct;

    /// v0.12.4 (Spec LE5): Golden-Case DLH 1386 (PIREP jJ0kojW7kD9kK0ke).
    /// Trip-Burn = takeoff 7341.383 − landing 3862.3726 = 3479.01 kg,
    /// planned 3340 → +4.16 %. Der alte block-fuel-basierte Wert wäre
    /// +9.47 % gewesen (block 7518.789 − landing 3862.3726 = 3656.42) —
    /// diese Regression darf NICHT zurückkommen.
    #[test]
    fn dlh1386_uses_trip_burn_not_block_fuel() {
        let pct = trip_burn_efficiency_pct(
            Some(7341.383),
            Some(3862.3726),
            Some(3340.0),
        )
        .expect("alle Inputs vorhanden");
        assert!(
            (pct - 4.16).abs() < 0.15,
            "erwartet ~+4.2 %, war {pct}"
        );
        assert!(
            pct < 6.0,
            "block-fuel-Regression (+9.5 %) zurück: {pct}"
        );
    }

    #[test]
    fn none_when_input_missing_or_planned_non_positive() {
        assert!(trip_burn_efficiency_pct(Some(7000.0), Some(3000.0), None).is_none());
        assert!(trip_burn_efficiency_pct(Some(7000.0), Some(3000.0), Some(0.0)).is_none());
        assert!(trip_burn_efficiency_pct(None, Some(3000.0), Some(3000.0)).is_none());
        assert!(trip_burn_efficiency_pct(Some(7000.0), None, Some(3000.0)).is_none());
    }

    /// v0.12.4 P2: Guard identisch zu `actual_burn_for_record` — bei
    /// Refuel / Sim-Anomalie (`takeoff <= landing`) → None statt negativem
    /// Phantom-Trip-Burn.
    #[test]
    fn none_when_takeoff_not_greater_than_landing() {
        // Refuel mid-flight: mehr Sprit bei Landung als bei Takeoff.
        assert!(trip_burn_efficiency_pct(Some(3000.0), Some(3500.0), Some(2000.0)).is_none());
        // Gleichstand zählt auch nicht (takeoff > landing strikt gefordert).
        assert!(trip_burn_efficiency_pct(Some(3000.0), Some(3000.0), Some(2000.0)).is_none());
    }

    /// Minderverbrauch ergibt einen negativen Prozent-Wert.
    #[test]
    fn under_burn_is_negative() {
        // Trip-Burn 2900 vs planned 3000 → −3.33 %.
        let pct = trip_burn_efficiency_pct(Some(6000.0), Some(3100.0), Some(3000.0))
            .unwrap();
        assert!((pct - (-3.333)).abs() < 0.05, "war {pct}");
    }
}

/// v0.10.0 (#runway-utilization-score) — Helper: populiert die für den
/// neuen `sub_rollout_v2`-Algorithmus benötigten Felder am
/// `LandingScoringInput`. Wird von allen 4 Compute-Sites (build_landing_
/// record, build PirepPayload, compute_aggregate_master_score, shadow-
/// validation) konsistent gerufen, damit Pilot-Client, PIREP-Notes,
/// Webapp + Recorder denselben Score sehen.
///
/// `airport_source` proxy: wenn `stats.runway_match` Some ist, wurde
/// der Touchdown via runway-match aufgelöst → setzt `Some("runway_match")`.
/// Bei None bleibt's None → `sub_rollout_v2` skipped mit
/// `off_airport_landing` (was korrekt ist).
///
/// Geometry-Trust + pre-displaced kommen aus dem zentralen
/// `runway_geometry_trust_check` resp. `assess_touchdown` damit die
/// Logik 1:1 mit dem ist was im PIREP-Payload landet.
fn fill_v2_rollout_fields(
    input: &mut landing_scoring::LandingScoringInput,
    stats: &FlightStats,
    arr_airport: &str,
) {
    let rm = stats.runway_match.as_ref();
    input.td_distance_from_threshold_m = rm
        .map(|m| (m.touchdown_distance_from_threshold_ft as f64) * 0.3048);
    input.landing_float_distance_m = stats.landing_float_distance_m;
    input.runway_length_m = rm.map(|m| (m.length_ft as f32) * 0.3048);
    input.runway_displaced_threshold_ft = stats
        .runway_nav_geometry
        .as_ref()
        .map(|g| g.displaced_threshold_ft);
    // assess_touchdown(stats).dds.in_pre_threshold_zone — identisch zu
    // dem was im TouchdownPayload + LandingRecord landet (single source).
    let assessed = assess_touchdown(stats);
    input.pre_displaced_threshold = assessed.dds.map(|d| d.in_pre_threshold_zone);
    let (trusted, _) = runway_geometry_trust_check(
        rm.map(|m| m.airport_ident.as_str()),
        arr_airport,
        stats.divert_hint.as_ref().and_then(|h| h.actual_icao.as_deref()),
        rm.map(|m| m.centerline_distance_m as f32),
        stats.landing_float_distance_m,
    );
    input.runway_geometry_trusted = Some(trusted);
    input.airport_source = rm.map(|_| "runway_match".to_string());
    input.runway_match_icao = rm.map(|m| m.airport_ident.clone());
    input.runway_match_ident = rm.map(|m| m.runway_ident.clone());
}

/// v0.7.1 Round-2 Helper: berechnet den gewichteten Aggregate-Master-
/// Score aus stats. Single-Source-of-Truth fuer alle phpVMS-/PIREP-/
/// MQTT-/UI-Pfade — vermeidet die Inkonsistenz dass App/Web "77/100"
/// zeigt aber phpVMS "60/100" speichert.
///
/// Returns None wenn keine Sub-Scores berechnet werden konnten
/// (= Touchdown-Daten fehlen voellig). Caller sollte dann auf
/// stats.landing_score.numeric() fallback'en.
fn compute_aggregate_master_score(
    stats: &FlightStats,
    aircraft_icao: Option<&str>,
    arr_airport: &str,
) -> Option<u8> {
    let actual_burn = actual_burn_for_record(stats);
    let mut scoring_input = landing_scoring::LandingScoringInput {
        // v0.7.17 (B-015a QS-Fix): Edge-Wert hat Vorrang — siehe
        // `score_basis_vs_fpm()` Doc.
        vs_fpm: score_basis_vs_fpm(stats),
        peak_g_load: stats.landing_peak_g_force,
        // v0.12.3 (LE8): zentraler Scored-G-Helper — EMA-Wert aus der
        // Forensik, sonst raw_fallback. Nie `None` an den Score (QS-P2).
        scored_g_load: Some(score_g_for_stats(stats).scored_g),
        // v0.7.6 P2-B: zentraler Helper statt direkten Read.
        bounce_count: Some(scored_bounce_count_for_score(stats)),
        approach_vs_stddev_fpm: stats.approach_vs_stddev_fpm,
        approach_bank_stddev_deg: stats.approach_bank_stddev_deg,
        rollout_distance_m: stats.rollout_distance_m.map(|m| m as f32),
        planned_burn_kg: stats.planned_burn_kg,
        actual_trip_burn_kg: actual_burn,
        planned_zfw_kg: stats.planned_zfw_kg,
        planned_tow_kg: stats.planned_tow_kg,
        // v0.7.17 (N-002): Aircraft-ICAO fuer den aircraft-category-
        // sensitiven Bahn-Auslastung-Score. None → Light-Default-
        // Schwellen (konservativ).
        aircraft_icao: aircraft_icao.map(str::to_string),
        ..Default::default()
    };
    // v0.10.0: v2-RolloutInput-Felder mit-füllen damit der LDA-basierte
    // Sub-Score gerechnet wird (siehe spec docs/spec/v0.10.0-runway-
    // utilization-score.md).
    fill_v2_rollout_fields(&mut scoring_input, stats, arr_airport);
    let subs = landing_scoring::compute_sub_scores(&scoring_input);
    landing_scoring::aggregate_master_score(&subs)
}

/// v0.7.1 Round-2: Aggregate-Score → Label-Mapping. Damit
/// score_label und score_numeric semantisch zueinander passen.
/// Nutzt die gleichen Schwellen wie LandingScore::numeric()
/// (100/80/60/30/0 → smooth/acceptable/firm/hard/severe).
fn aggregate_score_label(aggregate: u8) -> &'static str {
    if aggregate >= 90 {
        "smooth"
    } else if aggregate >= 70 {
        "acceptable"
    } else if aggregate >= 45 {
        "firm"
    } else if aggregate >= 15 {
        "hard"
    } else {
        "severe"
    }
}

/// v0.7.1 Round-2: leitet GateWindow-Werte aus den ApproachSamples ab.
/// Damit die UI-Tooltip-Aussage "Bewertet werden Anflug-Samples
/// zwischen X und Y ft AGL" wirklich auf den ECHTEN bewerteten
/// Bereich verweist und nicht nur auf die Crate-Konstanten.
///
/// Returns None wenn keine Samples die `is_scored_gate=true` Flag haben
/// (z.B. fuer pre-v0.7.1-PIREPs ohne die Felder).
///
/// Tuple-Format weil es zwei verschiedene GateWindow-Structs gibt
/// (storage + aeroacars-mqtt) — Caller baut den passenden Type.
fn extract_gate_window_values(
    approach_samples: &[ApproachSample],
) -> Option<(i64, i64, f32, f32, u32)> {
    let scored: Vec<&ApproachSample> = approach_samples
        .iter()
        .filter(|s| s.is_scored_gate.unwrap_or(false))
        .collect();
    if scored.is_empty() {
        return None;
    }
    let start = scored.first()?;
    let end = scored.last()?;
    Some((
        start.t_ms.unwrap_or(0) as i64,
        end.t_ms.unwrap_or(0) as i64,
        start.agl_ft.unwrap_or(0.0),
        end.agl_ft.unwrap_or(0.0),
        scored.len() as u32,
    ))
}

fn build_storage_gate_window(approach_samples: &[ApproachSample]) -> Option<GateWindow> {
    extract_gate_window_values(approach_samples).map(|(s, e, sh, eh, n)| GateWindow {
        start_at_ms: s,
        end_at_ms: e,
        start_height_ft: sh,
        end_height_ft: eh,
        sample_count: n,
    })
}

/// v0.7.1 Round-2: GateWindow direkt aus stats.approach_buffer +
/// stats.landing_at fuer den MQTT-Pfad (build_landing_record schon
/// hat approach_samples lokal, aber der PIREP-Payload-Builder nicht).
/// Berechnet die gleichen is_scored_gate-Flags wie in
/// build_landing_record (height in 0..=1000 ft AGL minus letzte 3s
/// vor TD) und liefert das resultierende Window.
fn build_mqtt_gate_window_from_stats(
    stats: &FlightStats,
) -> Option<aeroacars_mqtt::GateWindow> {
    use landing_scoring::gate::{
        STABILITY_GATE_FLARE_CUTOFF_MS, STABILITY_GATE_MAX_HEIGHT_FT,
        STABILITY_GATE_MIN_HEIGHT_FT,
    };
    let td_ts = stats.landing_at?;
    let scored: Vec<(&ApproachBufferSample, i32)> = stats
        .approach_buffer
        .iter()
        .filter_map(|s| {
            let height = s.agl_ft;
            let in_height_band = height > STABILITY_GATE_MIN_HEIGHT_FT
                && height <= STABILITY_GATE_MAX_HEIGHT_FT;
            let dt_ms = (s.at - td_ts).num_milliseconds() as i32;
            let ms_before_td = (-dt_ms) as i64;
            let in_flare =
                ms_before_td >= 0 && ms_before_td < STABILITY_GATE_FLARE_CUTOFF_MS;
            if in_height_band && !in_flare {
                Some((s, dt_ms))
            } else {
                None
            }
        })
        .collect();
    if scored.is_empty() {
        return None;
    }
    let (start, start_t) = scored.first()?;
    let (end, end_t) = scored.last()?;
    Some(aeroacars_mqtt::GateWindow {
        start_at_ms: *start_t as i64,
        end_at_ms: *end_t as i64,
        start_height_ft: start.agl_ft,
        end_height_ft: end.agl_ft,
        sample_count: scored.len() as u32,
    })
}

/// v0.7.1 (Spec F4 + P2.2-D): atomic write of landing rate + confidence
/// + source.
///
/// Realitaet vor v0.7.1: `landing_rate_fpm` wurde an drei Stellen final
/// gesetzt (lib.rs:9362 touchdown_v2-dump, lib.rs:11532 streamer-tick,
/// lib.rs:12312 sampler-carry-over). Wenn nur am Edge VALIDATE die
/// Confidence/Source gespeichert wurden, konnten Werte und Confidence
/// auseinanderlaufen — z.B. wenn der Streamer einen Smoothed-Fallback
/// schrieb, Confidence aber noch "High" vom Edge stand.
///
/// Loesung: alle 3 Sites rufen diesen Helper. Confidence/Source
/// IMMER konsistent zum finalen `landing_rate_fpm`.
fn finalize_landing_rate(
    stats: &mut FlightStats,
    vs_fpm: f32,
    confidence: Option<&str>,
    source: Option<&str>,
) {
    stats.landing_rate_fpm = Some(vs_fpm);
    stats.landing_peak_vs_fpm = Some(vs_fpm);
    stats.landing_confidence = confidence.map(|s| s.to_string());
    stats.landing_source = source.map(|s| s.to_string());
}

/// Build a `LandingRecord` from the current flight + stats. Returns None
/// when there's no usable touchdown captured (e.g. PIREP filed before
/// landing — synthetic / bug). The record is the immutable snapshot we
/// show in the Landing tab; once written it never changes.
/// v0.13.15: maximales Post-TD-Fenster fuer das angezeigte V/S-Profil.
const POST_TD_PROFILE_MS: i32 = 10_000;

/// v0.13.15 (Pilot-Befund ViolonC 2026-05-31): Baut das anzuzeigende V/S-
/// Touchdown-Profil. `snapshot_profile` ist der aus dem 5-s-snapshot_buffer
/// eingefrorene Teil (Pre-TD + die paar 100 ms, die der ggf. verspaetete
/// Streamer-Tick noch mitnahm). `post_buffer` enthaelt dieselben Samples PLUS
/// bis zu 10 s Post-TD (vom 50-Hz-Sampler). Wir uebernehmen den snapshot-Teil
/// 1:1 und haengen aus dem post_buffer nur die Samples NACH dem bereits
/// vorhandenen Maximum an (bis `post_td_profile_ms`), damit es im Overlap
/// keine Doppel-Punkte gibt. Vorher wurde der post_buffer beim Dump geleert
/// → der Record sah nur die ~0.5 s aus dem snapshot, obwohl der Chart
/// "inkl. 10 s nach TD" anzeigt (Discord-Befund WFL1505, 2026-05-31).
fn merge_touchdown_profile(
    snapshot_profile: &[TouchdownProfilePoint],
    post_buffer: &std::collections::VecDeque<TelemetrySample>,
    touchdown_at: DateTime<Utc>,
    post_td_profile_ms: i32,
) -> Vec<LandingProfilePoint> {
    let mut profile: Vec<LandingProfilePoint> = snapshot_profile
        .iter()
        .map(|p| LandingProfilePoint {
            t_ms: p.t_ms,
            vs_fpm: p.vs_fpm,
            g_force: p.g_force,
            agl_ft: p.agl_ft,
            on_ground: p.on_ground,
            heading_true_deg: p.heading_true_deg,
            groundspeed_kt: p.groundspeed_kt,
            indicated_airspeed_kt: p.indicated_airspeed_kt,
            pitch_deg: p.pitch_deg,
            bank_deg: p.bank_deg,
        })
        .collect();
    let existing_max_t_ms = profile.iter().map(|p| p.t_ms).max().unwrap_or(0);
    for s in post_buffer.iter() {
        let t_ms = (s.at - touchdown_at).num_milliseconds() as i32;
        if t_ms > existing_max_t_ms && t_ms <= post_td_profile_ms {
            profile.push(LandingProfilePoint {
                t_ms,
                vs_fpm: s.vs_fpm,
                g_force: s.g_force,
                agl_ft: s.agl_ft,
                on_ground: s.on_ground,
                heading_true_deg: s.heading_true_deg,
                groundspeed_kt: s.groundspeed_kt,
                indicated_airspeed_kt: s.indicated_airspeed_kt,
                pitch_deg: s.pitch_deg,
                bank_deg: s.bank_deg,
            });
        }
    }
    profile
}

fn build_landing_record<F>(
    flight: &ActiveFlight,
    stats: &FlightStats,
    sim_kind_label: Option<&str>,
    aircraft_icao: Option<&str>,
    aircraft_title: Option<&str>,
    // v0.15.x: der EFFEKTIVE (tatsächliche) Landeflughafen. Bei einem Divert
    // != flight.arr_airport (= geplant). Wird NUR für den Runway-Geometrie-
    // Trust-Check genutzt, damit eine Divert-Landung am ECHTEN Flughafen
    // (z.B. MGGT statt geplant MZBE) nicht als `icao_mismatch` verworfen wird
    // → Rollout/Runway werden korrekt gewertet (Live-Report Thomas, GLG2).
    // Das Anzeige-`arr_airport` im Record bleibt das geplante Ziel (+ Divert-
    // Banner). Für Nicht-Diverts ist effective == geplant (kein Verhaltens-
    // unterschied).
    effective_arr_icao: &str,
    airport_lookup: F,
) -> Option<LandingRecord>
where
    F: Fn(&str) -> Option<(f64, f64)>,
{
    let touchdown_at = stats.landing_at?;
    // v0.7.21 (MS713-QS): SSoT-Methode statt direkten Feld-Zugriff.
    // Damit der LandingRecord (= was im Pilot-Client Tab Landung
    // angezeigt wird) UND der Webapp-Live-Map den IDENTISCHEN Edge-Wert
    // sehen — nicht den Streamer-Tick-Snapshot.
    let landing_rate_fpm = stats.canonical_landing_rate_fpm()?;
    let touchdown_class = stats.landing_score?;
    // v0.7.1 P1.3-Fix + Round-2 P2-Fix: score_numeric UND score_label
    // beide aus dem Aggregate-Score, damit sie semantisch zueinander
    // passen. Vorher: "SMOOTH · 77/100" (Label aus Touchdown-Klasse,
    // Zahl aus Aggregate) — fuer Pilot verwirrend.
    // Fallback auf Touchdown-Klassifikation wenn keine Sub-Scores
    // berechnet werden konnten (Edge-Case Schutz).
    let mut scoring_input = landing_scoring::LandingScoringInput {
        // v0.7.17 (B-015a QS-Fix): Edge-Wert hat Vorrang — siehe
        // `score_basis_vs_fpm()` Doc.
        vs_fpm: score_basis_vs_fpm(stats),
        peak_g_load: stats.landing_peak_g_force,
        // v0.12.3 (LE8): zentraler Scored-G-Helper — EMA-Wert aus der
        // Forensik, sonst raw_fallback. Nie `None` an den Score (QS-P2).
        scored_g_load: Some(score_g_for_stats(stats).scored_g),
        // v0.7.6 P2-B: zentraler Helper statt direkten Read.
        bounce_count: Some(scored_bounce_count_for_score(stats)),
        approach_vs_stddev_fpm: stats.approach_vs_stddev_fpm,
        approach_bank_stddev_deg: stats.approach_bank_stddev_deg,
        rollout_distance_m: stats.rollout_distance_m.map(|m| m as f32),
        planned_burn_kg: stats.planned_burn_kg,
        actual_trip_burn_kg: actual_burn_for_record(stats),
        planned_zfw_kg: stats.planned_zfw_kg,
        planned_tow_kg: stats.planned_tow_kg,
        // v0.7.17 (N-002): Aircraft-Category aware rollout-Score.
        aircraft_icao: aircraft_icao.map(str::to_string),
        ..Default::default()
    };
    // v0.10.0 (#runway-utilization-score): LDA-basierten Bahn-Auslastungs-
    // Score aktivieren. Wenn alle benötigten Felder vorhanden → neuer
    // Algorithmus, sonst skipped mit konkretem Reason (KEIN Rollback auf
    // meter-only).
    // v0.15.x: effektiven Landeflughafen (Divert-aware) statt geplantes Ziel.
    fill_v2_rollout_fields(&mut scoring_input, stats, effective_arr_icao);
    let computed_sub_scores = landing_scoring::compute_sub_scores(&scoring_input);
    let aggregate_master =
        landing_scoring::aggregate_master_score(&computed_sub_scores);
    let score_numeric = aggregate_master
        .map(|m| m as i32)
        .unwrap_or_else(|| touchdown_class.numeric());
    let score_label = aggregate_master
        .map(|m| aggregate_score_label(m))
        .unwrap_or_else(|| touchdown_class.label());
    let grade = letter_grade(score_numeric);

    // Compute fuel-efficiency once so the Landing tab doesn't have to
    // redo the formula. Same shape as build_pirep_fields.
    let actual_burn = match (stats.takeoff_fuel_kg, stats.landing_fuel_kg) {
        (Some(toff), Some(land)) if toff > land && toff > 0.0 && land >= 0.0 => Some(toff - land),
        _ => None,
    };
    let (fuel_diff_kg, fuel_pct) = match (stats.planned_burn_kg, actual_burn) {
        (Some(plan), Some(actual)) if plan > 0.0 => {
            let d = actual - plan;
            (Some(d), Some((d / plan) * 100.0))
        }
        _ => (None, None),
    };

    let runway_match = stats.runway_match.as_ref().map(|m| {
        // v0.8.0 — Source + NavRunway-Geometrie aus stats holen.
        // Bei OurAirports-Fallback bleiben die nav_*-Felder None.
        let source_wire = stats
            .runway_source
            .map(runway_source_wire)
            .map(|s| s.to_string());
        let nav_g = stats.runway_nav_geometry.as_ref();
        LandingRunwayMatch {
            airport_ident: m.airport_ident.clone(),
            runway_ident: m.runway_ident.clone(),
            surface: m.surface.clone(),
            length_ft: m.length_ft as f64,
            centerline_distance_m: m.centerline_distance_m,
            centerline_distance_abs_ft: m.centerline_distance_abs_ft,
            side: m.side.clone(),
            touchdown_distance_from_threshold_ft: m.touchdown_distance_from_threshold_ft,
            source: source_wire,
            nav_cycle: stats.runway_nav_cycle.clone(),
            true_course_deg: nav_g.map(|g| g.true_course),
            displaced_threshold_ft: nav_g.map(|g| g.displaced_threshold_ft),
            tch_expected_ft: nav_g.map(|g| g.tch_ft),
            glideslope_angle_deg: nav_g.map(|g| g.glideslope_angle),
        }
    });

    // v0.11.2 (Pilotenwunsch ViolonC): touchdown_profile umfasst jetzt
    // Pre-TD (5 s Snapshot-Buffer, schon in stats.touchdown_profile) PLUS
    // bis zu 3 s Post-TD aus stats.post_touchdown_buffer. Pilot sieht im
    // Touchdown-Chart damit auch die Sinkrate-Kurve direkt nach dem
    // Aufsetzen (Strut-Compression / Rebound). Vorher endete das Chart
    // hart am TD-Punkt, was den fachlichen Wunsch „wie schnell hat sich
    // die V/S nach TD beruhigt?" nicht beantwortete.
    //
    // Post-TD-Samples bekommen positive t_ms (TD-Edge ist t_ms = 0),
    // gleicher Berechnungs-Schema wie Pre-TD (siehe lib.rs:16539).
    // v0.12.8: Post-TD-Fenster fürs V/S-Profil auf 10 s erweitert
    // (Pilot-Wunsch). Filtert den `post_touchdown_buffer`; ist der
    // kürzer, werden eben nur die vorhandenen Sekunden gezeigt.
    let touchdown_profile = merge_touchdown_profile(
        &stats.touchdown_profile,
        &stats.post_touchdown_buffer,
        touchdown_at,
        POST_TD_PROFILE_MS,
    );

    // v0.7.1 Phase 1 (P1.1-D + P1.3-C): erweitert um t_ms, agl_ft,
    // is_scored_gate, is_flare. Werte aus dem ApproachBufferSample +
    // landing-scoring Crate Konstanten.
    //
    // Phase 1 nutzt agl_ft direkt (nicht HAT) — `arr_elevation_ft` ist
    // im FlightStats nicht persistiert sondern nur lokal in
    // compute_approach_stability_v2. Phase 3 kann das praezisieren wenn
    // noetig; fuer das Chart-Rendering ist agl_ft genau genug.
    use landing_scoring::gate::{
        STABILITY_GATE_FLARE_CUTOFF_MS, STABILITY_GATE_MAX_HEIGHT_FT,
        STABILITY_GATE_MIN_HEIGHT_FT,
    };
    let approach_samples: Vec<ApproachSample> = stats
        .approach_buffer
        .iter()
        .map(|s| {
            let height = s.agl_ft;
            let in_height_band = height > STABILITY_GATE_MIN_HEIGHT_FT
                && height <= STABILITY_GATE_MAX_HEIGHT_FT;
            let (t_ms, in_flare) = match stats.landing_at {
                Some(td_ts) => {
                    let dt_ms = (s.at - td_ts).num_milliseconds() as i32;
                    let ms_before_td = -dt_ms as i64;
                    let in_flare = ms_before_td >= 0
                        && ms_before_td < STABILITY_GATE_FLARE_CUTOFF_MS;
                    (Some(dt_ms), in_flare)
                }
                None => (None, false),
            };
            ApproachSample {
                vs_fpm: s.vs_fpm,
                bank_deg: s.bank_deg,
                t_ms,
                agl_ft: Some(height),
                is_scored_gate: Some(in_height_band && !in_flare),
                is_flare: Some(in_flare),
            }
        })
        .collect();
    // v0.7.1 Round-2 P2-Fix: gate_window VOR dem LandingRecord-Init
    // berechnen damit approach_samples noch verfügbar ist (wird unten
    // ins Record gemoved).
    let gate_window = build_storage_gate_window(&approach_samples);

    // v0.7.18 (B-012): Touchdown-Airport-Resolution einmal berechnen
    // und in den Record einsetzen.
    let td_resolution = resolve_touchdown_airport(
        stats.runway_match.as_ref(),
        stats.landing_lat,
        stats.landing_lon,
        &flight.arr_airport,
        &airport_lookup,
    );

    // v0.8.0: Pure-Function-Assessment einmal rechnen, in den Record
    // einsetzen.
    let assessed = assess_touchdown(stats);

    Some(LandingRecord {
        pirep_id: flight.pirep_id.clone(),
        touchdown_at,
        recorded_at: Utc::now(),
        flight_number: flight.flight_number.clone(),
        airline_icao: flight.airline_icao.clone(),
        dpt_airport: flight.dpt_airport.clone(),
        arr_airport: flight.arr_airport.clone(),
        // v0.7.18 (B-012): Touchdown-Airport-Resolution-Werte werden
        // ueber die `td_resolution`-Bindung weiter unten in der `..` -
        // Erweiterung gesetzt. Hier nur Hauptfelder; siehe unten.
        touchdown_airport: Some(td_resolution.icao.clone()),
        touchdown_airport_source: Some(
            td_resolution.source.as_wire_str().to_string(),
        ),
        touchdown_distance_to_destination_nm:
            td_resolution.distance_to_destination_nm,
        touchdown_nearest_distance_nm: td_resolution.nearest_distance_nm,
        aircraft_registration: Some(flight.planned_registration.clone())
            .filter(|s| !s.is_empty()),
        aircraft_icao: aircraft_icao.map(|s| s.to_string()).filter(|s| !s.is_empty()),
        aircraft_title: aircraft_title.map(|s| s.to_string()).filter(|s| !s.is_empty()),
        sim_kind: sim_kind_label.map(|s| s.to_string()),

        score_numeric,
        score_label: score_label.to_string(),
        grade_letter: grade.to_string(),

        landing_rate_fpm,
        landing_peak_vs_fpm: stats.landing_peak_vs_fpm,
        landing_g_force: stats.landing_g_force,
        landing_peak_g_force: stats.landing_peak_g_force,
        landing_pitch_deg: stats.landing_pitch_deg,
        // Bank at touchdown isn't a top-level FlightStats field; pull
        // the sample closest to t=0 from the touchdown profile.
        landing_bank_deg: stats
            .touchdown_profile
            .iter()
            .min_by_key(|p| p.t_ms.abs())
            .map(|p| p.bank_deg),
        landing_speed_kt: stats.landing_speed_kt,
        landing_heading_deg: stats.landing_heading_deg,
        landing_weight_kg: stats.landing_weight_kg,
        touchdown_sideslip_deg: stats.touchdown_sideslip_deg,
        bounce_count: stats.bounce_count,

        headwind_kt: stats.landing_headwind_kt,
        crosswind_kt: stats.landing_crosswind_kt,

        approach_vs_stddev_fpm: stats.approach_vs_stddev_fpm,
        approach_bank_stddev_deg: stats.approach_bank_stddev_deg,
        rollout_distance_m: stats.rollout_distance_m,

        planned_block_fuel_kg: stats.planned_block_fuel_kg,
        planned_burn_kg: stats.planned_burn_kg,
        planned_tow_kg: stats.planned_tow_kg,
        planned_ldw_kg: stats.planned_ldw_kg,
        planned_zfw_kg: stats.planned_zfw_kg,
        actual_trip_burn_kg: actual_burn,
        fuel_efficiency_kg_diff: fuel_diff_kg,
        fuel_efficiency_pct: fuel_pct,
        takeoff_weight_kg: stats.takeoff_weight_kg,
        takeoff_fuel_kg: stats.takeoff_fuel_kg,
        landing_fuel_kg: stats.landing_fuel_kg,
        block_fuel_kg: stats.block_fuel_kg,

        runway_match,
        touchdown_profile,
        approach_samples,

        // v0.5.43: Forensik aus dem 50-Hz-Sampler-Buffer (compute_landing_analysis)
        // wenn der Buffer-Dump erfolgreich war. Sonst alle None.
        vs_at_edge_fpm: ana_f32(&stats.landing_analysis, "vs_at_edge_fpm"),
        vs_smoothed_250ms_fpm: ana_f32(&stats.landing_analysis, "vs_smoothed_250ms_fpm"),
        vs_smoothed_500ms_fpm: ana_f32(&stats.landing_analysis, "vs_smoothed_500ms_fpm"),
        vs_smoothed_1000ms_fpm: ana_f32(&stats.landing_analysis, "vs_smoothed_1000ms_fpm"),
        vs_smoothed_1500ms_fpm: ana_f32(&stats.landing_analysis, "vs_smoothed_1500ms_fpm"),
        peak_g_post_500ms: ana_f32(&stats.landing_analysis, "peak_g_post_500ms"),
        peak_g_post_1000ms: ana_f32(&stats.landing_analysis, "peak_g_post_1000ms"),
        // v0.12.3 (LE4/LE7): gescorter G (EMA, sonst raw_fallback) + Methode
        // — die G-Force-Card headlinet diesen Wert.
        landing_scored_g_force: Some(score_g_for_stats(stats).scored_g),
        scored_g_method: Some(score_g_for_stats(stats).method.as_str().to_string()),
        // v0.7.17 (B-009): G-Force-Forensik
        g_at_edge: ana_f32(&stats.landing_analysis, "g_at_edge"),
        g_smoothed_250ms_post: ana_f32(&stats.landing_analysis, "g_smoothed_250ms_post"),
        g_median_post_500ms: ana_f32(&stats.landing_analysis, "g_median_post_500ms"),
        g_p95_post_500ms: ana_f32(&stats.landing_analysis, "g_p95_post_500ms"),
        max_gear_force_n: ana_f32(&stats.landing_analysis, "max_gear_force_n"),
        peak_vs_pre_flare_fpm: ana_f32(&stats.landing_analysis, "peak_vs_pre_flare_fpm"),
        vs_at_flare_end_fpm: ana_f32(&stats.landing_analysis, "vs_at_flare_end_fpm"),
        flare_reduction_fpm: ana_f32(&stats.landing_analysis, "flare_reduction_fpm"),
        flare_dvs_dt_fpm_per_sec: ana_f32(&stats.landing_analysis, "flare_dvs_dt_fpm_per_sec"),
        flare_quality_score: ana_i32(&stats.landing_analysis, "flare_quality_score"),
        flare_detected: ana_bool(&stats.landing_analysis, "flare_detected"),
        forensic_sample_count: ana_u32(&stats.landing_analysis, "sample_count"),

        // ─── v0.8.3 (#8) — Forensische Bounce-Counts ins LandingRecord ───
        // Damit das UI „Light bounce X ft erkannt (score-frei)" zeigen
        // kann auch bei 5-14 ft Hopsern, die per Spec score-frei sind.
        // Reported 2026-05-14 Adrian: Touchdown #167 hatte
        // bounce_max_agl_ft=14.05, aber UI zeigte bounce_count=0 →
        // Pilot dachte "nicht erkannt".
        bounce_max_agl_ft: ana_f32(&stats.landing_analysis, "bounce_max_agl_ft"),
        forensic_bounce_count: ana_u32(&stats.landing_analysis, "forensic_bounce_count")
            .map(|n| n.min(u8::MAX as u32) as u8),
        scored_bounce_count: ana_u32(&stats.landing_analysis, "scored_bounce_count")
            .map(|n| n.min(u8::MAX as u32) as u8),

        // ─── v0.7.1 Felder (Spec docs/spec/v0.7.1-landing-ux-fairness.md §5) ──
        // Phase 1 = backbone: Felder durchreichen, kein Pilot-sichtbares
        // Verhalten geaendert. Phase 2/3 konsumieren sie.
        ux_version: 1, // v0.7.1+ marker — UI nutzt sub_scores statt LegacyPirepNotice
        forensics_version: touchdown_v2::FORENSICS_VERSION,
        landing_confidence: stats.landing_confidence.clone(),
        landing_source: stats.landing_source.clone(),
        // F7 (P2.1-A): bestehende Backend-Felder exponieren — keine
        // neue Berechnung. Phase 3 wird sub_stability Voting umstellen.
        approach_vs_jerk_fpm: stats.approach_vs_jerk_fpm,
        approach_ias_stddev_kt: stats.approach_ias_stddev_kt,
        approach_stable_config: stats.approach_stable_config,
        // approach_excessive_sink ist im FlightStats `bool` (nie None),
        // im Storage-Schema `Option<bool>` fuer backward-compat — wir
        // wrappen Some() unconditional.
        approach_excessive_sink: Some(stats.approach_excessive_sink),
        // v0.7.1 Round-2 P2-Fix: gate_window oben berechnet aus den
        // approach_samples — UI-Tooltip kann jetzt die echten
        // Boundaries zeigen statt nur die Crate-Konstanten.
        gate_window,
        // v0.11.0-dev: 3 weitere Stability-Werte ins Storage durchreichen.
        // Werden vom Stability-v2-Compute schon gefuellt (lib.rs:16699-16708)
        // und im PIREP/MQTT mitgeschickt — Storage-LandingRecord hatte sie
        // bisher nicht, die neue ApproachStabilityCard im Pilot-Client
        // braucht sie aber. Alte landing_history.json bleibt via
        // serde(default) lesbar.
        approach_vs_deviation_fpm: stats.approach_vs_deviation_fpm,
        approach_max_vs_deviation_below_500_fpm: stats
            .approach_max_vs_deviation_below_500_fpm,
        approach_used_hat: Some(stats.approach_used_hat),
        // P1.5 + Phase 2 F1/F2/F3 + P1.3-Fix: sub_scores wurden oben
        // schon berechnet damit aggregate_master_score → score_numeric
        // gehen kann. Hier nur noch durchreichen, NICHT erneut rechnen.
        sub_scores: computed_sub_scores,
        // v0.7.6 P1-3: Runway-Geometry-Trust ins LandingRecord. Damit
        // der Pilot-Client (LandingPanel.tsx) die TD-Zone und Float-
        // Distance bei untrusted geometry ausblenden kann — gleiche
        // Logik wie Web-Dashboard. Spec docs/spec/v0.7.6-landing-
        // payload-consistency.md §3 P1-3.
        runway_geometry_trusted: {
            let (trusted, _) = runway_geometry_trust_check(
                stats.runway_match.as_ref().map(|m| m.airport_ident.as_str()),
                effective_arr_icao,
                stats.divert_hint.as_ref().and_then(|h| h.actual_icao.as_deref()),
                stats.runway_match.as_ref().map(|m| m.centerline_distance_m as f32),
                stats.landing_float_distance_m,
            );
            Some(trusted)
        },
        runway_geometry_reason: {
            let (_, reason) = runway_geometry_trust_check(
                stats.runway_match.as_ref().map(|m| m.airport_ident.as_str()),
                effective_arr_icao,
                stats.divert_hint.as_ref().and_then(|h| h.actual_icao.as_deref()),
                stats.runway_match.as_ref().map(|m| m.centerline_distance_m as f32),
                stats.landing_float_distance_m,
            );
            reason.map(String::from)
        },
        // v0.7.19 GAF-707 Accident-Detection. Felder kommen aus dem
        // gelatchten FlightStats — gesetzt entweder durch Sim-Event-
        // Pfad (mid-air) oder durch Heuristik am Touchdown-Edge.
        accident: stats.accident_detected,
        accident_kind: stats.accident_kind.clone(),
        accident_confidence: stats.accident_confidence.clone(),
        accident_reasons: stats.accident_reasons.clone(),
        accident_at: stats.accident_at,

        // v0.8.0 VPS-Navdata + Runway-Awareness — Pure-Function-
        // Assessment-Werte. Wenn der runway_match aus Navigraph kam
        // sind ALLE Felder gefüllt; bei OurAirports-Fallback ist
        // TDZ/Aim/td_distance trotzdem gesetzt (length + td_distance
        // sind quell-agnostisch), nur DDS bleibt None weil
        // displaced_threshold_ft nicht in OurAirports vorkommt.
        // TCH bleibt für jetzt None — braucht AGL@threshold-crossing
        // Scan, kommt in Folge-Slice.
        td_distance_from_threshold_m: assessed.td_distance_from_threshold_m,
        td_in_tdz: assessed.tdz.map(|t| t.in_tdz),
        td_third: assessed.tdz.map(|t| t.third),
        td_tdz_length_m: assessed.tdz.map(|t| t.tdz_length_m),
        aim_delta_m: assessed.aim.as_ref().map(|a| a.delta_m),
        aim_class: assessed
            .aim
            .as_ref()
            .map(|a| aim_class_wire(a.class).to_string()),
        aim_point_m: assessed.aim.as_ref().map(|a| a.aim_point_m),
        tch_actual_ft: assessed.tch.as_ref().map(|t| t.actual_ft),
        tch_delta_ft: assessed.tch.as_ref().map(|t| t.delta_ft),
        tch_class: assessed
            .tch
            .as_ref()
            .map(|t| tch_class_wire(t.class).to_string()),
        pre_displaced_threshold: assessed.dds.map(|d| d.in_pre_threshold_zone),
        // v0.10.0 (#runway-utilization-score): markiert dass dieses
        // Record mit dem LDA-basierten Bahn-Auslastungs-Score gebaut
        // wurde. UI (LandingPanel.tsx) gated darauf das Rendering der
        // neuen `extra`-Lines + erweiterten Rationale-/Warning-Keys.
        // v0.16.21: bump 3→4 — MSFS touchdown V/S SimVar-lag corrected.
        score_algorithm_version: Some(4),
    })
}

/// Persist a landing record from a flight that just filed its PIREP.
/// Best-effort — failure is logged and ignored so the file path
/// doesn't fail because the history disk write blew up.
fn record_landing_for_filed_flight(
    app: &AppHandle,
    flight: &ActiveFlight,
    stats: &mut FlightStats,
    // v0.15.x: tatsächlicher Landeflughafen (Divert-aware) — siehe
    // build_landing_record. Für Nicht-Diverts == flight.arr_airport.
    effective_arr_icao: &str,
) {
    // v0.16.24: finalize-with-best — re-correlate the runway against the
    // (now-hopefully-warm) navdata cache and write the upgraded fields back
    // BEFORE building the record, so build_landing_record + all downstream
    // consumers (assess_touchdown, the TouchdownPayload, the score inputs)
    // see one consistent set. NON-RACY: this is a synchronous read of the
    // current cache contents — no async re-correlation races the filing.
    // ON-PLAN INVARIANT: when the touchdown match was already Navigraph
    // (non-divert), `finalize_runway_correlation` returns the stamped values
    // verbatim, so this write-back is a byte-identical no-op.
    //
    // v0.16.24 (QS-6): the PIREP score/body callers (`flight_end`,
    // `flight_end_manual`) now run `apply_finalized_runway_correlation` BEFORE
    // building the body, so by the time we get here the upgrade has usually
    // already happened — this second call is then the idempotent no-op
    // described above. Kept so `record_landing_for_filed_flight` stays correct
    // standalone (the LandingRecord is finalized regardless of caller).
    apply_finalized_runway_correlation(flight, stats);

    let snapshot = current_snapshot(app);
    let sim_kind_label = read_sim_config(app).kind;
    let sim_label = match sim_kind_label {
        SimKind::Off => None,
        SimKind::Msfs2020 | SimKind::Msfs2024 => Some("MSFS"),
        SimKind::XPlane11 | SimKind::XPlane12 => Some("X-PLANE"),
    };
    // v0.7.17 (B-015): Snapshot kann beim Filing None sein (Sim
    // disconnected, X-Plane Web API aus, etc.). Vorher: aircraft_icao
    // fiel dann ebenfalls None → sub_rollout-Score nutzte konservative
    // Light-GA-Schwellen → A320 mit 1096 m Rollout bekam fälschlich
    // 80 PTS (good_stop) statt 100 PTS (excellent_stop). Fallback auf
    // Bid-Wert (`flight.aircraft_icao`) der beim Flugstart aus dem
    // phpVMS-Bid persistiert wurde und über die gesamte Flight-Dauer
    // stabil bleibt. Webapp benutzt denselben Wert → konsistent.
    let bid_icao = flight.aircraft_icao.trim();
    let bid_icao_opt: Option<&str> = if bid_icao.is_empty() {
        None
    } else {
        Some(bid_icao)
    };
    let aircraft_icao = snapshot
        .as_ref()
        .and_then(|s| s.aircraft_icao.as_deref())
        .or(bid_icao_opt);
    let aircraft_title = snapshot.as_ref().and_then(|s| s.aircraft_title.as_deref());

    // v0.7.18 (B-012): airport_lookup-Closure aus dem AppState.airports-Cache.
    let airport_lookup_data: std::collections::HashMap<String, (f64, f64)> = {
        let app_state = app.state::<AppState>();
        let guard = app_state.airports.lock().expect("airports lock");
        guard
            .iter()
            .filter_map(|(k, v)| match (v.lat, v.lon) {
                (Some(la), Some(lo)) => Some((k.clone(), (la, lo))),
                _ => None,
            })
            .collect()
    };
    let airport_lookup =
        |icao: &str| airport_lookup_data.get(&icao.to_uppercase()).copied();

    let Some(record) = build_landing_record(
        flight,
        stats,
        sim_label,
        aircraft_icao,
        aircraft_title,
        effective_arr_icao,
        airport_lookup,
    ) else {
        tracing::debug!(
            pirep_id = %flight.pirep_id,
            "no touchdown captured — skipping landing-history record"
        );
        return;
    };
    let Some(store) = open_landing_store(app) else {
        tracing::warn!("landing store unavailable — landing not recorded");
        return;
    };
    if let Err(e) = store.upsert(record) {
        tracing::warn!(error = ?e, "could not persist landing record");
    } else {
        tracing::info!(pirep_id = %flight.pirep_id, "landing record persisted");
    }
}

/// Best-effort append to the flight log. Swallows errors so a missing
/// disk doesn't surface as a UI failure — the log is purely for replay
/// and post-flight analysis.
fn record_event(app: &AppHandle, pirep_id: &str, event: &FlightLogEvent) {
    if let Some(rec) = open_flight_recorder(app, pirep_id) {
        if let Err(e) = rec.append(event) {
            tracing::warn!(error = ?e, "could not append to flight log");
        }
    }
}

// v0.6.0: drain_position_queue ist entfallen — der phpVMS-Worker macht
// den Drain direkt aus der Memory-Outbox. Die persistente Queue
// (`position_queue.json`) wird nur noch beim Worker-Start eingelesen
// (für Recovery nach App-Restart) und beim Worker-Stop / Backlog>500
// rausgeschrieben. Kein in-Tick-Drain-Pattern mehr — strukturell
// unmöglich dass irgendwas den Streamer-Tick blockiert.

/// v0.6.0 — phpVMS-Position-Sync-Worker (eigener Background-Task).
///
/// **Architektur-Änderung:** Vorher war phpVMS-POST direkt im
/// Streamer-Tick (mit Critical-Window-Pause-Pattern und drain-Logik).
/// Das war der Ursprung der Bug-Klasse „Streamer hängt auf phpVMS"
/// (Pilot-Reports v0.5.45-v0.5.51).
///
/// Jetzt: separater eigenständiger Worker mit phase-aware POST-Cadence:
///
///   1. **Init-Load (einmalig beim Spawn):** items aus `position_queue.json`
///      die zur aktuellen `pirep_id` gehoeren in die Memory-Outbox laden
///      (Recovery nach App-Restart).
///   2. **Loop alle TICK=1s** (responsive Stop-Check + Backoff-Aufloesung):
///      a. Stop-Check; bei `flight.stop` final persist_outbox + break
///      b. Backoff-Check: wenn `backoff_until > now`, skip
///      c. **Phase-aware Throttle:** `position_interval(phase)` liefert
///         4-30s (Cruise=30s, Pushback=4s, Approach=8s usw). Nur posten
///         wenn `last_post_at.elapsed() >= interval`.
///      d. Bis `MAX_BATCH=50` items aus der Outbox draining
///      e. EIN Batch-POST an `client.post_positions(pirep_id, &batch)`
///         mit `BATCH_TIMEOUT=15s`
///   3. **Bei Erfolg:** `last_position_at` + `queued_position_count`
///      updaten, Backoff-Counter resetten, `last_post_at = now`.
///   4. **Bei 404:** PIREP serverseitig weg, `handle_remote_cancellation`
///      + Worker terminiert sauber.
///   5. **Bei anderem Fehler / Timeout:** kompletter Batch zurueck in die
///      Outbox VORN (chronologische Reihenfolge erhalten via `push_front`
///      in reverse-iter); `consecutive_failures += 1`.
///   6. **Persist-Trigger:** alle 30s (`PERSIST_INTERVAL`) wenn Outbox
///      nicht leer ist, `persist_outbox()` schreibt aktuellen Stand in
///      `position_queue.json` (read-modify-write, bewahrt items anderer
///      pireps). Begrenzt Crash-Verlust auf max ~30s. Im stop-branch
///      wird IMMER persistiert via `persist_outbox_clearing()` (atomar
///      clear+snapshot unter einem Lock-Hold).
///   7. **Exponential Backoff:** bei `consecutive_failures > 0` setzen wir
///      `backoff_until = now + min(60, 3 << (n-1))` Sekunden — verhindert
///      dass wir bei toter Verbindung jede TICK gegen die Wand laufen.
///      Nicht-blocking (loop-top check) damit Stop-Check responsive bleibt.
///
/// **Streamer-Tick MUSS NIE warten** — der pusht nur in die Outbox-
/// VecDeque (= ein schneller `std::sync::Mutex`-Push, ~1µs, kein
/// `.await` involviert).
///
/// **Persistenz:** beim Stop schreibt der Worker den finalen Outbox-
/// Stand in `position_queue.json` (read-modify-write). Beim naechsten
/// App-Start wird das vom neuen Worker im Init-Load (Schritt 1) wieder
/// reingeladen. Datenverlust nur wenn `phpvms_worker_spawned` panics —
/// dann sind die in-memory items weg, aber JSONL-Forensik ist komplett
/// und der Forensik-Upload nach PIREP-Filing bringt sie zurueck.
fn spawn_phpvms_position_worker(
    app: AppHandle,
    flight: Arc<ActiveFlight>,
    client: Client,
) {
    // Guard gegen Doppel-Spawn (mehrere flight_resume etc.)
    if flight.phpvms_worker_spawned.swap(true, Ordering::SeqCst) {
        return;
    }
    tauri::async_runtime::spawn(async move {
        // Per-Batch-Timeout: 50 Items + retries vom HTTP-Client koennen
        // schon mal 10s dauern. 15s ist grosszuegig genug, ohne den Tick
        // bei toter Verbindung minutenlang zu blockieren.
        const BATCH_TIMEOUT: Duration = Duration::from_secs(15);
        // TICK ist die Loop-Frequenz (Stop-Check + Outbox-Probe). Die
        // ECHTE POST-Cadence kommt aus position_interval(phase) und kann
        // bis 30s im Cruise sein — wir tracken last_post_at und posten
        // nur wenn das Phase-Intervall verstrichen ist. Kurzer TICK
        // braucht damit der stop-Check responsive bleibt + Backoff bei
        // Failure prazise zaehlt.
        const TICK: Duration = Duration::from_secs(1);
        const MAX_BATCH: usize = 50;
        // Exponentiel-Backoff bei consecutive failures: 3s, 6s, 12s,
        // 24s, 48s, gecapped bei 60s. Reset bei erstem Erfolg.
        let mut consecutive_failures: u32 = 0;
        // v0.6.1 — last successful POST timestamp fuer phase-aware
        // throttle (siehe position_interval). None = noch nie gepostet
        // (initial Position raus so schnell wie moeglich).
        let mut last_post_at: Option<std::time::Instant> = None;
        // Backoff-deadline: bei consecutive failures wird hier ein
        // future timestamp gesetzt; loop continuiert bis Instant::now()
        // den ueberschreitet. Verhindert dass wir bei toter Verbindung
        // jede TICK gegen die Wand laufen.
        let mut backoff_until: Option<std::time::Instant> = None;
        tracing::info!(pirep_id = %flight.pirep_id, "phpvms-position-worker started");
        // Initial: alte persistente Queue laden falls vorhanden.
        // Errors NICHT mehr silent swallowen — wenn die Datei korrupt
        // ist, soll der Pilot das im Log sehen.
        if let Some(q) = open_position_queue(&app) {
            match q.read_all() {
                Ok(items) if !items.is_empty() => {
                    let mut outbox = flight.position_outbox.lock()
                        .expect("position_outbox lock");
                    let mut recovered = 0usize;
                    let mut deserialize_failed = 0usize;
                    for item in items {
                        if item.pirep_id == flight.pirep_id {
                            match serde_json::from_value::<api_client::PositionEntry>(item.position) {
                                Ok(p) => {
                                    outbox.push_back(p);
                                    recovered += 1;
                                }
                                Err(_) => deserialize_failed += 1,
                            }
                        }
                    }
                    tracing::info!(
                        pirep_id = %flight.pirep_id,
                        recovered,
                        deserialize_failed,
                        "loaded persisted positions into outbox on worker-start"
                    );
                }
                Ok(_) => {} // empty queue, normal
                Err(e) => {
                    tracing::warn!(
                        pirep_id = %flight.pirep_id,
                        error = ?e,
                        "queue.json read failed during worker init — \
                         persisted positions for this PIREP are lost"
                    );
                }
            }
        }
        // v0.6.1 — Persist-Strategie: Abwägung zwischen Crash-Recovery
        // (oft persistieren = wenig Datenverlust bei Hardkill) vs. Disk-IO
        // (selten persistieren = weniger File-Rewrites).
        //
        // Strategie: alle PERSIST_INTERVAL=30s wenn Outbox NICHT leer ist.
        // Begrenzt Crash-Verlust auf max 30s an positions, unabhängig
        // vom Backlog. Bei großem Backlog (>500) ist das die gleiche
        // 30s-Cadence — ein zusätzlicher „Backlog-Schutz" wäre redundant
        // (würde die Cooldown verletzen oder dieselbe 30s-Cadence haben).
        //
        // Beim Stop wird IMMER persistiert (final state, ohne Cooldown,
        // via persist_outbox_clearing das atomar clear+snapshot macht).
        //
        // Worst-case Datenverlust für phpVMS Live-Map bei Hardkill:
        // ~30s an positions (= 1-10 Items je nach Phase). JSONL-SoT bleibt
        // unabhängig komplett (per-event-write).
        let mut last_persist_at: Option<std::time::Instant> = None;
        const PERSIST_INTERVAL: Duration = Duration::from_secs(30);
        loop {
            tokio::time::sleep(TICK).await;
            if flight.stop.load(Ordering::Relaxed) {
                // v0.6.1 KRITISCHER FIX — Orphan-Persist-Race:
                // Stop-Pfade machen `outbox.clear() -> stop=true`. Zwischen
                // diesen zwei Aufrufen kann der Streamer-Tick noch 1+ Items
                // in die Outbox geschoben haben (Race-Window klein aber real).
                //
                // Wir benutzen hier `persist_outbox_clearing` welches clear+
                // snapshot ATOMAR unter dem GLEICHEN Lock-Hold macht — kein
                // Streamer-Push zwischen clear und snapshot moeglich.
                //
                // Semantik in allen 5 stop-Paths:
                //   - flight_cancel/forget: User wollte explizit nichts mehr
                //   - flight_end/end_with_overrides: PIREP ist gefiled, JSONL
                //     hat alle Position-Events fuer Forensik-Upload
                //   - handle_remote_cancellation: PIREP serverseitig weg, POST
                //     wuerde eh 404 zurueckgeben
                // → in keinem Fall wollen wir Items aus dem aktuellen Pirep
                //   nach dem Stop noch persistieren.
                persist_outbox_clearing(&app, &flight);
                tracing::info!(pirep_id = %flight.pirep_id, "phpvms-position-worker stopped");
                break;
            }
            // Backoff-Check: bei consecutive failures haben wir ein
            // backoff_until in der Zukunft gesetzt — diese Loop-Iter
            // skipped bis der Zeitpunkt erreicht ist.
            if let Some(until) = backoff_until {
                if std::time::Instant::now() < until {
                    continue;
                }
                backoff_until = None;
            }
            // Aktuelle Phase fuer phase-aware Cadence ziehen.
            let phase = {
                let stats = flight.stats.lock().expect("flight stats");
                stats.phase
            };
            let interval = position_interval(phase);
            // Phase-aware Throttle: nur posten wenn `interval` seit
            // letztem ERFOLG verstrichen ist. Im Cruise = 30s, im
            // Pushback = 4s, im Approach = 8s (siehe position_interval).
            // None = noch nie erfolgreich gepostet -> sofort versuchen.
            let due = match last_post_at {
                None => true,
                Some(t) => t.elapsed() >= interval,
            };
            if !due {
                continue;
            }
            // Bis MAX_BATCH Items aus der Outbox ziehen — std::sync::Mutex,
            // synchroner Block, kein await innen.
            let batch: Vec<api_client::PositionEntry> = {
                let mut outbox = flight.position_outbox.lock()
                    .expect("position_outbox lock");
                let n = outbox.len().min(MAX_BATCH);
                outbox.drain(..n).collect()
            };
            if batch.is_empty() {
                continue;
            }
            tracing::debug!(
                pirep_id = %flight.pirep_id,
                batch_size = batch.len(),
                phase = ?phase,
                interval_secs = interval.as_secs(),
                "phpvms-worker batch POST"
            );
            // ECHT BATCHED POST: ein HTTP-Call mit allen N positionen
            // im JSON-Body. War vorher (v0.6.0 initial) ein Loop mit
            // einem POST pro Item — bei 50 items × 50ms RTT = 2.5s pro
            // Drain statt einer 70ms-Anfrage. Der phpVMS-Endpoint
            // /acars/position akzeptiert positions: [...] als Array.
            let post_fut = client.post_positions(&flight.pirep_id, &batch);
            match tokio::time::timeout(BATCH_TIMEOUT, post_fut).await {
                Ok(Ok(())) => {
                    // Success: queued_count = 0 (NICHT outbox.len()!).
                    //
                    // **WICHTIG zur Semantik:** zwischen drain und jetzt
                    // kann der Streamer was in die Outbox gepusht haben.
                    // outbox.len() waere dann > 0. Das wuerde aber heissen
                    // dass der Indikator "queued (offline)" zeigt obwohl
                    // gerade ein erfolgreicher POST gelaufen ist — exakt
                    // der UX-Bug aus dem Pilot-Report 2026-05-10.
                    //
                    // v0.5.x-Semantik war: queued_count = "stuck items"
                    // (failed POSTs in der file-queue). Im Cruise = 0,
                    // Indikator zeigt "live". Genau das wollen wir.
                    //
                    // Items die der Streamer zwischen drain und jetzt
                    // gepusht hat werden im NAECHSTEN POST mit raus.
                    {
                        let mut stats = flight.stats.lock().expect("flight stats");
                        stats.last_position_at = Some(Utc::now());
                        stats.queued_position_count = 0;
                    }
                    consecutive_failures = 0;
                    last_post_at = Some(std::time::Instant::now());
                    flight.connection_state.store(CONN_STATE_LIVE, Ordering::Relaxed);
                }
                Ok(Err(ApiError::NotFound)) => {
                    // PIREP serverseitig geloescht — terminiert sauber.
                    handle_remote_cancellation(
                        &app,
                        &flight,
                        "phpvms-worker POST",
                    );
                    flight.phpvms_worker_spawned.store(false, Ordering::SeqCst);
                    return;
                }
                Ok(Err(e @ ApiError::Unauthenticated)) | Ok(Err(e @ ApiError::Forbidden)) => {
                    // v0.7.17 (B-007): phpVMS hat 401/403 zurueckgegeben.
                    // Typische Ursachen:
                    //   * VA-Admin hat den Pilot-Account gesperrt
                    //     (suspended) oder inaktiv gesetzt
                    //   * API-Key wurde server-side rotated/revoked
                    //   * VA-Permissions wurden geaendert und der Pilot
                    //     hat den ACARS-Endpunkt nicht mehr
                    //
                    // Vor v0.7.17 wurde der Batch endlos requeued —
                    // phpVMS bekam 30 s Takt Spam von einem Account der
                    // gar nicht mehr posten darf. Jetzt: Outbox leeren,
                    // Connection-State BLOCKED, Worker terminieren,
                    // klarer Activity-Log-Eintrag. Pilot kontaktiert
                    // VA-Admin und re-logged-in nach Klaerung.
                    let http_code = match e {
                        ApiError::Unauthenticated => 401,
                        _ => 403,
                    };
                    // Schmeisse den Batch und die noch in der Outbox
                    // wartenden Items weg — retry sinnlos.
                    {
                        let mut outbox = flight.position_outbox.lock()
                            .expect("position_outbox lock");
                        outbox.clear();
                    }
                    {
                        let mut stats = flight.stats.lock().expect("flight stats");
                        stats.queued_position_count = 0;
                    }
                    flight.connection_state.store(CONN_STATE_BLOCKED, Ordering::Relaxed);
                    tracing::error!(
                        pirep_id = %flight.pirep_id,
                        http_code = http_code,
                        batch_size = batch.len(),
                        "phpvms-worker terminating: account blocked (401/403). \
                         outbox cleared, no more retries"
                    );
                    log_activity_handle(
                        &app,
                        ActivityLevel::Error,
                        "phpVMS lehnt deine Anfragen ab — Account gesperrt oder inaktiv",
                        Some(format!(
                            "HTTP {http_code}: VA-Admin kontaktieren und nach Freigabe neu einloggen. \
                             Position-Streaming wurde gestoppt."
                        )),
                    );
                    flight.phpvms_worker_spawned.store(false, Ordering::SeqCst);
                    return;
                }
                Ok(Err(e)) => {
                    // Andere Failure — KOMPLETTER batch zurueck in die outbox.
                    // queued_count = outbox.len() (nach requeue) damit der
                    // Indikator den ECHTEN backlog zeigt = stuck items.
                    tracing::warn!(
                        pirep_id = %flight.pirep_id,
                        error = %e,
                        batch_size = batch.len(),
                        "phpvms-worker batch POST failed; queueing entire batch back"
                    );
                    requeue_batch(&flight, batch);
                    let outbox_len = flight.position_outbox.lock()
                        .expect("position_outbox lock").len();
                    {
                        let mut stats = flight.stats.lock().expect("flight stats");
                        stats.queued_position_count = outbox_len as u32;
                    }
                    consecutive_failures = consecutive_failures.saturating_add(1);
                    flight.connection_state.store(CONN_STATE_FAILING, Ordering::Relaxed);
                }
                Err(_timeout) => {
                    tracing::warn!(
                        pirep_id = %flight.pirep_id,
                        batch_size = batch.len(),
                        "phpvms-worker batch POST timed out (15s); queueing back"
                    );
                    requeue_batch(&flight, batch);
                    let outbox_len = flight.position_outbox.lock()
                        .expect("position_outbox lock").len();
                    {
                        let mut stats = flight.stats.lock().expect("flight stats");
                        stats.queued_position_count = outbox_len as u32;
                    }
                    consecutive_failures = consecutive_failures.saturating_add(1);
                    flight.connection_state.store(CONN_STATE_FAILING, Ordering::Relaxed);
                }
            }
            // Outbox-Groesse fuer Persist-Check (kein queued_count-Update mehr
            // hier — das wurde im match-arm korrekt mit der richtigen Semantik
            // gesetzt. Vorher war hier ein unconditional update das den
            // success-arm-0-Wert mit dem Race-Condition-Wert ueberschrieb).
            let total_after = flight.position_outbox.lock()
                .expect("position_outbox lock").len();
            // Persist-Trigger: alle PERSIST_INTERVAL (30s) wenn die Outbox
            // nicht leer ist. Das begrenzt den Crash-Verlust für phpVMS
            // Live-Map auf max ~30s an Positions (= 1-10 Items je nach
            // Phase), unabhängig davon wie groß der Backlog ist.
            //
            // Wichtig: NICHT persistieren wenn outbox leer ist — sonst
            // schreiben wir bei jedem Cooldown-Ablauf sinnlos eine leere
            // file (im Cruise mit gutem Netz wäre das ständig der Fall:
            // Worker drained alle Items → outbox leer → Cooldown abgelaufen
            // → wir würden alle 30s eine leere persist machen).
            //
            // Im Stop-Branch wird via persist_outbox_clearing IMMER
            // geschrieben damit die finale leere file rauskommt + Items
            // anderer pireps erhalten bleiben.
            //
            // Worst-case Datenverlust bei Hardkill: ~30s an positions.
            // JSONL-SoT bleibt komplett (per-event-write).
            if total_after > 0 {
                let cooldown_ok = match last_persist_at {
                    None => true,
                    Some(t) => t.elapsed() >= PERSIST_INTERVAL,
                };
                if cooldown_ok {
                    persist_outbox(&app, &flight);
                    last_persist_at = Some(std::time::Instant::now());
                }
            }
            // Exponentieller Backoff bei consecutive failures (3s, 6s,
            // 12s, 24s, 48s, gecapped 60s). Statt blocking sleep setzen
            // wir backoff_until und der naechste Loop-Top-Check skipped
            // bis dahin — so bleibt der stop-Check responsive (1s Tick).
            if consecutive_failures > 0 {
                let extra_secs = (3u64 << (consecutive_failures - 1).min(5)).min(60);
                backoff_until = Some(
                    std::time::Instant::now() + Duration::from_secs(extra_secs)
                );
                tracing::debug!(
                    pirep_id = %flight.pirep_id,
                    consecutive_failures,
                    extra_sleep_secs = extra_secs,
                    "phpvms-worker backoff after failures"
                );
            }
        }
    });
}

/// v0.6.0 — Helper: failed batch zurueck in die Outbox VORN, mit
/// erhaltener chronologischer Reihenfolge. Wird vom phpVMS-Worker
/// aufgerufen wenn ein Batch-POST scheitert.
///
/// **Wichtig:** `batch.into_iter().rev() + push_front` ergibt die
/// originale Reihenfolge: batch=[a,b,c] -> push_front c, b, a ->
/// outbox = [a, b, c, ...].
fn requeue_batch(flight: &ActiveFlight, batch: Vec<api_client::PositionEntry>) {
    let mut outbox = flight.position_outbox.lock()
        .expect("position_outbox lock");
    for position in batch.into_iter().rev() {
        outbox.push_front(position);
    }
}

/// v0.6.0 — Helper: persistiert die Outbox in `position_queue.json`.
/// Wird beim Worker-Stop und bei großem Outbox-Backlog aufgerufen.
///
/// **Read-modify-write Pattern:** queue.json kann items von anderen
/// pirep_ids enthalten (z.B. nach App-Crash mid-flight eines prior
/// flights, der noch nicht aufgeräumt wurde). Wir lesen alles, filtern
/// die items des aktuellen pirep raus (= „outbox ist die einzige
/// Wahrheit für diesen pirep"), hängen die aktuelle outbox-snapshot
/// dran, und schreiben das kombinierte Set zurück.
///
/// **Empty-outbox-Behandlung:** WICHTIG — wenn die outbox leer ist,
/// MÜSSEN wir trotzdem die queue.json updaten (= aktuelle pirep-items
/// rauslöschen), sonst werden ältere persistierte items beim nächsten
/// App-Start re-loaded und re-posted (Duplikate auf der phpVMS Karte).
fn persist_outbox(app: &AppHandle, flight: &ActiveFlight) {
    persist_outbox_inner(app, flight, false);
}

/// v0.6.1 — Variante von persist_outbox die VOR dem Snapshot die Outbox
/// atomar leert. Wird vom Worker-Stop-Branch aufgerufen damit es keinen
/// Race gibt zwischen `outbox.clear()` und `persist_outbox()`-Lock-
/// Reacquire (Streamer könnte zwischendurch noch was pushen → orphan).
/// Mit `clear_first=true` passiert clear+snapshot unter EINEM Lock-Hold.
fn persist_outbox_clearing(app: &AppHandle, flight: &ActiveFlight) {
    persist_outbox_inner(app, flight, true);
}

fn persist_outbox_inner(app: &AppHandle, flight: &ActiveFlight, clear_first: bool) {
    let Some(queue) = open_position_queue(app) else {
        return;
    };
    // Aktuelle Outbox in Vec snapshotten — Lock so kurz wie möglich.
    // Bei clear_first=true: erst clear, DANN snapshot — beides unter
    // demselben Lock-Hold. Damit kann der Streamer zwischendurch nichts
    // pushen das danach als orphan in queue.json landet.
    // Defensive: wenn serde_json::to_value tatsaechlich mal scheitern
    // sollte (PositionEntry derives Serialize, also extrem unwahrscheinlich),
    // skippen wir den Eintrag und loggen — besser als ein null-Item das
    // beim Re-Load deserialize-Failure produziert.
    let outbox_items: Vec<QueuedPosition> = {
        let mut outbox = flight.position_outbox.lock().expect("position_outbox lock");
        if clear_first {
            outbox.clear();
        }
        outbox.iter().filter_map(|p| {
            match serde_json::to_value(p) {
                Ok(v) => Some(QueuedPosition {
                    pirep_id: flight.pirep_id.clone(),
                    position: v,
                }),
                Err(e) => {
                    tracing::error!(
                        pirep_id = %flight.pirep_id,
                        error = ?e,
                        "could not serialize PositionEntry for persist_outbox; skipping"
                    );
                    None
                }
            }
        }).collect()
    };
    // Bestehende queue.json lesen, items des aktuellen pirep
    // ausfiltern (= überschreiben), Items anderer pireps behalten.
    let existing_other_pirep: Vec<QueuedPosition> = match queue.read_all() {
        Ok(items) => items.into_iter()
            .filter(|i| i.pirep_id != flight.pirep_id)
            .collect(),
        Err(e) => {
            tracing::warn!(error = ?e, "could not read existing queue; will overwrite");
            Vec::new()
        }
    };
    let outbox_count = outbox_items.len();
    let other_count = existing_other_pirep.len();
    let mut combined = existing_other_pirep;
    combined.extend(outbox_items);
    if let Err(e) = queue.replace(&combined) {
        tracing::warn!(error = ?e, "could not persist outbox to position_queue.json");
    } else {
        tracing::info!(
            pirep_id = %flight.pirep_id,
            outbox_persisted = outbox_count,
            kept_from_other_pireps = other_count,
            total_in_file = combined.len(),
            "outbox persisted to position_queue.json"
        );
    }
}

// v0.6.0: spawn_position_queue_drain ist entfallen — `spawn_phpvms_position_worker`
// ist der einzige phpVMS-POST-Pfad, der direkt aus der Memory-Outbox liest.
// Persistenz in `position_queue.json` passiert nur lazy (bei Backlog>500 oder
// Worker-Stop), nicht mehr als primärer Drain-Mechanismus.

/// `GET /metar/{icao}` — fetch the current METAR for an airport.
/// Cached per-flight in `FlightStats` (departure + arrival), so the
/// dashboard / future briefing panel can reuse it without round-trips.
/// Errors map to a serializable `UiError` so the frontend can show a
/// localized message instead of a Rust enum.
#[tauri::command]
async fn metar_get(icao: String) -> Result<MetarSnapshot, UiError> {
    metar::fetch_metar(&icao).await.map_err(|e| match e {
        MetarError::NotFound(_) => UiError::new("metar_not_found", e.to_string()),
        MetarError::Network(_) => UiError::new("metar_network", e.to_string()),
        MetarError::Status(_) => UiError::new("metar_upstream", e.to_string()),
        MetarError::Parse(_) => UiError::new("metar_parse", e.to_string()),
    })
}

/// Compute the great-circle distance (nm) from the live sim position to
/// the airport with the given ICAO. Returns `None` when we don't have
/// a sim snapshot yet, can't resolve the airport, or the airport
/// coordinates are zero (typical for stub records). Used by
/// `flight_end` to enforce the "you have to actually be there to file"
/// rule. Reads the airport from the in-memory cache first; only goes
/// to the network if we haven't seen the ICAO yet.
async fn compute_distance_to_airport(
    app: &AppHandle,
    state: &tauri::State<'_, AppState>,
    icao: &str,
) -> Option<f64> {
    let snap = current_snapshot(app)?;
    let key = icao.trim().to_uppercase();

    // Cache hit: synchronous lookup, no network call.
    let cached: Option<Airport> = {
        let guard = state.airports.lock().expect("airports lock");
        guard.get(&key).cloned()
    };
    let airport = match cached {
        Some(a) => a,
        None => {
            // Cache miss: fetch via phpVMS. Best-effort — if the lookup
            // fails (network down, airport not in DB) we skip the check
            // rather than blocking the file.
            let client = state.client.lock().expect("client mutex").clone()?;
            let fetched = client.get_airport(&key).await.ok()?;
            let mut guard = state.airports.lock().expect("airports lock");
            guard.insert(key.clone(), fetched.clone());
            fetched
        }
    };

    let lat = airport.lat?;
    let lon = airport.lon?;
    if lat == 0.0 && lon == 0.0 {
        return None;
    }
    let meters = ::geo::distance_m(snap.lat, snap.lon, lat, lon);
    Some(meters / 1852.0)
}

/// File the active PIREP with computed final stats. Refuses to file if any
/// of the minimum-quality checks in `validate_for_filing` fail — the UI then
/// surfaces a dialog letting the user cancel the flight or file as a manual
/// PIREP via [`flight_end_manual`].
/// `divert_to` is optional and carries the ICAO of the actual landing
/// airport when the pilot is filing a divert. JS side passes this when
/// the user clicks "Submit as divert to X" on the divert-detected
/// banner. When `Some`, the proximity-to-planned-arrival validation is
/// skipped, the FileBody includes `arr_airport_id` to override the
/// bid's planned destination, and a "DIVERT: X → Y" line is prepended
/// to the notes.
#[tauri::command]
async fn flight_end(
    app: AppHandle,
    state: tauri::State<'_, AppState>,
    divert_to: Option<String>,
    divert_reason: Option<String>,
    accident_decision: Option<String>,
) -> Result<(), UiError> {
    let divert_to = divert_to
        .as_deref()
        .map(|s| s.trim().to_uppercase())
        .filter(|s| !s.is_empty());
    // v0.12.5 (Spec v0.12.5-divert-and-manual-pirep.md, LE2): die
    // Divert-Begründung. Pflichtfeld sobald `divert_to` gesetzt ist —
    // das Bestätigungs-Modal validiert frontend-seitig, dieser Guard
    // schließt den API-Contract serverseitig ab.
    let divert_reason = divert_reason
        .as_deref()
        .map(|s| s.trim().to_string())
        .filter(|s| !s.is_empty());
    if divert_to.is_some() && divert_reason.is_none() {
        return Err(UiError::new(
            "divert_reason_required",
            "a divert PIREP requires a reason",
        ));
    }

    // v0.7.19 GAF-707 (QS-R1 Finding 3): Pilot-Override-Pfad. Werte:
    // - None / "auto"        → Stats-Werte bleiben unveraendert.
    //   Pilot bestaetigt im Dialog dass die Klassifikation stimmt.
    // - "as_accident"        → wie None, expliziter "ja, war Unfall"-
    //   Klick. Wird nicht ueberschrieben, nur fuer Audit-Notes geloggt.
    // - "as_hard_landing"    → Pilot widerspricht der Klassifikation
    //   und filed den Flug als regulaere Landung. Setzt
    //   stats.accident_detected=false, kind/confidence=None,
    //   ergaenzt reasons um "pilot_override=as_hard_landing(...)".
    //   Die Notes/Custom-Fields zeigen den Override transparent.
    //
    // Spec §Active Flight / Flight End "Nein, als harte Landung
    // behandeln".
    let accident_decision = accident_decision
        .as_deref()
        .map(|s| s.trim().to_string())
        .filter(|s| !s.is_empty());
    if let Some(decision) = accident_decision.as_deref() {
        if decision == "as_hard_landing" {
            // v0.7.19 (QS-R2 Finding 1): Override-MQTT-Event vorbereiten
            // BEVOR wir den Stats-Latch clearen — damit wir die Original-
            // Klassifikation fuer den `previous_*`-Audit-Trail kennen.
            // Webapp persistierte beim Touchdown-Edge schon `accident=true`;
            // dieser Korrektur-Event triggert den DB-Update.
            let override_payload_opt = {
                let guard = state.active_flight.lock().expect("active_flight lock");
                if let Some(flight) = guard.as_ref() {
                    let mut stats = flight.stats.lock().expect("flight stats");
                    if stats.accident_detected
                        || stats.accident_confidence.as_deref() == Some("medium")
                    {
                        let prev_kind = stats.accident_kind.clone().unwrap_or_default();
                        let prev_conf = stats.accident_confidence.clone();
                        let prev_reasons = stats.accident_reasons.join(", ");
                        stats.accident_detected = false;
                        stats.accident_kind = None;
                        stats.accident_confidence = None;
                        stats.accident_reasons = vec![format!(
                            "pilot_override=as_hard_landing (was: {prev_kind}; reasons: {prev_reasons})"
                        )];
                        // accident_at wird NICHT geloescht — Audit-Spur fuer den
                        // Override-Zeitpunkt bleibt. Notes-Builder ignoriert sie
                        // wenn accident_detected=false.
                        log_activity(
                            &state,
                            ActivityLevel::Warn,
                            "Pilot hat Accident-Klassifikation widersprochen — filing als harte Landung".to_string(),
                            Some(format!(
                                "Vorherige Klassifikation: kind={prev_kind}, reasons=[{prev_reasons}]"
                            )),
                        );

                        Some(aeroacars_mqtt::TouchdownAccidentOverridePayload {
                            ts: Utc::now().timestamp_millis(),
                            pirep_id: flight.pirep_id.clone(),
                            decision: "as_hard_landing".into(),
                            accident: false,
                            accident_kind: None,
                            accident_confidence: None,
                            accident_reasons: stats.accident_reasons.clone(),
                            previous_kind: Some(prev_kind),
                            previous_confidence: prev_conf,
                        })
                    } else {
                        None
                    }
                } else {
                    None
                }
            };

            // MQTT-Publish OHNE Locks halten. Best-effort — Recorder
            // retried den Touchdown-Row-Update unabhaengig.
            if let Some(payload) = override_payload_opt {
                let app_state = state.inner();
                let mqtt_handle = app_state.mqtt.lock().await.clone();
                if let Some(handle) = mqtt_handle {
                    handle.touchdown_accident_override(payload);
                }
            }
        }
    }

    // Pull the arrival ICAO so we can resolve its coords without holding
    // the active_flight lock across the network call.
    let arr_icao = {
        let guard = state.active_flight.lock().expect("active_flight lock");
        let flight = guard
            .as_ref()
            .ok_or_else(|| UiError::new("no_active_flight", "no flight is active"))?;
        flight.arr_airport.clone()
    };
    // Compute distance to the planned arrival. Used as an extra
    // pre-flight-filing gate ("not_at_arrival") so the pilot can't
    // file a flight from 200 nm out — they have to taxi to the gate or
    // file as a manual divert via flight_end_manual.
    //
    // SKIPPED entirely when filing as a divert — by definition the
    // pilot is NOT at the planned arrival, that's the whole point.
    let distance_to_arr_nm = if divert_to.is_some() {
        None
    } else {
        compute_distance_to_airport(&app, &state, &arr_icao).await
    };

    // Validate WITHOUT removing the flight from state, so a failed validation
    // leaves the user able to retry, edit-and-file-manual, or cancel.
    {
        let guard = state.active_flight.lock().expect("active_flight lock");
        let flight = guard
            .as_ref()
            .ok_or_else(|| UiError::new("no_active_flight", "no flight is active"))?;
        let stats = flight.stats.lock().expect("flight stats");
        let elapsed_minutes = (Utc::now() - flight.started_at).num_minutes() as i32;
        let mut missing = validate_for_filing(flight, &stats, elapsed_minutes);
        if let Some(d) = distance_to_arr_nm {
            if d > MAX_FILE_DISTANCE_NM {
                missing.push("not_at_arrival");
            }
        }
        if !missing.is_empty() {
            tracing::warn!(
                pirep_id = %flight.pirep_id,
                missing = ?missing,
                distance_to_arr_nm,
                "rejecting PIREP filing — validation failed"
            );
            return Err(UiError::new(
                "flight_validation_failed",
                "flight does not meet minimum requirements for an ACARS PIREP",
            )
            .with_details(serde_json::json!({ "missing": missing })));
        }
    }

    // Validation passed — now actually take the flight out of state and file.
    let flight = {
        let mut guard = state.active_flight.lock().expect("active_flight lock");
        guard
            .take()
            .ok_or_else(|| UiError::new("no_active_flight", "no flight is active"))?
    };
    // v0.6.0: Outbox VOR stop=true leeren — bei Filing ist die PIREP
    // im Server abgeschlossen, weiteres POSTen ist sinnlos. Forensik-
    // Upload (file_pirep-Anhang) enthält die JSONL mit allen Position-
    // Events, kein Datenverlust. Verhindert dass der Worker beim
    // letzten Tick orphan items in position_queue.json persistiert.
    flight.position_outbox.lock().expect("position_outbox lock").clear();
    flight.stop.store(true, Ordering::Relaxed);

    let client = current_client(&state)?;

    // Snapshot all stats inside a single short-lived guard to avoid holding
    // the Mutex across an `await`.
    let (body, block_on_iso) = {
        let mut stats = flight.stats.lock().expect("flight stats");
        // v0.16.24 (QS-6): upgrade the runway correlation to the best
        // available (Navigraph) BEFORE building the PIREP body, so the native
        // `score` (compute_aggregate_master_score) and the "Landing Score"
        // custom field (build_pirep_fields) read the upgraded LDA/rollout
        // geometry on a divert whose on-demand navdata fetch has since
        // completed — keeping the authoritative scored PIREP record consistent
        // with the local LandingRecord. No-op (byte-identical) on-plan and
        // when the fetch hasn't landed (keeps the provisional OurAirports).
        apply_finalized_runway_correlation(&flight, &mut stats);
        // Flight time = takeoff → landing (when both timestamps were
        // captured by the FSM). Falls back to the started_at → now
        // window only if takeoff/landing weren't observed (e.g.
        // manual file before the FSM advanced through Takeoff). The
        // takeoff→landing range matches what phpVMS expects in its
        // native Flt.Time column.
        //
        // Spec sim-disconnect-auto-resume F3 (Block-Time-Korrektur):
        // Pause-Akkumulator wird in Minuten umgerechnet und abgezogen,
        // damit Sim-Crash-/Esc-Pause-Pausen nicht als Flugzeit landen.
        let raw_flight_time_min = match (stats.takeoff_at, stats.landing_at) {
            (Some(t), Some(l)) if l > t => (l - t).num_minutes() as i32,
            _ => ((Utc::now() - flight.started_at).num_minutes() as i32).max(0),
        };
        let pause_min =
            (stats.pause_total_duration_secs / 60).clamp(0, i32::MAX as i64) as i32;
        let flight_time = Some(raw_flight_time_min.saturating_sub(pause_min).max(0));

        let fares = if flight.fares.is_empty() {
            None
        } else {
            Some(
                flight
                    .fares
                    .iter()
                    .map(|(id, count)| FareEntry {
                        id: *id,
                        count: *count,
                    })
                    .collect(),
            )
        };

        // Block→remaining diff in kg, converted to pounds for phpVMS.
        // We round to whole kilograms BEFORE the lb conversion so the
        // PIREP-detail page shows clean integer values (`9733 kg`
        // instead of `9733.45 kg`). Real-world refuelling has no
        // sub-kg precision anyway, and a half-kg loss is invisible
        // to pilots — what's NOT invisible is `9733.45 kg` looking
        // like a unit-mix-up bug. Same logic for fuel_used.
        let fuel_used = match (stats.block_fuel_kg, stats.last_fuel_kg) {
            (Some(b), Some(c)) if b > c => Some(((b - c) as f64).round() * KG_TO_LB),
            _ => None,
        };
        // Block fuel sent natively so phpVMS computes "Verbleibender
        // Treibstoff" correctly (= block_fuel - fuel_used). Without
        // this the dashboard shows "-fuel_used kg" because the
        // missing block_fuel defaults to 0. Same unit as fuel_used.
        let block_fuel = stats
            .block_fuel_kg
            .filter(|kg| *kg > 0.0)
            .map(|kg| (kg as f64).round() * KG_TO_LB);
        // Cruise level = peak MSL altitude observed. phpVMS column
        // `Flt.Level`. Rounded to the nearest 100 ft so the value
        // matches the conventional FL display.
        let level = stats.peak_altitude_ft.map(|ft| {
            let rounded = ((ft / 100.0).round() * 100.0) as i32;
            rounded.max(0)
        });
        // Native landing rate field — same value as the custom field
        // but on the native column phpVMS shows on the PIREP overview.
        //
        // v0.7.21 (MS713-QS): MUSS `canonical_landing_rate_fpm()` sein,
        // sonst kriegt phpVMS den Streamer-Tick-Snapshot statt des
        // Engineering-Edge-Wertes. Vorher: -204 (0.5s-Mittel via
        // landing_rate_fpm), seit Fix: -194 (vs_at_edge_fpm). Diese
        // Zeile war die letzte uebersehene Stelle aus dem v0.7.17
        // B-015a-Sweep.
        let landing_rate = stats
            .canonical_landing_rate_fpm()
            .map(|v| v as f64);
        // v0.7.1 P1 (Round-2 Review): phpVMS bekommt jetzt den
        // GLEICHEN gewichteten Aggregate-Score wie App/Web/MQTT
        // (siehe build_landing_record P1.3-Fix). Vorher landete der
        // alte Touchdown-Klassifikator-Score (vs/g/bounces only) im
        // phpVMS-Datensatz waehrend App "77/100" zeigte und phpVMS
        // "60/100" — Score-Vertragsbruch.
        // Fallback: stats.landing_score.numeric() wenn Crate keinen
        // Aggregate liefert (z.B. komplett leerer Sub-Score-Vec).
        //
        // v0.16.24 (QS-2 FIX A): den EFFEKTIVEN Ankunftsflughafen
        // (`divert_to` falls bestätigt, sonst geplant) übergeben — exakt
        // das gleiche Argument das `build_pirep_payload` / `build_landing_record`
        // schon nutzen. Sonst prüfte der native Score die Runway-Geometrie
        // gegen das GEPLANTE Ziel und übersprang bei einem Divert (Aircraft
        // parkt >2 nm vom Threshold → `divert_hint.actual_icao`=None) den
        // Rollout/LDA-Sub-Score, während Payload/Record ihn bekamen — der
        // autoritative PIREP-Score wich vom Record ab. On-Plan: `divert_to`=None
        // → effective_arr == arr_airport → BYTE-IDENTISCH.
        let effective_arr = divert_to.as_deref().unwrap_or(&flight.arr_airport);
        let score = compute_aggregate_master_score(&stats, Some(&flight.aircraft_icao), effective_arr)
            .map(|m| m as i32)
            .or_else(|| stats.landing_score.map(|s| s.numeric()));
        let distance_nm = stats.distance_nm;
        let fields = build_pirep_fields(&flight, &stats, effective_arr);
        let mut notes = build_pirep_notes(&flight, &stats);
        // Prepend a divert banner to the notes so the VA admin sees
        // immediately on the PIREP page that this wasn't a normal
        // arrival. Format mirrors what most ACARS clients write
        // ("DIVERT: <planned> → <actual>") so admins can grep.
        // v0.12.5 (LE2): die Pflicht-Begründung steht direkt unter dem
        // Banner — ein Audit-Eintrag pro Divert für den VA-Admin.
        if let Some(actual) = divert_to.as_deref() {
            let reason_line = divert_reason
                .as_deref()
                .map(|r| format!("Reason: {r}\n\n"))
                .unwrap_or_default();
            notes = format!(
                "DIVERT: {} → {} (planned destination not reached)\n{}\n{}",
                arr_icao, actual, reason_line, notes
            );
        }

        let body = FileBody {
            flight_time,
            fuel_used,
            block_fuel,
            distance: Some(distance_nm),
            level,
            landing_rate,
            score,
            source_name: Some(format!("AeroACARS/{}", env!("CARGO_PKG_VERSION"))),
            notes: Some(notes),
            fares,
            fields: Some(fields),
            arr_airport_id: divert_to.clone(),
        };
        // Block-on time = touchdown timestamp captured by the FSM.
        // Needed by the divert-finalize path because we skip /file
        // entirely there, so phpVMS won't auto-set this column.
        let block_on_iso = stats.landing_at.map(|t| t.to_rfc3339());
        (body, block_on_iso)
    };
    // v0.3.1: Divert finalization bypasses /file entirely.
    //
    // Background: earlier versions tried to route diverts into PENDING via
    // (a) a pre-file source=MANUAL "smuggle" through the update endpoint,
    // and (b) a post-file state=PENDING update. Both are dead on real
    // phpVMS deployments:
    //   * Acars\PirepController::file() ignores the stored source field
    //     and always evaluates auto_approve_acars on the rank, so (a)
    //     does not route through auto_approve_manual.
    //   * Once the PIREP is ACCEPTED, PirepController::checkReadOnly()
    //     blocks any further state-update, so (b) returns "PIREP is
    //     read-only" (verified against german-sky-group.eu, 2026-05-04).
    //
    // The path that actually works: while the PIREP is still IN_PROGRESS
    // (not read-only), mass-assign EVERYTHING /file would have written —
    // including state=PENDING, source=MANUAL, arr_airport_id, all final
    // stats — through a single update_pirep call. This bypasses
    // PirepService::submit() and the auto-approve check entirely. The
    // PIREP shows up in the admin's PENDING queue with the correct
    // arrival airport and divert notes.
    //
    // Strategy verified against phpvms@dev: PirepController::update +
    // parsePirep() pass the full request payload to mass-assignment, and
    // (source, state, arr_airport_id, landing_rate, score, submitted_at,
    // block_on_time) are all in Pirep $fillable. Acars\UpdateRequest
    // doesn't strip non-validated keys.
    if divert_to.is_some() {
        let now_iso = Utc::now().to_rfc3339();
        let finalize = api_client::UpdateBody {
            state: Some(1),                                   // PirepState::PENDING
            source: Some(api_client::pirep_source::MANUAL),   // 1
            status: Some("ONB".to_string()),                  // PirepStatus::ARRIVED
            flight_time: body.flight_time,
            distance: body.distance,
            fuel_used: body.fuel_used,
            block_fuel: body.block_fuel,
            level: body.level,
            landing_rate: body.landing_rate,
            score: body.score,
            source_name: body.source_name.clone(),
            notes: body.notes.clone(),
            arr_airport_id: divert_to.clone(),
            submitted_at: Some(now_iso.clone()),
            block_on_time: block_on_iso.clone(),
            updated_at: Some(now_iso),
        };
        match client.update_pirep(&flight.pirep_id, &finalize).await {
            Ok(()) => tracing::info!(
                pirep_id = %flight.pirep_id,
                "divert finalize update OK — PIREP mass-assigned to MANUAL/PENDING"
            ),
            Err(e) => {
                log_activity(
                    &state,
                    ActivityLevel::Error,
                    "Divert: Finalisierung fehlgeschlagen".to_string(),
                    Some(format!("{} — Flug bleibt aktiv für Retry", e)),
                );
                let mut guard = state.active_flight.lock().expect("active_flight lock");
                *guard = Some(flight);
                return Err(e.into());
            }
        }
        // Custom PIREP fields live in `pirep_field_values` (separate
        // table from `pireps`) — they don't go through Pirep
        // mass-assignment. Push them via the dedicated endpoint.
        // Failures are non-fatal: the main PIREP is already in PENDING.
        if let Some(fields_map) = body.fields.as_ref() {
            if let Err(e) = client.post_pirep_fields(&flight.pirep_id, fields_map).await {
                tracing::warn!(
                    pirep_id = %flight.pirep_id,
                    error = %e,
                    "post_pirep_fields after divert finalize failed (non-fatal)"
                );
            }
        }
        // Verify the PIREP actually landed in PENDING. The mass-assign
        // strategy is well-trodden but the verification is cheap and
        // gives us loud feedback if a future phpVMS upgrade changes the
        // semantics. Failure here doesn't unwind the file — it just
        // surfaces a warning so the pilot knows to ping the VA admin.
        match client.get_pirep(&flight.pirep_id).await {
            Ok(p) => {
                let s = p.state.unwrap_or(-1);
                if s == 1 {
                    tracing::info!(
                        pirep_id = %flight.pirep_id,
                        "verified: divert PIREP state == PENDING"
                    );
                } else {
                    tracing::warn!(
                        pirep_id = %flight.pirep_id,
                        actual_state = s,
                        "divert PIREP did NOT land in PENDING — phpVMS semantics changed?"
                    );
                    log_activity(
                        &state,
                        ActivityLevel::Error,
                        "Divert: konnte NICHT für Admin-Review markiert werden".to_string(),
                        Some(format!(
                            "Server-Status nach Divert-Finalize: {} (erwartet: 1=PENDING). Bitte VA-Admin manuell informieren.",
                            s
                        )),
                    );
                }
            }
            Err(e) => {
                tracing::warn!(
                    pirep_id = %flight.pirep_id,
                    error = %e,
                    "post-divert state verify failed"
                );
            }
        }
        // Local snapshot + activity log + bid cleanup, mirroring the
        // /file success path so downstream UI (Landung-Tab, Activity)
        // sees the same state for divert and normal arrivals.
        {
            let mut stats = flight.stats.lock().expect("flight stats");
            // v0.15.x: Divert → effektiver Landeflughafen für den Geometrie-Trust.
            record_landing_for_filed_flight(
                &app,
                &flight,
                &mut stats,
                divert_to.as_deref().unwrap_or(&flight.arr_airport),
            );
        }
        clear_persisted_flight(&app);
        log_activity(
            &state,
            ActivityLevel::Info,
            format!(
                "PIREP filed: {} {} → {} (DIVERT, planned {})",
                format_callsign(&flight.airline_icao, &flight.flight_number),
                flight.dpt_airport,
                divert_to.as_deref().unwrap_or(&flight.arr_airport),
                flight.arr_airport,
            ),
            {
                let dist = body.distance.unwrap_or(0.0);
                let fuel = body.fuel_used.unwrap_or(0.0);
                let stats_line = if fuel > 0.0 {
                    format!("Distance {dist:.1} nm, fuel {fuel:.0} lb")
                } else {
                    format!("Distance {dist:.1} nm")
                };
                Some(format!("{stats_line} · MANUAL/PENDING (admin review)"))
            },
        );
        record_event(
            &app,
            &flight.pirep_id,
            &FlightLogEvent::FlightEnded {
                timestamp: Utc::now(),
                pirep_id: flight.pirep_id.clone(),
                outcome: FlightOutcome::Filed,
            },
        );
        // v0.12.5 (Spec v0.12.5-divert-and-manual-pirep.md, Bug A/B):
        // Divert-Pfad publisht jetzt — wie der normale /file-Pfad — das
        // MQTT-PIREP-Event und lädt das JSONL-Forensik-Logfile hoch.
        // Vorher kehrte dieser Branch via `return Ok(())` zurück OHNE
        // beides → diverted Flüge fehlten dauerhaft in den VPS-Reports
        // und es gab kein Logfile. `effective_arr_icao` = das Divert-
        // ICAO, `planned_arr_icao` = das ursprüngliche Ziel → der
        // Helper setzt `divert`/`diverted_to` korrekt.
        {
            let effective_arr = divert_to
                .as_deref()
                .unwrap_or(&flight.arr_airport);
            let mut pirep_payload = build_pirep_payload(
                &flight,
                &body,
                effective_arr,
                &flight.arr_airport,
            );
            // v0.12.5 (LE2): Divert-Begründung auch ins MQTT-Payload
            // (Audit) — der Recorder/JSONL hält damit den Grund.
            pirep_payload.notes = divert_reason.clone();
            let pirep_payload_json = serde_json::to_value(&pirep_payload)
                .unwrap_or(serde_json::Value::Null);
            // QS-P1: JSONL-PirepFiled IMMER schreiben, MQTT-Publish nur
            // wenn ein Handle da ist.
            let mqtt = state.mqtt.lock().await;
            finalize_filed_pirep(
                &app,
                mqtt.as_ref(),
                &flight.pirep_id,
                pirep_payload_json,
            );
        }
        // v0.12.5 (LE7-QS): LandingFinalized-JSONL-Event auch beim Divert
        // — vor dem Upload, damit es im hochgeladenen Logfile steht.
        emit_landing_finalized(&app, &flight);
        // v0.12.5 (Bug A): Forensik-Upload auch beim Divert — gzip +
        // POST des kompletten JSONL-Logfiles an aeroacars-live.
        spawn_flight_log_upload(&app, flight.pirep_id.clone());
        // v0.7.14: Pilot-Client-Discord-Post fuer Divert entfernt — Recorder
        // postet das jetzt zentral (= eine Quelle, kein Doppel-Post). Die
        // Divert-Info ist im PirepPayload (divert + diverted_to) und kommt
        // automatisch beim Recorder an wenn der MQTT-PIREP-Event publisht.
        // Audit Q4-2026-05 (C1).
        // v0.7.19 (QS-R1 Finding 1): Bei delete_bid-fail in pending_bid_cleanup.
        // QS-R2 Finding 2: flight_id-Fallback mitgeben.
        consume_bid_best_effort(
            &app,
            &client,
            &flight.pirep_id,
            flight.bid_id,
            Some(flight.flight_id.as_str()),
            "divert_filed",
        ).await;
        // Drop the in-memory active flight: divert is finalized.
        let _ = state.active_flight.lock().expect("active_flight lock").take();
        return Ok(());
    }
    tracing::info!(
        pirep_id = %flight.pirep_id,
        flight_time = body.flight_time.unwrap_or(0),
        distance = body.distance.unwrap_or(0.0),
        fuel_used = body.fuel_used.unwrap_or(0.0),
        fare_classes = flight.fares.len(),
        custom_fields = body.fields.as_ref().map(|f| f.len()).unwrap_or(0),
        "filing PIREP"
    );
    // Non-divert path. (Diverts return early above via the dedicated
    // mass-assign-to-PENDING flow; only normal arrivals reach /file.)
    //
    // v0.5.49 — file_pirep_with_retry: 3 attempts mit 5s+30s Backoff
    // bei TRANSIENTEM Fehler (Netz, Timeout, 5xx, 429). Bei 3× Fail
    // queued der Err-Branch unten den PIREP in den persistenten
    // pirep_queue/ — Background-Worker reicht ihn ein sobald die
    // Verbindung wieder steht. Pilot sieht „PIREP queued" statt
    // „PIREP filed", kann aber sofort den nächsten Flug starten.
    match file_pirep_with_retry(&client, &flight.pirep_id, &body).await {
        Ok(()) => {
            // Snapshot the landing into the local history file BEFORE
            // we drop the persisted flight — gives the new "Landung"
            // tab something to render even after the PIREP is filed
            // and the in-memory FlightStats goes out of scope.
            {
                let mut stats = flight.stats.lock().expect("flight stats");
                // v0.15.x: tatsächlicher Landeflughafen (= gefilte arr) für Trust.
                record_landing_for_filed_flight(
                    &app,
                    &flight,
                    &mut stats,
                    body.arr_airport_id.as_deref().unwrap_or(&flight.arr_airport),
                );
            }
            clear_persisted_flight(&app);
            log_activity(
                &state,
                ActivityLevel::Info,
                format!(
                    "PIREP filed: {} {} → {}",
                    format_callsign(&flight.airline_icao, &flight.flight_number),
                    flight.dpt_airport,
                    flight.arr_airport,
                ),
                {
                    let dist = body.distance.unwrap_or(0.0);
                    let fuel = body.fuel_used.unwrap_or(0.0);
                    if fuel > 0.0 {
                        Some(format!("Distance {dist:.1} nm, fuel {fuel:.0} lb"))
                    } else {
                        Some(format!("Distance {dist:.1} nm"))
                    }
                },
            );
            record_event(
                &app,
                &flight.pirep_id,
                &FlightLogEvent::FlightEnded {
                    timestamp: Utc::now(),
                    pirep_id: flight.pirep_id.clone(),
                    outcome: FlightOutcome::Filed,
                },
            );
            // v0.7.14: Pilot-Client-Discord-Post fuer PirepFiled entfernt —
            // Recorder postet das jetzt zentral via `postPirep` aus dem
            // MQTT-PIREP-Event. Audit Q4-2026-05 (C1).
            // v0.5.11: MQTT live-tracking PIREP publish. Best-effort,
            // fire-and-forget. Monitor uses this to mark a flight
            // as completed in the live history.
            {
                // v0.12.5 (Spec v0.12.5-divert-and-manual-pirep.md, LE1):
                // Der MQTT-PirepPayload-Build ist in `build_pirep_payload`
                // ausgelagert — eine Stelle für alle Filing-Pfade. Normaler
                // /file-Pfad: effective == planned == flight.arr_airport.
                let pirep_payload = build_pirep_payload(
                    &flight,
                    &body,
                    &flight.arr_airport,
                    &flight.arr_airport,
                );
                // v0.12.5 (LE1): JSONL-Forensik + MQTT-Publish über den
                // zentralen Finalizer — gleicher Pfad wie Divert/Manual/Queue.
                // QS-P1: JSONL-PirepFiled IMMER, MQTT nur bei Handle.
                let pirep_payload_json = serde_json::to_value(&pirep_payload)
                    .unwrap_or(serde_json::Value::Null);
                let mqtt = state.mqtt.lock().await;
                finalize_filed_pirep(
                    &app,
                    mqtt.as_ref(),
                    &flight.pirep_id,
                    pirep_payload_json,
                );
            }
            // v0.7.0 — emit landing_finalized mit dem finalen Score
            // (Spec docs/spec/touchdown-forensics-v2.md Sektion 7.2).
            // v0.12.5 (LE7-QS): in `emit_landing_finalized` ausgelagert —
            // Divert- und Manual-Pfad rufen denselben Helper.
            emit_landing_finalized(&app, &flight);
            // v0.5.23 Forensik-Upload: gzip + POST des kompletten JSONL-
            // Logfiles an aeroacars-live damit der VA-Owner ohne den
            // Piloten zu kontaktieren das vollstaendige SimSnapshot-Log
            // (80 Felder) + Activity-Log + PhaseChanged-Stream pro
            // Session abrufen kann. Fire-and-forget, blockt PIREP-File
            // nicht — Failure landet nur im Log.
            spawn_flight_log_upload(&app, flight.pirep_id.clone());
            // v0.7.19 (QS-R1 Finding 1): Bei delete_bid-fail wird der Bid
            // in pending_bid_cleanup eingereiht und vom Background-Worker
            // retried — keine haengenden Aircraft/Bid mehr nach Accident-
            // FILED. Reason-String spiegelt die Filing-Variante.
            let bid_reason = if flight.stats.lock().expect("stats lock").accident_detected {
                "accident_filed"
            } else {
                "normal_filed"
            };
            consume_bid_best_effort(
                &app,
                &client,
                &flight.pirep_id,
                flight.bid_id,
                Some(flight.flight_id.as_str()),
                bid_reason,
            ).await;
            Ok(())
        }
        Err(e) => {
            // v0.5.49 — Auto-Retry hat schon 3× erfolglos versucht.
            // Wenn der Fehler TRANSIENT ist (Netz, Timeout) → in den
            // persistenten Queue schieben, Flight clearen, Pilot kann
            // weiter. Background-Worker reicht den PIREP ein sobald
            // die Verbindung wieder steht.
            // Wenn der Fehler HARD ist (Validation, Auth) → wie bisher
            // Flight in State halten damit der Pilot was korrigieren
            // kann.
            if is_transient_pirep_error(&e) {
                // v0.12.5 (LE1b): MQTT-PIREP-Payload schon hier bauen und
                // mit-persistieren — der Queue-Worker publisht es nach
                // erfolgreichem /file. Normaler /file-Pfad: effective ==
                // planned == flight.arr_airport.
                let pirep_payload_json = serde_json::to_value(
                    build_pirep_payload(
                        &flight,
                        &body,
                        &flight.arr_airport,
                        &flight.arr_airport,
                    ),
                )
                .unwrap_or(serde_json::Value::Null);
                let queued = pirep_queue::QueuedPirep {
                    pirep_id: flight.pirep_id.clone(),
                    bid_id: flight.bid_id,
                    airline_icao: flight.airline_icao.clone(),
                    flight_number: flight.flight_number.clone(),
                    dpt_airport: flight.dpt_airport.clone(),
                    arr_airport: flight.arr_airport.clone(),
                    body: body.clone(),
                    queued_at: Utc::now(),
                    last_attempt_at: Some(Utc::now()),
                    attempt_count: 3, // = die 3 retries die wir grade verbraucht haben
                    last_error: Some(friendly_net_error(&e)),
                    // v0.7.19 (QS-R2 Finding 2): phpVMS-flight_id mit-
                    // persistieren damit der Worker-Bid-Cleanup nach
                    // erfolgreichem queued-Filing den flight_id-Fallback
                    // hat. Empty-String fuer pre-v0.7.7-Bids ist okay.
                    flight_id: flight.flight_id.clone(),
                    pirep_payload_json,
                };
                if let Err(qe) = pirep_queue::enqueue(&app, &queued) {
                    // Queue selber kaputt — fallback auf altes Verhalten
                    tracing::error!(error = %qe, "PIREP-Queue enqueue failed — falling back to flight-in-state");
                    log_activity(
                        &state,
                        ActivityLevel::Error,
                        "PIREP file failed",
                        Some(format!("{} — Queue ebenfalls kaputt, Flug bleibt aktiv für Retry", e)),
                    );
                    let mut guard = state.active_flight.lock().expect("active_flight lock");
                    *guard = Some(flight);
                    return Err(e.into());
                }
                // Erfolgreich gequeued → Landing-Snapshot, clear, Activity-Log
                {
                    let mut stats = flight.stats.lock().expect("flight stats");
                    // v0.15.x: tatsächlicher Landeflughafen (= gefilte arr) für Trust.
                    record_landing_for_filed_flight(
                        &app,
                        &flight,
                        &mut stats,
                        body.arr_airport_id.as_deref().unwrap_or(&flight.arr_airport),
                    );
                }
                clear_persisted_flight(&app);
                log_activity(
                    &state,
                    ActivityLevel::Warn,
                    format!(
                        "PIREP queued: {} {} → {}",
                        format_callsign(&flight.airline_icao, &flight.flight_number),
                        flight.dpt_airport,
                        flight.arr_airport,
                    ),
                    Some(format!(
                        "{} — wird automatisch eingereicht sobald die Verbindung wieder steht. Du kannst den nächsten Flug starten.",
                        friendly_net_error(&e)
                    )),
                );
                record_event(
                    &app,
                    &flight.pirep_id,
                    &FlightLogEvent::FlightEnded {
                        timestamp: Utc::now(),
                        pirep_id: flight.pirep_id.clone(),
                        outcome: FlightOutcome::Filed, // queued zählt als „abgeschlossen"
                    },
                );
                Ok(())
            } else {
                // Hard-Fail (Validation, Auth, …) — Pilot muss das selber
                // korrigieren. Flight bleibt in state.
                log_activity(
                    &state,
                    ActivityLevel::Error,
                    "PIREP file failed",
                    Some(format!("{} — flight kept in state for retry", e)),
                );
                let mut guard = state.active_flight.lock().expect("active_flight lock");
                *guard = Some(flight);
                Err(e.into())
            }
        }
    }
}

/// Best-effort: drop the bid that was used for this flight. phpVMS does NOT
/// auto-consume bids on PIREP file, so without this the booked flight stays
/// in the pilot's bid list even after Accepted.
///
/// v0.7.19 GAF-707 (QS-R1 Finding 1): Bei transientem Fehler wird der
/// Bid-Drop in die persistente `PendingBidCleanupQueue` enqueued — der
/// Background-Worker retried das spaeter. So bleibt nach Accident-FILED
/// kein Aircraft + Bid auf phpVMS haengen wenn der delete_bid-Aufruf
/// transient versagt (Netz weg, 5xx). Spec §Pending Bid Cleanup Queue.
///
/// v0.7.19 (QS-R2 Finding 2): `flight_id` wird als Fallback mitgegeben.
/// Wenn `delete_bid(bid_id)` 400/404/422 liefert (Bid existiert nicht
/// mehr oder VA-Plugin akzeptiert `bid_id` nicht), versucht die
/// `delete_bid`-Implementation den `flight_id`-Body-Pfad. Ohne den
/// Fallback haette der Background-Worker 8x denselben kaputten Pfad
/// retried. Empty-String-`flight_id` (pre-v0.7.7-Bid) wird zu None
/// gemapped.
/// v0.7.19 (QS-R3 Finding 1): Pure-function-Helper fuer
/// `consume_bid_best_effort` — entscheidet welche der zwei IDs an
/// `delete_bid` weitergegeben werden. Extrahiert damit der Path-
/// Selection-Logik unit-testbar bleibt ohne dass ein `Client` (HTTP-
/// I/O) im Test-Path noetig ist.
///
/// Returns:
/// - `None` wenn beide IDs fehlen (Caller skipt komplett).
/// - `Some((bid_id_opt, flight_id_opt))` sonst — leerer flight_id-
///   String wird als None behandelt (pre-v0.7.7-Resume-Files).
pub(crate) fn resolve_bid_cleanup_args(
    bid_id: i64,
    flight_id: Option<&str>,
) -> Option<(Option<i64>, Option<String>)> {
    let flight_id_opt = flight_id
        .filter(|s| !s.is_empty())
        .map(|s| s.to_string());
    if bid_id <= 0 && flight_id_opt.is_none() {
        return None;
    }
    let bid_id_opt = if bid_id > 0 { Some(bid_id) } else { None };
    Some((bid_id_opt, flight_id_opt))
}

async fn consume_bid_best_effort(
    app: &AppHandle,
    client: &Client,
    pirep_id: &str,
    bid_id: i64,
    flight_id: Option<&str>,
    reason: &str,
) {
    // v0.7.19 (QS-R3 Finding 1): nur skippen wenn BEIDE IDs fehlen.
    // Frueher: `if bid_id <= 0 { return; }` — hat den flight_id-only-
    // Pfad still verschluckt. Im Orphan-Cleanup-/Accident-Filing-Pfad
    // kann es legitim vorkommen dass nur die phpVMS-flight_id bekannt
    // ist (z. B. bei VAs ohne separates bid_id-Feld).
    let Some((bid_id_opt, flight_id_owned)) =
        resolve_bid_cleanup_args(bid_id, flight_id)
    else {
        return;
    };
    let flight_id_opt = flight_id_owned.as_deref();
    match client.delete_bid(bid_id_opt, flight_id_opt).await {
        Ok(()) => tracing::info!(
            ?bid_id_opt,
            ?flight_id_opt,
            "bid removed after PIREP filing"
        ),
        Err(e) => {
            tracing::warn!(
                ?bid_id_opt,
                ?flight_id_opt,
                pirep_id,
                error = %e,
                "delete_bid failed — enqueueing for pending_bid_cleanup retry"
            );
            enqueue_pending_bid_cleanup(
                app,
                pirep_id,
                bid_id_opt,
                flight_id_owned.clone(),
                reason,
            );
        }
    }
}

/// v0.7.19 GAF-707: Helper-Wrapper um PendingBidCleanupQueue::enqueue
/// damit Caller nicht das app_data_dir aufloesen muessen. Schluckt
/// alle I/O-Fehler (warn-log) — diese Queue ist ein Best-Effort-Backup
/// fuer den primaeren delete_bid-Pfad und darf NIE den File-Flow
/// brechen.
fn enqueue_pending_bid_cleanup(
    app: &AppHandle,
    pirep_id: &str,
    bid_id: Option<i64>,
    flight_id: Option<String>,
    reason: &str,
) {
    let Ok(dir) = app.path().app_data_dir() else {
        tracing::warn!(
            pirep_id,
            "pending_bid_cleanup: konnte app_data_dir nicht aufloesen — Eintrag verloren"
        );
        return;
    };
    let queue = match storage::PendingBidCleanupQueue::open(dir) {
        Ok(q) => q,
        Err(e) => {
            tracing::warn!(
                pirep_id,
                error = %e,
                "pending_bid_cleanup: konnte Queue nicht oeffnen"
            );
            return;
        }
    };
    let entry = storage::PendingBidCleanup {
        pirep_id: pirep_id.to_string(),
        bid_id,
        flight_id,
        reason: reason.to_string(),
        created_at: Utc::now(),
        last_attempt_at: None,
        attempts: 0,
    };
    if let Err(e) = queue.enqueue(entry) {
        tracing::warn!(
            pirep_id,
            error = %e,
            "pending_bid_cleanup: enqueue fehlgeschlagen"
        );
    } else {
        tracing::info!(
            pirep_id,
            bid_id = ?bid_id,
            reason,
            "pending_bid_cleanup: Eintrag persistiert fuer Background-Retry"
        );
    }
}

/// v0.7.19 GAF-707: drain-Pass fuer den PendingBidCleanupQueue. Wird im
/// spawn_pirep_queue_worker-Tick mit aufgerufen (selbe 60s-Frequenz).
/// Cap auf 8 Versuche pro Eintrag, danach bleibt der Eintrag liegen
/// und wird ueber den B-011 Orphan-Cleanup-Flow sichtbar.
async fn drain_pending_bid_cleanup(app: &AppHandle, client: &Client) {
    const MAX_ATTEMPTS: u32 = 8;
    let Ok(dir) = app.path().app_data_dir() else { return; };
    let Ok(queue) = storage::PendingBidCleanupQueue::open(dir) else { return; };
    let entries = match queue.read_all() {
        Ok(v) => v,
        Err(e) => {
            tracing::warn!(error = %e, "pending_bid_cleanup drain: read_all failed");
            return;
        }
    };
    if entries.is_empty() {
        return;
    }
    tracing::info!(count = entries.len(), "pending_bid_cleanup drain tick");

    let mut survivors: Vec<storage::PendingBidCleanup> = Vec::new();
    for mut e in entries {
        if e.attempts >= MAX_ATTEMPTS {
            tracing::warn!(
                pirep_id = %e.pirep_id,
                attempts = e.attempts,
                "pending_bid_cleanup: max attempts reached — leaving in queue for orphan-cleanup UI"
            );
            survivors.push(e);
            continue;
        }
        e.attempts += 1;
        e.last_attempt_at = Some(Utc::now());
        match client.delete_bid(e.bid_id, e.flight_id.as_deref()).await {
            Ok(()) => {
                tracing::info!(
                    pirep_id = %e.pirep_id,
                    attempts = e.attempts,
                    reason = %e.reason,
                    "pending_bid_cleanup: delete_bid succeeded — Eintrag entfernt"
                );
                // Eintrag NICHT in survivors aufnehmen → wird gedroppt.
            }
            Err(err) => {
                tracing::warn!(
                    pirep_id = %e.pirep_id,
                    attempt = e.attempts,
                    error = %err,
                    "pending_bid_cleanup: delete_bid failed — bleibt in Queue"
                );
                survivors.push(e);
            }
        }
    }
    if let Err(e) = queue.replace(&survivors) {
        tracing::warn!(error = %e, "pending_bid_cleanup drain: queue write failed");
    }
}

/// File the active PIREP as a *manual* report — bypasses the validation in
/// `flight_end` and tags the source as manual so the VA admin knows the data
/// wasn't 100% machine-collected.
///
/// Use cases:
///   * Flight ended with broken stats (e.g. resumed run that lost block_fuel)
///     but pilot still wants to file rather than cancel.
///   * Divert: planned EDDP→EDDF, actually landed EDDV. The pilot supplies
///     `divert_to = "EDDV"` and a `reason`; admin sees the divert tag in the
///     notes and adjusts the PIREP airports manually.
///   * Sim disconnect mid-flight: the FSM never saw landing, so flight_time /
///     fuel_used / landing_rate are all wrong. Pilot supplies the override
///     fields below and we ship those instead of the (broken) FSM values.
///
/// Every override field is `Option<...>`; `None` falls back to whatever the
/// FSM captured. All overrides also get tagged in the notes so the admin
/// can see WHICH fields the pilot edited by hand.
///
/// `block_off_at_iso` / `block_on_at_iso` accept any RFC-3339 timestamp
/// (typically `2026-05-02T15:30:00Z`); blank uses the FSM-captured time.
#[tauri::command]
#[allow(clippy::too_many_arguments)]
async fn flight_end_manual(
    app: AppHandle,
    state: tauri::State<'_, AppState>,
    notes_override: Option<String>,
    divert_to: Option<String>,
    reason: Option<String>,
    flight_time_minutes: Option<i32>,
    block_fuel_kg: Option<f32>,
    // v0.12.5 (LE4): Resttreibstoff im Tank in kg — NICHT der Verbrauch.
    // Das Backend rechnet `fuel_used_kg = block_fuel_kg − remaining_fuel_kg`.
    remaining_fuel_kg: Option<f32>,
    distance_nm: Option<f64>,
    cruise_level_ft: Option<i32>,
    landing_rate_fpm: Option<f32>,
    block_off_at_iso: Option<String>,
    block_on_at_iso: Option<String>,
) -> Result<(), UiError> {
    let flight = {
        let mut guard = state.active_flight.lock().expect("active_flight lock");
        guard
            .take()
            .ok_or_else(|| UiError::new("no_active_flight", "no flight is active"))?
    };
    // v0.6.0: Outbox VOR stop=true leeren — siehe flight_end Begründung.
    flight.position_outbox.lock().expect("position_outbox lock").clear();
    flight.stop.store(true, Ordering::Relaxed);
    let client = current_client(&state)?;

    // Parse RFC-3339 block-off/on overrides if present. Anything that
    // doesn't parse cleanly is dropped — we don't want a typo to
    // silently file a PIREP with a bogus "1970" timestamp.
    let block_off_override: Option<DateTime<Utc>> = block_off_at_iso
        .as_deref()
        .and_then(|s| {
            if s.trim().is_empty() {
                None
            } else {
                DateTime::parse_from_rfc3339(s.trim())
                    .ok()
                    .map(|dt| dt.with_timezone(&Utc))
            }
        });
    let block_on_override: Option<DateTime<Utc>> = block_on_at_iso
        .as_deref()
        .and_then(|s| {
            if s.trim().is_empty() {
                None
            } else {
                DateTime::parse_from_rfc3339(s.trim())
                    .ok()
                    .map(|dt| dt.with_timezone(&Utc))
            }
        });

    let body = {
        let mut stats = flight.stats.lock().expect("flight stats");

        // v0.16.24 (QS-6): upgrade the runway correlation to the best
        // available (Navigraph) BEFORE building the manual PIREP body, so the
        // "Landing Score" custom field (build_pirep_fields →
        // compute_aggregate_master_score) reads the upgraded LDA/rollout
        // geometry on a divert whose on-demand navdata fetch has completed.
        // Same idempotent, on-plan-byte-identical, graceful-when-not-fetched
        // contract as the auto-file path.
        apply_finalized_runway_correlation(&flight, &mut stats);

        // Apply block-time overrides BEFORE building the body so the
        // notes block + custom fields pick them up.
        if let Some(off) = block_off_override {
            stats.block_off_at = Some(off);
        }
        if let Some(on) = block_on_override {
            stats.block_on_at = Some(on);
        }
        if let Some(kg) = block_fuel_kg.filter(|v| *v > 0.0) {
            stats.block_fuel_kg = Some(kg);
        }

        // Same flight-time / block-fuel / level / landing-rate / score
        // mapping as the regular file path, with manual-overrides
        // taking precedence. phpVMS skips missing values cleanly
        // thanks to `skip_serializing_if`.
        //
        // Spec sim-disconnect-auto-resume F3 (Block-Time-Korrektur):
        // im Auto-Compute-Pfad (= keine Manual-Override) wird der
        // Pause-Akkumulator abgezogen. Bei Manual-Override (Pilot
        // tippt eine Flight-Time im Edit-Dialog ein) wird sein Wert
        // ungeaendert uebernommen — er hat die Pause bewusst
        // beruecksichtigt oder absichtlich ignoriert.
        let flight_time = match flight_time_minutes.filter(|m| *m >= 0) {
            Some(m) => Some(m),
            None => {
                let raw_min = match (stats.takeoff_at, stats.landing_at) {
                    (Some(t), Some(l)) if l > t => (l - t).num_minutes() as i32,
                    _ => ((Utc::now() - flight.started_at).num_minutes() as i32).max(0),
                };
                let pause_min = (stats.pause_total_duration_secs / 60)
                    .clamp(0, i32::MAX as i64) as i32;
                Some(raw_min.saturating_sub(pause_min).max(0))
            }
        };
        let fares = if flight.fares.is_empty() {
            None
        } else {
            Some(
                flight
                    .fares
                    .iter()
                    .map(|(id, count)| FareEntry {
                        id: *id,
                        count: *count,
                    })
                    .collect(),
            )
        };
        // v0.12.5 (LE4): Der Pilot gibt die Restmenge im Tank (kg) ein,
        // nicht den Verbrauch. fuel_used_kg = block_fuel_kg − remaining.
        // Guard: block_fuel_kg > remaining_fuel_kg >= 0, sonst greift der
        // FSM-Fallback (block − last_fuel). Gerechnet wird in kg, ERST am
        // Ende nach lb konvertiert (phpVMS-Site-Unit = lb) — QS-R2-P2.
        // `stats.block_fuel_kg` trägt hier schon den Manual-Override
        // (oben gesetzt falls `block_fuel_kg`-Param > 0).
        let fuel_used = {
            let from_remaining = match (stats.block_fuel_kg, remaining_fuel_kg) {
                (Some(block), Some(rem)) if rem >= 0.0 && block > rem => {
                    Some((block - rem) as f64)
                }
                _ => None,
            };
            from_remaining
                .or_else(|| match (stats.block_fuel_kg, stats.last_fuel_kg) {
                    (Some(b), Some(c)) if b > c => Some((b - c) as f64),
                    _ => None,
                })
                .map(|kg| kg.round() * KG_TO_LB)
        };
        let block_fuel = stats
            .block_fuel_kg
            .filter(|kg| *kg > 0.0)
            .map(|kg| (kg as f64).round() * KG_TO_LB);
        let level = cruise_level_ft.filter(|ft| *ft > 0).or_else(|| {
            stats.peak_altitude_ft.map(|ft| {
                let rounded = ((ft / 100.0).round() * 100.0) as i32;
                rounded.max(0)
            })
        });
        // v0.7.21 (MS713-QS): canonical_landing_rate_fpm() statt direkt.
        let landing_rate = landing_rate_fpm
            .map(|v| v as f64)
            .or_else(|| stats.canonical_landing_rate_fpm().map(|v| v as f64));
        let score = stats.landing_score.map(|s| s.numeric());
        let resolved_distance = distance_nm
            .filter(|d| *d > 0.0)
            .unwrap_or(stats.distance_nm);
        // v0.16.24 (QS-2 FIX A): effektiver Ankunftsflughafen für die
        // "Landing Score"-Custom-Field-Geometrie-Trust-Prüfung — gleiche
        // Normalisierung (trim/uppercase/non-empty) wie der Divert-Notes-Block
        // unten und wie der `record_landing_for_filed_flight`-Aufruf weiter
        // unten. On-Plan (`divert_to`=None) == `flight.arr_airport`.
        let effective_arr_norm = divert_to
            .as_ref()
            .map(|s| s.trim().to_uppercase())
            .filter(|s| !s.is_empty());
        let effective_arr =
            effective_arr_norm.as_deref().unwrap_or(&flight.arr_airport);
        let fields = build_pirep_fields(&flight, &stats, effective_arr);
        let mut notes = build_pirep_notes(&flight, &stats);
        notes.push_str("\n\n[MANUAL FILE — auto-validation bypassed by pilot.]");
        if let Some(divert) = divert_to
            .as_ref()
            .map(|s| s.trim().to_uppercase())
            .filter(|s| !s.is_empty())
        {
            notes.push_str(&format!(
                "\n\n[DIVERT] Planned arrival: {planned}. Actual landing: {actual}.",
                planned = flight.arr_airport,
                actual = divert,
            ));
        }
        if let Some(r) = reason
            .as_ref()
            .map(|s| s.trim())
            .filter(|s| !s.is_empty())
        {
            notes.push_str("\n\nReason: ");
            notes.push_str(r);
        }

        // List which fields the pilot manually overrode so the admin
        // can review at a glance. Helps avoid silently mis-attributing
        // FSM stats to manual entry.
        let mut overrides: Vec<&'static str> = Vec::new();
        if flight_time_minutes.is_some() {
            overrides.push("flight_time");
        }
        if block_fuel_kg.is_some() {
            overrides.push("block_fuel");
        }
        if remaining_fuel_kg.is_some() {
            overrides.push("fuel_used");
        }
        if distance_nm.is_some() {
            overrides.push("distance");
        }
        if cruise_level_ft.is_some() {
            overrides.push("cruise_level");
        }
        if landing_rate_fpm.is_some() {
            overrides.push("landing_rate");
        }
        if block_off_override.is_some() {
            overrides.push("block_off_time");
        }
        if block_on_override.is_some() {
            overrides.push("block_on_time");
        }
        if !overrides.is_empty() {
            notes.push_str(&format!(
                "\n\n[MANUAL OVERRIDES] {}",
                overrides.join(", ")
            ));
        }

        if let Some(extra) = notes_override
            .as_ref()
            .map(|s| s.trim())
            .filter(|s| !s.is_empty())
        {
            notes.push_str("\n\nPilot notes: ");
            notes.push_str(extra);
        }
        FileBody {
            flight_time,
            fuel_used,
            block_fuel,
            distance: Some(resolved_distance),
            level,
            landing_rate,
            score,
            source_name: Some(format!(
                "AeroACARS/{} (manual)",
                env!("CARGO_PKG_VERSION")
            )),
            notes: Some(notes),
            fares,
            fields: Some(fields),
            // The manual flow already had a `divert_to` parameter for
            // notes — pre-fix it only annotated the notes block and left
            // the admin to update arr_airport_id by hand. Now we override
            // the field directly too, same way the auto-divert flow does.
            arr_airport_id: divert_to
                .as_ref()
                .map(|s| s.trim().to_uppercase())
                .filter(|s| !s.is_empty()),
        }
    };
    // Flip the PIREP `source` to MANUAL (1) before submitting. PhpVMS's
    // PirepService::submit() decides ACCEPTED-vs-PENDING based on
    // (source, rank.auto_approve_acars, rank.auto_approve_manual). With
    // source=MANUAL and the VA having `auto_approve_manual=false` on the
    // pilot's rank, the PIREP lands in PENDING for admin review instead
    // of being auto-accepted as a normal ACARS submission.
    //
    // The Acars/UpdateRequest validation rules don't include `source`,
    // but the controller's parsePirep() forwards EVERY request input
    // to mass-assignment, and `source` is in the Pirep $fillable. So
    // the smuggle works as long as upstream phpVMS doesn't change it.
    // Verified against phpvms@dev on 2026-05-03.
    let source_marker = UpdateBody {
        source: Some(api_client::pirep_source::MANUAL),
        ..Default::default()
    };
    if let Err(e) = client.update_pirep(&flight.pirep_id, &source_marker).await {
        tracing::warn!(
            pirep_id = %flight.pirep_id,
            error = %e,
            "could not flip PIREP source to MANUAL — VA admin must filter on source_name"
        );
    } else {
        tracing::info!(pirep_id = %flight.pirep_id, "PIREP source flipped to MANUAL");
    }
    tracing::info!(pirep_id = %flight.pirep_id, "filing PIREP (manual)");
    match client.file_pirep(&flight.pirep_id, &body).await {
        Ok(()) => {
            // Same landing-history snapshot as the regular file path.
            {
                let mut stats = flight.stats.lock().expect("flight stats");
                // v0.15.x: manueller Divert → effektiver Landeflughafen für Trust.
                record_landing_for_filed_flight(
                    &app,
                    &flight,
                    &mut stats,
                    divert_to.as_deref().unwrap_or(&flight.arr_airport),
                );
            }
            clear_persisted_flight(&app);
            log_activity(
                &state,
                ActivityLevel::Warn,
                {
                    let actual_arr = divert_to.as_deref().unwrap_or(&flight.arr_airport);
                    let suffix = if divert_to.is_some() {
                        format!(" (DIVERT, planned {})", flight.arr_airport)
                    } else {
                        String::new()
                    };
                    format!(
                        "Manual PIREP filed: {} {} → {}{}",
                        format_callsign(&flight.airline_icao, &flight.flight_number),
                        flight.dpt_airport,
                        actual_arr,
                        suffix
                    )
                },
                Some("Source tagged 'manual' — admin will review".into()),
            );
            record_event(
                &app,
                &flight.pirep_id,
                &FlightLogEvent::FlightEnded {
                    timestamp: Utc::now(),
                    pirep_id: flight.pirep_id.clone(),
                    outcome: FlightOutcome::Manual,
                },
            );
            // v0.12.5 (Spec v0.12.5-divert-and-manual-pirep.md, Bug B/C):
            // der manuelle Filing-Pfad publisht jetzt — wie der normale
            // /file-Pfad — das MQTT-PIREP-Event und lädt das JSONL-
            // Forensik-Logfile hoch. Vorher tat dieser Pfad keins von
            // beidem → manuell gefilte Flüge (z.B. Diverts) fehlten
            // dauerhaft in den VPS-Reports und es gab kein Logfile.
            // `effective_arr` = das Divert-ICAO falls gesetzt (steht
            // schon uppercase im `body.arr_airport_id`), sonst das
            // geplante Ziel.
            {
                let effective_arr = body
                    .arr_airport_id
                    .as_deref()
                    .unwrap_or(&flight.arr_airport);
                let mut pirep_payload = build_pirep_payload(
                    &flight,
                    &body,
                    effective_arr,
                    &flight.arr_airport,
                );
                // v0.12.5 (LE2-QS): die manuelle Begründung auch ins
                // MQTT-Payload (notes) — konsistent mit dem
                // `flight_end`-Divert-Pfad, damit Recorder/JSONL den
                // Grund im Audit haben.
                pirep_payload.notes = reason
                    .as_deref()
                    .map(|s| s.trim().to_string())
                    .filter(|s| !s.is_empty());
                let pirep_payload_json =
                    serde_json::to_value(&pirep_payload)
                        .unwrap_or(serde_json::Value::Null);
                // QS-P1: JSONL-PirepFiled IMMER, MQTT nur bei Handle.
                let mqtt = state.mqtt.lock().await;
                finalize_filed_pirep(
                    &app,
                    mqtt.as_ref(),
                    &flight.pirep_id,
                    pirep_payload_json,
                );
            }
            // v0.12.5 (LE7-QS): LandingFinalized-JSONL-Event auch beim
            // manuellen File — vor dem Upload.
            emit_landing_finalized(&app, &flight);
            // v0.12.5 (Bug B): Forensik-Upload auch beim manuellen File.
            spawn_flight_log_upload(&app, flight.pirep_id.clone());
            // v0.7.19 (QS-R1 Finding 1) + QS-R2 Finding 2 (flight_id fallback).
            consume_bid_best_effort(
                &app,
                &client,
                &flight.pirep_id,
                flight.bid_id,
                Some(flight.flight_id.as_str()),
                "manual_filed",
            ).await;
            Ok(())
        }
        Err(e) => {
            tracing::warn!(
                pirep_id = %flight.pirep_id,
                error = %e,
                "manual PIREP file failed — restoring flight to state for retry"
            );
            let mut guard = state.active_flight.lock().expect("active_flight lock");
            *guard = Some(flight);
            Err(e.into())
        }
    }
}

/// v0.13.0 Stream F (LE22-LE26): Pilot-getriggerter Position-Re-Check.
///
/// Workflow:
///   1. AeroACARS-Client startet nach Sim-Crash neu, ActiveFlight wird
///      vom Disk restored mit `was_just_resumed=true`.
///   2. Sim-Position weicht stark ab → `resume_position_suspect=true`.
///   3. ResumeFlightBanner zeigt drei Optionen, EINE davon ist
///      "Position prüfen + fortsetzen". Pilot positioniert sich erst
///      manuell im Sim wieder zur letzten gespeicherten Position, drückt
///      DANN den Button.
///   4. Dieser Command holt die aktuelle Sim-Snapshot, vergleicht die
///      Drift mit `RESUME_DRIFT_CLEAN_NM` und prüft auf airborne↔
///      on_ground-Inkonsistenz.
///   5. Wenn alles OK → setzt `was_just_resumed=false` → Frontend ruft
///      anschließend den normalen Resume-Pfad → kein untrusted-Stempel.
///   6. Wenn nicht OK → returnt drift_nm + still_suspect=true, Pilot
///      kann nochmal positionieren und nochmal prüfen.
///
/// Tolerant gegen Zeit-Gaps bis ~10min — wir prüfen NUR die Position,
/// nicht wie lange der Pilot zum Reposition gebraucht hat.
#[derive(Serialize)]
struct ResumeCheckPositionOutcome {
    ok: bool,
    drift_nm: f64,
    sim_on_ground_inconsistent: bool,
    persisted_phase: &'static str,
    detail: String,
    // v0.13.0 Stream F: aktuelle Sim-Position damit Frontend einen
    // Vergleich anzeigen kann (persisted vs current).
    #[serde(skip_serializing_if = "Option::is_none")]
    current_sim_lat: Option<f64>,
    #[serde(skip_serializing_if = "Option::is_none")]
    current_sim_lon: Option<f64>,
    #[serde(skip_serializing_if = "Option::is_none")]
    current_sim_alt_ft: Option<i32>,
    current_sim_on_ground: bool,
    #[serde(skip_serializing_if = "Option::is_none")]
    persisted_lat: Option<f64>,
    #[serde(skip_serializing_if = "Option::is_none")]
    persisted_lon: Option<f64>,
    // v0.13.0 Stream F: Fuel/Weight/Aircraft-Vergleich. Frontend zeigt
    // damit "Sim hat 5 t weniger Fuel als gespeichert" oder "anderes
    // Aircraft im Sim geladen" an, sobald der Pilot auf "Position prüfen"
    // drückt.
    #[serde(skip_serializing_if = "Option::is_none")]
    current_sim_fuel_kg: Option<f32>,
    #[serde(skip_serializing_if = "Option::is_none")]
    current_sim_zfw_kg: Option<f32>,
    #[serde(skip_serializing_if = "Option::is_none")]
    current_sim_total_weight_kg: Option<f32>,
    #[serde(skip_serializing_if = "Option::is_none")]
    current_sim_aircraft_icao: Option<String>,
}

#[tauri::command]
async fn flight_resume_check_position(
    app: AppHandle,
    state: tauri::State<'_, AppState>,
) -> Result<ResumeCheckPositionOutcome, UiError> {
    let guard = state.active_flight.lock().expect("active_flight lock");
    let flight = guard
        .as_ref()
        .ok_or_else(|| UiError::new("no_active_flight", "no flight is active"))?;

    if !flight.was_just_resumed.load(Ordering::Relaxed) {
        // Flight is already live — recheck not applicable
        return Ok(ResumeCheckPositionOutcome {
            ok: true,
            drift_nm: 0.0,
            sim_on_ground_inconsistent: false,
            persisted_phase: "Live",
            detail: "Flight already live, no recheck needed".to_string(),
            current_sim_lat: None,
            current_sim_lon: None,
            current_sim_alt_ft: None,
            current_sim_on_ground: false,
            persisted_lat: None,
            persisted_lon: None,
            current_sim_fuel_kg: None,
            current_sim_zfw_kg: None,
            current_sim_total_weight_kg: None,
            current_sim_aircraft_icao: None,
        });
    }

    let snap = current_snapshot(&app).ok_or_else(|| {
        UiError::new("sim_disconnected", "Sim ist nicht verbunden — bitte erst den Sim wieder starten und positionieren")
    })?;

    let (persisted_phase, persisted_pos) = {
        let stats = flight.stats.lock().expect("flight stats");
        let pos = match (stats.last_lat, stats.last_lon) {
            (Some(la), Some(lo)) => Some((la, lo)),
            _ => None,
        };
        (stats.phase, pos)
    };

    let drift_nm = if let Some((plat, plon)) = persisted_pos {
        ::geo::distance_m(plat, plon, snap.lat, snap.lon) / 1852.0
    } else {
        // No persisted position — can't compute drift, treat as clean
        0.0
    };

    let persisted_airborne = matches!(
        persisted_phase,
        FlightPhase::Climb
            | FlightPhase::Cruise
            | FlightPhase::Holding
            | FlightPhase::Descent
            | FlightPhase::Approach
            | FlightPhase::Final
    );
    let sim_on_ground_inconsistent = persisted_airborne && snap.on_ground;

    let ok = drift_nm < RESUME_DRIFT_CLEAN_NM && !sim_on_ground_inconsistent;

    let detail = if ok {
        format!(
            "Position OK — Drift {:.2} nm (Limit {:.1} nm). Flug läuft jetzt als sauber weiter.",
            drift_nm, RESUME_DRIFT_CLEAN_NM
        )
    } else if sim_on_ground_inconsistent {
        format!(
            "Flugzeug ist im Sim am Boden, gespeicherter Flug war in der Luft (Phase {:?}). Bitte zurück in die Luft positionieren ODER Flug verwerfen.",
            persisted_phase
        )
    } else {
        format!(
            "Drift {:.2} nm — zu weit weg von gespeicherter Position (Limit {:.1} nm). Bitte näher positionieren und nochmal prüfen.",
            drift_nm, RESUME_DRIFT_CLEAN_NM
        )
    };

    if ok {
        // Pilot hat sich erfolgreich repositioniert — Resume gilt als sauber.
        // was_just_resumed=false → resume_position_suspect wird ebenfalls
        // false bei nächstem flight_status-Poll → Banner schließt sich.
        flight.was_just_resumed.store(false, Ordering::Relaxed);
        tracing::info!(
            pirep_id = %flight.pirep_id,
            drift_nm,
            "flight_resume_check_position: clean — was_just_resumed cleared"
        );
    } else {
        tracing::info!(
            pirep_id = %flight.pirep_id,
            drift_nm,
            sim_on_ground_inconsistent,
            "flight_resume_check_position: still suspect"
        );
    }

    Ok(ResumeCheckPositionOutcome {
        ok,
        drift_nm,
        sim_on_ground_inconsistent,
        persisted_phase: phase_to_str(persisted_phase),
        detail,
        current_sim_lat: Some(snap.lat),
        current_sim_lon: Some(snap.lon),
        current_sim_alt_ft: Some(snap.altitude_msl_ft.round() as i32),
        current_sim_on_ground: snap.on_ground,
        persisted_lat: persisted_pos.map(|(la, _)| la),
        persisted_lon: persisted_pos.map(|(_, lo)| lo),
        current_sim_fuel_kg: Some(snap.fuel_total_kg),
        current_sim_zfw_kg: snap.zfw_kg,
        current_sim_total_weight_kg: snap.total_weight_kg,
        current_sim_aircraft_icao: snap.aircraft_icao.clone(),
    })
}

fn phase_to_str(phase: FlightPhase) -> &'static str {
    match phase {
        FlightPhase::Preflight => "Preflight",
        FlightPhase::Boarding => "Boarding",
        FlightPhase::Pushback => "Pushback",
        FlightPhase::TaxiOut => "TaxiOut",
        FlightPhase::TakeoffRoll => "TakeoffRoll",
        FlightPhase::Takeoff => "Takeoff",
        FlightPhase::Climb => "Climb",
        FlightPhase::Cruise => "Cruise",
        FlightPhase::Holding => "Holding",
        FlightPhase::Descent => "Descent",
        FlightPhase::Approach => "Approach",
        FlightPhase::Final => "Final",
        FlightPhase::Landing => "Landing",
        FlightPhase::TaxiIn => "TaxiIn",
        FlightPhase::BlocksOn => "BlocksOn",
        FlightPhase::Arrived => "Arrived",
        FlightPhase::PirepSubmitted => "PirepSubmitted",
    }
}

/// Cancel the active PIREP without filing it.
#[tauri::command]
async fn flight_cancel(
    app: AppHandle,
    state: tauri::State<'_, AppState>,
    force: Option<bool>,
) -> Result<FlightCancelOutcome, UiError> {
    // SCHRITT 1: Nur LESEN, damit wir is_finalizable bestimmen können.
    // guard.take() machen wir erst beim eigentlichen Wegräumen weiter
    // unten — sonst wäre der Flight bei einem zwischenzeitlichen Fehler
    // weg ohne dass irgendwas passiert ist.
    //
    // v0.7.18 (B-014): is_finalizable-Check vor File-First-Versuch.
    // Spec docs/spec/v0.7.18-orphan-flight-cleanup.md §B-014.
    let is_finalizable = {
        let guard = state.active_flight.lock().expect("active_flight lock");
        let flight = guard
            .as_ref()
            .ok_or_else(|| UiError::new("no_active_flight", "no flight is active"))?;
        let stats = flight.stats.lock().expect("flight stats");
        // Annahme: solange flight in state.active_flight liegt UND eine
        // gültige `landing_at`-Markierung gesetzt ist UND die FSM-Phase
        // eine TD-Phase ist, ist der Flug noch nicht gefiled (gefilte
        // Flüge räumen `state.active_flight` selber via flight_end-Pfad).
        matches!(
            stats.phase,
            FlightPhase::Landing
                | FlightPhase::TaxiIn
                | FlightPhase::BlocksOn
                | FlightPhase::Arrived
        ) && stats.landing_at.is_some()
    };

    let user_forced_cancel = force.unwrap_or(false);

    if is_finalizable && !user_forced_cancel {
        // PIREP-ID merken bevor flight_end den active_flight-Slot räumt
        let pirep_id_for_outcome = {
            let guard = state.active_flight.lock().expect("active_flight lock");
            guard.as_ref().map(|f| f.pirep_id.clone()).unwrap_or_default()
        };

        // Best-Effort: erst zu filen versuchen via flight_end-Pfad.
        // flight_end macht selbst:
        //   - Validation (not_at_arrival etc.)
        //   - guard.take() falls Validation OK
        //   - file_pirep_with_retry (3 attempts, transient → pirep_queue)
        //   - record_landing + activity_log + record_event + MQTT publish
        //
        // Outcome-Mapping (siehe Spec + R2-1):
        //   Ok(())                  → Filed ODER Queued (beide OK aus Cancel-Sicht)
        //   Err(code="blocked")     → Err propagieren (B-007 Account-Sperre)
        //   Err(andere Hard-Fails)  → Err mit code="file_first_failed".
        //                             Kein Auto-Cancel mehr (R2-1 UX-Fix).
        //                             active_flight bleibt erhalten, Pilot
        //                             entscheidet im Frontend nochmal.
        match flight_end(app.clone(), state.clone(), None, None, None).await {
            Ok(()) => {
                // flight_end hat erfolgreich gefilt ODER gequeued. In
                // beiden Faellen ist active_flight geleert, der PIREP
                // lebt server-side bzw. im Queue-Worker.
                //
                // v0.7.18 (R1-5): Filed vs Queued unterscheiden — Pilot
                // soll wissen ob der PIREP schon eingereicht ist oder
                // noch auf den naechsten Network-Recovery wartet.
                // flight_end hat keinen Outcome-Type; wir checken die
                // pirep_queue auf unsere pirep_id.
                let is_queued = pirep_queue::list_all(&app)
                    .iter()
                    .any(|q| q.pirep_id == pirep_id_for_outcome);

                if is_queued {
                    log_activity(
                        &state,
                        ActivityLevel::Warn,
                        format!(
                            "Flug statt abgebrochen in der Queue für späteren Retry — PIREP {pirep_id_for_outcome}"
                        ),
                        Some(
                            "B-014 File-First-Pfad: transient-Fehler beim Filing. Der Background-Worker reicht den PIREP ein sobald die Verbindung wieder steht.".into(),
                        ),
                    );
                    return Ok(FlightCancelOutcome::Queued {
                        pirep_id: pirep_id_for_outcome,
                    });
                }

                log_activity(
                    &state,
                    ActivityLevel::Info,
                    format!("Flug statt abgebrochen ordentlich eingereicht — PIREP {pirep_id_for_outcome}"),
                    Some("B-014 File-First-Pfad: Server hat den PIREP angenommen.".into()),
                );
                return Ok(FlightCancelOutcome::FiledInstead {
                    pirep_id: pirep_id_for_outcome,
                });
            }
            Err(e) if e.code == "blocked" => {
                // 401/403 Account-Sperre — Cancel würde ebenfalls 401/403
                // werfen, also kein Cancel-Versuch. state.active_flight
                // bleibt unverändert für Re-Try nach VA-Klärung.
                tracing::warn!(
                    code = e.code,
                    "flight_cancel: File-First abgebrochen wegen Account-Sperre"
                );
                return Err(e);
            }
            Err(e) => {
                // v0.7.18 (R2-1): Validierungs-/Hard-Fehler beim Auto-File.
                // Wir fallen NICHT mehr automatisch in den Cancel-Pfad —
                // der Pilot hat "Lieber filen versuchen" geklickt, nicht
                // "bei Fehler trotzdem verwerfen". Das wäre UX-seitig eine
                // versteckte destruktive Aktion.
                //
                // state.active_flight bleibt erhalten (flight_end macht
                // guard.take() nur bei Success), also kann der Pilot:
                //   1. den Fehler beheben + erneut filen,
                //   2. den Cancel-Button nochmal drücken und im zweiten
                //      Dialog explizit "Trotzdem verwerfen" wählen.
                //
                // Frontend (ActiveFlightPanel) catched code="file_first_failed"
                // und zeigt den zweiten Confirm-Dialog.
                tracing::warn!(
                    code = e.code,
                    "flight_cancel: File-First fehlgeschlagen, gebe an UI zurueck statt Auto-Cancel"
                );
                log_activity(
                    &state,
                    ActivityLevel::Warn,
                    format!(
                        "Auto-File vor Cancel fehlgeschlagen ({}) — Pilot muss erneut bestätigen",
                        e.code
                    ),
                    Some(format!("{e:?}")),
                );
                return Err(UiError::new(
                    "file_first_failed",
                    format!(
                        "Filen-Versuch vor Cancel fehlgeschlagen: {} ({}). \
                         Bitte beheben und erneut filen, oder explizit verwerfen.",
                        e.message, e.code
                    ),
                ));
            }
        }
    }

    // SCHRITT 2: Cancel-Pfad. Erst JETZT den Flight aus state.active_flight
    // herausnehmen (guard.take()) bevor wir destruktiv werden.
    let flight = {
        let mut guard = state.active_flight.lock().expect("active_flight lock");
        guard.take().ok_or_else(|| {
            UiError::new(
                "no_active_flight",
                "flight was concurrently removed — likely already filed",
            )
        })?
    };
    // v0.6.0: Outbox VOR stop=true leeren — sonst persistiert der
    // phpVMS-Worker beim nächsten Tick (im stop-branch) die noch
    // gepufferten Positions zurück in position_queue.json. Bei einem
    // Cancel will der Pilot aber explizit dass NICHTS mehr an phpVMS
    // gesendet wird.
    flight.position_outbox.lock().expect("position_outbox lock").clear();
    flight.stop.store(true, Ordering::Relaxed);
    let client = current_client(&state)?;
    let result = client.cancel_pirep(&flight.pirep_id).await;
    // Clear local persistence regardless — the user wants this gone.
    clear_persisted_flight(&app);
    discard_queued_positions_for(&app, &flight.pirep_id);
    pirep_queue::remove(&app, &flight.pirep_id);
    result?;
    log_activity(
        &state,
        ActivityLevel::Warn,
        format!(
            "Flight cancelled: {} {} → {}",
            format_callsign(&flight.airline_icao, &flight.flight_number),
            flight.dpt_airport,
            flight.arr_airport
        ),
        Some(format!("PIREP {}", flight.pirep_id)),
    );
    record_event(
        &app,
        &flight.pirep_id,
        &FlightLogEvent::FlightEnded {
            timestamp: Utc::now(),
            pirep_id: flight.pirep_id.clone(),
            outcome: FlightOutcome::Cancelled,
        },
    );
    Ok(FlightCancelOutcome::Cancelled {
        pirep_id: flight.pirep_id.clone(),
    })
}

/// v0.7.18 (B-014) — Outcome eines `flight_cancel`-Aufrufs.
///
/// Spec docs/spec/v0.7.18-orphan-flight-cleanup.md §B-014. Frontend
/// rendert pro Variante eine andere Bestätigung.
#[derive(Debug, Clone, Serialize)]
#[serde(tag = "kind", rename_all = "snake_case")]
pub enum FlightCancelOutcome {
    /// File-First-Versuch hat geklappt — PIREP wurde direkt an phpVMS
    /// abgeschickt und akzeptiert.
    FiledInstead { pirep_id: String },
    /// File-First-Versuch hat transienten Fehler (Netz, 5xx, Timeout)
    /// produziert — PIREP liegt jetzt in der pirep_queue für Background-
    /// Retry. Cancel hat NICHT stattgefunden (sonst Datenverlust).
    Queued { pirep_id: String },
    /// Pilot hat explizit „Trotzdem verwerfen" gewählt (force=true ODER
    /// nicht-finalisierbarer Flug). Regulärer Cancel-Pfad ist gelaufen,
    /// PIREP ist CANCELLED auf phpVMS. (R2-1: File-First-HardFail führt
    /// hier NICHT mehr automatisch hin — der Pilot muss explizit zweiten
    /// Confirm-Dialog bestätigen.)
    Cancelled { pirep_id: String },
}

/// Confirm an auto-resumed flight: now actually spawn the position streamer.
/// Called by the resume banner when its 10-second countdown elapses (or the
/// user clicks "Resume now"). Until this fires, no position posts go out, so
/// the user can still cancel without leaving footprints on phpVMS.
#[tauri::command]
async fn flight_resume_confirm(
    app: AppHandle,
    state: tauri::State<'_, AppState>,
) -> Result<(), UiError> {
    let flight = {
        let guard = state.active_flight.lock().expect("active_flight lock");
        guard
            .as_ref()
            .cloned()
            .ok_or_else(|| UiError::new("no_active_flight", "no flight to resume"))?
    };
    let client = current_client(&state)?;
    // v0.12.5 (Spec docs/spec/v0.12.5-divert-and-manual-pirep.md, LE9):
    // NICHT mehr bedingungslos scharfschalten. Bisher spawnte
    // flight_resume_confirm Streamer/phpVMS-Worker/Sampler sofort — nach
    // einem App-/Mac-Neustart mitten im Flug lief der Flug damit OHNE
    // Simulator (eingefrorene Stats wurden an phpVMS gepostet). Stattdessen
    // wartet ein Sim-Gate-Task auf einen FRISCHEN Sim-Snapshot und schaltet
    // erst dann scharf. `was_just_resumed` bleibt true bis dahin → die UI
    // zeigt weiter den Resume-/Warte-Zustand statt einen scheinbar laufenden
    // Flug. Sim-agnostisch (X-Plane + MSFS via `current_snapshot`).
    spawn_resume_sim_gate(app, Arc::clone(&flight), client);
    Ok(())
}

/// v0.12.5 (LE9): Resume-Sim-Gate. Wartet nach einem Flight-Resume auf
/// einen frischen Sim-Snapshot (≤ `SIM_GATE_FRESH_SECS`) und schaltet den
/// Flug erst dann scharf — Streamer + phpVMS-Worker + Touchdown-Sampler.
/// Bis dahin: kein Streaming, kein phpVMS-Post. Bricht ab, wenn der Flug
/// nicht mehr aktiv ist (Cancel/Forget/End) oder `stop` gesetzt wurde.
fn spawn_resume_sim_gate(app: AppHandle, flight: Arc<ActiveFlight>, client: Client) {
    tauri::async_runtime::spawn(async move {
        log_activity_handle(
            &app,
            ActivityLevel::Warn,
            "Warte auf Simulator — Flug wird scharfgeschaltet, sobald der Sim Daten liefert"
                .to_string(),
            Some(
                "Resume nach App-/Sim-Neustart: kein Streaming und kein phpVMS-Post, \
                 bis ein frischer Sim-Snapshot vorliegt."
                    .to_string(),
            ),
        );
        loop {
            // Flug abgebrochen / beendet / vergessen → Gate beenden.
            if flight.stop.load(Ordering::Relaxed) {
                tracing::info!(
                    pirep_id = %flight.pirep_id,
                    "resume sim-gate: flight stopped — exiting without arming"
                );
                return;
            }
            let still_active = {
                let st = app.state::<AppState>();
                let guard = st.active_flight.lock().expect("active_flight lock");
                guard
                    .as_ref()
                    .map(|f| f.pirep_id == flight.pirep_id)
                    .unwrap_or(false)
            };
            if !still_active {
                tracing::info!(
                    pirep_id = %flight.pirep_id,
                    "resume sim-gate: flight no longer active — exiting"
                );
                return;
            }
            // Frischer Snapshot vom aktuell gewählten Simulator?
            if let Some(snap) = current_snapshot(&app) {
                let age_secs = (Utc::now() - snap.timestamp).num_seconds();
                if age_secs.abs() <= SIM_GATE_FRESH_SECS {
                    // Sim liefert frische Daten → jetzt scharfschalten.
                    flight.was_just_resumed.store(false, Ordering::Relaxed);
                    spawn_phpvms_position_worker(
                        app.clone(),
                        Arc::clone(&flight),
                        client.clone(),
                    );
                    spawn_position_streamer(
                        app.clone(),
                        Arc::clone(&flight),
                        client.clone(),
                    );
                    spawn_touchdown_sampler(app.clone(), Arc::clone(&flight));
                    tracing::info!(
                        pirep_id = %flight.pirep_id,
                        age_secs,
                        "resume sim-gate: fresh sim snapshot — flight armed"
                    );
                    log_activity_handle(
                        &app,
                        ActivityLevel::Info,
                        "Simulator verbunden — Flug scharfgeschaltet".to_string(),
                        None,
                    );
                    return;
                }
            }
            tokio::time::sleep(Duration::from_secs(2)).await;
        }
    });
}

/// Drop local active-flight state without contacting phpVMS. Useful when the
/// stored PIREP is orphaned/dead on the server side and the user wants a
/// clean slate.
#[tauri::command]
async fn flight_forget(
    app: AppHandle,
    state: tauri::State<'_, AppState>,
) -> Result<(), UiError> {
    if let Some(flight) = state
        .active_flight
        .lock()
        .expect("active_flight lock")
        .take()
    {
        // v0.6.0: Outbox VOR stop=true leeren — siehe flight_cancel.
        flight.position_outbox.lock().expect("position_outbox lock").clear();
        flight.stop.store(true, Ordering::Relaxed);
        tracing::info!(pirep_id = %flight.pirep_id, "active flight forgotten (no phpVMS call)");
        discard_queued_positions_for(&app, &flight.pirep_id);
        record_event(
            &app,
            &flight.pirep_id,
            &FlightLogEvent::FlightEnded {
                timestamp: Utc::now(),
                pirep_id: flight.pirep_id.clone(),
                outcome: FlightOutcome::Forgotten,
            },
        );
    }
    clear_persisted_flight(&app);
    Ok(())
}

// ───────────────────────────────────────────────────────────────────
// v0.7.18 (B-011) Orphan-Flight-Cleanup
//
// Spec: docs/spec/v0.7.18-orphan-flight-cleanup.md
//
// Drei Tauri-Commands:
//   - flight_list_orphans       → IN_PROGRESS PIREPs des Piloten, ohne den
//                                 aktiven lokalen Flight
//   - flight_cancel_orphan      → cancel_pirep + optional delete_bid (mit
//                                 bid_id ODER flight_id Body) + lokale
//                                 Aufraeumung
//   - flight_forget_remote      → nur lokale Aufraeumung, kein API-Call
//
// v0.16.17 ergänzt zwei Dinge:
//   1. Alle Orphan-Konsumenten holen IN_PROGRESS-PIREPs jetzt über
//      `get_user_pireps_in_progress()` (server-seitiges `?state=0`) statt
//      fetch-then-filter über das paginierte `get_user_pireps()` (20/Seite,
//      newest first) — Orphans älter als ~20 Flüge waren vorher unsichtbar
//      (24 Leichen am 2026-06-13 manuell in Prod gelöscht).
//   2. Selbstheilung beim Flugstart: `sweep_stale_orphans_before_prefile`
//      räumt >24-h-alte Leichen automatisch ab, bevor ein neuer PIREP
//      geprefiled wird (siehe unten).
// ───────────────────────────────────────────────────────────────────

/// v0.16.17: Mindestalter, ab dem ein fremder IN_PROGRESS-PIREP beim
/// Flugstart automatisch gecancelt wird (Selbstheilung).
///
/// Warum 24 h: das schützt einen Piloten, der JETZT GERADE auf einem
/// zweiten PC fliegt — ein lebender Parallel-Flug hat zwingend ein
/// frisches `created_at` (Stunden, nicht Tage) und bleibt damit
/// unangetastet. Jüngere Orphans bleiben ebenfalls liegen: für die ist
/// der Resume-Banner-Flow (`flight_discover_resumable`) bzw. das manuelle
/// Clean-Up-Panel zuständig (unverändert).
const ORPHAN_AUTO_CLEANUP_MIN_AGE_HOURS: i64 = 24;

/// Pure Entscheidung: darf der Kandidaten-PIREP beim Flugstart automatisch
/// aufgeräumt (gecancelt) werden?
///
/// Regeln (konservativ — im Zweifel NICHT canceln):
///   - Kandidat == lokal aktiver/resumender Flug → false (nie anfassen)
///   - `created_at` fehlt oder unparsebar       → false (Alter nicht
///     beweisbar; der PIREP bleibt für Resume-Banner + Clean-Up-Panel
///     sichtbar, der Pilot entscheidet)
///   - Alter > [`ORPHAN_AUTO_CLEANUP_MIN_AGE_HOURS`] → true
fn should_auto_cleanup(
    created_at: Option<&str>,
    now: DateTime<Utc>,
    active_pirep_id: Option<&str>,
    candidate_id: &str,
) -> bool {
    if active_pirep_id == Some(candidate_id) {
        return false;
    }
    let Some(created) = created_at.and_then(|s| DateTime::parse_from_rfc3339(s).ok())
    else {
        return false;
    };
    now - created.with_timezone(&Utc)
        > chrono::Duration::hours(ORPHAN_AUTO_CLEANUP_MIN_AGE_HOURS)
}

/// v0.16.17 (Selbstheilung beim Flugstart): cancelt best-effort alle
/// verwaisten IN_PROGRESS-PIREPs älter als 24 h, BEVOR der neue PIREP
/// geprefiled wird. Vorher blieben solche Leichen liegen, bis ein Admin
/// sie löschte — der Pilot sah nur „aircraft not available".
///
/// Nimmt die bereits geholte IN_PROGRESS-Liste entgegen und gibt die
/// **Überlebenden** zurück, damit der Aufrufer seinen Adopt-/Collision-
/// Check auf demselben Fetch fahren kann (kein zweiter API-Call).
///
/// Fehlerphilosophie: jeder Cancel ist best-effort. Ein Fehlschlag wird
/// geloggt, der PIREP bleibt in der Überlebenden-Liste (→ weiterhin im
/// Clean-Up-Panel sichtbar / ggf. adoptierbar) — die Selbstheilung darf
/// den Flugstart NIEMALS blockieren.
async fn sweep_stale_orphans_before_prefile(
    app: &AppHandle,
    client: &Client,
    in_progress: Vec<api_client::PirepSummary>,
) -> Vec<api_client::PirepSummary> {
    // Geschützt: der lokal aktive Flug ODER ein Disk-Resume-Kandidat, den
    // try_resume_flight noch einsammeln will. Beim Flugstart ist
    // active_flight praktisch immer None (der Guard im Command hätte sonst
    // schon abgebrochen), aber der Check kostet nichts; der Disk-Kandidat
    // dagegen ist real — sein PIREP gehört dem Resume-Flow.
    let protected: Option<String> = {
        let state = app.state::<AppState>();
        let guard = state.active_flight.lock().expect("active_flight lock");
        guard.as_ref().map(|f| f.pirep_id.clone())
    }
    .or_else(|| read_persisted_flight(app).map(|p| p.pirep_id));

    let now = Utc::now();
    let mut survivors = Vec::with_capacity(in_progress.len());
    for p in in_progress {
        if !should_auto_cleanup(p.created_at.as_deref(), now, protected.as_deref(), &p.id) {
            survivors.push(p);
            continue;
        }
        match client.cancel_pirep(&p.id).await {
            Ok(()) => {
                // Alter ist hier immer parsebar — should_auto_cleanup hätte
                // sonst false geliefert. Fallback trotzdem defensiv.
                let alter = p
                    .created_at
                    .as_deref()
                    .and_then(|s| DateTime::parse_from_rfc3339(s).ok())
                    .map(|dt| {
                        let h = (now - dt.with_timezone(&Utc)).num_hours();
                        if h >= 48 {
                            format!("{} Tage alt", h / 24)
                        } else {
                            format!("{h} h alt")
                        }
                    })
                    .unwrap_or_else(|| "Alter unbekannt".to_string());
                let nr = p.flight_number.as_deref().unwrap_or("?");
                let dep = p.dpt_airport_id.as_deref().unwrap_or("?");
                let arr = p.arr_airport_id.as_deref().unwrap_or("?");
                log_activity_handle(
                    app,
                    ActivityLevel::Info,
                    format!(
                        "Verwaister Flug {nr} ({dep}→{arr}, {alter}) automatisch aufgeräumt"
                    ),
                    Some(format!(
                        "PIREP {} server-seitig gecancelt (Selbstheilung beim Flugstart)",
                        p.id
                    )),
                );
            }
            Err(e) => {
                tracing::warn!(
                    pirep_id = %p.id,
                    error = %e,
                    "auto-cleanup: cancel_pirep failed — orphan bleibt liegen, Flugstart läuft weiter"
                );
                survivors.push(p);
            }
        }
    }
    survivors
}

#[cfg(test)]
mod orphan_auto_cleanup_tests {
    use super::*;

    fn now() -> DateTime<Utc> {
        DateTime::parse_from_rfc3339("2026-06-13T12:00:00+00:00")
            .unwrap()
            .with_timezone(&Utc)
    }

    /// Älter als 24 h → aufräumen.
    #[test]
    fn cleans_up_orphan_older_than_24h() {
        assert!(should_auto_cleanup(
            Some("2026-06-12T11:00:00+00:00"), // 25 h alt
            now(),
            None,
            "pirep_old",
        ));
    }

    /// Frischer Orphan (< 24 h) → liegen lassen (Resume-Banner-Flow).
    #[test]
    fn keeps_fresh_orphan() {
        assert!(!should_auto_cleanup(
            Some("2026-06-13T10:00:00+00:00"), // 2 h alt
            now(),
            None,
            "pirep_fresh",
        ));
    }

    /// Exakt 24 h → noch NICHT aufräumen (strikt „älter als").
    #[test]
    fn keeps_orphan_at_exactly_24h() {
        assert!(!should_auto_cleanup(
            Some("2026-06-12T12:00:00+00:00"),
            now(),
            None,
            "pirep_boundary",
        ));
    }

    /// Kandidat == lokal aktiver/resumender Flug → nie anfassen,
    /// egal wie alt.
    #[test]
    fn never_touches_active_pirep() {
        assert!(!should_auto_cleanup(
            Some("2026-06-01T00:00:00+00:00"), // uralt
            now(),
            Some("pirep_active"),
            "pirep_active",
        ));
    }

    /// created_at fehlt → konservativ liegen lassen.
    #[test]
    fn keeps_orphan_without_created_at() {
        assert!(!should_auto_cleanup(None, now(), None, "pirep_no_ts"));
    }

    /// created_at unparsebar → konservativ liegen lassen.
    #[test]
    fn keeps_orphan_with_unparseable_created_at() {
        assert!(!should_auto_cleanup(
            Some("gestern Mittag"),
            now(),
            None,
            "pirep_bad_ts",
        ));
    }

    /// Anderer PIREP als der aktive, alt genug → aufräumen (der
    /// active-Schutz greift nur bei ID-Gleichheit).
    #[test]
    fn cleans_up_old_orphan_while_other_flight_is_active() {
        assert!(should_auto_cleanup(
            Some("2026-06-10T00:00:00+00:00"),
            now(),
            Some("pirep_active"),
            "pirep_other",
        ));
    }
}

#[derive(Debug, Clone, Serialize)]
pub struct OrphanFlight {
    pub pirep_id: String,
    pub bid_id: Option<i64>,
    /// phpVMS `flight_id` (alphanumerisch, z.B. "flightid_1") — wird
    /// fuer den `{ flight_id }`-Fallback-Body in `delete_bid` benutzt.
    pub flight_id: Option<String>,
    pub flight_number: Option<String>,
    pub airline_id: Option<i64>,
    pub dpt_airport: Option<String>,
    pub arr_airport: Option<String>,
    pub aircraft_id: Option<i64>,
    pub aircraft_icao: Option<String>,
    pub aircraft_registration: Option<String>,
    /// ISO-8601 UTC timestamp from phpVMS `created_at`. Frontend
    /// konvertiert zu „vor X h Y min".
    pub started_at: Option<String>,
    /// Berechnet vom Backend wenn `started_at` gesetzt ist, sonst None.
    pub age_minutes: Option<i64>,
}

/// `flight_list_orphans` — listet verwaiste PIREPs (state=IN_PROGRESS)
/// auf phpVMS, ohne den lokal aktiven Flight (falls vorhanden).
///
/// Spec: docs/spec/v0.7.18-orphan-flight-cleanup.md §B-011.
#[tauri::command]
async fn flight_list_orphans(
    state: tauri::State<'_, AppState>,
) -> Result<Vec<OrphanFlight>, UiError> {
    let client = current_client(&state)?;

    // Aktiv-Flight-PIREP-ID (falls vorhanden) — diesen filtern wir raus.
    let active_pirep_id: Option<String> = {
        let guard = state.active_flight.lock().expect("active_flight lock");
        guard.as_ref().map(|f| f.pirep_id.clone())
    };

    // 1) IN_PROGRESS-PIREPs holen — v0.16.17: server-seitig gefiltert
    //    (?state=0). Vorher fetch-then-filter über das paginierte
    //    get_user_pireps() (20/Seite, newest first) — Orphans älter als
    //    ~20 Flüge waren im Clean-Up-Panel unsichtbar (24 Leichen am
    //    2026-06-13 manuell in Prod gelöscht).
    let all_pireps = client.get_user_pireps_in_progress().await.map_err(|e| {
        tracing::warn!(error = %e, "flight_list_orphans: get_user_pireps_in_progress failed");
        UiError::from(e)
    })?;
    let in_progress: Vec<_> = all_pireps
        .into_iter()
        .filter(|p| p.state == Some(0)) // defensiv — Server hat bereits gefiltert
        .filter(|p| {
            active_pirep_id
                .as_deref()
                .map(|active| active != p.id)
                .unwrap_or(true)
        })
        .collect();

    if in_progress.is_empty() {
        return Ok(Vec::new());
    }

    // 2) Bids holen fuer Cross-Reference (bid_id / flight_id zu PIREPs zuordnen).
    //    Best-Effort: wenn Bids-API failt, machen wir die Liste ohne Bid-Info.
    let bids = client.get_bids().await.unwrap_or_else(|e| {
        tracing::info!(error = %e, "flight_list_orphans: get_bids failed — continuing without bid info");
        Vec::new()
    });

    // 3) Fleet-Lookup-Map fuer Aircraft-ICAO + Registration via aircraft_id.
    //    Auch best-effort.
    let fleet = client.get_fleet().await.unwrap_or_else(|e| {
        tracing::info!(error = %e, "flight_list_orphans: get_fleet failed — continuing without aircraft info");
        Vec::new()
    });
    let aircraft_lookup: std::collections::HashMap<i64, (Option<String>, Option<String>)> = fleet
        .iter()
        .flat_map(|sf| sf.aircraft.iter())
        .map(|ac| (ac.id, (ac.icao.clone(), ac.registration.clone())))
        .collect();

    // 4) OrphanFlight bauen
    let now = Utc::now();
    let orphans: Vec<OrphanFlight> = in_progress
        .into_iter()
        .map(|p| {
            // Bid-Match via flight_id (PirepSummary.flight_id ↔ Bid.flight.id).
            // Bid.flight.id ist canonical String, PirepSummary.flight_id ist
            // Option<String>.
            let matching_bid = bids.iter().find(|b| {
                p.flight_id
                    .as_ref()
                    .map(|fid| &b.flight.id == fid)
                    .unwrap_or(false)
            });

            // Aircraft-Anreicherung: erst aus PIREP-Summary direkt
            // probieren, dann Fleet-Lookup als Fallback.
            let (aircraft_icao, aircraft_registration) = if p.aircraft_icao.is_some()
                || p.aircraft_registration.is_some()
            {
                (p.aircraft_icao.clone(), p.aircraft_registration.clone())
            } else if let Some(aid) = p.aircraft_id {
                aircraft_lookup
                    .get(&aid)
                    .cloned()
                    .unwrap_or((None, None))
            } else {
                (None, None)
            };

            // Age berechnen wenn created_at parsebar ist
            let (started_at, age_minutes) = match p
                .created_at
                .as_deref()
                .and_then(|s| DateTime::parse_from_rfc3339(s).ok())
            {
                Some(dt) => {
                    let utc_dt = dt.with_timezone(&Utc);
                    let age = (now - utc_dt).num_minutes();
                    (Some(utc_dt.to_rfc3339()), Some(age))
                }
                None => (p.created_at.clone(), None),
            };

            OrphanFlight {
                pirep_id: p.id.clone(),
                bid_id: matching_bid.map(|b| b.id),
                flight_id: p.flight_id.clone(),
                flight_number: p.flight_number.clone(),
                airline_id: p.airline_id,
                dpt_airport: p.dpt_airport_id.clone(),
                arr_airport: p.arr_airport_id.clone(),
                aircraft_id: p.aircraft_id,
                aircraft_icao,
                aircraft_registration,
                started_at,
                age_minutes,
            }
        })
        .collect();

    Ok(orphans)
}

/// `flight_cancel_orphan` — cancelt einen verwaisten PIREP server-side
/// und droppt optional den dazugehoerigen Bid.
///
/// Spec: docs/spec/v0.7.18-orphan-flight-cleanup.md §B-011 Backend-API.
#[tauri::command]
async fn flight_cancel_orphan(
    app: AppHandle,
    state: tauri::State<'_, AppState>,
    pirep_id: String,
    bid_id: Option<i64>,
    flight_id: Option<String>,
) -> Result<(), UiError> {
    let client = current_client(&state)?;

    // Sicherheits-Check: NICHT den aktiv laufenden Flight versehentlich
    // ueber den Orphan-Pfad cancellen. Der hat `flight_cancel`.
    {
        let guard = state.active_flight.lock().expect("active_flight lock");
        if let Some(active) = guard.as_ref() {
            if active.pirep_id == pirep_id {
                return Err(UiError::new(
                    "is_active_flight",
                    "Dieser PIREP ist der aktive Flug — benutze stattdessen den Cancel-Knopf im Cockpit-Tab.",
                ));
            }
        }
    }

    // 1) PIREP cancellen
    match client.cancel_pirep(&pirep_id).await {
        Ok(()) => {
            tracing::info!(pirep_id = %pirep_id, "orphan PIREP cancelled");
        }
        Err(ApiError::NotFound) => {
            // PIREP ist serverseitig schon weg — kein Problem, weiter.
            tracing::info!(
                pirep_id = %pirep_id,
                "orphan PIREP already gone on server (404) — continuing to bid cleanup"
            );
        }
        Err(ApiError::Unauthenticated) | Err(ApiError::Forbidden) => {
            return Err(UiError::new(
                "blocked",
                "phpVMS lehnt deine Anfragen ab — Account gesperrt oder inaktiv. VA-Admin kontaktieren.",
            ));
        }
        Err(e) => {
            tracing::warn!(pirep_id = %pirep_id, error = %e, "cancel_pirep failed");
            return Err(e.into());
        }
    }

    // 2) Bid droppen — nur wenn bid_id ODER flight_id vorhanden ist.
    if bid_id.is_some() || flight_id.is_some() {
        match client.delete_bid(bid_id, flight_id.as_deref()).await {
            Ok(()) => {
                tracing::info!(
                    bid_id = ?bid_id,
                    flight_id = ?flight_id,
                    "orphan bid dropped"
                );
            }
            Err(ApiError::NotFound) => {
                // Bid schon weg — ok
                tracing::info!(bid_id = ?bid_id, "orphan bid already gone on server (404)");
            }
            Err(e) => {
                // PIREP-Cancel war erfolgreich, Bid-Drop nicht — Pilot kann
                // den Bid via phpVMS-UI manuell loeschen. Aircraft sollte
                // schon durch cancel_pirep frei sein.
                tracing::warn!(
                    bid_id = ?bid_id,
                    flight_id = ?flight_id,
                    error = %e,
                    "delete_bid failed after orphan PIREP cancel — Aircraft sollte trotzdem frei sein"
                );
            }
        }
    }

    // 3) Lokale Aufraeumung. Wichtig: NICHT den aktiven Flight anfassen
    // (Sicherheits-Check oben hat schon verhindert dass das hier der
    // aktive PIREP wird).
    discard_queued_positions_for(&app, &pirep_id);
    pirep_queue::remove(&app, &pirep_id);

    log_activity(
        &state,
        ActivityLevel::Warn,
        format!("Verwaister Flug abgebrochen — PIREP {pirep_id}"),
        Some(format!(
            "PIREP cancelled, Bid {:?} dropped, lokale Queues bereinigt.",
            bid_id
        )),
    );
    record_event(
        &app,
        &pirep_id,
        &FlightLogEvent::FlightEnded {
            timestamp: Utc::now(),
            pirep_id: pirep_id.clone(),
            outcome: FlightOutcome::Cancelled,
        },
    );

    Ok(())
}

/// `flight_forget_remote` — lokale Aufraeumung ohne phpVMS-Call.
/// Fuer Faelle wo `cancel_pirep` mit 404 antwortet aber der Pilot
/// sicher ist dass der PIREP wirklich weg ist.
///
/// Spec: docs/spec/v0.7.18-orphan-flight-cleanup.md §B-011.
#[tauri::command]
async fn flight_forget_remote(
    app: AppHandle,
    state: tauri::State<'_, AppState>,
    pirep_id: String,
) -> Result<(), UiError> {
    // Selbe Sicherheit wie `flight_cancel_orphan`: nicht den aktiven
    // Flight versehentlich anfassen.
    {
        let guard = state.active_flight.lock().expect("active_flight lock");
        if let Some(active) = guard.as_ref() {
            if active.pirep_id == pirep_id {
                return Err(UiError::new(
                    "is_active_flight",
                    "Dieser PIREP ist der aktive Flug — benutze stattdessen den Forget-Knopf im Cockpit-Tab.",
                ));
            }
        }
    }

    discard_queued_positions_for(&app, &pirep_id);
    pirep_queue::remove(&app, &pirep_id);

    log_activity(
        &state,
        ActivityLevel::Info,
        format!("Verwaister Flug lokal vergessen — PIREP {pirep_id}"),
        Some("Keine Server-Anfrage gemacht. PIREP-Status auf phpVMS unveraendert.".to_string()),
    );

    Ok(())
}

/// Spec sim-disconnect-auto-resume F1 (Auto-Resume) + F2 (Akkumulator)
/// + F3 (Block-Time-Korrektur).
///
/// Zentraler Resume-Helper. Wird von zwei Pfaden aufgerufen:
///   1. Streamer-Loop wenn ein Sim-Snapshot wieder verfuegbar ist
///      und `paused_since.is_some()` — *Auto-Resume*.
///   2. Tauri-Command `flight_resume_after_disconnect` wenn der
///      Pilot manuell den Pause-Button klickt — *Manual-Resume*.
///
/// Beide Pfade laufen durch denselben Code damit:
///   - Pause-Segmente und `pause_total_duration_secs` konsistent
///     akkumuliert werden (= Block-/Flight-Time-Korrektur in der
///     PIREP-Berechnung greift egal welcher Resume-Weg)
///   - `last_lat`/`last_lon` IMMER auf None gesetzt werden, damit
///     Reposition-Distanz nicht ins `distance_nm` einlaeuft
///   - Activity-Log und JSONL gleichen Inhalt sehen
///
/// Returns das fertige `PauseSegment` (falls Pause wirklich aktiv war)
/// — oder None wenn `paused_since.is_none()` (= nichts zu tun).
fn apply_pause_resume(
    app: &AppHandle,
    flight: &Arc<ActiveFlight>,
    current_snap: Option<&SimSnapshot>,
    reason: PauseReason,
) -> Option<PauseSegment> {
    let now = Utc::now();
    let (started_at, last_known) = {
        let stats = flight.stats.lock().expect("flight stats");
        let start = stats.paused_since?;
        (start, stats.paused_last_known.clone())
    };

    let duration_secs = (now - started_at).num_seconds().max(0);
    // MVP Toggle-Debounce: Pausen unter 1s nicht im Akkumulator
    // verbuchen — verhindert dass eine Esc-Esc-Sequenz oder ein
    // einzelner verlorener Snapshot-Tick die Statistik verfaelscht.
    // Der Pause-State wird trotzdem geclearet.
    let count_toward_accumulator = duration_secs >= 1;

    // Drift-Werte berechnen (None wenn entweder Side fehlt).
    let (drift_nm, alt_delta_ft, fuel_delta_kg) = match (&last_known, current_snap) {
        (Some(prev), Some(cur)) => {
            let d_m = ::geo::distance_m(prev.lat, prev.lon, cur.lat, cur.lon);
            let nm = d_m / 1852.0;
            let alt = (cur.altitude_msl_ft - prev.altitude_ft).abs();
            let fuel = (cur.fuel_total_kg as f64 - prev.fuel_total_kg as f64).abs();
            (Some(nm), Some(alt), Some(fuel))
        }
        _ => (None, None, None),
    };

    let segment = PauseSegment {
        started_at,
        ended_at: now,
        duration_secs,
        reason,
        drift_nm,
        altitude_delta_ft: alt_delta_ft,
        fuel_delta_kg,
    };

    {
        let mut stats = flight.stats.lock().expect("flight stats");
        if count_toward_accumulator {
            stats.pause_total_duration_secs =
                stats.pause_total_duration_secs.saturating_add(duration_secs);
            stats.pause_segments.push(segment.clone());
        }
        stats.paused_since = None;
        stats.paused_last_known = None;
        stats.current_pause_reason = None;
        // Reposition-Distanz darf nicht in distance_nm einlaufen —
        // last_lat/lon auf None setzt die Distanz-Baseline neu, der
        // naechste Tick startet frisch (entspricht dem alten Verhalten
        // von flight_resume_after_disconnect).
        stats.last_lat = None;
        stats.last_lon = None;
    }
    save_active_flight(app, flight);

    // Activity-Log mit Drift-Stufen aus v0.4-MVP-Spec:
    //   < 1 NM  : Info ohne Drift-Suffix
    //   1-50 NM : Info "repositioniert X nm"
    //   50-200  : Warn "auffaellige Reposition X nm"
    //   > 200   : Warn "Sehr grosse Reposition X nm — pruefe ob der richtige Flug geladen ist"
    //
    // KEIN Drift-Level blockiert Resume (Spec-Prinzip P2: informieren
    // statt blockieren). Der Pilot kann ueber PIREP-Cancel-UI
    // korrigieren wenn er einen falschen Flug erwischt hat.
    let auto_prefix = match reason {
        PauseReason::SimDisconnect => "▶ Flug automatisch fortgesetzt",
        PauseReason::SimPause => "▶ Sim-Pause beendet — Flug fortgesetzt",
        PauseReason::ManualResume => "▶ Flug wiederaufgenommen",
    };
    let (level, msg) = match drift_nm {
        Some(d) if d > RESUME_DRIFT_EXTREME_NM => (
            ActivityLevel::Warn,
            format!(
                "{auto_prefix} — Sehr grosse Reposition {:.1} nm. Pruefe ob der richtige Flug geladen ist.",
                d
            ),
        ),
        Some(d) if d > RESUME_DRIFT_WARN_NM => (
            ActivityLevel::Warn,
            format!("{auto_prefix} — Auffaellige Reposition {:.1} nm", d),
        ),
        Some(d) if d > RESUME_DRIFT_TOAST_NM => (
            ActivityLevel::Info,
            format!("{auto_prefix} — Repositioniert {:.1} nm", d),
        ),
        Some(_) => (ActivityLevel::Info, auto_prefix.to_string()),
        None => (ActivityLevel::Info, auto_prefix.to_string()),
    };
    let detail = match (&last_known, current_snap) {
        (Some(prev), Some(cur)) => Some(format!(
            "Pause-Dauer: {} s\nVorher: LAT {:.4}° · LON {:.4}° · ALT {:.0} ft\nJetzt:  LAT {:.4}° · LON {:.4}° · ALT {:.0} ft",
            duration_secs, prev.lat, prev.lon, prev.altitude_ft,
            cur.lat, cur.lon, cur.altitude_msl_ft,
        )),
        _ => Some(format!("Pause-Dauer: {} s", duration_secs)),
    };
    log_activity_handle(app, level, msg, detail);

    // Spec v0.7.15 F7: Aircraft-Change-Detection nach Resume.
    //
    // Wenn der Sim-Snapshot nach Resume ein anderes Flugzeug-ICAO
    // meldet als der aktive Flug erwartet, ist das ein starkes
    // Signal "falsches Bid geladen". Beispiel: Pilot loadet
    // versehentlich aus dem MSFS-Menue die A320 statt der B738
    // die laut Bid eingetragen ist.
    //
    // Wir blockieren NICHT (Spec-Prinzip P2: informieren statt
    // blockieren) — aber Warnung im Activity-Log mit konkretem
    // Mismatch-Hinweis. Der Pilot kann ueber das normale Bid/PIREP-
    // Cancel-UI korrigieren wenn das wirklich der falsche Flug ist.
    //
    // Vergleich gegen `flight.aircraft_icao` (= Bid-Wert), nicht
    // gegen `paused_last_known.aircraft_icao` — der Bid-Wert ist
    // die "Wahrheit" was geflogen werden soll. Wenn das Pre-Pause-
    // Aircraft schon falsch war, hat das Activity-Log das beim
    // Flug-Start schon protokolliert.
    //
    // Sim-Coverage:
    //   - MSFS: aircraft_icao kommt aus SimConnect (ATC MODEL/ATC ID-
    //     Pfad in crates/sim-msfs/src/adapter/telemetry.rs)
    //   - X-Plane: aircraft_icao kommt aus der X-Plane Web-API ab
    //     v12.1 (sim/aircraft/view/acf_ICAO, siehe
    //     crates/sim-xplane/src/web_api.rs + adapter.rs:264). Wenn
    //     der Pilot die Web-API NICHT in X-Plane → Settings → Network
    //     aktiviert hat, ist `aircraft_icao=None` und F7 ueberspringt
    //     die Pruefung still (= keine falsch-positiven Warnungen).
    //
    // v0.15.12: alias-BEWUSSTER Check. Vorher war das ein stumpfer
    // `snap_icao != bid_icao` Direktvergleich, der WEDER die hardcoded
    // `aircraft_aliases()`-Tabelle NOCH die VPS-gepflegten Aliase las.
    // Folge: Falsch-Warnungen nach Resume trotz passendem Alias (Sim
    // „PHENOM30" vs Bid „E55P"; „B738" vs „B737" — Letzteres feuerte
    // sogar obwohl es in der hardcoded Tabelle steht). Jetzt nutzt der
    // Resume-Check denselben gemeinsamen Helper wie der flight_start-
    // Gate + der Auto-Start-Watcher (`aircraft_type_matches_sim` mit
    // `clean_atc_model`-Normalisierung + Title-Substring-Fallback + VPS-
    // Aliasen), sodass „Alias im Recorder-Admin pflegen → überall ruhig"
    // konsistent gilt. Bleibt eine reine WARNUNG (Prinzip P2: informieren
    // statt blockieren). Sync-Pfad: kein Alias-Refresh nötig — die Aliase
    // wurden beim flight_start (vor jeder Pause) bereits in den State
    // geladen; wir lesen nur den aktuellen Snapshot.
    if let Some(cur) = current_snap {
        let bid_icao = flight.aircraft_icao.trim().to_uppercase();
        let sim_icao = cur.aircraft_icao.as_deref().and_then(clean_atc_model);
        if let (false, Some(actual)) = (bid_icao.is_empty(), sim_icao.as_deref()) {
            let vps_aliases = app
                .state::<AppState>()
                .aircraft_aliases_vps
                .lock()
                .expect("aircraft_aliases_vps lock")
                .clone();
            let sim_title = cur.aircraft_title.as_deref().unwrap_or("");
            if !aircraft_type_matches_sim(
                Some(bid_icao.as_str()),
                Some(actual),
                sim_title,
                &vps_aliases,
            ) {
                log_activity_handle(
                    app,
                    ActivityLevel::Warn,
                    format!(
                        "⚠ Aircraft-Mismatch nach Resume: Sim meldet {}, Bid erwartet {}",
                        actual, bid_icao
                    ),
                    Some(format!(
                        "Falls du wirklich ein anderes Flugzeug laedst, cancel den aktuellen PIREP \
                         und starte einen neuen Flug mit dem passenden Bid. Andernfalls lade im Sim \
                         das richtige Flugzeug nach (Bid-ICAO: {bid_icao}). Ist es derselbe Flieger \
                         und der Sim meldet nur einen anderen Typ-String, pflege im Recorder-Admin \
                         einen Aircraft-Alias {bid_icao} → {actual}."
                    )),
                );
                tracing::warn!(
                    pirep_id = %flight.pirep_id,
                    snap_icao = %actual,
                    bid_icao = %bid_icao,
                    "aircraft mismatch detected after pause-resume"
                );
            }
        }
    }

    tracing::info!(
        pirep_id = %flight.pirep_id,
        duration_secs,
        drift_nm = ?drift_nm,
        reason = ?reason,
        "pause resume applied"
    );

    Some(segment)
}

/// v0.4.1: Pilot klickt „Flug wiederaufnehmen" nachdem der Sim wegbrach
/// und neu positioniert wurde. Hebt den Pause-State in den FlightStats auf
/// — der Streamer fängt im nächsten Tick wieder an Position-Posts an
/// phpVMS zu schicken, der Phase-FSM nimmt die Verarbeitung auf den
/// neuen Sim-Werten wieder auf.
///
/// Loggt eine Repositions-Audit-Zeile mit der Distanz zwischen letzter
/// bekannter Position (vor Disconnect) und der aktuellen Sim-Position
/// (nach Reposition). Bei großen Sprüngen (> REPOSITION_WARN_DELTA_NM)
/// als WARN-Level damit's bei VA-Audits sichtbar bleibt.
///
/// Bewusst KEINE 5-NM/2000-ft-Restriktion wie bei smartCARS — der Pilot
/// entscheidet wo er weitermacht, der Audit-Log macht's nachvollziehbar.
#[tauri::command]
async fn flight_resume_after_disconnect(
    app: AppHandle,
    state: tauri::State<'_, AppState>,
) -> Result<(), UiError> {
    let flight = state
        .active_flight
        .lock()
        .expect("active_flight lock")
        .as_ref()
        .map(Arc::clone)
        .ok_or_else(|| UiError::new("no_active_flight", "no flight is active"))?;

    // Pre-Check: Pause-State muss aktiv sein, sonst UI-Fehler zurueck.
    // Der Helper unten returnt sonst nur None und der Caller wuesste
    // nicht warum nichts passierte.
    if flight
        .stats
        .lock()
        .expect("flight stats")
        .paused_since
        .is_none()
    {
        return Err(UiError::new(
            "not_paused",
            "flight is not currently paused — nothing to resume",
        ));
    }

    // Read the current sim snapshot (best-effort) for the delta calculation.
    let current_snap = current_snapshot(&app);

    // Spec sim-disconnect-auto-resume: Manual-Resume nutzt denselben
    // Code-Pfad wie Auto-Resume. Pause-Segment wird akkumuliert,
    // last_lat/lon zurueckgesetzt, Activity-Log geschrieben.
    let _segment = apply_pause_resume(
        &app,
        &flight,
        current_snap.as_ref(),
        PauseReason::ManualResume,
    );
    // state ist nur fuer den Tauri-Command-Signatur-Erhalt da — der
    // Helper schreibt das Activity-Log via log_activity_handle, was
    // den State-aware-Pfad ueberbrueckt.
    let _ = state;
    Ok(())
}

/// Spawn the background task that pushes the latest sim snapshot to phpVMS at
/// `POSITION_INTERVAL_SECS`. Stops when `flight.stop` is set or the active
/// flight is replaced.
///
/// CAS-guarded: at most one streamer task per ActiveFlight. Repeat calls are
/// no-ops, which makes it safe to invoke from multiple UI paths
/// (`flight_resume_confirm` racing with itself, StrictMode double-mount, etc.).
/// Spawn a high-rate (~30 Hz) sampler dedicated to populating the
/// touchdown ring buffer in `FlightStats`. Runs alongside the
/// position streamer (which posts to phpVMS at 1–30 s cadence,
/// way too slow for sub-second touchdown capture).
///
/// The actual telemetry rate is bounded by SimConnect's
/// `SIMCONNECT_PERIOD_VISUAL_FRAME` updates (~30 Hz typical) and
/// the adapter worker's 50 ms drain sleep — so in practice the
/// buffer accumulates ~20 samples/second, which still gives 100
/// entries in the 5-second look-back window. That is more than
/// enough to capture the actual touchdown subframe instead of
/// the bounce rebound that the single 1 Hz sample was catching.
///
/// Exits when `flight.stop` is set, just like the streamer.
/// v0.5.23 Forensik-Upload. Spawnt einen async-Task der das per-Flug
/// JSONL-Logfile `<app_data>/flight_logs/<pirep_id>.jsonl` gzippt und an
/// aeroacars-live POSTet. Endpoint: `/api/flight-logs/upload`. Auth via
/// HTTP Basic gegen die provisioned_pilots-Tabelle (gleiche Cred-Pair wie
/// Mosquitto-MQTT-Login).
///
/// Failure-Modi (alle non-fatal):
///   * Log-Datei nicht vorhanden — z.B. Recording war disabled oder
///     PIREP wurde manuell gefilet ohne dass das Recorder-Modul den
///     Flug initialisiert hat. → tracing::debug, kein Retry.
///   * Keyring-Read fehlgeschlagen — auch non-fatal. Pilot kann beim
///     naechsten App-Start neu provisionieren.
///   * Server gibt non-2xx zurueck (401 / 403 / 5xx) — gelogged, keine
///     Retry-Queue heute (kann spaeter mit Pending-Folder kommen).
fn spawn_flight_log_upload(app: &AppHandle, pirep_id: String) {
    let app = app.clone();
    tauri::async_runtime::spawn(async move {
        // 1. Pfad zur JSONL-Datei zusammensetzen — gleiche Logik wie der
        //    Recorder selbst (sanitize_pirep_id).
        let app_data_dir = match app.path().app_data_dir() {
            Ok(d) => d,
            Err(e) => {
                tracing::warn!(error = %e, "log-upload: no app_data_dir");
                return;
            }
        };
        let safe_pirep = pirep_id
            .chars()
            .map(|c| if c.is_ascii_alphanumeric() || c == '-' || c == '_' { c } else { '_' })
            .collect::<String>();
        let log_path = app_data_dir
            .join("flight_logs")
            .join(format!("{safe_pirep}.jsonl"));
        if !log_path.exists() {
            tracing::debug!(path = ?log_path, "log-upload: file missing — skipping");
            return;
        }

        // 2. MQTT-Credentials aus Keyring (= identisch zu HTTP-Basic).
        let username = match secrets::load_api_key(MQTT_KEYRING_USERNAME) {
            Ok(Some(u)) => u,
            _ => {
                tracing::warn!("log-upload: no MQTT username in keyring — skip");
                return;
            }
        };
        let password = match secrets::load_api_key(MQTT_KEYRING_PASSWORD) {
            Ok(Some(p)) => p,
            _ => {
                tracing::warn!("log-upload: no MQTT password in keyring — skip");
                return;
            }
        };

        // 3. Hochladen.
        match aeroacars_mqtt::log_upload::upload_flight_log(
            &log_path,
            &pirep_id,
            &username,
            &password,
            None, // default endpoint = https://live.kant.ovh/api/flight-logs/upload
        ).await {
            Ok(stats) => {
                tracing::info!(
                    pirep_id = %pirep_id,
                    raw_kb = stats.raw_size / 1024,
                    gzip_kb = stats.compressed_size / 1024,
                    "flight log uploaded",
                );
                // v0.5.23: Pilot-UI-Feedback im Activity-Log damit der
                // Pilot sieht dass der Upload geklappt hat. Detail-Spalte
                // zeigt die Groessen-Statistik fuer Debugging.
                log_activity_handle(
                    &app,
                    ActivityLevel::Info,
                    "Flight log uploaded to live-tracking server",
                    Some(format!(
                        "{} KB raw → {} KB gzip ({}% Kompression)",
                        stats.raw_size / 1024,
                        stats.compressed_size / 1024,
                        ((stats.compressed_size as f64 / stats.raw_size as f64) * 100.0) as i32,
                    )),
                );
            }
            Err(e) => {
                tracing::warn!(
                    pirep_id = %pirep_id,
                    error = %e,
                    "flight log upload failed (non-fatal)",
                );
                // Fehler ist non-fatal — JSONL bleibt lokal verfuegbar.
                // Wir loggen mit ActivityLevel::Warn damit der Pilot
                // weiss dass Forensik-Upload nicht klappte (= bei
                // Bug-Reports den Pfad zur lokalen Datei nennen).
                log_activity_handle(
                    &app,
                    ActivityLevel::Warn,
                    "Flight log upload failed (non-fatal)",
                    Some(format!("{} — Log liegt lokal in flight_logs/{}.jsonl", e, pirep_id)),
                );
            }
        }
    });
}

/// v0.5.39: Helper um Felder aus dem landing_analysis-JSON-Value zu lesen.
/// Werden vom Touchdown-Payload-Builder benutzt damit wir nicht jedes Mal
/// die gleichen .get(...).and_then(...).map(...) Kette dranschreiben.
fn ana_f32(v: &Option<serde_json::Value>, key: &str) -> Option<f32> {
    v.as_ref()?.get(key)?.as_f64().map(|x| x as f32)
}
fn ana_i32(v: &Option<serde_json::Value>, key: &str) -> Option<i32> {
    v.as_ref()?.get(key)?.as_i64().map(|x| x as i32)
}
fn ana_u32(v: &Option<serde_json::Value>, key: &str) -> Option<u32> {
    v.as_ref()?.get(key)?.as_u64().map(|x| x as u32)
}
fn ana_bool(v: &Option<serde_json::Value>, key: &str) -> Option<bool> {
    v.as_ref()?.get(key)?.as_bool()
}
/// v0.12.3: String aus der Forensik-Analyse-Map (z. B. `scored_g_method`).
fn ana_str(v: &Option<serde_json::Value>, key: &str) -> Option<String> {
    Some(v.as_ref()?.get(key)?.as_str()?.to_string())
}

/// v0.12.3 (LE8): **der eine** Scored-G-Wert, den jeder Pfad eines
/// `FlightStats` nutzt — Touchdown-Klassifikation, Activity-/ACARS-Text,
/// MQTT-Touchdown-Payload und das `LandingScored`-Event.
///
/// Liest den EMA-geglätteten `scored_g` aus der Forensik-Analyse. Gibt es
/// kein Touchdown-Fenster (`landing_analysis` ist `None`), fällt der Wert
/// definiert auf den rohen Peak zurück (`raw_fallback`, LE8) — **kein**
/// Pfad bekommt je `None`/`0` an den Score.
fn score_g_for_stats(stats: &FlightStats) -> recorder::ScoredG {
    if let Some(scored) = ana_f32(&stats.landing_analysis, "scored_g") {
        let method = match ana_str(&stats.landing_analysis, "scored_g_method").as_deref() {
            Some("raw_fallback") => recorder::ScoredGMethod::RawFallback,
            _ => recorder::ScoredGMethod::EmaMax,
        };
        recorder::ScoredG {
            scored_g: scored,
            raw_peak: stats.landing_peak_g_force.unwrap_or(scored),
            method,
        }
    } else {
        recorder::scored_g_raw_fallback(stats.landing_peak_g_force.unwrap_or(0.0))
    }
}

// ======================================================================
// v0.16.22 — MSFS flare metric on the lag-free AGL-geometric V/S
// ======================================================================
//
// PROBLEM. The flare metric in `compute_landing_analysis` derives
// `peak_vs_pre` / `vs_at_flare_end` (window [-2000ms, -100ms]) from
// `s.vs_fpm`. On MSFS that field is the DISPLAY vertical-speed SimVar,
// which lags the airframe ~0.5-0.7 s through the flare (same lag the
// v0.16.21 touchdown de-lag corrects at the edge). So at -100 ms the
// SimVar still reflects the descent ~0.6 s earlier — BEFORE a late
// flare took effect — the reduction reads near zero and the metric
// reports "no flare" even when the pilot genuinely pulled.
//
// Proven on JBU323 (Fenix A320, MSFS2024): lagged peak -469 / end -440
// → reduction 30 fpm → flare_detected=FALSE. But the lag-free AGL-
// geometric derivative over the SAME window shows the real profile
// (pre-flare ~-569, mid-flare ~-370) → real reduction ~130-200 fpm; the
// pitch rose 2.5°→5.2°. The pilot DID flare — it was just late, so the
// aircraft still settled firm (edge -423, peak_g 1.43). The de-lag fix
// already credits the firmer-than-displayed *touchdown*; this fix
// credits the *flare* the lag hid, without softening the touchdown.
//
// THE FIX. For MSFS fixed-wing, compute `peak_vs_pre` / `vs_at_flare_
// end` from the AGL trace via a SMOOTHED LOCAL LINEAR FIT (least-squares
// slope of agl_ft over a ±MSFS_FLARE_AGL_FIT_HALF_WINDOW_MS window of
// samples) rather than raw consecutive-sample diffs (too noisy). The
// slope (ft/min) is the geometric sink at that instant — lag-free,
// because position/AGL is not the lagged SimVar. X-Plane (raw local_vy,
// far less lagged) and Other keep the existing `s.vs_fpm` path so their
// analysis output is byte-identical.
//
// WHY THE FIT IS NOISE-ROBUST. A single-sample AGL diff at 50 Hz is
// dominated by AGL quantization (MSFS reports AGL in ~0.5-0.6 ft steps).
// A least-squares slope over ±300 ms (typically 15-20 samples) averages
// that quantization out — the residual after the linear trend is the
// noise floor, and the slope is the trend. On the corpus the detection
// verdict is identical at half-windows of 250/300/350 ms for every
// flight (only JBU323's reduction MAGNITUDE moves, 116-207 fpm, all
// well above the 50 fpm threshold). We pick the STEEPEST fitted slope in
// the window as `peak_vs_pre`; on JBU323 that peak (-659) is supported
// by a plateau of neighbours in the -580..-660 band, not a lone spike.
//
// NO PHANTOM FLARES. The reduction is a REAL geometric reduction in the
// AGL trace, not a SimVar lag artifact. A firm landing with no real
// flare (DLH848: AGL slope flat at -382 across the window) yields
// reduction 0 → flare_detected=false, unchanged. The endpoint score
// still reflects the firm touchdown — we credit the reduction, never
// turn a firm landing soft.

/// Half-window (ms) of AGL samples used for each local linear-fit slope.
/// ±300 ms ≈ 15-20 samples at 50 Hz — wide enough to average out MSFS's
/// ~0.5 ft AGL quantization, narrow enough to resolve the flare's sink
/// reduction. Corpus-stable: detection verdict identical at 250/350 too.
const MSFS_FLARE_AGL_FIT_HALF_WINDOW_MS: i64 = 300;
/// Minimum airborne AGL samples inside a fit window for the slope to be
/// trusted. Below this the least-squares slope is too sensitive to a
/// single quantization step; we skip that time point.
const MSFS_FLARE_AGL_FIT_MIN_SAMPLES: usize = 4;
/// AGL above this (ft) at a fit point means we are not yet in the flare/
/// short-final geometry — the same guard the touchdown AGL estimator
/// uses for window-start. Keeps a high pre-flare descent out of the
/// flare-window slope set. Reuses TD_AGL_MAX_AT_WINDOW_START_FT.
const MSFS_FLARE_AGL_MAX_FT: f32 = TD_AGL_MAX_AT_WINDOW_START_FT;

// ─── v0.16.22 hardening: phantom-flare guards ────────────────────────────
//
// Adversarial QS found two phantom "butter" flares the bare AGL path
// produced. Both are DATA pathologies, not piloting:
//   • E195 MXY322 — the AGL trace FROZE at 9.96 ft for ~14 samples
//     (-466…-31 ms), so the flare-end fit slope read ~0 → vs_at_flare_end
//     ≈ 0 → reduction 742 → score 100, on a firm -315 fpm / 1.46 g arrival
//     with NOSE-DOWN pitch. The whole flare window had only 4 DISTINCT
//     agl_ft values.
//   • DA40 GSG2056 — touched at -1626 ms (on_ground=true, g 1.3),
//     ballooned ~2.4 ft, settled. The credited "reduction" was the
//     post-bounce settle, pitch -6° nose-DOWN at flare-end.
//
// A 316-landing VPS sweep + the local corpus drove the thresholds below.
// Gate 1 (data quality) + Gate 2 (bounce) suppress BOTH phantoms AND the
// near-frozen B738 (7 distinct) QS also flagged, while NOT touching any
// of 115 real flares (incl. JBU323, the FSLabs A321, the Baron 58P).
//
/// Gate 1a — minimum DISTINCT `agl_ft` values among the airborne flare-
/// window samples for the AGL geometry to be trusted. Below this the trace
/// is too coarse to differentiate (a step/plateau, not a slope). VPS data:
/// the only two flights under 8 in 316 landings are the two frozen
/// phantoms (4 and 7 distinct); the lowest REAL flare has 18 distinct —
/// a 2.25× margin. On reject we fall back to the SimVar path so no garbage
/// AGL endpoint is published.
const MSFS_FLARE_MIN_DISTINCT_AGL: usize = 8;
/// Gate 1b — maximum MEDIAN sample Δt (ms) inside the flare window. Above
/// this the effective rate is < ~16 Hz and a local slope is unreliable.
/// All healthy captures in the corpus sit at ~31 ms (32 Hz); this is a
/// safety net for genuinely degraded capture (it fires on none of the 316
/// — the frozen E195 still streamed at 31 ms, so distinct-count, not Δt,
/// is what catches it). Reject → SimVar fallback.
const MSFS_FLARE_MAX_MEDIAN_DT_MS: i64 = 60;
/// Gate 1c — minimum DISTINCT `agl_ft` values in the FLARE-END fit window
/// (±MSFS_FLARE_AGL_FIT_HALF_WINDOW_MS around flare_hi). This is the LOCAL
/// version of Gate 1a: it catches a freeze that corrupts ONLY the flare-
/// end slope while the rest of the window streamed fine. Such a freeze
/// reads vs_at_flare_end ≈ 0 from a plateau and INFLATES the reduction
/// (E195 phantom whole-window; vrNEVnl phantom mid-window with 25 distinct
/// overall, which Gate 1a misses; pVGZW real-but-corrupt — a genuine flare
/// whose AGL froze in the final ~360 ms so the AGL ENDPOINT is garbage and
/// the honest SimVar value should publish instead). VPS data: the three
/// frozen-end phantoms have 1-3 distinct values in the end-fit window; the
/// largest REAL flares (reduction 500+) have 8 — a clean 2× margin at 4.
const MSFS_FLARE_MIN_END_FIT_DISTINCT_AGL: usize = 4;
/// Gate 1c BACKSTOP — minimum AGL SPAN (ft) in the flare-END fit window
/// (±MSFS_FLARE_AGL_FIT_HALF_WINDOW_MS around flare_hi). The distinct-bucket
/// count above (Gate 1c) is fooled by a NOISY freeze: a trace that dithers
/// across ≥4 quantized 0.01 ft buckets while spanning near-zero TRUE height
/// passes the bucket count yet still reads vs_at_flare_end ≈ 0 from the flat
/// plateau → a huge fake reduction → phantom score-100. The span check is the
/// physics floor that bucket-counting cannot give: in the final ±300 ms a
/// REAL flare descends through real height. On the corpus the slowest REAL
/// flare-end (extra_y8Y5, end −95 fpm) covers ≈0.95 ft in that 600 ms window
/// and the JBU323/jbu322 flares span 4-6 ft; a frozen/near-frozen plateau
/// spans ~0. 0.3 ft sits an order of magnitude below the slowest real end
/// span yet an order of magnitude above quantization+jitter (~0.01-0.05 ft),
/// so it fires ONLY on a true plateau. Reject → SimVar fallback.
const MSFS_FLARE_MIN_END_AGL_SPAN_FT: f32 = 0.3;
/// Gate 2 — balloon tolerance (ft). If the airborne AGL trace rises by
/// more than this above a prior in-window minimum it is non-monotone (a
/// bounce/balloon), not a descent+flare. DA40 GSG2056 balloons ~2.4 ft;
/// every real flare in the corpus stays ≤ ~0.25 ft. Reject → SimVar
/// fallback. (An on_ground=true sample anywhere in the window is a
/// separate, unconditional bounce reject.)
const MSFS_FLARE_BALLOON_TOL_FT: f32 = 1.5;
/// Gate 3 — pitch-corroboration veto. `flare_detected` is additionally
/// withheld when the net pitch trend across the window is strongly
/// NOSE-DOWN (a settle/shed signature, not a pull). Tuned conservatively:
/// real held-attitude flares on the VPS show window pitch-deltas as low as
/// −0.6° (the pilot sets a flare attitude early and HOLDS it while the
/// sink decays in ground effect), so a positive "+Δ required" gate would
/// wrongly suppress real flares — Gates 1+2 are the primary phantom
/// defense. This veto only trips on a clear nose-down trend, below every
/// real flare observed, and is belt-and-suspenders for a future bounce
/// that somehow evades Gate 2.
const MSFS_FLARE_PITCH_NOSEDOWN_VETO_DEG: f32 = -1.0;
/// The flare-source detection floor (fpm of reduction). Kept at 50 (NOT
/// nudged to 60): the real FSLabs A321 flare in the QS set reduces 58.5
/// fpm and MUST stay detected, so 60 would drop a real marginal flare.
/// The fragile band is instead cleaned by Gates 1-3, which remove the
/// frozen/bounce members of that band without touching real soft flares.
const MSFS_FLARE_DETECT_FLOOR_FPM: f64 = 50.0;

/// Pitch-corrected AGL-geometric V/S (fpm, negative = descending) at the
/// time point `t_ms`, via a least-squares fit of `agl_ft` over the
/// airborne samples in `[t_ms ± MSFS_FLARE_AGL_FIT_HALF_WINDOW_MS]`.
///
/// `fit_hi_cap`: when `Some(cap)`, no sample at or after `cap` ms enters the
/// fit. v0.16.22 hardening: the end point (nearest flare_hi = edge−100 ms)
/// would otherwise reach edge+200 ms; on a touchdown-then-bounce the
/// post-edge airborne balloon has RISING AGL, which flattens/reverses the
/// end slope → an inflated reduction → phantom. Capping at `edge_ms` keeps
/// the end fit on the genuine pre-touchdown descent (a firm landing's
/// post-edge samples are on_ground and already excluded, so it is
/// unaffected). Pass `None` for an uncapped fit.
///
/// Lag-free: AGL/position is not the lagged display-VSI SimVar. Returns
/// `None` when fewer than `MSFS_FLARE_AGL_FIT_MIN_SAMPLES` qualifying
/// samples exist, the AGL is above `MSFS_FLARE_AGL_MAX_FT` at the point,
/// or the time spread is degenerate (all samples share one timestamp).
/// Pure + side-effect-free → unit-testable on every platform.
fn agl_geometric_vs_fpm_at(
    samples: &[TouchdownWindowSample],
    t_ms: i64,
    pitch_deg_at_t: f32,
    fit_hi_cap: Option<i64>,
) -> Option<f32> {
    let lo = t_ms - MSFS_FLARE_AGL_FIT_HALF_WINDOW_MS;
    let hi = t_ms + MSFS_FLARE_AGL_FIT_HALF_WINDOW_MS;
    // Least-squares slope of agl_ft (y) over time-offset in ms (x,
    // centred on t_ms so the numbers stay small). Only airborne samples
    // near the ground — a high sample would be pre-flare descent.
    let mut n = 0_usize;
    let mut sx = 0.0_f64;
    let mut sy = 0.0_f64;
    let mut sxx = 0.0_f64;
    let mut sxy = 0.0_f64;
    for s in samples {
        let ts = s.at.timestamp_millis();
        if ts < lo || ts > hi || s.on_ground {
            continue;
        }
        // Do not let the fit cross the touchdown moment (post-edge balloon
        // would corrupt the end slope on a bounce).
        if let Some(cap) = fit_hi_cap {
            if ts >= cap {
                continue;
            }
        }
        if s.agl_ft > MSFS_FLARE_AGL_MAX_FT || !s.agl_ft.is_finite() {
            continue;
        }
        let x = (ts - t_ms) as f64; // ms, centred
        let y = s.agl_ft as f64; // ft
        n += 1;
        sx += x;
        sy += y;
        sxx += x * x;
        sxy += x * y;
    }
    if n < MSFS_FLARE_AGL_FIT_MIN_SAMPLES {
        return None;
    }
    let nf = n as f64;
    let denom = nf * sxx - sx * sx;
    if denom.abs() < 1e-9 {
        return None; // all samples at one timestamp → no slope
    }
    let slope_ft_per_ms = (nf * sxy - sx * sy) / denom;
    let fpm = slope_ft_per_ms * 1000.0 * 60.0; // ft/ms → ft/min
    if !fpm.is_finite() {
        return None;
    }
    // Pitch-correct (× cos(pitch)) — mirrors the SimVar flare path so
    // the metric stays consistent across sources. Tiny here but correct.
    let pitch_rad = (pitch_deg_at_t as f64) * std::f64::consts::PI / 180.0;
    Some((fpm * pitch_rad.cos()) as f32)
}

/// The AGL-derived flare endpoints for MSFS: the steepest (most
/// negative) AGL-geometric V/S anywhere in `[flare_lo, flare_hi]` and
/// the AGL-geometric V/S at the sample nearest `flare_hi` (-100 ms).
/// Both already pitch-corrected. Returns `(peak_vs_pre, vs_at_flare_
/// end)`; either may be `None` if no fit point qualified.
fn compute_msfs_agl_flare_endpoints(
    samples: &[TouchdownWindowSample],
    flare_lo: i64,
    flare_hi: i64,
) -> (Option<f32>, Option<f32>) {
    let mut peak_vs_pre: Option<f32> = None; // most negative AGL slope
    let mut vs_at_flare_end: Option<f32> = None;
    let mut min_dist_to_end = i64::MAX;
    // v0.16.22 hardening: cap every endpoint fit at the touchdown edge so a
    // post-edge bounce/balloon (rising AGL after first ground contact) never
    // contaminates the end slope. flare_hi == edge_ms − 100, so edge_ms is
    // flare_hi + 100; samples at/after that never enter a fit.
    let edge_cap = flare_hi + 100;
    for s in samples {
        let ts = s.at.timestamp_millis();
        if ts < flare_lo || ts > flare_hi || s.on_ground {
            continue;
        }
        let vs_agl = match agl_geometric_vs_fpm_at(samples, ts, s.pitch_deg, Some(edge_cap)) {
            Some(v) => v,
            None => continue,
        };
        if peak_vs_pre.map(|p| vs_agl < p).unwrap_or(true) {
            peak_vs_pre = Some(vs_agl);
        }
        let dist_to_end = (flare_hi - ts).abs();
        if dist_to_end < min_dist_to_end {
            min_dist_to_end = dist_to_end;
            vs_at_flare_end = Some(vs_agl);
        }
    }
    (peak_vs_pre, vs_at_flare_end)
}

/// v0.16.22 hardening: outcome of the phantom-flare guards over the MSFS
/// flare window. `agl_reliable` is false when Gate 1 (data quality) OR
/// Gate 2 (bounce) tripped → the caller MUST fall back to the SimVar path
/// so no garbage AGL endpoint is published. `unreliable_source` is true
/// only when a DATA-QUALITY gate tripped (frozen/degraded AGL) so the
/// provenance string can distinguish that from a plain non-MSFS fallback.
/// `pitch_nose_down` is the Gate-3 veto signal (a strongly nose-down net
/// pitch trend) — it does NOT block the AGL endpoints (the reduction is
/// still computed for forensics), only `flare_detected`.
struct MsfsFlareGates {
    agl_reliable: bool,
    unreliable_source: bool,
    pitch_nose_down: bool,
}

/// Evaluate the v0.16.22 phantom-flare guards over `[flare_lo, flare_hi]`.
/// Pure + side-effect-free → unit-testable. See the gate constants above
/// for the data behind each threshold.
fn evaluate_msfs_flare_gates(
    samples: &[TouchdownWindowSample],
    flare_lo: i64,
    flare_hi: i64,
) -> MsfsFlareGates {
    // Collect the in-window samples (airborne + ground) in time order.
    let mut in_window: Vec<&TouchdownWindowSample> = samples
        .iter()
        .filter(|s| {
            let ts = s.at.timestamp_millis();
            ts >= flare_lo && ts <= flare_hi
        })
        .collect();
    in_window.sort_by_key(|s| s.at.timestamp_millis());

    // ── Gate 2 (bounce, part A): any on_ground=true in the PRE-edge window
    // means a touchdown already happened here — a post-bounce settle, not a
    // flare. (Kept pre-edge: EVERY normal landing is on_ground just past the
    // edge — that is the touchdown itself, not a prior bounce. Extending this
    // to post-edge would wrongly trip on all firm landings; the post-edge
    // bounce signal is the BALLOON below, not on_ground.)
    let any_on_ground = in_window.iter().any(|s| s.on_ground);

    // ── Gate 2 (bounce) extended balloon-scan window. v0.16.22 hardening: a
    // touchdown-then-bounce contacts the ground AT/near the edge, then goes
    // airborne again just past it with RISING AGL. A NORMAL landing has no
    // airborne samples post-edge (it is on the ground), so extending only the
    // BALLOON (non-monotone rise among airborne samples) to flare_hi + the
    // fit half-window (= edge + 200 ms) catches the bounce balloon WITHOUT
    // tripping firm landings. (The fit endpoints are already capped at the
    // edge — this gate is the corroborating veto so a bounce earns no
    // credited flare. Data-quality gates 1a/1b/1c stay on the pre-edge set.)
    let bounce_scan_hi = flare_hi + MSFS_FLARE_AGL_FIT_HALF_WINDOW_MS;

    // Airborne, finite-AGL, near-ground samples in the FLARE window drive the
    // data-quality checks (mirrors the slope fit's qualifying set).
    let air: Vec<&TouchdownWindowSample> = in_window
        .iter()
        .copied()
        .filter(|s| !s.on_ground && s.agl_ft.is_finite() && s.agl_ft <= MSFS_FLARE_AGL_MAX_FT)
        .collect();
    // Airborne set over the EXTENDED balloon-scan window (pre-edge flare
    // window + post-edge fit reach) — used ONLY for the balloon (non-monotone
    // rise) check so a post-edge bounce balloon is visible.
    let mut air_bounce: Vec<&TouchdownWindowSample> = samples
        .iter()
        .filter(|s| {
            let ts = s.at.timestamp_millis();
            ts >= flare_lo
                && ts <= bounce_scan_hi
                && !s.on_ground
                && s.agl_ft.is_finite()
                && s.agl_ft <= MSFS_FLARE_AGL_MAX_FT
        })
        .collect();
    air_bounce.sort_by_key(|s| s.at.timestamp_millis());

    // ── Gate 1a (data quality): distinct agl_ft count. Quantize to 0.01 ft
    // so float jitter does not inflate the count (the frozen E195 repeats
    // EXACTLY, e.g. 9.96, so quantization is conservative here).
    let mut distinct: Vec<i64> = air
        .iter()
        .map(|s| (s.agl_ft as f64 * 100.0).round() as i64)
        .collect();
    distinct.sort_unstable();
    distinct.dedup();
    let n_distinct = distinct.len();

    // ── Gate 1c (data quality, LOCAL): distinct agl_ft in the flare-END
    // fit window only — catches a freeze that corrupts the end slope while
    // the rest of the window is fine (Gate 1a's whole-window count misses
    // a localized mid/late freeze). Same quantization as Gate 1a.
    let end_lo = flare_hi - MSFS_FLARE_AGL_FIT_HALF_WINDOW_MS;
    let end_hi = flare_hi + MSFS_FLARE_AGL_FIT_HALF_WINDOW_MS;
    let end_agls: Vec<f32> = air
        .iter()
        .filter(|s| {
            let ts = s.at.timestamp_millis();
            ts >= end_lo && ts <= end_hi
        })
        .map(|s| s.agl_ft)
        .collect();
    let mut end_distinct: Vec<i64> = end_agls
        .iter()
        .map(|a| (*a as f64 * 100.0).round() as i64)
        .collect();
    end_distinct.sort_unstable();
    end_distinct.dedup();
    // Only judge the end window if it actually has samples (an empty end
    // window cannot be "frozen" — let the MIN_SAMPLES fit guard handle it).
    let n_end_distinct = end_distinct.len();
    // Gate 1c backstop: the AGL SPAN across the end-fit window. A NOISY
    // freeze dithers across ≥MSFS_FLARE_MIN_END_FIT_DISTINCT_AGL quantized
    // buckets (passing the distinct count) while spanning ~0 true height —
    // the span catches that where bucket-counting cannot.
    let end_agl_span = if end_agls.len() >= 2 {
        let mut lo = f32::INFINITY;
        let mut hi = f32::NEG_INFINITY;
        for &a in &end_agls {
            if a < lo {
                lo = a;
            }
            if a > hi {
                hi = a;
            }
        }
        Some(hi - lo)
    } else {
        None
    };

    // ── Gate 1b (data quality): median sample Δt over the FULL in-window
    // set (airborne + ground) — a degraded stream is degraded regardless of
    // on_ground. Median is robust to the occasional duplicate-timestamp.
    let mut dts: Vec<i64> = in_window
        .windows(2)
        .map(|w| w[1].at.timestamp_millis() - w[0].at.timestamp_millis())
        .filter(|&d| d >= 0)
        .collect();
    let median_dt = if dts.is_empty() {
        0
    } else {
        dts.sort_unstable();
        dts[dts.len() / 2]
    };

    // ── Gate 2 (bounce, part B): non-monotone balloon. Walk the airborne
    // AGL trace (over the EXTENDED bounce-scan window so a post-edge balloon
    // is visible) tracking the running minimum; if AGL rises more than the
    // tolerance above that minimum, the trace ballooned back up.
    let mut balloon_ft = 0.0_f32;
    let mut running_min = f32::INFINITY;
    for s in &air_bounce {
        if s.agl_ft < running_min {
            running_min = s.agl_ft;
        } else {
            let rise = s.agl_ft - running_min;
            if rise > balloon_ft {
                balloon_ft = rise;
            }
        }
    }

    // Frozen end if EITHER the distinct-bucket count is too low (coarse/
    // stepped freeze) OR the AGL span across the end window is below the
    // physics floor (noisy multi-bucket freeze on a flat plateau). The span
    // backstop is what catches a dither that spreads across ≥4 buckets yet
    // covers near-zero true height (vs_at_flare_end ≈ 0 → fake reduction).
    let end_span_flat = end_agl_span
        .map(|sp| sp < MSFS_FLARE_MIN_END_AGL_SPAN_FT)
        .unwrap_or(false);
    let end_frozen = (n_end_distinct > 0
        && n_end_distinct < MSFS_FLARE_MIN_END_FIT_DISTINCT_AGL)
        || end_span_flat;
    let dq_reject = n_distinct < MSFS_FLARE_MIN_DISTINCT_AGL
        || median_dt > MSFS_FLARE_MAX_MEDIAN_DT_MS
        || end_frozen;
    let bounce_reject = any_on_ground || balloon_ft > MSFS_FLARE_BALLOON_TOL_FT;

    // ── Gate 3 (pitch corroboration): net window pitch trend. Compare the
    // mean pitch over the first ~300 ms of airborne samples to the mean over
    // the last ~300 ms. A strongly NOSE-DOWN trend vetoes detection.
    let pitch_nose_down = if air.len() >= 2 {
        let first_t = air.first().unwrap().at.timestamp_millis();
        let last_t = air.last().unwrap().at.timestamp_millis();
        let mean_pitch = |pred: &dyn Fn(i64) -> bool| -> Option<f32> {
            let vals: Vec<f32> = air
                .iter()
                .filter(|s| pred(s.at.timestamp_millis()))
                .map(|s| s.pitch_deg)
                .collect();
            if vals.is_empty() {
                None
            } else {
                Some(vals.iter().sum::<f32>() / vals.len() as f32)
            }
        };
        let p_start = mean_pitch(&|t| t <= first_t + 300);
        let p_end = mean_pitch(&|t| t >= last_t - 300);
        match (p_start, p_end) {
            (Some(a), Some(b)) => (b - a) <= MSFS_FLARE_PITCH_NOSEDOWN_VETO_DEG,
            _ => false,
        }
    } else {
        false
    };

    MsfsFlareGates {
        agl_reliable: !(dq_reject || bounce_reject),
        unreliable_source: dq_reject,
        pitch_nose_down,
    }
}

/// v0.5.39: Forensik-Bewertung der Landung aus dem 50-Hz-Sample-Buffer
/// um den TD-Edge. Gibt JSON-Map zurück, die im LandingAnalysis-Event in
/// die JSONL geschrieben + im MQTT-Touchdown-Payload mit-publisht wird.
///
/// Berechnete Felder:
///   - vs_at_edge_fpm           — interpolierte VS exakt am on_ground-Edge
///   - vs_smoothed_250ms_fpm    — Mean über letzte 250 ms vor Edge
///   - vs_smoothed_500ms_fpm    — 500 ms (= Volanta-Style)
///   - vs_smoothed_1000ms_fpm   — 1000 ms (= DLHv-Style)
///   - vs_smoothed_1500ms_fpm   — 1500 ms
///   - peak_g_post_500ms        — Max G im 500 ms post-Edge (Gear-Spike)
///   - peak_g_post_1000ms       — Max G im 1000 ms post-Edge
///   - peak_vs_pre_flare_fpm    — steepste Sinkrate in [-2000, -100 ms]
///   - vs_at_flare_end_fpm      — VS bei -100 ms (kurz vor TD)
///   - flare_reduction_fpm      — peak_vs_pre_flare - vs_at_flare_end
///   - flare_dvs_dt_fpm_per_sec — Steigungs-Rate der VS-Reduktion
///   - flare_quality_score      — 0..100, höher = besser geflared
///   - flare_detected           — bool, true wenn signifikante Reduktion
///
/// v0.16.22: Auf MSFS (fixed-wing) werden die Flare-Endpunkte
/// `peak_vs_pre_flare_fpm` / `vs_at_flare_end_fpm` aus der LAG-FREIEN
/// AGL-Geometrie (lokaler Linear-Fit der agl_ft-Spur) berechnet statt
/// aus dem lagbehafteten `s.vs_fpm`-Display-SimVar — sonst meldet der
/// Flare-Metrik bei spät/firm geflareten Landungen faelschlich "kein
/// Flare". Die roh-lagbehafteten Werte bleiben als Forensik-Keys
/// (`peak_vs_pre_flare_fpm_raw`, `vs_at_flare_end_fpm_raw`); `flare_vs_
/// source` markiert die Quelle ("msfs_agl" | "simvar"). X-Plane (raw
/// local_vy, kaum Lag) und Other behalten den SimVar-Pfad — ihre
/// Analyse-Ausgabe ist byte-identisch. Touchdown-Rate/Klasse und der
/// Master-Score bleiben unveraendert (Flare ist forensisch/Coaching).
///   - bounce_count             — Anzahl on_ground=False Excursionen post-TD
///   - bounce_max_agl_ft        — höchster Bounce
///   - sample_count             — Anzahl Samples im Buffer
///   - pre_edge_sample_count    — davon vor Edge (= Pre-TD-Coverage)
///   - post_edge_sample_count   — davon nach Edge
fn compute_landing_analysis(
    samples: &[TouchdownWindowSample],
    edge_at: DateTime<Utc>,
    simulator: Simulator,
) -> serde_json::Value {
    use serde_json::json;
    if samples.is_empty() {
        return json!({ "error": "empty_buffer" });
    }
    let edge_ms = edge_at.timestamp_millis();

    // --- Multi-Window VS-Mittel (nur airborne-Samples vor Edge mit
    // negativer V/S — das ist die "reine Sinkrate"). Positive Samples
    // (= Float-Effekt, Ground-Effect-Bumps, Ballooning kurz vor TD)
    // wuerden den Mittelwert sonst Richtung 0 verfaelschen und einen
    // sanfteren Touchdown vortaeuschen als physikalisch passiert ist.
    // Volanta/DLHv filtern aehnlich. ---
    let mean_vs_window = |window_ms: i64| -> Option<f32> {
        let lo = edge_ms - window_ms;
        let mut sum = 0.0_f64;
        let mut n = 0_u32;
        for s in samples {
            let ts = s.at.timestamp_millis();
            if ts >= lo && ts <= edge_ms && !s.on_ground && s.vs_fpm < 0.0 {
                sum += s.vs_fpm as f64;
                n += 1;
            }
        }
        if n > 0 { Some((sum / n as f64) as f32) } else { None }
    };
    let vs_250 = mean_vs_window(250);
    let vs_500 = mean_vs_window(500);
    let vs_1000 = mean_vs_window(1000);
    let vs_1500 = mean_vs_window(1500);

    // --- Interpolated VS am Edge ---
    // Finde das Sample-Paar (last airborne, first on_ground) das den Edge
    // umschließt; lineare Interpolation der VS auf edge_ms.
    let mut last_air: Option<&TouchdownWindowSample> = None;
    let mut first_ground: Option<&TouchdownWindowSample> = None;
    for s in samples {
        if !s.on_ground {
            last_air = Some(s);
        } else if last_air.is_some() && first_ground.is_none() {
            first_ground = Some(s);
            break;
        }
    }
    let vs_at_edge = match (last_air, first_ground) {
        (Some(a), Some(g)) => {
            let t_a = a.at.timestamp_millis() as f64;
            let t_g = g.at.timestamp_millis() as f64;
            let t_edge = edge_ms as f64;
            if (t_g - t_a).abs() < 1e-6 {
                Some(a.vs_fpm)
            } else {
                let alpha = ((t_edge - t_a) / (t_g - t_a)).clamp(0.0, 1.0);
                Some((a.vs_fpm as f64 + (g.vs_fpm as f64 - a.vs_fpm as f64) * alpha) as f32)
            }
        }
        _ => None,
    };

    // --- Peak G post-TD (Gear-Compression sucht nach Edge) ---
    let peak_g_window = |window_ms: i64| -> Option<f32> {
        let hi = edge_ms + window_ms;
        let mut peak = 0.0_f32;
        let mut found = false;
        for s in samples {
            let ts = s.at.timestamp_millis();
            if ts >= edge_ms && ts <= hi {
                if s.g_force > peak { peak = s.g_force; }
                found = true;
            }
        }
        if found { Some(peak) } else { None }
    };
    let pg_500 = peak_g_window(500);
    let pg_1000 = peak_g_window(1000);

    // v0.7.17 (B-009): G-Force-Forensik — analog Sinkrate-Forensik.
    //
    // Sample-basierte robuste Statistiken statt naivem max(), damit
    // Sim-Strut-Compression-Spikes (X-Plane + MSFS) nicht den Score
    // zerschiessen.

    // G im interpolierten Edge-Frame (analog vs_at_edge).
    let g_at_edge: Option<f32> = match (last_air, first_ground) {
        (Some(a), Some(g)) => {
            let t_a = a.at.timestamp_millis() as f64;
            let t_g = g.at.timestamp_millis() as f64;
            let t_edge = edge_ms as f64;
            if (t_g - t_a).abs() < 1e-6 {
                Some(a.g_force)
            } else {
                let alpha = ((t_edge - t_a) / (t_g - t_a)).clamp(0.0, 1.0);
                Some((a.g_force as f64 + (g.g_force as f64 - a.g_force as f64) * alpha) as f32)
            }
        }
        _ => None,
    };

    // Hilfsfunktion: G-Samples im Post-Edge-Fenster sammeln.
    let collect_g_post = |window_ms: i64| -> Vec<f32> {
        let hi = edge_ms + window_ms;
        samples
            .iter()
            .filter_map(|s| {
                let ts = s.at.timestamp_millis();
                if ts >= edge_ms && ts <= hi {
                    Some(s.g_force)
                } else {
                    None
                }
            })
            .collect()
    };

    // Mean / Median / 95p — robuste Statistiken.
    fn mean_of(xs: &[f32]) -> Option<f32> {
        if xs.is_empty() { return None; }
        let sum: f64 = xs.iter().map(|x| *x as f64).sum();
        Some((sum / xs.len() as f64) as f32)
    }
    fn percentile_of(xs: &[f32], p: f32) -> Option<f32> {
        if xs.is_empty() { return None; }
        let mut sorted: Vec<f32> = xs.to_vec();
        sorted.sort_by(|a, b| a.partial_cmp(b).unwrap_or(std::cmp::Ordering::Equal));
        let idx = ((sorted.len() as f32 - 1.0) * p).round() as usize;
        Some(sorted[idx.min(sorted.len() - 1)])
    }

    let g_250_samples = collect_g_post(250);
    let g_500_samples = collect_g_post(500);
    let g_smoothed_250ms_post = mean_of(&g_250_samples);
    let g_median_post_500ms = percentile_of(&g_500_samples, 0.5);
    let g_p95_post_500ms = percentile_of(&g_500_samples, 0.95);

    // Max Gear-Normal-Force im Post-Edge-Fenster (Strut-Compression-Mass).
    // gear_normal_force_n ist Option<f32> (X-Plane liefert es, MSFS None).
    let max_gear_force_n: Option<f32> = {
        let hi = edge_ms + 1000; // 1 s nach Edge
        let mut peak = 0.0_f32;
        let mut found = false;
        for s in samples {
            let ts = s.at.timestamp_millis();
            if ts >= edge_ms && ts <= hi {
                if let Some(f) = s.gear_normal_force_n {
                    if f > peak {
                        peak = f;
                        found = true;
                    }
                }
            }
        }
        if found { Some(peak) } else { None }
    };

    // --- Flare-Analyse ---
    // Window: [-2000 ms, -100 ms] vor Edge. Suche steepste Sinkrate +
    // VS-Wert kurz vor Edge.
    let flare_lo = edge_ms - 2000;
    let flare_hi = edge_ms - 100;
    // SimVar pass (pitch-corrected `s.vs_fpm`). On X-Plane/Other this is
    // the published flare metric; on MSFS it lags the airframe and is
    // kept only as the `_raw` forensic provenance (see v0.16.22 block).
    let mut peak_vs_pre_simvar: Option<f32> = None;     // most negative
    let mut vs_at_flare_end_simvar: Option<f32> = None; // VS am ts nahe -100ms
    let mut min_dist_to_end = i64::MAX;
    let mut earliest_in_window: Option<&TouchdownWindowSample> = None;
    for s in samples {
        let ts = s.at.timestamp_millis();
        if ts >= flare_lo && ts <= flare_hi && !s.on_ground {
            // Pitch-korrigierte VS verwenden — bei steilem Flare wichtig
            let pitch_rad = (s.pitch_deg as f64) * std::f64::consts::PI / 180.0;
            let vs_corrected = (s.vs_fpm as f64 * pitch_rad.cos()) as f32;
            if peak_vs_pre_simvar.map(|p| vs_corrected < p).unwrap_or(true) {
                peak_vs_pre_simvar = Some(vs_corrected);
            }
            let dist_to_end = (flare_hi - ts).abs();
            if dist_to_end < min_dist_to_end {
                min_dist_to_end = dist_to_end;
                vs_at_flare_end_simvar = Some(vs_corrected);
            }
            if earliest_in_window.map(|e| ts < e.at.timestamp_millis()).unwrap_or(true) {
                earliest_in_window = Some(s);
            }
        }
    }

    // v0.16.22: MSFS flare metric on the lag-free AGL-geometric V/S.
    // For MSFS2020/2024 fixed-wing, replace the lagged SimVar endpoints
    // with the AGL local-linear-fit slope endpoints over the SAME
    // window; keep the SimVar values as `_raw` provenance. X-Plane (raw
    // local_vy) / Other keep the SimVar endpoints → byte-identical.
    // Heli/seaplane are NOT category-gated here (compute_landing_analysis
    // has no category); we gate on the AGL endpoints existing AND being a
    // real reduction — a near-zero-V/S rotorcraft touchdown produces no
    // AGL flare reduction, so the metric stays inert. Fixed-wing scope is
    // additionally enforced by the de-lag/score paths that consume this.
    let is_msfs = matches!(simulator, Simulator::Msfs2020 | Simulator::Msfs2024);
    let (peak_vs_pre_agl, vs_at_flare_end_agl) = if is_msfs {
        compute_msfs_agl_flare_endpoints(samples, flare_lo, flare_hi)
    } else {
        (None, None)
    };
    // v0.16.22 hardening: evaluate the phantom-flare guards (frozen/coarse
    // AGL, bounce/balloon, nose-down pitch). On a data-quality or bounce
    // reject we fall back to the SimVar path so no garbage AGL endpoint is
    // published; the pitch veto is applied to `flare_detected` only.
    let flare_gates = if is_msfs {
        evaluate_msfs_flare_gates(samples, flare_lo, flare_hi)
    } else {
        MsfsFlareGates {
            agl_reliable: true,
            unreliable_source: false,
            pitch_nose_down: false,
        }
    };
    // The endpoints that actually drive reduction / score / detected.
    // MSFS: AGL if BOTH endpoints resolved AND the guards pass, else fall
    // back to SimVar (too few AGL samples, frozen/coarse trace, or a
    // bounce — never worse than the pre-v0.16.22 SimVar behaviour).
    let use_agl = is_msfs
        && peak_vs_pre_agl.is_some()
        && vs_at_flare_end_agl.is_some()
        && flare_gates.agl_reliable;
    let (peak_vs_pre, vs_at_flare_end, flare_vs_source) = if use_agl {
        (peak_vs_pre_agl, vs_at_flare_end_agl, "msfs_agl")
    } else if is_msfs && flare_gates.unreliable_source {
        // A data-quality gate tripped: mark the fallback distinctly so the
        // provenance shows WHY we did not use the AGL geometry.
        (peak_vs_pre_simvar, vs_at_flare_end_simvar, "simvar_agl_unreliable")
    } else {
        (peak_vs_pre_simvar, vs_at_flare_end_simvar, "simvar")
    };

    // Reduktion: positive Zahl = Flare hat Sinkrate verkleinert
    let flare_reduction = match (peak_vs_pre, vs_at_flare_end) {
        (Some(p), Some(v)) => Some(v - p),
        _ => None,
    };
    // dVS/dt grob: (vs_at_flare_end - vs_at_flare_start) / window_dt.
    // Secondary diagnostic. v0.16.22 FIX 4: route this through the SAME
    // endpoint SOURCE as the published `flare_reduction` so the two
    // diagnostics never disagree. On the MSFS AGL path both start and end are
    // AGL-geometric (start = the capped AGL fit at the earliest in-window
    // sample, end = the published AGL `vs_at_flare_end`); on the SimVar
    // fallback (and X-Plane / Other) both stay SimVar → byte-identical to
    // pre-v0.16.22.
    let flare_dvs_dt = match earliest_in_window {
        Some(start) => {
            let dt_sec = (flare_hi - start.at.timestamp_millis()) as f64 / 1000.0;
            if dt_sec > 0.1 {
                // Pick the start/end pair from the SAME source as the reduction.
                let endpoints = if use_agl {
                    // AGL start at the earliest-window timestamp (edge-capped,
                    // matching compute_msfs_agl_flare_endpoints) + AGL end.
                    let start_vs = agl_geometric_vs_fpm_at(
                        samples,
                        start.at.timestamp_millis(),
                        start.pitch_deg,
                        Some(flare_hi + 100),
                    );
                    match (start_vs, vs_at_flare_end) {
                        (Some(sv), Some(ev)) => Some((sv, ev)),
                        _ => None,
                    }
                } else {
                    // SimVar pass: pitch-corrected vs_fpm start + SimVar end.
                    let pitch_rad = (start.pitch_deg as f64) * std::f64::consts::PI / 180.0;
                    let start_vs = (start.vs_fpm as f64 * pitch_rad.cos()) as f32;
                    vs_at_flare_end_simvar.map(|ev| (start_vs, ev))
                };
                endpoints.map(|(start_vs, end_vs)| ((end_vs - start_vs) as f64 / dt_sec) as f32)
            } else {
                None
            }
        }
        None => None,
    };

    // v0.5.41: rebalanced — Endpoint-Score dominiert (was kommt am TD raus),
    // Reduktion gibt Bonus-Punkte (= rettete eine harte Landung wenn aus
    // hohem VS reduziert wurde). Vorherige Skala bestrafte Piloten die
    // schon mit niedriger VS reinkamen (= eigentlich gute Approaches) zu
    // hart, weil "Reduktion >0 fpm" pauschal nur 20 Punkte gab.
    //
    // Endpoint-Score (= VS unmittelbar vor TD, der eigentliche Touchdown-
    // Indikator):
    //   > -75 fpm:       100 (butter)
    //   > -150 fpm:       80 (smooth)
    //   > -300 fpm:       60 (acceptable)
    //   > -500 fpm:       40 (firm)
    //   sonst:            20 (hard/severe)
    //
    // Reduktions-Bonus (= Flare-Manöver hat eine harte Landung gerettet,
    // der Pilot hat gepulled):
    //   > 400 fpm:       +20
    //   > 200 fpm:       +15
    //   > 100 fpm:       +10
    //   >  50 fpm:        +5
    //   sonst:             0
    //
    // Endpoint + Bonus, gecappt [0..100].
    //
    // Beispiele:
    //   - DLH 1404 (Peter, Fenix A320 SL): vs_end=-61, red=59 → 100+5 = 100 ✓
    //   - Hypothetisch B738 perfect: vs_end=-100, red=600 → 80+20 = 100 ✓
    //   - URO 913 (Aerosoft A346): vs_end=-606 (estimated), red=315 → 20+15 = 35
    //   - Bad Pilot: vs_end=-800, red=0 → 20+0 = 20
    let (flare_score, flare_detected) = match (flare_reduction, vs_at_flare_end) {
        (Some(red), Some(final_vs)) => {
            let red = red as f64;
            let final_vs = final_vs as f64;
            let endpoint: f64 = if final_vs > -75.0 { 100.0 }
                else if final_vs > -150.0 { 80.0 }
                else if final_vs > -300.0 { 60.0 }
                else if final_vs > -500.0 { 40.0 }
                else { 20.0 };
            let bonus: f64 = if red > 400.0 { 20.0 }
                else if red > 200.0 { 15.0 }
                else if red > 100.0 { 10.0 }
                else if red > 50.0 { 5.0 }
                else { 0.0 };
            let score = (endpoint + bonus).max(0.0).min(100.0) as i32;
            // Detection floor. MSFS_FLARE_DETECT_FLOOR_FPM == 50.0, so the
            // value here is byte-identical to the previous `red > 50.0` for
            // X-Plane / Other. v0.16.22: on the MSFS AGL path the pitch
            // veto (Gate 3) additionally withholds detection when the net
            // pitch trend is strongly nose-down (a settle/shed, not a
            // pull) — the reduction/score still publish for forensics.
            let mut detected = red > MSFS_FLARE_DETECT_FLOOR_FPM;
            if is_msfs && use_agl && flare_gates.pitch_nose_down {
                detected = false;
            }
            (Some(score), Some(detected))
        }
        _ => (None, None),
    };

    // --- Bounce-Profile ---
    // Post-TD: zähle on_ground=False Excursionen mit AGL-Höhe.
    //
    // v0.7.6 P1-2: Zwei Counts werden parallel gefuehrt damit Forensik
    // (kleine Hopser sichtbar) und Score (nur "echte" Bounces bestraft)
    // dieselbe AGL-Datenbasis aber unterschiedliche Schwellen nutzen.
    // Konstanten in `touchdown_v2.rs`. Spec docs/spec/v0.7.6-landing-
    // payload-consistency.md §3 P1-2.
    let mut forensic_bounces = 0_u32;
    let mut scored_bounces = 0_u32;
    let mut bounce_max_agl: f32 = 0.0;
    let mut in_bounce = false;
    let mut current_bounce_max: f32 = 0.0;
    for s in samples {
        let ts = s.at.timestamp_millis();
        if ts < edge_ms { continue; }
        if !s.on_ground {
            if !in_bounce {
                in_bounce = true;
                current_bounce_max = s.agl_ft;
            } else if s.agl_ft > current_bounce_max {
                current_bounce_max = s.agl_ft;
            }
        } else if in_bounce {
            if current_bounce_max >= touchdown_v2::BOUNCE_FORENSIC_MIN_AGL_FT {
                forensic_bounces += 1;
                if current_bounce_max > bounce_max_agl {
                    bounce_max_agl = current_bounce_max;
                }
            }
            if current_bounce_max >= touchdown_v2::BOUNCE_SCORED_MIN_AGL_FT {
                scored_bounces += 1;
            }
            in_bounce = false;
            current_bounce_max = 0.0;
        }
    }

    let pre_count = samples.iter().filter(|s| s.at.timestamp_millis() < edge_ms).count();
    let post_count = samples.len() - pre_count;

    // v0.12.3 (LE1–LE3): FOQA-konformer gescorter G-Wert — EMA-geglätteter
    // Fenster-Peak statt rohem 50-Hz-Einzelframe-Peak. Einzige
    // Berechnungsstelle (LE8); alle Consumer lesen `scored_g` aus dieser
    // Analyse-Map.
    let scored = recorder::compute_scored_g(samples, edge_at);

    let mut analysis = json!({
        "vs_at_edge_fpm": vs_at_edge,
        "vs_smoothed_250ms_fpm": vs_250,
        "vs_smoothed_500ms_fpm": vs_500,
        "vs_smoothed_1000ms_fpm": vs_1000,
        "vs_smoothed_1500ms_fpm": vs_1500,
        "peak_g_post_500ms": pg_500,
        "peak_g_post_1000ms": pg_1000,
        // v0.12.3 (LE1): EMA-geglätteter Scored-G (FOQA-Methode) — der
        // Wert, auf dem die Landung gescort wird. `peak_g_post_*` bleibt
        // der rohe Forensik-Peak.
        "scored_g": scored.scored_g,
        "scored_g_method": scored.method.as_str(),
        // v0.7.17 (B-009): G-Force-Forensik
        "g_at_edge": g_at_edge,
        "g_smoothed_250ms_post": g_smoothed_250ms_post,
        "g_median_post_500ms": g_median_post_500ms,
        "g_p95_post_500ms": g_p95_post_500ms,
        "max_gear_force_n": max_gear_force_n,
        "peak_vs_pre_flare_fpm": peak_vs_pre,
        "vs_at_flare_end_fpm": vs_at_flare_end,
        "flare_reduction_fpm": flare_reduction,
        "flare_dvs_dt_fpm_per_sec": flare_dvs_dt,
        "flare_quality_score": flare_score,
        "flare_detected": flare_detected,
        // v0.7.6 P1-2: bounce_count BLEIBT auf forensic count fuer
        // Backward-Compat (alte Reader/Replays). Neuer Konsument soll
        // explizit forensic_bounce_count oder scored_bounce_count lesen.
        "bounce_count": forensic_bounces,
        "forensic_bounce_count": forensic_bounces,
        "scored_bounce_count": scored_bounces,
        "bounce_max_agl_ft": if bounce_max_agl > 0.0 { Some(bounce_max_agl) } else { None },
        "sample_count": samples.len(),
        "pre_edge_sample_count": pre_count,
        "post_edge_sample_count": post_count,
    });

    // v0.16.22: provenance of the MSFS AGL flare endpoints — ADDITIVE,
    // MSFS-ONLY. `flare_vs_source` marks whether the published flare
    // endpoints are the lag-free AGL fit ("msfs_agl") or the SimVar
    // fallback ("simvar"); the `_raw` keys carry the lagged display-VSI
    // values for forensics. On X-Plane / Other we add NOTHING so their
    // analysis JSON is byte-identical to pre-v0.16.22 (no new keys).
    if is_msfs {
        if let Some(obj) = analysis.as_object_mut() {
            obj.insert("flare_vs_source".into(), json!(flare_vs_source));
            obj.insert(
                "peak_vs_pre_flare_fpm_raw".into(),
                json!(peak_vs_pre_simvar),
            );
            obj.insert(
                "vs_at_flare_end_fpm_raw".into(),
                json!(vs_at_flare_end_simvar),
            );
        }
    }
    analysis
}

/// v0.5.39: Beim TD-Edge — Pre-TD-Buffer (snapshot_buffer, ~5 s @ 50 Hz)
/// in den post_touchdown_buffer kopieren und das Landing-Critical-Window
/// öffnen. Der Sampler füllt den Buffer in den nächsten Iterationen mit
/// Post-TD-Samples weiter und dumpt ihn nach TOUCHDOWN_POST_WINDOW_MS.
fn open_touchdown_capture_window(stats: &mut FlightStats, now: DateTime<Utc>) {
    stats.landing_critical_until = Some(
        now + chrono::Duration::milliseconds(TOUCHDOWN_POST_WINDOW_MS),
    );
    stats.post_touchdown_buffer.clear();
    for s in &stats.snapshot_buffer {
        stats.post_touchdown_buffer.push_back(*s);
    }
    // Touch-and-Go: erlaubt nicht ein zweites Dump-Event (TD-Capture
    // bleibt einmalig per sampler_touchdown_at-Guard), aber wenn diese
    // Funktion aus irgendeinem Grund doch zweimal liefe → Reset clean.
    stats.touchdown_window_dumped_at = None;
}

fn spawn_touchdown_sampler(app: AppHandle, flight: Arc<ActiveFlight>) {
    // Guard gegen Doppel-Spawn (mehrere flight_resume etc.) — analog zu
    // streamer_spawned/phpvms_worker_spawned. Ohne dies koennen zwei
    // unabhaengige Aufrufer von flight_resume_confirm (z. B. das
    // Hauptfenster UND ein via LAN-Fernbedienung verbundenes Tablet, siehe
    // remote/bridge.rs) zwei parallele Sampler fuer denselben Flug starten.
    if flight.touchdown_sampler_spawned.swap(true, Ordering::SeqCst) {
        return;
    }
    tauri::async_runtime::spawn(async move {
        tracing::info!(pirep_id = %flight.pirep_id, "touchdown sampler started");
        // v0.4.4: lokale Edge-Tracking-State.
        //
        // X-Plane: bevorzugt `gear_normal_force_n` (Newton, spikt
        // präzise im Frame des physischen Touchdowns) — das macht
        // auch xgs (etabliertes X-Plane-Landing-Speed-Plugin seit ~10
        // Jahren). xgs nutzt exakt `force != 0.0` als Trigger; wir
        // wählen `> 1.0 N` als minimaler Filter gegen Float-Noise und
        // catchen damit immer noch den ersten Kontakt-Frame (echte
        // Touchdowns gehen blitzartig auf mehrere kN — ein 60-300t
        // Airliner mit 1.0g Bremsmoment = mindestens 588-2940 kN auf
        // dem Gear). 1.0 N = ~100g Auflagedruck, also unter jeder
        // physikalisch plausiblen Touchdown-Schwelle.
        //
        // MSFS: gear_normal_force_n ist None → fallback auf
        // `on_ground`-Edge wie vorher (MSFS hat eh den separaten
        // `PLANE TOUCHDOWN NORMAL VELOCITY`-SimVar als Primary).
        let mut prev_in_air: Option<bool> = None;
        // v0.7.18 (B-013): Sim-Position-Reset-Detection.
        //
        // Spec docs/spec/v0.7.18-orphan-flight-cleanup.md §B-013.
        //
        // Quelle: GAF 152 Crash 2026-05-12 — MSFS produzierte einen
        // Sample mit lat/lon ≈ 0/0 / alt=53820 ft mid-flight. Sampler
        // hat das uebernommen und einen 14-G-Crash daraus geloggt.
        //
        // Detection-Kriterien (ein Match reicht zum Verwerfen):
        //   1. lat/lon ≈ 0/0 (innerhalb 0.1°)         — Null-Island-Reset
        //   2. Altitude-Sprung > 10.000 ft seit prev  — physikal unmoeglich
        //   3. Position-Sprung > 10 nmi seit prev     — teleport
        //
        // dt-Guard: Jump-Checks nur bei consecutive samples mit
        // dt <= RESET_CHECK_MAX_DT_SECS. Bei groesserer Luecke
        // (Pause, Disconnect, App-Hintergrund) sind grosse legitime
        // Spruenge erwartbar — wir setzen prev_state dann einfach
        // mit dem neuen Sample neu, kein Reset-Detect.
        let mut prev_sample_for_reset_check: Option<(f64, f64, f64, DateTime<Utc>)> = None;
        let mut reset_warning_logged_this_session = false;
        const RESET_NULL_ISLAND_DEG: f64 = 0.1;
        const RESET_MAX_ALT_JUMP_FT: f64 = 10_000.0;
        const RESET_MAX_DIST_NM_PER_TICK: f64 = 10.0;
        const RESET_CHECK_MAX_DT_SECS: i64 = 2;
        loop {
            // 20 ms = 50 Hz target — matches GEES (`SAMPLE_RATE = 20`),
            // the only open-source reference impl that publishes its
            // sample cadence. The actual upper bound comes from how
            // fast `current_snapshot` returns fresh data; on a
            // typical PC the SimConnect adapter ticks at the rendered
            // frame rate (60-120 fps) so we never under-sample here.
            tokio::time::sleep(Duration::from_millis(20)).await;
            if flight.stop.load(Ordering::Relaxed) {
                break;
            }
            let Some(snap) = current_snapshot(&app) else {
                continue;
            };
            let now = Utc::now();

            // v0.7.18 (B-013) Reset-Detection — vor Buffer-Push + Edge-Detect.
            let is_null_island = snap.lat.abs() < RESET_NULL_ISLAND_DEG
                && snap.lon.abs() < RESET_NULL_ISLAND_DEG;
            let (alt_jump, dist_jump_nm, dt_too_large) = match prev_sample_for_reset_check {
                Some((p_lat, p_lon, p_alt, p_at)) => {
                    let dt = (now - p_at).num_seconds();
                    if dt > RESET_CHECK_MAX_DT_SECS {
                        // Zu lange her → Jump-Checks skippen, prev_state
                        // wird unten neu gesetzt mit dem aktuellen Sample.
                        (0.0, 0.0, true)
                    } else {
                        let dist_m =
                            ::geo::distance_m(p_lat, p_lon, snap.lat, snap.lon);
                        let dist_nm = dist_m / 1852.0;
                        let alt_diff =
                            (snap.altitude_msl_ft - p_alt).abs();
                        (alt_diff, dist_nm, false)
                    }
                }
                None => (0.0, 0.0, false),
            };
            let is_alt_jump = !dt_too_large && alt_jump > RESET_MAX_ALT_JUMP_FT;
            let is_dist_jump = !dt_too_large && dist_jump_nm > RESET_MAX_DIST_NM_PER_TICK;

            if is_null_island || is_alt_jump || is_dist_jump {
                if !reset_warning_logged_this_session {
                    let reason = if is_null_island {
                        "lat/lon ≈ 0/0 (Null-Island)"
                    } else if is_alt_jump {
                        "Altitude-Sprung > 10.000 ft"
                    } else {
                        "Position-Sprung > 10 nmi"
                    };
                    tracing::warn!(
                        pirep_id = %flight.pirep_id,
                        lat = snap.lat,
                        lon = snap.lon,
                        alt_ft = snap.altitude_msl_ft,
                        alt_jump_ft = alt_jump,
                        dist_jump_nm = dist_jump_nm,
                        reason = reason,
                        "Sim-Position-Reset detektiert — Sample verworfen"
                    );
                    reset_warning_logged_this_session = true;
                }
                // Sample komplett verwerfen — kein Buffer-Push, kein
                // Edge-Update. prev_sample_for_reset_check absichtlich
                // NICHT updaten, sonst gewoehnt sich der Detector an
                // den Reset und der naechste echte Sample springt
                // wieder >10 nmi von 0/0 weg.
                continue;
            }

            // Sample ist OK ODER dt war zu gross (Resume-Fall) →
            // prev_state mit dem aktuellen Sample neu setzen.
            prev_sample_for_reset_check =
                Some((snap.lat, snap.lon, snap.altitude_msl_ft, now));

            let mut stats = flight.stats.lock().expect("flight stats");
            stats.snapshot_buffer.push_back(TelemetrySample {
                at: now,
                // The snapshot_buffer is the touchdown-window source (feeds the
                // touchdown_v2 cascade, vs_at_edge and landing_peak). It MUST use
                // the raw, lag-free V/S (X-Plane local_vy) — using the damped
                // display VVI here would re-introduce the v0.4.3 VSI-lag bug
                // where a real sink averages to ~0 by the touchdown moment.
                vs_fpm: snap.touchdown_vs_source_fpm(),
                g_force: snap.g_force,
                on_ground: snap.on_ground,
                agl_ft: snap.altitude_agl_ft as f32,
                heading_true_deg: snap.heading_deg_true,
                groundspeed_kt: snap.groundspeed_kt,
                indicated_airspeed_kt: snap.indicated_airspeed_kt,
                lat: snap.lat,
                lon: snap.lon,
                pitch_deg: snap.pitch_deg,
                bank_deg: snap.bank_deg,
                // v0.7.0 — Forensik-v2 fields direkt aus dem Sim-Snapshot.
                // gear_normal_force_n ist X-Plane-only (None bei MSFS),
                // total_weight_kg ist bei beiden Sims meist verfuegbar.
                gear_normal_force_n: snap.gear_normal_force_n,
                total_weight_kg: snap.total_weight_kg,
            });

            // v0.5.11: running peak-descent VS in the LOW-ALTITUDE zone
            // only (AGL ≤ 250 ft). Earlier versions (v0.5.5+) tracked
            // this across the whole Approach + Final segment, which
            // produced phantom hard-landing reports when a steep
            // pre-flare descent (e.g. -1346 fpm @ 943 ft AGL) won
            // over the actual gentle touchdown.
            //
            // Now: ONLY samples from the low-altitude footprint count.
            // This is a fallback only — the AGL-derivative estimator
            // (estimate_xplane_touchdown_vs_from_agl) is the primary
            // source. low_agl_vs_min_fpm is used when the estimator
            // can't find a valid window (extremely sparse RREF, etc.).
            let approach_or_final = matches!(
                stats.phase,
                FlightPhase::Approach | FlightPhase::Final
            );
            if approach_or_final
                && !snap.on_ground
                && snap.altitude_agl_ft <= 250.0
            {
                let pitch_rad = (snap.pitch_deg as f32) * std::f32::consts::PI / 180.0;
                // Touchdown VS fallback → raw, lag-free signal (X-Plane local_vy),
                // NOT the display VVI, so the landing rate stays responsive.
                let vs_corrected = snap.touchdown_vs_source_fpm() * pitch_rad.cos();
                let curr_min = stats.low_agl_vs_min_fpm.unwrap_or(f32::INFINITY);
                if vs_corrected < curr_min {
                    stats.low_agl_vs_min_fpm = Some(vs_corrected);
                }
                // v0.5.35: speichere AUCH die letzte airborne V/S
                // (= chronologisch jüngste, nicht das Minimum). Wird
                // als Fallback genutzt wenn der Lua-30-Sample-Estimator
                // wegen sparse Sampling versagt. AGL-Window 500ft
                // (gross genug fuer GA mit langsamen DataRefs).
                if snap.altitude_agl_ft <= 500.0 && vs_corrected < -20.0 {
                    stats.last_low_agl_vs_fpm = Some((vs_corrected, Utc::now()));
                }
            }

            // v0.4.4: Edge-Detection direkt im Sampler.
            //
            // Primary signal: `gear_normal_force_n` (X-Plane-only) —
            // spikt im Frame des physischen Touchdowns (xgs-Methode).
            // Fallback: `on_ground`-Flag (für MSFS und falls X-Plane-
            // DataRef mal None liefert).
            //
            // Wir halten `prev_in_air` als rolling-state. Der Edge
            // ist `true → false` (vom in-air zu am-Boden).
            //
            // Capture nur ONCE: sampler_touchdown_at bleibt Some bis
            // Flight-Reset → kein Re-Trigger bei Bouncing nach dem
            // initialen Touchdown.
            // Category-aware "in air" signal. Resolved once per tick from the
            // live ICAO + gear-type flags (FixedWing when unknown).
            let category = aircraft_category::resolve_category(
                snap.aircraft_icao.as_deref(),
                snap.gear_is_skid,
                snap.gear_is_floats,
                snap.gear_is_wheels,
                snap.water_rudder_present,
            );
            // For a seaplane/amphibian on water the wheeled gear / on_ground
            // edge never fires; `sampler_in_air_now` falls back to height above
            // the water surface so the touchdown edge fires when the floats
            // settle, then flows through the SAME pending → validate → capture
            // path (the seaplane validation anchors on sustained low-AGL, so a
            // wave bounce / low pass is dropped). Fixed-wing / helicopter /
            // on-runway are byte-identical to the wheeled branch.
            let in_air_now = sampler_in_air_now(
                category,
                snap.on_ground,
                snap.altitude_agl_ft,
                snap.gear_normal_force_n,
            );
            let edge_detected = matches!(prev_in_air, Some(true)) && !in_air_now;

            // v0.5.0: Premium-Plugin-Override.
            //
            // Wenn der AeroACARS X-Plane Plugin (optional, v0.5.0+) ein
            // Touchdown-Event gesendet hat, übernimmt es den Capture
            // unabhängig von der RREF-Edge — der Plugin sieht das Edge
            // mit Frame-Genauigkeit und kennt das tatsächliche peak
            // descent VS aus seinem eigenen 500ms-Lookback-Buffer
            // (gleicher Algorithmus wie unten, aber INNERHALB von
            // X-Plane gemessen, also keine UDP-Verzögerung / Eviction-
            // Race). Wir brauchen lokal den `prev_in_air`-Reset
            // trotzdem, damit das `bouncing`-Re-Trigger-Guard greift
            // wenn das Aircraft kurz wieder abhebt.
            //
            // `stats.sampler_touchdown_at.is_none()`-Guard: identisch
            // zur RREF-Edge — nur ein Capture pro Landing.
            // v0.7.0 — P1 fix: Premium-Touchdown-Pfad (X-Plane-Plugin) geht
            // jetzt auch ueber pending_td_at + validate_candidate. Vorher
            // wurde sampler_touchdown_at sofort gesetzt + open_capture_window
            // aufgerufen, was die touchdown_v2 Validation umging. Wenn das
            // Plugin einen Float-Streifschuss meldete, wurde der Bug
            // (DAH 3181-Pattern) reproduziert.
            //
            // Jetzt: Premium-event setzt pending_td_at (gleicher Mechanismus
            // wie der RREF-Edge-Pfad). Im subsequent pending-validation-block
            // wird validate_candidate aufgerufen. Bei VALIDATED wird die
            // Premium-VS als override im stats.sampler_touchdown_vs_fpm
            // verwendet (= "frame-perfect" Wert vom Plugin).
            //
            // Effekt: alle Pfade (RREF-edge + Premium-plugin) durchlaufen
            // identische Validation. False-edges werden konsistent gefiltert.
            if let Some(td) = current_premium_touchdown(&app) {
                // ACHTUNG: current_premium_touchdown() ist drain via take().
                // Das Event ist hier bereits konsumiert — wir muessen es jetzt
                // *immer* speichern (oder bewusst verwerfen), sonst geht es
                // still verloren.
                // v0.15.20: Premium-Touchdown in JEDER Flug-Phase akzeptieren
                // (nicht nur Approach/Final/Landing) — sonst geht der frame-
                // genaue Plugin-Wert bei fehl-phasierter FSM (Go-Around →
                // „Climb", OWx9) verloren. Phantom-Schutz via is_flight_phase
                // (Boden-/Taxi-Phasen bleiben ausgeschlossen).
                // v0.15.23: also capturable in Takeoff once airborne (short/low
                // bush hops that land before the 500 ft Takeoff→Climb gate).
                let capturable_phase =
                    is_touchdown_capturable_phase(stats.phase, stats.was_airborne);
                if !capturable_phase || stats.sampler_touchdown_at.is_some() {
                    // Out-of-phase (Boden/Taxi) oder TD schon abgeschlossen → drop.
                    tracing::debug!(
                        pirep_id = %flight.pirep_id,
                        captured_vs_fpm = td.captured_vs_fpm,
                        capturable_phase = capturable_phase,
                        td_already_captured = stats.sampler_touchdown_at.is_some(),
                        "premium TD event dropped (out of phase or TD already finalised)"
                    );
                } else if stats.pending_td_at.is_none() {
                    // Premium ist der erste Edge — neuer Candidate.
                    stats.pending_td_at = Some(now);
                    stats.pending_td_premium_vs = Some(td.captured_vs_fpm);
                    stats.pending_td_premium_g = Some(td.captured_g_normal);
                    tracing::info!(
                        pirep_id = %flight.pirep_id,
                        captured_vs_fpm = td.captured_vs_fpm,
                        captured_g = td.captured_g_normal,
                        source = "x-plane-plugin-premium",
                        "v0.7.0 premium TD candidate detected — pending validation in 1.1s"
                    );
                } else if stats.pending_td_premium_vs.is_none() {
                    // Round-4 P2 fix: RREF/gear-force hat bereits pending_td_at
                    // gesetzt, Premium-UDP-Event kommt einen Tick spaeter.
                    // Vorher (Bug): Event wurde durch den Guard verworfen, der
                    // Premium-Override fiel beim VALIDATED-Block still weg.
                    // Jetzt: Premium-Werte werden an den bestehenden Candidate
                    // angehaengt. pending_td_at bleibt am frueheren RREF-Edge.
                    let pending_age_ms = stats
                        .pending_td_at
                        .map(|t| (now - t).num_milliseconds())
                        .unwrap_or(0);
                    stats.pending_td_premium_vs = Some(td.captured_vs_fpm);
                    stats.pending_td_premium_g = Some(td.captured_g_normal);
                    tracing::info!(
                        pirep_id = %flight.pirep_id,
                        captured_vs_fpm = td.captured_vs_fpm,
                        captured_g = td.captured_g_normal,
                        pending_age_ms = pending_age_ms,
                        source = "x-plane-plugin-premium-late",
                        "v0.7.0 premium TD attached to existing RREF pending candidate"
                    );
                } else {
                    // Pending hat bereits Premium-Werte — Re-Trigger ignorieren,
                    // erste Premium-Messung war frame-perfekter.
                    tracing::debug!(
                        pirep_id = %flight.pirep_id,
                        captured_vs_fpm = td.captured_vs_fpm,
                        existing_premium_vs = stats.pending_td_premium_vs,
                        "premium TD re-trigger ignored — first premium edge already pending"
                    );
                }
            }

            // v0.5.24: Takeoff-Edge (Wheels-Up) — opposite of touchdown.
            // Wenn `prev_in_air=false` und jetzt `in_air_now=true`, ist
            // der Flieger gerade abgehoben. Wir capturen Pitch + Bank
            // exakt im Frame (50Hz, <20ms-Genauigkeit). Guard
            // `sampler_takeoff_at.is_none()` verhindert Re-Trigger bei
            // Touch-and-Go im Pattern (= zweiter Wheels-Up nach erstem
            // Touchdown ueberschreibt nicht den initialen Takeoff-Wert).
            let takeoff_edge_detected =
                matches!(prev_in_air, Some(false)) && in_air_now;
            if takeoff_edge_detected && stats.sampler_takeoff_at.is_none() {
                stats.sampler_takeoff_at = Some(now);
                stats.sampler_takeoff_pitch_deg = Some(snap.pitch_deg);
                stats.sampler_takeoff_bank_deg = Some(snap.bank_deg);
                tracing::info!(
                    pirep_id = %flight.pirep_id,
                    captured_pitch_deg = snap.pitch_deg,
                    captured_bank_deg = snap.bank_deg,
                    on_ground = snap.on_ground,
                    fnrml_n = snap.gear_normal_force_n,
                    "sampler-side takeoff edge detected (wheels-up frame)"
                );
            }

            // v0.5.45: Phase-Guard gegen Phantom-Touchdowns auf Bush-Strips.
            // Bei unebenem Untergrund kann gear_normal_force_n < 1.0 N kurz
            // unterschritten werden waehrend Taxi (DA40 auf X-Plane Bush-
            // Strip 2026-05-09) — der Sampler interpretiert das sonst als
            // Touchdown. TD-Edge nur akzeptieren wenn die FSM in einer
            // Landing-relevanten Phase ist. Approach-Ausloeser AGL>1500ft
            // ist OK (lange Endanflug-Bahnen), aber Taxi/Boarding/Cruise
            // sind explizit ausgeschlossen.
            // v0.15.20: accept the touchdown edge in any FLIGHT phase (not just
            // Approach/Final/Landing) so a real touchdown isn't lost when the FSM
            // is mis-phased (go-around → "Climb", OWx9 GSG544).
            // v0.15.23: ALSO accept it in Takeoff once airborne — short/low VFR
            // bush hops land before the 500 ft Takeoff→Climb gate, so they're
            // still in Takeoff at touchdown (GSG309 OR72→OR35, peaked 357 ft).
            // Phantom-safe: ground/taxi phases stay excluded (taxi gear-bumps
            // v0.5.45); the FIRST air→ground edge in Takeoff is the real landing
            // and the once-guard blocks rollout bumps after it; a mid-air
            // on_ground glitch is rejected by validate_candidate (low-AGL +
            // sustained-ground fail at altitude / on a single tick).
            let capturable_phase =
                is_touchdown_capturable_phase(stats.phase, stats.was_airborne);
            // v0.7.0 — P0 Fix: Edge-Detection setzt jetzt nur `pending_td_at`.
            // Die echte Validation (touchdown_v2::validate_candidate) folgt 1.1 sec
            // spaeter wenn genug post-edge samples im Buffer sind. False-edges
            // (= Float-Streifschuesse wie bei DAH 3181 sample 125) werden dann
            // verworfen, der Sampler beobachtet weiter den naechsten Edge.
            //
            // Vorher (Bug): erster Edge wurde direkt als TD akzeptiert. DAH 3181
            // Float-Streifschuss mit vs=+104 fpm wurde gescort, der echte TD
            // 4 sec spaeter wurde ignoriert (single-shot is_none() Guard).
            if edge_detected && stats.sampler_touchdown_at.is_none()
                && stats.pending_td_at.is_none() && capturable_phase {
                stats.pending_td_at = Some(now);
                tracing::info!(
                    pirep_id = %flight.pirep_id,
                    edge_at = %now,
                    edge_agl_ft = snap.altitude_agl_ft,
                    // Log the RAW touchdown source (what actually gets scored),
                    // not the display VVI, so forensic logs match the score.
                    edge_vs_fpm = snap.touchdown_vs_source_fpm(),
                    edge_gear_force_n = ?snap.gear_normal_force_n,
                    "v0.7.0 TD-edge candidate detected — pending validation in 1.1s"
                );
            }

            // v0.7.0 — Pending Validation: 1.1 sec nach edge die post-edge samples
            // sind im snapshot_buffer (TOUCHDOWN_BUFFER_SECS=5sec cutoff = "now-5s",
            // edge bei "now-1.1s" → samples [now-1.1s, now] sind drin).
            if let Some(pending_at) = stats.pending_td_at {
                let elapsed_ms = (now - pending_at).num_milliseconds();
                if elapsed_ms >= 1100 {
                    // Convert snapshot_buffer (TelemetrySample) zu Vec<TouchdownWindowSample>
                    let v2_samples: Vec<TouchdownWindowSample> = stats
                        .snapshot_buffer
                        .iter()
                        .copied()
                        .map(TouchdownWindowSample::from)
                        .collect();
                    // Find candidate sample (first sample at >= pending_at)
                    let cand_idx = v2_samples.iter().position(|s| s.at >= pending_at);
                    if let Some(idx) = cand_idx {
                        let cand_sample = &v2_samples[idx];
                        let candidate = touchdown_v2::TdCandidate {
                            edge_sample_index: idx,
                            edge_at: cand_sample.at,
                            edge_agl_ft: cand_sample.agl_ft,
                            edge_vs_fpm: cand_sample.vs_fpm,
                            edge_gear_force_n: cand_sample.gear_normal_force_n,
                            edge_g_force: cand_sample.g_force,
                            edge_total_weight_kg: cand_sample.total_weight_kg,
                        };
                        // Compute impact_frame fuer A3/B4 (vs_negative_at_impact)
                        let impact_for_validation = touchdown_v2::compute_impact_frame(
                            &v2_samples, candidate.edge_at,
                        );
                        let impact_vs = impact_for_validation
                            .as_ref().map(|r| r.impact_vs_fpm).unwrap_or(0.0);
                        // sim from snap (Simulator → SimKind)
                        let sim = match snap.simulator {
                            Simulator::Msfs2020 => SimKind::Msfs2020,
                            Simulator::Msfs2024 => SimKind::Msfs2024,
                            Simulator::XPlane11 => SimKind::XPlane11,
                            Simulator::XPlane12 => SimKind::XPlane12,
                            _ => SimKind::Off,
                        };
                        // Category-aware validation (loop-level `category`): a
                        // rotorcraft / seaplane soft set-down has no force/G/vs
                        // spike, so the fixed-wing anchors would drop it.
                        let validation = touchdown_v2::validate_candidate(
                            &candidate, &v2_samples, sim, impact_vs, category,
                        );
                        match validation {
                            touchdown_v2::ValidationResult::Validated { result } => {
                                tracing::info!(
                                    pirep_id = %flight.pirep_id,
                                    edge_at = %pending_at,
                                    impact_vs = impact_vs,
                                    "v0.7.0 TD candidate VALIDATED — promoting to sampler_touchdown"
                                );
                                stats.sampler_touchdown_at = Some(pending_at);
                                // Round-3 P2 fix: Premium-VS aus pending-state
                                // (wurde beim Premium-Edge gespeichert weil
                                // take_premium_touchdown() drain ist).
                                stats.sampler_touchdown_vs_fpm =
                                    stats.pending_td_premium_vs.or(Some(impact_vs));
                                stats.sampler_touchdown_g_force = stats
                                    .pending_td_premium_g
                                    .or(Some(result.g_force_peak_in_window));
                                open_touchdown_capture_window(&mut stats, pending_at);
                                stats.pending_td_at = None;
                                stats.pending_td_premium_vs = None;
                                stats.pending_td_premium_g = None;

                                // v0.15.24: Phase-independent touchdown METADATA.
                                //
                                // Short/low VFR bush hops (GSG312 97OG) land via
                                // this sampler path while the FSM is still stuck
                                // in Takeoff/Climb — the touchdown is captured,
                                // scored and published (v0.15.23), but the
                                // metadata (landing IAS/pitch/bank/heading/
                                // coords/fuel/weight, touchdown profile,
                                // sideslip, wind, RUNWAY correlation) was only
                                // ever stamped in the FSM Landing arm, so the
                                // PIREP report silently lost all those fields.
                                // Stamp them here, at the validated touchdown,
                                // with the SAME helpers the FSM arm calls.
                                //
                                // First-touchdown-wins guard: only stamp when
                                // the FSM arm hasn't already (landing_lat is
                                // its unconditional marker). On normal flights
                                // the FSM Landing arm still runs afterwards and
                                // overwrites these with its own values — its
                                // behaviour is unchanged.
                                //
                                // `pending_at` is the validated contact time —
                                // the same instant the FSM arm would use as
                                // `actual_td_at` (it prefers
                                // `sampler_touchdown_at` once set).
                                //
                                // v0.16.6: the two formerly-known gaps
                                // (approach-stability evaluation + rollout)
                                // are closed below — the central
                                // phase-independent sampling in `step_flight`
                                // keeps the approach_buffer fed on descending
                                // low-level segments, the evaluation here
                                // windows it to the touchdown, and the
                                // streamer drives `rollout_tick` for
                                // sampler-stamped touchdowns.
                                if stats.landing_lat.is_none() {
                                    let td_buf_sample = touchdown_buffer_sample(&stats);
                                    stamp_touchdown_metadata(
                                        &mut stats,
                                        &snap,
                                        pending_at,
                                        td_buf_sample.as_ref(),
                                    );
                                    correlate_touchdown_runway(
                                        &mut stats,
                                        &snap,
                                        &flight,
                                        td_buf_sample.as_ref(),
                                    );
                                    stamp_landing_weight(&mut stats, &snap);

                                    // v0.16.6: approach-stability evaluation on
                                    // the sampler path — mirrors the FSM
                                    // Landing-arm block (same inputs:
                                    // `correlate_touchdown_runway` above has
                                    // just resolved `runway_nav_geometry`
                                    // exactly like the FSM arm does before its
                                    // call), except both stats families are
                                    // windowed to the last
                                    // SAMPLER_STABILITY_WINDOW_SECS before the
                                    // touchdown so a long low-level bush cruise
                                    // doesn't poison the gate. On normal
                                    // flights the FSM Landing arm runs
                                    // afterwards and overwrites all of these
                                    // with its full-buffer values, exactly as
                                    // today (the `landing_lat.is_none()` guard
                                    // above keeps this stamp first-touchdown-
                                    // only, the FSM arm has no guard).
                                    let td_ts = Some(pending_at);
                                    let stab_window = chrono::Duration::seconds(
                                        SAMPLER_STABILITY_WINDOW_SECS,
                                    );
                                    let windowed_buf = approach_buffer_window(
                                        &stats.approach_buffer,
                                        pending_at,
                                        stab_window,
                                    );
                                    let (vs_sd, bank_sd) =
                                        compute_approach_stddev(&windowed_buf, td_ts);
                                    // Rotorcraft / seaplane: stability stddevs
                                    // nulled — same category rule as the FSM arm.
                                    let (vs_sd, bank_sd) = if category.is_non_conventional() {
                                        (None, None)
                                    } else {
                                        (vs_sd, bank_sd)
                                    };
                                    stats.approach_vs_stddev_fpm = vs_sd;
                                    stats.approach_bank_stddev_deg = bank_sd;
                                    let stab_v2 = compute_approach_stability_v2(
                                        &stats.approach_buffer,
                                        stats.arr_airport_elevation_ft,
                                        td_ts,
                                        stats
                                            .runway_nav_geometry
                                            .as_ref()
                                            .map(|g| g.glideslope_angle),
                                        Some((pending_at, stab_window)),
                                    );
                                    stats.approach_vs_deviation_fpm = stab_v2.vs_deviation_fpm;
                                    stats.approach_max_vs_deviation_below_500_fpm =
                                        stab_v2.max_vs_deviation_below_500_fpm;
                                    stats.approach_bank_stddev_filtered_deg =
                                        stab_v2.bank_stddev_filtered_deg;
                                    stats.approach_runway_changed_late =
                                        stab_v2.runway_changed_late;
                                    stats.approach_stable_at_gate = stab_v2.stable_at_gate;
                                    stats.approach_vs_jerk_fpm = stab_v2.vs_jerk_fpm;
                                    stats.approach_ias_stddev_kt = stab_v2.ias_stddev_kt;
                                    stats.approach_excessive_sink = stab_v2.excessive_sink;
                                    stats.approach_stable_config = stab_v2.stable_config;
                                    stats.approach_used_hat = stab_v2.used_hat;
                                    stats.approach_window_sample_count =
                                        Some(stab_v2.window_sample_count);
                                    stats.approach_stable_at_da = stab_v2.stable_at_da;
                                    stats.approach_stall_warning_count =
                                        stab_v2.stall_warning_count;
                                    tracing::info!(
                                        pirep_id = %flight.pirep_id,
                                        vs_dev_fpm = ?stab_v2.vs_deviation_fpm,
                                        bank_sd_filtered = ?stab_v2.bank_stddev_filtered_deg,
                                        stable_at_gate = ?stab_v2.stable_at_gate,
                                        samples = stab_v2.window_sample_count,
                                        window_secs = SAMPLER_STABILITY_WINDOW_SECS,
                                        "approach stability v2 computed (sampler path)"
                                    );

                                    // v0.16.6: rollout init — mirror of the FSM
                                    // Landing-entry init, but anchored at the
                                    // buffered touchdown coords (just stamped
                                    // into landing_lat/lon above; the live
                                    // `snap` fallback only fires on resumed
                                    // flights with an empty buffer, same as the
                                    // metadata stamp). The streamer's
                                    // `sampler_path_rollout_tick` accumulates
                                    // from here each tick while the FSM never
                                    // reaches Landing; on normal flights the
                                    // FSM Landing-entry re-initialises these
                                    // with its own values, exactly as today.
                                    stats.rollout_distance_m = Some(0.0);
                                    stats.rollout_finalized = false;
                                    stats.rollout_last_lat =
                                        Some(stats.landing_lat.unwrap_or(snap.lat));
                                    stats.rollout_last_lon =
                                        Some(stats.landing_lon.unwrap_or(snap.lon));
                                }

                                // v0.7.0 P2 fix — emit TouchdownDetected mit
                                // den ECHTEN Werten aus compute_landing_rate-
                                // Cascade (vorher: confidence falsch = sim-string,
                                // source hardcoded, vs_fpm nur impact_vs ohne
                                // Cascade-Fallbacks).
                                let landing_rate = impact_for_validation
                                    .as_ref()
                                    .and_then(|ir| touchdown_v2::compute_landing_rate(&v2_samples, ir, category).ok());
                                let impact_at_v = impact_for_validation
                                    .as_ref().map(|r| r.impact_at).unwrap_or(pending_at);
                                let (final_vs, final_src, final_conf) = match &landing_rate {
                                    Some(lr) => (
                                        lr.vs_fpm,
                                        lr.source.clone(),
                                        format!("{:?}", lr.confidence),
                                    ),
                                    None => (
                                        impact_vs,
                                        "impact_frame_fallback".to_string(),
                                        "Unknown".to_string(),
                                    ),
                                };
                                drop(stats);
                                record_event(
                                    &app,
                                    &flight.pirep_id,
                                    &FlightLogEvent::TouchdownDetected {
                                        timestamp: now,
                                        forensics_version: touchdown_v2::FORENSICS_VERSION,
                                        contact_at: pending_at,
                                        impact_at: impact_at_v,
                                        vs_fpm: final_vs,
                                        confidence: final_conf,
                                        source: final_src,
                                        sim: format!("{:?}", result.sim),
                                    },
                                );
                                stats = flight.stats.lock().expect("flight stats");
                            }
                            touchdown_v2::ValidationResult::FalseEdge { reason, .. } => {
                                tracing::warn!(
                                    pirep_id = %flight.pirep_id,
                                    edge_at = %pending_at,
                                    impact_vs = impact_vs,
                                    reason = ?reason,
                                    "v0.7.0 TD candidate FALSE_EDGE — ignoring, continue watching"
                                );
                                stats.pending_td_at = None;
                                stats.pending_td_premium_vs = None;
                                stats.pending_td_premium_g = None;
                            }
                        }
                    } else {
                        // Kein sample ab pending_at gefunden — Buffer-Drift, ignore
                        stats.pending_td_at = None;
                        stats.pending_td_premium_vs = None;
                        stats.pending_td_premium_g = None;
                    }
                }
            }

            // Legacy-Pfad fuer Capture-Window-Setup (=Pre-Buffer einkopieren) bleibt
            // unveraendert — wird jetzt nur fuer VALIDATED candidates aufgerufen.
            if false {
                // Pitch-Korrektur: world-frame Y-Velocity → body-axial
                // (xgs-Pattern). Bei typischem Touchdown-Pitch ~3-5°
                // ist cos(pitch)≈0.998, also <0.5% Unterschied. Bei
                // steilen Flares (STOL-Aircraft, ~10°) bis 1.5%.
                // Konsistent mit xgs's `vy * cos(theta * deg2rad)`.
                let pitch_rad = (snap.pitch_deg as f32) * std::f32::consts::PI / 180.0;
                let pitch_cos = pitch_rad.cos();
                let current_vs = snap.vertical_speed_fpm * pitch_cos;
                // VS-min der letzten 2 s — fängt den echten Sinkflug
                // ein bevor Rollout-Damping zugeschlagen hat. v0.5.5
                // erweitert das Fenster von 500 ms auf 2 s nachdem ein
                // Pilot-Test gezeigt hat dass 500 ms bei aggressivem
                // Flare nur Post-Touchdown-Rebound-Samples sieht (alle
                // VS-Werte positiv). 2 s deckt sicher die letzte
                // Flare-Phase ab; falls X-Plane uns RREF mit niedriger
                // Rate liefert haben wir trotzdem genug Samples drin.
                let lookback_start = now - chrono::Duration::milliseconds(2000);
                let recent_vs_min: f32 = stats
                    .snapshot_buffer
                    .iter()
                    .filter(|s| s.at >= lookback_start)
                    .map(|s| {
                        // Pitch-Korrektur auch auf Buffer-Samples — die
                        // sind je nach Aircraft beim Flare auch unter
                        // Nase-hoch-Bedingungen erfasst worden.
                        let p_rad = (s.pitch_deg as f32) * std::f32::consts::PI / 180.0;
                        s.vs_fpm * p_rad.cos()
                    })
                    .fold(f32::INFINITY, f32::min);
                let captured_vs = if recent_vs_min.is_finite() {
                    recent_vs_min.min(current_vs)
                } else {
                    current_vs
                };
                // Peak G im gleichen Window
                let recent_g_peak: f32 = stats
                    .snapshot_buffer
                    .iter()
                    .filter(|s| s.at >= lookback_start)
                    .map(|s| s.g_force)
                    .fold(0.0, f32::max);
                let captured_g = recent_g_peak.max(snap.g_force);

                stats.sampler_touchdown_at = Some(now);
                stats.sampler_touchdown_vs_fpm = Some(captured_vs);
                stats.sampler_touchdown_g_force = Some(captured_g);
                open_touchdown_capture_window(&mut stats, now);
                tracing::info!(
                    pirep_id = %flight.pirep_id,
                    captured_vs_fpm = captured_vs,
                    current_vs_fpm = current_vs,
                    captured_g = captured_g,
                    fnrml_n = snap.gear_normal_force_n,
                    on_ground = snap.on_ground,
                    "sampler-side touchdown edge detected"
                );
            }
            prev_in_air = Some(in_air_now);

            // v0.5.39: Continuous Post-TD-Capture + Dump.
            //
            // Solange Touchdown detektiert ist und wir noch nicht gedumpt
            // haben, sammelt jeder Sampler-Tick den aktuellen Snapshot ins
            // post_touchdown_buffer (= Pre-TD-Buffer wurde von
            // open_touchdown_capture_window initial reinkopiert). Nach
            // TOUCHDOWN_POST_WINDOW_MS wird der gesamte Buffer als ein
            // TouchdownWindow-Event in die JSONL geflusht — das schließt
            // das ~15-s-Loch (5 s pre + 10 s post @ 50 Hz ≈ 750 Samples)
            // das im Streamer-Tick wegen phpVMS-Latenz entstand.
            let dump_payload: Option<(DateTime<Utc>, Vec<TouchdownWindowSample>)> = {
                let td_at = stats.sampler_touchdown_at;
                let already_dumped = stats.touchdown_window_dumped_at.is_some();
                if let (Some(td_at), false) = (td_at, already_dumped) {
                    // Letzten Snapshot ins post-Buffer (snapshot_buffer.back()
                    // wurde in dieser Iteration oben push_back). Dedup gegen
                    // letzten Eintrag falls open_touchdown_capture_window den
                    // gleichen Snapshot grade reinkopiert hat.
                    if let Some(latest) = stats.snapshot_buffer.back().copied() {
                        let same_as_back = stats
                            .post_touchdown_buffer
                            .back()
                            .map(|s| s.at == latest.at)
                            .unwrap_or(false);
                        if !same_as_back {
                            stats.post_touchdown_buffer.push_back(latest);
                        }
                    }
                    let elapsed_ms = (now - td_at).num_milliseconds();
                    if elapsed_ms >= TOUCHDOWN_POST_WINDOW_MS {
                        // v0.13.15 (Pilot-Befund ViolonC 2026-05-31): NICHT
                        // mehr `drain(..)` — der Buffer muss erhalten bleiben,
                        // damit der spaeter beim PIREP-Filing gebaute
                        // LandingRecord (build_landing_record) die vollen 10 s
                        // Post-TD ins touchdown_profile uebernehmen kann. Vorher
                        // war der Buffer hier geleert → der Record sah nur die
                        // ~0.5 s aus dem 5-s-snapshot_buffer, obwohl der Chart
                        // "inkl. 10 s nach TD" verspricht. Der `already_dumped`-
                        // Guard oben verhindert weiteres Anhaengen; geleert wird
                        // der Buffer erst beim Flug-Reset (open_touchdown_capture
                        // _window / End-of-Flight).
                        let samples: Vec<TouchdownWindowSample> = stats
                            .post_touchdown_buffer
                            .iter()
                            .copied()
                            .map(TouchdownWindowSample::from)
                            .collect();
                        stats.touchdown_window_dumped_at = Some(now);
                        // v0.6.0: landing_critical_until wird nicht mehr vom
                        // Streamer konsumiert (Streamer ist vom phpVMS-IO
                        // entkoppelt). Buffer-Dump läuft hier unabhängig
                        // vom Critical-Window-Marker.
                        Some((td_at, samples))
                    } else {
                        None
                    }
                } else {
                    None
                }
            };

            let cutoff = now - chrono::Duration::seconds(TOUCHDOWN_BUFFER_SECS);
            while stats
                .snapshot_buffer
                .front()
                .is_some_and(|s| s.at < cutoff)
            {
                stats.snapshot_buffer.pop_front();
            }

            // Forensik-Analyse VOR Lock-Drop berechnen + im stats persistieren
            // damit der Touchdown-Payload-Builder im Streamer-Tick die Felder
            // direkt zur Verfuegung hat (anstatt aus der JSONL re-zu-parsen).
            let prepared_dump = if let Some((edge_at, samples)) = dump_payload {
                let mut analysis =
                    compute_landing_analysis(&samples, edge_at, snap.simulator);
                // v0.16.21: MSFS touchdown V/S SimVar-lag de-lag —
                // g-force-gated. Runs BEFORE the analysis is stored, the
                // accident heuristic, and the class re-derivation below, so
                // the corrected (un-lagged) `vs_at_edge_fpm` flows through
                // `canonical_landing_rate_fpm` to the score / PIREP / MQTT.
                // No-op for X-Plane / Other, helis, the accident band, and
                // any landing whose impact g corroborates the high V/S. The
                // returned Some(corrected) also routes the landing CLASS
                // through the corrected value below (class label ↔ score).
                let msfs_delag_vs = apply_msfs_touchdown_delag(
                    &mut analysis,
                    &stats.snapshot_buffer,
                    edge_at,
                    snap.simulator,
                    category,
                );
                stats.landing_analysis = Some(analysis.clone());
                // v0.7.19 GAF-707: Heuristik-Klassifikator EINMAL pro
                // Touchdown am TD-Edge ausfuehren — direkt nachdem die
                // landing_analysis (mit vs_at_edge_fpm etc) materialisiert
                // wurde. Spec §Klassifikator-Trigger-Punkte. NICHT im
                // 50-Hz-Loop. Worst-Case-Aggregation fuer Multi-TD
                // (Touch-and-Go) ist im Helper.
                apply_accident_heuristic(&mut stats, &analysis);
                Some((edge_at, samples, analysis, msfs_delag_vs))
            } else {
                None
            };

            // Dump-IO außerhalb des Lock-Holds — record_event macht
            // synchroness File-Append (~1-10 ms auf NTFS), das wollen wir
            // nicht das stats-Lock blockieren lassen.
            drop(stats);
            // v0.16.24: if the sampler-path runway correlation just fell
            // back to OurAirports (divert the pre-fetch missed), kick off the
            // on-demand navdata fetch for the actual landing airport — same
            // finalize-with-best wiring as the FSM path. Idempotent.
            maybe_fetch_actual_landing_navdata(&app, &flight);
            if let Some((edge_at, samples, analysis, msfs_delag_vs)) = prepared_dump {
                // v0.5.49 — IMMEDIATE persist nach dem Setzen von
                // touchdown_window_dumped_at. Vorher wurde der Flag in
                // stats gesetzt, aber save_active_flight wartete auf den
                // nächsten STATS_PERSIST_EVERY_TICKS-Tick. Wenn die App
                // dazwischen quitted (z.B. Pilot schließt sofort nach
                // Landing), war die persistente Kopie noch dumped_at=None
                // → nach Resume fired der Dump erneut. Genau das Symptom
                // aus dem PTO-705-Log (zwei TouchdownWindow-Events,
                // 18:48:25 und 18:51:16 nach Resume). Ein expliziter
                // Save direkt nach dem Setzen verhindert das.
                save_active_flight(&app, &flight);
                let count = samples.len();
                // v0.7.0 — clone fuer touchdown_v2 weiter unten
                // (samples wird gleich in record_event gemoved)
                let samples_for_v2 = samples.clone();
                record_event(
                    &app,
                    &flight.pirep_id,
                    &FlightLogEvent::TouchdownWindow {
                        timestamp: now,
                        edge_at,
                        samples,
                    },
                );
                record_event(
                    &app,
                    &flight.pirep_id,
                    &FlightLogEvent::LandingAnalysis {
                        timestamp: now,
                        edge_at,
                        analysis: analysis.clone(),
                    },
                );

                // v0.7.0 — Touchdown-Forensik v2 (Spec docs/spec/touchdown-forensics-v2.md).
                // Ersetzt den fruheren vs_at_edge-unconditional-override (= war
                // Bug #1 vom DAH 3181 Float-Streifschuss + 8 weitere Bugs).
                //
                // Neue Cascade:
                //   1. touchdown_v2::compute_impact_frame liefert contact_frame +
                //      impact_frame (= min vs in [contact-250ms, contact+100ms]) +
                //      initial_load_peak.
                //   2. touchdown_v2::compute_landing_rate macht VS-Cascade mit
                //      HARD GUARDS:
                //         vs_at_impact -> smoothed_500ms -> smoothed_1000ms ->
                //         pre_flare_peak -> REJECT (kein Score).
                //   3. Niemals positive Landerate (HARD GUARD strukturell).
                //   4. forensics_version = 2 marker geht in PIREP-payload.
                //
                // Legacy: bei REJECT (z.B. positive vs_at_edge UND alle smoothed
                // positiv = sollte nie passieren) bleibt das Feld unveraendert
                // (= alter SimVar-Wert wenn vorhanden).
                // Category-aware landing rate (loop-level `category`):
                // rotorcraft / seaplane touch down near-zero V/S, so the -10 fpm
                // fixed-wing acceptance floor in the cascade is relaxed.
                let v2_result = touchdown_v2::compute_impact_frame(&samples_for_v2, edge_at)
                    .and_then(|impact_result| {
                        touchdown_v2::compute_landing_rate(&samples_for_v2, &impact_result, category).ok()
                    });

                // v0.7.11: Edge-Wert aus dem 50-Hz-Buffer als kanonische
                // Score-Basis. Vorher haben wir bei v2-REJECT den SimVar-
                // latched-Wert behalten — das war unsinnig weil der 50-Hz-
                // Edge-Wert physikalisch genauer ist (interpoliert auf den
                // exakten on_ground-Edge). User-Forderung Mai 12: "warum
                // nutzen wir den MSFS Wert wenn wir das selber ermitteln".
                //
                // Neue Cascade-Ordnung:
                //   1. v2-Result (= raffinierte Cascade vs_at_impact ->
                //      smoothed_500ms -> smoothed_1000ms -> pre_flare_peak)
                //   2. vs_at_edge_fpm aus dem Buffer (= 50-Hz interpoliert)
                //   3. landing_rate_fpm unveraendert (= SimVar-latched
                //      Fallback wenn weder v2 noch Edge verfuegbar — sehr
                //      selten, nur bei Pre-v0.5.43 oder Buffer-Dump-Fail)
                let edge_vs = analysis
                    .get("vs_at_edge_fpm")
                    .and_then(|v| v.as_f64())
                    .map(|x| x as f32)
                    .filter(|v| v.is_finite() && *v < 0.0);

                let pg_500 = analysis.get("peak_g_post_500ms").and_then(|v| v.as_f64()).map(|x| x as f32);
                {
                    let mut s = flight.stats.lock().expect("flight stats");
                    if let Some(ref v2) = v2_result {
                        // Forensik-v2 hat einen plausiblen VS gewählt
                        // (HARD GUARD strukturell ausgeschlossen positiv)
                        // v0.7.1 P2.2-D: atomic write via finalize_landing_rate
                        // damit confidence/source zum finalen Wert konsistent
                        // bleiben.
                        let conf_str = format!("{:?}", v2.confidence);
                        finalize_landing_rate(
                            &mut s,
                            v2.vs_fpm,
                            Some(&conf_str),
                            Some(&v2.source),
                        );
                        tracing::info!(
                            pirep_id = %flight.pirep_id,
                            vs_fpm = v2.vs_fpm,
                            source = %v2.source,
                            confidence = ?v2.confidence,
                            forensics_version = v2.forensics_version,
                            "touchdown-forensics-v2 landing rate computed"
                        );
                    } else if let Some(edge) = edge_vs {
                        // v0.7.11: v2-REJECT-Fallback auf vs_at_edge_fpm
                        // statt SimVar-latched. Der Edge-Wert ist die
                        // 50-Hz-Buffer-Interpolation am exakten on_ground-
                        // Frame — genauer als der SimVar-latched-Read der
                        // typisch 1 Frame versetzt sein kann (Beispiel DAL804:
                        // SimVar -407 fpm vs Edge -364 fpm).
                        let previous = s.landing_rate_fpm.unwrap_or(0.0);
                        finalize_landing_rate(
                            &mut s,
                            edge,
                            Some("Medium"),
                            Some("vs_at_edge_50hz"),
                        );
                        tracing::info!(
                            pirep_id = %flight.pirep_id,
                            vs_fpm = edge,
                            previous = previous,
                            source = "vs_at_edge_50hz",
                            "v0.7.11: v2-REJECT, override mit vs_at_edge_fpm"
                        );
                    } else {
                        // Echter REJECT: weder v2 noch Edge verfuegbar.
                        // Pre-v0.5.43-Eintrag oder kompletter Buffer-Fail.
                        // Behalte den primary-chain Wert (= SimVar-latched).
                        tracing::warn!(
                            pirep_id = %flight.pirep_id,
                            "touchdown-forensics-v2 + edge beide nicht verfuegbar — keeping primary-chain value"
                        );
                    }
                    if let Some(g) = pg_500 {
                        // Nur ueberschreiben wenn der Buffer-Peak hoeher ist als
                        // der bisher gemessene (= echter Gear-Compression-Spike).
                        let cur = s.landing_peak_g_force.unwrap_or(0.0);
                        if g > cur { s.landing_peak_g_force = Some(g); }
                    }
                    // Re-Klassifizierung mit den neuen Werten
                    // BUG #6 fix: bounce_count from analysis (50Hz Sampler-Wahrheit),
                    // nicht vom Streamer-side s.bounce_count counter.
                    //
                    // v0.7.6 P1-2: `scored_bounce_count` aus dem Analysis-JSON
                    // ist die SSoT fuer den Sub-Score (filtert auf
                    // BOUNCE_SCORED_MIN_AGL_FT = 15 ft). Vorher hat das hier
                    // nur die Legacy-Klassifikation (LandingScore::classify)
                    // mit dem 5-ft-Forensic-Count gefuettert UND `s.bounce_count`
                    // wurde nicht zurueckgeschrieben → der spaetere PIREP-Build
                    // las den Streamer-Count (oft 0 weil der erst >35 ft armed)
                    // und der Score-Crate-Sub-Score `bounces` zeigte 100 obwohl
                    // die Forensik einen Hopser gesehen hatte (SAS9987 v0.7.5).
                    // Fix: scored_bounce_count zurueck in s.bounce_count damit
                    // das Sub-Score-Aggregat konsistent ist mit der Forensik.
                    // Spec docs/spec/v0.7.6-landing-payload-consistency.md §3 P1-2.
                    let scored_bounce: u8 = analysis.get("scored_bounce_count")
                        .and_then(|v| v.as_u64())
                        .map(|n| n.min(u8::MAX as u64) as u8)
                        // Fallback fuer alte Analysis-JSONs ohne neues Feld
                        // (Replays, JSONL-Recovery): Legacy bounce_count.
                        .or_else(|| analysis.get("bounce_count")
                            .and_then(|v| v.as_u64())
                            .map(|n| n.min(u8::MAX as u64) as u8))
                        .unwrap_or(s.bounce_count);
                    s.bounce_count = scored_bounce;
                    // v0.16.21: when the MSFS V/S-lag de-lag fired, route
                    // the CLASS through the same corrected (un-lagged) V/S
                    // that `canonical_landing_rate_fpm` now scores on. The
                    // `finalize_landing_rate` calls above set BOTH
                    // `landing_rate_fpm` AND `landing_peak_vs_fpm` from the
                    // v2/edge forensic value, which on a flared MSFS landing
                    // is the lagged peak — so we overwrite BOTH here so the
                    // class LABEL matches the corrected numeric score AND any
                    // direct reader of `landing_rate_fpm` (e.g. the
                    // `LandingFinalized` forensic event in
                    // `emit_landing_finalized`, which does not go through
                    // `canonical_landing_rate_fpm`) reports the same corrected
                    // rate — no class-vs-score and no field-vs-field split.
                    // The lagged value stays preserved in the analysis
                    // `vs_at_edge_fpm_raw` forensic key. The g-band term in
                    // `classify` is untouched, so a real firm impact can still
                    // only relax to the level g allows.
                    if let Some(corrected) = msfs_delag_vs {
                        s.landing_rate_fpm = Some(corrected);
                        s.landing_peak_vs_fpm = Some(corrected);
                    }
                    let peak_vs = s.landing_peak_vs_fpm.unwrap_or(0.0);
                    // v0.12.3 (LE8/QS-P1): classify on the EMA-scored G, not
                    // the raw 50 Hz peak — a single raw spike must not push
                    // the landing to Hard/Severe on its own.
                    let scored_g = score_g_for_stats(&s).scored_g;
                    let new_score = LandingScore::classify(peak_vs, scored_g, scored_bounce);
                    s.landing_score = Some(new_score);
                    s.landing_score_finalized = true;
                    // Reset announcement-flag damit announce_landing_score den
                    // Block jetzt durchstellt — vorher hat es wegen
                    // landing_score_finalized=false zurueckgehalten.
                    s.landing_score_announced = false;
                }

                let flare_score = analysis.get("flare_quality_score")
                    .and_then(|v| v.as_i64()).unwrap_or(-1);
                let smooth_500 = analysis.get("vs_smoothed_500ms_fpm")
                    .and_then(|v| v.as_f64()).unwrap_or(f64::NAN);
                tracing::info!(
                    pirep_id = %flight.pirep_id,
                    sample_count = count,
                    window_ms = TOUCHDOWN_POST_WINDOW_MS,
                    flare_score = flare_score,
                    smooth_500ms_fpm = smooth_500,
                    vs_v2_fpm = v2_result.as_ref().map(|v| v.vs_fpm),
                    vs_v2_source = v2_result.as_ref().map(|v| v.source.as_str()),
                    peak_g_post_500ms = pg_500,
                    "touchdown window + analysis flushed; score recomputed from buffer"
                );
            }

            // v0.7.0 — Phase H Step 2: Multi-TD via Climb-out-Reset.
            //
            // Spec Sektion 6 (LandingEpisode-Lifecycle): wenn aircraft nach
            // einem TD wieder hochsteigt > 100ft AGL, ist der nächste TD eine
            // neue Episode (Touch-and-Go / Go-Around / Re-Approach). Damit
            // der Sampler die zweite Landung erfasst, muessen wir die single-
            // shot Guards zuruecksetzen.
            //
            // Konsequenz fuer PIREP-Score: der LETZTE validierte TD ist der
            // "final landing" TD. Ein dump pro Episode = ein touchdown_window
            // event + landing_analysis event in der JSONL. Score wird beim
            // PIREP-filing aus dem letzten gewonnen.
            //
            // PTO 705 Beispiel: Touch um 07:54:30 -> climbout auf 1560ft AGL ->
            // Re-Approach -> echter Touch um 08:01:29 -> dieser bekommt jetzt
            // eigenen capture-cycle + Score.
            {
                let mut s = flight.stats.lock().expect("flight stats");
                let dumped = s.touchdown_window_dumped_at.is_some();
                let agl_now = snap.altitude_agl_ft as f32;
                if dumped && agl_now > 100.0 {
                    // Climb-out detected nach Dump → bereit fuer naechste TD.
                    // Reset alle TD-state-fields.
                    s.sampler_touchdown_at = None;
                    s.sampler_touchdown_vs_fpm = None;
                    s.sampler_touchdown_g_force = None;
                    s.touchdown_window_dumped_at = None;
                    s.post_touchdown_buffer.clear();
                    s.landing_score_finalized = false;
                    // v0.16.5: re-arm the sampler-path metadata stamp. Its
                    // once-guard keys on `landing_lat.is_none()` — on a
                    // touch-and-go the FINAL touchdown must stamp fresh
                    // metadata, not keep TD#1's (the FSM Landing arm never
                    // runs on bush flights to overwrite it). Clearing the
                    // anchor re-arms the guard; the next stamp overwrites
                    // every other landing_* field anyway.
                    s.landing_lat = None;
                    s.landing_lon = None;
                    // v0.16.6: stability stats + rollout are per-episode too —
                    // the FINAL touchdown must re-evaluate its own approach
                    // window and re-accumulate its own rollout (on bush
                    // flights no FSM Landing arm ever overwrites them).
                    clear_approach_stability_and_rollout(&mut s);
                    // landing_critical_until bleibt write-only (legacy field)
                    tracing::info!(
                        pirep_id = %flight.pirep_id,
                        agl_ft = agl_now,
                        "v0.7.0 Multi-TD reset — climb-out > 100ft AGL detected after dump, ready for next TD"
                    );
                }
            }
        }
        tracing::info!(pirep_id = %flight.pirep_id, "touchdown sampler stopped");
    });
}

/// v0.13.18: reine FOB-Ableitung des Fuel-Flow (testbar). Genutzt vom
/// Position-Streamer als Fallback, wenn die Standard-SimVar `ENG FUEL FLOW PPH`
/// nichts liefert (iniBuilds/Aerosoft A340-600 / ToLiss). `fuel_flow ≈ ΔFOB/Δt`.
///
/// - `None`, wenn `dt_secs` unter dem Glättungs-Fenster liegt → Aufrufer hält
///   den letzten Wert (kein Flackern bei kurzen Ticks).
/// - sonst die Rate in kg/h, geclampt auf `[0, FF_MAX]`: Tankung (negativ) oder
///   ein FOB-Sprung (Dump/Reset) ergeben `0` statt eines unsinnigen Werts.
fn derive_fuel_flow_kg_per_h(prev_fob_kg: f32, cur_fob_kg: f32, dt_secs: f32) -> Option<f32> {
    const FF_DERIVE_WINDOW_S: f32 = 60.0;
    // 4-Mot-Heavy verbrennt grob 5–8 t/h; > 30 t/h ist physikalisch unplausibel.
    const FF_MAX_KG_PER_H: f32 = 30_000.0;
    if dt_secs < FF_DERIVE_WINDOW_S {
        return None;
    }
    let dt_h = dt_secs / 3600.0;
    let rate = (prev_fob_kg - cur_fob_kg) / dt_h;
    Some(if rate.is_finite() && (0.0..=FF_MAX_KG_PER_H).contains(&rate) {
        rate
    } else {
        0.0
    })
}

// ---- v0.16.10 Fuel-Used-Fallback (Task B) ----
/// SimVar gilt als "lebendig" sobald sie mehr als diesen Wert meldet —
/// dann hat sie Vorrang vor dem FOB-Delta.
const FUEL_USED_SIMVAR_ALIVE_KG: f32 = 0.5;
/// FOB-Delta muss mindestens so groß sein bevor der Fallback greift
/// (filtert FOB-Mess-Rauschen am Gate raus).
const FUEL_USED_MIN_DELTA_KG: f32 = 5.0;
/// Steigt der FOB mehr als so viel ÜBER die Baseline, war das ein
/// Mid-Flight-/Gate-Refuel → Baseline auf den neuen Maximalwert
/// re-latchen statt negative Deltas zu produzieren.
const FUEL_USED_REFUEL_RELATCH_KG: f32 = 50.0;
/// v0.16.10 QS (M1): Gate-DEFUEL — ein instantaner FOB-ABFALL pro Tick
/// über diese Schwelle (vor dem Takeoff) re-latcht die Baseline NACH
/// UNTEN. Spiegelt den Block-Fuel-Defuel-Guard (`DEFUEL_THRESHOLD_KG`
/// in `update_running_stats`): 200 kg liegt über jedem realistischen
/// Engine-Burn eines Tick-Intervalls, also kein False-Positive durch
/// normalen Betrieb.
const FUEL_USED_DEFUEL_RELATCH_KG: f32 = 200.0;

/// PMDG liefert FUEL TOTAL QUANTITY USED nicht (Live-Befund GLO4587
/// 2026-06-11) — Fallback aus FOB-Delta.
///
/// Latcht beim ersten Tick mit Fuel an Bord die FOB-Baseline
/// (`initial_fob_kg`, persistiert via PersistedFlightStats) und leitet
/// `fuel_used_kg` als `baseline − FOB` ab, solange die SimVar-Quelle
/// tot ist (< FUEL_USED_SIMVAR_ALIVE_KG — beide Adapter stempeln das
/// Feld aktuell hart auf 0.0). Kommt die SimVar je zum Leben, gewinnt
/// sie. Refuel-Schutz: FOB > Baseline + 50 kg → Baseline re-latchen
/// (Delta startet danach wieder bei ~0, nie negativ — geclampt).
///
/// v0.16.10 QS (M1) Defuel-Schutz: lädt der Pilot am Gate Fuel AB
/// (SimBrief-Korrektur nach unten), bliebe die Baseline sonst auf dem
/// alten Maximum und `fuel_used` wäre den GANZEN Flug um die Defuel-
/// Menge zu hoch. Solange der Flug noch nicht airborne war
/// (`pre_takeoff`, vom Aufrufer als `stats.takeoff_at.is_none()`
/// durchgereicht) re-latcht ein instantaner Tick-Abfall über
/// `FUEL_USED_DEFUEL_RELATCH_KG` die Baseline NACH UNTEN
/// (`prev_fob_kg` = FOB des Vor-Ticks, `stats.last_fuel_kg` VOR dem
/// Stats-Update dieses Ticks). Airborne re-latchen wir NIE nach unten —
/// Caveat: ein Fuel-Jettison zählt damit als "verbraucht"; das ist
/// gewollt konservativ (abgelassener Sprit ist weg, und ein Downward-
/// Re-Latch in der Luft würde echte Dumps unsichtbar machen und wäre
/// von einem Sensor-Glitch nicht unterscheidbar).
fn fuel_used_effective_kg(
    initial_fob_kg: &mut Option<f32>,
    simvar_used_kg: f32,
    fob_kg: f32,
    pre_takeoff: bool,
    prev_fob_kg: Option<f32>,
) -> f32 {
    if fob_kg > 0.0 {
        match *initial_fob_kg {
            // Flugstart (bzw. erster Tick mit Fuel) → Baseline latchen.
            None => *initial_fob_kg = Some(fob_kg),
            // Refuel: FOB deutlich über Baseline → auf neues Max re-latchen.
            Some(initial) if fob_kg > initial + FUEL_USED_REFUEL_RELATCH_KG => {
                *initial_fob_kg = Some(fob_kg);
            }
            // v0.16.10 QS (M1): Gate-Defuel — instantaner Tick-Abfall
            // > 200 kg, Ergebnis unter der Baseline, noch nicht
            // airborne → Baseline nach unten re-latchen. Gradueller
            // APU-/Taxi-Burn (wenige kg pro Tick) triggert das nie.
            Some(initial)
                if pre_takeoff
                    && fob_kg < initial
                    && prev_fob_kg
                        .is_some_and(|prev| prev - fob_kg > FUEL_USED_DEFUEL_RELATCH_KG) =>
            {
                *initial_fob_kg = Some(fob_kg);
            }
            Some(_) => {}
        }
    }
    // SimVar lebt → sie ist authoritativ (kennt z.B. APU-Burn exakt).
    if simvar_used_kg >= FUEL_USED_SIMVAR_ALIVE_KG {
        return simvar_used_kg;
    }
    match *initial_fob_kg {
        Some(initial) => {
            let delta = initial - fob_kg;
            if delta > FUEL_USED_MIN_DELTA_KG {
                // Clamp ist Belt-and-Braces — delta > 5 impliziert > 0.
                delta.max(0.0)
            } else {
                // Kleines/negatives Delta (Gate, frisches Refuel) →
                // SimVar-Wert (≈ 0) unverändert durchreichen.
                simvar_used_kg
            }
        }
        None => simvar_used_kg,
    }
}

fn spawn_position_streamer(app: AppHandle, flight: Arc<ActiveFlight>, client: Client) {
    if flight
        .streamer_spawned
        .compare_exchange(false, true, Ordering::SeqCst, Ordering::SeqCst)
        .is_err()
    {
        tracing::debug!(
            pirep_id = %flight.pirep_id,
            "position streamer already running, skipping spawn"
        );
        return;
    }
    tauri::async_runtime::spawn(async move {
        tracing::info!(pirep_id = %flight.pirep_id, "position streamer started");
        // Heartbeat tracker: ensures `POST /pireps/{id}/update` fires at
        // least every `HEARTBEAT_INTERVAL` so phpVMS's RemoveExpiredLiveFlights
        // cron never reaches the inactivity threshold. Initialised one
        // interval in the past so the first eligible tick triggers it.
        let mut last_heartbeat: std::time::Instant =
            std::time::Instant::now() - HEARTBEAT_INTERVAL;
        // Phase-adaptive cadence: re-read the current phase on every tick so
        // the sleep matches what the aircraft is actually doing right now
        // (5 s during takeoff/landing, 8 s on approach/final, 10 s on the
        // ground / climb / descent, 30 s in cruise — capped at 30 s so the
        // live map never goes more than half a minute stale).
        // v0.4.1: track last good snapshot so we can detect Sim-Disconnect
        // (kein Snapshot mehr für > SIM_DISCONNECT_THRESHOLD_S s) und den
        // letzten bekannten Stand für Repositions-Anzeige im Cockpit-Banner
        // einfrieren.
        let mut last_good_snap: Option<SimSnapshot> = None;
        let mut last_good_snap_at: Option<std::time::Instant> = None;
        // v0.6.0: `last_phpvms_post_at` ist entfallen — der Streamer-Tick
        // postet nicht mehr selber an phpVMS (push to outbox only).
        // Die Cadence-Steuerung sitzt jetzt im phpVMS-Worker.
        //
        // v0.12.4 (Spec docs/spec/v0.12.4-score-consistency.md, LE4):
        // Edge-Detektor für das touchdown_rollout_finalized-Event. Hält den
        // `landing_at`-Zeitstempel des zuletzt gepublishten Touchdowns —
        // so wird bei Touch-and-Go / Stop-and-Go JEDER Touchdown mit seinem
        // EIGENEN Rollout gepublisht (nicht nur der erste). Loop-lokal —
        // übersteht keinen App-Neustart, was OK ist: nach einem Neustart
        // re-published der erste Tick einmal idempotent (Recorder-Patch ist
        // idempotent + touchdown-scharf), siehe LE7 Punkt 5.
        let mut last_published_rollout_ts: Option<i64> = None;
        // v0.13.18: FOB-abgeleiteter Fuel-Flow-Fallback. Manche Addons
        // (iniBuilds/Aerosoft A340-600, ToLiss-Engine-Modell) treiben die
        // Standard-SimVar `ENG FUEL FLOW PPH` NICHT → `fuel_flow_kg_per_h`
        // bleibt None, obwohl Sprit verbrannt wird (Live IRM1140/IBE778). Der
        // Tankinhalt (FOB) läuft aber korrekt runter, also leiten wir die Rate
        // daraus ab: fuel_flow ≈ ΔFOB / Δt, neu berechnet über ein ~60-s-
        // Fenster (glättet FOB-Rauschen) und dazwischen gehalten. Loop-lokal,
        // kein FlightStats/Resume-Touch. Greift NUR wenn die direkte SimVar
        // fehlt → kein Regress. Reine Live-Map-/Telemetrie-Anzeige (der
        // Gesamt-Verbrauch wird ohnehin aus dem FOB-Delta gerechnet).
        let mut ff_last_fob_kg: Option<f32> = None;
        let mut ff_last_fob_at: Option<std::time::Instant> = None;
        let mut ff_derived_kg_per_h: Option<f32> = None;
        loop {
            let current_phase = {
                let stats = flight.stats.lock().expect("flight stats");
                stats.phase
            };
            // v0.5.35: loop runs at adaptive cadence — 3s in Cruise/Climb/etc,
            // schneller (1s, 500ms) wenn der Pilot nah am Boden ist
            // (Approach/Final/Landing/Takeoff unter 1000ft AGL).
            // Verhindert dass der Touchdown-Moment in eine Sample-Lücke
            // fällt — User-Report 2026-05-08: GA-Flug C152 hatte
            // 10s Mean-Interval und peak_vs_fpm=-33 statt realer ~-350.
            // phpVMS POST throttled separately further down (8-30s).
            let tick_interval = {
                let phase = flight.stats.lock().expect("flight stats").phase;
                let agl = last_good_snap.as_ref().map(|s| s.altitude_agl_ft);
                adaptive_tick_interval(phase, agl)
            };
            tokio::time::sleep(tick_interval).await;
            if flight.stop.load(Ordering::Relaxed) {
                break;
            }

            // v0.13.9 Stream F (Mid-Session Sim-Crash-Recovery — LE27):
            // Wenn was_just_resumed=true gesetzt ist, pausiert der Streamer
            // den Position-Push (kein FSM-Step, kein Outbox-Push, kein
            // MQTT-Position-Publish, kein PhpVMS-Worker-Trigger). Der
            // ResumeFlightBanner (Frontend) zeigt sich via flight_status-
            // Polling und der Pilot muss aktiv bestaetigen.
            //
            // v0.13.10 (QS-Round-1 Fix): Heartbeat wird WAEHREND der Pause
            // weiterhin gesendet, sonst killt phpVMS' RemoveExpiredLiveFlights-
            // Cron den PIREP nach `acars.live_time` (default 2h) — auch
            // realistisch wenn der Pilot den Banner laengere Zeit ignoriert
            // (Telefon, Pinkelpause, Pause im Sim). Heartbeat-Body baut sich
            // aus dem letzten guten Pre-Recovery-Snapshot (last_good_snap
            // VOR diesem Tick, identisch zum SimPause/SimDisconnect-Pfad).
            if flight.was_just_resumed.load(Ordering::Relaxed) {
                if last_heartbeat.elapsed() >= HEARTBEAT_INTERVAL {
                    if let Some(hb) = last_good_snap.as_ref() {
                        let (phase, body) = {
                            let stats = flight.stats.lock().expect("flight stats");
                            let p = stats.phase;
                            (p, build_heartbeat_body(hb, &stats, p))
                        };
                        match client.update_pirep(&flight.pirep_id, &body).await {
                            Ok(()) => {
                                last_heartbeat = std::time::Instant::now();
                                {
                                    let mut stats =
                                        flight.stats.lock().expect("flight stats");
                                    stats.last_heartbeat_at = Some(Utc::now());
                                }
                                tracing::debug!(
                                    pirep_id = %flight.pirep_id,
                                    phase = ?phase,
                                    "PIREP heartbeat sent during sim-crash-recovery banner"
                                );
                            }
                            Err(ApiError::NotFound) => {
                                // phpVMS hat den PIREP serverseitig
                                // entfernt — sauberer Recovery-Pfad
                                // (gleiches Verhalten wie SimPause).
                                handle_remote_cancellation(
                                    &app,
                                    &flight,
                                    "POST update (sim-crash-recovery)",
                                );
                            }
                            Err(_) => {
                                // Transient — retry naechster Tick.
                            }
                        }
                    }
                }
                continue;
            }

            // v0.13.9 Stream F: Snapshot VOR Overwrite cachen damit die
            // Recovery-Detection (airborne -> on_ground mit massivem
            // Altitude-Drop) den Vergleich machen kann.
            let previous_snap_for_recovery: Option<SimSnapshot> = last_good_snap.clone();

            let snapshot = current_snapshot(&app);
            if let Some(ref s) = snapshot {
                last_good_snap = Some(s.clone());
                last_good_snap_at = Some(std::time::Instant::now());
            }

            // v0.13.9 Stream F (LE27): Mid-Session Sim-Crash-Detection.
            //
            // Symptom realer Pilot-Befunde (User Michel, 25.05.2026 ITY 608
            // KBOS->KJFK, 3x XP12-Reload heute beobachtet):
            //   - vor Reload: airborne in CRUISE, FL320-FL360
            //   - nach Reload: on_ground=true am naechstgelegenen Airport,
            //     Altitude springt -30k ft in einem Sample-Intervall
            //
            // Diese Kombination ist physikalisch unmoeglich (max real
            // achievable descent ~4000 fpm = 4000 ft pro Minute), also
            // eindeutig ein Sim-Reload-Artefakt.
            //
            // Wir setzen `was_just_resumed=true` — der bereits existierende
            // Stream-F-Workflow (Banner + Re-Check) greift dann automatisch
            // via flight_status-Polling. Naechster Tick laeuft in den Guard
            // oben hinein und pausiert den Streamer bis Pilot entschieden hat.
            //
            // Schwelle: 5000 ft Altitude-Drop in einem Tick UND on_ground
            // erst false dann true UND vorherige FlightPhase = airborne-Set.
            // Position-Distance ist NICHT geprueft weil XP12-Crash-Recovery
            // am NAECHSTEN Airport (typisch 10-20 km vom Cruise-Punkt) eine
            // Drift unter Schwellenwert haben kann (RESUME_DRIFT_WARN_NM=50nm).
            if let (Some(prev), Some(curr)) = (previous_snap_for_recovery.as_ref(), snapshot.as_ref()) {
                if is_mid_session_sim_crash_recovery(
                    current_phase,
                    prev.on_ground,
                    prev.altitude_msl_ft,
                    curr.on_ground,
                    curr.altitude_msl_ft,
                ) {
                    let alt_drop_ft = (prev.altitude_msl_ft - curr.altitude_msl_ft).abs();
                    flight.was_just_resumed.store(true, Ordering::SeqCst);
                    // v0.13.11 (QS-Round-2 Fix): last_good_snap auf den Pre-
                    // Recovery-Snapshot zuruecksetzen damit der Pause-
                    // Heartbeat (Guard oben im naechsten Tick) phpVMS mit den
                    // echten airborne-Cruise-Werten beliefert statt dem
                    // falschen Ground/Reload-Snapshot, den der Adapter
                    // gerade geliefert hat.
                    last_good_snap = previous_snap_for_recovery.clone();
                    save_active_flight(&app, &flight);
                    log_activity_handle(
                        &app,
                        ActivityLevel::Error,
                        "⚠ Sim-Reload erkannt — Aufzeichnung pausiert".to_string(),
                        Some(format!(
                            "Vorher: FL{:.0} airborne · jetzt: {:.0} ft am Boden bei LAT {:.3}° LON {:.3}° (Drop: {:.0} ft). \
                            Bitte im ResumeFlightBanner waehlen: zurueck zur Cruise-Position positionieren + Position pruefen, \
                            oder trotzdem fortsetzen — der Sprung wird im Activity-Log dokumentiert.",
                            prev.altitude_msl_ft / 100.0,
                            curr.altitude_msl_ft,
                            curr.lat,
                            curr.lon,
                            alt_drop_ft,
                        )),
                    );
                    tracing::warn!(
                        pirep_id = %flight.pirep_id,
                        prev_alt_ft = prev.altitude_msl_ft,
                        curr_alt_ft = curr.altitude_msl_ft,
                        alt_drop_ft,
                        curr_on_ground = curr.on_ground,
                        prev_on_ground = prev.on_ground,
                        phase = ?current_phase,
                        "Stream F mid-session sim-crash-recovery detected — streamer paused"
                    );
                    // Skip restlichen Tick — naechster Tick faellt in den
                    // Guard oben hinein und pausiert bis Pilot bestaetigt.
                    continue;
                }
            }

            // Spec v0.7.15 F5/F6: Sim-eigene Pause-Detection.
            //
            // SimSnapshot.paused wird vom Adapter gesetzt:
            // - MSFS: aus dem SimConnect-`Paused`/`Unpaused`-Event-Atomic
            //   (siehe crates/sim-msfs/src/adapter.rs)
            // - X-Plane: aus dem Plugin `sim/time/paused` DataRef
            //   (siehe F6 unten, falls Plugin v0.7.15+)
            //
            // Wenn der Sim eigenstaendig pausiert und ACARS noch nicht im
            // Pause-State ist: paused_since setzen, last_known speichern,
            // Reason vermerken. Der bestehende `is_paused`-Block
            // (siehe unten) macht dann den Rest — Skip-Streamer-Tick +
            // Heartbeat-mit-last_good_snap.
            let snap_says_paused = snapshot.as_ref().map(|s| s.paused).unwrap_or(false);
            if snap_says_paused {
                let already_paused = {
                    let stats = flight.stats.lock().expect("flight stats");
                    stats.paused_since.is_some()
                };
                if !already_paused {
                    if let Some(ref snap) = snapshot {
                        let paused = PausedSnapshot {
                            lat: snap.lat,
                            lon: snap.lon,
                            heading_deg: snap.heading_deg_true,
                            altitude_ft: snap.altitude_indicated_ft.unwrap_or(snap.altitude_msl_ft),
                            fuel_total_kg: snap.fuel_total_kg,
                            zfw_kg: snap.zfw_kg,
                        };
                        let detail = format!(
                            "Letzte bekannte Position: LAT {:.4}° · LON {:.4}° · ALT {:.0} ft",
                            paused.lat, paused.lon, paused.altitude_ft,
                        );
                        {
                            let mut stats = flight.stats.lock().expect("flight stats");
                            stats.paused_since = Some(Utc::now());
                            stats.paused_last_known = Some(paused);
                            stats.current_pause_reason = Some(PauseReason::SimPause);
                        }
                        log_activity_handle(
                            &app,
                            ActivityLevel::Info,
                            "⏸ Simulator pausiert — AeroACARS pausiert die Aufzeichnung.".to_string(),
                            Some(detail),
                        );
                        save_active_flight(&app, &flight);
                        tracing::info!(
                            pirep_id = %flight.pirep_id,
                            "sim-pause detected via snapshot.paused flag"
                        );
                    }
                }
            }

            // Spec sim-disconnect-auto-resume F1 (Auto-Resume):
            //
            // Frueher (v0.4.1) war Pause ein strikter Block — der Streamer
            // wartete auf manuellen Klick selbst wenn der Sim wieder Daten
            // lieferte. Reale Folge im AUA-323-Incident: Pilot hat die
            // Pause erst nach der Landung gemerkt → 23 min Datenloch +
            // Server-Splitter macht zwei Sessions.
            //
            // Neu: wenn wir wieder einen Sim-Snapshot haben, wird der
            // Pause-State automatisch beendet (apply_pause_resume), die
            // Pause-Dauer in den Akkumulator akkumuliert (damit der
            // Flight-Time-Wert im PIREP korrekt bleibt) und der Streamer
            // verarbeitet den aktuellen Tick normal weiter.
            //
            // Heartbeat (= `POST /pireps/{id}/update`) laeuft auch waehrend
            // der Pause weiter — siehe Heartbeat-Code-Pfad unten. Damit
            // bleibt der phpVMS-PIREP aktiv egal wie lange der Sim weg ist.
            //
            // Manueller Resume-Button (`flight_resume_after_disconnect`)
            // bleibt als Fallback erhalten — z.B. wenn der Sim gar keine
            // Snapshots mehr liefert, der Pilot aber den PIREP weiter-
            // fuehren will.
            let is_paused = flight
                .stats
                .lock()
                .expect("flight stats")
                .paused_since
                .is_some();
            if is_paused {
                // Resume-Bedingung: Snapshot ist da UND Sim ist NICHT
                // mehr in eigener Pause (snap.paused=false). Sonst
                // bleibt der Streamer pausiert auch wenn Snapshots
                // kommen (F5: Frozen-Snapshots waehrend Esc-Pause).
                let can_resume = snapshot.is_some() && !snap_says_paused;
                if can_resume {
                    // Auto-Resume: Reason aus dem State (gesetzt vom
                    // Disconnect- bzw. Sim-Pause-Detect-Pfad). Helper
                    // updated State, schreibt Activity-Log, persistiert
                    // active_flight.json. Anschliessend faellt der Tick
                    // durch zum normalen Position-Stream-Pfad.
                    let resume_reason = {
                        let stats = flight.stats.lock().expect("flight stats");
                        stats
                            .current_pause_reason
                            .unwrap_or(PauseReason::SimDisconnect)
                    };
                    let _ = apply_pause_resume(
                        &app,
                        &flight,
                        snapshot.as_ref(),
                        resume_reason,
                    );
                    // fall-through zum naechsten Code-Pfad
                } else {
                    // Sim liefert keine Daten → weiter pausieren.
                    //
                    // QS-Finding HIGH (2026-05-12): Der ALTE Pfad hatte hier
                    // ein blankes `continue`, welches den Heartbeat-Code-Pfad
                    // weiter unten (Z. ~12143) komplett ueberspringt. Folge:
                    // phpVMS sieht nach dem letzten Pre-Pause-Heartbeat keine
                    // Updates mehr und der `RemoveExpiredLiveFlights`-Cron
                    // killt den PIREP nach ~6h. Die Spec-Aussage "Heartbeat
                    // haelt PIREP unbegrenzt am Leben" war damit nicht
                    // umgesetzt.
                    //
                    // Fix: bevor wir continue'n, einen Heartbeat senden wenn
                    // (a) wir je einen guten Snapshot hatten (sonst gibt's
                    // nichts zu senden) und (b) das HEARTBEAT_INTERVAL
                    // erreicht ist. Wir nutzen `last_good_snap` als
                    // Position-/Phase-Quelle — der Heartbeat-Body braucht
                    // einen Snapshot fuer level/fuel/etc. Werte sind
                    // eingefroren auf dem Pre-Pause-Stand, was korrekt ist:
                    // der Flieger steht "weiterhin" dort, bis ein Sim-
                    // Snapshot beweist dass er weiter geflogen ist.
                    // Heartbeat-Quelle: bei SimPause haben wir den
                    // aktuellen (eingefrorenen) Snapshot, bei
                    // SimDisconnect nur den letzten guten Pre-Pause-
                    // Snapshot. Beide funktionieren — der Heartbeat-
                    // Body enthaelt eingefrorene Position/Alt/Fuel-
                    // Werte was korrekt ist: der Flieger steht zu
                    // dem Zeitpunkt eingefroren.
                    let hb_snap = snapshot.as_ref().or(last_good_snap.as_ref());
                    if let Some(hb) = hb_snap {
                        if last_heartbeat.elapsed() >= HEARTBEAT_INTERVAL {
                            let (phase, body) = {
                                let stats = flight.stats.lock().expect("flight stats");
                                let p = stats.phase;
                                (p, build_heartbeat_body(hb, &stats, p))
                            };
                            match client.update_pirep(&flight.pirep_id, &body).await {
                                Ok(()) => {
                                    last_heartbeat = std::time::Instant::now();
                                    {
                                        let mut stats =
                                            flight.stats.lock().expect("flight stats");
                                        stats.last_heartbeat_at = Some(Utc::now());
                                    }
                                    tracing::debug!(
                                        pirep_id = %flight.pirep_id,
                                        phase = ?phase,
                                        sim_paused = snap_says_paused,
                                        "PIREP heartbeat sent during pause"
                                    );
                                }
                                Err(ApiError::NotFound) => {
                                    // phpVMS hat den PIREP soft-deleted —
                                    // gleiches Verhalten wie im Standard-
                                    // Heartbeat-Pfad weiter unten.
                                    handle_remote_cancellation(&app, &flight, "POST update (paused)");
                                    break;
                                }
                                Err(e) => {
                                    tracing::warn!(
                                        pirep_id = %flight.pirep_id,
                                        phase = ?phase,
                                        error = %e,
                                        "PIREP heartbeat failed during pause"
                                    );
                                }
                            }
                        }
                    }
                    tokio::time::sleep(Duration::from_secs(5)).await;
                    continue;
                }
            }

            // Sim-Disconnect-Detection: hatten irgendwann mal Daten, aber
            // der letzte gute Snapshot ist > THRESHOLD her → Pause auslösen.
            let disconnect_detected = match (last_good_snap_at, snapshot.is_some()) {
                (Some(t), false) => {
                    t.elapsed() > Duration::from_secs(SIM_DISCONNECT_THRESHOLD_S as u64)
                }
                _ => false,
            };
            if disconnect_detected {
                if let Some(ref last) = last_good_snap {
                    let paused = PausedSnapshot {
                        lat: last.lat,
                        lon: last.lon,
                        heading_deg: last.heading_deg_true,
                        altitude_ft: last.altitude_msl_ft,
                        fuel_total_kg: last.fuel_total_kg,
                        zfw_kg: last.zfw_kg,
                    };
                    {
                        let mut stats = flight.stats.lock().expect("flight stats");
                        if stats.paused_since.is_none() {
                            stats.paused_since = Some(Utc::now());
                            stats.paused_last_known = Some(paused.clone());
                            // Spec v0.7.15 F5: Reason setzen damit der
                            // Resume-Helper weiss welcher Trigger es war.
                            stats.current_pause_reason =
                                Some(PauseReason::SimDisconnect);
                        }
                    }
                    let detail = format!(
                        "Letzte bekannte Position: LAT {:.4}° · LON {:.4}° · HDG {:.0}° · ALT {:.0} ft · Fuel {:.0} kg · ZFW {}",
                        paused.lat,
                        paused.lon,
                        paused.heading_deg,
                        paused.altitude_ft,
                        paused.fuel_total_kg,
                        paused
                            .zfw_kg
                            .map(|v| format!("{:.0} kg", v))
                            .unwrap_or_else(|| "—".to_string())
                    );
                    log_activity_handle(
                        &app,
                        ActivityLevel::Warn,
                        "⏸ Sim getrennt — Flug pausiert. Klicke „Flug wiederaufnehmen\" sobald du repositioniert hast.".to_string(),
                        Some(detail),
                    );
                    save_active_flight(&app, &flight);
                    tracing::warn!(
                        pirep_id = %flight.pirep_id,
                        "sim disconnect detected, flight paused"
                    );
                }
                continue;
            }

            // Wenn weder pausiert noch frischer Snapshot da, einfach weiter
            // warten — bis zum Threshold poll'n wir geduldig.
            let Some(mut snap) = snapshot else {
                tracing::debug!(
                    pirep_id = %flight.pirep_id,
                    "no sim snapshot yet — waiting (will pause after {}s)",
                    SIM_DISCONNECT_THRESHOLD_S
                );
                continue;
            };

            // v0.13.18: Fuel-Flow-Fallback aus dem FOB-Verlauf (siehe loop-
            // lokale ff_*-Deklaration oben). Direkt nach dem snap-Binding, damit
            // ALLE nachgelagerten Verbraucher (phpVMS-Position-Payload, MQTT-
            // Live-Map) den abgeleiteten Wert sehen.
            if snap.fuel_flow_kg_per_h.is_none() {
                let now_i = std::time::Instant::now();
                match (ff_last_fob_kg, ff_last_fob_at) {
                    (Some(prev_fob), Some(prev_at)) => {
                        let dt_secs = now_i.duration_since(prev_at).as_secs_f32();
                        // Nur über ein volles Fenster neu rechnen (None = noch
                        // zu kurz → letzten abgeleiteten Wert weiter halten).
                        if let Some(rate) =
                            derive_fuel_flow_kg_per_h(prev_fob, snap.fuel_total_kg, dt_secs)
                        {
                            ff_derived_kg_per_h = Some(rate);
                            ff_last_fob_kg = Some(snap.fuel_total_kg);
                            ff_last_fob_at = Some(now_i);
                        }
                    }
                    _ => {
                        // Erste Baseline setzen (noch kein abgeleiteter Wert).
                        ff_last_fob_kg = Some(snap.fuel_total_kg);
                        ff_last_fob_at = Some(now_i);
                    }
                }
                snap.fuel_flow_kg_per_h = ff_derived_kg_per_h;
            } else {
                // Direkte SimVar liefert → Baseline frischhalten, NICHT ableiten.
                ff_last_fob_kg = Some(snap.fuel_total_kg);
                ff_last_fob_at = Some(std::time::Instant::now());
                ff_derived_kg_per_h = None;
            }

            // v0.16.10: Fuel-Used-Fallback aus dem FOB-Delta. PMDG liefert
            // FUEL TOTAL QUANTITY USED nicht (Live-Befund GLO4587
            // 2026-06-11: Cruise zeigte fuel_used_kg = 0.0 während der FOB
            // korrekt runterlief) — tatsächlich stempeln BEIDE Adapter das
            // Snapshot-Feld hart auf 0.0. Gleiche Stelle wie der Fuel-Flow-
            // Fallback oben, damit ALLE nachgelagerten Verbraucher (JSONL-
            // Flight-Log Position-Events, Forensik-Analysen) den
            // abgeleiteten Wert sehen. Die FOB-Baseline lebt PERSISTIERT in
            // den FlightStats (Resume-sicher — Fuel-Used zählt fürs PIREP-
            // Umfeld). Der PIREP-`fuel_used`-Payload selbst rechnet
            // unabhängig davon weiter block_fuel_kg − last_fuel_kg (Peak-
            // FOB-Delta, war nie von der toten SimVar abhängig).
            {
                let mut stats = flight.stats.lock().expect("flight stats");
                // v0.16.10 QS (M1): pre_takeoff + Vor-Tick-FOB für den
                // Gate-Defuel-Re-Latch. `takeoff_at` latcht beim ersten
                // →Takeoff-Übergang (inkl. Rescue-Latch-Backfill, siehe
                // latch_takeoff_stats) und bleibt danach Some — Defuel-
                // Re-Latch ist also exakt bis zum ersten Airborne aktiv.
                // `last_fuel_kg` wird erst weiter unten in
                // update_running_stats (via step_flight) auf den
                // aktuellen Tick gestempelt — hier lesen wir noch den
                // FOB des VOR-Ticks.
                let pre_takeoff = stats.takeoff_at.is_none();
                let prev_fob_kg = stats.last_fuel_kg;
                snap.fuel_used_kg = fuel_used_effective_kg(
                    &mut stats.initial_fob_kg,
                    snap.fuel_used_kg,
                    snap.fuel_total_kg,
                    pre_takeoff,
                    prev_fob_kg,
                );
            }

            // Snapshot the current phase BEFORE stepping so we can pass
            // the from→to pair to the recorder when it changes.
            // Plus snapshot Takeoff/Block-flags fuer MQTT-Snapshot-Publish
            // beim None→Some-Übergang nach step_flight.
            // v0.7.14: prev_landing_at war frueher fuer Discord-Webhook-Post
            // — Discord macht jetzt der Recorder zentral. Wir tracken nur noch
            // Takeoff + Block fuer die MQTT-Snapshot-Publishes (weiter unten).
            let (prev_phase, prev_block_off_at, prev_takeoff_at) = {
                let stats = flight.stats.lock().expect("flight stats");
                (stats.phase, stats.block_off_at, stats.takeoff_at)
            };
            // Update running stats AND step the flight-phase FSM.
            // v0.5.25: arr_airport_elevation_ft fuer HAT-basiertes
            // Stable-Approach-Gate. Lazy lookup beim ersten Tick wo wir
            // die Elevation noch nicht haben — phpVMS-API-Cache aus
            // state.airports liefert sie sobald airport_get aufgerufen
            // wurde (passiert beim Bid-Pickup ueblicherweise schon).
            // Ohne Elevation: Fallback auf AGL-Filter, used_hat=false.
            {
                let mut stats_g = flight.stats.lock().expect("flight stats");
                if stats_g.arr_airport_elevation_ft.is_none() {
                    let app_state = app.state::<AppState>();
                    let airports = app_state.airports.lock().expect("airports lock");
                    if let Some(arr) = airports.get(&flight.arr_airport.to_uppercase()) {
                        if let Some(elev) = arr.elevation {
                            stats_g.arr_airport_elevation_ft = Some(elev as f32);
                            tracing::info!(
                                arr = %flight.arr_airport,
                                elevation_ft = elev,
                                "arr airport elevation cached for HAT-based Stable-Approach-Gate"
                            );
                        }
                    }
                }
            }
            let phase_change = step_flight(&flight, &snap);

            // v0.16.24: approach-phase divert navdata pre-fetch. On a
            // committed, stable descending approach to a field OTHER than
            // the planned `arr_airport`, warm that field's Navigraph navdata
            // so the runway correlation at touchdown hits the cache instead
            // of falling back to the coarse OurAirports CSV. The decision is
            // pure + debounced (`divert_prefetch_decision`); the fetch is
            // idempotent per ICAO (`spawn_navdata_fetch` skips cached ones),
            // so this is bounded — it only fires on a genuine divergence.
            {
                let prefetch_icao = {
                    let mut stats = flight.stats.lock().expect("flight stats");
                    divert_prefetch_decision(&mut stats, &snap, &flight.arr_airport, Utc::now())
                };
                if let Some(icao) = prefetch_icao {
                    tracing::info!(
                        actual = %icao,
                        planned = %flight.arr_airport,
                        "divert approach detected — pre-fetching navdata for actual landing airport"
                    );
                    spawn_navdata_fetch(&app, &flight, vec![icao]);
                }
            }

            // v0.16.24: on-demand navdata fetch at touchdown. If the FSM
            // Landing arm just correlated the runway and had to fall back to
            // OurAirports (the actual landing field wasn't cached — e.g. a
            // late divert the approach pre-fetch didn't catch), kick off a
            // fetch for the real airport NOW so `build_landing_record` can
            // re-correlate against the warm cache at PIREP-filing time
            // (finalize-with-best). Non-racy: the provisional OurAirports
            // result is already stamped; this only improves what the record
            // builder sees later. Idempotent (per-ICAO guard).
            maybe_fetch_actual_landing_navdata(&app, &flight);

            // v0.16.6: rollout for sampler-path landings (bush flights — the
            // FSM never reaches Landing, so its arm never accumulates). Runs
            // AFTER step_flight so the post-step `stats.phase` gates out the
            // Landing case (the FSM arm has just ticked the same helper) and
            // BEFORE the rollout-finalized publish block below so a finalise
            // on this tick is published immediately.
            {
                let mut stats = flight.stats.lock().expect("flight stats");
                sampler_path_rollout_tick(&mut stats, &snap);
            }

            // #phase-v2 Cutover: v2-Phase dieses Ticks für die Publish-Pfade
            // (MQTT-Position, phpVMS-Heartbeat) cachen. `None` bei Pause/Slew
            // (Schatten-Engine tickt dann nicht) → Publish fällt auf v1 zurück.
            let mut tick_shadow_phase: Option<FlightPhase> = None;

            // v0.16.12 (#phase-v2): Schatten-Phasen-Engine ticken — NACH
            // step_flight (braucht die autoritative Post-Step-Phase als
            // Sync-Quelle außerhalb des En-Route-Bands), VOR dem JSONL-
            // Position-Append unten (die Schatten-Felder sollen im selben
            // Snapshot landen). Beobachtet nur: kein Pfad liest die
            // Schatten-Phase für Entscheidungen. Pause/Slew friert die
            // Engine ein wie die alte FSM (step_flight returnt dort früh);
            // die >5-min-Gap-Erkennung im Segmenter fängt den Resume ab.
            if !snap.paused && !snap.slew_mode {
                let shadow_now = Utc::now();
                let mut stats = flight.stats.lock().expect("flight stats");
                let old_phase_post_step = stats.phase;
                // cruise_ref: FMC-Cruise-Alt (PMDG, vom Piloten gepflegt,
                // step-climb-aktuell) vor dem geplanten Bid-/Manual-Level.
                let cruise_ref_ft = snap
                    .pmdg
                    .as_ref()
                    .and_then(|p| p.fmc_cruise_alt_ft)
                    .filter(|&ft| ft > 0)
                    .map(f64::from)
                    .or(stats.planned_cruise_alt_ft);
                // Divergenz-dt: Abstand zum letzten Schatten-Tick, auf 10 s
                // gekappt (Streamer tickt ≤ 3 s; Resume-Lücken zählen so
                // höchstens einen gedeckelten Tick).
                let dt_secs = stats
                    .shadow_last_tick_at
                    .map(|prev| {
                        ((shadow_now - prev).num_milliseconds() as f64 / 1000.0)
                            .clamp(0.0, 10.0)
                    })
                    .unwrap_or(0.0);
                stats.shadow_last_tick_at = Some(shadow_now);
                let (shadow_phase, shadow_segment) = stats.shadow_engine.step(
                    shadow_now,
                    snap.altitude_msl_ft,
                    snap.altitude_agl_ft,
                    snap.vertical_speed_fpm,
                    snap.on_ground,
                    old_phase_post_step,
                    cruise_ref_ft,
                );
                stats.shadow_phase = Some(shadow_phase);
                stats.shadow_segment = Some(shadow_segment);
                tick_shadow_phase = Some(shadow_phase);
                // Holding ist in v2 (Runde 1) bewusst unmodelliert —
                // diese Ticks zählen nicht als Divergenz (Report klammert
                // sie ebenfalls aus).
                if shadow_phase != old_phase_post_step
                    && old_phase_post_step != FlightPhase::Holding
                {
                    stats.shadow_divergence_secs += dt_secs;
                }
                drop(stats);
                // Additive Telemetrie-Felder: landen via `snap.clone()` im
                // JSONL-Position-Event (lokaler Recorder → VPS-Upload).
                // Der alte VPS-Recorder speichert sie verbatim mit — NULL
                // Recorder-Änderungen nötig.
                snap.shadow_phase = Some(phase_to_snake(shadow_phase).to_string());
                snap.shadow_segment =
                    Some(shadow_segment.as_snake_str().to_string());
            }

            // v0.12.4 (Spec docs/spec/v0.12.4-score-consistency.md, LE4):
            // Sobald `step_flight` den Rollout finalisiert hat (~40 kt /
            // Heading-Turn-off), das touchdown_rollout_finalized-Event mit
            // dem FINALEN rollout_distance_m nachschicken. `touchdown_complete`
            // bleibt davon unberührt (Live-Event, schon vorher gesendet) —
            // dieses Event patcht beim Recorder nur das Anzeige-Rohfeld.
            //
            // Touchdown-scharf: `touchdown_at` = `landing_at` (= ts des
            // zugehörigen TouchdownPayloads). Wir publishen einmal pro
            // distinktem `landing_at` — bei Touch-and-Go bekommt also jeder
            // Touchdown sein eigenes Event statt nur der erste.
            {
                let finalized = {
                    let stats = flight.stats.lock().expect("flight stats");
                    if stats.rollout_finalized {
                        // `landing_at` None (z.B. direkt nach einem T&G) →
                        // kein Publish; der nächste Touchdown setzt es neu.
                        stats.landing_at.map(|td| {
                            (
                                td.timestamp_millis(),
                                stats.rollout_distance_m.unwrap_or(0.0),
                                stats.rollout_finalize_reason.clone(),
                            )
                        })
                    } else {
                        None
                    }
                };
                if let Some((touchdown_at, rollout_m, reason)) = finalized {
                    if last_published_rollout_ts != Some(touchdown_at) {
                        let app_state = app.state::<AppState>();
                        let mqtt = app_state.mqtt.lock().await;
                        if let Some(handle) = mqtt.as_ref() {
                            handle.touchdown_rollout_finalized(
                                aeroacars_mqtt::TouchdownRolloutFinalizedPayload {
                                    ts: Utc::now().timestamp_millis(),
                                    pirep_id: flight.pirep_id.clone(),
                                    touchdown_at,
                                    rollout_distance_m: rollout_m,
                                    finalize_reason: reason,
                                },
                            );
                        }
                        last_published_rollout_ts = Some(touchdown_at);
                        tracing::info!(
                            pirep_id = %flight.pirep_id,
                            touchdown_at,
                            rollout_m,
                            "touchdown_rollout_finalized published"
                        );
                    }
                }
            }

            // v0.7.14: Pilot-Client-Discord-Posts fuer Takeoff + Landing
            // entfernt — Recorder postet das jetzt zentral via MQTT-Trigger
            // (`takeoff` + `touchdown` Events publishen sowieso, Recorder
            // abonniert sie). Audit Q4-2026-05 (C1).
            // v0.5.14: MQTT block + takeoff snapshots. Fire on the same
            // None→Some transitions used by the Discord webhook block
            // above. Block fires when block_off_at is stamped (=
            // pushback / first taxi-out motion); takeoff fires when
            // takeoff_at is stamped (= aircraft has lifted off).
            // Both use retain=true so a Monitor that joins mid-flight
            // sees the snapshot.
            {
                let block_payload_opt: Option<aeroacars_mqtt::BlockPayload> = {
                    let stats = flight.stats.lock().expect("flight stats");
                    if prev_block_off_at.is_none() && stats.block_off_at.is_some() {
                        Some(aeroacars_mqtt::BlockPayload {
                            ts: stats
                                .block_off_at
                                .map(|t| t.timestamp_millis())
                                .unwrap_or(0),
                            block_fuel_kg: stats.block_fuel_kg,
                            planned_block_fuel_kg: stats.planned_block_fuel_kg,
                            planned_burn_kg: stats.planned_burn_kg,
                            planned_reserve_kg: stats.planned_reserve_kg,
                            planned_zfw_kg: stats.planned_zfw_kg,
                            planned_tow_kg: stats.planned_tow_kg,
                            planned_ldw_kg: stats.planned_ldw_kg,
                            planned_max_zfw_kg: stats.planned_max_zfw_kg,
                            planned_max_tow_kg: stats.planned_max_tow_kg,
                            planned_max_ldw_kg: stats.planned_max_ldw_kg,
                            planned_route: stats.planned_route.clone(),
                            planned_alternate: stats.planned_alternate.clone(),
                            dep_gate: stats.dep_gate.clone(),
                            dep_metar: stats.dep_metar_raw.clone(),
                        })
                    } else {
                        None
                    }
                };
                let takeoff_payload_opt: Option<aeroacars_mqtt::TakeoffPayload> = {
                    let stats = flight.stats.lock().expect("flight stats");
                    if prev_takeoff_at.is_none() && stats.takeoff_at.is_some() {
                        Some(aeroacars_mqtt::TakeoffPayload {
                            ts: stats
                                .takeoff_at
                                .map(|t| t.timestamp_millis())
                                .unwrap_or(0),
                            takeoff_weight_kg: stats.takeoff_weight_kg.map(|w| w as f32),
                            takeoff_fuel_kg: stats.takeoff_fuel_kg,
                            takeoff_lat: Some(snap.lat),
                            takeoff_lon: Some(snap.lon),
                            dep_metar: stats.dep_metar_raw.clone(),
                            dep_runway: snap.selected_runway.clone(),
                        })
                    } else {
                        None
                    }
                };
                if block_payload_opt.is_some() || takeoff_payload_opt.is_some() {
                    let app_state = app.state::<AppState>();
                    let mqtt = app_state.mqtt.lock().await;
                    if let Some(handle) = mqtt.as_ref() {
                        if let Some(p) = block_payload_opt {
                            // v0.5.34: Forensik-Mitschnitt ins JSONL
                            record_event(
                                &app,
                                &flight.pirep_id,
                                &FlightLogEvent::BlockSnapshot {
                                    timestamp: Utc::now(),
                                    payload: serde_json::to_value(&p)
                                        .unwrap_or(serde_json::Value::Null),
                                },
                            );
                            handle.block(p);
                        }
                        if let Some(p) = takeoff_payload_opt {
                            // v0.5.34: Forensik-Mitschnitt ins JSONL
                            record_event(
                                &app,
                                &flight.pirep_id,
                                &FlightLogEvent::TakeoffSnapshot {
                                    timestamp: Utc::now(),
                                    payload: serde_json::to_value(&p)
                                        .unwrap_or(serde_json::Value::Null),
                                },
                            );
                            handle.takeoff(p);
                        }
                    }
                }
            }
            // Detect when the touchdown-analyzer window has just locked
            // in a final score so we can emit the activity-log entry
            // exactly once. `landing_score` flips from None to Some
            // inside `step_flight` after TOUCHDOWN_WINDOW_SECS.
            // Returns Some(message) the first time a score is announced
            // so the streamer can mirror it into `acars/logs`.
            let landing_log_message = announce_landing_score(&app, &flight);
            // v0.5.11: MQTT touchdown event. Fires once per landing
            // when the score message gets generated (= touchdown was
            // captured + scored). Snapshot relevant fields from
            // FlightStats inside a short-lived block so the
            // std::sync::MutexGuard (not Send) doesn't span the
            // tokio Mutex `.await` below.
            if landing_log_message.is_some() {
                // v0.7.18 (B-012): Touchdown-Airport-Resolution. Lookup-
                // Closure greift in den AppState.airports-Cache.
                let airport_lookup_data: std::collections::HashMap<String, (f64, f64)> = {
                    let app_state = app.state::<AppState>();
                    let airports = app_state.airports.lock().expect("airports lock");
                    airports
                        .iter()
                        .filter_map(|(k, v)| match (v.lat, v.lon) {
                            (Some(la), Some(lo)) => Some((k.clone(), (la, lo))),
                            _ => None,
                        })
                        .collect()
                };
                let payload_opt: Option<aeroacars_mqtt::TouchdownPayload> = {
                    let stats = flight.stats.lock().expect("flight stats");
                    // v0.15.23: derive the touchdown timestamp from the sampler's
                    // validated touchdown, falling back to the FSM `landing_at`.
                    // On the short/low VFR path the sampler finalizes the score
                    // BEFORE the FSM stamps `landing_at` (which only happens at
                    // Arrived via the fallback, ~70-215 s later) — gating this live
                    // MQTT touchdown publish on `landing_at` meant the touchdown
                    // was scored but NEVER published, so the recorder saw
                    // no_touchdown → INT hold (GSG308/GSG301). `sampler_touchdown_at`
                    // is set the instant the touchdown validates, in any phase, so
                    // the publish now fires on the same tick the score is announced.
                    stats.sampler_touchdown_at.or(stats.landing_at).map(|td_ts| {
                        let rwy_match = stats.runway_match.as_ref();
                        // B-012: Touchdown-Airport via Cascade aufloesen.
                        let td_resolution = resolve_touchdown_airport(
                            rwy_match,
                            stats.landing_lat,
                            stats.landing_lon,
                            &flight.arr_airport,
                            |icao| {
                                airport_lookup_data
                                    .get(&icao.to_uppercase())
                                    .copied()
                            },
                        );
                        // v0.8.0: identische Assessment-Werte wie
                        // im LandingRecord (single source: assess_touchdown).
                        let payload_assessed = assess_touchdown(&stats);
                        aeroacars_mqtt::TouchdownPayload {
                            ts: td_ts.timestamp_millis(),
                            // v0.11.1: Pilot-Client-Version aus dem Cargo-
                            // Manifest in jeden Touchdown mitsenden, damit
                            // die Webapp-Reports-Liste + LandingAnalysis-
                            // Header die Version direkt anzeigen koennen
                            // (vorher war client_version nur in FlightMeta,
                            // landete also nie in der Touchdown-DB-Row).
                            client_version: Some(env!("CARGO_PKG_VERSION")),
                            // v0.7.19 (QS-R2 Finding 1): Recorder/Webapp
                            // targeted Korrektur-Events per pirep_id auf
                            // den exakten Touchdown-Row.
                            pirep_id: Some(flight.pirep_id.clone()),
                            // v0.7.17 (B-015a QS-Round-2): Edge-Wert hat
                            // Vorrang — siehe `score_basis_vs_fpm()` Doc.
                            // Live-Touchdown-MQTT-Top-Level-Wert war
                            // bisher der einzige verbleibende Pfad mit
                            // der alten `landing_rate_fpm.or(peak)`-
                            // Cascade. Konsumenten (Recorder-DB
                            // `touchdowns.vs_fpm`, Discord-Touchdown-
                            // Posts, Live-Hardlanding-Notifications)
                            // bekommen jetzt durchgaengig den Edge-Wert.
                            vs_fpm: score_basis_vs_fpm(&stats)
                                .map(|v| v.round() as i32)
                                .unwrap_or(0),
                            ias_kt: stats
                                .landing_speed_kt
                                .map(|v| v.round() as i32)
                                .unwrap_or(0),
                            // v0.5.17: GS captured separately from IAS,
                            // falls aware of head/tailwind.
                            gs_kt: stats
                                .landing_groundspeed_kt
                                .map(|v| v.round() as i32),
                            pitch_deg: stats.landing_pitch_deg,
                            // v0.5.17: bank at touchdown (= "Landing
                            // Roll" in maintenance-plugin lingo,
                            // captured in v0.5.16 alongside pitch).
                            bank_deg: stats.landing_bank_deg,
                            g_load: stats.landing_g_force,
                            peak_g_load: stats.landing_peak_g_force,
                            // v0.12.3 (LE7/LE8): zentraler Scored-G-Helper —
                            // EMA-Wert, sonst raw_fallback; nie None (QS-P2).
                            // peak_g_load (oben) bleibt der rohe Wert.
                            scored_g_load: Some(score_g_for_stats(&stats).scored_g),
                            scored_g_method: Some(
                                score_g_for_stats(&stats).method.as_str().to_string(),
                            ),
                            sideslip_deg: stats.touchdown_sideslip_deg,
                            headwind_kt: stats.landing_headwind_kt,
                            crosswind_kt: stats.landing_crosswind_kt,
                            score: stats.landing_score.map(|s| s.numeric()),
                            bounce: Some(stats.bounce_count > 0),
                            bounce_count: Some(stats.bounce_count),
                            // v0.16.6 (Daten-Audit 2026-06-11): `approach_runway`
                            // ist praktisch nie gesetzt → das Top-Level-Feld war
                            // bei 407/407 VPS-Flügen None, und die Webapp-Anzeigen
                            // (Stats/Heatmap/Pilots + Live-Notifications), die
                            // `touchdowns.runway` lesen, zeigten NIE eine Runway —
                            // obwohl der Korrelations-Match (97,5 % Trefferquote)
                            // direkt daneben im Payload steht. Fallback auf den
                            // Match-Ident füllt die DB-Spalte für neue Flüge.
                            runway: stats.approach_runway.clone().or_else(|| {
                                stats
                                    .runway_match
                                    .as_ref()
                                    .map(|m| m.runway_ident.clone())
                            }),
                            // v0.7.18 (B-012): aufgelöster Touchdown-Airport
                            // statt blind auf flight.arr_airport zu setzen.
                            airport: Some(td_resolution.icao.clone()),
                            airport_source: Some(
                                td_resolution.source.as_wire_str().to_string(),
                            ),
                            airport_distance_to_destination_nm:
                                td_resolution.distance_to_destination_nm,
                            airport_nearest_distance_nm:
                                td_resolution.nearest_distance_nm,
                            // v0.7.18 (R1-4): Plan-Destination mit-publishen
                            // damit die Webapp den Off-airport-Banner gegen
                            // den echten geplanten Wert vergleichen kann.
                            planned_arr_airport: Some(flight.arr_airport.clone()),
                            lat: stats.landing_lat,
                            lon: stats.landing_lon,
                            heading_true_deg: stats.landing_heading_true_deg,
                            heading_mag_deg: stats.landing_heading_deg,
                            landing_weight_kg: stats.landing_weight_kg.map(|w| w as f32),
                            landing_fuel_kg: stats.landing_fuel_kg,
                            // v0.7.17 (B-015d): OFP-Plan-Werte ans MQTT-
                            // Touchdown-Payload anhängen damit die Webapp
                            // den Loadsheet-Sub-Score genauso berechnen
                            // kann wie der Pilot-Client.
                            planned_zfw_kg: stats.planned_zfw_kg,
                            planned_tow_kg: stats.planned_tow_kg,
                            rollout_distance_m: stats.rollout_distance_m.map(|d| d as f32),
                            approach_vs_stddev_fpm: stats.approach_vs_stddev_fpm,
                            approach_bank_stddev_deg: stats.approach_bank_stddev_deg,
                            go_around_count: Some(stats.go_around_count),
                            arr_metar: stats.arr_metar_raw.clone(),
                            runway_match_icao: rwy_match.map(|m| m.airport_ident.clone()),
                            runway_match_ident: rwy_match.map(|m| m.runway_ident.clone()),
                            runway_match_distance_m: rwy_match
                                .map(|m| (m.touchdown_distance_from_threshold_ft as f32) * 0.3048),
                            runway_match_centerline_offset_m: rwy_match
                                .map(|m| m.centerline_distance_m as f32),
                            // v0.5.23: Touchdown-Forensik — alle Schaetzer-
                            // Zwischenergebnisse fuer Server-seitige
                            // Algorithmus-Vergleiche (siehe stats Felder
                            // landing_vs_estimate_*_fpm + landing_vs_source).
                            simulator: stats.landing_simulator
                                .map(|s| s.to_string()),
                            vs_estimate_xp_fpm: stats.landing_vs_estimate_xp_fpm,
                            vs_estimate_msfs_fpm: stats.landing_vs_estimate_msfs_fpm,
                            vs_source: stats.landing_vs_source
                                .map(|s| s.to_string()),
                            gear_force_peak_n: stats.landing_gear_force_peak_n,
                            estimate_window_ms: stats.landing_estimate_window_ms,
                            estimate_sample_count: stats.landing_estimate_sample_count,
                            // v0.5.25: Approach-Stability v2 — Stable-Approach-
                            // Gate-konform mit HAT-statt-AGL, V/S-Jerk,
                            // IAS-σ, Excessive-Sink, Stable-Config.
                            approach_vs_deviation_fpm: stats.approach_vs_deviation_fpm,
                            approach_max_vs_deviation_below_500_fpm: stats
                                .approach_max_vs_deviation_below_500_fpm,
                            approach_bank_stddev_filtered_deg: stats
                                .approach_bank_stddev_filtered_deg,
                            approach_runway_changed_late: stats.approach_runway_changed_late,
                            approach_stable_at_gate: stats.approach_stable_at_gate,
                            approach_window_sample_count: stats.approach_window_sample_count,
                            approach_vs_jerk_fpm: stats.approach_vs_jerk_fpm,
                            approach_ias_stddev_kt: stats.approach_ias_stddev_kt,
                            approach_excessive_sink: Some(stats.approach_excessive_sink),
                            approach_stable_config: stats.approach_stable_config,
                            approach_used_hat: Some(stats.approach_used_hat),
                            // v0.5.26
                            landing_wing_strike_severity_pct: stats.landing_wing_strike_severity_pct,
                            // v0.7.6 P1-3: Raw-Wert bleibt im Payload
                            // (interne Diagnostik), Web blendet bei
                            // runway_geometry_trusted=false aus.
                            landing_float_distance_m: stats.landing_float_distance_m,
                            // v0.7.6 P1-3: Bei untrusted Runway-Geometrie
                            // auf None setzen (kein "TD Zone 1" auf Basis
                            // einer falschen Runway-Geometrie wie GSG303
                            // v0.7.5: K5S9 statt OR66, 3.5 km Centerline-
                            // Offset). Spec docs/spec/v0.7.6-landing-
                            // payload-consistency.md §3 P1-3.
                            landing_touchdown_zone: {
                                let (trusted, _) = runway_geometry_trust_check(
                                    rwy_match.map(|m| m.airport_ident.as_str()),
                                    &flight.arr_airport,
                                    stats.divert_hint.as_ref()
                                        .and_then(|h| h.actual_icao.as_deref()),
                                    rwy_match.map(|m| m.centerline_distance_m as f32),
                                    stats.landing_float_distance_m,
                                );
                                if trusted { stats.landing_touchdown_zone } else { None }
                            },
                            landing_vref_deviation_kt: stats.landing_vref_deviation_kt,
                            landing_vref_source: stats.landing_vref_source.map(|s| s.to_string()),
                            approach_stable_at_da: stats.approach_stable_at_da,
                            approach_stall_warning_count: Some(stats.approach_stall_warning_count),
                            landing_yaw_rate_deg_per_sec: stats.landing_yaw_rate_deg_per_sec,
                            landing_brake_energy_proxy: stats.landing_brake_energy_proxy,
                            // v0.5.22: feeds the live-monitor's "Bahn-
                            // Auslastung"-sub-score so it matches the
                            // in-app PIREP value 1:1.
                            runway_length_m: rwy_match
                                .map(|m| m.length_ft * 0.3048),
                            // v0.12.4 (Spec docs/spec/v0.12.4-score-
                            // consistency.md, LE5): prozentuale Abweichung
                            // des **tatsächlichen Trip-Burn** (takeoff_fuel −
                            // landing_fuel) vom geplanten OFP-Trip-Burn
                            // (planned_burn_kg). Positiv = Mehrverbrauch.
                            //
                            // Vorher (bis v0.12.3) fälschlich block-fuel-basiert
                            // (block_fuel − landing_fuel) — das zählt den Taxi-
                            // out-Sprit mit und wich daher vom v0.7.1-Sub-Score
                            // ab (SAS9987: -2.28% hier vs -5.0% im sub_scores;
                            // DLH 1386: +9.5% statt korrekt +4.2%). Jetzt
                            // identische Basis wie `LandingRecord.
                            // fuel_efficiency_pct` und `sub_scores[].fuel`.
                            fuel_efficiency_pct: trip_burn_efficiency_pct(
                                stats.takeoff_fuel_kg,
                                stats.landing_fuel_kg,
                                stats.planned_burn_kg,
                            ),
                            // v0.5.39: 50-Hz-Forensik aus dem Sampler-Buffer.
                            // landing_analysis ist ein serde_json::Value das
                            // von compute_landing_analysis() im Sampler-Loop
                            // geschrieben wird. Wenn None (Sampler hat noch
                            // nicht 10s post-TD gesehen, oder Touchdown vor
                            // Buffer-Init), bleiben alle Felder None.
                            vs_at_edge_fpm: ana_f32(&stats.landing_analysis, "vs_at_edge_fpm"),
                            vs_smoothed_250ms_fpm: ana_f32(&stats.landing_analysis, "vs_smoothed_250ms_fpm"),
                            vs_smoothed_500ms_fpm: ana_f32(&stats.landing_analysis, "vs_smoothed_500ms_fpm"),
                            vs_smoothed_1000ms_fpm: ana_f32(&stats.landing_analysis, "vs_smoothed_1000ms_fpm"),
                            vs_smoothed_1500ms_fpm: ana_f32(&stats.landing_analysis, "vs_smoothed_1500ms_fpm"),
                            peak_g_post_500ms: ana_f32(&stats.landing_analysis, "peak_g_post_500ms"),
                            peak_g_post_1000ms: ana_f32(&stats.landing_analysis, "peak_g_post_1000ms"),
                            // v0.7.17 (B-009): G-Force-Forensik
                            g_at_edge: ana_f32(&stats.landing_analysis, "g_at_edge"),
                            g_smoothed_250ms_post: ana_f32(&stats.landing_analysis, "g_smoothed_250ms_post"),
                            g_median_post_500ms: ana_f32(&stats.landing_analysis, "g_median_post_500ms"),
                            g_p95_post_500ms: ana_f32(&stats.landing_analysis, "g_p95_post_500ms"),
                            max_gear_force_n: ana_f32(&stats.landing_analysis, "max_gear_force_n"),
                            peak_vs_pre_flare_fpm: ana_f32(&stats.landing_analysis, "peak_vs_pre_flare_fpm"),
                            vs_at_flare_end_fpm: ana_f32(&stats.landing_analysis, "vs_at_flare_end_fpm"),
                            flare_reduction_fpm: ana_f32(&stats.landing_analysis, "flare_reduction_fpm"),
                            flare_dvs_dt_fpm_per_sec: ana_f32(&stats.landing_analysis, "flare_dvs_dt_fpm_per_sec"),
                            flare_quality_score: ana_i32(&stats.landing_analysis, "flare_quality_score"),
                            flare_detected: ana_bool(&stats.landing_analysis, "flare_detected"),
                            bounce_max_agl_ft: ana_f32(&stats.landing_analysis, "bounce_max_agl_ft"),
                            forensic_sample_count: ana_u32(&stats.landing_analysis, "sample_count"),
                            // v0.8.3 (#8): Forensic + scored Counts mit-publizieren.
                            // Quelle: touchdown_v2::compute_landing_analysis schreibt
                            // beide ins analysis-JSON (Zeile ~12863). aeroacars-live
                            // (recorder) + LandingPanel.tsx (Pilot-Client) sehen so
                            // den UnterschiedDes zwischen forensic (5 ft) und scored
                            // (15 ft) und koennen score-freie Hopser dezent surface.
                            forensic_bounce_count: ana_u32(&stats.landing_analysis, "forensic_bounce_count")
                                .map(|n| n.min(u8::MAX as u32) as u8),
                            scored_bounce_count: ana_u32(&stats.landing_analysis, "scored_bounce_count")
                                .map(|n| n.min(u8::MAX as u32) as u8),
                            // v0.7.6 P1-3: Trust-Status auch in den
                            // touchdown_complete-Payload damit aeroacars-
                            // live (Touchdown-Tab) und ggf. Pilot-Client-
                            // Replay-View den Hinweis-Pill rendern koennen.
                            // Pure-function Check, gleiche Inputs wie bei
                            // landing_touchdown_zone (siehe oben).
                            runway_geometry_trusted: {
                                let (trusted, _) = runway_geometry_trust_check(
                                    rwy_match.map(|m| m.airport_ident.as_str()),
                                    &flight.arr_airport,
                                    stats.divert_hint.as_ref()
                                        .and_then(|h| h.actual_icao.as_deref()),
                                    rwy_match.map(|m| m.centerline_distance_m as f32),
                                    stats.landing_float_distance_m,
                                );
                                Some(trusted)
                            },
                            runway_geometry_reason: {
                                let (_, reason) = runway_geometry_trust_check(
                                    rwy_match.map(|m| m.airport_ident.as_str()),
                                    &flight.arr_airport,
                                    stats.divert_hint.as_ref()
                                        .and_then(|h| h.actual_icao.as_deref()),
                                    rwy_match.map(|m| m.centerline_distance_m as f32),
                                    stats.landing_float_distance_m,
                                );
                                reason.map(String::from)
                            },
                            // v0.7.19 GAF-707 Accident-Detection.
                            // `accident_classifier_version` ist der
                            // Sentinel — v0.7.19+ setzt ihn IMMER, auch
                            // wenn kein Accident erkannt wurde. Webapp
                            // unterscheidet damit "Classifier lief, kein
                            // Accident" von "historischer Payload, bitte
                            // nachklassifizieren".
                            accident_classifier_version: Some(
                                accident::ACCIDENT_CLASSIFIER_VERSION.into(),
                            ),
                            accident: if stats.accident_detected {
                                Some(true)
                            } else {
                                None
                            },
                            accident_kind: stats.accident_kind.clone(),
                            accident_confidence: stats
                                .accident_confidence
                                .clone(),
                            accident_reasons: if stats
                                .accident_reasons
                                .is_empty()
                            {
                                None
                            } else {
                                Some(stats.accident_reasons.clone())
                            },
                            accident_at: stats
                                .accident_at
                                .map(|t| t.timestamp_millis()),
                            // v0.8.0: Pure-Function-Assessment in den
                            // Live-MQTT-Payload. Identische Werte wie
                            // im LandingRecord (record_landing_for_filed_
                            // flight) — Spec verlangt Field-Symmetrie.
                            navdata_source: stats
                                .runway_source
                                .map(|s| runway_source_wire(s).to_string()),
                            navdata_cycle: stats.runway_nav_cycle.clone(),
                            runway_true_course_deg: stats
                                .runway_nav_geometry
                                .as_ref()
                                .map(|g| g.true_course),
                            runway_displaced_threshold_ft: stats
                                .runway_nav_geometry
                                .as_ref()
                                .map(|g| g.displaced_threshold_ft),
                            runway_tch_expected_ft: stats
                                .runway_nav_geometry
                                .as_ref()
                                .map(|g| g.tch_ft),
                            runway_glideslope_angle_deg: stats
                                .runway_nav_geometry
                                .as_ref()
                                .map(|g| g.glideslope_angle),
                            td_distance_from_threshold_m: payload_assessed
                                .td_distance_from_threshold_m,
                            td_in_tdz: payload_assessed.tdz.map(|t| t.in_tdz),
                            td_third: payload_assessed.tdz.map(|t| t.third),
                            td_tdz_length_m: payload_assessed
                                .tdz
                                .map(|t| t.tdz_length_m),
                            aim_delta_m: payload_assessed
                                .aim
                                .as_ref()
                                .map(|a| a.delta_m),
                            aim_class: payload_assessed.aim.as_ref().map(|a| {
                                aim_class_wire(a.class).to_string()
                            }),
                            aim_point_m: payload_assessed
                                .aim
                                .as_ref()
                                .map(|a| a.aim_point_m),
                            tch_actual_ft: payload_assessed
                                .tch
                                .as_ref()
                                .map(|t| t.actual_ft),
                            tch_delta_ft: payload_assessed
                                .tch
                                .as_ref()
                                .map(|t| t.delta_ft),
                            tch_class: payload_assessed.tch.as_ref().map(|t| {
                                tch_class_wire(t.class).to_string()
                            }),
                            pre_displaced_threshold: payload_assessed
                                .dds
                                .map(|d| d.in_pre_threshold_zone),
                            // v0.10.0 (#runway-utilization-score): Marker
                            // dass das nachgelagert berechnete sub_scores-
                            // Array via sub_rollout_v2 (LDA-basiert)
                            // entstanden ist.
                            // v0.16.21: bump 3→4 — MSFS touchdown V/S
                            // SimVar-lag corrected (g-force-gated de-lag).
                            score_algorithm_version: Some(4),
                        }
                    })
                };
                if let Some(payload) = payload_opt {
                    // v0.5.34: gleicher Forensik-Payload landet ins JSONL.
                    // Damit kann ein Recovery-Tool die Touchdown-DB-Row
                    // 1:1 rekonstruieren falls die Server-DB Daten verliert.
                    record_event(
                        &app,
                        &flight.pirep_id,
                        &FlightLogEvent::TouchdownComplete {
                            timestamp: Utc::now(),
                            payload: serde_json::to_value(&payload)
                                .unwrap_or(serde_json::Value::Null),
                        },
                    );
                    let app_state = app.state::<AppState>();
                    let mqtt = app_state.mqtt.lock().await;
                    if let Some(handle) = mqtt.as_ref() {
                        handle.touchdown(payload);
                    }
                }
            }
            // Diff cockpit knobs against last-seen values and log changes
            // to the activity feed. One entry per change, not per tick.
            detect_telemetry_changes(&app, &flight, &snap);
            let position = snapshot_to_position(&snap);

            // Collect any text-log entries we want to mirror into phpVMS's
            // `/acars/logs` for the PIREP detail page. Phase changes get a
            // generic "Phase: <name>" line; landings get the touchdown
            // summary. Posted in a single batch at the end of the tick to
            // minimise HTTP round-trips.
            let mut acars_log_entries: Vec<api_client::LogEntry> = Vec::new();
            // v0.19.1: trigger is "the DISPLAYED (v2-preferred) phase
            // changed", not "v1 transitioned" — computed every tick
            // (unconditionally), independent of `phase_change`. Previously
            // both the log line and the retained MQTT phase topic below
            // only fired on a v1 transition; if v1 gets stuck on an
            // en-route phase (field report GSG22 EDLN→EDDL — legacy FSM
            // never left Climb) while v2 correctly progresses on its own
            // kinematic evidence, neither ever fired even though every
            // OTHER v2-fed path (position payload, phpVMS heartbeat, tray,
            // cockpit UI) already showed the real phase. Comparing against
            // `last_logged_effective_phase` (not `phase_change`) also
            // naturally de-dupes the common case where v1 and v2 change
            // together in the same tick — only one line, not two.
            //
            // Uses `effective_phase(&stats)` — the same PERSISTED
            // `stats.shadow_phase` every other display surface
            // (`flight_info`, tray) reads — NOT `effective_display_phase`
            // with this tick's `tick_shadow_phase`. `tick_shadow_phase` is
            // `None` on a paused/slew tick (the shadow engine skips
            // stepping then), and `effective_display_phase` falls back to
            // the raw v1 phase in that case — caught in code review: on
            // sim-pause this would have republished/relogged a stale v1
            // value (e.g. a still-stuck `Climb`) even though every other
            // surface kept correctly showing the last real v2 phase
            // (`stats.shadow_phase` is simply left untouched on a paused
            // tick, not cleared) — exactly the "Live-Karte flackert kurz
            // auf v1" failure the old, now-removed comment warned about,
            // just reachable via ordinary pausing instead of a v1-race.
            //
            // Exception: v2 deliberately never models `Holding` (documented
            // diff, see phase_v2.rs) — without a special case, a real ATC
            // hold would silently vanish from this log (previously the one
            // surface still showing it, since it read raw v1). Treat a v1
            // transition INTO Holding as an unconditional, Holding-labelled
            // log-worthy change, and record it so leaving the hold (v2
            // resuming e.g. Cruise) is itself detected as a change too —
            // a clean start/end pair, matching the old pure-v1 log.
            let v1_entered_holding = phase_change == Some(FlightPhase::Holding);
            let (effective_phase_changed, effective_phase_this_tick) = {
                let mut stats = flight.stats.lock().expect("flight stats");
                let effective = if v1_entered_holding {
                    FlightPhase::Holding
                } else {
                    effective_phase(&stats)
                };
                let changed =
                    v1_entered_holding || stats.last_logged_effective_phase != Some(effective);
                if changed {
                    stats.last_logged_effective_phase = Some(effective);
                }
                (changed, effective)
            };
            if effective_phase_changed {
                acars_log_entries.push(api_client::LogEntry {
                    log: format!("Phase: {}", phase_human_label(effective_phase_this_tick)),
                    lat: Some(snap.lat),
                    lon: Some(snap.lon),
                    created_at: Some(Utc::now().to_rfc3339()),
                });
                // v0.5.11: live-tracking phase publish. Retained
                // message — Monitor sees current phase on connect
                // even when joining mid-flight.
                {
                    let app_state = app.state::<AppState>();
                    let mqtt = app_state.mqtt.lock().await;
                    if let Some(handle) = mqtt.as_ref() {
                        handle.phase(effective_phase_this_tick, Utc::now());
                    }
                }
            }
            if let Some(msg) = landing_log_message {
                acars_log_entries.push(api_client::LogEntry {
                    log: msg,
                    lat: Some(snap.lat),
                    lon: Some(snap.lon),
                    created_at: Some(Utc::now().to_rfc3339()),
                });
            }

            // Drain any T&G / go-around log lines that the FSM
            // queued during this tick (or accumulated since the
            // last tick — the touchdown sampler runs at 30 Hz, the
            // streamer ticks at ~5 s, so multiple events can stack
            // up between drains). Order is preserved so the PIREP
            // detail page reads chronologically.
            {
                let mut stats = flight.stats.lock().expect("flight stats");
                if !stats.pending_acars_logs.is_empty() {
                    let drained: Vec<String> =
                        std::mem::take(&mut stats.pending_acars_logs);
                    drop(stats);
                    let now_ts = Utc::now().to_rfc3339();
                    for line in drained {
                        // Mirror to the in-app activity log so the
                        // pilot sees the T&G / go-around immediately
                        // in the cockpit dashboard, not just after the
                        // PIREP is filed and they look at phpVMS. The
                        // 5 s dedupe window is fine here — successive
                        // T&Gs are >1 min apart (FSM has to descend
                        // back to Approach in between).
                        log_activity_handle(
                            &app,
                            ActivityLevel::Info,
                            line.clone(),
                            None,
                        );
                        acars_log_entries.push(api_client::LogEntry {
                            log: line,
                            lat: Some(snap.lat),
                            lon: Some(snap.lon),
                            created_at: Some(now_ts.clone()),
                        });
                    }
                }
            }

            // v0.6.0 — Critical-Window + In-Tick-Drain komplett entfernt.
            //
            // Vorher (v0.5.39-v0.5.51): Streamer-Tick hatte komplexe
            // Critical-Window-Logik die phpVMS-POSTs während Approach
            // pausierte + drain-Pattern beim Tick-Wiederholen. Beides
            // war Workaround für blockierende POSTs im Tick.
            //
            // Jetzt: phpVMS-POSTs laufen IM EIGENEN Worker
            // (`spawn_phpvms_position_worker`) — vollständig entkoppelt
            // vom Streamer-Tick. Tick muss nur in die Memory-Outbox
            // pushen (= 1µs Mutex-Push, blockt nie). Worker bedient
            // Outbox phase-aware mit Per-Item-Timeout.
            //
            // Effekt:
            // - Streamer-Tick blockiert NIE auf phpVMS (strukturell garantiert)
            // - Live-Map-Track läuft kontinuierlich bis zum Gate
            // - Sample-Cadence im Approach wird NICHT mehr durch HTTP-Latenz gestreckt

            // v0.5.11: MQTT live-tracking publish (best-effort,
            // independent of phpVMS post). Publishing happens on a
            // bounded mpsc — try_send drops at full buffer so a
            // stalled broker can NEVER stall the streamer's hot
            // path. Position is the high-frequency channel; the
            // crate marks it QoS 0 retained for live-map snap-on-
            // connect.
            {
                let app_state = app.state::<AppState>();
                    let mqtt = app_state.mqtt.lock().await;
                if let Some(handle) = mqtt.as_ref() {
                    // v0.5.44: aircraft_icao mit Fallback-Cascade.
                    //
                    // flight.aircraft_icao kommt aus phpVMS GET /aircraft/<id>
                    // (siehe ActiveFlight-Init). Wenn der Pilot kein SimBrief
                    // OFP hat oder das OFP keinen aircraft_id mitbringt, ist
                    // das leer. Der Sim weiss aber das Aircraft (MSFS ATC
                    // MODEL SimVar / X-Plane DataRef) — wir extrahieren da
                    // den ICAO per Regex (z.B. "ATCCOM.AC_MODEL A321.0.text"
                    // → "A321"). Damit Live-Monitor + Heatmap auch ohne OFP
                    // den richtigen Type zeigen.
                    let resolved_icao = if !flight.aircraft_icao.trim().is_empty() {
                        flight.aircraft_icao.clone()
                    } else {
                        snap.aircraft_icao
                            .as_deref()
                            .and_then(extract_icao_code)
                            .unwrap_or_default()
                    };
                    let meta = aeroacars_mqtt::FlightMeta {
                        callsign: format_callsign(
                            &flight.airline_icao,
                            &flight.flight_number,
                        ),
                        aircraft_icao: resolved_icao,
                        dep_icao: flight.dpt_airport.clone(),
                        arr_icao: flight.arr_airport.clone(),
                        // v0.5.19: phpVMS-side registration overrides
                        // sim's ATC-ID for the live-tracking stream.
                        planned_registration: flight.planned_registration.clone(),
                        // Spec sim-disconnect-auto-resume F4: pirep_id wird
                        // in jedem Position-Tick mitgegeben damit der Server
                        // Sessions ueber pirep_id joinen kann — verhindert
                        // den AUA-323-Split bei langer Positions-Luecke.
                        pirep_id: flight.pirep_id.clone(),
                    };
                    // v0.5.14: pass current phase so it's inlined into
                    // the position payload — Monitor doesn't have to
                    // wait for a separate phase-topic delivery.
                    // #phase-v2 Cutover: Live-Map bekommt die v2-Phase.
                    let live_phase = effective_display_phase(
                        phase_change.unwrap_or(prev_phase),
                        tick_shadow_phase,
                    );
                    handle.position(&snap, &meta, live_phase);
                }
            }

            // v0.15.x: geflogenen Track im Backend bei voller Streamer-Tick-
            // Rate akkumulieren (fokus-/fenster-unabhängig → lückenlos auch bei
            // X-Plane-Vollbild). Das Frontend pollt ihn via `flight_get_track`.
            // KURZLEBIGER, SYNCHRONER Block — der std-Mutex-Guard ist nicht Send
            // und darf NICHT über ein `.await` gehalten werden (kein await im
            // Block; Guard fällt am Block-Ende). Ausdünnung 1:1 wie
            // client/src/lib/trackStore.ts (siehe record_track_point).
            {
                let mut stats = flight.stats.lock().expect("flight stats");
                record_track_point(&mut stats, snap.lon, snap.lat, snap.on_ground);
            }

            // v0.5.35: JSONL-Append jetzt PRO TICK (= 3s Cadence, oder
            // adaptive bis zu 500ms unter AGL<100ft). Vorher war der
            // Append nur INSIDE des phpVMS-OK-Branch — bei phpVMS-
            // Throttle (8-30s im Approach) verlor der Forensik-Log
            // 80% der Frames und der Touchdown-Moment fiel komplett
            // in eine Lücke. User-Report von gsg/2 GA-Flug 2026-05-08:
            // 0.1 Hz Sample-Rate, peak_vs_fpm=-33 fpm während realer TD
            // bei vermutlich -350 fpm war.
            record_event(
                &app,
                &flight.pirep_id,
                &FlightLogEvent::Position {
                    timestamp: Utc::now(),
                    snapshot: snap.clone(),
                },
            );

            // v0.6.0/v0.6.1 — Position in Memory-Outbox pushen (Worker holt
            // sie ab). Ein simpler ~1µs Mutex-Push, blockiert NIE — der
            // phpVMS-Worker (TICK=1s + phase-aware POST-Cadence 4-30s, batch
            // bis 50 Items) bedient die Outbox entkoppelt. Bei Failure:
            // Worker queued den ganzen batch zurueck in die Outbox + bei
            // Backlog>=500 (mit 30s-Hysteresis) in `position_queue.json`.
            {
                let mut outbox = flight.position_outbox.lock()
                    .expect("position_outbox lock");
                outbox.push_back(position.clone());
                // Cap auf 5000 — das sind ca. 8 Stunden Cruise-Daten.
                // Wenn die Verbindung so lange tot ist: aelteste positions
                // werden aus dem Live-Stream gedroppt (Live-Map verliert
                // Anfang des Tracks), aber die JSONL-SoT hat sie alle —
                // Forensik-Upload nach PIREP-Filing zieht sie nach.
                let mut dropped_this_tick = 0u32;
                while outbox.len() > 5000 {
                    outbox.pop_front();
                    dropped_this_tick += 1;
                }
                drop(outbox);
                if dropped_this_tick > 0 {
                    // Warn pro Tick — auf einem dauerhaft toten Netz koennte
                    // das jede Sekunde feuern, aber das ist genau das Signal
                    // das wir wollen: „Backlog ist voll, Daten gehen aus dem
                    // Live-Stream verloren". JSONL-Forensik bleibt komplett.
                    tracing::warn!(
                        pirep_id = %flight.pirep_id,
                        dropped_this_tick,
                        outbox_cap = 5000u32,
                        "outbox cap reached — oldest positions dropped from live-stream \
                         (JSONL forensics still complete; check phpVMS connectivity)"
                    );
                }
                // v0.6.1 — KEIN queued_position_count-Update hier!
                //
                // Semantik in v0.5.x: queued_position_count zeigte echten
                // BACKLOG (failed POSTs in der file-queue). Im normalen
                // Cruise = 0. Pilot interpretiert >0 als „Verbindungs-
                // Problem".
                //
                // Wenn wir hier outbox.len() schreiben würden: Streamer
                // pusht alle ~3s, Worker drained nur alle 30s im Cruise
                // -> outbox.len() ist 29 von 30 Sekunden > 0 -> Indikator
                // zeigt durchgehend „queued (offline)" obwohl alles ok.
                //
                // Stattdessen: nur der Worker setzt queued_position_count
                // im success-Pfad (= was nach Drain noch übrig ist) bzw.
                // failure-Pfad (= was nach Requeue drin steht). Im Cruise:
                // nach erfolgreichem Drain ist outbox leer -> count=0.
                // Bei Network-Down: Requeue lässt Backlog wachsen -> count
                // steigt korrekt.
            }

            // Periodically flush running stats to disk so a Tauri restart
            // (or crash) doesn't lose distance/fuel/phase data. The
            // identification fields are written every time too — cheap,
            // and keeps the file consistent if any of them changed via
            // backfill (airline_icao / planned_registration on resume).
            let should_persist = {
                let stats = flight.stats.lock().expect("flight stats");
                stats.position_count % STATS_PERSIST_EVERY_TICKS == 0
            };
            // Re-check stop *before* writing — `flight_end` may have run
            // since the top-of-loop check, taken the flight, called
            // `clear_persisted_flight`, and we'd otherwise resurrect the
            // disk file. Without this, the resume banner pops on the next
            // launch for a flight the user already filed.
            if should_persist && !flight.stop.load(Ordering::Relaxed) {
                save_active_flight(&app, &flight);
            }

            // On phase change, push the new status to phpVMS so the
            // live-map and PIREP detail page reflect the current phase.
            if let Some(new_phase) = phase_change {
                log_activity_handle(
                    &app,
                    ActivityLevel::Info,
                    format!("Phase: {:?}", new_phase),
                    Some(format!(
                        "Alt {:.0} ft, GS {:.0} kt, AGL {:.0} ft",
                        snap.altitude_msl_ft, snap.groundspeed_kt, snap.altitude_agl_ft
                    )),
                );
                // Diagnostic fuel/weight snapshot at the four phases
                // where the values get captured into PIREP fields.
                // Lets the pilot verify what the app saw — especially
                // useful with Fenix where TOTAL WEIGHT / ZFW / payload
                // sometimes report 0 and the pilot can't tell from
                // the PIREP alone whether the SimVar was missing or
                // the addon hadn't finished loading at capture time.
                log_fuel_weight_at_phase(&app, &flight, new_phase, &snap);
                record_event(
                    &app,
                    &flight.pirep_id,
                    &FlightLogEvent::PhaseChanged {
                        timestamp: Utc::now(),
                        from: prev_phase,
                        to: new_phase,
                        altitude_msl_ft: snap.altitude_msl_ft,
                        groundspeed_kt: snap.groundspeed_kt,
                        altitude_agl_ft: snap.altitude_agl_ft,
                    },
                );
                // METAR snapshot at the two phase transitions where it
                // matters most: just after takeoff for the departure
                // weather, and just before/at touchdown for the arrival
                // weather. Spawned async so a flaky aviationweather.gov
                // doesn't stall the streamer.
                maybe_spawn_metar_fetch(&app, &flight, new_phase);

                // v0.12.6: Backend-Auto-File. Latcht der FSM auf
                // `Arrived` und hat der Pilot Auto-File aktiviert, filet
                // das Backend den PIREP selbst — fenster-unabhängig.
                // Vorher lief Auto-File nur als Frontend-`useEffect`, der
                // bei Hintergrund-Fenster / nicht-aktivem Cockpit-Tab
                // nicht feuerte (Pilot-Befund: PIREP ging erst raus,
                // nachdem der Pilot AeroACARS in den Vordergrund holte).
                // Divert wird ausgelassen — den Ausweich-Airport muss der
                // Pilot über das Divert-Banner bestätigen (LE2).
                if new_phase == FlightPhase::Arrived
                    && app
                        .state::<AppState>()
                        .auto_file_enabled
                        .load(Ordering::Relaxed)
                {
                    let is_divert = flight
                        .stats
                        .lock()
                        .expect("flight stats")
                        .divert_hint
                        .is_some();
                    if is_divert {
                        tracing::info!(
                            pirep_id = %flight.pirep_id,
                            "backend auto-file skipped — divert detected, \
                             pilot confirms via banner"
                        );
                    } else {
                        tracing::info!(
                            pirep_id = %flight.pirep_id,
                            "Arrived — backend auto-file"
                        );
                        let app_af = app.clone();
                        let flight_af = Arc::clone(&flight);
                        tauri::async_runtime::spawn(async move {
                            let st = app_af.state::<AppState>();
                            match flight_end(app_af.clone(), st, None, None, None)
                                .await
                            {
                                Ok(()) => {
                                    // LE7-Erfolgs-Banner: das Frontend
                                    // hört auf dieses Event und zeigt das
                                    // grüne ✅ — sonst verschwände der Flug
                                    // beim Backend-Auto-File kommentarlos.
                                    let payload = serde_json::json!({
                                        "callsign": format_callsign(
                                            &flight_af.airline_icao,
                                            &flight_af.flight_number,
                                        ),
                                        "dpt": flight_af.dpt_airport,
                                        "arr": flight_af.arr_airport,
                                    });
                                    let _ = tauri::Emitter::emit(
                                        &app_af,
                                        "pirep_auto_filed",
                                        payload.clone(),
                                    );
                                    // v0.16.0 (#LAN-Remote): fan out to LAN WS.
                                    app_af.state::<AppState>().remote_events.send(
                                        remote::RemoteEvent::new("pirep_auto_filed", payload),
                                    );
                                }
                                Err(e) => {
                                    log_activity_handle(
                                        &app_af,
                                        ActivityLevel::Warn,
                                        "Auto-File fehlgeschlagen — bitte \
                                         manuell „Flug beenden\" klicken"
                                            .to_string(),
                                        Some(format!("{}: {}", e.code, e.message)),
                                    );
                                }
                            }
                        });
                    }
                }
            }

            // Unified heartbeat-and-phase-update: POST `/pireps/{id}/update`
            // either when the phase just changed (so the live map sees the
            // new status immediately) OR after every `HEARTBEAT_INTERVAL`
            // (so phpVMS's RemoveExpiredLiveFlights cron never fires
            // mid-flight). Both purposes use the same payload — sending
            // monotonic flight_time / distance also guarantees the row is
            // dirty so Eloquent always writes UPDATE and bumps updated_at.
            // #phase-v2 Cutover: phpVMS-Live-Status = v2-Phase.
            let phase_for_heartbeat = effective_display_phase(
                phase_change.unwrap_or(current_phase),
                tick_shadow_phase,
            );
            let due_for_heartbeat = last_heartbeat.elapsed() >= HEARTBEAT_INTERVAL;
            if phase_change.is_some() || due_for_heartbeat {
                let body = {
                    let stats = flight.stats.lock().expect("flight stats");
                    build_heartbeat_body(&snap, &stats, phase_for_heartbeat)
                };
                match client.update_pirep(&flight.pirep_id, &body).await {
                    Ok(()) => {
                        last_heartbeat = std::time::Instant::now();
                        {
                            let mut stats = flight.stats.lock().expect("flight stats");
                            stats.last_heartbeat_at = Some(Utc::now());
                        }
                        tracing::debug!(
                            pirep_id = %flight.pirep_id,
                            phase = ?phase_for_heartbeat,
                            phase_changed = phase_change.is_some(),
                            flight_time_min = body.flight_time.unwrap_or(0),
                            distance_nm = body.distance.unwrap_or(0.0),
                            "PIREP heartbeat sent"
                        );
                    }
                    Err(ApiError::NotFound) => {
                        handle_remote_cancellation(&app, &flight, "POST update");
                        break;
                    }
                    Err(e) => {
                        tracing::warn!(
                            pirep_id = %flight.pirep_id,
                            phase = ?phase_for_heartbeat,
                            error = %e,
                            "PIREP heartbeat failed"
                        );
                    }
                }
            }

            // Mirror collected text events into phpVMS's `/acars/logs` for
            // the PIREP detail page. Best-effort: a transient network
            // error here doesn't matter — the activity log + recorder
            // already have the durable copy. 404 still means the PIREP
            // is gone, so handle that the same way as the heartbeat.
            if !acars_log_entries.is_empty() {
                match client
                    .post_acars_logs(&flight.pirep_id, &acars_log_entries)
                    .await
                {
                    Ok(()) => {
                        tracing::debug!(
                            pirep_id = %flight.pirep_id,
                            count = acars_log_entries.len(),
                            "ACARS log lines pushed"
                        );
                    }
                    Err(ApiError::NotFound) => {
                        handle_remote_cancellation(&app, &flight, "POST acars/logs");
                        break;
                    }
                    Err(e) => {
                        tracing::warn!(
                            pirep_id = %flight.pirep_id,
                            count = acars_log_entries.len(),
                            error = %e,
                            "ACARS log push failed"
                        );
                    }
                }
            }
        }
        tracing::info!(pirep_id = %flight.pirep_id, "position streamer stopped");
    });
}

/// Map SimBrief's text fix `<type>` ("apt", "wpt", "vor", "ndb", "ltlg")
/// to phpVMS's numeric `nav_type` for `POST /pireps/{id}/route`. phpVMS
/// is permissive (`nav_type` is `sometimes|int`); when we can't classify
/// a fix we omit the field and let the server render it generically.
fn simbrief_kind_to_nav_type(kind: &str) -> Option<i32> {
    match kind.to_ascii_lowercase().as_str() {
        "wpt" => Some(1),
        "ndb" => Some(2),
        "vor" => Some(3),
        "apt" => Some(4),
        _ => None,
    }
}

/// v0.16.23: Baut den `Vec<RouteWaypoint>` aus SimBrief-Navlog-Fixes
/// — die Form die `POST /api/pireps/{id}/route` erwartet (0-based order,
/// `nav_type` aus `simbrief_kind_to_nav_type`). Aus `flight_start`
/// extrahiert (cf. der Inline-Bau dort), damit `flight_refresh_route_only`
/// BIT-IDENTISCH dieselbe Route postet wie der Flight-Start. Reine
/// Funktion ohne Score-Beruehrung — bewusst NICHT mit der
/// FlightStats-Mutation gemischt.
fn build_route_waypoints(fixes: &[api_client::RouteFix]) -> Vec<api_client::RouteWaypoint> {
    fixes
        .iter()
        .enumerate()
        .map(|(i, fix)| api_client::RouteWaypoint {
            name: fix.ident.clone(),
            order: i as i32,
            nav_type: simbrief_kind_to_nav_type(&fix.kind),
            lat: fix.lat,
            lon: fix.lon,
        })
        .collect()
}

/// Human-readable single-word label for a `FlightPhase`. Used in the
/// `/acars/logs` text we ship to phpVMS. Pilots already see these in
/// the German activity feed; matching them here keeps the PIREP detail
/// consistent with what was on screen during the flight.
fn phase_human_label(phase: FlightPhase) -> &'static str {
    match phase {
        FlightPhase::Preflight => "Preflight",
        FlightPhase::Boarding => "Boarding",
        FlightPhase::Pushback => "Pushback",
        FlightPhase::TaxiOut => "Taxi Out",
        FlightPhase::TakeoffRoll => "Takeoff Roll",
        FlightPhase::Takeoff => "Takeoff",
        FlightPhase::Climb => "Initial Climb",
        FlightPhase::Cruise => "Cruise",
        FlightPhase::Holding => "Holding",
        FlightPhase::Descent => "Descent",
        FlightPhase::Approach => "Approach",
        FlightPhase::Final => "Final",
        FlightPhase::Landing => "Landing",
        FlightPhase::TaxiIn => "Taxi In",
        FlightPhase::BlocksOn => "On Blocks",
        FlightPhase::Arrived => "Arrived",
        FlightPhase::PirepSubmitted => "PIREP Submitted",
    }
}

/// Read a snapshot from whichever adapter is currently active per
/// the persisted `SimKind`. We try the active adapter first; if it
/// hasn't seen any data yet (e.g. just after startup), we still
/// return None — caller is expected to handle "no snapshot yet".
fn current_snapshot(app: &AppHandle) -> Option<SimSnapshot> {
    let state = app.state::<AppState>();
    let kind = read_sim_config(app).kind;
    if kind.is_xplane() {
        let adapter = state.xplane.lock().expect("xplane lock");
        return adapter.snapshot();
    }
    #[cfg(target_os = "windows")]
    {
        if kind.is_msfs() {
            let adapter = state.msfs.lock().expect("msfs lock");
            return adapter.snapshot();
        }
    }
    None
}

/// Drain any pending touchdown event from the AeroACARS X-Plane Plugin
/// (v0.5.0+ premium mode). Returns `Some` exactly once per landing
/// when the plugin is installed and detected a touchdown edge in its
/// flight-loop callback. `None` if the plugin isn't running, or if
/// the active sim isn't X-Plane, or if no touchdown is pending. The
/// touchdown sampler calls this each tick and prefers premium values
/// over its own RREF-derived edge detection when available.
fn current_premium_touchdown(app: &AppHandle) -> Option<sim_xplane::PremiumTouchdown> {
    let state = app.state::<AppState>();
    let kind = read_sim_config(app).kind;
    if !kind.is_xplane() {
        return None;
    }
    let adapter = state.xplane.lock().expect("xplane lock");
    adapter.take_premium_touchdown()
}

// v0.7.13: `current_premium_status` entfernt — war seit der Refactor-Welle
// in v0.6.x ohne Caller. UI greift direkt via `app.state::<AppState>()` auf
// den X-Plane-Premium-Status zu. Audit Q4-2026-05.

/// Update running stats AND step the flight-phase FSM. Returns the new phase
/// when a transition fires, otherwise `None`.
/// v0.5.40: Anti-Flicker für `engines_running`. Aerosoft A340-600 Pro
/// (und etliche andere Add-ons) zappeln den GENERAL ENG COMBUSTION SimVar
/// pro Tick zwischen 0 und N. Die Phase-FSM sieht dann zufällig false und
/// blockiert Pushback→TaxiOut. Hier: gilt als "effektiv laufend" wenn
/// snap.engines_running > 0 ODER der letzte >0-Reading <2 s her ist.
/// v0.5.44: Extrahiert einen ICAO-Aircraft-Code aus dem rohen Sim-String.
///
/// MSFS liefert oft kuriose Werte fuer ATC MODEL — siehe importJsonl.ts
/// cleanAircraftIcao mit dem gleichen Pattern:
///   "ATCCOM.AC_MODEL A321.0.text" → "A321"
///   "BoeingB738" → "B738"
///   "FNX320"  → "A320" (matched in fallback)
///   "A320"   → "A320"
///
/// Regex: \b([A-Z]\d{2,3}|[A-Z]{2,4}\d{0,3})\b — Boeing/Airbus-typische
/// 4-Zeichen-Codes (B738, A320, C172, DA42, ...). Faellt bei keinem Match
/// zurueck auf die ersten 8 Zeichen, gefiltert auf alphanumerisch.
fn extract_icao_code(raw: &str) -> Option<String> {
    let raw = raw.trim();
    if raw.is_empty() { return None; }
    // Regex on-demand kompilieren — wird selten genutzt, nicht kritisch
    // genug fuer eine static.
    use regex::Regex;
    let re = Regex::new(r"\b([A-Z]\d{2,3}|[A-Z]{2,4}\d{0,3})\b").ok()?;
    if let Some(caps) = re.captures(raw) {
        if let Some(m) = caps.get(1) {
            return Some(m.as_str().to_string());
        }
    }
    // Fallback: erste 8 alphanumerische Chars uppercase
    let cleaned: String = raw.chars()
        .filter(|c| c.is_ascii_alphanumeric())
        .take(8)
        .collect::<String>()
        .to_uppercase();
    if cleaned.is_empty() { None } else { Some(cleaned) }
}

/// v0.7.19 GAF-707 Accident-Detection (Heuristik-Pfad).
///
/// Spec §Klassifikator-Trigger-Punkte: wird EINMAL pro Touchdown am
/// TD-Edge aufgerufen (= direkt nach `stats.landing_analysis = Some(...)`
/// im Sampler-Loop). NICHT im 50-Hz-Loop.
///
/// Behaviour:
/// - Sim-Event hat schon Confirmed(SimCrash) gelatcht → Reasons mergen,
///   kind bleibt SimCrash (authoritativ).
/// - Suspected ueber bestehenden None → Suspected latchen.
/// - Confirmed ueber bestehenden Suspected → upgraden auf Confirmed.
/// - Confirmed-vs-Confirmed bei Multi-TD (Touch-and-Go): Reasons werden
///   nur ersetzt wenn die neue |vs_at_edge_fpm| HOEHER ist (Worst-Case-
///   Aggregation per Spec §Leitentscheidung 7).
fn apply_accident_heuristic(stats: &mut FlightStats, analysis: &serde_json::Value) {
    let input = accident::AccidentHeuristicInput {
        vs_at_edge_fpm: ana_f32(&Some(analysis.clone()), "vs_at_edge_fpm"),
        // v0.12.3 (LE10): Accident-/Crash-Erkennung nutzt BEWUSST den
        // rohen `peak_g_load`, NICHT den EMA-geglätteten `scored_g`.
        // Crash-Detektion ist Extremwert-Detektion — der schärfste Wert
        // ist der relevante; die EMA-Glättung (faire Pilot-Bewertung)
        // würde einen Grenzfall-Crash unter die Schwelle drücken. Nicht
        // versehentlich auf `scored_g` umstellen.
        peak_g_load: stats.landing_peak_g_force,
        sideslip_deg: stats.touchdown_sideslip_deg,
        landing_wing_strike_severity_pct: stats.landing_wing_strike_severity_pct,
        approach_stall_warning_count: Some(stats.approach_stall_warning_count),
        runway_match_found: Some(stats.runway_match.is_some()),
        rollout_distance_m: stats.rollout_distance_m.map(|m| m as f32),
    };
    let new_vs_abs = input.vs_at_edge_fpm.map(|v| v.abs()).unwrap_or(0.0);
    let decision = accident::classify_accident_heuristic(&input);

    match decision {
        accident::AccidentDecision::None => {}
        accident::AccidentDecision::Suspected { kind, reasons } => {
            if !stats.accident_detected
                && stats.accident_confidence.is_none()
            {
                // Erste Suspected-Klassifikation. Nicht als accident_detected
                // (das bleibt fuer Confirmed reserviert), aber Felder zur
                // UI/Webapp-Banner-Anzeige setzen.
                stats.accident_kind = Some(kind.as_wire_str().into());
                stats.accident_confidence = Some("medium".into());
                stats.accident_at = stats.landing_at;
                stats.accident_reasons.extend(reasons);
                tracing::warn!(
                    kind = kind.as_wire_str(),
                    reasons = ?stats.accident_reasons,
                    "v0.7.19: heuristic suspected accident"
                );
            }
            // Wenn schon Confirmed → ignorieren (Suspected < Confirmed).
        }
        accident::AccidentDecision::Confirmed { kind, reasons } => {
            let was_sim_crash = stats.accident_kind.as_deref()
                == Some(accident::AccidentKind::SimCrash.as_wire_str());

            if !stats.accident_detected {
                // First Confirmed (entweder vom None oder vom Suspected upgrade).
                stats.accident_detected = true;
                stats.accident_kind = Some(kind.as_wire_str().into());
                stats.accident_confidence = Some("high".into());
                stats.accident_at = stats.accident_at.or(stats.landing_at);
                stats.accident_reasons.extend(reasons);
                tracing::warn!(
                    kind = kind.as_wire_str(),
                    reasons = ?stats.accident_reasons,
                    "v0.7.19: heuristic confirmed accident"
                );
            } else if was_sim_crash {
                // Sim-Event hat schon Confirmed(SimCrash) gelatcht. Kind
                // bleibt; Heuristik-Reasons mergen.
                stats.accident_reasons.extend(reasons);
                tracing::info!(
                    heuristic_kind = kind.as_wire_str(),
                    "v0.7.19: heuristic reasons merged into sim-crash latch"
                );
            } else {
                // Multi-TD Worst-Case-Aggregation: nur ersetzen wenn die
                // neue Touchdown-|vs| hoeher ist (Spec §Leitentscheidung 7
                // Tie-Breaker).
                let prev_vs_abs = stats
                    .accident_reasons
                    .iter()
                    .find_map(|r| r.strip_prefix("vs_at_edge_fpm="))
                    .and_then(|v| v.parse::<f32>().ok())
                    .map(|v| v.abs())
                    .unwrap_or(0.0);
                if new_vs_abs > prev_vs_abs {
                    stats.accident_kind = Some(kind.as_wire_str().into());
                    stats.accident_reasons = reasons;
                    stats.accident_at = stats.landing_at;
                    tracing::warn!(
                        kind = kind.as_wire_str(),
                        prev_vs_abs,
                        new_vs_abs,
                        "v0.7.19: multi-touchdown worst-case replaced earlier accident"
                    );
                }
            }
        }
    }
}

fn engines_effectively_running(stats: &FlightStats, snap: &SimSnapshot, now: DateTime<Utc>) -> bool {
    if snap.engines_running > 0 { return true; }
    stats
        .last_engines_running_above_zero_at
        .map(|t| (now - t).num_milliseconds() < 2000)
        .unwrap_or(false)
}

/// v0.16.9: der Takeoff-Latch der drei →Takeoff-Übergänge, an EINER Stelle.
/// Semantik exakt wie die bisherigen Inline-Blöcke (Overwrite, Sampler-
/// bevorzugte Attitude, TOTAL-WEIGHT-Fallback auf ZFW+Fuel) — nur extrahiert,
/// damit Latch-Logik nie wieder pro Call-Site driftet.
/// Gross weight at this snapshot: prefer TOTAL WEIGHT (fuel + payload +
/// empty); fall back to ZFW + fuel only when the SimVar isn't wired.
/// Shared by both takeoff-latch variants so the fallback can never drift.
fn takeoff_weight_from_snapshot(snap: &SimSnapshot) -> Option<f64> {
    if let Some(tw) = snap.total_weight_kg {
        return Some(tw as f64);
    }
    let zfw = snap.zfw_kg.unwrap_or(0.0);
    let weight = zfw as f64 + snap.fuel_total_kg as f64;
    (weight > 0.0).then_some(weight)
}

fn latch_takeoff_stats(stats: &mut FlightStats, snap: &SimSnapshot, now: DateTime<Utc>) {
    stats.takeoff_at = Some(now);
    stats.takeoff_fuel_kg = Some(snap.fuel_total_kg);
    // v0.5.16: capture pitch + bank for tail-strike / wing-strike
    // maintenance detection (DisposableSpecial dmaintenance reads these
    // as numeric custom fields).
    // v0.5.24: prefer the 50Hz-sampler value (Wheels-Up-frame-genau)
    // ueber den Streamer-Tick-Snapshot. Bei tail-strike-empfindlichen
    // Aircraft wie A321 spart das 2-3° Pitch-Drift gegen den
    // 3-30s-spaeter-Tick.
    stats.takeoff_pitch_deg = stats.sampler_takeoff_pitch_deg.or(Some(snap.pitch_deg));
    stats.takeoff_bank_deg = stats.sampler_takeoff_bank_deg.or(Some(snap.bank_deg));
    if let Some(weight) = takeoff_weight_from_snapshot(snap) {
        stats.takeoff_weight_kg = Some(weight);
    }
}

/// v0.16.9: Takeoff-Latch-Sicherheitsnetz für Pfade, die airborne werden,
/// OHNE durch `FlightPhase::Takeoff` zu gehen — heute genau das
/// v0.13.17-Airborne-Rescue (Live-Flug BCS8: totes vbz-Signal → Pushback nie
/// verlassen → Rescue forcte Pushback→Climb → `takeoff_fuel_kg` blieb None →
/// OFP-Fuel-Sub-Score „no_actual_burn"-skipped).
///
/// Unterschiede zum echten Takeoff-Latch — bewusst:
/// * `get_or_insert`-Semantik: überschreibt NIE bereits gelatchte Werte.
/// * `takeoff_at`: bevorzugt den frame-genauen 50Hz-Sampler-Edge
///   (`sampler_takeoff_at`, falls der Sampler den Wheels-up sah), sonst jetzt.
/// * Pitch/Bank NUR vom Sampler (echter Wheels-up-Frame): der Rescue-Snapshot
///   steckt schon tief im Climb — dessen ~15° Pitch würde der Tail-Strike-
///   Maintenance-Erkennung einen falschen „Takeoff-Pitch" füttern. Lieber
///   leer als falsch.
/// * Fuel/Weight vom Rescue-Snapshot (≤ 500 ft AGL): Burn seit Rotation ist
///   < 1 % des Trip-Burns — für die OFP-Treue-Bewertung präzise genug, und
///   unendlich besser als „nicht bewertbar".
fn latch_takeoff_stats_if_missing(
    stats: &mut FlightStats,
    snap: &SimSnapshot,
    now: DateTime<Utc>,
) {
    if stats.takeoff_at.is_none() {
        stats.takeoff_at = Some(stats.sampler_takeoff_at.unwrap_or(now));
    }
    if stats.takeoff_fuel_kg.is_none() {
        stats.takeoff_fuel_kg = Some(snap.fuel_total_kg);
    }
    if stats.takeoff_pitch_deg.is_none() {
        stats.takeoff_pitch_deg = stats.sampler_takeoff_pitch_deg;
    }
    if stats.takeoff_bank_deg.is_none() {
        stats.takeoff_bank_deg = stats.sampler_takeoff_bank_deg;
    }
    if stats.takeoff_weight_kg.is_none() {
        stats.takeoff_weight_kg = takeoff_weight_from_snapshot(snap);
    }
}

/// v0.13.17 Airborne-Rescue-Bedingung (rein, testbar). True, wenn die FSM in
/// einer Boden-/Pre-Takeoff-Phase steht, das Flugzeug aber klar in der Luft
/// ist (nicht am Boden + AGL > 500 ft) und der Tick kein Reload-/Slew-Glitch
/// ist. Dann zwingt `step_flight` die Phase auf Climb — damit ein Addon mit
/// kaputten Engine-SimVars (engines_running bleibt 0 → Pushback→Takeoff feuert
/// nie) nicht den ganzen Flug in einer Boden-Phase festhaengt.
fn phase_stuck_on_ground_while_airborne(
    phase: FlightPhase,
    on_ground: bool,
    altitude_agl_ft: f64,
    reload_gap_suspect: bool,
) -> bool {
    let ground_phase = matches!(
        phase,
        FlightPhase::Preflight
            | FlightPhase::Boarding
            | FlightPhase::Pushback
            | FlightPhase::TaxiOut
            | FlightPhase::TakeoffRoll
    );
    ground_phase && !on_ground && altitude_agl_ft > 500.0 && !reload_gap_suspect
}

/// v0.15.20: True für eine FLUG-Phase (in der Luft) — Gegenstück zu Boden-/
/// Departure-Phasen (Boarding/Pushback/TaxiOut/TakeoffRoll/Takeoff/TaxiIn/
/// BlocksOn/Arrived/PirepSubmitted).
///
/// Maßgeblich dafür, ob ein realer Luft→Boden-Edge als Touchdown akzeptiert
/// wird — an ALLEN drei Erfassungsstellen (Sampler-RREF-Edge, Sampler-Premium-
/// Plugin, FSM-Capture). Vorher war das auf `Approach|Final|Landing` beschränkt,
/// wodurch ein Touchdown bei fehl-phasierter FSM (Go-Around → in „Climb" hängen,
/// OWx9) überall verworfen wurde.
///
/// Der Phantom-Touchdown-Schutz (Gear-Force-Wackler beim Taxi auf unebenem
/// Boden) bleibt darüber **vollständig** erhalten: in einer Flug-Phase ist
/// `gear_normal_force_n` durchgehend entlastet → es kann gar kein Gear-Bump-Edge
/// (`prev_in_air=true → on_ground`) entstehen; die Wackler passieren nur am
/// Boden (Taxi), und Boden-Phasen sind hier ausgeschlossen.
fn is_flight_phase(phase: FlightPhase) -> bool {
    matches!(
        phase,
        FlightPhase::Climb
            | FlightPhase::Cruise
            | FlightPhase::Descent
            | FlightPhase::Holding
            | FlightPhase::Approach
            | FlightPhase::Final
            | FlightPhase::Landing
    )
}

/// Whether the 50 Hz touchdown sampler may accept an air→ground edge in this
/// phase. Flight phases (Climb…Landing) always qualify. `Takeoff` ALSO
/// qualifies once the aircraft has genuinely flown (`was_airborne`, armed at
/// 50 ft AGL): this is the durable fix for short / low VFR bush hops that land
/// before climbing through the 500 ft Takeoff→Climb gate and so are still in
/// `Takeoff` phase at touchdown (real case GSG309 OR72→OR35, peaked 357 ft,
/// phase arc Takeoff→Arrived → the edge was previously blocked → no touchdown).
///
/// Phantom safety: ground/taxi phases (Boarding/TaxiOut/TaxiIn/Arrived) stay
/// excluded, so a taxi gear-bump is never a candidate. Within `Takeoff` the
/// aircraft cannot be on the ground until it lands, so the FIRST air→ground
/// edge is the real touchdown; the once-per-landing guard
/// (`sampler_touchdown_at.is_none()`) then blocks any rollout bump after it.
/// A spurious mid-air on_ground glitch is still rejected by `validate_candidate`
/// (low-AGL-persistence + sustained-ground fail at altitude / on a single tick).
fn is_touchdown_capturable_phase(phase: FlightPhase, was_airborne: bool) -> bool {
    is_flight_phase(phase) || (matches!(phase, FlightPhase::Takeoff) && was_airborne)
}

/// Takeoff → Climb AGL gate. A rotorcraft routinely flies an entire leg below
/// the 500 ft fixed-wing gate, which would strand it in `Takeoff` — a phase
/// excluded from [`is_flight_phase`], so the touchdown sampler never captures
/// its landing. A low gate moves it into Climb (a capturable flight phase)
/// once clearly airborne and translating. Fixed-wing keeps 500 ft.
fn takeoff_climb_gate_ft(category: aircraft_category::AircraftCategory) -> f64 {
    if category.is_rotorcraft() {
        60.0
    } else {
        500.0
    }
}

/// Sampler touchdown-edge gear-force threshold (N). Below this the gear is
/// considered unloaded (in the air); X-Plane `fnrml_gear` spikes far above it
/// on a wheel touchdown.
const SAMPLER_GEAR_TOUCHDOWN_THRESHOLD_N: f32 = 1.0;

/// Seaplane / amphibian water-contact AGL (ft): at or below this height above
/// the water surface the floats / hull are settling onto the water.
const SAMPLER_WATER_CONTACT_AGL_FT: f64 = 3.0;

/// Category-aware "in air" signal for the 50 Hz touchdown sampler.
///
/// For a seaplane / amphibian on water `on_ground` stays false and there is no
/// gear-force, so the wheeled touchdown edge never fires. For those categories
/// — and only while off the runway (`on_ground == false`) — this uses height
/// above the water surface instead: the aircraft counts as "in air" while above
/// [`SAMPLER_WATER_CONTACT_AGL_FT`], so the edge fires when the floats settle
/// onto the water. Everything else (fixed-wing, a helicopter on skids/wheels,
/// any aircraft whose `on_ground` / gear-force is meaningful) uses the unchanged
/// wheeled signal.
///
/// This only produces the candidate EDGE; the touchdown_v2 validation 1.1 s
/// later still gates it (the seaplane path anchors on sustained low-AGL, so a
/// wave bounce / momentary dip is dropped as a FalseEdge). The water branch is
/// gated on a water-capable category, so it can never fire for a fixed-wing or
/// helicopter — those stay byte-identical to the previous behaviour.
fn sampler_in_air_now(
    category: aircraft_category::AircraftCategory,
    on_ground: bool,
    altitude_agl_ft: f64,
    gear_normal_force_n: Option<f32>,
) -> bool {
    if category.water_capable() && !on_ground {
        altitude_agl_ft > SAMPLER_WATER_CONTACT_AGL_FT
    } else {
        match gear_normal_force_n {
            Some(force) => force < SAMPLER_GEAR_TOUCHDOWN_THRESHOLD_N,
            None => !on_ground,
        }
    }
}

/// v0.15.24: First on-ground sample in the 50 Hz snapshot buffer — the
/// touchdown moment as the sampler recorded it. Shared by the FSM Landing
/// arm and the sampler-validation stamping path so both read the SAME
/// TD-instant values. `None` when the buffer is empty (resumed flight) or
/// holds no on-ground sample yet — callers fall back to the live snap.
fn touchdown_buffer_sample(stats: &FlightStats) -> Option<TelemetrySample> {
    stats.snapshot_buffer.iter().find(|s| s.on_ground).cloned()
}

/// v0.15.24: Touchdown-METADATA stamp — extracted verbatim from the FSM
/// Landing arm in `step_flight` so the validated sampler touchdown can stamp
/// the same fields when the FSM never reaches Landing. Short/low VFR bush
/// hops (GSG312, 97OG) land via the 50 Hz sampler while the FSM is still in
/// Takeoff/Climb: the touchdown was captured + scored + published
/// (v0.15.23), but landing IAS/pitch/bank/heading/speed/groundspeed/fuel/
/// coords/profile/sideslip/wind were only ever stamped inside the FSM
/// Landing arm — so the PIREP report silently lost all of them
/// (`build_pirep_payload` omits `None` stats).
///
/// Behaviour-preserving for the FSM path: identical fallback chains, in the
/// identical order — buffered TD-moment sample → MSFS-latched touchdown
/// SimVars → live snap. The `snap` fallback is the worst case (post-rollout
/// values), kept only for resumed flights where the buffer is empty.
///
/// `actual_td_at` anchors the profile timestamps; pass the same TD instant
/// the caller uses for `landing_at` (FSM arm) / `sampler_touchdown_at`
/// (sampler-validation path) so `t_ms = 0` is the contact frame.
fn stamp_touchdown_metadata(
    stats: &mut FlightStats,
    snap: &SimSnapshot,
    actual_td_at: DateTime<Utc>,
    td_buf_sample: Option<&TelemetrySample>,
) {
    // IAS / pitch / heading: prefer the buffered sample
    // at the actual TD moment (see `td_buf_sample`).
    // Fall back chain — buffered sample → MSFS-latched
    // touchdown SimVars → live snap. The `snap` fallback
    // is the worst case (post-rollout values), kept only
    // for resumed flights where the buffer is empty.
    stats.landing_pitch_deg = Some(
        snap.touchdown_pitch_deg
            .or_else(|| td_buf_sample.map(|s| s.pitch_deg))
            .unwrap_or(snap.pitch_deg),
    );
    // v0.5.16: bank at touchdown for wing-strike maintenance
    // detection. MSFS latches bank too via the touchdown
    // SimVar set; X-Plane via the buffered sample. Live
    // snap as last-resort fallback (resumed flights).
    stats.landing_bank_deg = Some(
        snap.touchdown_bank_deg
            .or_else(|| td_buf_sample.map(|s| s.bank_deg))
            .unwrap_or(snap.bank_deg),
    );
    // Heading capture: MSFS gives us a magnetic-heading
    // touchdown latch; the buffer carries true-heading
    // only. When we fall back to the buffer we approximate
    // magnetic from true via the live magvar delta
    // (true−magnetic at the streamer tick) — small error
    // since magvar doesn't change in 5 s of rollout.
    stats.landing_heading_deg = Some(
        snap.touchdown_heading_mag_deg
            .or_else(|| {
                td_buf_sample.map(|s| {
                    let magvar =
                        snap.heading_deg_true - snap.heading_deg_magnetic;
                    s.heading_true_deg - magvar
                })
            })
            .unwrap_or(snap.heading_deg_magnetic),
    );
    stats.landing_speed_kt = Some(
        td_buf_sample
            .map(|s| s.indicated_airspeed_kt)
            .unwrap_or(snap.indicated_airspeed_kt),
    );
    // v0.5.17: groundspeed at touchdown (parallel to IAS).
    // Buffered sample preferred — live snap is the post-
    // rollout fallback for resumed flights only.
    stats.landing_groundspeed_kt = Some(
        td_buf_sample
            .map(|s| s.groundspeed_kt)
            .unwrap_or(snap.groundspeed_kt),
    );
    stats.landing_fuel_kg = Some(snap.fuel_total_kg);

    // ---- Tier 2/3 BeatMyLanding-aligned extras ----

    // Position + true heading at the touchdown edge — used
    // for runway lookup and disambiguation between parallel
    // runway pairs (08L/08R) via heading match.
    //
    // Pulls from the buffered TD-moment sample (same
    // reasoning as the IAS / pitch / heading capture
    // above): `snap` is up to 5 s late on the streamer
    // tick, time enough for a typical airliner to roll
    // 50–100 m down the runway and drift left/right via
    // nose-wheel correction — the centerline offset
    // sign would invert if the pilot touched down 3 m
    // left and then drifted through center to right of
    // centerline during the rollout. Live bug 2026-05-03
    // (MKJS RWY 07: pilot reported 3 m left, app showed
    // 2.7 m right). Buffer fallback to `snap` only when
    // the buffer is empty (resumed flight).
    stats.landing_lat = Some(
        td_buf_sample
            .map(|s| s.lat)
            .unwrap_or(snap.lat),
    );
    stats.landing_lon = Some(
        td_buf_sample
            .map(|s| s.lon)
            .unwrap_or(snap.lon),
    );
    stats.landing_heading_true_deg = Some(
        td_buf_sample
            .map(|s| s.heading_true_deg)
            .unwrap_or(snap.heading_deg_true),
    );

    // Touchdown profile — full buffer reframed to ms-relative
    // timestamps. PIREP renders this as a tiny V/S curve so
    // the pilot can see the flare shape after the fact.
    stats.touchdown_profile = stats
        .snapshot_buffer
        .iter()
        .map(|s| TouchdownProfilePoint {
            t_ms: (s.at - actual_td_at).num_milliseconds() as i32,
            vs_fpm: s.vs_fpm,
            g_force: s.g_force,
            agl_ft: s.agl_ft,
            on_ground: s.on_ground,
            heading_true_deg: s.heading_true_deg,
            groundspeed_kt: s.groundspeed_kt,
            indicated_airspeed_kt: s.indicated_airspeed_kt,
            pitch_deg: s.pitch_deg,
            bank_deg: s.bank_deg,
        })
        .collect();

    // Sideslip / crab angle at touchdown — GEES-aligned:
    //   sideslip = atan2(VEL_BODY_X, VEL_BODY_Z) × 180/π
    // VEL_BODY_X is the right component of velocity in the
    // aircraft's body frame; VEL_BODY_Z is the forward
    // component. The ratio's arctangent IS the angle
    // between the velocity vector and the nose. Native
    // and exact — much better than reconstructing track
    // from successive lat/lon. None when the SimVar isn't
    // wired or the aircraft is essentially stopped (Z<3 fps
    // ≈ 1.8 kt, vector noise dominates below that).
    stats.touchdown_sideslip_deg = match (
        snap.velocity_body_x_fps,
        snap.velocity_body_z_fps,
    ) {
        (Some(x), Some(z)) if z.abs() > 3.0 => {
            Some(x.atan2(z).to_degrees())
        }
        _ => None,
    };

    // Headwind / crosswind components at the touchdown
    // frame, native from `AIRCRAFT WIND X/Z`. Z is signed
    // such that positive = tailwind (wind blowing into the
    // aircraft from behind), so headwind = -Z. X positive
    // = wind from the right side.
    stats.landing_headwind_kt = snap.aircraft_wind_z_kt.map(|z| -z);
    stats.landing_crosswind_kt = snap.aircraft_wind_x_kt;
}

/// v0.16.24: how close (in nm) a second airport must be to the nearest one
/// for the touchdown to count as "ambiguous between two fields". Inside this
/// margin we prefer the planned `arr_airport` if it's one of the two — so a
/// touchdown that is geometrically tied between the planned airport and an
/// immediate neighbour never flips away from the plan. 1.5 nm is well below
/// the spacing of any two distinct real-world airports a pilot could land on
/// in one rollout, yet large enough to absorb the nearest-threshold proxy
/// error `find_nearest_airports` introduces (it keys on the closest runway
/// threshold, not the airport reference point).
const CORRELATE_AIRPORT_AMBIGUITY_NM: f64 = 1.5;
/// v0.16.24: search radius (nm) for resolving the ACTUAL landing airport from
/// the touchdown coordinate. The touchdown is on a runway, so the nearest
/// airport is at most a runway-half-length away (~1.5 nm for the longest
/// strips). 6 nm is generous head-room without pulling in distant neighbours.
const CORRELATE_AIRPORT_SEARCH_RADIUS_NM: f64 = 6.0;

/// v0.16.24: resolve the ICAO of the airport the wheels ACTUALLY touched on,
/// from the touchdown coordinate, for keying the navdata cache.
///
/// THE on-plan invariant (load-bearing): for a non-divert landing the nearest
/// airport to the touchdown IS the planned `arr_airport`, so this returns
/// `arr_airport` unchanged → the downstream cache lookup, NavAirport, runway
/// match, source and geometry are byte-identical to the pre-v0.16.24
/// `arr_airport`-keyed path. We additionally short-circuit to `arr_airport`
/// the moment the nearest result matches it (case-insensitive) so the
/// on-plan path never even looks at a different key.
///
/// On a DIVERT the nearest airport is the actual landing field (e.g. WMKA),
/// not the planned one (WMKK) — we return that so the cached navdata for the
/// real airport (warmed by the alternate fetch or the approach pre-fetch)
/// becomes reachable.
///
/// Tie-break: when two airports are within `CORRELATE_AIRPORT_AMBIGUITY_NM`
/// of each other and one of them is the planned `arr_airport`, prefer the
/// plan — this keeps a touchdown that is geometrically ambiguous between the
/// planned field and a stone's-throw neighbour anchored to the plan.
///
/// Returns the uppercased planned `arr_airport` when no airport is in range
/// (mid-ocean / off-grid strip) — identical to the old behaviour, where the
/// cache lookup on `arr_airport` would simply miss and fall through to
/// OurAirports.
fn correlate_airport_icao(arr_airport: &str, td_lat: f64, td_lon: f64) -> String {
    let planned = arr_airport.trim().to_uppercase();
    // Pull a small candidate set (not just the nearest) so the planned
    // airport can win a near-tie even when a co-located / satellite field's
    // runway-threshold proxy is marginally closer than the planned airport's
    // own nearest threshold. 5 covers any realistic cluster of fields around
    // one touchdown.
    let nearby = runway::find_nearest_airports(
        td_lat,
        td_lon,
        CORRELATE_AIRPORT_SEARCH_RADIUS_NM * 1852.0,
        5,
    );
    let Some(nearest) = nearby.first() else {
        // No airport within range — keep the planned key (cache miss →
        // OurAirports fallback, exactly as before).
        return planned;
    };
    let nearest_icao = nearest.icao.trim().to_uppercase();
    // On-plan fast path: nearest IS the plan → byte-identical to the old
    // `arr_airport`-keyed lookup.
    if nearest_icao == planned {
        return planned;
    }
    // Ambiguity tie-break (on-plan invariant guard): if the planned airport
    // is among the candidates AND sits within the ambiguity margin of the
    // nearest, prefer the plan. This keeps a genuine on-plan landing anchored
    // to `arr_airport` even when threshold-proxy noise made a stone's-throw
    // neighbour the bare nearest — so the result stays byte-identical to the
    // old `arr_airport`-keyed path for non-diverts.
    let planned_in_candidates = nearby
        .iter()
        .find(|na| na.icao.trim().eq_ignore_ascii_case(&planned));
    if let Some(planned_cand) = planned_in_candidates {
        let gap_nm = (planned_cand.distance_m - nearest.distance_m) / 1852.0;
        if gap_nm <= CORRELATE_AIRPORT_AMBIGUITY_NM {
            return planned;
        }
    }
    // QS-1 vanished-arr guard (v0.16.24): the planned field can be MISSING
    // from OurAirports entirely — a closed/inactive strip (real surface:
    // CYWA) is dropped from the parsed runway table (closed runways are
    // skipped at parse time). When that happens an on-plan landing there
    // finds NO `arr_airport` candidate, and if a DIFFERENT open field sits
    // within the search radius the bare-nearest logic would key the cache on
    // that neighbour's ICAO — wrong. Distinguish this from a genuine divert
    // by whether `arr_airport` is findable in OurAirports at all:
    //   * NOT findable (`airport_position` == None, same parsed table the
    //     candidate set comes from) ⇒ the planned field is simply absent from
    //     our data, the wheels are most plausibly on the planned-but-unlisted
    //     strip → PREFER `arr_airport` so the cache key (and any on-demand
    //     navdata fetch / OurAirports fallback) stays anchored to the plan.
    //   * findable (`airport_position` == Some) but not within the search
    //     radius ⇒ a real, mapped planned field that is far from here ⇒ a
    //     GENUINE divert → fall through and return the actual nearest field.
    // This only ever fires when the planned ICAO is absent from OurAirports,
    // so it cannot touch the 99.5% path where `arr_airport` is present.
    if planned_in_candidates.is_none() && runway::airport_position(&planned).is_none() {
        return planned;
    }
    // Genuine divert — the wheels touched a different field than planned.
    nearest_icao
}

/// v0.16.24: per-tick decision for the approach-phase divert navdata
/// pre-fetch. Pure (no I/O): inspects the live snapshot + the planned
/// `arr_airport`, updates the stability-tracking state in `stats`, and
/// returns `Some(icao)` exactly when a stable, committed approach to a
/// DIFFERENT field has just become eligible for a navdata pre-fetch. The
/// caller fires `spawn_navdata_fetch` for that ICAO (which has its own
/// per-ICAO idempotency guard, so a duplicate is a cheap no-op).
///
/// Why it doesn't hammer the VPS:
///   * Only runs while airborne and descending (`MIN_SINK_FPM`) below
///     `MAX_AGL_FT` — i.e. an actual approach, not cruise.
///   * Only considers a field that is (a) within `MAX_DIST_NM`, (b)
///     genuinely diverged from the plan (`PLANNED_DIVERGE_NM`), and (c)
///     NOT the planned `arr_airport` (whose navdata is already fetched).
///   * Debounced: the same diverged field must stay the nearest candidate
///     for `STABLE_SECS` before we fire — a field merely overflown on a
///     vector resets the timer.
///   * Dedup: once fired for an ICAO we record it in
///     `stats.divert_prefetch_icao` and never re-fire for the same field.
///
/// Returns `None` (and clears the stability timer) whenever the conditions
/// don't hold, so the timer only accrues on a genuinely stable candidate.
fn divert_prefetch_decision(
    stats: &mut FlightStats,
    snap: &SimSnapshot,
    arr_airport: &str,
    now: DateTime<Utc>,
) -> Option<String> {
    // Gate: airborne, low enough, and actually descending.
    let committed_approach = !snap.on_ground
        && snap.altitude_agl_ft <= DIVERT_PREFETCH_MAX_AGL_FT
        && (snap.vertical_speed_fpm as f64) <= DIVERT_PREFETCH_MIN_SINK_FPM;
    if !committed_approach {
        stats.divert_prefetch_stable_since = None;
        return None;
    }

    let planned = arr_airport.trim().to_uppercase();
    // How far is the planned destination from here? If we're still near it
    // there's no divert to pre-fetch — the planned navdata covers us.
    //
    // v0.16.24 (QS-2 FIX C): resolve the planned airport's position ONCE per
    // flight and reuse it. `airport_position` is a full ~48k-row linear scan;
    // the planned airport never changes, so we memoize it (`get_or_insert_with`)
    // instead of re-scanning every approach tick. Behaviour is identical — the
    // cached value (including `None` when the planned ICAO isn't in OurAirports)
    // preserves the exact INFINITY-distance fallback the inline call produced.
    let planned_pos = *stats
        .planned_arr_position_cache
        .get_or_insert_with(|| runway::airport_position(&planned));
    let dist_to_planned_nmi = planned_pos
        .map(|(la, lo)| runway::distance_m(snap.lat, snap.lon, la, lo) / 1852.0)
        .unwrap_or(f64::INFINITY);
    if dist_to_planned_nmi < DIVERT_PREFETCH_PLANNED_DIVERGE_NM {
        stats.divert_prefetch_stable_since = None;
        return None;
    }

    // Nearest field to the current position, within the committed-approach
    // radius.
    let nearby = runway::find_nearest_airports(
        snap.lat,
        snap.lon,
        DIVERT_PREFETCH_MAX_DIST_NM * 1852.0,
        1,
    );
    let Some(nearest) = nearby.into_iter().next() else {
        stats.divert_prefetch_stable_since = None;
        return None;
    };
    let nearest_icao = nearest.icao.trim().to_uppercase();
    // Same airport as planned → not a divert; nothing to pre-fetch.
    if nearest_icao == planned {
        stats.divert_prefetch_stable_since = None;
        return None;
    }

    // Stable candidate? Track since-when this exact field has been the
    // committed nearest. Reset the timer whenever the candidate changes.
    match &stats.divert_prefetch_candidate {
        Some(prev) if *prev == nearest_icao => {}
        _ => {
            stats.divert_prefetch_candidate = Some(nearest_icao.clone());
            stats.divert_prefetch_stable_since = Some(now);
        }
    }
    let stable_since = stats.divert_prefetch_stable_since.get_or_insert(now);
    if (now - *stable_since).num_seconds() < DIVERT_PREFETCH_STABLE_SECS {
        return None;
    }

    // Already pre-fetched this field? Idempotent at this layer too.
    if stats.divert_prefetch_icao.as_deref() == Some(nearest_icao.as_str()) {
        return None;
    }
    stats.divert_prefetch_icao = Some(nearest_icao.clone());
    Some(nearest_icao)
}

/// v0.15.24: Runway correlation at the touchdown point — extracted verbatim
/// from the FSM Landing arm (see `stamp_touchdown_metadata` for why).
/// Resolves which runway the wheels actually touched on (Navigraph
/// navdata-cache with transparent OurAirports fallback), stamps
/// `runway_match` / `runway_source` / `runway_nav_cycle` /
/// `runway_nav_geometry` plus the actual threshold-crossing height.
///
/// None when no runway lies within ~3 km of the touchdown coordinate. Sits
/// next to `approach_runway` (from `ATC RUNWAY SELECTED`) — the runway_match
/// value is the authoritative one because it's derived from where the wheels
/// actually touched, not the ATC clearance. Uses the buffered TD-moment
/// lat/lon/heading (same reasoning as the `landing_lat` capture in
/// `stamp_touchdown_metadata`) so the centerline-offset sign and along-track
/// distance reflect the real touchdown point, not where the aircraft has
/// rolled to during the streamer's 5 s edge-detection lag.
///
/// Lock order: caller holds the `flight.stats` lock; this takes
/// `flight.navdata` nested inside it — same order as the pre-extraction FSM
/// arm (stats → navdata), never the reverse anywhere in the codebase.
fn correlate_touchdown_runway(
    stats: &mut FlightStats,
    snap: &SimSnapshot,
    flight: &ActiveFlight,
    td_buf_sample: Option<&TelemetrySample>,
) {
    let (rw_lat, rw_lon, rw_hdg_true) = td_buf_sample
        .map(|s| (s.lat, s.lon, s.heading_true_deg))
        .unwrap_or((snap.lat, snap.lon, snap.heading_deg_true));

    // v0.16.24: Navdata-Cache gegen den ECHTEN Landeflughafen befragen,
    // nicht gegen den geplanten `arr_airport`. Bei einem On-Plan-Landing
    // ist der nächste Airport zum Touchdown == `arr_airport`, also bleibt
    // `actual_icao` == `arr_airport` und der Cache-Lookup ist
    // BYTE-IDENTISCH zum vor-v0.16.24-Pfad (siehe `correlate_airport_icao`
    // — die On-Plan-Invariante). Bei einem DIVERT ist `actual_icao` das
    // tatsächliche Landefeld (z.B. WMKA statt geplant WMKK), womit dessen
    // — vom Approach-Pre-Fetch oder Alternate-Fetch — gecachte Navdata
    // erreichbar wird. `lookup_runway_with_fallback` fällt weiterhin
    // transparent auf OurAirports zurück, wenn kein NavAirport vorhanden
    // ist oder die NavRunways zu weit vom Touchdown liegen.
    let actual_icao = correlate_airport_icao(&flight.arr_airport, rw_lat, rw_lon);
    let (nav_opt, nav_cycle) = {
        let cache = flight.navdata.lock().expect("navdata lock");
        let apt = cache.get(&actual_icao).cloned();
        let cycle = cache.cycle.clone();
        (apt, cycle)
    };
    // Record the actual landing airport for the on-demand fetch + the
    // finalize-with-best re-correlation + diagnostics.
    stats.runway_correlation_icao = Some(actual_icao.clone());

    let lookup_result = runway::lookup_runway_with_fallback(
        rw_lat,
        rw_lon,
        rw_hdg_true,
        nav_opt.as_ref(),
    );
    if let Some((rw, source)) = lookup_result {
        // Wenn der Match aus Navigraph kam, finde die
        // konkrete NavRunway-Geometrie (designator-Match)
        // damit die Assessment-Funktionen (TDZ/TCH/DDS)
        // den displaced_threshold_ft, tch_ft und
        // glideslope_angle ohne zweite Lookup-Runde
        // bekommen. Bei OurAirports-Fallback bleibt
        // runway_nav_geometry = None und die Assessment-
        // Funktionen werden skipped.
        let nav_geometry = if matches!(source, runway::RunwaySource::Navigraph) {
            nav_opt.as_ref().and_then(|apt| {
                apt.runways
                    .iter()
                    .find(|nr| nr.designator == rw.runway_ident)
                    .cloned()
            })
        } else {
            None
        };
        // v0.16.24: remember whether we fell back to OurAirports at the
        // touchdown instant, so the caller can fire an on-demand navdata
        // fetch for the actual landing airport and `build_landing_record`
        // can re-correlate against the now-warm cache (finalize-with-best).
        let is_fallback = matches!(source, runway::RunwaySource::OurAirportsFallback);
        stats.runway_fallback_at_touchdown = is_fallback;
        // v0.16.24: enriched diagnostics on the fallback. The actual
        // landing ICAO, whether its navdata was cached (cache-miss vs.
        // present-but-too-far), and the AIRAC cycle — so a future fallback
        // is diagnosable from the breadcrumb alone instead of "match came
        // from OurAirports, no idea why".
        if is_fallback {
            let cached = nav_opt.is_some();
            let reason = if cached {
                // NavAirport WAS cached but its runways were all too far
                // from the touchdown — pilot landed at a field we have
                // navdata for, just not on a runway it lists (rare; stale
                // geometry or a closed runway).
                "navdata_cached_but_no_runway_within_range"
            } else {
                // The actual airport's navdata was never fetched / not in
                // the active cycle — the common divert case.
                "navdata_cache_miss"
            };
            tracing::warn!(
                actual_airport = %actual_icao,
                planned_airport = %flight.arr_airport,
                divert = actual_icao != flight.arr_airport.trim().to_uppercase(),
                navdata_cached = cached,
                fallback_reason = reason,
                airac_cycle = ?nav_cycle,
                runway = %rw.runway_ident,
                "runway correlation fell back to OurAirports"
            );
        }
        tracing::info!(
            airport = %rw.airport_ident,
            runway = %rw.runway_ident,
            centerline_m = rw.centerline_distance_m,
            from_threshold_ft = rw.touchdown_distance_from_threshold_ft,
            side = %rw.side,
            source = ?source,
            cycle = ?nav_cycle,
            "touchdown correlated to runway"
        );
        stats.runway_match = Some(rw);
        stats.runway_source = Some(source);
        stats.runway_nav_cycle = if matches!(source, runway::RunwaySource::Navigraph) {
            nav_cycle
        } else {
            None
        };
        stats.runway_nav_geometry = nav_geometry;
    } else {
        // No runway within range at all — not a navdata fallback, just no
        // match (mid-ocean / off-grid). Clear the fallback flag too.
        stats.runway_fallback_at_touchdown = false;
        stats.runway_match = None;
        stats.runway_source = None;
        stats.runway_nav_cycle = None;
        stats.runway_nav_geometry = None;
    }

    // v0.8.0 F5 — TCH (Threshold-Crossing-Height) Actual:
    // Scanne den snapshot_buffer chronologisch und nimm den
    // ersten Sample dessen along-track-Distanz vom Landing-
    // Threshold ≥ 0 ist (= Aircraft hat die Threshold-Linie
    // gerade überflogen). agl_ft an diesem Sample = actual
    // TCH. Nur möglich wenn wir die Navigraph-Geometrie
    // haben (= echte Threshold-Position) — OurAirports-
    // Threshold ist um bis zu 11 m off (MS713-Anchor),
    // damit wäre der TCH-Wert unzuverlässig.
    stats.runway_tch_actual_ft = None;
    if let Some(geom) = stats.runway_nav_geometry.as_ref() {
        let thr_lat = geom.threshold.lat;
        let thr_lon = geom.threshold.lon;
        let end_lat = geom.far_end.lat;
        let end_lon = geom.far_end.lon;
        for s in stats.snapshot_buffer.iter() {
            let along = runway::along_track_m_signed(
                thr_lat, thr_lon, end_lat, end_lon, s.lat, s.lon,
            );
            if along >= 0.0 {
                // Erstes Sample past-threshold gefunden.
                // Realistisch landet der TCH-Sample im
                // Bereich 40-60 ft AGL für ILS-Anflüge.
                stats.runway_tch_actual_ft = Some(s.agl_ft);
                break;
            }
        }
    }
}

/// v0.16.24: the runway-correlation fields, resolved at record-build time
/// (finalize-with-best). Mirrors the four `stats.runway_*` fields so
/// `build_landing_record` can use a possibly-UPGRADED set without mutating
/// `stats`.
struct FinalizedRunwayCorrelation {
    runway_match: Option<runway::RunwayMatch>,
    runway_source: Option<runway::RunwaySource>,
    runway_nav_cycle: Option<String>,
    runway_nav_geometry: Option<aeroacars_mqtt::navdata::NavRunway>,
    runway_tch_actual_ft: Option<f32>,
}

/// v0.16.24: finalize-with-best runway correlation, run at LandingRecord
/// build time (minutes after touchdown, at/just-before PIREP filing).
///
/// The touchdown-instant correlation (`correlate_touchdown_runway`)
/// produced a PROVISIONAL result. On a divert it may have fallen back to
/// OurAirports because the actual airport's navdata wasn't cached yet. By
/// record-build time the on-demand fetch (`maybe_fetch_actual_landing_navdata`)
/// and/or the approach pre-fetch have (hopefully) warmed the cache. This
/// re-runs the lookup against the now-current cache and RETURNS the better
/// result if Navigraph is now available — otherwise it returns the stamped
/// provisional values verbatim (graceful).
///
/// NON-RACY by construction: this is a synchronous read of whatever the
/// cache holds AT THE MOMENT the record is built — there is no separate
/// async "re-correlate later" path that could race the filing. If the
/// fetch hasn't completed, the cache simply still lacks the airport and we
/// keep the provisional OurAirports result.
///
/// ON-PLAN INVARIANT: for a non-divert landing the stamped source is
/// already Navigraph (the planned airport was fetched at flight start), so
/// the `is_fallback` guard below is false and we return the stamped values
/// UNCHANGED — byte-identical to pre-v0.16.24. We only ever re-run the
/// lookup when the touchdown FELL BACK, never when it already matched
/// Navigraph.
fn finalize_runway_correlation(
    flight: &ActiveFlight,
    stats: &FlightStats,
) -> FinalizedRunwayCorrelation {
    // The provisional (stamped) set — the default we keep unless we can
    // strictly improve it.
    let provisional = FinalizedRunwayCorrelation {
        runway_match: stats.runway_match.clone(),
        runway_source: stats.runway_source,
        runway_nav_cycle: stats.runway_nav_cycle.clone(),
        runway_nav_geometry: stats.runway_nav_geometry.clone(),
        runway_tch_actual_ft: stats.runway_tch_actual_ft,
    };

    // Only attempt an upgrade when the touchdown correlation fell back to
    // OurAirports. If it already matched Navigraph (the on-plan case), keep
    // the stamped values verbatim → byte-identical, no re-lookup.
    if !matches!(
        stats.runway_source,
        Some(runway::RunwaySource::OurAirportsFallback)
    ) {
        return provisional;
    }

    // Need the buffered TD-moment coordinates that the touchdown
    // correlation used (stamped into landing_* by `stamp_touchdown_metadata`
    // from the SAME td_buf_sample, so re-correlation uses identical inputs).
    let (Some(rw_lat), Some(rw_lon), Some(rw_hdg_true)) = (
        stats.landing_lat,
        stats.landing_lon,
        stats.landing_heading_true_deg,
    ) else {
        return provisional;
    };

    // Resolve the actual landing airport the same way the touchdown
    // correlation did and look it up in the (now-warm) cache.
    let actual_icao = correlate_airport_icao(&flight.arr_airport, rw_lat, rw_lon);
    let (nav_opt, nav_cycle) = {
        let cache = flight.navdata.lock().expect("navdata lock");
        (cache.get(&actual_icao).cloned(), cache.cycle.clone())
    };
    // No navdata for the actual field yet (fetch not landed / 404) → keep
    // the provisional OurAirports result. Graceful.
    let Some(apt) = nav_opt else {
        return provisional;
    };
    // Re-run the Navigraph-only lookup. If it still misses (pilot landed at
    // a field we have navdata for but on a runway it doesn't list), keep
    // the provisional result — never worse than today.
    let Some(rw) = runway::lookup_runway_in_nav(rw_lat, rw_lon, rw_hdg_true, &apt) else {
        return provisional;
    };

    // We have a strictly-better Navigraph match. Rebuild the consistent
    // field set exactly as `correlate_touchdown_runway` would have, had the
    // cache been warm at touchdown.
    let nav_geometry = apt
        .runways
        .iter()
        .find(|nr| nr.designator == rw.runway_ident)
        .cloned();
    // TCH-actual: deliberately NOT recomputed here. The first-past-threshold
    // scan needs the pre-touchdown samples (~50 ft AGL at the threshold), but
    // by record-build time (minutes after touchdown) the rolling 5 s
    // `snapshot_buffer` has long evicted them — it now holds only on-ground /
    // taxi samples, so a re-scan would stamp a garbage ~0 ft "TCH". The
    // provisional value was `None` (the OurAirports fallback gates the TCH
    // scan off), and `None` (honest "couldn't measure") is the correct,
    // never-worse result for the upgrade. TCH-actual is forensic/coaching
    // only and not a scored field, so the upgrade still delivers the
    // LDA/rollout geometry that matters.
    let runway_tch_actual_ft = None;

    tracing::info!(
        actual_airport = %actual_icao,
        runway = %rw.runway_ident,
        cycle = ?nav_cycle,
        "finalize-with-best: upgraded provisional OurAirports runway match to Navigraph"
    );

    FinalizedRunwayCorrelation {
        runway_match: Some(rw),
        runway_source: Some(runway::RunwaySource::Navigraph),
        runway_nav_cycle: nav_cycle,
        runway_nav_geometry: nav_geometry,
        runway_tch_actual_ft,
    }
}

/// v0.16.24 (QS-6): run `finalize_runway_correlation` and WRITE the (possibly
/// upgraded) result back into `stats`, so every downstream consumer that reads
/// `stats.runway_*` — the phpVMS PIREP native `score`
/// (`compute_aggregate_master_score`), the "Landing Score" custom field
/// (`build_pirep_fields`), the LandingRecord, the TouchdownPayload — sees ONE
/// consistent, best-available runway-correlation set.
///
/// WHY THIS EXISTS (the bug it closes): on a divert where the touchdown-instant
/// correlation fell back to OurAirports (the actual field's navdata wasn't
/// cached yet) the on-demand fetch fires AT touchdown, but PIREP filing happens
/// minutes later (after rollout/taxi/Arrived). Before this helper the PIREP
/// score + body were built from the PROVISIONAL OurAirports stats while only
/// the LandingRecord (built inside `record_landing_for_filed_flight`, which
/// already finalized) saw Navigraph — an inconsistency, and the authoritative
/// scored PIREP record never got the LDA/rollout upgrade. Calling this at the
/// TOP of the body-build stats lock makes the score/fields read the upgraded
/// Navigraph geometry too.
///
/// IDEMPOTENT + ON-PLAN-SAFE: `finalize_runway_correlation` is a no-op whenever
/// the stamped source is already Navigraph (the on-plan case, or a second call
/// after the first upgrade), so a non-divert write-back is byte-identical and
/// the later `record_landing_for_filed_flight` finalize sees the values already
/// upgraded and returns them verbatim. Caller must hold the `stats` mutex
/// mutably.
fn apply_finalized_runway_correlation(flight: &ActiveFlight, stats: &mut FlightStats) {
    let finalized = finalize_runway_correlation(flight, stats);
    stats.runway_match = finalized.runway_match;
    stats.runway_source = finalized.runway_source;
    stats.runway_nav_cycle = finalized.runway_nav_cycle;
    stats.runway_nav_geometry = finalized.runway_nav_geometry;
    stats.runway_tch_actual_ft = finalized.runway_tch_actual_ft;
}

/// v0.15.24: Landing-weight stamp — extracted verbatim from the tail of the
/// FSM Landing arm. Prefer TOTAL WEIGHT (fuel + payload + empty); only
/// fall back to ZFW + fuel if the SimVar is missing. Fenix returns 0 for
/// both → snapshot mapping converted it to None, so the field stays unset
/// and the PIREP filter drops it.
fn stamp_landing_weight(stats: &mut FlightStats, snap: &SimSnapshot) {
    if let Some(tw) = snap.total_weight_kg {
        stats.landing_weight_kg = Some(tw as f64);
    } else {
        let zfw = snap.zfw_kg.unwrap_or(0.0);
        let weight = zfw as f64 + snap.fuel_total_kg as f64;
        if weight > 0.0 {
            stats.landing_weight_kg = Some(weight);
        }
    }
}

/// v0.16.6: per-tick rollout accumulate/finalise — extracted VERBATIM from
/// the FSM Landing arm in `step_flight` so sampler-path (bush) landings can
/// drive it too while the FSM never reaches Landing. The FSM Landing arm
/// calls this at the exact position its inline code used to sit (first thing
/// in the arm), so FSM-path behaviour is unchanged.
///
/// Sums haversine deltas from the last seen position until one of the three
/// finalisation triggers fires (~40 kt exit speed / >30° heading turn-off /
/// 5 kt full-stop — see the `ROLLOUT_*` consts), then sets
/// `rollout_finalized` + `rollout_finalize_reason`. No-op once finalised.
/// Survives a Tauri restart because (last_lat, last_lon, distance,
/// finalized) persist in `PersistedFlightStats`.
fn rollout_tick(stats: &mut FlightStats, snap: &SimSnapshot) {
    if !stats.rollout_finalized {
        if let (Some(prev_lat), Some(prev_lon)) =
            (stats.rollout_last_lat, stats.rollout_last_lon)
        {
            let delta = ::geo::distance_m(prev_lat, prev_lon, snap.lat, snap.lon);
            stats.rollout_distance_m =
                Some(stats.rollout_distance_m.unwrap_or(0.0) + delta);
        }
        stats.rollout_last_lat = Some(snap.lat);
        stats.rollout_last_lon = Some(snap.lon);

        // Three independent finalisation triggers — whichever
        // fires first wins. See the constants near the top of
        // this file for the rationale on each threshold.
        let exit_speed_reached =
            snap.groundspeed_kt < ROLLOUT_EXIT_GS_KT && snap.on_ground;
        let full_stop = snap.groundspeed_kt < ROLLOUT_STOP_GS_KT && snap.on_ground;
        let turned_off_runway = match stats.landing_heading_true_deg {
            Some(td_heading) => {
                // Wrap-around-safe signed delta in (-180, 180].
                let mut diff = snap.heading_deg_true - td_heading;
                while diff > 180.0 {
                    diff -= 360.0;
                }
                while diff <= -180.0 {
                    diff += 360.0;
                }
                diff.abs() > ROLLOUT_HEADING_DEVIATION_DEG
            }
            None => false,
        };

        if exit_speed_reached || full_stop || turned_off_runway {
            stats.rollout_finalized = true;
            // v0.12.4 (Spec LE4): wire-form reason — the streamer
            // loop copies it into the `touchdown_rollout_finalized`
            // MQTT event.
            let reason = if turned_off_runway {
                "turned_off_runway"
            } else if full_stop {
                "full_stop"
            } else {
                "exit_speed"
            };
            stats.rollout_finalize_reason = Some(reason.to_string());
            tracing::info!(
                meters = stats.rollout_distance_m.unwrap_or(0.0),
                gs_kt = snap.groundspeed_kt,
                reason,
                "rollout finalised"
            );
        }
    }
}

/// v0.16.6: streamer-driven rollout for sampler-path landings. Bush flights
/// (GSG312 97OG) touch down via the validated 50 Hz sampler while the FSM is
/// still in Takeoff/Climb — the FSM Landing arm (which owns the per-tick
/// rollout) never runs, so `rollout_distance_m` stayed `Some(0.0)` forever.
/// Called once per streamer tick right after `step_flight`:
///
///   * `sampler_touchdown_at` Some → a validated touchdown initialised the
///     rollout fields (sampler stamp block).
///   * `!rollout_finalized` → still accumulating.
///   * FSM NOT in Landing → no double-tick: when the FSM IS in Landing its
///     arm has just driven `rollout_tick` inside `step_flight` on this very
///     tick. On normal flights the Final→Landing transition re-initialises
///     the rollout fields with the FSM's own values, so this pre-Landing
///     accumulation is discarded there — byte-identical to before.
fn sampler_path_rollout_tick(stats: &mut FlightStats, snap: &SimSnapshot) {
    if stats.sampler_touchdown_at.is_some()
        && !stats.rollout_finalized
        && !matches!(stats.phase, FlightPhase::Landing)
    {
        rollout_tick(stats, snap);
    }
}

/// v0.16.6: per-episode reset of the approach-stability stats + rollout
/// fields — called from the sampler's climb-out reset (touch-and-go) right
/// next to the `landing_lat`/`landing_lon` re-arm. The FINAL touchdown of a
/// bush flight must evaluate stability over ITS OWN window and accumulate
/// ITS OWN rollout; without this the PIREP would silently carry TD#1's
/// numbers (the FSM Landing arm never runs on bush flights to overwrite
/// them). On FSM-tracked flights the Landing-entry recompute overwrites all
/// of these at the next touchdown anyway — clearing them here additionally
/// only means the fields read `None`/default between the T&G and the final
/// touchdown instead of holding stale TD#1 values.
fn clear_approach_stability_and_rollout(stats: &mut FlightStats) {
    stats.approach_vs_stddev_fpm = None;
    stats.approach_bank_stddev_deg = None;
    stats.approach_vs_deviation_fpm = None;
    stats.approach_max_vs_deviation_below_500_fpm = None;
    stats.approach_bank_stddev_filtered_deg = None;
    stats.approach_runway_changed_late = false;
    stats.approach_stable_at_gate = None;
    stats.approach_vs_jerk_fpm = None;
    stats.approach_ias_stddev_kt = None;
    stats.approach_excessive_sink = false;
    stats.approach_stable_config = None;
    stats.approach_used_hat = false;
    stats.approach_window_sample_count = None;
    stats.approach_stable_at_da = None;
    stats.approach_stall_warning_count = 0;
    stats.rollout_distance_m = None;
    stats.rollout_finalized = false;
    stats.rollout_last_lat = None;
    stats.rollout_last_lon = None;
    stats.rollout_finalize_reason = None;
}

/// Groundspeed-Schwelle, unter der TakeoffRoll (nachhaltig) als „rollt
/// nicht" gilt. 10 kt unter dem Vorwärts-Trigger (GS > 30 kt) → Hysterese
/// gegen Flip-Flop an der Schwelle.
const TAKEOFF_ROLL_ABORT_KT: f32 = 20.0;
/// Dwell, den die GS unter der Schwelle bleiben muss, bevor demotet wird
/// (frisst GS-Einzeltick-Glitches; braucht ≥ 2 Ticks über ≥ 3 s).
const TAKEOFF_ROLL_ABORT_DWELL_SECS: i64 = 3;

/// Rückkante der TakeoffRoll-Phase — behebt den flottenweiten
/// TAKEOFF_ROLL_STUCK (5 % der Flüge, 614-Flug-Scan 2026-07-05).
///
/// `TaxiOut → TakeoffRoll` triggert bei GS > 30 kt am Boden. Das trippt
/// auch ein schneller BACKTRACK (z. B. die kurze EGLC-Bahn zum Schwellen-
/// kopf runterrollen). Bremst der Flieger dann zum Ausrichten/Warten wieder
/// ab, hing die Phase bisher für IMMER auf „Takeoff Roll" — der TakeoffRoll-
/// Arm kannte nur die Vorwärtskante (on_ground → airborne = Takeoff).
///
/// Fällt die Groundspeed nachhaltig (Dwell) unter `TAKEOFF_ROLL_ABORT_KT`
/// während der Flieger am Boden ist, zurück zu TaxiOut. Während einer
/// ECHTEN Startrolle ist die Bedingung nie erfüllt (GS steigt dort monoton
/// von > 30 auf > 150 kt, dippt nie unter 20).
///
/// Pur + uhrlos (Caller liefert `now`) → direkt testbar. Rückgabe:
/// (Ziel-Phase falls demotet, neuer `slow_since`-Wert für die Stats).
fn takeoff_roll_demote(
    on_ground: bool,
    groundspeed_kt: f32,
    slow_since: Option<DateTime<Utc>>,
    now: DateTime<Utc>,
) -> (Option<FlightPhase>, Option<DateTime<Utc>>) {
    if on_ground && groundspeed_kt < TAKEOFF_ROLL_ABORT_KT {
        let since = slow_since.unwrap_or(now);
        if (now - since).num_seconds() >= TAKEOFF_ROLL_ABORT_DWELL_SECS {
            (Some(FlightPhase::TaxiOut), None) // Dwell erfüllt → demote + Reset
        } else {
            (None, Some(since)) // Dwell läuft noch → Phase halten
        }
    } else {
        (None, None) // GS zurück über Schwelle / airborne → Dwell verwerfen
    }
}

fn step_flight(flight: &ActiveFlight, snap: &SimSnapshot) -> Option<FlightPhase> {
    step_flight_at(flight, snap, Utc::now())
}

/// Uhr-injizierbare Variante von [`step_flight`] — `now` ist DER Zeitpunkt
/// dieses Ticks für sämtliche Dwell-Timer und Zeitstempel im FSM-Schritt.
/// Produktion ruft immer über den [`step_flight`]-Wrapper (echte Uhr);
/// Replay-Tests füttern historische Timestamps aus echten Flug-Logs und
/// machen damit die v1-FSM erstmals offline-replayfähig (das JSONL-
/// Recorder-Format verspricht das seit jeher — "feed it back into the FSM
/// offline", crates/recorder).
fn step_flight_at(
    flight: &ActiveFlight,
    snap: &SimSnapshot,
    now: DateTime<Utc>,
) -> Option<FlightPhase> {
    let mut stats = flight.stats.lock().expect("flight stats");

    // Category-aware FSM: a rotorcraft flies a profile the fixed-wing phase
    // logic mis-reads (operates below the 500 ft Climb gate, arrests its
    // descent into a hover that looks like a go-around, lands rotors-running).
    // Resolved once per tick from the live ICAO + gear-type flags; FixedWing
    // when unknown ⇒ all of the branches below are byte-identical to before.
    let category = aircraft_category::resolve_category(
        snap.aircraft_icao.as_deref(),
        snap.gear_is_skid,
        snap.gear_is_floats,
        snap.gear_is_wheels,
        snap.water_rudder_present,
    );

    // v0.7.19 GAF-707 Sim-Event-Pfad (Spec §Klassifikator-Trigger-Punkte):
    // wenn der Adapter `snap.crashed=true` liefert und der aktive Flug
    // noch nicht gelatcht war, sofort Accident setzen — KEIN Warten auf
    // Touchdown-Edge. `kind=SimCrash` ist authoritativ; spaeter
    // greifende Heuristik mergt nur ihre Reasons rein, aendert aber
    // nicht den kind.
    //
    // `CrashReset` aus dem Adapter laesst snap.crashed wieder auf false
    // fallen, aber der hier gesetzte Latch persistiert bis Flight-End/
    // Cleanup/neuem Flight-Start (Spec §Leitentscheidung 6).
    if snap.crashed && !stats.accident_detected {
        stats.accident_detected = true;
        stats.accident_at = Some(now);
        stats.accident_kind = Some(accident::AccidentKind::SimCrash.as_wire_str().to_string());
        stats.accident_confidence = Some("high".into());
        let source = snap.crash_source.clone().unwrap_or_else(|| "sim_event".into());
        stats.accident_reasons.push(format!("crash_source={source}"));
        tracing::warn!(
            crash_source = %source,
            "v0.7.19: simulator crash event latched on active flight"
        );
    }

    // v0.5.40: Anti-Flicker-State + Pushback-Active-Tracking refreshen.
    // Muss am Anfang passieren damit alle nachfolgenden Phase-Handler den
    // aktuellen Stand sehen.
    if snap.engines_running > 0 {
        stats.last_engines_running_above_zero_at = Some(now);
    }
    if let Some(pb) = snap.pushback_state {
        if pb != 3 {
            stats.saw_pushback_state_active = true;
        }
    }

    // Distance accounting.
    if let (Some(prev_lat), Some(prev_lon)) = (stats.last_lat, stats.last_lon) {
        let d_m = ::geo::distance_m(prev_lat, prev_lon, snap.lat, snap.lon);
        if d_m > DISTANCE_EPSILON_M {
            stats.distance_nm += d_m / 1852.0;
        }
    }
    stats.last_lat = Some(snap.lat);
    stats.last_lon = Some(snap.lon);
    stats.position_count = stats.position_count.saturating_add(1);
    let prev_fuel_kg = stats.last_fuel_kg;
    stats.last_fuel_kg = Some(snap.fuel_total_kg);
    // v0.3.0: ZFW + Total-Weight für Live-Loadsheet (Cockpit-Tab
    // während Boarding-Phase). Updates jeden Tick. None bleiben sie
    // wenn das Aircraft-Profil die SimVars nicht meldet (z.B. Fenix
    // ohne erweiterte Profile).
    stats.last_zfw_kg = snap.zfw_kg;
    stats.last_total_weight_kg = snap.total_weight_kg;

    // Block fuel = peak fuel observed across the flight, with a
    // defuel guard. Rationale:
    //   * Tracking the peak captures the loaded amount no matter
    //     when refuelling completes — Fenix's async EFB load,
    //     APU burn during boarding, etc. all become non-issues
    //     because the peak naturally settles on the loaded value.
    //   * BUT pure peak doesn't handle defuelling: pilot loads
    //     4000 kg, realises overload, removes 1000 kg → peak
    //     stays at 4000, Used Fuel = 4000 − landing reads ~1000
    //     kg too high. So we detect a sudden large drop (well
    //     above any realistic engine burn over a tick interval)
    //     and reset the peak to the current value. Threshold
    //     200 kg covers even A380 at takeoff thrust over a 30 s
    //     cruise tick (~210 kg max), so no false positives from
    //     normal operations.
    let live_fuel = snap.fuel_total_kg;
    if live_fuel > 0.0 {
        const DEFUEL_THRESHOLD_KG: f32 = 200.0;
        let is_defuel = prev_fuel_kg
            .map(|prev| prev - live_fuel > DEFUEL_THRESHOLD_KG)
            .unwrap_or(false);
        if is_defuel {
            tracing::info!(
                prev = prev_fuel_kg,
                live = live_fuel,
                drop = prev_fuel_kg.unwrap_or(0.0) - live_fuel,
                "defuel detected — resetting block_fuel peak baseline"
            );
            stats.block_fuel_kg = Some(live_fuel);
        } else {
            stats.block_fuel_kg = Some(
                stats
                    .block_fuel_kg
                    .map_or(live_fuel, |peak| peak.max(live_fuel)),
            );
        }
    }

    // Peak altitude tracker — every tick, take the max with the live
    // MSL altitude. Reported as the PIREP `level` field.
    let alt = snap.altitude_msl_ft as f32;
    stats.peak_altitude_ft = Some(stats.peak_altitude_ft.map_or(alt, |p| p.max(alt)));

    // Mark the flight as having actually been airborne. Sticky once
    // set — even if the aircraft comes back down (final approach,
    // touch-and-go) the flag stays true. Gates the universal
    // Arrived-fallback so neither GSX repositioning nor a few-meter
    // wackeln at the gate accidentally promotes the FSM to Arrived
    // pre-flight. See WAS_AIRBORNE_AGL_FT for the threshold rationale.
    // `was_airborne` flag — three-layer defense against false positives
    // (live bug 2026-05-03: PMDG B738, MSFS reported AGL=53819 ft for
    // 60 s during scenery load and the flag flipped true; 30 min later
    // the GSX pushback fired the universal Arrived-fallback through
    // the now-poisoned gate):
    //
    //   1. AGL must be in a sane range — > 50 ft AND < 30000 ft.
    //      53819 ft would have been ignored.
    //   2. `block_off_at` must be set — chronologically the aircraft
    //      can't be airborne before it's even been block-off.
    //      Belt-and-braces against any other future loading glitch
    //      that produces sane-looking but pre-flight airborne values.
    //   3. Conditions must hold for WAS_AIRBORNE_DWELL_TICKS in a
    //      row — single-tick glitches don't poison the flag.
    let airborne_now = !snap.on_ground
        && stats.block_off_at.is_some()
        && {
            let agl = snap.altitude_agl_ft as f32;
            agl > WAS_AIRBORNE_AGL_FT && agl < WAS_AIRBORNE_AGL_MAX_FT
        };
    if airborne_now {
        stats.airborne_dwell_ticks =
            stats.airborne_dwell_ticks.saturating_add(1);
        if stats.airborne_dwell_ticks >= WAS_AIRBORNE_DWELL_TICKS {
            stats.was_airborne = true;
        }
    } else {
        stats.airborne_dwell_ticks = 0;
    }

    // Touchdown ring-buffer is now populated by the dedicated 30 Hz
    // sampler (`spawn_touchdown_sampler`) — the streamer ticks every
    // 5–8 s during Final / Landing, way too sparse to reliably catch
    // the actual touchdown subframe. The sampler shares the same
    // `stats.snapshot_buffer` so the FSM still reads the buffer when
    // it transitions to Landing, just with 30× more samples to pick
    // the worst V/S and peak G from.

    let prev_phase = stats.phase;
    let mut next_phase = prev_phase;
    let was_on_ground = stats.was_on_ground.unwrap_or(snap.on_ground);
    // was_parking_brake is no longer consulted by any phase transition
    // (we removed the brake-release-only Pushback trigger), but the
    // tracking field stays — the activity-log change detector below
    // and any future transition that wants brake-state history will
    // pick it up. Acknowledge to silence the unused-variable warning.
    let _ = stats.was_parking_brake;

    // Capture the departure gate as soon as MSFS gives us a parking
    // name — that means the aircraft is still on the named stand and
    // hasn't pushed back yet. Set once and stay.
    if stats.dep_gate.is_none() {
        if let Some(name) = snap.parking_name.as_ref().filter(|s| !s.is_empty()) {
            let label = match snap.parking_number.as_ref() {
                Some(num) if !num.is_empty() => format!("{name} {num}"),
                _ => name.clone(),
            };
            stats.dep_gate = Some(label);
        }
    }

    // v0.5.11: freeze FSM transitions during sim pause / slew mode.
    //
    // Position recording, distance tracking, fuel tracking, peak-altitude
    // tracking, and the phpVMS heartbeat above all continue running.
    // Only the phase classifier pauses with the sim — otherwise:
    //
    //   * Pause: a frozen snapshot with bank > 15° and |VS| < 200 fpm
    //     would let the wall-clock dwell timer falsely classify the
    //     pilot as "in Holding" after 90 real-world seconds (pilot
    //     making coffee while paused mid-turn = falsely identified as
    //     a holding pattern).
    //   * Slew: teleporting from FL340 → 500 ft AGL produces a
    //     massive lost_altitude spike in one tick → would falsely
    //     fire Climb→Descent / Heli-vertical transitions / mid-air
    //     ground-edges. Slew is a debug/positioning tool, not real
    //     flight motion.
    //
    // When the pilot un-pauses or exits slew, FSM resumes from the
    // current state with current snapshot values. Any pending dwell
    // timers (Holding, Touch-and-Go, Go-Around) keep their last
    // value and continue from there.
    if snap.paused || snap.slew_mode {
        // QS-Runde 1 (Pause-Loch): die Versöhner-Uhr ist Wanduhr — eine
        // Sim-Pause unterhalb der Reload-Gap-Schwelle (bis 150 s bei
        // Cruise-Kadenz!) liefe sonst voll in den Dwell ein, und der erste
        // Resume-Tick feuerte mit VOR-Pause-Evidenz (die Schatten-Engine
        // tickt erst NACH step_flight, ihre eigene Gap-Erkennung greift
        // erst > 5 min). Pause unterbricht die Beobachtung → Uhr neu.
        stats.enroute_divergence_since = None;
        return None;
    }

    // v0.12.1 (Stream A LE2): reload-gap detection. A gap between two
    // processed snapshots well above the expected tick interval means the
    // sim was reloading / repositioning — the first snapshot after the gap
    // carries glitch-prone velocity values (verified: BTX8815 EDVE, an
    // 11 s gap produced a spurious gs 2.6 kt tick with zero actual
    // displacement). The Boarding branch uses this to skip velocity-
    // derived transitions on that one suspect tick.
    let interval_secs = position_interval(prev_phase).as_secs_f64();
    let reload_gap_suspect = stats
        .last_step_at
        .map(|prev| {
            is_reload_gap(
                (now - prev).num_milliseconds() as f64 / 1000.0,
                interval_secs,
            )
        })
        .unwrap_or(false);
    stats.last_step_at = Some(now);

    // v0.13.17: Airborne-Rescue-Sicherheitsnetz. Wenn die FSM in einer
    // Boden-/Pre-Takeoff-Phase festhaengt, das Flugzeug aber nachweislich in
    // der Luft ist (on_ground=false + AGL deutlich ueber Boden), zwingen wir
    // die Phase auf Climb. Hintergrund: bei Addons mit kaputten Engine-
    // SimVars (iniBuilds/Aerosoft A340-600 / MSFS 2024 — GENERAL ENG
    // COMBUSTION konstant 0) feuerte der engines-abhaengige Pushback→TaxiOut
    // →Takeoff-Pfad nie → die Phase blieb den GANZEN Flug auf Pushback →
    // kein Approach/Landing → kein Touchdown/Score, PIREP ohne Landedaten
    // (Live IRM1140/IBE778, 2026-06-03). Der N1-Fallback im Adapter behebt
    // die Ursache; dieses Netz ist die addon-agnostische Garantie, dass NIE
    // wieder ein ganzer Flug an einer stuck-on-ground-Phase scheitert.
    // Greift NICHT im Normalfall: dort ist die Phase laengst Climb, bevor
    // AGL 500 ft ueberschreitet. reload_gap_suspect schuetzt vor einem
    // Slew-/Reload-Glitch-Tick.
    if phase_stuck_on_ground_while_airborne(
        prev_phase,
        snap.on_ground,
        snap.altitude_agl_ft,
        reload_gap_suspect,
    ) {
        tracing::warn!(
            ?prev_phase,
            agl_ft = snap.altitude_agl_ft,
            gs_kt = snap.groundspeed_kt,
            "v0.13.17 airborne-rescue: phase stuck on ground while airborne — forcing Climb"
        );
        // v0.16.9: das Rescue überspringt die Takeoff-Phase — ohne dieses
        // Netz blieben alle Takeoff-Latches leer (BCS8: takeoff_fuel_kg
        // None → OFP-Fuel-Sub-Score unbewertbar). get_or_insert-Semantik,
        // Attitude nur vom Sampler — Details am Helper.
        latch_takeoff_stats_if_missing(&mut stats, snap, now);
        // Commit identisch zum normalen Ende von step_flight (siehe unten).
        if should_reset_holding_pending(prev_phase, FlightPhase::Climb) {
            stats.holding_pending_since = None;
        }
        stats.phase = FlightPhase::Climb;
        stats.transitions.push((now, FlightPhase::Climb));
        stats.was_on_ground = Some(snap.on_ground);
        stats.was_parking_brake = Some(snap.parking_brake);
        return Some(FlightPhase::Climb);
    }

    // v0.16.6: phase-independent approach sampling — see
    // `should_push_approach_sample`. For Approach/Final this is the exact
    // same per-tick push the two arms used to do as their first statement
    // (nothing executes between here and the old call sites); for mis-phased
    // bush flights it keeps the buffer fed on any descending segment below
    // 2000 ft AGL so the sampler-path stability evaluation has data.
    if should_push_approach_sample(
        prev_phase,
        stats.was_airborne,
        snap.on_ground,
        snap.altitude_agl_ft,
        snap.vertical_speed_fpm,
    ) {
        push_approach_sample(&mut stats, snap, now);
    }

    // Match on a local Copy so the rest of the body is free to mutate `stats`.
    match prev_phase {
        FlightPhase::Boarding => {
            // Pushback / departure detection: actual movement is the
            // only reliable trigger. Brake-release alone is NOT enough
            // — pilots routinely release the brake to test controls,
            // prep for taxi, or because GSX flips it during boarding.
            // Without movement, that's still Boarding.
            //
            // Branches:
            //   * Moving with engines OFF → tug is pushing → Pushback
            //   * Moving with engines ON  → straight to TaxiOut
            //                                (powered movement, no push)
            //
            // Both flows MSFS supports get covered: the native Ctrl+P
            // push (often doesn't touch parking brake) and the GSX
            // / hand-flown push (brake released first, then truck).
            // v0.5.11: accept water surface as ground-equivalent for
            // seaplanes. Some sims (MSFS especially) report
            // on_ground=false when an aircraft is sitting on water,
            // because the gear-on-pavement contact model returns
            // false on liquid surfaces. The aircraft is functionally
            // on the surface (AGL ≈ 0, VS ≈ 0) and water-taxi
            // movement is real motion. Without this, seaplanes that
            // boot on water would stay stuck in Boarding forever.
            //
            // The AGL < 5 ft + |VS| < 50 fpm guard ensures we're
            // genuinely at surface level (not low-level approach,
            // which is past Boarding anyway, but defensive).
            let on_surface = snap.on_ground
                || (snap.altitude_agl_ft < 5.0
                    && snap.vertical_speed_fpm.abs() < 50.0);
            // v0.12.1 (Stream A LE1+LE2): de-glitch the Boarding→Pushback
            // / TaxiOut trigger. A single `groundspeed_kt > 0.5` sample is
            // NOT enough — a sim-reload glitch can spike groundspeed while
            // the aircraft sits still (verified BTX8815: post-reload tick
            // gs 2.6 kt, bit-identical lat/lon, parking brake set). We now
            // require BOTH: gs sustained across 2 ticks AND real position
            // displacement (> MIN_BOARDING_MOVEMENT_M) from a reference
            // point. lat/lon can't be faked by a velocity glitch. A
            // reload-suspect tick (LE2) re-baselines the reference and
            // triggers nothing.
            let gs_over_threshold = snap.groundspeed_kt > 0.5;
            let real_movement = if reload_gap_suspect {
                stats.boarding_ref_pos = Some((snap.lat, snap.lon));
                stats.prev_gs_over_threshold = false;
                false
            } else {
                if stats.boarding_ref_pos.is_none() {
                    stats.boarding_ref_pos = Some((snap.lat, snap.lon));
                }
                let moved_m = stats
                    .boarding_ref_pos
                    .map(|(rlat, rlon)| {
                        ::geo::distance_m(rlat, rlon, snap.lat, snap.lon)
                    })
                    .unwrap_or(0.0);
                let moved = boarding_real_movement(
                    on_surface,
                    gs_over_threshold,
                    stats.prev_gs_over_threshold,
                    moved_m,
                );
                stats.prev_gs_over_threshold = gs_over_threshold;
                moved
            };
            if real_movement {
                stats.block_off_at = Some(now);
                // Note: block_fuel_kg is tracked as a running peak
                // (see top of step_flight), not captured here. APU
                // burn during boarding would otherwise eat into the
                // captured value before block-off ever fires.
                // v0.3.0: Loadsheet-Snapshot ins Activity-Log. Einmalig
                // beim Block-off — gibt dem PIREP-Audit-Trail einen
                // klaren "was war geladen, als wir losrollten" Eintrag.
                if !stats.loadsheet_logged_at_blockoff {
                    let block = stats.block_fuel_kg.unwrap_or(snap.fuel_total_kg);
                    let zfw = snap.zfw_kg;
                    let tow = snap.total_weight_kg;
                    let plan_block = stats.planned_block_fuel_kg;
                    // v0.3.0: Loadsheet als kompakte Zeile in den
                    // pending_acars_logs Buffer pushen. Streamer drainet
                    // den nächsten Tick und mirrort in Activity-Log
                    // (Cockpit-UI) UND ACARS-Log (phpVMS-PIREP). Bewusst
                    // einzeilig — der Drain-Pfad unterstützt keine
                    // 2-zeiligen Display-Logs.
                    // v0.3.0: ohne Emoji-Icon — wird in phpVMS-PIREP-
                    // Detailseite als verzerrter Glyph gerendert (Font-
                    // Stack hat dort keinen Emoji-Font).
                    let mut line = String::from("Loadsheet @ Block-off — Block ");
                    line.push_str(&format!("{:.0} kg", block));
                    if let Some(p) = plan_block {
                        let delta = block - p;
                        line.push_str(&format!(" (Plan {:.0} kg, Δ {:+.0})", p, delta));
                    }
                    if let Some(z) = zfw {
                        line.push_str(&format!(" · ZFW {:.0} kg", z));
                    }
                    if let Some(t) = tow {
                        line.push_str(&format!(" · TOW {:.0} kg", t));
                    }
                    stats.pending_acars_logs.push(line);
                    // v0.3.0 Bonus 1: "Über-Tankt"-Hinweis als zweiter
                    // Eintrag, falls IST-Block > Plan-Block + Reserve +
                    // 500 kg Toleranz. Sanft, nicht blockierend.
                    if let (Some(p_block), Some(p_reserve)) =
                        (stats.planned_block_fuel_kg, stats.planned_reserve_kg)
                    {
                        let threshold = p_block + p_reserve + 500.0;
                        if block > threshold {
                            let extra = block - p_block;
                            stats.pending_acars_logs.push(format!(
                                "💡 Über-tankt — Sehr viel Sprit an Bord ({:+.0} kg über Plan + Reserve), höherer Burn unterwegs zu erwarten.",
                                extra
                            ));
                        }
                    }
                    stats.loadsheet_logged_at_blockoff = true;
                }
                // v0.15.13: Pushback wird jetzt AUCH erkannt, wenn die
                // Triebwerke bereits laufen — entscheidend ist RÜCKWÄRTS-
                // Bewegung (Tug schiebt; vbz < 0), nicht der Motorstatus. Vorher
                // sprang ein Pushback mit bereits gestarteten Triebwerken direkt
                // auf TaxiOut. Liefert der Sim kein vbz, bleibt es beim alten
                // engines==0-Kriterium. Block-Off-Zeit ist davon UNBERÜHRT (oben
                // bereits gesetzt) — es geht nur ums Phasen-Label.
                next_phase = if snap.engines_running == 0
                    || moving_backward(snap.velocity_body_z_fps)
                {
                    FlightPhase::Pushback
                } else {
                    FlightPhase::TaxiOut
                };
            }
            // v0.5.10/11: pure-hover / glider direct-launch escape hatch.
            // Aircraft that lift off straight from the gate without
            // ever entering TaxiOut would otherwise stay in Boarding
            // forever. Detect the on_ground edge and skip straight to
            // Takeoff. Covers:
            //   * Helicopters that take off vertically from the gate
            //     (GS = 0, never triggers Boarding → TaxiOut on
            //     groundspeed alone)
            //   * Gliders that get winched from the boarding spot
            //     (engines = 0 throughout)
            //
            // v0.5.11 widening: dropped engines > 0 requirement so
            // glider winch launches fire correctly. AGL > 3 ft +
            // VS > 100 fpm remain as the safety net against sim-
            // glitch on_ground-flicker during boarding.
            // v0.12.1 (Stream A LE2): a reload-suspect tick must not drive
            // the velocity-derived vertical-takeoff hatch either.
            else if !reload_gap_suspect
                && was_on_ground
                && !snap.on_ground
                && snap.altitude_agl_ft > 3.0
                && snap.vertical_speed_fpm > 100.0
            {
                next_phase = FlightPhase::Takeoff;
                latch_takeoff_stats(&mut stats, snap, now);
                tracing::info!(
                    pirep_id = %flight.pirep_id,
                    "vertical takeoff from boarding (helicopter pure-hover) — Boarding → Takeoff"
                );
            }
        }
        FlightPhase::Pushback => {
            // Pushback → TaxiOut Übergang. Echter Ablauf am Gate:
            //   1. Tug schiebt zurück
            //   2. Tug-Crew koppelt ab (PUSHBACK STATE = 3)
            //   3. Pilot steht ~10 s mit gesetzter Bremse, hat Funk,
            //      checkt Freigabe
            //   4. Pilot löst Bremse + Schub → Flugzeug rollt an
            // Erst dann ist es "Taxi". Vorher würde der Tug-Schub bei
            // > 3 kt fälschlicherweise schon TaxiOut triggern.
            //
            // Implementierung als 3-Stufen-Gate:
            //   * `tug_done` = MSFS meldet PUSHBACK STATE == 3 — ABER nur
            //                  gültig wenn vorher mal 0/1/2 gesehen wurde
            //                  (`saw_pushback_state_active`); sonst ist 3
            //                  einfach der Default und kein Pushback war
            //                  je aktiv (GSX-Pushback / manuell)
            //   * `stopped`  = Flugzeug ist nach tug_done zum Stillstand
            //                  gekommen (gs < 0.5 kt). Wir merken uns
            //                  den Zeitpunkt in `pushback_stopped_at`.
            //   * `dwell_ok` = Stillstand mind. 10 s gehalten.
            //   * `powered_taxi` = Triebwerke + gs > 3 kt
            // Nur wenn alles stimmt, springt die Phase auf TaxiOut.
            //
            // Sims ohne PUSHBACK STATE (X-Plane / manche Add-ons) UND
            // Aircraft die den State nie auf 0/1/2 setzen (z.B. Aerosoft
            // A340-600 Pro mit GSX-Pushback) fallen auf die alte
            // Heuristik zurück — sonst würden sie für immer in Pushback
            // stecken bleiben (siehe URO 913 ZWWW→EHBK 2026-05-09:
            // 9 h hängen geblieben weil pushback_state konstant 3 war).
            const PUSHBACK_DWELL_SECS: i64 = 10;
            let engines_running = engines_effectively_running(&stats, snap, now);
            // v0.12.1 (Stream A LE2): gate the velocity-derived TaxiOut
            // signal on `!reload_gap_suspect` — a reload glitch tick must
            // not flip Pushback→TaxiOut any more than it may flip
            // Boarding→Pushback.
            let powered_taxi = powered_taxi_move(
                reload_gap_suspect,
                snap.on_ground,
                engines_running,
                snap.groundspeed_kt,
                snap.velocity_body_z_fps,
            );
            // tug_done greift nur wenn der State MAL aktiv (≠3) war
            let tug_done = snap.pushback_state == Some(3)
                && stats.saw_pushback_state_active;
            let no_tug_ever = snap.pushback_state.is_none()
                || (snap.pushback_state == Some(3) && !stats.saw_pushback_state_active);

            if tug_done {
                // Stillstand nach Tug-Ab: Timestamp setzen (einmal).
                if snap.groundspeed_kt < 0.5 && stats.pushback_stopped_at.is_none() {
                    stats.pushback_stopped_at = Some(now);
                }
                let dwell_ok = stats
                    .pushback_stopped_at
                    .map(|t| (now - t).num_seconds() >= PUSHBACK_DWELL_SECS)
                    .unwrap_or(false);
                if dwell_ok && powered_taxi {
                    stats.pushback_stopped_at = None;
                    next_phase = FlightPhase::TaxiOut;
                }
            } else if no_tug_ever && powered_taxi {
                // Kein PUSHBACK STATE vom Sim verfügbar (X-Plane) ODER
                // der State war nie != 3 (GSX-Pushback / manuell).
                // Alte Fallback-Logik: bewegt sich + Triebwerke an = TaxiOut.
                next_phase = FlightPhase::TaxiOut;
            }
        }
        FlightPhase::TaxiOut => {
            // Threshold lowered from 40 → 30 kt so GA aircraft (Cessna,
            // Diamond) which rotate around 50 kt enter TakeoffRoll well
            // before liftoff. Plus the engine-running guard means a
            // pilot dragging the parking brake at high taxi speed
            // doesn't accidentally trigger TakeoffRoll without throttle.
            if snap.on_ground
                && snap.groundspeed_kt > 30.0
                && engines_effectively_running(&stats, snap, now)
            {
                next_phase = FlightPhase::TakeoffRoll;
            }
            // v0.5.10/11: helicopter / VTOL / glider / seaplane
            // escape hatch.
            //
            // Conventional aircraft trigger TakeoffRoll via GS > 30 kt,
            // then Takeoff via the on_ground edge. Several classes of
            // aircraft skip TakeoffRoll entirely:
            //   * Helicopters / VTOL: take off vertically (GS stays
            //     below 30 kt the whole time on the ground)
            //   * Gliders on aerotow: GS > 30 kt but engines = 0
            //     (the glider's own engine is off, the towplane pulls)
            //   * Gliders on winch: very fast vertical climb, engines = 0
            //   * Seaplanes that report on_ground=true on water:
            //     same path as conventional but engines might briefly
            //     show 0 in some sims
            //
            // For all of these we want: when in TaxiOut and the
            // on_ground edge fires (ground → air), promote to Takeoff
            // directly. The AGL > 5 ft + VS > 100 fpm guards confirm
            // a REAL liftoff (not sim-glitch on_ground-flicker on
            // bumpy runways / PMDG texture quirks).
            //
            // v0.5.11 widening: dropped the engines > 0 requirement
            // so glider tow / winch launches also fire correctly.
            // The AGL/VS guards remain as the false-positive safety
            // net (a single-frame on_ground-flicker can't satisfy
            // both AGL > 5 ft AND VS > 100 fpm).
            else if (was_on_ground
                && !snap.on_ground
                && snap.altitude_agl_ft > 5.0
                && snap.vertical_speed_fpm > 100.0)
                // v0.5.11: seaplane catchall — sims that report
                // on_ground=false on water never produce the ground
                // edge above. Once the seaplane lifts off the water
                // (AGL > 50 ft + VS > 100 fpm + actively airborne),
                // fire Takeoff regardless of edge. AGL > 50 is a
                // strict guard against sim-spawn-at-altitude
                // false-fires; a real water takeoff easily exceeds
                // 50 ft AGL within seconds of breaking the surface.
                || (!snap.on_ground
                    && snap.altitude_agl_ft > 50.0
                    && snap.vertical_speed_fpm > 100.0
                    && !snap.slew_mode
                    && !snap.paused)
            {
                next_phase = FlightPhase::Takeoff;
                latch_takeoff_stats(&mut stats, snap, now);
                tracing::info!(
                    pirep_id = %flight.pirep_id,
                    "non-conventional takeoff detected (heli / glider / seaplane) — TaxiOut → Takeoff"
                );
            }
        }
        FlightPhase::TakeoffRoll => {
            // PMDG capture (Phase 5.6): TakeoffRoll is the right
            // moment to record V-speeds + planned TO-flaps + the
            // takeoff-config-warning-was-active flag, because the
            // pilot completed PERF-INIT before this point. We
            // capture continuously through the roll (rather than
            // once at entry) because V-speeds may not have been
            // entered until the very last moment.
            if let Some(p) = &snap.pmdg {
                if stats.pmdg_takeoff_flaps_planned.is_none() {
                    stats.pmdg_takeoff_flaps_planned = p.fmc_takeoff_flaps_deg;
                }
                if let (Some(v1), Some(vr), Some(v2)) =
                    (p.fmc_v1_kt, p.fmc_vr_kt, p.fmc_v2_kt)
                {
                    if stats.pmdg_v_speeds_takeoff.is_none() {
                        stats.pmdg_v_speeds_takeoff = Some((v1, vr, v2));
                    }
                }
                if p.takeoff_config_warning {
                    stats.pmdg_takeoff_config_warning_seen = true;
                }
                if stats.pmdg_fmc_flight_number.is_none()
                    && !p.fmc_flight_number.is_empty()
                {
                    stats.pmdg_fmc_flight_number =
                        Some(p.fmc_flight_number.clone());
                }
            }

            if was_on_ground && !snap.on_ground {
                next_phase = FlightPhase::Takeoff;
                latch_takeoff_stats(&mut stats, snap, now);
            } else {
                // Rückkante (fehlte bisher — der Arm ging nur vorwärts):
                // nachhaltig langsam + am Boden → zurück zu TaxiOut. Behebt
                // TAKEOFF_ROLL_STUCK (Backtrack trippt TakeoffRoll, dann
                // Ausrichten/Warten). Siehe takeoff_roll_demote.
                let (demote, slow_since) = takeoff_roll_demote(
                    snap.on_ground,
                    snap.groundspeed_kt,
                    stats.takeoff_roll_slow_since,
                    now,
                );
                stats.takeoff_roll_slow_since = slow_since;
                if let Some(target) = demote {
                    next_phase = target;
                }
            }
        }
        FlightPhase::Takeoff => {
            // Helicopters/VTOL routinely fly an entire leg below the 500 ft
            // fixed-wing Climb gate (pad-to-pad hops, survey, EMS), which
            // would strand them in Takeoff — a phase EXCLUDED from
            // `is_flight_phase`, so the touchdown sampler never captures their
            // landing. A low gate moves a rotorcraft into Climb (a flight
            // phase) once it is clearly airborne and translating; the sampler
            // + the category-aware validator then capture the set-down. Fixed-
            // wing keeps 500 ft unchanged.
            let climb_gate_ft = takeoff_climb_gate_ft(category);
            if snap.altitude_agl_ft > climb_gate_ft {
                next_phase = FlightPhase::Climb;
                // v0.5.9: reset climb peak so the new climb segment
                // starts fresh (handles re-takeoffs after a divert).
                stats.climb_peak_msl = None;
            }
        }
        FlightPhase::Climb => {
            // Track the highest altitude we've seen while climbing —
            // used as the reference point for "did we really start
            // descending, or is this just a single VS spike?".
            let climb_peak = stats.climb_peak_msl.unwrap_or(0.0);
            if (snap.altitude_msl_ft as f32) > climb_peak {
                stats.climb_peak_msl = Some(snap.altitude_msl_ft as f32);
            }

            // v0.5.9: Climb → Descent now requires BOTH:
            //   * Sustained sink rate (< −500 fpm)
            //   * Altitude actually lost from climb peak (> 200 ft)
            //
            // Pilot Michael 2026-05-07 EGPH→HEGN: a single -742 fpm
            // sample (level-off blip during climb to FL340) flipped
            // the FSM to Descent at FL050. Aircraft kept climbing to
            // FL340 and cruised, but FSM was stuck in Descent for the
            // next 50+ minutes because there's no Descent → Climb
            // transition. Without the altitude-lost guard a single
            // turbulence spike or autopilot trim correction wrecks
            // the rest of the timeline.
            //
            // 200 ft threshold filters typical level-off oscillation
            // (pitch-corrections + turbulence rarely exceed this) but
            // is well below any real top-of-descent (which loses
            // thousands of feet quickly).
            let lost_from_peak =
                stats.climb_peak_msl.unwrap_or(0.0) - snap.altitude_msl_ft as f32;

            // Climb → Descent triggers in any of three scenarios:
            //   (a) Standard TOD: sustained sink (-500 fpm) AND
            //       altitude actually lost (>200 ft) — Airliners.
            //   (b) v0.5.10: GA / Heli low-altitude approach —
            //       gentle descent (-100 fpm) AND we're below
            //       3000 ft AGL AND lost >500 ft from climb peak.
            //       Catches GA flights that cruise at 2-3000 ft and
            //       descend gently at 300-500 fpm to a pattern
            //       altitude landing.
            //   (c) v0.5.10: anything significantly below climb peak
            //       AND below 2000 ft AGL — robust catchall for
            //       low-altitude operations where neither (a) nor
            //       (b) clearly fires (helicopter ops, bush flying).
            // v0.7.17 (B-010): Descent-Transition mit Dwell + Light-GA-
            // Schwellen. Siehe check_descent_transition() Doc.
            if let Some(p) = check_descent_transition(&mut stats, snap, now, lost_from_peak) {
                next_phase = p;
            } else if snap.vertical_speed_fpm.abs() < 200.0
                && snap.altitude_agl_ft > 5000.0
            {
                next_phase = FlightPhase::Cruise;
            }
            // v0.5.11: removed low-altitude Cruise alternative path.
            // The pre-release v0.5.10 attempt to detect Pattern /
            // GA cruise via "vs.abs() < 100 + lost_from_peak < 100"
            // was unsafe — during ACTIVE climb, lost_from_peak is
            // always ~0 (peak updates each tick). A single tick with
            // vs ≈ 50 fpm (autopilot mode switch, trim, turbulence)
            // would falsely trigger Cruise. GA aircraft just stay in
            // Climb until they descend; our enhanced Climb → Descent
            // triggers above handle the transition robustly. Cruise
            // is reserved for high-altitude flights that genuinely
            // need the 30 s streamer cadence.
        }
        FlightPhase::Cruise => {
            // Track the highest altitude we've seen at this cruise
            // — used as the reference point for "did we really
            // descend, or is this just an ATC step-down?".
            let peak = stats.cruise_peak_msl.unwrap_or(0.0);
            if (snap.altitude_msl_ft as f32) > peak {
                stats.cruise_peak_msl = Some(snap.altitude_msl_ft as f32);
            }

            // Cruise → Descent triggers when sustained sink (-500 fpm,
            // filters trim/turbulence noise) is observed AND one of:
            //
            //   (a) Lost > 5000 ft from the cruise peak — typical
            //       airline TOD. ATC step-downs (FL380 → FL360 = 2000 ft)
            //       stay in Cruise and don't ping-pong the timeline.
            //
            //   (b) AGL < 3000 ft — low-altitude pattern / GA flight.
            //       v0.5.4 hotfix: pilot reported a short MWCR → MWCR
            //       test at 5000-ft pattern altitude that never left
            //       Cruise. The FSM expected a 5000-ft drop from the
            //       cruise peak, but the cruise peak was barely above
            //       5000 ft AGL, so the drop maxed out at 4973 ft —
            //       just below threshold. Universal Arrived fallback
            //       then jumped straight Cruise → Arrived, skipping
            //       Final → Landing entirely (= no touchdown captured).
            //       AGL < 3000 ft + sinking is unambiguous approach
            //       territory regardless of cruise altitude; allow
            //       the transition.
            let lost_alt =
                stats.cruise_peak_msl.unwrap_or(0.0) - snap.altitude_msl_ft as f32;
            let sinking = snap.vertical_speed_fpm < -500.0;
            let big_drop = lost_alt > 5000.0;
            let close_to_ground = snap.altitude_agl_ft < 3000.0;
            if sinking && (big_drop || close_to_ground) {
                next_phase = FlightPhase::Descent;
            } else if check_holding_entry(&mut stats, snap, now) {
                stats.previous_phase_before_holding = Some(FlightPhase::Cruise);
                next_phase = FlightPhase::Holding;
            }
        }
        FlightPhase::Holding => {
            // v0.5.11: detect holding pattern exit. Three exit modes:
            //
            //   1. Active descent (vs < -300 fpm + AGL < 5000 ft) —
            //      ATC has cleared us out of the hold for the
            //      approach. Jump directly to Approach.
            //   2. Low-altitude descent at any rate — going down
            //      toward the runway, definitely not holding anymore.
            //   3. Sustained straight-and-level (bank < 5° for
            //      HOLDING_EXIT_DWELL_SECS) — resumed normal flight.
            //      Restore the phase we came from (Cruise or Approach).
            let descent_resumed = snap.vertical_speed_fpm < -300.0
                && snap.altitude_agl_ft < 5000.0;
            if descent_resumed {
                next_phase = FlightPhase::Approach;
                stats.holding_pending_since = None;
                stats.holding_exit_pending_since = None;
                stats.previous_phase_before_holding = None;
                // Reset approach VS-min tracker (v0.5.5) for fresh
                // approach measurement post-hold.
                stats.low_agl_vs_min_fpm = None;
                stats.last_low_agl_vs_fpm = None;
            } else if snap.bank_deg.abs() < 5.0 {
                let exit = stats.holding_exit_pending_since.get_or_insert(now);
                if (now - *exit).num_seconds() >= HOLDING_EXIT_DWELL_SECS {
                    let prev = stats
                        .previous_phase_before_holding
                        .unwrap_or(FlightPhase::Cruise);
                    next_phase = prev;
                    stats.holding_pending_since = None;
                    stats.holding_exit_pending_since = None;
                    stats.previous_phase_before_holding = None;
                }
            } else {
                stats.holding_exit_pending_since = None;
            }
        }
        FlightPhase::Descent => {
            // Approach starts when we're both low *and* still
            // descending. Without the V/S guard a brief AGL dip
            // during a mountain overflight (Alps, Rockies) wrongly
            // triggered Approach mid-cruise. The aircraft is on
            // approach when it's actually heading down toward the
            // destination, not when it happened to skim a peak.
            if snap.altitude_agl_ft < 5000.0 && snap.vertical_speed_fpm < 0.0 {
                next_phase = FlightPhase::Approach;
                // v0.5.5: reset running peak-descent tracker on Approach
                // entry. Stays alive across Approach → Final transitions
                // (we keep tracking through final). Only resets here so a
                // go-around (which routes Final → Climb → Approach again)
                // gets a clean per-attempt picture.
                stats.low_agl_vs_min_fpm = None;
                stats.last_low_agl_vs_fpm = None;
            } else if snap.vertical_speed_fpm.abs() < 200.0
                && snap.altitude_agl_ft > 5000.0
            {
                // v0.7.17 (B-003): Descent → Cruise Recovery. Wenn der
                // Sink stoppt UND wir wieder hoch genug sind, war das
                // wahrscheinlich ein ATC-Step-Down oder ein V/S-Spike
                // (Pause/Resume-Race) der die FSM faelschlich nach
                // Descent gekippt hat. Vorher gab es nur Descent →
                // Approach — Aircraft blieb fuer immer als „Descent"
                // gemeldet, auch wenn Pilot wieder cruiste. Tester-
                // Report ICE 529 EDDB→EVRA: FL330 Cruise, FMA ALT CRZ,
                // Live-Map zeigte „Descent" + V/S -11 fpm. Selber
                // Schwellwert wie Climb → Cruise (200 fpm + AGL > 5000).
                next_phase = FlightPhase::Cruise;
            }
        }
        FlightPhase::Approach => {
            // Approach-stability samples (V/S + bank stddev → "Approach
            // Stability" sub-score) are pushed by the central
            // phase-independent call right before this match (v0.16.6) —
            // same per-tick cadence as the old arm-local call here.
            // Track lowest AGL during approach for go-around detection.
            update_lowest_approach_agl(&mut stats, snap);

            // PMDG capture (Phase 5.6): on Approach the pilot has
            // typically dialed in landing flaps + VREF in the FMC,
            // and chosen autobrake. Capture continuously through
            // approach so a last-minute change still gets recorded.
            if let Some(p) = &snap.pmdg {
                if stats.pmdg_landing_flaps_planned.is_none() {
                    stats.pmdg_landing_flaps_planned = p.fmc_landing_flaps_deg;
                }
                if stats.pmdg_vref_at_landing.is_none() {
                    stats.pmdg_vref_at_landing = p.fmc_vref_kt;
                }
                // Autobrake: keep capturing until touchdown so we
                // record the LAST setting before landing.
                if !p.autobrake_label.is_empty() && p.autobrake_label != "?" {
                    stats.pmdg_autobrake_at_landing =
                        Some(p.autobrake_label.clone());
                }
            }

            // Helicopters arrest a descent into a hover before set-down
            // (collective cushion), which the fixed-wing detector reads as a
            // climb-away go-around and reverts the phase to Climb. Suppress it
            // for rotorcraft so a normal confined-area / pad approach is not
            // falsely logged as a missed approach.
            let ga_phase = if category.is_rotorcraft() {
                None
            } else {
                check_go_around(&mut stats, snap, now)
            };
            if let Some(ga_phase) = ga_phase {
                next_phase = ga_phase;
            } else if snap.altitude_agl_ft < 700.0 {
                // 1500 ft AGL was too eager — pilots reported a 3 min
                // "Final" segment because most aircraft intercept the
                // ILS at that altitude and still have several miles to
                // run. Real-world Final starts ~700 ft AGL (FAF crossed
                // for non-precision, decision height area for ILS).
                next_phase = FlightPhase::Final;
            } else if check_holding_entry(&mut stats, snap, now) {
                // v0.5.11: Approach-level holding (low-altitude hold).
                // VATSIM ATC frequently issues "hold over WAYPOINT"
                // during inbound sequencing — aircraft circles at
                // ~5000 ft for 5-15 minutes. Without this we'd just
                // see endless Approach phase with no signal.
                stats.previous_phase_before_holding = Some(FlightPhase::Approach);
                next_phase = FlightPhase::Holding;
            }
        }
        FlightPhase::Final => {
            // Approach-stability sampling continues through the final
            // segment too (lots of pilots stabilise late; measuring only
            // Approach would underweight the truly important last 700 ft
            // AGL) — handled by the central phase-independent call right
            // before this match (v0.16.6), same cadence as before.
            update_lowest_approach_agl(&mut stats, snap);
            // Rotorcraft hover-arrest is not a go-around (see Approach arm) —
            // suppress so a heli that stabilises into a hover before set-down
            // stays in Final and its touchdown is captured by Path B.
            let ga_phase = if category.is_rotorcraft() {
                None
            } else {
                check_go_around(&mut stats, snap, now)
            };
            if let Some(ga_phase) = ga_phase {
                next_phase = ga_phase;
            }
            // Approach runway: snapshot whatever ATC currently has us
            // cleared for. May still change before touchdown, so we
            // refresh until wheels are down.
            if let Some(rw) = snap.selected_runway.as_ref().filter(|s| !s.is_empty()) {
                stats.approach_runway = Some(rw.clone());
            }
            if !was_on_ground && snap.on_ground {
                next_phase = FlightPhase::Landing;

                // CRITICAL: anchor the window around the ACTUAL
                // touchdown moment, not `now`. The position-streamer
                // ticks every 5 s during Landing phase, so the on-
                // ground edge is detected up to 5 s after the wheels
                // actually touched. The 30 Hz touchdown-sampler has
                // been faithfully recording samples in the meantime,
                // so the first on-ground sample in the buffer IS the
                // touchdown moment. Using `now` instead would give a
                // window over the rollout, where V/S is near zero —
                // exactly the "-48 fpm" bug.
                let actual_td_at = stats
                    .snapshot_buffer
                    .iter()
                    .find(|s| s.on_ground)
                    .map(|s| s.at)
                    .unwrap_or(now);
                stats.landing_at = Some(actual_td_at);

                // Snapshot the buffer entry AT the actual touchdown
                // moment. Used below for IAS / pitch / heading
                // capture so they reflect the real TD-instant values,
                // not the post-rollout numbers that `snap` carries
                // (current snap is up to 5 s late on the streamer
                // tick, time enough for a typical airliner to bleed
                // ~17 kt IAS and derotate the nose to negative pitch).
                // Live bug 2026-05-03: pilot at 135 kt touchdown saw
                // "IAS bei TD: 118 kt" + "pitch -4.9°" because we
                // were reading post-derotation values.
                let td_buf_sample = touchdown_buffer_sample(&stats);

                // v0.5.12: SIM-AWARE touchdown capture — different
                // priority chains for MSFS vs X-Plane.
                //
                // The earlier v0.5.11 unified chain (AGL-Δ primary
                // for both sims) was a scope error — MSFS already
                // had a perfect source via the `PLANE TOUCHDOWN
                // NORMAL VELOCITY` SimVar (frame-accurate, latched
                // at the exact contact moment by the sim itself).
                // Routing MSFS through the AGL estimator with strict
                // AGL ≤ 5 guards rejected it (MSFS reports AGL ≈ 14 ft
                // even when on_ground=true — sim quirk), the chain
                // fell through to the X-Plane-style sampler which
                // captured a transient -1173 fpm spike from MSFS's
                // gear-contact rebound oscillation. Pilot's
                // 2026-05-07 LH595 DNAA→EDDF report: actual rate
                // ~-419/-560 fpm (Volanta + LHA + MSFS-latched),
                // we reported -1173. Bug class: cross-contamination
                // from a refactor that should've been X-Plane only.
                //
                // Clean architecture v0.5.12:
                //
                //   MSFS:
                //     1. snap.touchdown_vs_fpm (PRIMARY — latched
                //        SimVar, frame-accurate, gold standard)
                //     2. AGL-Δ estimator (sanity fallback if SimVar
                //        wasn't populated for some reason)
                //     3. Buffer scan
                //
                //   X-Plane:
                //     1. AGL-Δ estimator (PRIMARY — LandingRate-1
                //        algorithm, Volanta uses the same)
                //     2. sampler_touchdown_vs_fpm (FALLBACK — uses
                //        fnrml_gear edge from v0.4.4 sampler)
                //     3. Buffer scan
                //     4. low_agl_vs_min_fpm
                //
                // Both paths apply negative_only filtering.
                if let Some(sampler_at) = stats.sampler_touchdown_at {
                    stats.landing_at = Some(sampler_at);
                }
                let actual_td_at = stats.landing_at.unwrap_or(actual_td_at);

                let is_msfs = matches!(
                    snap.simulator,
                    Simulator::Msfs2020 | Simulator::Msfs2024
                );
                let is_xplane = matches!(
                    snap.simulator,
                    Simulator::XPlane11 | Simulator::XPlane12
                );

                // v0.5.13: AGL-derivative estimators run once.
                //
                //   * `agl_estimate_xp` — Lua-style 30-sample window
                //     (LandingRate-1 algorithm, Volanta-aligned).
                //     Used as PRIMARY for X-Plane.
                //   * `agl_estimate_msfs` — original time-tier window
                //     (multi-tier 750ms/1s/1.5s/2s/3s/12s with
                //     min-sample guards). Used as FALLBACK for MSFS
                //     when the latched SimVar is null. v0.5.12-validated
                //     against real pilot flights — leave alone.
                //
                // Both have identical AGL guards (TD ≤ 5 ft / on_ground
                // = true, window-start ≤ 250 ft) — they differ only
                // in WINDOW SIZING strategy. The Lua method adapts
                // to sample density automatically; the time-tier
                // method walks fixed time windows.
                let agl_estimate_xp =
                    estimate_xplane_touchdown_vs_lua_style(
                        &stats.snapshot_buffer,
                        actual_td_at,
                    );
                let agl_estimate_msfs = estimate_xplane_touchdown_vs_from_agl(
                    &stats.snapshot_buffer,
                    actual_td_at,
                );

                // Tight buffer-window scan (used by both paths as a
                // fallback — AGL ≤ 250 ft filter prevents pre-flare
                // contamination).
                let half_window =
                    chrono::Duration::milliseconds(TOUCHDOWN_VS_WINDOW_MS / 2);
                let vs_window_start = actual_td_at - half_window;
                let vs_window_end = actual_td_at + half_window;
                let buffered_vs_min_raw: f32 = stats
                    .snapshot_buffer
                    .iter()
                    .filter(|s| s.at >= vs_window_start && s.at <= vs_window_end)
                    .filter(|s| s.agl_ft <= TD_AGL_MAX_AT_WINDOW_START_FT)
                    .map(|s| s.vs_fpm)
                    .fold(f32::INFINITY, f32::min);
                let buffered_vs_min = if buffered_vs_min_raw.is_finite() {
                    Some(buffered_vs_min_raw)
                } else {
                    None
                };

                let touchdown_vs = if is_msfs {
                    // MSFS: priority chain (v0.5.12 — validated against
                    // 11 real pilot flights, Pete + Michael):
                    //   1. Latched SimVar (PLANE TOUCHDOWN NORMAL VELOCITY)
                    //   2. Time-tier AGL-Δ (UNCHANGED, GEES-aligned)
                    //   3. Buffered VS-min — last resort
                    //
                    // EXPLICITLY NOT used for MSFS:
                    //   * sampler_touchdown_vs_fpm — gear-contact
                    //     rebound spike contamination
                    //   * low_agl_vs_min_fpm — same risk
                    //   * Lua-style 30-sample estimator — that's
                    //     X-Plane only by design
                    let result = negative_only(snap.touchdown_vs_fpm)
                        .or_else(|| agl_estimate_msfs.map(|e| e.fpm))
                        .or_else(|| negative_only(buffered_vs_min))
                        .unwrap_or(0.0);
                    tracing::info!(
                        sim = "msfs",
                        latched = ?snap.touchdown_vs_fpm,
                        agl_estimate = ?agl_estimate_msfs.map(|e| e.fpm),
                        buffer_min = ?buffered_vs_min,
                        chosen = result,
                        "touchdown VS captured (MSFS path — time-tier estimator + sampler bypassed)"
                    );
                    result
                } else if is_xplane {
                    // X-Plane (v0.5.13): Lua-style 30-sample AGL-Δ is
                    // PRIMARY (LandingRate-1 algorithm, Volanta-aligned).
                    // Adapts to sim framerate naturally — high-fps gets
                    // tight 0.5 s windows, low-fps gets wider 2-3 s
                    // windows. No fixed time-tier brittleness.
                    //
                    // v0.5.35: Sanity-Check + Sparse-Sampling-Fallback.
                    // Bug-Report 2026-05-08 (gsg/2 GA-Flug, Cessna 152):
                    // bei sehr niedriger DataRef-Rate spannt das 30-Sample-
                    // Fenster den ganzen Approach (10s+ window) statt der
                    // Flare → estimator gibt geglätteten Mittelwert (-33 fpm)
                    // statt echter TD-V/S (-360 fpm). Loesung:
                    //   1. Estimator-Window > 3000ms = unplausibel (verwerfen)
                    //   2. last_low_agl_vs_fpm (letztes airborne Sample
                    //      <500ft AGL) als robuster Fallback — der wird
                    //      pro Tick upgedated und ueberlebt sparse Sampling
                    //   3. Wenn beide vorhanden: wähle den deeperen
                    //      (= numerisch kleineren) — schuetzt vor
                    //      Window-Spread-Artefakten
                    let xp_est_plausible = agl_estimate_xp
                        .filter(|e| e.window_ms < 3000)
                        .map(|e| e.fpm);
                    let last_low_recent = stats
                        .last_low_agl_vs_fpm
                        .filter(|(_, ts)| (now - *ts).num_seconds() <= 15);
                    let result = match (xp_est_plausible, last_low_recent) {
                        (Some(est), Some((last, _))) => est.min(last),
                        (Some(est), None) => est,
                        (None, Some((last, _))) => last,
                        (None, None) => negative_only(stats.sampler_touchdown_vs_fpm)
                            .or_else(|| negative_only(buffered_vs_min))
                            .or_else(|| negative_only(stats.low_agl_vs_min_fpm))
                            .unwrap_or(0.0),
                    };
                    if let Some(ref est) = agl_estimate_xp {
                        tracing::info!(
                            sim = "xplane",
                            agl_fpm = est.fpm,
                            source = est.source,
                            window_ms = est.window_ms,
                            sample_count = est.sample_count,
                            chosen = result,
                            "touchdown VS captured (X-Plane Lua-style 30-sample primary)"
                        );
                    } else {
                        tracing::info!(
                            sim = "xplane",
                            sampler_vs = ?stats.sampler_touchdown_vs_fpm,
                            buffer_min = ?buffered_vs_min,
                            low_agl_min = ?stats.low_agl_vs_min_fpm,
                            chosen = result,
                            "touchdown VS captured (X-Plane path, AGL-Δ unavailable)"
                        );
                    }
                    result
                } else {
                    // Unknown sim — generic fallback, preserves prior
                    // behaviour for edge cases (Other/sim_set_kind=Off).
                    // Uses time-tier MSFS-side estimator since it's
                    // the more conservative of the two.
                    negative_only(snap.touchdown_vs_fpm)
                        .or_else(|| agl_estimate_msfs.map(|e| e.fpm))
                        .or_else(|| negative_only(stats.sampler_touchdown_vs_fpm))
                        .or_else(|| negative_only(buffered_vs_min))
                        .unwrap_or(0.0)
                };

                if touchdown_vs == 0.0 {
                    tracing::warn!(
                        sim = ?snap.simulator,
                        sampler_vs = ?stats.sampler_touchdown_vs_fpm,
                        latched = ?snap.touchdown_vs_fpm,
                        buffer_min = ?buffered_vs_min,
                        low_agl_min = ?stats.low_agl_vs_min_fpm,
                        "touchdown VS — all sources failed or were positive, defaulting to 0"
                    );
                }

                // ─── v0.5.23 Touchdown-Forensik-Capture ──────────────
                //
                // Spiegel der Priority-Chain oben — bestimmt welcher Pfad
                // den finalen `touchdown_vs` lieferte und merkt sich die
                // Werte ALLER Pfade zum Vergleich. Der Streamer baut
                // damit den TouchdownPayload und schickt es an aeroacars-
                // live damit der VA-Owner Algorithmen-Disagreements
                // forensisch auswerten kann.
                let vs_source: &'static str = if is_msfs {
                    if negative_only(snap.touchdown_vs_fpm).is_some() {
                        "msfs_simvar_latched"
                    } else if agl_estimate_msfs.is_some() {
                        "agl_estimate_msfs"
                    } else if negative_only(buffered_vs_min).is_some() {
                        "buffer_min"
                    } else {
                        "fallback_zero"
                    }
                } else if is_xplane {
                    // v0.5.35: Mirror der neuen Priority-Chain.
                    // - "agl_estimate_xp_plausible" = Estimator-Window <3s
                    // - "last_low_agl_vs" = letztes airborne Sample (sparse-Sampling-Rettung)
                    // - "agl_estimate_xp_implausible" = Estimator-Window ≥3s, also wahrscheinlich Spread-Artifact (= reported als low confidence)
                    let est_plausible = agl_estimate_xp.map(|e| e.window_ms < 3000).unwrap_or(false);
                    let last_low_recent = stats.last_low_agl_vs_fpm
                        .map(|(_, ts)| (now - ts).num_seconds() <= 15)
                        .unwrap_or(false);
                    if est_plausible && last_low_recent {
                        // Beide vorhanden — wir haben den deeperen genommen
                        "agl_estimate_xp_or_last_low"
                    } else if est_plausible {
                        "agl_estimate_xp"
                    } else if last_low_recent {
                        "last_low_agl_vs"
                    } else if agl_estimate_xp.is_some() {
                        "agl_estimate_xp_implausible_window"
                    } else if negative_only(stats.sampler_touchdown_vs_fpm).is_some() {
                        "sampler_gear_force"
                    } else if negative_only(buffered_vs_min).is_some() {
                        "buffer_min"
                    } else if negative_only(stats.low_agl_vs_min_fpm).is_some() {
                        "low_agl_vs_min"
                    } else {
                        "fallback_zero"
                    }
                } else {
                    "other_fallback"
                };
                stats.landing_simulator = Some(if is_msfs {
                    "msfs"
                } else if is_xplane {
                    "xplane"
                } else {
                    "other"
                });
                stats.landing_vs_estimate_xp_fpm =
                    agl_estimate_xp.map(|e| e.fpm.round() as i32);
                stats.landing_vs_estimate_msfs_fpm =
                    agl_estimate_msfs.map(|e| e.fpm.round() as i32);
                stats.landing_vs_source = Some(vs_source);
                // gear_force_peak_n: nur X-Plane liefert den Wert ueber
                // den Sampler-Pfad. snap.gear_normal_force_n im Touchdown-
                // Frame ist die direkteste Quelle.
                stats.landing_gear_force_peak_n = if is_xplane {
                    snap.gear_normal_force_n
                } else {
                    None
                };
                // window_ms + sample_count: nur fuer den Pfad der wirklich
                // gewann (= Lua bei XP, Time-Tier bei MSFS). Fallback-Pfade
                // haben keine Window-Metrik.
                if vs_source == "agl_estimate_xp" {
                    if let Some(est) = agl_estimate_xp {
                        stats.landing_estimate_window_ms = Some(est.window_ms as i32);
                        stats.landing_estimate_sample_count = Some(est.sample_count as u32);
                    }
                } else if vs_source == "agl_estimate_msfs" {
                    if let Some(est) = agl_estimate_msfs {
                        stats.landing_estimate_window_ms = Some(est.window_ms as i32);
                        stats.landing_estimate_sample_count = Some(est.sample_count as u32);
                    }
                }

                // v0.7.1 P2.2-D: atomic write via finalize_landing_rate.
                // confidence ist hier nicht direkt vom touchdown_v2-Cascade
                // verfuegbar (wir sind im legacy-streamer-Pfad), daher None.
                // Wenn der touchdown_v2-Pfad in Site 1 (lib.rs ~9362) schon
                // einen Wert mit Confidence gesetzt hat und der Streamer-Tick
                // hier nochmal feuert, wird Confidence uebergeschrieben — das
                // ist OK, weil der Streamer-Tick die "endgueltige" Quelle
                // gegenueber dem Edge-Wert ist (Smoothed-Fallback).
                finalize_landing_rate(
                    &mut stats,
                    touchdown_vs,
                    None,
                    Some(vs_source),
                );

                // G capture: prefer sampler-side (v0.4.4) wenn verfügbar.
                // Sonst peak G from full buffer (5 s of pre-touchdown
                // history). Subsequent ticks in the Landing arm refine
                // this further until TOUCHDOWN_G_WINDOW_MS elapses.
                let touchdown_g = if let Some(sampler_g) = stats.sampler_touchdown_g_force {
                    sampler_g
                } else {
                    let buffered_g_peak: f32 = stats
                        .snapshot_buffer
                        .iter()
                        .map(|s| s.g_force)
                        .fold(0.0, f32::max);
                    buffered_g_peak.max(snap.g_force)
                };
                stats.landing_g_force = Some(touchdown_g);
                stats.landing_peak_g_force = Some(touchdown_g);

                // Touchdown metadata (IAS/pitch/bank/heading/speed/GS/fuel,
                // TD coords, profile, sideslip, wind) + runway correlation —
                // extracted to phase-independent helpers (v0.15.24) so the
                // validated sampler touchdown can stamp them too when the
                // FSM never reaches Landing (bush hops, GSG312). This call
                // is behaviour-identical to the pre-extraction inline code;
                // it deliberately OVERWRITES any earlier sampler-path stamp
                // with the FSM-tick values, exactly as before.
                stamp_touchdown_metadata(
                    &mut stats,
                    snap,
                    actual_td_at,
                    td_buf_sample.as_ref(),
                );
                correlate_touchdown_runway(
                    &mut stats,
                    snap,
                    flight,
                    td_buf_sample.as_ref(),
                );

                // Reset bounce state for the new analyzer window.
                stats.bounce_armed_above_threshold = false;
                stats.bounce_count = 0;

                // ---- Landing Analyzer (Stage 1) ----

                // Compute approach-stability stddev from the buffer
                // accumulated during Approach + Final. None when we
                // have fewer than 3 samples (resumed flight,
                // ultra-fast approach).
                //
                // v0.5.25: PLUS Stable-Approach-Gate-konforme v2-
                // Auswertung (1000-ft-AGL-Window, Glide-Slope-Deviation,
                // Vector-Window-Filter, Late-RWY-Change-Detection).
                // Beide Werte werden mit-publiziert — pre-v0.5.25-
                // Konsumenten weiter mit den σ-Werten, neue UI nutzt
                // approach_vs_deviation_fpm fuer das echte Gate-Maß.
                // v0.5.46: TD-Timestamp an Stability-Funktionen reichen damit
                // die letzten 3 sec (Flare-Manoever) nicht als Instabilitaet
                // gewertet werden (Adrian-Feedback). landing_at ist im
                // Landing-Phase-Handler bereits gesetzt.
                let td_ts = stats.landing_at;
                let (vs_sd, bank_sd) = compute_approach_stddev(&stats.approach_buffer, td_ts);
                // Rotorcraft / seaplane fly a vertical / non-glideslope profile
                // that the fixed-wing approach-stability model mis-reads as
                // "unstable" (high sink, large bank/IAS variance). The stability
                // sub-score is DRIVEN by these std-devs and `sub_stability`
                // returns None on None inputs (= sub-score SKIPPED, not
                // penalised), so null them for these categories. Fixed-wing
                // unchanged.
                let (vs_sd, bank_sd) = if category.is_non_conventional() {
                    (None, None)
                } else {
                    (vs_sd, bank_sd)
                };
                stats.approach_vs_stddev_fpm = vs_sd;
                stats.approach_bank_stddev_deg = bank_sd;
                let stab_v2 = compute_approach_stability_v2(
                    &stats.approach_buffer,
                    stats.arr_airport_elevation_ft,
                    td_ts,
                    // v0.15.17: echter Gleitwinkel der aufgelösten Bahn (oben bei
                    // 18597 gesetzt, also vor diesem Aufruf). None bei OurAirports-
                    // Fallback / keinem Match → Faktor 1,0 (3°-Verhalten).
                    stats
                        .runway_nav_geometry
                        .as_ref()
                        .map(|g| g.glideslope_angle),
                    // v0.16.6: kein Zeit-Fenster auf dem FSM-Pfad — exakt das
                    // bisherige Verhalten (das Fenster ist nur fuer den
                    // Sampler-Pfad, dessen Buffer Low-Level-Cruise enthalten kann).
                    None,
                );
                stats.approach_vs_deviation_fpm = stab_v2.vs_deviation_fpm;
                stats.approach_max_vs_deviation_below_500_fpm = stab_v2.max_vs_deviation_below_500_fpm;
                stats.approach_bank_stddev_filtered_deg = stab_v2.bank_stddev_filtered_deg;
                stats.approach_runway_changed_late = stab_v2.runway_changed_late;
                stats.approach_stable_at_gate = stab_v2.stable_at_gate;
                stats.approach_vs_jerk_fpm = stab_v2.vs_jerk_fpm;
                stats.approach_ias_stddev_kt = stab_v2.ias_stddev_kt;
                stats.approach_excessive_sink = stab_v2.excessive_sink;
                stats.approach_stable_config = stab_v2.stable_config;
                stats.approach_used_hat = stab_v2.used_hat;
                stats.approach_window_sample_count = Some(stab_v2.window_sample_count);
                stats.approach_stable_at_da = stab_v2.stable_at_da;
                stats.approach_stall_warning_count = stab_v2.stall_warning_count;

                // ─── v0.5.26 Per-Touchdown-Metriken ─────────────────
                let limits = aircraft_limits_for(&flight.aircraft_icao);

                // Wing-Strike-Severity: |bank_at_td| / max_bank × 100%.
                // A rotorcraft has no wing to strike, and the fixed-wing 8°
                // fallback bank limit would flag a normal heli touchdown bank
                // (15-20° on a slope/crosswind) as a 190-250% "wing strike" —
                // skip it for rotorcraft. (Seaplanes keep it: a float-tip /
                // wing-tip strike on water is still meaningful.)
                if !category.is_rotorcraft() {
                    if let Some(bank) = stats.landing_bank_deg {
                        let pct = (bank.abs() / limits.max_bank_landing_deg) * 100.0;
                        stats.landing_wing_strike_severity_pct = Some(pct);
                    }
                }

                // Float-Distance: Threshold-Crossing → TD.
                // Threshold-Position kommt aus runway_match. Distanz
                // direkt approximierbar als (rollout-Distanz von TD bis
                // GS<2kt = total runway-overrun) — aber wir haben das
                // nicht. Stattdessen: from-threshold-Distanz vom
                // runway_match (= TD-Punkt past threshold).
                // Float-Distanz ≈ past_threshold − typische
                // Threshold-50ft-Crossing-Distance. Vereinfacht:
                // touchdown_distance_from_threshold_ft direkt als
                // "Float" interpretieren (= Distanz die der Pilot nach
                // Threshold floated bevor er aufgesetzt hat). Pre-
                // Threshold-Approach-Pfad ist hier nicht relevant.
                if let Some((past_threshold_m, total_m)) = stats.runway_match.as_ref().map(|rw| {
                    let past = rw.touchdown_distance_from_threshold_ft as f32 * 0.3048;
                    let total = rw.length_ft * 0.3048;
                    (past, total)
                }) {
                    stats.landing_float_distance_m = Some(past_threshold_m);

                    // Touchdown-Zone-Klassifikation (FAA-Standard:
                    // Zone 1 = erstes Drittel, Zone 2 = zweites,
                    // Zone 3 = drittes Drittel der Bahn)
                    if total_m > 0.0 {
                        let third = total_m / 3.0;
                        let zone = if past_threshold_m <= third { 1 }
                                   else if past_threshold_m <= 2.0 * third { 2 }
                                   else { 3 };
                        stats.landing_touchdown_zone = Some(zone);
                    }
                }

                // Vref-Deviation: PMDG-FMC-Vref → ICAO-Default-Fallback
                let vref_kt = stats.pmdg_vref_at_landing.map(|v| v as f32);
                let (vref_used, vref_source) = match vref_kt {
                    Some(v) => (Some(v), "pmdg"),
                    None => match limits.typical_vref_kt {
                        Some(v) => (Some(v), "icao_default"),
                        None => (None, "unknown"),
                    },
                };
                stats.landing_vref_source = Some(vref_source);
                if let (Some(vref), Some(ias)) = (vref_used, stats.landing_speed_kt) {
                    stats.landing_vref_deviation_kt = Some(ias - vref);
                }

                // Yaw-Rate am TD: heading-Aenderung pro Sekunde im
                // letzten 1-sec-Fenster vor TD.
                let yaw_window_start = actual_td_at - chrono::Duration::milliseconds(1000);
                let yaw_samples: Vec<(DateTime<Utc>, f32)> = stats.snapshot_buffer.iter()
                    .filter(|s| s.at >= yaw_window_start && s.at <= actual_td_at)
                    .map(|s| (s.at, s.heading_true_deg))
                    .collect();
                if yaw_samples.len() >= 2 {
                    let first = yaw_samples.first().unwrap();
                    let last = yaw_samples.last().unwrap();
                    let mut delta = last.1 - first.1;
                    while delta > 180.0 { delta -= 360.0; }
                    while delta < -180.0 { delta += 360.0; }
                    let dt_sec = (last.0 - first.0).num_milliseconds() as f32 / 1000.0;
                    if dt_sec > 0.1 {
                        stats.landing_yaw_rate_deg_per_sec = Some(delta.abs() / dt_sec);
                    }
                }

                // Brake-Energy-Proxy = (mass × ias²) / rollout_distance.
                // Vereinfacht: ohne mass = (ias²) / rollout — damit
                // auch ohne LDW-SimVar berechenbar. Skaliert wenn mass
                // verfuegbar.
                if let (Some(ias), Some(rollout)) = (stats.landing_speed_kt, stats.rollout_distance_m) {
                    if rollout > 50.0 && ias > 0.0 {
                        let ias_ms = ias * 0.5144; // kt → m/s
                        let mass = stats.landing_weight_kg.unwrap_or(50_000.0);
                        let kinetic = 0.5 * mass * (ias_ms as f64).powi(2);
                        // Normalisiert auf 100 = 100kJ pro Meter Rollout
                        // = brake-typical 1MN-Aircraft mit 100m-Stop
                        let energy_per_m = kinetic / rollout as f64;
                        stats.landing_brake_energy_proxy = Some((energy_per_m / 1_000.0) as f32);
                    }
                }
                tracing::info!(
                    pirep_id = %flight.pirep_id,
                    vs_dev_fpm = ?stab_v2.vs_deviation_fpm,
                    max_vs_dev_below_500 = ?stab_v2.max_vs_deviation_below_500_fpm,
                    bank_sd_filtered = ?stab_v2.bank_stddev_filtered_deg,
                    rwy_changed_late = stab_v2.runway_changed_late,
                    stable_at_gate = ?stab_v2.stable_at_gate,
                    samples = stab_v2.window_sample_count,
                    "approach stability v2 computed"
                );

                // Reset rollout tracking. The Landing-phase arm below
                // accumulates haversine distance from `(landing_lat,
                // landing_lon)` until the rollout finalises (~40 kt exit
                // speed / >30° heading turn-off / 5 kt full-stop), then
                // sets `rollout_finalized`.
                stats.rollout_distance_m = Some(0.0);
                stats.rollout_finalized = false;
                stats.rollout_last_lat = Some(snap.lat);
                stats.rollout_last_lon = Some(snap.lon);
                // Landing weight — extracted helper (v0.15.24), called at
                // the SAME point in the arm as the pre-extraction inline
                // code (after the brake-energy proxy above, which must keep
                // seeing the PREVIOUS landing_weight_kg on touch-and-go).
                stamp_landing_weight(&mut stats, snap);
            }
        }
        FlightPhase::Landing => {
            // Rollout-distance accumulator: from `landing_lat/lon` until
            // the rollout finalises (~40 kt exit speed / >30° heading
            // turn-off / 5 kt full-stop). Extracted verbatim to
            // `rollout_tick` (v0.16.6) so sampler-path bush landings can
            // drive the same logic from the streamer — this call sits at
            // the exact position the inline code used to.
            rollout_tick(&mut stats, snap);

            // Touchdown analyzer windows (BeatMyLanding-aligned):
            //   * Peak G refined for TOUCHDOWN_G_WINDOW_MS (1500 ms)
            //   * Peak |V/S| refined for TOUCHDOWN_WINDOW_SECS (5 s) —
            //     wider to catch a hard secondary contact after a bounce.
            //   * Bounces tracked via AGL-edge for BOUNCE_WINDOW_SECS (8 s).
            //   * Score finalised once the bounce window closes.
            if let Some(touchdown) = stats.landing_at {
                let elapsed_ms = (now - touchdown).num_milliseconds();
                let elapsed_secs = elapsed_ms / 1_000;
                let in_vs_window = elapsed_secs <= TOUCHDOWN_WINDOW_SECS;
                let in_g_window = elapsed_ms <= TOUCHDOWN_G_WINDOW_MS;
                let in_bounce_window = elapsed_secs <= BOUNCE_WINDOW_SECS;

                if in_vs_window {
                    // Post-touchdown peak-|V/S| refinement is a scored value, so
                    // it uses the raw, lag-free touchdown source (not the VVI).
                    let raw_vs = snap.touchdown_vs_source_fpm();
                    let peak_vs = stats.landing_peak_vs_fpm.unwrap_or(0.0);
                    if raw_vs < peak_vs {
                        stats.landing_peak_vs_fpm = Some(raw_vs);
                    }
                }
                if in_g_window {
                    let peak_g = stats.landing_peak_g_force.unwrap_or(0.0);
                    if snap.g_force > peak_g {
                        stats.landing_peak_g_force = Some(snap.g_force);
                    }
                }

                // Bounce detection — AGL-edge state machine. Replaces
                // the noisy on-ground flicker we used pre-Tier-1, which
                // tripped on gear-strut oscillation and over-counted
                // bounces on a clean landing.
                //
                // Arm: AGL crosses up through BOUNCE_AGL_THRESHOLD_FT
                //      (v0.8.3: 15 ft = touchdown_v2 SCORED-Threshold,
                //       gesenkt von 35 ft weil typische Hopser nie zaehlten).
                // Fire: AGL drops back below BOUNCE_AGL_RETURN_FT
                //      (5 ft, `BounceRadioAltReturnFeet`).
                // Both must happen inside BOUNCE_WINDOW_SECS for a bounce
                // to count — past that we assume the pilot did a touch-
                // and-go or got airborne again deliberately.
                if in_bounce_window {
                    if !stats.bounce_armed_above_threshold
                        && snap.altitude_agl_ft > BOUNCE_AGL_THRESHOLD_FT
                    {
                        stats.bounce_armed_above_threshold = true;
                    } else if stats.bounce_armed_above_threshold
                        && snap.altitude_agl_ft < BOUNCE_AGL_RETURN_FT
                    {
                        stats.bounce_count = stats.bounce_count.saturating_add(1);
                        stats.bounce_armed_above_threshold = false;
                        tracing::info!(
                            count = stats.bounce_count,
                            agl_ft = snap.altitude_agl_ft,
                            elapsed_ms,
                            "bounce counted (AGL re-entered ground band)"
                        );
                    }
                }

                if !in_bounce_window && stats.landing_score.is_none() {
                    // All windows have closed — finalise the score once.
                    //
                    // v0.7.17 (B-005): Wenn `landing_peak_vs_fpm` None ist
                    // (= Sampler hat den Touchdown-VS gar nicht erfasst,
                    // typisch bei Phantom-Touchdowns durch on_ground-
                    // Flicker oder Sim-Bug), waere `unwrap_or(0.0)` =
                    // 0.0 fpm gefallen → Smooth-Score 100 trotz nie
                    // wirklich gemessenen Werts. Pilot sieht „Butter
                    // Landing 100/100" obwohl gar kein Touchdown war.
                    //
                    // Fix: nur klassifizieren wenn `landing_peak_vs_fpm`
                    // tatsaechlich Some ist (also der Sampler einen Wert
                    // hatte). Sonst landing_score bleibt None, das
                    // Touchdown-Event wird im PIREP als „score not
                    // captured" markiert.
                    if let Some(peak_vs) = stats.landing_peak_vs_fpm {
                        // v0.12.3 (LE8/QS-P1): classify on the scored G
                        // (raw_fallback here — no forensics window).
                        let scored_g = score_g_for_stats(&stats).scored_g;
                        let score = LandingScore::classify(peak_vs, scored_g, stats.bounce_count);
                        stats.landing_score = Some(score);
                    } else {
                        tracing::warn!(
                            pirep_id = %flight.pirep_id,
                            "landing_peak_vs_fpm = None at score-finalise — keeping landing_score=None (B-005). Sampler likely missed the touchdown edge."
                        );
                    }
                }

                // Touch-and-Go classifier — runs in parallel with the
                // bounce/score windows. Looks for a sustained climb
                // back above TOUCH_AND_GO_AGL_THRESHOLD_FT within
                // TOUCH_AND_GO_WATCH_SECS of the touchdown. If the
                // pilot really lifted off and is climbing out (= T&G),
                // we record the touchdown as kind=TouchAndGo, reset
                // the landing window for the next touchdown, and bump
                // the FSM back to Climb so subsequent phase
                // transitions work normally on the next descent.
                let tg_in_window = elapsed_secs <= TOUCH_AND_GO_WATCH_SECS;
                if tg_in_window {
                    let agl = snap.altitude_agl_ft as f32;
                    let conds_met = agl > TOUCH_AND_GO_AGL_THRESHOLD_FT
                        && !snap.on_ground
                        && snap.engines_running > 0;
                    if conds_met {
                        let pending = stats.touch_and_go_pending_since.get_or_insert(now);
                        if (now - *pending).num_seconds() >= TOUCH_AND_GO_DWELL_SECS {
                            // CONFIRMED: this was a touch-and-go.
                            let event = TouchdownEvent {
                                timestamp: touchdown,
                                kind: TouchdownKind::TouchAndGo,
                                peak_vs_fpm: stats.landing_peak_vs_fpm.unwrap_or(0.0),
                                peak_g: stats.landing_peak_g_force.unwrap_or(0.0),
                                lat: stats.landing_lat.unwrap_or(snap.lat),
                                lon: stats.landing_lon.unwrap_or(snap.lon),
                                sub_bounces: stats.bounce_count,
                            };
                            stats.touchdown_events.push(event.clone());
                            // JBU327-Fix: ein Touch-and-Go / Balked-Landing IST
                            // ein Go-Around — der Anflug wurde abgebrochen und neu
                            // angesetzt. `check_go_around` (nur Approach/Final)
                            // erfasst ausschliesslich den Go-Around OHNE
                            // Bodenberuehrung; der balked-landing-Fall (Raeder
                            // beruehrten kurz, dann Wegstieg) lief bisher NUR durch
                            // diesen T&G-Pfad und blieb in `go_around_count`
                            // ungezaehlt — fehlte damit im PIREP (phpVMS) + auf der
                            // Live-Map. Hier mitzaehlen. Reporting-only, KEIN
                            // Score-Einfluss (`go_around_count` fliesst nicht in
                            // `landing_scoring`).
                            stats.go_around_count = stats.go_around_count.saturating_add(1);
                            let ga_count = stats.go_around_count;
                            let tg_count = stats
                                .touchdown_events
                                .iter()
                                .filter(|e| matches!(e.kind, TouchdownKind::TouchAndGo))
                                .count();
                            tracing::info!(
                                count = tg_count,
                                go_around_count = ga_count,
                                peak_vs = event.peak_vs_fpm,
                                peak_g = event.peak_g,
                                sub_bounces = event.sub_bounces,
                                "touch-and-go classified (counts as go-around) — resetting landing window"
                            );
                            stats.pending_acars_logs.push(format!(
                                "Go-around #{} (touch-and-go) — V/S {:.0} fpm, G {:.2}",
                                ga_count, event.peak_vs_fpm, event.peak_g
                            ));
                            // Reset landing window so the NEXT touchdown
                            // gets a fresh score window. Bounce count
                            // resets too — T&Gs don't drag down the
                            // final-landing's score.
                            stats.landing_at = None;
                            stats.landing_peak_vs_fpm = None;
                            stats.landing_peak_g_force = None;
                            stats.landing_score = None;
                            stats.landing_score_announced = false;
                            stats.landing_lat = None;
                            stats.landing_lon = None;
                            stats.bounce_count = 0;
                            stats.bounce_armed_above_threshold = false;
                            stats.touch_and_go_pending_since = None;
                            // CRITICAL: also clear the GA tracker so the
                            // NEXT approach starts with a fresh AGL
                            // minimum. Without this, the just-recorded
                            // T&G's ~50 ft touchdown AGL becomes the
                            // floor against which the next GA detector
                            // compares — which means EVERY future
                            // approach would trivially exceed
                            // "lowest + 200 ft" the moment the pilot
                            // climbs above 250 ft AGL, hiding any real
                            // missed-approach behind an immediate
                            // false-positive trigger.
                            stats.lowest_agl_during_approach_ft = None;
                            stats.go_around_climb_pending_since = None;
                            // v0.5.11: also reset climb_peak_msl so
                            // the new Climb segment after T&G starts
                            // fresh. Without this, the prior pattern
                            // altitude (e.g. 2000 ft) stays as the
                            // peak — and the moment the aircraft
                            // descends 500+ ft below it for the next
                            // approach, the v0.5.10 low-altitude
                            // Climb→Descent trigger would fire
                            // immediately (lost_from_peak > 500
                            // already satisfied via stale data).
                            // Pattern flying with multiple T&Gs
                            // would oscillate between Climb and
                            // Descent on every traffic-pattern leg.
                            stats.climb_peak_msl = None;
                            // FSM: revert to Climb so the streamer's
                            // phase-change handler emits "Phase: Climb"
                            // and subsequent descent re-detection works.
                            next_phase = FlightPhase::Climb;
                        }
                    } else {
                        // Conditions broke (engines off, AGL dropped,
                        // back on ground) — restart the dwell timer.
                        stats.touch_and_go_pending_since = None;
                    }
                }

                // v0.7.20 (QS-Nebenfund GSG219): FinalLanding-Push aus dem
                // `else if`-Branch entkoppelt — vorher konnte der Push
                // verloren gehen wenn:
                //   1. der Score im selben Tick finalisiert wurde aber der
                //      `else if` durch den vorherigen `if tg_in_window`-Pfad
                //      blockiert blieb, ODER
                //   2. die Phase im selben Tick auf TaxiIn wechselte bevor
                //      ein zweiter Tick im Landing-Branch lief.
                //
                // Ausserdem nicht mehr an `landing_score.is_some()` gekoppelt:
                // bei Sampler-Fallback (vs_source=last_low_agl_vs, kein
                // Sampler-Edge) kann `landing_score` durch den B-005-Guard
                // ohne `landing_peak_vs_fpm` None bleiben — der Touchdown
                // hat aber definitiv stattgefunden (Webapp-Anzeige + Pilot-
                // Tab "Landung" + MQTT-touchdown_complete zeigen das). Der
                // TouchdownEvent gehoert ins Audit/PIREP-`touchdown_count`-
                // Feld, unabhaengig davon ob die Score-Kategorie klassifiziert
                // werden konnte.
                //
                // peak_vs_fpm fuellt sich aus dem besten verfuegbaren Wert:
                // Sampler-Peak (best) → landing_rate_fpm (Fallback aus dem
                // touchdown_v2-Cascade) → 0.0 (defensiv).
                if !tg_in_window
                    && stats.landing_at == Some(touchdown)
                    && stats
                        .touchdown_events
                        .last()
                        .map(|e| e.timestamp != touchdown)
                        .unwrap_or(true)
                {
                    let event = TouchdownEvent {
                        timestamp: touchdown,
                        kind: TouchdownKind::FinalLanding,
                        peak_vs_fpm: stats
                            .landing_peak_vs_fpm
                            .or(stats.landing_rate_fpm)
                            .unwrap_or(0.0),
                        peak_g: stats.landing_peak_g_force.unwrap_or(0.0),
                        lat: stats.landing_lat.unwrap_or(snap.lat),
                        lon: stats.landing_lon.unwrap_or(snap.lon),
                        sub_bounces: stats.bounce_count,
                    };
                    stats.touchdown_events.push(event);
                    tracing::info!(
                        total_touchdowns = stats.touchdown_events.len(),
                        "final landing recorded as TouchdownEvent"
                    );
                }
            }

            if snap.groundspeed_kt < 30.0 && snap.on_ground {
                next_phase = FlightPhase::TaxiIn;
            }
        }
        FlightPhase::TaxiIn => {
            if snap.parking_brake && snap.groundspeed_kt < 1.0 && snap.on_ground {
                next_phase = FlightPhase::BlocksOn;
                stats.block_on_at = Some(now);
                // Capture the arrival stand the moment we settle at
                // the gate. MSFS only fills `parking_name` while the
                // aircraft is on a named stand, so this is the right
                // moment.
                if let Some(name) =
                    snap.parking_name.as_ref().filter(|s| !s.is_empty())
                {
                    let label = match snap.parking_number.as_ref() {
                        Some(num) if !num.is_empty() => format!("{name} {num}"),
                        _ => name.clone(),
                    };
                    stats.arr_gate = Some(label);
                }
            }
        }
        FlightPhase::BlocksOn => {
            // BlocksOn → Arrived once the pilot has actually shut
            // down: engines off + parking brake set + at least 30 s
            // since the wheels stopped. Real pilots routinely leave
            // engines running a minute or two after blocks-on for
            // cool-down / APU transition, so we don't flip to Arrived
            // the instant they hit the brake.
            if let Some(block_on) = stats.block_on_at {
                let settled_secs = (now - block_on).num_seconds();
                if settled_secs >= 30
                    && snap.engines_running == 0
                    && snap.parking_brake
                    && snap.on_ground
                {
                    next_phase = FlightPhase::Arrived;
                }
            }
        }
        FlightPhase::Arrived | FlightPhase::PirepSubmitted => {
            // v0.7.17 (B-004): Sanity-Check fuer „Aircraft fliegt wieder
            // obwohl Phase ARRIVED ist". Klassisches Pattern: Pilot
            // landet, vergisst Flug zu beenden (oder Auto-File scheitert
            // silent, siehe B-006), startet im Sim einen neuen Flug.
            // Position-Stream lief vorher endlos mit der alten PIREP-ID
            // weiter und packte die neuen Positionen in den alten
            // PIREP-Recorder-Stream (= „Aircraft springt nach Landung
            // ploetzlich 750 km weg" wie bei CFG 1641 EDDM→EDDL).
            //
            // Hier ist die FSM die einzige Stelle die das mitbekommen
            // kann — der Position-Worker selbst hat keinen Zugriff auf
            // die Phase, posted blind. Wir setzen flight.stop damit der
            // Worker beim naechsten Tick sauber abdreht. PIREP bleibt
            // existing (wird nicht gefilt, bleibt prefiled — falls Pilot
            // doch zurueckkommt und manuell beenden moechte).
            let aircraft_clearly_flying =
                !snap.on_ground && snap.groundspeed_kt > 100.0 && snap.engines_running > 0;
            if aircraft_clearly_flying && !stats.arrived_stale_warning_logged {
                tracing::warn!(
                    pirep_id = %flight.pirep_id,
                    phase = ?stats.phase,
                    gs_kt = snap.groundspeed_kt,
                    agl_ft = snap.altitude_agl_ft,
                    "FSM phase=Arrived/PirepSubmitted but aircraft is flying again — stopping position stream"
                );
                stats.arrived_stale_warning_logged = true;
                stats.pending_acars_logs.push(
                    "Position-Stream gestoppt — Flugzeug fliegt wieder, aber PIREP war als 'angekommen' markiert. \
                     Bitte den alten Flug manuell beenden (PIREP-Detail) oder via 'Flug verwerfen' verwerfen, \
                     dann neuen Flug starten.".to_string(),
                );
                flight.stop.store(true, Ordering::Relaxed);
            }
        }
        FlightPhase::Preflight => {}
    }

    // Universal "we're done" fallback. The normal FSM chain assumes a
    // fixed-wing flight with a Pushback → Cruise → BlocksOn arc, and
    // a parking brake / engines-off shutdown sequence. None of that
    // applies cleanly to:
    //   * helicopters (no taxi-out / no parking brake / vertical
    //     takeoff and landing — the FSM gets stuck around TaxiOut)
    //   * very-short hops with no real cruise phase
    //   * engine-failure / emergency landings near the destination
    //   * aircraft profiles that don't wire `parking_brake` at all
    //
    // The escape hatch: once the aircraft has actually started
    // moving (block_off recorded), if it's now sitting on-ground
    // with engines off within 2 nmi of the arrival airport for at
    // least ARRIVED_FALLBACK_DWELL_SECS, we force `Arrived` regardless
    // of prior phase. Block_on_at gets back-filled here so the PIREP
    // file logic (which reads it for flight-time / chocks-on) still
    // works.
    let already_done = matches!(
        next_phase,
        FlightPhase::Arrived | FlightPhase::PirepSubmitted
    );
    let pre_block_off = matches!(
        next_phase,
        FlightPhase::Preflight | FlightPhase::Boarding
    );
    // GATE: only run the universal Arrived-fallback (and the divert
    // detection inside it) if the aircraft has actually been airborne
    // at some point. Without this, GSX/sim ground-handling jitter at
    // the gate can stamp `block_off_at` (any motion >0.5 kt counts),
    // and ARRIVED_FALLBACK_DWELL_SECS later the fallback fires with phase=Arrived plus a
    // bogus divert hint pointing at the departure airport — exactly
    // the bug pilots reported with NKS 833 KFLL→MKJS where GSX wackeln
    // produced "you landed at KFLL, planned was MKJS, file as divert?".
    if !already_done && !pre_block_off && stats.block_off_at.is_some() && stats.was_airborne {
        let arr_pos = runway::airport_position(&flight.arr_airport);
        let dist_to_planned_nmi = arr_pos
            .map(|(la, lo)| runway::distance_m(snap.lat, snap.lon, la, lo) / 1852.0)
            .unwrap_or(f64::INFINITY);
        let near_planned = dist_to_planned_nmi <= ARRIVED_FALLBACK_RADIUS_NM;
        // We treat "no airport in local DB" as near_planned=true so we
        // don't block the file path for obscure ICAO codes — same as
        // the original fallback behaviour.
        let near_planned = near_planned || arr_pos.is_none();

        // v0.7.5 Phase-Safety Hotfix (Spec docs/spec/flight-phase-state-
        // machine.md §13.8): siehe arrived_fallback_conditions_basic.
        //
        // Helicopters routinely keep the rotor running after touchdown (hot
        // ops: EMS offload, sightseeing turnaround, pad/rig work), so the
        // engines-off requirement would never finalise their arrival. Relax it
        // for rotorcraft — but ONLY at the planned destination (`near_planned`)
        // with the same on-ground + stationary + ARRIVED_FALLBACK_DWELL_SECS
        // guards, so a rotors-running intermediate stop can never be
        // mis-filed as a divert (the divert path keeps the strict
        // engines-off requirement).
        // Original engines-off-Pfad (ARRIVED_FALLBACK_DWELL_SECS Dwell) inkl.
        // Rotorcraft-Relaxation (Rotoren laufen oft nach dem Aufsetzen weiter
        // → nur Stillstand am Ziel gefordert).
        let engines_off_path = if category.is_rotorcraft() && near_planned {
            snap.on_ground && snap.groundspeed_kt < 1.0
        } else {
            arrived_fallback_conditions_basic(
                snap.on_ground,
                snap.engines_running,
                snap.groundspeed_kt,
            )
        };
        // v0.17.x (#Premium, Aircraft-Scan): Stillstands-Fallback für Addons,
        // deren `engines_running` nach dem Shutdown klemmt (Contrail FA50
        // Trijet: bleibt bei 3 → der engines-off-Pfad feuert NIE, Auto-File
        // hängt). Ein Flieger, der am Zielflughafen voll steht (< 1 kt) MIT
        // gesetzter Parkbremse, ist angekommen — unabhängig vom (falschen)
        // Triebwerkszähler. NUR `near_planned` (der Divert-Pfad unten behält
        // die strikte engines-off-Bedingung).
        //
        // v0.18.x QA-Härtung: bewusst NICHT mehr fleet-weit (Einwand Thomas —
        // an großen Hubs ziehen Piloten die Parkbremse auch bei einem langen
        // Rollhalt, z. B. beim Warten auf weitere Rollfreigabe; ohne Gate hätte
        // das JEDEN Piloten mitten auf dem Rollweg beenden können). Läuft nur
        // noch für Flugzeuge mit bestätigt kaputtem Triebwerkszähler (siehe
        // `AircraftProfile::engine_count_unreliable`) — für alle anderen bleibt
        // ausschließlich der harte engines-off-Pfad übrig, exakt wie vor v0.17.x.
        let standstill_path = snap.aircraft_profile.engine_count_unreliable()
            && arrived_standstill_condition(
                near_planned,
                snap.on_ground,
                snap.groundspeed_kt,
                snap.parking_brake,
            );
        let conditions_basic = engines_off_path || standstill_path;
        if conditions_basic {
            // Shared wall-clock timer for both paths (see
            // arrived_fallback_pending_since's doc comment for why it's
            // deliberately shared rather than reset on every path switch).
            // Only the dwell threshold differs by path.
            let pending_at = stats.arrived_fallback_pending_since.get_or_insert(now);
            let elapsed = (now - *pending_at).num_seconds();
            let dwell_needed = if engines_off_path {
                ARRIVED_FALLBACK_DWELL_SECS
            } else {
                ARRIVED_STANDSTILL_DWELL_SECS
            };
            if elapsed >= dwell_needed {
                // Two paths to Arrived from here:
                //
                //   1. near_planned    → normal arrival, original fallback behaviour
                //   2. far from planned → DIVERT — find nearest airport, populate
                //                          divert_hint so the cockpit can ask the
                //                          pilot to confirm the actual destination
                //                          and file with the correct arr_airport_id
                let mut detected_hint: Option<DivertHint> = None;
                if !near_planned && dist_to_planned_nmi >= DIVERT_DETECT_RADIUS_NM {
                    let nearby = runway::find_nearest_airports(
                        snap.lat,
                        snap.lon,
                        DIVERT_NEAREST_SEARCH_RADIUS_NM * 1852.0,
                        1,
                    );
                    // Only count as "at airport X" when the nearest
                    // runway threshold is within the same on-airport
                    // tolerance we use for the planned-arrival check.
                    let nearest_icao = nearby
                        .into_iter()
                        .next()
                        .filter(|na| {
                            na.distance_m / 1852.0 <= ARRIVED_FALLBACK_RADIUS_NM
                        })
                        .map(|na| na.icao);
                    let alt_match = nearest_icao
                        .as_deref()
                        .zip(stats.planned_alternate.as_deref())
                        .map(|(a, b)| a.eq_ignore_ascii_case(b))
                        .unwrap_or(false);
                    let kind = if alt_match {
                        "alternate"
                    } else if nearest_icao.is_some() {
                        "nearest"
                    } else {
                        "unknown"
                    };
                    detected_hint = Some(DivertHint {
                        actual_icao: nearest_icao,
                        planned_arr_icao: flight.arr_airport.clone(),
                        planned_alt_icao: stats.planned_alternate.clone(),
                        distance_to_planned_nmi: dist_to_planned_nmi,
                        kind,
                    });
                    tracing::info!(
                        planned = %flight.arr_airport,
                        actual = ?detected_hint.as_ref().and_then(|h| h.actual_icao.as_deref()),
                        dist_nmi = dist_to_planned_nmi,
                        kind,
                        "divert detected"
                    );
                }

                if near_planned || detected_hint.is_some() {
                    tracing::info!(
                        prev_phase = ?prev_phase,
                        elapsed,
                        near_planned,
                        diverted = detected_hint.is_some(),
                        "Arrived fallback fired — forcing FSM to Arrived"
                    );
                    next_phase = FlightPhase::Arrived;
                    if stats.block_on_at.is_none() {
                        stats.block_on_at = Some(now);
                    }
                    // Helicopters often don't fire a touchdown event the
                    // way the analyzer expects. If we never recorded
                    // landing_at, stamp it now so the file body has a
                    // sensible flight_time. (Shared helper — the enroute-
                    // reconcile Landing pull needs the exact same rescue.)
                    rescue_landing_at_from_sampler(&mut stats, now);
                    if let Some(hint) = detected_hint {
                        stats.divert_hint = Some(hint);
                    }
                }
            }
        } else {
            stats.arrived_fallback_pending_since = None;
        }
    } else {
        stats.arrived_fallback_pending_since = None;
    }

    stats.was_on_ground = Some(snap.on_ground);
    stats.was_parking_brake = Some(snap.parking_brake);

    // En-Route-Versöhner (siehe Doc an `ENROUTE_RECONCILE_DWELL_SECS`):
    // läuft NACH allen regulären Übergangs-Armen und NUR, wenn keiner von
    // ihnen diesen Tick etwas entschieden hat — der Primärpfad behält
    // immer Vorrang. Liest `stats.shadow_phase` vom VORHERIGEN Tick
    // (die Schatten-Engine tickt im Streamer nach `step_flight`) — bei
    // 90 s Dwell irrelevant. `Insufficient` = v2 hat gerade keine echte
    // Kinematik-Evidenz (frisch resettet nach Reload/Time-Skip) → nicht
    // nur nicht feuern, sondern die Divergenz-Uhr komplett neu starten.
    if next_phase == prev_phase && !reload_gap_suspect {
        // PRIMÄRES Gate: die Kinematik muss v1s Phase aktiv WIDERLEGEN —
        // bloßes v1≠v2 genügt nicht (QS-Runde 1: sonst Oszillation auf
        // gesunden Flügen, siehe segment_contradicts_v1-Doc). Subsumiert
        // `Insufficient` (widerspricht nie → keine Evidenz, kein Urteil).
        let contradicted =
            segment_contradicts_v1(prev_phase, stats.shadow_engine.current_segment());
        match stats.shadow_phase {
            Some(v2)
                if enroute_reconcile_eligible(prev_phase, v2)
                    && contradicted
                    // QS-Runde 1: `Landing` als Ziel nur mit ROHEM
                    // on_ground dieses Ticks — v2s Ground-Mehrheit ist
                    // fensterträge; hebt der Flieger im Versatz-Tick
                    // wieder ab (Balked Landing), würde ein Luft-Zug auf
                    // Landing BEIDE Engines unlösbar festnageln (v2
                    // spiegelt Landing 1:1 zurück, v1=Landing hat ohne
                    // landing_at keinen Luft-Ausstieg, der Versöhner
                    // selbst ist raus).
                    && (v2 != FlightPhase::Landing || snap.on_ground) =>
            {
                // Uhr ist an v1s STILLSTAND gekoppelt, nicht an ein
                // stabiles (v1, v2)-Paar — v2 darf während des Dwells
                // legitim weiterwandern (siehe Feld-Doc). Gezogen wird
                // auf v2s AKTUELLE Phase (frischeste Evidenz).
                let since = match stats.enroute_divergence_since {
                    Some((p1, t)) if p1 == prev_phase => t,
                    _ => {
                        stats.enroute_divergence_since = Some((prev_phase, now));
                        now
                    }
                };
                // Asymmetrischer Dwell nach Zug-Richtung — siehe
                // ENROUTE_RECONCILE_DWELL_SECS-Doc. Die Richtung wird pro
                // Tick aus der AKTUELLEN v2-Phase bestimmt: wandert v2
                // während des Dwells vorwärts (Descent→Approach→Final),
                // gilt ab da der Vorwärts-Dwell — die Uhr selbst läuft
                // von ihrem einen Startpunkt weiter.
                let dwell_needed = if enroute_reconcile_is_forward(prev_phase, v2) {
                    ENROUTE_RECONCILE_FORWARD_DWELL_SECS
                } else {
                    ENROUTE_RECONCILE_DWELL_SECS
                };
                if (now - since).num_seconds() >= dwell_needed {
                    tracing::warn!(
                        ?prev_phase,
                        target = ?v2,
                        held_secs = (now - since).num_seconds(),
                        dwell_needed,
                        "enroute-reconcile: v1 auf Luft-Phase festgefahren, Kinematik \
                         widerlegt sie, v2-Evidenz zeigt beständig eine andere Phase — \
                         ziehe v1 nach"
                    );
                    stats.enroute_divergence_since = None;
                    // Timer-Hygiene (QS-Runde 1): armierte Dwell-Timer
                    // anderer Detektoren dürfen den Quer-Zug nicht als
                    // Alt-Zustand überleben — ein stehen gebliebener
                    // go_around_climb_pending_since könnte bei späterem
                    // Approach-Wiedereintritt via get_or_insert die 8-s-
                    // GA-Dwell sofort erfüllen (falscher Go-Around).
                    stats.descent_pending_since = None;
                    stats.go_around_climb_pending_since = None;
                    stats.touch_and_go_pending_since = None;
                    match v2 {
                        FlightPhase::Approach => {
                            // Gleiche Entry-Semantik wie die reguläre
                            // Descent→Approach-Kante: frisches Per-
                            // Anflug-Bild (Werte eines FRÜHEREN Anflugs
                            // dürfen nicht in den Touchdown-VS-Fallback
                            // sickern). Bei Ziel Final BEWUSST nicht —
                            // dort läuft der aktuelle Anflug bereits,
                            // seine Low-AGL-Samples sind die Wahrheit.
                            stats.low_agl_vs_min_fpm = None;
                            stats.last_low_agl_vs_fpm = None;
                        }
                        FlightPhase::Landing => {
                            // Zug direkt auf Landing = die Final→Landing-
                            // Kante (dort latcht normal landing_at) wurde
                            // übersprungen — ohne diese Rettung bliebe
                            // landing_at=None (aufgeblähte flight_time,
                            // kein LandingRecord, Landing-Arm-Analyzer
                            // komplett tot, is_finalizable=false).
                            rescue_landing_at_from_sampler(&mut stats, now);
                        }
                        _ => {}
                    }
                    next_phase = v2;
                }
            }
            _ => {
                stats.enroute_divergence_since = None;
            }
        }
    } else {
        // Frische v1-Transition (= lebendige FSM, wird NIE übersteuert)
        // oder Reload-Glitch-Tick: Divergenz-Uhr neu starten.
        stats.enroute_divergence_since = None;
    }

    if next_phase != prev_phase {
        // v0.7.5 Phase-Safety Hotfix (Spec §13.9): siehe should_reset_holding_pending.
        if should_reset_holding_pending(prev_phase, next_phase) {
            stats.holding_pending_since = None;
        }
        stats.phase = next_phase;
        stats.transitions.push((now, next_phase));
        Some(next_phase)
    } else {
        None
    }
}

#[cfg(test)]
mod arrived_fallback_dwell_tests {
    //! v0.19.1 — tests for the universal Arrived-fallback's `engines_off_path`
    //! dwell, lowered from a flat 30 s to `ARRIVED_FALLBACK_DWELL_SECS = 9 s`
    //! (field report: GSG22 EDLN→EDDL, pilot perceived the app as frozen on
    //! "Final" for 3-4 min after touchdown — see docs/release-notes/v0.19.1.md).
    //!
    //! Deliberately still wall-clock (not a tick count): `step_flight` reads
    //! real time via `Utc::now()` with no injectable clock, and — more
    //! importantly — a tick-count threshold would be wrong on its own terms
    //! here, because `adaptive_tick_interval` drops the ground/near-ground
    //! tick cadence to 500 ms exactly in the "stuck on Final near/at 0 AGL"
    //! state this fallback rescues (an earlier version of this fix used tick
    //! counting and was caught doing this in code review before release —
    //! see the ARRIVED_FALLBACK_DWELL_SECS doc comment). These tests seed
    //! `arrived_fallback_pending_since` directly to simulate "N seconds have
    //! already elapsed" without sleeping in the test.
    //!
    //! `standstill_path` (engine_count_unreliable addons, e.g. Contrail
    //! FA50) shares the same `arrived_fallback_pending_since` timer with a
    //! separate, much longer dwell (`ARRIVED_STANDSTILL_DWELL_SECS`) — see
    //! `standstill_path_uses_its_own_longer_dwell_via_the_shared_timer`.

    use super::*;

    /// Minimal ActiveFlight for exercising `step_flight` directly. Uses a
    /// non-existent arrival ICAO so `runway::airport_position` returns
    /// `None` and the fallback's `near_planned` check short-circuits to
    /// `true` — isolates these tests to the dwell mechanic itself, not
    /// runway-distance geometry (covered elsewhere).
    fn fixture() -> ActiveFlight {
        ActiveFlight {
            pirep_id: "test-pirep".into(),
            bid_id: 0,
            flight_id: String::new(),
            bid_callsign: None,
            pilot_callsign: None,
            started_at: Utc::now(),
            airline_icao: String::new(),
            planned_registration: String::new(),
            aircraft_icao: "C172".into(),
            aircraft_name: String::new(),
            flight_number: "1".into(),
            dpt_airport: "EDDF".into(),
            arr_airport: "ZZZZ".into(),
            airline_logo_url: None,
            fares: Vec::new(),
            stats: Mutex::new(FlightStats::new()),
            stop: AtomicBool::new(false),
            was_just_resumed: AtomicBool::new(false),
            streamer_spawned: AtomicBool::new(false),
            cancelled_remotely: AtomicBool::new(false),
            position_outbox: Mutex::new(std::collections::VecDeque::new()),
            phpvms_worker_spawned: AtomicBool::new(false),
            touchdown_sampler_spawned: AtomicBool::new(false),
            connection_state: std::sync::atomic::AtomicU8::new(CONN_STATE_LIVE),
            navdata: Mutex::new(NavdataCache::default()),
        }
    }

    /// Arms the "has genuinely flown" gate the universal fallback requires
    /// (`block_off_at.is_some() && was_airborne`). Starts from `Climb`, not
    /// a ground/terminal phase: this is deliberately the real-world
    /// scenario that triggers the escape hatch (legacy FSM stuck on an
    /// en-route phase, e.g. the GSG22 flight this fix is based on) — and,
    /// as a test-isolation bonus, `Climb`'s own match arm only reacts to
    /// altitude, so it can't independently transition on the ground-
    /// condition snapshots these tests feed in (a ground/terminal starting
    /// phase like `TaxiIn` would confound the fallback's own dwell with the
    /// *normal* FSM's blocks-on transition, which reacts to the exact same
    /// conditions).
    ///
    /// `dwell_started_secs_ago`: pre-seeds `arrived_fallback_pending_since`
    /// so the very first `step_flight` call already sees that much elapsed
    /// time, without sleeping. `None` leaves it unset (fresh timer, starts
    /// on the first qualifying tick — real `now()`).
    fn armed_flight(dwell_started_secs_ago: Option<i64>) -> ActiveFlight {
        let flight = fixture();
        {
            let mut stats = flight.stats.lock().unwrap();
            stats.phase = FlightPhase::Climb;
            stats.block_off_at = Some(Utc::now() - chrono::Duration::minutes(20));
            stats.was_airborne = true;
            if let Some(secs) = dwell_started_secs_ago {
                stats.arrived_fallback_pending_since =
                    Some(Utc::now() - chrono::Duration::seconds(secs));
            }
        }
        flight
    }

    /// `SimSnapshot::default()` is already "parked, engines off, on the
    /// ground" (see its doc comment) — exactly `arrived_fallback_
    /// conditions_basic`'s satisfied state.
    fn arrived_conditions_snap() -> SimSnapshot {
        SimSnapshot::default()
    }

    #[test]
    fn does_not_fire_before_dwell_elapsed() {
        let flight = armed_flight(Some(ARRIVED_FALLBACK_DWELL_SECS - 3));
        let snap = arrived_conditions_snap();
        let result = step_flight(&flight, &snap);
        assert_eq!(result, None);
        assert_eq!(flight.stats.lock().unwrap().phase, FlightPhase::Climb);
        assert!(
            flight
                .stats
                .lock()
                .unwrap()
                .arrived_fallback_pending_since
                .is_some(),
            "the timer keeps running, just hasn't reached the dwell yet"
        );
    }

    #[test]
    fn fires_once_dwell_elapsed() {
        let flight = armed_flight(Some(ARRIVED_FALLBACK_DWELL_SECS + 1));
        let snap = arrived_conditions_snap();
        let result = step_flight(&flight, &snap);
        assert_eq!(result, Some(FlightPhase::Arrived));
        assert_eq!(flight.stats.lock().unwrap().phase, FlightPhase::Arrived);
    }

    #[test]
    fn fires_exactly_at_the_dwell_boundary() {
        // elapsed >= dwell_needed — the boundary itself must fire, not just
        // strictly-greater.
        let flight = armed_flight(Some(ARRIVED_FALLBACK_DWELL_SECS));
        let snap = arrived_conditions_snap();
        let result = step_flight(&flight, &snap);
        assert_eq!(result, Some(FlightPhase::Arrived));
    }

    #[test]
    fn an_interrupting_tick_resets_the_dwell_timer() {
        let flight = armed_flight(Some(ARRIVED_FALLBACK_DWELL_SECS + 1));
        let mut snap_engine_on = arrived_conditions_snap();
        snap_engine_on.engines_running = 1; // stray "still running" sample

        // The condition breaks before the (already-elapsed) dwell is ever
        // checked against a qualifying tick — must reset, not fire.
        let result = step_flight(&flight, &snap_engine_on);
        assert_eq!(result, None);
        assert!(
            flight
                .stats
                .lock()
                .unwrap()
                .arrived_fallback_pending_since
                .is_none(),
            "condition broke — timer must reset"
        );

        // A fresh qualifying tick starts a NEW timer at `now` — does not
        // fire immediately even though the aircraft was "ready" a moment
        // ago, because the interruption discarded that progress.
        let snap_ok = arrived_conditions_snap();
        let result = step_flight(&flight, &snap_ok);
        assert_eq!(result, None);
        assert_eq!(flight.stats.lock().unwrap().phase, FlightPhase::Climb);
    }

    #[test]
    fn standstill_path_uses_its_own_longer_dwell_via_the_shared_timer() {
        // engine_count_unreliable aircraft (Contrail FA50 pattern): stock
        // engines_running is stuck NONZERO, so engines_off_path is false
        // and only standstill_path (no engines_running requirement) can
        // fire — gated by the much longer ARRIVED_STANDSTILL_DWELL_SECS.
        let flight = armed_flight(Some(ARRIVED_FALLBACK_DWELL_SECS + 1));
        let mut snap = arrived_conditions_snap();
        snap.aircraft_profile = sim_core::AircraftProfile::ContrailFa50;
        snap.engines_running = 3; // stuck nonzero — the documented FA50 bug

        // Only ARRIVED_FALLBACK_DWELL_SECS (9s) has elapsed — far short of
        // the standstill path's 300s. Must NOT fire.
        let result = step_flight(&flight, &snap);
        assert_eq!(
            result, None,
            "standstill_path must not borrow engines_off_path's short dwell"
        );

        // Now simulate the full standstill dwell having elapsed.
        {
            let mut stats = flight.stats.lock().unwrap();
            stats.arrived_fallback_pending_since =
                Some(Utc::now() - chrono::Duration::seconds(ARRIVED_STANDSTILL_DWELL_SECS + 1));
        }
        let result = step_flight(&flight, &snap);
        assert_eq!(result, Some(FlightPhase::Arrived));
    }

    #[test]
    fn switching_between_paths_does_not_discard_accumulated_dwell_time() {
        // Regression guard: an aircraft that satisfies engines_off_path on
        // most ticks but standstill_path on an occasional flaky tick (e.g.
        // an unreliable engine counter that isn't permanently stuck, just
        // flaky) must not have its progress wiped by the path switch —
        // both paths share one timer that only resets when BOTH are false.
        // Seeded comfortably PAST the short engines_off_path dwell (9s) but
        // nowhere near the long standstill_path dwell (300s) — tick 1 must
        // stay None (standstill_path's own threshold isn't met), tick 2
        // must fire immediately once engines_off_path becomes active,
        // proving the accumulated time carried over rather than restarting.
        let flight = armed_flight(Some(ARRIVED_FALLBACK_DWELL_SECS + 1));
        let mut snap = arrived_conditions_snap();
        snap.aircraft_profile = sim_core::AircraftProfile::ContrailFa50;
        snap.engines_running = 3; // this tick: only standstill_path qualifies

        // Not enough elapsed yet for standstill_path's 300s dwell.
        let result = step_flight(&flight, &snap);
        assert_eq!(result, None);
        assert!(
            flight
                .stats
                .lock()
                .unwrap()
                .arrived_fallback_pending_since
                .is_some(),
            "standstill_path being active must not clear the shared timer"
        );

        // Next tick: engines_running flickers to 0 (engines_off_path now
        // qualifies instead). The ORIGINAL start time must be preserved —
        // total elapsed is now comfortably over the short engines_off_path
        // dwell, so it fires immediately rather than restarting from 0.
        snap.engines_running = 0;
        let result = step_flight(&flight, &snap);
        assert_eq!(
            result,
            Some(FlightPhase::Arrived),
            "switching to engines_off_path must use the time already accumulated, not restart"
        );
    }
}

#[cfg(test)]
mod enroute_reconcile_tests {
    //! En-Route-Versöhner (Korpus-Audit 2026-07, 632 Flüge) — siehe Doc an
    //! `ENROUTE_RECONCILE_DWELL_SECS`. Diese Tests seeden
    //! `enroute_divergence_since` direkt (gleiches Muster wie
    //! `arrived_fallback_dwell_tests`: `step_flight` liest `Utc::now()`
    //! ohne injizierbare Uhr — seeden statt schlafen). Die v2-Evidenz wird
    //! ECHT aufgebaut (Samples durch die Schatten-Engine), damit die Tests
    //! nicht an Resolver-Interna vorbei konstruieren.

    use super::*;

    fn fixture() -> ActiveFlight {
        ActiveFlight {
            pirep_id: "test-pirep".into(),
            bid_id: 0,
            flight_id: String::new(),
            bid_callsign: None,
            pilot_callsign: None,
            started_at: Utc::now(),
            airline_icao: String::new(),
            planned_registration: String::new(),
            aircraft_icao: "BE24".into(),
            aircraft_name: String::new(),
            flight_number: "22".into(),
            dpt_airport: "EDLN".into(),
            arr_airport: "ZZZZ".into(),
            airline_logo_url: None,
            fares: Vec::new(),
            stats: Mutex::new(FlightStats::new()),
            stop: AtomicBool::new(false),
            was_just_resumed: AtomicBool::new(false),
            streamer_spawned: AtomicBool::new(false),
            cancelled_remotely: AtomicBool::new(false),
            position_outbox: Mutex::new(std::collections::VecDeque::new()),
            phpvms_worker_spawned: AtomicBool::new(false),
            touchdown_sampler_spawned: AtomicBool::new(false),
            connection_state: std::sync::atomic::AtomicU8::new(CONN_STATE_LIVE),
            navdata: Mutex::new(NavdataCache::default()),
        }
    }

    /// Baut ECHTE v2-Fenster-Evidenz auf: `n` Samples im 3-s-Raster durch
    /// die Schatten-Engine, `old_phase` konstant gehalten (wie eine
    /// festgefahrene v1). Endet zeitlich bei ~`Utc::now()`, damit der
    /// nachfolgende `step_flight`-Tick keinen Segmenter-Time-Skip sieht.
    /// Gibt die zuletzt aufgelöste v2-Phase zurück; der Test stempelt sie
    /// — wie der Streamer — nach `stats.shadow_phase`.
    #[allow(clippy::too_many_arguments)]
    fn feed_v2_evidence(
        stats: &mut FlightStats,
        old_phase: FlightPhase,
        n: usize,
        alt0: f64,
        alt_step: f64,
        agl0: f64,
        agl_step: f64,
        vs: f32,
        on_ground: bool,
    ) -> FlightPhase {
        feed_v2_evidence_ending(
            stats, old_phase, n, alt0, alt_step, agl0, agl_step, vs, on_ground, 0,
        )
    }

    /// Wie [`feed_v2_evidence`], aber das Sample-Fenster endet
    /// `end_secs_ago` Sekunden VOR jetzt — für Tests, die zwei Evidenz-
    /// Regime hintereinander füttern (z. B. Sinkflug, dann Level-Off):
    /// zwei Feeds, die beide bei `now` endeten, überlappten sich zeitlich,
    /// und der Segmenter verwürfe die rückdatierten Samples still (Min-
    /// Abstands-Guard gegen rückwärts laufende Zeit).
    #[allow(clippy::too_many_arguments)]
    fn feed_v2_evidence_ending(
        stats: &mut FlightStats,
        old_phase: FlightPhase,
        n: usize,
        alt0: f64,
        alt_step: f64,
        agl0: f64,
        agl_step: f64,
        vs: f32,
        on_ground: bool,
        end_secs_ago: i64,
    ) -> FlightPhase {
        let start =
            Utc::now() - chrono::Duration::seconds(3 * n as i64 + end_secs_ago);
        let mut phase = old_phase;
        for i in 0..n {
            let t = start + chrono::Duration::seconds(3 * i as i64);
            let (p, _) = stats.shadow_engine.step(
                t,
                alt0 + alt_step * i as f64,
                (agl0 + agl_step * i as f64).max(0.0),
                vs,
                on_ground,
                old_phase,
                None,
            );
            phase = p;
        }
        stats.shadow_phase = Some(phase);
        phase
    }

    /// GSG22-Form: v1 hängt auf `Climb`, während der Flieger real längst
    /// sinkt. Snapshot so gewählt, dass JEDER reguläre Climb-Arm-Übergang
    /// still bleibt: V/S −300 (über der −500-standard_tod-Schwelle),
    /// `climb_peak_msl` == aktuelle MSL (lost_from_peak = 0 → low_alt/
    /// near_ground unerreichbar — exakt die Niedrig-Peak-Blockade aus dem
    /// Audit), AGL < 5000 (Cruise-Gate zu).
    fn stuck_climb_flight(divergence_seeded_secs_ago: Option<i64>) -> (ActiveFlight, SimSnapshot) {
        let flight = fixture();
        let mut snap = SimSnapshot::default();
        snap.on_ground = false;
        snap.altitude_msl_ft = 900.0;
        snap.altitude_agl_ft = 800.0;
        snap.vertical_speed_fpm = -300.0;
        snap.groundspeed_kt = 95.0;
        snap.engines_running = 1;
        {
            let mut stats = flight.stats.lock().unwrap();
            stats.phase = FlightPhase::Climb;
            stats.climb_peak_msl = Some(snap.altitude_msl_ft as f32);
            stats.was_airborne = true;
            stats.was_on_ground = Some(false);
            // Sinkende Fenster-Evidenz: −600 fpm über ~2 min → Segment
            // Descending, v2-Phase Descent (von Descent aus gefüttert,
            // Baseline-Sync beim ersten Sample). AGL bleibt über dem
            // 5000-ft-Approach-Gate, damit v2 nicht schon zu Approach
            // weiterbefördert — die Tests wollen das Paar (Climb, Descent).
            let v2 = feed_v2_evidence(
                &mut stats,
                FlightPhase::Descent,
                40,
                9000.0,
                -30.0,
                8000.0,
                -30.0,
                -600.0,
                false,
            );
            assert_eq!(
                v2,
                FlightPhase::Descent,
                "test setup: v2 must resolve a sustained descent as Descent"
            );
            if let Some(secs) = divergence_seeded_secs_ago {
                stats.enroute_divergence_since = Some((
                    FlightPhase::Climb,
                    Utc::now() - chrono::Duration::seconds(secs),
                ));
            }
        }
        (flight, snap)
    }

    // ---- Eignungs-Prüfung (rein) ----

    #[test]
    fn eligible_pairs_within_the_air_band() {
        for (v1, v2) in [
            (FlightPhase::Climb, FlightPhase::Descent),
            (FlightPhase::Climb, FlightPhase::Landing),
            (FlightPhase::Cruise, FlightPhase::Descent),
            (FlightPhase::Descent, FlightPhase::Cruise),
            (FlightPhase::Approach, FlightPhase::Final),
            (FlightPhase::Final, FlightPhase::Landing),
        ] {
            assert!(enroute_reconcile_eligible(v1, v2), "{v1:?} → {v2:?}");
        }
    }

    #[test]
    fn holding_is_never_reconciled() {
        // v2 modelliert Holding bewusst nicht — dort DARF v1 abweichen.
        for v2 in [
            FlightPhase::Climb,
            FlightPhase::Cruise,
            FlightPhase::Descent,
            FlightPhase::Landing,
        ] {
            assert!(!enroute_reconcile_eligible(FlightPhase::Holding, v2));
        }
        // ... und Holding ist auch als ZIEL tabu (v2 erzeugt es nie —
        // defensive Absicherung, falls sich das je ändert).
        assert!(!enroute_reconcile_eligible(FlightPhase::Cruise, FlightPhase::Holding));
    }

    #[test]
    fn ground_and_terminal_v1_phases_are_authoritative() {
        // Außerhalb des Luft-Bands ist v1 die Sync-QUELLE für v2 (1:1-
        // Mirror) — der Versöhner darf dort nie eingreifen. `Landing` als
        // v1 gehört dazu: eine v1, die Landing selbst erreicht hat, ist
        // nicht festgefahren.
        for v1 in [
            FlightPhase::Preflight,
            FlightPhase::Boarding,
            FlightPhase::Pushback,
            FlightPhase::TaxiOut,
            FlightPhase::TakeoffRoll,
            FlightPhase::Takeoff,
            FlightPhase::Landing,
            FlightPhase::TaxiIn,
            FlightPhase::BlocksOn,
            FlightPhase::Arrived,
        ] {
            assert!(!enroute_reconcile_eligible(v1, FlightPhase::Descent), "{v1:?}");
        }
    }

    #[test]
    fn v2_targets_outside_the_air_band_are_taboo() {
        for v2 in [
            FlightPhase::Preflight,
            FlightPhase::Boarding,
            FlightPhase::TaxiIn,
            FlightPhase::BlocksOn,
            FlightPhase::Arrived,
        ] {
            assert!(!enroute_reconcile_eligible(FlightPhase::Climb, v2), "{v2:?}");
        }
    }

    #[test]
    fn agreement_is_not_divergence() {
        for p in [
            FlightPhase::Climb,
            FlightPhase::Cruise,
            FlightPhase::Descent,
            FlightPhase::Approach,
            FlightPhase::Final,
        ] {
            assert!(!enroute_reconcile_eligible(p, p));
        }
    }

    #[test]
    fn contradiction_gate_matrix() {
        use phase_v2::Segment;
        // Climb: nur ein sinkendes oder bodenständiges Fenster widerlegt
        // einen Steigflug — nie Level (TOC-Wartezeit, Restrictions) oder
        // Climbing (er steigt ja gerade, per Definition kein Widerspruch).
        assert!(segment_contradicts_v1(FlightPhase::Climb, Segment::Descending));
        assert!(segment_contradicts_v1(FlightPhase::Climb, Segment::Ground));
        assert!(!segment_contradicts_v1(FlightPhase::Climb, Segment::Climbing));
        assert!(!segment_contradicts_v1(FlightPhase::Climb, Segment::Level));
        assert!(!segment_contradicts_v1(FlightPhase::Climb, Segment::Insufficient));

        // Cruise: BEWUSST nur Ground (Absurditäts-Guard). NICHT Descending
        // — v1s eigener single-tick −500-fpm-Trigger deckt jeden echten
        // TOD ab (0/632 Flüge im Korpus je in Cruise festgefahren); ein
        // Zug bei Descending erzeugte in QS-Runde 1 den bewiesenen Pull/
        // Recovery-Zyklus bei ATC-Step-Downs. Diese Zeile hält die
        // Absicht fest — NICHT versehentlich auf Descending erweitern.
        assert!(segment_contradicts_v1(FlightPhase::Cruise, Segment::Ground));
        assert!(!segment_contradicts_v1(FlightPhase::Cruise, Segment::Descending));
        assert!(!segment_contradicts_v1(FlightPhase::Cruise, Segment::Climbing));
        assert!(!segment_contradicts_v1(FlightPhase::Cruise, Segment::Level));

        // Descent/Approach/Final: nur ein steigendes oder bodenständiges
        // Fenster widerlegt sie (GSG-105-Klasse + verpasster Go-Around /
        // verpasste Touchdown-Kante) — nie Level (Zwischen-Level-Off,
        // v1s B-003-Recovery übernimmt eigenständig bei |V/S|<200) oder
        // Descending (konsistent mit der eigenen Phase).
        for p in [FlightPhase::Descent, FlightPhase::Approach, FlightPhase::Final] {
            assert!(segment_contradicts_v1(p, Segment::Climbing), "{p:?}");
            assert!(segment_contradicts_v1(p, Segment::Ground), "{p:?}");
            assert!(!segment_contradicts_v1(p, Segment::Descending), "{p:?}");
            assert!(!segment_contradicts_v1(p, Segment::Level), "{p:?}");
        }

        // Außerhalb des Luft-Bands (z. B. Holding) widerspricht nichts —
        // der Versöhner ist dort ohnehin nicht eligible.
        assert!(!segment_contradicts_v1(FlightPhase::Holding, Segment::Descending));
    }

    #[test]
    fn cruise_with_sustained_descending_evidence_is_never_pulled() {
        // Absurditäts-Guard, integrationsscharf: selbst eine lange (weit
        // über jedem Dwell liegende), durchgehend bestätigte Descending-
        // Evidenz darf ein Cruise NIE über den Versöhner nach Descent
        // ziehen — das ist v1s eigenem single-tick-Trigger vorbehalten
        // (Absicht siehe contradiction_gate_matrix). Snapshot selbst hält
        // v1s Trigger bewusst still (vs>−500, AGL fern von Boden, kein
        // 5000-ft-Verlust seit Peak).
        let flight = fixture();
        let mut snap = SimSnapshot::default();
        snap.on_ground = false;
        snap.altitude_msl_ft = 33000.0;
        snap.altitude_agl_ft = 32000.0;
        snap.vertical_speed_fpm = -480.0; // knapp unter v1s -500-Schwelle
        snap.groundspeed_kt = 400.0;
        snap.engines_running = 2;
        {
            let mut stats = flight.stats.lock().unwrap();
            stats.phase = FlightPhase::Cruise;
            stats.cruise_peak_msl = Some(35000.0); // lost_alt = 2000 < 5000
            stats.was_airborne = true;
            stats.was_on_ground = Some(false);
            let v2 = feed_v2_evidence(
                &mut stats,
                FlightPhase::Descent,
                40,
                35000.0,
                -20.0,
                34000.0,
                -20.0,
                -480.0,
                false,
            );
            assert_eq!(v2, FlightPhase::Descent, "test setup: v2 resolves sustained descent");
            assert_eq!(stats.shadow_engine.current_segment(), phase_v2::Segment::Descending);
            stats.enroute_divergence_since = Some((
                FlightPhase::Cruise,
                Utc::now() - chrono::Duration::seconds(ENROUTE_RECONCILE_DWELL_SECS + 500),
            ));
        }
        let result = step_flight(&flight, &snap);
        assert_eq!(result, None, "Cruise must never be pulled to Descent by the reconciler");
        assert_eq!(flight.stats.lock().unwrap().phase, FlightPhase::Cruise);
    }

    #[test]
    fn pull_direction_follows_the_flight_arc() {
        // Vorwärts (kurzer Dwell): v2 ist im Bogen weiter als v1.
        assert!(enroute_reconcile_is_forward(FlightPhase::Climb, FlightPhase::Descent));
        assert!(enroute_reconcile_is_forward(FlightPhase::Climb, FlightPhase::Landing));
        assert!(enroute_reconcile_is_forward(FlightPhase::Final, FlightPhase::Landing));
        assert!(enroute_reconcile_is_forward(FlightPhase::Cruise, FlightPhase::Approach));
        // Rückwärts (langer Dwell): v2 hängt hinter v1.
        assert!(!enroute_reconcile_is_forward(FlightPhase::Descent, FlightPhase::Cruise));
        assert!(!enroute_reconcile_is_forward(FlightPhase::Final, FlightPhase::Approach));
        assert!(!enroute_reconcile_is_forward(FlightPhase::Cruise, FlightPhase::Climb));
        // Gleichstand ist keine Richtung.
        assert!(!enroute_reconcile_is_forward(FlightPhase::Cruise, FlightPhase::Cruise));
    }

    // ---- Integration über step_flight ----

    #[test]
    fn stuck_climb_with_sustained_v2_descent_reconciles_after_dwell() {
        // Climb→Descent ist VORWÄRTS im Bogen → der kurze Dwell gilt.
        let (flight, snap) = stuck_climb_flight(Some(ENROUTE_RECONCILE_FORWARD_DWELL_SECS + 1));
        {
            // QS-Runde 1: Timer-Hygiene-Assertions nicht-vakuös machen —
            // die Timer ECHT armieren, damit ihr Clear beweisbar am
            // Feuer-Pfad hängt (check_descent_transition nullt
            // descent_pending bei diesem Snapshot ohnehin jeden Tick,
            // die anderen beiden räumt NUR der Versöhner).
            let mut stats = flight.stats.lock().unwrap();
            stats.go_around_climb_pending_since =
                Some(Utc::now() - chrono::Duration::seconds(3));
            stats.touch_and_go_pending_since = Some(Utc::now() - chrono::Duration::seconds(3));
        }
        let result = step_flight(&flight, &snap);
        assert_eq!(result, Some(FlightPhase::Descent));
        let stats = flight.stats.lock().unwrap();
        assert_eq!(stats.phase, FlightPhase::Descent);
        assert!(stats.enroute_divergence_since.is_none(), "fired — clock cleared");
        assert!(
            stats.descent_pending_since.is_none(),
            "primary-path dwell must not carry stale arming into Descent"
        );
        assert!(
            stats.go_around_climb_pending_since.is_none(),
            "a stale armed GA dwell must not survive the pull (false GA on re-entry)"
        );
        assert!(
            stats.touch_and_go_pending_since.is_none(),
            "a stale armed T&G dwell must not survive the pull"
        );
    }

    #[test]
    fn does_not_fire_before_dwell_elapsed() {
        let (flight, snap) = stuck_climb_flight(Some(ENROUTE_RECONCILE_FORWARD_DWELL_SECS - 10));
        let result = step_flight(&flight, &snap);
        assert_eq!(result, None);
        let stats = flight.stats.lock().unwrap();
        assert_eq!(stats.phase, FlightPhase::Climb);
        assert!(
            stats.enroute_divergence_since.is_some(),
            "clock keeps running, just hasn't reached the dwell yet"
        );
    }

    #[test]
    fn backward_pull_needs_the_long_dwell() {
        // GSG-105-Klasse: v1 hängt in Descent (es gibt keinen Descent→
        // Climb-Weg zurück), der Flieger steigt aber real und nachhaltig —
        // das Kinematik-Gate ist erfüllt (Climbing ⊥ Descent). v2 sagt
        // Cruise — RÜCKWÄRTS im Bogen. Der kurze Vorwärts-Dwell darf hier
        // NICHT reichen; erst der lange Dwell feuert.
        fn descent_stuck_flight(seed_secs: i64) -> (ActiveFlight, SimSnapshot) {
            let flight = fixture();
            let mut snap = SimSnapshot::default();
            snap.on_ground = false;
            snap.altitude_msl_ft = 9000.0;
            snap.altitude_agl_ft = 8000.0;
            // +800 fpm: hält BEIDE Descent-Arm-Pfade still (Approach
            // braucht vs<0, die B-003-Cruise-Recovery |vs|<200).
            snap.vertical_speed_fpm = 800.0;
            snap.groundspeed_kt = 250.0;
            snap.engines_running = 2;
            {
                let mut stats = flight.stats.lock().unwrap();
                stats.phase = FlightPhase::Descent;
                stats.was_airborne = true;
                stats.was_on_ground = Some(false);
                // Steigende Fenster-Evidenz (+800 fpm) → Segment Climbing;
                // v2 promotet aus Cruise heraus auf Climb → Ziel = Climb,
                // Rang 0 < 2 = rückwärts.
                let v2 = feed_v2_evidence(
                    &mut stats,
                    FlightPhase::Cruise,
                    40,
                    7000.0,
                    40.0,
                    6000.0,
                    40.0,
                    800.0,
                    false,
                );
                assert_eq!(v2, FlightPhase::Climb, "test setup: v2 resolves the sustained climb");
                assert_eq!(
                    stats.shadow_engine.current_segment(),
                    phase_v2::Segment::Climbing,
                    "test setup: sustained climb evidence"
                );
                stats.enroute_divergence_since = Some((
                    FlightPhase::Descent,
                    Utc::now() - chrono::Duration::seconds(seed_secs),
                ));
            }
            (flight, snap)
        }

        // Vorwärts-Dwell überschritten, Rückwärts-Dwell nicht → kein Zug.
        let (flight, snap) = descent_stuck_flight(ENROUTE_RECONCILE_FORWARD_DWELL_SECS + 1);
        let result = step_flight(&flight, &snap);
        assert_eq!(result, None, "backward pull must not borrow the short forward dwell");
        assert_eq!(flight.stats.lock().unwrap().phase, FlightPhase::Descent);

        // Rückwärts-Dwell voll → jetzt zieht v2 die festgefahrene v1.
        let (flight, snap) = descent_stuck_flight(ENROUTE_RECONCILE_DWELL_SECS + 1);
        let result = step_flight(&flight, &snap);
        assert_eq!(result, Some(FlightPhase::Climb));
    }

    // ---- QS-Runde 1: Anti-Oszillations-Gate (segment_contradicts_v1) ----

    #[test]
    fn atc_step_down_level_off_is_never_pulled() {
        // QS-Befund F1a (empirisch bewiesen): ATC-Step-Down, dann Level —
        // v1 bleibt by design Cruise, v2 hält unterhalb obsref−2000 ft
        // BEWUSST Descent. Ohne Kinematik-Gate zog der Versöhner v1 alle
        // ~55 s in einen Pull/Recovery-Zyklus. Level widerspricht Cruise
        // NICHT → kein Zug, Uhr wird verworfen.
        let flight = fixture();
        let mut snap = SimSnapshot::default();
        snap.on_ground = false;
        snap.altitude_msl_ft = 7500.0;
        snap.altitude_agl_ft = 6500.0;
        snap.vertical_speed_fpm = -50.0;
        snap.groundspeed_kt = 280.0;
        snap.engines_running = 2;
        {
            let mut stats = flight.stats.lock().unwrap();
            stats.phase = FlightPhase::Cruise;
            stats.was_airborne = true;
            stats.was_on_ground = Some(false);
            // Sinkflug 10000→7500 (endet vor 90 s), dann Level-Hold bei
            // 7500 (< obsref −2000) → v2 bleibt Descent, Segment kippt
            // auf Level.
            feed_v2_evidence_ending(
                &mut stats,
                FlightPhase::Descent,
                30,
                10000.0,
                -85.0,
                9000.0,
                -85.0,
                -1500.0,
                false,
                90,
            );
            let v2 = feed_v2_evidence(
                &mut stats,
                FlightPhase::Descent,
                30,
                7500.0,
                0.0,
                6500.0,
                0.0,
                0.0,
                false,
            );
            assert_eq!(v2, FlightPhase::Descent, "test setup: v2 holds Descent on level-off");
            assert_eq!(
                stats.shadow_engine.current_segment(),
                phase_v2::Segment::Level,
                "test setup: level evidence"
            );
            stats.enroute_divergence_since = Some((
                FlightPhase::Cruise,
                Utc::now() - chrono::Duration::seconds(ENROUTE_RECONCILE_DWELL_SECS + 100),
            ));
        }
        let result = step_flight(&flight, &snap);
        assert_eq!(result, None, "a healthy level Cruise must never be pulled");
        let stats = flight.stats.lock().unwrap();
        assert_eq!(stats.phase, FlightPhase::Cruise);
        assert!(stats.enroute_divergence_since.is_none(), "no contradiction — clock discarded");
    }

    #[test]
    fn toc_healthy_cruise_without_ref_is_never_pulled_back() {
        // QS-Befund F1c (empirisch bewiesen): Top-of-Climb ohne cruise_ref
        // — v1 latcht Cruise single-tick, v2 braucht 240 s Level-Dauer-
        // Heuristik → bis zu ~285 s gewollte Divergenz (Cruise, Climb).
        // Ohne Kinematik-Gate: deterministischer Rückzug + Oszillation an
        // JEDEM normalen TOC. Level widerspricht Cruise nicht → kein Zug.
        let flight = fixture();
        let mut snap = SimSnapshot::default();
        snap.on_ground = false;
        snap.altitude_msl_ft = 36000.0;
        snap.altitude_agl_ft = 35000.0;
        snap.vertical_speed_fpm = -20.0;
        snap.groundspeed_kt = 480.0;
        snap.engines_running = 2;
        {
            let mut stats = flight.stats.lock().unwrap();
            stats.phase = FlightPhase::Cruise;
            stats.was_airborne = true;
            stats.was_on_ground = Some(false);
            // 2 min Level-Evidenz (< 240 s) mit old=Climb → v2 hält Climb.
            let v2 = feed_v2_evidence(
                &mut stats,
                FlightPhase::Climb,
                40,
                36000.0,
                0.0,
                35000.0,
                0.0,
                0.0,
                false,
            );
            assert_eq!(v2, FlightPhase::Climb, "test setup: v2 still on Climb before 240s");
            stats.enroute_divergence_since = Some((
                FlightPhase::Cruise,
                Utc::now() - chrono::Duration::seconds(ENROUTE_RECONCILE_DWELL_SECS + 100),
            ));
        }
        let result = step_flight(&flight, &snap);
        assert_eq!(result, None, "healthy TOC cruise must never be pulled back to Climb");
        assert_eq!(flight.stats.lock().unwrap().phase, FlightPhase::Cruise);
    }

    #[test]
    fn ga_climbout_is_never_pulled_back_into_the_approach() {
        // QS-Befund F3: v1 klassifiziert einen Go-Around korrekt (→Climb),
        // v2 hält Final bis +700 ft Bestätigung — bei langsamen Steigern
        // u. U. minutenlang. (Climb, Final) wäre „vorwärts" (45 s) — aber
        // Climbing widerspricht Climb NICHT → kein Rückzug in den Anflug,
        // keine GA-Doppelzählung.
        let flight = fixture();
        let mut snap = SimSnapshot::default();
        snap.on_ground = false;
        snap.altitude_msl_ft = 1400.0;
        snap.altitude_agl_ft = 900.0;
        snap.vertical_speed_fpm = 450.0;
        snap.groundspeed_kt = 120.0;
        snap.engines_running = 1;
        {
            let mut stats = flight.stats.lock().unwrap();
            stats.phase = FlightPhase::Climb;
            stats.climb_peak_msl = Some(snap.altitude_msl_ft as f32);
            stats.was_airborne = true;
            stats.was_on_ground = Some(false);
            // Steigende Evidenz (+400 fpm, +500 ft gesamt — unter der
            // 700-ft-GA-Bestätigung) mit old=Final → v2 hält Final.
            let v2 = feed_v2_evidence(
                &mut stats,
                FlightPhase::Final,
                25,
                900.0,
                20.0,
                400.0,
                20.0,
                400.0,
                false,
            );
            assert_eq!(v2, FlightPhase::Final, "test setup: v2 still holds Final during climb-out");
            assert_eq!(
                stats.shadow_engine.current_segment(),
                phase_v2::Segment::Climbing,
                "test setup: climbing evidence"
            );
            stats.enroute_divergence_since = Some((
                FlightPhase::Climb,
                Utc::now() - chrono::Duration::seconds(ENROUTE_RECONCILE_DWELL_SECS + 100),
            ));
        }
        let result = step_flight(&flight, &snap);
        assert_eq!(result, None, "a genuine climb-out must never be pulled back to Final");
        assert_eq!(flight.stats.lock().unwrap().phase, FlightPhase::Climb);
    }

    #[test]
    fn paused_tick_resets_the_clock() {
        // QS-Befund (Pause-Loch): die Uhr ist Wanduhr; eine Sim-Pause
        // unter der Reload-Gap-Schwelle (Cruise: bis 150 s!) liefe sonst
        // voll in den Dwell. Pause unterbricht die Beobachtung → Reset.
        let (flight, mut snap) = stuck_climb_flight(Some(ENROUTE_RECONCILE_FORWARD_DWELL_SECS + 1));
        snap.paused = true;
        let result = step_flight(&flight, &snap);
        assert_eq!(result, None);
        assert!(
            flight.stats.lock().unwrap().enroute_divergence_since.is_none(),
            "a paused tick must discard the divergence clock"
        );
    }

    #[test]
    fn fires_exactly_at_the_dwell_boundary() {
        // >= — die Grenze selbst muss feuern (QS-Runde 1: Mutation >= → >
        // überlebte die Suite; dieser Test tötet sie).
        let (flight, snap) = stuck_climb_flight(Some(ENROUTE_RECONCILE_FORWARD_DWELL_SECS));
        let result = step_flight(&flight, &snap);
        assert_eq!(result, Some(FlightPhase::Descent));
    }

    #[test]
    fn first_divergent_tick_only_arms_the_clock() {
        let (flight, snap) = stuck_climb_flight(None);
        let result = step_flight(&flight, &snap);
        assert_eq!(result, None);
        let stats = flight.stats.lock().unwrap();
        let (p1, since) = stats
            .enroute_divergence_since
            .expect("first divergent tick must arm the clock");
        assert_eq!(p1, FlightPhase::Climb);
        assert!((Utc::now() - since).num_seconds() < 5, "armed at ~now");
    }

    #[test]
    fn insufficient_evidence_resets_the_clock() {
        // Frisch resettete Schatten-Engine (Reload/Time-Skip): v2s Phase
        // steht zwar noch auf Descent, aber ohne aktuelle Fenster-Evidenz
        // (`Insufficient`) darf der Versöhner weder feuern noch die Uhr
        // weiterlaufen lassen.
        let (flight, snap) = stuck_climb_flight(Some(ENROUTE_RECONCILE_DWELL_SECS + 100));
        {
            let mut stats = flight.stats.lock().unwrap();
            stats.shadow_engine = phase_v2::ShadowPhaseEngine::default();
            stats.shadow_phase = Some(FlightPhase::Descent);
        }
        let result = step_flight(&flight, &snap);
        assert_eq!(result, None);
        let stats = flight.stats.lock().unwrap();
        assert_eq!(stats.phase, FlightPhase::Climb);
        assert!(
            stats.enroute_divergence_since.is_none(),
            "no evidence — clock must reset, not idle along"
        );
    }

    #[test]
    fn v2_progress_during_the_dwell_does_not_restart_the_clock() {
        // Replay-Befund BE24: eine paar-gekoppelte Uhr startete bei jedem
        // legitimen v2-Evidenz-Fortschritt (Descent→Approach→Final auf
        // kurzen, flachen Anflügen) neu und feuerte erst NACH dem
        // Touchdown. Die Uhr hängt deshalb an v1s STILLSTAND: hier wurde
        // sie (irgendwann, mit damals anderem v2-Wert) für das
        // festgefahrene Climb gestartet — v2 zeigt inzwischen Descent.
        // Der abgelaufene Dwell muss auf v2s AKTUELLE Phase ziehen.
        let (flight, snap) = stuck_climb_flight(Some(ENROUTE_RECONCILE_DWELL_SECS + 1));
        let result = step_flight(&flight, &snap);
        assert_eq!(
            result,
            Some(FlightPhase::Descent),
            "v1's standstill is what counts — v2 wandering must not reset the dwell"
        );
    }

    #[test]
    fn stale_clock_from_another_v1_phase_re_arms() {
        // Die gespeicherte Uhr gehört zu einer ANDEREN v1-Phase (Cruise) —
        // z. B. weil v1 über einen Pfad gewechselt hat, der den normalen
        // Commit umgeht (v0.13.17-Airborne-Rescue early return, Resume-
        // Restore). Sie darf nicht für das jetzige Climb weiterzählen.
        let (flight, snap) = stuck_climb_flight(None);
        {
            let mut stats = flight.stats.lock().unwrap();
            stats.enroute_divergence_since = Some((
                FlightPhase::Cruise,
                Utc::now() - chrono::Duration::seconds(ENROUTE_RECONCILE_DWELL_SECS + 500),
            ));
        }
        let result = step_flight(&flight, &snap);
        assert_eq!(result, None, "a clock armed for another v1 phase must not fire");
        let stats = flight.stats.lock().unwrap();
        let (p1, since) = stats.enroute_divergence_since.expect("re-armed");
        assert_eq!(p1, FlightPhase::Climb);
        assert!((Utc::now() - since).num_seconds() < 5, "fresh clock");
    }

    #[test]
    fn fresh_v1_transition_wins_and_resets_the_clock() {
        // v1 lebt: ihr eigener Climb→Cruise-Übergang feuert diesen Tick
        // (V/S ±0, AGL > 5000). Der Versöhner — obwohl sein Dwell längst
        // um wäre — darf den Normalpfad weder übersteuern noch seine Uhr
        // behalten.
        let (flight, mut snap) = stuck_climb_flight(Some(ENROUTE_RECONCILE_DWELL_SECS + 100));
        snap.vertical_speed_fpm = -50.0;
        snap.altitude_agl_ft = 6000.0;
        snap.altitude_msl_ft = 7000.0;
        {
            // Peak nachziehen, damit der Descent-Primärpfad still bleibt.
            let mut stats = flight.stats.lock().unwrap();
            stats.climb_peak_msl = Some(snap.altitude_msl_ft as f32);
        }
        let result = step_flight(&flight, &snap);
        assert_eq!(result, Some(FlightPhase::Cruise), "the normal path always wins");
        let stats = flight.stats.lock().unwrap();
        assert!(
            stats.enroute_divergence_since.is_none(),
            "a live v1 transition restarts the divergence clock"
        );
    }

    #[test]
    fn reload_glitch_tick_neither_fires_nor_keeps_the_clock() {
        let (flight, snap) = stuck_climb_flight(Some(ENROUTE_RECONCILE_DWELL_SECS + 100));
        {
            // 60 s Lücke seit dem letzten Tick — weit über dem Reload-
            // Verdacht (2.5 × 10 s Climb-Intervall).
            let mut stats = flight.stats.lock().unwrap();
            stats.last_step_at = Some(Utc::now() - chrono::Duration::seconds(60));
        }
        let result = step_flight(&flight, &snap);
        assert_eq!(result, None);
        let stats = flight.stats.lock().unwrap();
        assert_eq!(stats.phase, FlightPhase::Climb);
        assert!(
            stats.enroute_divergence_since.is_none(),
            "glitch tick restarts the clock"
        );
    }

    #[test]
    fn stuck_climb_on_the_ground_is_pulled_to_v2_landing() {
        // GSG22-Endzustand: v1 hing noch auf Climb, als der Flieger längst
        // ausrollte; v2 hatte sich per Ground-Evidenz auf Landing
        // selbstbefördert (v0.19.1). Der Versöhner zieht v1 nach Landing —
        // ab dort läuft v1s EIGENE Landing→TaxiIn→BlocksOn→Arrived-Kette
        // normal weiter, statt dass erst der Not-Arrived-Fallback greift.
        let flight = fixture();
        let mut snap = SimSnapshot::default();
        snap.on_ground = true;
        snap.altitude_msl_ft = 120.0;
        snap.altitude_agl_ft = 0.0;
        snap.vertical_speed_fpm = 0.0;
        snap.groundspeed_kt = 25.0; // Rollout — Arrived-Fallback bleibt still
        snap.engines_running = 1;
        {
            let mut stats = flight.stats.lock().unwrap();
            stats.phase = FlightPhase::Climb;
            stats.climb_peak_msl = Some(snap.altitude_msl_ft as f32);
            stats.was_airborne = true;
            stats.was_on_ground = Some(true);
            // Für den landing_at-Rescue (QS-Runde 1): der Flug ist real
            // gestartet, der 50-Hz-Sampler hat den Touchdown gelatcht.
            stats.takeoff_at = Some(Utc::now() - chrono::Duration::minutes(10));
            stats.sampler_touchdown_at = Some(Utc::now() - chrono::Duration::seconds(30));
            stats.sampler_touchdown_vs_fpm = Some(-320.0);
            let v2 = feed_v2_evidence(
                &mut stats,
                FlightPhase::Landing,
                40,
                120.0,
                0.0,
                0.0,
                0.0,
                0.0,
                true,
            );
            assert_eq!(
                v2,
                FlightPhase::Landing,
                "test setup: old=Landing is mirrored 1:1 while ground evidence accumulates"
            );
            stats.enroute_divergence_since = Some((
                FlightPhase::Climb,
                Utc::now() - chrono::Duration::seconds(ENROUTE_RECONCILE_DWELL_SECS + 1),
            ));
        }
        let result = step_flight(&flight, &snap);
        assert_eq!(result, Some(FlightPhase::Landing));
        let stats = flight.stats.lock().unwrap();
        assert_eq!(stats.phase, FlightPhase::Landing);
        // QS-Runde 1 (HIGH): der Zug auf Landing überspringt die Final→
        // Landing-Kante — landing_at MUSS aus dem Sampler gerettet werden,
        // sonst: aufgeblähte flight_time, kein LandingRecord, toter
        // Landing-Arm-Analyzer, is_finalizable=false.
        assert_eq!(stats.landing_at, stats.sampler_touchdown_at);
        assert_eq!(stats.landing_rate_fpm, Some(-320.0));
    }

    #[test]
    fn landing_pull_requires_raw_on_ground_this_tick() {
        // QS-Runde 1 (HIGH): v2=Landing stammt aus fensterträger Ground-
        // Mehrheit — hebt der Flieger im Versatz-Tick wieder ab (Balked
        // Landing), würde ein Luft-Zug auf Landing beide Engines unlösbar
        // festnageln. Rohes on_ground=false ⇒ kein Landing-Zug.
        let flight = fixture();
        let mut snap = SimSnapshot::default();
        snap.on_ground = false; // wieder in der Luft
        snap.altitude_msl_ft = 200.0;
        snap.altitude_agl_ft = 80.0;
        snap.vertical_speed_fpm = 900.0;
        snap.groundspeed_kt = 130.0;
        snap.engines_running = 1;
        {
            let mut stats = flight.stats.lock().unwrap();
            stats.phase = FlightPhase::Climb;
            stats.climb_peak_msl = Some(snap.altitude_msl_ft as f32);
            stats.was_airborne = true;
            stats.was_on_ground = Some(false);
            let v2 = feed_v2_evidence(
                &mut stats,
                FlightPhase::Landing,
                40,
                120.0,
                0.0,
                0.0,
                0.0,
                0.0,
                true,
            );
            assert_eq!(v2, FlightPhase::Landing, "test setup: v2 still says Landing");
            stats.enroute_divergence_since = Some((
                FlightPhase::Climb,
                Utc::now() - chrono::Duration::seconds(ENROUTE_RECONCILE_DWELL_SECS + 100),
            ));
        }
        let result = step_flight(&flight, &snap);
        assert_eq!(result, None, "no Landing pull while airborne");
        assert_eq!(flight.stats.lock().unwrap().phase, FlightPhase::Climb);
    }
}

#[cfg(test)]
mod enroute_reconcile_replay_tests {
    //! End-to-End-Replay der ECHTEN Flug-Logs aus dem Korpus-Audit 2026-07
    //! durch die komplette v1-FSM (`step_flight_at`, historische Uhr) plus
    //! Schatten-Engine — exakt in der Kopplung des Streamer-Ticks (v1
    //! zuerst, dann v2 mit der Post-Step-Phase als Sync-Quelle, Ergebnis
    //! nach `stats.shadow_phase` gestempelt, wo der Versöhner des
    //! NÄCHSTEN Ticks es liest).
    //!
    //! Fixtures (Dateinamen ohne Callsigns, Konvention wie phase_*):
    //!   * `phase_stuck_climb_be24.jsonl.gz` — der Feld-Report-Flug
    //!     (GSG22-Klasse): v1 blieb historisch von 15:00 bis zum Not-
    //!     Arrived-Fallback auf `Climb` (die `lost_from_peak`-Schwellen
    //!     sind bei 883 ft Peak-AGL mathematisch unerreichbar). Erwartung
    //!     NEU: der Versöhner zieht v1 noch IN DER LUFT aus `Climb`, und
    //!     der Flug endet über die normale Terminal-Kette.
    //!   * `phase_stuck_climb_c172.jsonl.gz` — Ultra-Low-Bush-Hop (Peak
    //!     357 ft AGL, Median 135 ft): v1 bleibt by-design in `Takeoff`
    //!     (500-ft-Climb-Gate nie erreicht), v2 spiegelt Takeoff 1:1 —
    //!     der Versöhner hat hier NICHTS zu tun und darf keine En-Route-
    //!     Phasen erfinden (Negativ-/Regressions-Beleg).

    use super::*;
    use flate2::read::GzDecoder;
    use std::io::{BufRead, BufReader};

    fn fixture_path(name: &str) -> std::path::PathBuf {
        let mut p = std::path::PathBuf::from(env!("CARGO_MANIFEST_DIR"));
        p.push("tests");
        p.push("fixtures");
        p.push(name);
        p
    }

    struct ReplaySample {
        t: DateTime<Utc>,
        snap: SimSnapshot,
    }

    /// Positions-Events laden. Bewusst KEINE volle SimSnapshot-
    /// Deserialisierung (ältere Logs kennen neuere Pflichtfelder nicht) —
    /// Default + gezielte Overrides der Felder, die die durchlaufenen
    /// FSM-Arme konsultieren.
    fn load_positions(name: &str) -> Vec<ReplaySample> {
        let f = std::fs::File::open(fixture_path(name)).expect("fixture file");
        let r = BufReader::new(GzDecoder::new(f));
        let mut out = Vec::new();
        for line in r.lines() {
            let Ok(line) = line else { continue };
            let Ok(v) = serde_json::from_str::<serde_json::Value>(&line) else { continue };
            if v["type"].as_str() != Some("position") {
                continue;
            }
            let Some(t) = v["timestamp"]
                .as_str()
                .and_then(|s| DateTime::parse_from_rfc3339(s).ok())
                .map(|d| d.with_timezone(&Utc))
            else {
                continue;
            };
            let s = &v["snapshot"];
            let mut snap = SimSnapshot::default();
            macro_rules! f64_field {
                ($field:ident) => {
                    if let Some(x) = s[stringify!($field)].as_f64() {
                        snap.$field = x;
                    }
                };
            }
            macro_rules! f32_field {
                ($field:ident) => {
                    if let Some(x) = s[stringify!($field)].as_f64() {
                        snap.$field = x as f32;
                    }
                };
            }
            f64_field!(lat);
            f64_field!(lon);
            f64_field!(altitude_msl_ft);
            f64_field!(altitude_agl_ft);
            f32_field!(vertical_speed_fpm);
            f32_field!(groundspeed_kt);
            f32_field!(fuel_total_kg);
            f32_field!(pitch_deg);
            f32_field!(bank_deg);
            if let Some(x) = s["on_ground"].as_bool() {
                snap.on_ground = x;
            }
            if let Some(x) = s["paused"].as_bool() {
                snap.paused = x;
            }
            if let Some(x) = s["slew_mode"].as_bool() {
                snap.slew_mode = x;
            }
            if let Some(x) = s["parking_brake"].as_bool() {
                snap.parking_brake = x;
            }
            if let Some(x) = s["engines_running"].as_u64() {
                snap.engines_running = x as u8;
            }
            snap.pushback_state = s["pushback_state"].as_u64().map(|x| x as u8);
            snap.velocity_body_z_fps = s["velocity_body_z_fps"].as_f64().map(|x| x as f32);
            snap.total_weight_kg = s["total_weight_kg"].as_f64().map(|x| x as f32);
            snap.zfw_kg = s["zfw_kg"].as_f64().map(|x| x as f32);
            snap.aircraft_icao = s["aircraft_icao"].as_str().map(str::to_owned);
            out.push(ReplaySample { t, snap });
        }
        out
    }

    fn replay_fixture() -> ActiveFlight {
        ActiveFlight {
            pirep_id: "replay".into(),
            bid_id: 0,
            flight_id: String::new(),
            bid_callsign: None,
            pilot_callsign: None,
            started_at: Utc::now(),
            airline_icao: String::new(),
            planned_registration: String::new(),
            aircraft_icao: String::new(),
            aircraft_name: String::new(),
            flight_number: "22".into(),
            dpt_airport: "EDLN".into(),
            // Absichtlich nicht im (leeren) Navdata-Cache auflösbar —
            // `near_planned` kurzschließt dann zu true (gleiche Isolation
            // wie in arrived_fallback_dwell_tests; Distanz-Geometrie ist
            // dort separat abgedeckt).
            arr_airport: "ZZZZ".into(),
            airline_logo_url: None,
            fares: Vec::new(),
            stats: Mutex::new(FlightStats::new()),
            stop: AtomicBool::new(false),
            was_just_resumed: AtomicBool::new(false),
            streamer_spawned: AtomicBool::new(false),
            cancelled_remotely: AtomicBool::new(false),
            position_outbox: Mutex::new(std::collections::VecDeque::new()),
            phpvms_worker_spawned: AtomicBool::new(false),
            touchdown_sampler_spawned: AtomicBool::new(false),
            connection_state: std::sync::atomic::AtomicU8::new(CONN_STATE_LIVE),
            navdata: Mutex::new(NavdataCache::default()),
        }
    }

    /// Replayt ein Fixture durch v1+v2 in Streamer-Kopplung und liefert
    /// den v1-Phasen-Bogen als (Zeitpunkt, Phase)-Transitions-Liste.
    fn run_v1_arc(name: &str) -> Vec<(DateTime<Utc>, FlightPhase)> {
        let samples = load_positions(name);
        assert!(samples.len() > 100, "fixture must carry real telemetry");
        let flight = replay_fixture();
        let mut arc: Vec<(DateTime<Utc>, FlightPhase)> = Vec::new();
        for ReplaySample { t, snap } in samples {
            if let Some(p) = step_flight_at(&flight, &snap, t) {
                arc.push((t, p));
            }
            if !snap.paused && !snap.slew_mode {
                let mut stats = flight.stats.lock().unwrap();
                let old_phase_post_step = stats.phase;
                let (shadow, _seg) = stats.shadow_engine.step(
                    t,
                    snap.altitude_msl_ft,
                    snap.altitude_agl_ft,
                    snap.vertical_speed_fpm,
                    snap.on_ground,
                    old_phase_post_step,
                    None,
                );
                stats.shadow_phase = Some(shadow);
                stats.shadow_segment = Some(_seg);
            }
        }
        arc
    }

    #[test]
    fn be24_field_report_flight_leaves_climb_in_the_air_and_lands_normally() {
        // Historisch (echtes Log): Climb ab 15:00:39, dann NICHTS mehr bis
        // der Not-Arrived-Fallback um 15:15:16 zuschlug — Touchdown war
        // 15:11:13. Mit dem Versöhner muss v1 den Climb VOR dem Touchdown
        // verlassen und der Flug über die reguläre Kette enden.
        let arc = run_v1_arc("phase_stuck_climb_be24.jsonl.gz");
        let touchdown =
            DateTime::parse_from_rfc3339("2026-07-11T15:11:13.795049900Z")
                .unwrap()
                .with_timezone(&Utc);

        // Abflug-Kette unangetastet (der Versöhner greift erst im
        // Luft-Band): Boarding→TaxiOut→TakeoffRoll→Takeoff→Climb wie im
        // echten Log.
        let phases: Vec<FlightPhase> = arc.iter().map(|(_, p)| *p).collect();
        assert_eq!(
            &phases[..4],
            &[
                FlightPhase::TaxiOut,
                FlightPhase::TakeoffRoll,
                FlightPhase::Takeoff,
                FlightPhase::Climb,
            ],
            "departure chain must replay unchanged; full arc: {phases:?}"
        );

        // Kern-Assertion: v1 verlässt Climb IN DER LUFT (vor Touchdown) —
        // exakt das, was im echten Flug nie passierte.
        let left_climb_at = arc
            .iter()
            .skip_while(|(_, p)| *p != FlightPhase::Climb)
            .skip(1)
            .map(|(t, _)| *t)
            .next()
            .expect("v1 must transition out of Climb somewhere");
        assert!(
            left_climb_at < touchdown,
            "reconciler must pull v1 out of Climb before touchdown \
             (left at {left_climb_at}, touchdown {touchdown}); arc: {phases:?}"
        );

        // Terminal-Kette erreicht (Arrived — egal ob über BlocksOn oder
        // den Fallback; entscheidend ist, dass der Flug regulär endet).
        assert_eq!(
            phases.last(),
            Some(&FlightPhase::Arrived),
            "flight must terminate in Arrived; arc: {phases:?}"
        );
        // ... und die Landung wurde als Phase erlebt, nicht übersprungen.
        assert!(
            phases.contains(&FlightPhase::Landing),
            "the landing must appear as a real phase in the arc: {phases:?}"
        );
    }

    #[test]
    fn c172_ultra_low_bush_hop_stays_untouched_by_the_reconciler() {
        // Peak 357 ft AGL — das 500-ft-Climb-Gate wird nie erreicht, v1
        // bleibt by-design in Takeoff, v2 spiegelt Takeoff 1:1 (kein
        // En-Route-Band, keine Divergenz). Der Versöhner darf hier keine
        // Luft-Phasen erfinden — der Bogen muss dem historischen Verlauf
        // entsprechen (Bush-Hop-Verhalten, Landing-Erfassung läuft seit
        // v0.15.23 ohnehin phasenunabhängig über den Sampler).
        let arc = run_v1_arc("phase_stuck_climb_c172.jsonl.gz");
        let phases: Vec<FlightPhase> = arc.iter().map(|(_, p)| *p).collect();
        for (_, p) in &arc {
            assert!(
                matches!(
                    p,
                    FlightPhase::TaxiOut
                        | FlightPhase::TakeoffRoll
                        | FlightPhase::Takeoff
                        | FlightPhase::Arrived
                ),
                "no invented en-route phase on a sub-gate bush hop; arc: {phases:?}"
            );
        }
        assert_eq!(phases.last(), Some(&FlightPhase::Arrived), "arc: {phases:?}");
    }
}

/// Build the body for an in-flight `POST /api/pireps/{id}/update` call.
/// Used both by the periodic heartbeat (every `HEARTBEAT_INTERVAL`) and by
/// phase-change callbacks. Sends monotonically growing `flight_time` and
/// `distance` so Eloquent always sees the model as dirty and bumps
/// `pireps.updated_at`, which is what the cleanup cron checks.
/// Spec sim-disconnect-auto-resume F3 (Block-Time-Korrektur):
/// Reine Subtraktions-Helper, extrahiert damit Unit-Tests gegen die
/// Saturating-Arithmetik laufen koennen ohne den vollen FlightStats-
/// Snapshot bauen zu muessen.
///
/// Verhalten:
/// - `pause_total_secs <= 0`             → raw_secs unveraendert
/// - `pause_total_secs > i32::MAX`       → clamp auf i32::MAX
/// - `pause_total_secs >= raw_secs`      → 0 (Underflow-Schutz)
/// - sonst                               → `raw_secs - pause_total_secs`
fn flight_time_with_pause_secs(raw_secs: i32, pause_total_secs: i64) -> i32 {
    let pause_secs_i32 = pause_total_secs.clamp(0, i32::MAX as i64) as i32;
    raw_secs.saturating_sub(pause_secs_i32).max(0)
}

fn build_heartbeat_body(
    snap: &SimSnapshot,
    stats: &FlightStats,
    current_phase: FlightPhase,
) -> UpdateBody {
    let now = Utc::now();
    let raw_flight_time_secs = match (stats.takeoff_at, stats.landing_at) {
        (Some(t), Some(l)) if l > t => (l - t).num_seconds().max(0) as i32,
        (Some(t), None) => (now - t).num_seconds().max(0) as i32,
        // Pre-takeoff: fall back to block-off so cancellation cron sees
        // movement during the boarding/taxi period too.
        _ => stats
            .block_off_at
            .map(|b| (now - b).num_seconds().max(0) as i32)
            .unwrap_or(0),
    };
    // Spec sim-disconnect-auto-resume F3 (Block-Time-Korrektur):
    // Pause-Akkumulator von der Wall-Clock-Flugzeit abziehen damit
    // 23 min Sim-Crash oder 30 min MSFS-Esc-Pause nicht als 23/30
    // zusaetzliche Flugminuten im PIREP-Heartbeat landen. Saturating-
    // Arithmetik via Helper.
    let flight_time_secs =
        flight_time_with_pause_secs(raw_flight_time_secs, stats.pause_total_duration_secs);
    // Same fuel arithmetic as the file body: block - remaining, in pounds.
    // Round to whole kg before lb conversion so the live-map / dashboard
    // shows clean integer kg values (no `5890.29 kg` artefacts from the
    // round-trip).
    let fuel_used = match (stats.block_fuel_kg, stats.last_fuel_kg) {
        (Some(b), Some(c)) if b > c => Some(((b - c) as f64).round() * KG_TO_LB),
        _ => None,
    };
    // Prefer the peak altitude observed (matches the FILE-time `level`),
    // but fall back to the current MSL altitude during early climb so the
    // live map shows something sensible before peak gets captured.
    let level = stats
        .peak_altitude_ft
        .map(|ft| ((ft / 100.0).round() * 100.0) as i32)
        .or_else(|| {
            if snap.altitude_msl_ft > 100.0 {
                Some(((snap.altitude_msl_ft / 100.0).round() * 100.0) as i32)
            } else {
                None
            }
        })
        .map(|v| v.max(0));
    // phpVMS' `Pirep::progress_percent` uses PHP's `empty()` to gate
    // the distance/upper_bound division. `empty(0)` AND `empty(null)`
    // are BOTH true in PHP — so the v0.3.0 fix (send `None` when
    // distance < 0.5 nm) never worked: phpVMS still saw null, fell
    // back to upper_bound=1, computed 1/1 = 100 % progress, and
    // showed "Geflogene Route: 100%" during Boarding. Live bug
    // confirmed 2026-05-05 (pilot Michel D. on YBBN→NWWW).
    //
    // Fix: send a tiny non-zero floor (0.001 nm) until real distance
    // accumulates. `empty(0.001)` is false → PHP runs the real
    // division → 0.001 / planned_distance ≈ 0.00..% → displayed as
    // 0 % during boarding, ramps up correctly once we move.
    let distance = Some(stats.distance_nm.max(0.001));
    let flight_time_min = if flight_time_secs >= 60 {
        Some(flight_time_secs / 60)
    } else {
        None
    };
    // v0.3.0: send block_fuel on every heartbeat so phpVMS' live page
    // can compute "Verbleibender Treibstoff = block_fuel − fuel_used"
    // correctly. Without this the missing column defaults to 0 and the
    // remaining-fuel display reads as "−<fuel_used>" (bug reported by
    // pilot on 2026-05-04: "−17008 kg" mid-cruise). Same kg→lb round-
    // trip as fuel_used so the dashboard shows clean integer values.
    let block_fuel = stats
        .block_fuel_kg
        .map(|b| (b as f64).round() * KG_TO_LB);
    UpdateBody {
        state: None,
        source: None,
        status: phase_to_status(current_phase).map(|s| s.to_string()),
        flight_time: flight_time_min,
        distance,
        fuel_used,
        block_fuel,
        level,
        source_name: Some(format!("AeroACARS/{}", env!("CARGO_PKG_VERSION"))),
        notes: None,
        // Always-fresh timestamp so Eloquent sees the row as dirty
        // even on heartbeats where no other field changed (boarding
        // / long stable cruise). See `UpdateBody::updated_at` doc.
        updated_at: Some(now.to_rfc3339()),
        // Heartbeat-only path — divert-finalize fields stay None.
        arr_airport_id: None,
        landing_rate: None,
        score: None,
        submitted_at: None,
        block_on_time: None,
    }
}

/// Handle a 404 from the live PIREP endpoints (positions / update). phpVMS
/// soft-deletes in-flight PIREPs after `acars.live_time` hours of no
/// `updated_at` bump (cron `RemoveExpiredLiveFlights`); when that happens,
/// every subsequent post returns 404 and the streamer would otherwise
/// retry-spam forever. This stops the streamer cleanly and surfaces the
/// situation to the user so they can re-file as a manual PIREP.
fn handle_remote_cancellation(app: &AppHandle, flight: &Arc<ActiveFlight>, source: &str) {
    if flight.cancelled_remotely.swap(true, Ordering::SeqCst) {
        // Already handled by an earlier 404 in the same cycle.
        return;
    }
    // v0.6.0: Outbox leeren — PIREP existiert serverseitig nicht mehr,
    // weiteres POSTen würde 404 liefern. Verhindert orphan-persist im
    // worker-stop-branch.
    flight.position_outbox.lock().expect("position_outbox lock").clear();
    flight.stop.store(true, Ordering::Relaxed);
    log_activity_handle(
        app,
        ActivityLevel::Error,
        "PIREP wurde vom Server gecancelt".to_string(),
        Some(format!(
            "{source} antwortet mit 404 — phpVMS hat den laufenden PIREP entfernt (vermutlich Inaktivitäts-Timeout). Bitte als Manual-PIREP einreichen."
        )),
    );
    // Best-effort UI nudge — the dashboard listens for this and pops the
    // manual-PIREP banner. Failure to emit isn't fatal; the activity-log
    // entry above is the durable signal.
    let payload = serde_json::json!({
        "pirep_id": flight.pirep_id,
        "source": source,
    });
    let _ = tauri::Emitter::emit(app, "pirep_cancelled_remotely", payload.clone());
    // v0.16.0 (#LAN-Remote): fan out to LAN WS subscribers.
    app.state::<AppState>()
        .remote_events
        .send(remote::RemoteEvent::new("pirep_cancelled_remotely", payload));
}

/// Build the custom-fields map sent in `POST /api/pireps/{id}/file`. Field
/// names follow the de-facto vmsACARS convention so VAs that already configured
/// fields for vmsACARS see them populate without any work.
fn build_pirep_fields(
    flight: &ActiveFlight,
    stats: &FlightStats,
    // v0.16.24 (QS-2 FIX A): the EFFECTIVE arrival airport (the
    // pilot-confirmed divert if any, else the planned `arr_airport`) — the
    // same value `build_pirep_payload` / `build_landing_record` pass into the
    // runway trust check. The "Landing Score" custom field below derives its
    // aggregate via `compute_aggregate_master_score`, which trusts the runway
    // geometry only when the matched ICAO equals the effective arrival; passing
    // the planned `arr_airport` here would skip the rollout/LDA sub-score on a
    // divert and disagree with the native `score` + the local record. On-plan
    // this equals `flight.arr_airport` → byte-identical.
    effective_arr_icao: &str,
) -> HashMap<String, String> {
    // Single-form custom-fields set: human-readable Title Case with
    // units. Earlier versions emitted EVERY field twice (Title Case +
    // snake_case "for SQL-sortable leaderboards") which made the
    // PIREP-detail list balloon to 60+ entries with obvious
    // duplicates ("Block Fuel: 9733 kg" right next to "block_fuel_kg:
    // 9733"). VA admins who want raw numbers can hit the database
    // directly — no point doubling everything in the UI.
    //
    // Notes block (separate PIREP field) still carries the prose
    // summary; THIS map carries the structured key-value pairs.
    let mut f: HashMap<String, String> = HashMap::new();

    f.insert(
        "Source".into(),
        format!("AeroACARS/{}", env!("CARGO_PKG_VERSION")),
    );

    // v0.7.19 GAF-707 Accident-Detection: strukturierte Felder fuer den
    // VA-Admin PIREP-Detail-View. Spec §PIREP-Payload.
    f.insert(
        "Accident Classifier Version".into(),
        accident::ACCIDENT_CLASSIFIER_VERSION.into(),
    );
    if stats.accident_detected {
        f.insert("Accident".into(), "TRUE".into());
        if let Some(kind) = stats.accident_kind.as_deref() {
            f.insert("Accident Kind".into(), kind.into());
        }
        if let Some(c) = stats.accident_confidence.as_deref() {
            f.insert("Accident Confidence".into(), c.into());
        }
        if !stats.accident_reasons.is_empty() {
            f.insert(
                "Accident Reasons".into(),
                stats.accident_reasons.join(", "),
            );
        }
        if let Some(t) = stats.accident_at {
            f.insert(
                "Accident Detected At".into(),
                t.format("%H:%M:%S UTC").to_string(),
            );
        }
    }

    // v0.3.0: Aircraft-Type / Name / Reg im PIREP-Custom-Field damit
    // VA-Admins auf der phpVMS-Detail-Seite ohne Lookup wissen was
    // geflogen wurde (vorher nur PMDG-Variant; jetzt für jeden
    // Aircraft-Typ aus dem Bid-Aircraft-Lookup).
    if !flight.aircraft_icao.is_empty() {
        let label = if !flight.aircraft_name.is_empty() {
            format!("{} ({})", flight.aircraft_icao, flight.aircraft_name)
        } else {
            flight.aircraft_icao.clone()
        };
        f.insert("Aircraft Type".into(), label);
    }
    if !flight.planned_registration.is_empty() {
        f.insert("Aircraft Reg".into(), flight.planned_registration.clone());
    }

    // ---- Times (HH:MM:SS UTC, glanceable) + durations ----
    fn fmt_time(t: &DateTime<Utc>) -> String {
        t.format("%H:%M:%S UTC").to_string()
    }
    if let Some(t) = stats.block_off_at {
        f.insert("Blocks Off Time".into(), fmt_time(&t));
    }
    if let Some(t) = stats.takeoff_at {
        f.insert("Takeoff Time".into(), fmt_time(&t));
    }
    if let Some(t) = stats.landing_at {
        f.insert("Landing Time".into(), fmt_time(&t));
    }
    if let Some(t) = stats.block_on_at {
        f.insert("Blocks On Time".into(), fmt_time(&t));
    }
    if let (Some(off), Some(on)) = (stats.block_off_at, stats.block_on_at) {
        f.insert(
            "Total Block Time".into(),
            humanize_duration_minutes((on - off).num_minutes()),
        );
    }
    if let (Some(takeoff), Some(landing)) = (stats.takeoff_at, stats.landing_at) {
        f.insert(
            "Total Flight Time".into(),
            humanize_duration_minutes((landing - takeoff).num_minutes()),
        );
    }
    if let (Some(off), Some(takeoff)) = (stats.block_off_at, stats.takeoff_at) {
        f.insert(
            "Taxi Out Time".into(),
            humanize_duration_minutes((takeoff - off).num_minutes()),
        );
    }
    if let (Some(land), Some(blocks_on)) = (stats.landing_at, stats.block_on_at) {
        f.insert(
            "Taxi In Time".into(),
            humanize_duration_minutes((blocks_on - land).num_minutes()),
        );
    }

    // ---- Weights & fuel (skip 0-value to avoid Fenix-bogus garbage) ----
    if let Some(w) = stats.takeoff_weight_kg.filter(|v| *v > 0.0) {
        f.insert("Takeoff Weight".into(), format!("{:.0} kg", w));
    }
    if let Some(w) = stats.landing_weight_kg.filter(|v| *v > 0.0) {
        f.insert("Landing Weight".into(), format!("{:.0} kg", w));
    }
    if let Some(b) = stats.block_fuel_kg.filter(|v| *v > 0.0) {
        f.insert("Block Fuel".into(), format!("{:.0} kg", b));
    }
    if let Some(fuel) = stats.landing_fuel_kg.filter(|v| *v > 0.0) {
        f.insert("Landing Fuel".into(), format!("{:.0} kg", fuel));
    }
    if let (Some(b), Some(c)) = (stats.block_fuel_kg, stats.last_fuel_kg) {
        if b > 0.0 && b > c {
            f.insert("Fuel Used".into(), format!("{:.0} kg", b - c));
        }
    }

    // ---- Touchdown analysis ----
    // v0.7.1 Round-2 P2-Fix: "Landing Score" Custom-Field nutzt jetzt
    // den Aggregate-Master-Score (gleicher Wert wie App/Web/MQTT/
    // phpVMS-native). Vorher zeigte es den Touchdown-Klassifikator-
    // Score — Pilot sah in der phpVMS-Detailansicht zwei verschiedene
    // Zahlen ("Score: 77/100" oben, "Landing Score: A+ (smooth) —
    // 100/100" unten). Fallback auf Touchdown-Klassifikation wenn
    // Crate keinen Aggregate liefert.
    if let Some(touchdown_class) = stats.landing_score {
        let aggregate = compute_aggregate_master_score(stats, Some(&flight.aircraft_icao), effective_arr_icao);
        let (label, numeric) = match aggregate {
            Some(m) => (aggregate_score_label(m), m as i32),
            None => (touchdown_class.label(), touchdown_class.numeric()),
        };
        let grade = letter_grade(numeric);
        f.insert(
            "Landing Score".into(),
            format!("{} ({}) — {}/100", grade, label, numeric),
        );
    }
    // v0.7.21 (MS713-QS): canonical_landing_rate_fpm() — sonst zeigt
    // das PIREP-Custom-Feld "Landing Rate" einen anderen Wert als das
    // Live-Touchdown und der Pilot-Client.
    if let Some(rate) = stats.canonical_landing_rate_fpm() {
        // SIGNED — negative on descent. Matches both LandingToast and
        // the latched SimVar reading. Pilots want to see the minus.
        //
        // v0.15.14: KEIN Peak-Override mehr. Vorher überschrieb hier
        // `landing_peak_vs_fpm` (= Peak-Sinkrate, z.B. -444) den kanonischen
        // Wert (`rate`, z.B. -264). Folge: das PIREP-Feld "Landing Rate" zeigte
        // -444, während Score + phpVMS-`landing_rate`-Spalte + Live-Map den
        // kanonischen FAR-25.473-Aufsetzwert (-264) nutzten → ZWEI verschiedene
        // Lande-Raten auf derselben PIREP (Live-Report Thomas, GLG2/MGGT mit
        // ausgeprägtem Flare: Edge -264 vs Peak -444). Jetzt durchgängig die
        // kanonische Quelle (= dieselbe wie der Score). Der Peak bleibt als
        // klar beschriftetes Forensik-Detail in der Live-Map sichtbar.
        //
        // v0.5.16: NUMERIC value only (no " fpm" suffix). The
        // FatihKoz/DisposableSpecial dmaintenance plugin reads this
        // field and runs `is_numeric()` against it; "-1641 fpm"
        // returns false there → hard-landing penalty silently
        // skipped. Pure numeric makes the maintenance check work.
        f.insert("Landing Rate".into(), format!("{:.0}", rate));
    }
    if stats.landing_peak_g_force.or(stats.landing_g_force).is_some() {
        // v0.5.16: pure numeric (no " G" suffix). Some maintenance
        // plugins also read this; same is_numeric() reasoning.
        //
        // v0.12.3: das phpVMS-/Wartungs-Feld trägt denselben **gescorten**
        // (EMA, FOQA-Methode) G-Wert wie die Pilot-Anzeige — nicht den
        // rohen 50-Hz-Einzelframe-Peak. Pilot-Anzeige und Maintenance-
        // Penalty-Basis müssen konsistent sein (sonst sieht der Pilot
        // 1.78, das Plugin straft auf 1.95).
        let g = score_g_for_stats(stats).scored_g;
        f.insert("Landing G-Force".into(), format!("{:.2}", g));
    }
    if let Some(p) = stats.landing_pitch_deg {
        // v0.5.16: pure numeric — `landing-pitch` slug is the tail-
        // strike-on-landing trigger in dmaintenance.
        f.insert("Landing Pitch".into(), format!("{:+.1}", p));
    }
    if let Some(b) = stats.landing_bank_deg {
        // v0.5.16: bank at touchdown — `landing-roll` slug is the
        // wing-strike-on-landing trigger in dmaintenance (default
        // limit 15°). Pure numeric.
        f.insert("Landing Roll".into(), format!("{:+.1}", b));
    }
    if let Some(p) = stats.takeoff_pitch_deg {
        // v0.5.16: `takeoff-pitch` slug — tail-strike-on-takeoff
        // trigger in dmaintenance. Pure numeric.
        f.insert("Takeoff Pitch".into(), format!("{:+.1}", p));
    }
    if let Some(b) = stats.takeoff_bank_deg {
        // v0.5.16: `takeoff-roll` slug — wing-strike-on-takeoff
        // trigger in dmaintenance. Pure numeric.
        f.insert("Takeoff Roll".into(), format!("{:+.1}", b));
    }
    if let Some(s) = stats.landing_speed_kt.filter(|v| *v > 0.0) {
        f.insert("Landing Speed".into(), format!("{:.0} kt", s));
    }
    if let Some(h) = stats.landing_heading_deg {
        f.insert("Landing Heading".into(), format!("{:03.0}°", h));
    }
    if let Some(slip) = stats.touchdown_sideslip_deg {
        f.insert("Touchdown Sideslip".into(), format!("{:+.1}°", slip));
    }
    if let Some(hw) = stats.landing_headwind_kt {
        if hw >= 0.0 {
            f.insert("Touchdown Headwind".into(), format!("{:.0} kt", hw));
        } else {
            f.insert("Touchdown Tailwind".into(), format!("{:.0} kt", -hw));
        }
    }
    if let Some(xw) = stats.landing_crosswind_kt {
        let side = if xw >= 0.0 { "from right" } else { "from left" };
        f.insert(
            "Touchdown Crosswind".into(),
            format!("{:.0} kt {}", xw.abs(), side),
        );
    }
    if stats.bounce_count > 0 {
        // Suppress the "Bounces: 0" row — every clean landing had it
        // and it added noise without information.
        f.insert("Bounces".into(), stats.bounce_count.to_string());
    }

    // ---- Touch-and-Go + Go-Around counters (v0.1.26) ----
    // Only surface when nonzero — every routine PIREP has zero of
    // both, no point adding empty rows. The detailed touchdown list
    // (peak V/S + G per event) lives in the Notes prose so it doesn't
    // bloat the structured fields with N rows on a training flight.
    let tg_count = stats
        .touchdown_events
        .iter()
        .filter(|e| matches!(e.kind, TouchdownKind::TouchAndGo))
        .count();
    if tg_count > 0 || stats.touchdown_events.len() > 1 {
        // "Touchdowns: 4 (3 T&G + final)" — gives the VA admin one
        // glanceable line that matches the Notes story.
        let total = stats.touchdown_events.len();
        let suffix = if tg_count == 0 {
            String::new()
        } else if total == tg_count {
            format!(" ({} T&G)", tg_count)
        } else {
            format!(" ({} T&G + final)", tg_count)
        };
        f.insert("Touchdowns".into(), format!("{}{}", total, suffix));
    }
    if stats.go_around_count > 0 {
        f.insert("Go-Arounds".into(), stats.go_around_count.to_string());
    }

    // ---- Approach Stability + Rollout (Landing Analyzer Stage 1) ----
    if let Some(sd) = stats.approach_vs_stddev_fpm {
        f.insert("Approach V/S Stddev".into(), format!("{:.0} fpm", sd));
    }
    if let Some(sd) = stats.approach_bank_stddev_deg {
        f.insert("Approach Bank Stddev".into(), format!("{:.1}°", sd));
    }
    if let Some(meters) = stats.rollout_distance_m {
        // Single field with both units — "935 m (3068 ft)" instead of
        // three separate Rollout Distance / rollout_distance_m /
        // rollout_distance_ft entries.
        f.insert(
            "Rollout Distance".into(),
            format!("{:.0} m ({:.0} ft)", meters, meters * 3.28084),
        );
    }

    // ---- PMDG Premium Telemetry (Phase H.4 / v0.2.0) ----
    // Only emitted when the pilot flew a PMDG aircraft AND had the
    // SDK enabled (so we got real cockpit data). Field names use
    // "PMDG …" prefix so VA admins can filter PIREPs that have
    // premium-telemetry coverage.
    if let Some(label) = stats.pmdg_variant_label.as_deref() {
        f.insert("PMDG Aircraft".into(), label.to_string());
    }
    if let Some(fnum) = stats.pmdg_fmc_flight_number.as_deref().filter(|s| !s.is_empty()) {
        f.insert("PMDG FMC Flight #".into(), fnum.to_string());
    }
    if let Some((v1, vr, v2)) = stats.pmdg_v_speeds_takeoff {
        f.insert(
            "PMDG V-Speeds (Takeoff)".into(),
            format!("V1 {v1} · VR {vr} · V2 {v2} kt"),
        );
    }
    if let Some(vref) = stats.pmdg_vref_at_landing {
        f.insert("PMDG VREF (Landing)".into(), format!("{vref} kt"));
    }
    if let Some(deg) = stats.pmdg_takeoff_flaps_planned {
        f.insert("PMDG Plan TO Flaps".into(), format!("{deg}°"));
    }
    if let Some(deg) = stats.pmdg_landing_flaps_planned {
        f.insert("PMDG Plan LDG Flaps".into(), format!("{deg}°"));
    }
    if let Some(ab) = stats.pmdg_autobrake_at_landing.as_deref() {
        f.insert("PMDG Autobrake (Landing)".into(), ab.to_string());
    }
    if stats.pmdg_takeoff_config_warning_seen {
        f.insert(
            "PMDG TO Config Warning".into(),
            "JA — Warnung war während TakeoffRoll aktiv".to_string(),
        );
    }
    // 777 ECL phase summary — only emit when at least ONE phase
    // was completed (avoids "PMDG ECL: 0/10" on aircraft without
    // ECL like NG3).
    if let Some(ecl) = stats.pmdg_ecl_phases_complete {
        let labels = [
            "Preflight", "BeforeStart", "BeforeTaxi", "BeforeTakeoff",
            "AfterTakeoff", "Descent", "Approach", "Landing",
            "Shutdown", "Secure",
        ];
        let done: Vec<&str> = ecl
            .iter()
            .zip(labels.iter())
            .filter_map(|(d, l)| if *d { Some(*l) } else { None })
            .collect();
        if !done.is_empty() {
            f.insert(
                "PMDG ECL Complete".into(),
                format!("{} / 10 ({})", done.len(), done.join(", ")),
            );
        }
    }

    // ---- SimBrief OFP plan + fuel-efficiency (Landing Analyzer Stage 2) ----
    // Surface the dispatcher's plan alongside the actuals, and compute
    // a fuel-efficiency delta so the VA can grade burn discipline.
    if let Some(b) = stats.planned_block_fuel_kg {
        f.insert("Plan Block Fuel".into(), format!("{:.0} kg", b));
    }
    if let Some(b) = stats.planned_burn_kg {
        f.insert("Plan Trip Burn".into(), format!("{:.0} kg", b));
    }
    if let Some(r) = stats.planned_reserve_kg {
        f.insert("Plan Reserve Fuel".into(), format!("{:.0} kg", r));
    }
    if let Some(z) = stats.planned_zfw_kg {
        f.insert("Plan ZFW".into(), format!("{:.0} kg", z));
    }
    if let Some(t) = stats.planned_tow_kg {
        f.insert("Plan TOW".into(), format!("{:.0} kg", t));
    }
    if let Some(l) = stats.planned_ldw_kg {
        f.insert("Plan LDW".into(), format!("{:.0} kg", l));
    }
    if let Some(route) = stats.planned_route.as_deref().filter(|s| !s.is_empty()) {
        f.insert("Plan Route".into(), route.to_string());
    }
    if let Some(alt) = stats.planned_alternate.as_deref().filter(|s| !s.is_empty()) {
        f.insert("Plan Alternate".into(), alt.to_string());
    }
    // Fuel efficiency: compare actual trip burn to the planned trip
    // burn. Use takeoff_fuel_kg − landing_fuel_kg as the actual trip
    // burn (excludes taxi out/in, matching SimBrief's est_burn).
    if let (Some(plan_burn), Some(toff), Some(land)) = (
        stats.planned_burn_kg,
        stats.takeoff_fuel_kg,
        stats.landing_fuel_kg,
    ) {
        if plan_burn > 0.0 && toff > 0.0 && land >= 0.0 && toff > land {
            let actual_burn = toff - land;
            let diff = actual_burn - plan_burn; // +ve = burned more than planned
            let pct = (diff / plan_burn) * 100.0;
            let sign = if diff >= 0.0 { "+" } else { "" };
            f.insert(
                "Fuel Efficiency".into(),
                format!("{sign}{:.0} kg ({sign}{:.1}%)", diff, pct),
            );
        }
    }

    // ---- Runway correlation (Tier 2) ----
    if let Some(rw) = &stats.runway_match {
        // Composite line covers airport+ident+length+surface in one
        // glanceable cell instead of five separate snake_case rows.
        f.insert(
            "Touchdown Runway".into(),
            format!(
                "{}/{} ({:.0} m, {})",
                rw.airport_ident,
                rw.runway_ident,
                rw.length_ft as f64 * 0.3048,
                rw.surface,
            ),
        );
        f.insert(
            "Centerline Offset".into(),
            format!("{:.1} m {}", rw.centerline_distance_m.abs(), rw.side),
        );
        f.insert(
            "Touchdown Past Threshold".into(),
            format!(
                "{:.0} m (runway {:.0} m long)",
                rw.touchdown_distance_from_threshold_ft as f64 * 0.3048,
                rw.length_ft as f64 * 0.3048,
            ),
        );
    }

    // ---- ATC-derived gates and approach runway (from MSFS SimVars) ----
    if let Some(g) = stats.dep_gate.as_ref().filter(|s| !s.is_empty()) {
        f.insert("Departure Gate".into(), g.clone());
    }
    if let Some(g) = stats.arr_gate.as_ref().filter(|s| !s.is_empty()) {
        f.insert("Arrival Gate".into(), g.clone());
    }
    if let Some(rw) = stats.approach_runway.as_ref().filter(|s| !s.is_empty()) {
        f.insert("Approach Runway (ATC)".into(), rw.clone());
    }

    // ---- Distance / cruise level ----
    if stats.distance_nm > 0.0 {
        f.insert(
            "Flown Distance".into(),
            format!("{:.1} nm", stats.distance_nm),
        );
    }
    if let Some(fl) = stats.peak_altitude_ft {
        f.insert("Cruise Level".into(), format!("FL{:.0}", fl / 100.0));
    }

    // ---- METAR snapshots ----
    if let Some(raw) = stats.dep_metar_raw.as_ref().filter(|s| !s.is_empty()) {
        f.insert("Departure METAR".into(), raw.clone());
    }
    if let Some(raw) = stats.arr_metar_raw.as_ref().filter(|s| !s.is_empty()) {
        f.insert("Arrival METAR".into(), raw.clone());
    }

    f
}

fn humanize_duration_minutes(minutes: i64) -> String {
    let m = minutes.max(0);
    let h = m / 60;
    let r = m % 60;
    if h == 0 {
        format!("{}m", r)
    } else {
        format!("{}h {:02}m", h, r)
    }
}

/// Build the human-readable summary that goes into the PIREP `notes` field —
/// a concise multi-line text that's always visible regardless of how the VA
/// configured custom fields.
fn build_pirep_notes(flight: &ActiveFlight, stats: &FlightStats) -> String {
    use std::fmt::Write;
    let mut s = String::new();

    // v0.7.19 GAF-707 Accident-Detection: bei Confirmed Accident
    // einen Banner ueber den normalen Header schreiben, damit der
    // VA-Admin in der PIREP-Liste sofort sieht dass das KEIN
    // normaler Flug war. Suspected wird hier NICHT als Banner
    // gezeigt — der Pilot hat den Override-Pfad gewaehlt oder
    // confirmed via Dialog. Spec §PIREP-Payload / Notes.
    if stats.accident_detected {
        if let (Some(kind), Some(confidence)) = (
            stats.accident_kind.as_deref(),
            stats.accident_confidence.as_deref(),
        ) {
            let kind_enum = match kind {
                "sim_crash" => accident::AccidentKind::SimCrash,
                "off_airport_impact" => accident::AccidentKind::OffAirportImpact,
                _ => accident::AccidentKind::Impact,
            };
            let banner = accident::build_accident_notes(
                kind_enum,
                confidence,
                &stats.accident_reasons,
            );
            s.push_str("=== ACCIDENT DETECTED ===\n");
            s.push_str(&banner);
            s.push_str("\n=========================\n\n");
        }
    }

    // Header — flight number + route + (when known) callsign airline.
    let _ = write!(
        s,
        "{} · {} → {}",
        flight.flight_number, flight.dpt_airport, flight.arr_airport
    );

    // ---- Times ----
    let mut wrote_section = false;
    let start_section = |s: &mut String, title: &str| {
        s.push_str("\n\n");
        s.push_str(title);
        s.push('\n');
    };
    let any_time = stats.block_off_at.is_some()
        || stats.takeoff_at.is_some()
        || stats.landing_at.is_some()
        || stats.block_on_at.is_some();
    if any_time {
        start_section(&mut s, "TIMES (UTC)");
        wrote_section = true;
        if let Some(t) = stats.block_off_at {
            let _ = writeln!(s, "  Blocks off    {}", t.format("%H:%M:%S"));
        }
        if let Some(t) = stats.takeoff_at {
            let _ = writeln!(s, "  Takeoff       {}", t.format("%H:%M:%S"));
        }
        if let Some(t) = stats.landing_at {
            let _ = writeln!(s, "  Landing       {}", t.format("%H:%M:%S"));
        }
        if let Some(t) = stats.block_on_at {
            let _ = writeln!(s, "  Blocks on     {}", t.format("%H:%M:%S"));
        }
        if let (Some(off), Some(on)) = (stats.block_off_at, stats.block_on_at) {
            let _ = writeln!(
                s,
                "  Block time    {}",
                humanize_duration_minutes((on - off).num_minutes())
            );
        }
        if let (Some(t1), Some(t2)) = (stats.takeoff_at, stats.landing_at) {
            let _ = writeln!(
                s,
                "  Flight time   {}",
                humanize_duration_minutes((t2 - t1).num_minutes())
            );
        }
        if let (Some(off), Some(takeoff)) = (stats.block_off_at, stats.takeoff_at) {
            let _ = writeln!(
                s,
                "  Taxi out      {}",
                humanize_duration_minutes((takeoff - off).num_minutes())
            );
        }
        if let (Some(land), Some(on)) = (stats.landing_at, stats.block_on_at) {
            let _ = writeln!(
                s,
                "  Taxi in       {}",
                humanize_duration_minutes((on - land).num_minutes())
            );
        }
    }

    // ---- Touchdown ----
    if stats.landing_at.is_some() {
        start_section(&mut s, "TOUCHDOWN");
        wrote_section = true;
        // v0.7.21 (MS713-QS): canonical_landing_rate_fpm() statt direkt.
        if let Some(rate) = stats.canonical_landing_rate_fpm() {
            let _ = writeln!(s, "  Landing rate  {:.0} fpm", rate);
        }
        if let Some(g) = stats.landing_g_force {
            let _ = writeln!(s, "  G-force       {:.2} G", g);
        }
        if let Some(p) = stats.landing_pitch_deg {
            let _ = writeln!(s, "  Pitch         {:+.1}°", p);
        }
        if let Some(kt) = stats.landing_speed_kt.filter(|v| *v > 0.0) {
            let _ = writeln!(s, "  Speed         {:.0} kt", kt);
        }
        if let Some(slip) = stats.touchdown_sideslip_deg {
            let _ = writeln!(s, "  Sideslip      {:+.1}°", slip);
        }
        if let Some(hw) = stats.landing_headwind_kt {
            // Positive = headwind, negative = tailwind. We swap the
            // label rather than printing a negative number.
            if hw >= 0.0 {
                let _ = writeln!(s, "  Headwind      {:.0} kt", hw);
            } else {
                let _ = writeln!(s, "  Tailwind      {:.0} kt", -hw);
            }
        }
        if let Some(xw) = stats.landing_crosswind_kt {
            // Positive = from right, negative = from left.
            let side = if xw >= 0.0 { "from right" } else { "from left" };
            let _ = writeln!(s, "  Crosswind     {:.0} kt {}", xw.abs(), side);
        }
        let _ = writeln!(s, "  Bounces       {}", stats.bounce_count);
        if let Some(sd) = stats.approach_vs_stddev_fpm {
            let _ = writeln!(s, "  Apr V/S σ     {:.0} fpm", sd);
        }
        if let Some(sd) = stats.approach_bank_stddev_deg {
            let _ = writeln!(s, "  Apr Bank σ    {:.1}°", sd);
        }
        if let Some(m) = stats.rollout_distance_m {
            let _ = writeln!(s, "  Rollout       {:.0} m", m);
        }
        if let Some(score) = stats.landing_score {
            let grade = letter_grade(score.numeric());
            let _ = writeln!(
                s,
                "  Grade         {} ({}, {}/100)",
                grade,
                score.label().to_uppercase(),
                score.numeric()
            );
        }
    }

    // ---- Touchdown history (T&G + final) ----
    // Only render when something noteworthy happened: at least one
    // T&G, OR more than one touchdown event total. A routine A→B with
    // a single final landing skips this section to keep notes short.
    let tg_count = stats
        .touchdown_events
        .iter()
        .filter(|e| matches!(e.kind, TouchdownKind::TouchAndGo))
        .count();
    if tg_count > 0 || stats.touchdown_events.len() > 1 {
        start_section(&mut s, "TOUCHDOWNS");
        wrote_section = true;
        for (i, ev) in stats.touchdown_events.iter().enumerate() {
            let label = match ev.kind {
                TouchdownKind::TouchAndGo => "T&G",
                TouchdownKind::FinalLanding => "Final",
            };
            let _ = writeln!(
                s,
                "  #{:<2} {:<5} {} V/S {:+.0} fpm · G {:.2} · bounces {}",
                i + 1,
                label,
                ev.timestamp.format("%H:%M:%S"),
                ev.peak_vs_fpm,
                ev.peak_g,
                ev.sub_bounces,
            );
        }
    }
    if stats.go_around_count > 0 {
        start_section(&mut s, "GO-AROUNDS");
        wrote_section = true;
        let _ = writeln!(s, "  Count         {}", stats.go_around_count);
    }

    // ---- Runway ----
    if let Some(rw) = &stats.runway_match {
        start_section(&mut s, "RUNWAY");
        wrote_section = true;
        let _ = writeln!(
            s,
            "  Touchdown     {}/{}  ({}, {:.0} m long)",
            rw.airport_ident,
            rw.runway_ident,
            rw.surface,
            rw.length_ft as f64 * 0.3048,
        );
        let _ = writeln!(
            s,
            "  Centerline    {:.1} m  ({})",
            rw.centerline_distance_m.abs(),
            rw.side
        );
        let _ = writeln!(
            s,
            "  Past thresh   {:.0} m",
            rw.touchdown_distance_from_threshold_ft as f64 * 0.3048,
        );
    }

    // ---- Fuel & Weight ----
    let any_fuel = stats.block_fuel_kg.filter(|v| *v > 0.0).is_some()
        || stats.takeoff_weight_kg.filter(|v| *v > 0.0).is_some()
        || stats.landing_weight_kg.filter(|v| *v > 0.0).is_some()
        || stats.landing_fuel_kg.filter(|v| *v > 0.0).is_some();
    if any_fuel {
        start_section(&mut s, "FUEL & WEIGHT");
        wrote_section = true;
        if let Some(b) = stats.block_fuel_kg.filter(|v| *v > 0.0) {
            let _ = writeln!(s, "  Block fuel    {:.0} kg", b);
        }
        if let (Some(b), Some(c)) = (stats.block_fuel_kg, stats.last_fuel_kg) {
            if b > 0.0 && b > c {
                let _ = writeln!(s, "  Fuel used     {:.0} kg", b - c);
            }
        }
        if let Some(f) = stats.landing_fuel_kg.filter(|v| *v > 0.0) {
            let _ = writeln!(s, "  Landing fuel  {:.0} kg", f);
        }
        if let Some(w) = stats.takeoff_weight_kg.filter(|v| *v > 0.0) {
            let _ = writeln!(s, "  TOW           {:.0} kg", w);
        }
        if let Some(w) = stats.landing_weight_kg.filter(|v| *v > 0.0) {
            let _ = writeln!(s, "  LDW           {:.0} kg", w);
        }
        // Stage 2: SimBrief plan + efficiency delta.
        if let Some(b) = stats.planned_burn_kg {
            let _ = writeln!(s, "  Plan burn     {:.0} kg", b);
        }
        if let Some(b) = stats.planned_block_fuel_kg {
            let _ = writeln!(s, "  Plan block    {:.0} kg", b);
        }
        if let Some(t) = stats.planned_tow_kg {
            let _ = writeln!(s, "  Plan TOW      {:.0} kg", t);
        }
        if let Some(l) = stats.planned_ldw_kg {
            let _ = writeln!(s, "  Plan LDW      {:.0} kg", l);
        }
        if let (Some(plan_burn), Some(toff), Some(land)) = (
            stats.planned_burn_kg,
            stats.takeoff_fuel_kg,
            stats.landing_fuel_kg,
        ) {
            if plan_burn > 0.0 && toff > land && toff > 0.0 && land >= 0.0 {
                let actual = toff - land;
                let diff = actual - plan_burn;
                let pct = (diff / plan_burn) * 100.0;
                let sign = if diff >= 0.0 { "+" } else { "" };
                let _ = writeln!(
                    s,
                    "  Efficiency    {sign}{:.0} kg ({sign}{:.1}%)",
                    diff, pct
                );
            }
        }
    }

    // ---- Stand / Runway (ATC-cleared) ----
    let any_atc = stats.dep_gate.as_ref().is_some_and(|v| !v.is_empty())
        || stats.arr_gate.as_ref().is_some_and(|v| !v.is_empty())
        || stats.approach_runway.as_ref().is_some_and(|v| !v.is_empty());
    if any_atc {
        start_section(&mut s, "GATES & ATC");
        wrote_section = true;
        if let Some(g) = stats.dep_gate.as_ref().filter(|v| !v.is_empty()) {
            let _ = writeln!(s, "  Departure gate  {}", g);
        }
        if let Some(g) = stats.arr_gate.as_ref().filter(|v| !v.is_empty()) {
            let _ = writeln!(s, "  Arrival gate    {}", g);
        }
        if let Some(rw) = stats.approach_runway.as_ref().filter(|v| !v.is_empty()) {
            let _ = writeln!(s, "  Approach rwy    {}", rw);
        }
    }

    // ---- Distance ----
    if stats.distance_nm > 0.0 || stats.peak_altitude_ft.is_some() {
        start_section(&mut s, "DISTANCE & LEVEL");
        wrote_section = true;
        let _ = writeln!(s, "  Flown         {:.1} nm", stats.distance_nm);
        if let Some(fl) = stats.peak_altitude_ft {
            let _ = writeln!(s, "  Cruise level  FL{:.0}", fl / 100.0);
        }
        let _ = writeln!(s, "  Positions     {}", stats.position_count);
    }

    // ---- METAR ----
    let dep_metar = stats.dep_metar_raw.as_ref().filter(|v| !v.is_empty());
    let arr_metar = stats.arr_metar_raw.as_ref().filter(|v| !v.is_empty());
    if dep_metar.is_some() || arr_metar.is_some() {
        start_section(&mut s, "METAR");
        wrote_section = true;
        if let Some(m) = dep_metar {
            let _ = writeln!(s, "  Departure  {}", m);
        }
        if let Some(m) = arr_metar {
            let _ = writeln!(s, "  Arrival    {}", m);
        }
    }

    // Footer
    if wrote_section {
        s.push('\n');
    } else {
        s.push_str("\n\n");
    }
    let _ = write!(
        s,
        "AeroACARS {} · Forensik v{}",
        env!("CARGO_PKG_VERSION"),
        touchdown_v2::FORENSICS_VERSION
    );

    // v0.7.1 Phase 0 Schatten-Validation (Spec docs/spec/v0.7.1-landing-ux-fairness.md
    // §6 Phase 0 Step 4): die landing-scoring Crate berechnet parallel den
    // Master-Score aus den gleichen Feldern wie das TS-LandingPanel +
    // libComputeSubScores. Der Wert wird NICHT in den PIREP-Notes
    // geschrieben (Pilot-sichtbar) sondern via tracing::info!() geloggt
    // — Drift wird im Log-File sichtbar, Pilot sieht nichts.
    //
    // KRITISCH: Inputs muessen identisch sein zu LandingPanel.tsx:137-149
    //   peakVs = landing_peak_vs_fpm ?? landing_rate_fpm
    //   peak_g  = landing_peak_g_force (NICHT landing_g_force)
    //   fuel_efficiency_pct: actual_burn = takeoff_fuel - landing_fuel
    //                        (NICHT block_fuel - landing_fuel — siehe
    //                         build_landing_record lib.rs:6467-6477)
    //
    // Phase-0-Acceptance: dieser Schatten-Wert MUSS dem TS-berechneten
    // Master-Score entsprechen (Bit-Drift = Phase-0-Bug).
    // Phase 2 Update: nutzt jetzt planned_burn + actual_trip_burn
    // (statt fuel_efficiency_pct Legacy-Pfad), planned_zfw + planned_tow
    // damit sub_loadsheet skipped/scored werden kann.
    let actual_burn = match (stats.takeoff_fuel_kg, stats.landing_fuel_kg) {
        (Some(toff), Some(land))
            if toff > land && toff > 0.0 && land >= 0.0 =>
        {
            Some(toff - land)
        }
        _ => None,
    };
    let mut crate_input = landing_scoring::LandingScoringInput {
        // v0.7.1 Phase 0 Schatten-Validation muss identische Inputs nutzen
        // wie der echte PIREP-Pfad (build_landing_record + PirepPayload).
        // v0.7.17 (B-015a QS-Fix): Edge-Wert hat Vorrang — siehe
        // `score_basis_vs_fpm()` Doc.
        vs_fpm: score_basis_vs_fpm(stats),
        peak_g_load: stats.landing_peak_g_force,
        // v0.12.3 (LE8): zentraler Scored-G-Helper — EMA-Wert aus der
        // Forensik, sonst raw_fallback. Nie `None` an den Score (QS-P2).
        scored_g_load: Some(score_g_for_stats(stats).scored_g),
        // v0.7.6 P2-B: zentraler Helper statt direkten Read.
        bounce_count: Some(scored_bounce_count_for_score(stats)),
        approach_vs_stddev_fpm: stats.approach_vs_stddev_fpm,
        approach_bank_stddev_deg: stats.approach_bank_stddev_deg,
        rollout_distance_m: stats.rollout_distance_m.map(|m| m as f32),
        planned_burn_kg: stats.planned_burn_kg,
        actual_trip_burn_kg: actual_burn,
        planned_zfw_kg: stats.planned_zfw_kg,
        planned_tow_kg: stats.planned_tow_kg,
        // v0.10.0 QS-Code-R1 P2-1 Fix: ohne aircraft_icao rechnete die
        // Shadow-Validation für A388/A320 mit Light-Default-Schwellen
        // (Heavy-Allowance fehlte) → Drift gegen die echten Pfade
        // → falsche Audit-Logs. Identisch zu den anderen 3 Sites.
        aircraft_icao: Some(flight.aircraft_icao.clone()),
        ..Default::default()
    };
    // v0.10.0 (#runway-utilization-score): Shadow-Validation muss den
    // gleichen Algorithmus rechnen wie der echte PIREP-Pfad — sonst
    // hätten wir Drift gegen uns selbst.
    fill_v2_rollout_fields(&mut crate_input, stats, &flight.arr_airport);
    let crate_subs = landing_scoring::compute_sub_scores(&crate_input);
    if let Some(crate_master) = landing_scoring::aggregate_master_score(&crate_subs) {
        // v0.7.1 P2.6-Fix: Drift-Vergleich gegen den ECHTEN
        // Touchdown-Klassifikator-Score (LandingScore::numeric) ist
        // unsinnig — das ist eine andere Score-Definition (vs/g/bounce-
        // basierte Kategorie). Der Schatten-Wert ist jetzt selbst der
        // gewichtete Aggregate-Score und wird im UI auch so verwendet
        // (P1.3-Fix). Wir loggen nur, damit Audit-Trail im Log bleibt
        // welcher Master-Score in welchem PIREP gelandet ist.
        let touchdown_class = stats.landing_score.map(|sc| sc.label());
        tracing::info!(
            pirep_id = %flight.pirep_id,
            master_score_v0_7_1 = crate_master,
            touchdown_class = ?touchdown_class,
            crate_input_vs_fpm = ?crate_input.vs_fpm,
            crate_input_peak_g = ?crate_input.peak_g_load,
            crate_input_bounces = ?crate_input.bounce_count,
            crate_sub_count = crate_subs.len(),
            crate_skipped_count = crate_subs.iter().filter(|s| s.skipped).count(),
            "v0.7.1 Master-Score-Aggregate (Crate-SSoT)"
        );
    }

    s
}

/// Map our internal `FlightPhase` to the phpVMS PirepStatus code we POST
/// in `update_pirep`. Codes verified against the canonical phpVMS Core
/// enum at `phpvms/phpvms` → `app/Models/Enums/PirepStatus.php`:
///
///   INI Initiated   SCH Scheduled    BST Boarding         RDT Ready
///   PBT Pushback    OFB Off block    DIR Ready de-ice     DIC De-icing
///   GRT Ground rtn  TXI Taxi         TOF Takeoff (roll)   TKO Airborne
///   ICL Init climb  ENR Enroute      DV  Diverted
///   TEN Approach    APR Approach     FIN On final         LDG Landing
///   LAN Landed      ONB On block     ARR Arrived          DX  Cancelled
///   EMG Emerg desc  PSD Paused
///
/// Notes / pitfalls discovered while wiring this up (real bugs):
///   * Pushback must be PBT, not OFB. phpVMS labels `OFB` as
///     "departed" (German: "Abgeflogen") — sending OFB during pushback
///     made the live tracker show "Abgeflogen" before the aircraft had
///     even moved off the gate.
///   * There is no "TOD" or "FAP" or "TXG" in phpVMS — early versions
///     of this client invented those, which would have been silently
///     dropped (or echoed as the literal letters in some VA themes).
///   * `TOF` is the on-runway-takeoff-roll phase, `TKO` is the
///     airborne / climb-out phase. Their human-readable labels
///     collapse to "takeoff" and "enroute" respectively.
///   * Phases the API offers but we don't drive: SCH, DIR/DIC (de-ice),
///     GRT (ground return), DV (divert), EMG, PSD. We may emit them
///     later from manual-end paths.
fn phase_to_status(phase: FlightPhase) -> Option<&'static str> {
    match phase {
        FlightPhase::Preflight | FlightPhase::Boarding => Some("BST"),
        FlightPhase::Pushback => Some("PBT"),
        FlightPhase::TaxiOut => Some("TXI"),
        FlightPhase::TakeoffRoll => Some("TOF"),
        FlightPhase::Takeoff => Some("TKO"),
        FlightPhase::Climb => Some("ICL"),
        // No dedicated "descent" code in phpVMS — the canonical
        // taxonomy stays ENROUTE until the aircraft enters the
        // approach phase (which we cover with APR / FIN below).
        FlightPhase::Cruise | FlightPhase::Descent => Some("ENR"),
        // v0.5.11: phpVMS has no "Holding" status code. ENR is the
        // closest match (we're enroute, just circling). The Cockpit
        // tab UI has its own Holding badge that does NOT depend on
        // this status code mapping.
        FlightPhase::Holding => Some("ENR"),
        FlightPhase::Approach => Some("APR"),
        FlightPhase::Final => Some("FIN"),
        FlightPhase::Landing => Some("LDG"),
        // No separate "taxi to gate" code; phpVMS reuses TXI.
        FlightPhase::TaxiIn => Some("TXI"),
        FlightPhase::BlocksOn => Some("ONB"),
        FlightPhase::Arrived => Some("ARR"),
        FlightPhase::PirepSubmitted => None,
    }
}

/// Trigger one-shot METAR fetches for departure (at takeoff) and arrival
/// (at touchdown). Each side fires only once per flight — the
/// `dep_metar_requested` / `arr_metar_requested` flags on FlightStats
/// gate it. Fetch runs on the Tauri async runtime so the streamer
/// keeps ticking even if aviationweather.gov is slow.
fn maybe_spawn_metar_fetch(app: &AppHandle, flight: &Arc<ActiveFlight>, new_phase: FlightPhase) {
    let kind = match new_phase {
        FlightPhase::Takeoff => MetarKind::Departure,
        // Trigger at Final so the arrival weather is in the activity
        // log *before* the touchdown line, not after — pilots want the
        // wind for the approach, not for the rollout.
        FlightPhase::Final => MetarKind::Arrival,
        _ => return,
    };
    let icao = match kind {
        MetarKind::Departure => flight.dpt_airport.clone(),
        MetarKind::Arrival => flight.arr_airport.clone(),
    };
    {
        let mut stats = flight.stats.lock().expect("flight stats");
        let already = match kind {
            MetarKind::Departure => stats.dep_metar_requested,
            MetarKind::Arrival => stats.arr_metar_requested,
        };
        if already {
            return;
        }
        match kind {
            MetarKind::Departure => stats.dep_metar_requested = true,
            MetarKind::Arrival => stats.arr_metar_requested = true,
        }
    }
    let app = app.clone();
    let flight = Arc::clone(flight);
    tauri::async_runtime::spawn(async move {
        match metar::fetch_metar(&icao).await {
            Ok(snap) => {
                let raw = snap.raw.clone();
                {
                    let mut stats = flight.stats.lock().expect("flight stats");
                    match kind {
                        MetarKind::Departure => stats.dep_metar_raw = Some(raw.clone()),
                        MetarKind::Arrival => stats.arr_metar_raw = Some(raw.clone()),
                    }
                }
                let label = match kind {
                    MetarKind::Departure => "Departure METAR",
                    MetarKind::Arrival => "Arrival METAR",
                };
                log_activity_handle(
                    &app,
                    ActivityLevel::Info,
                    format!("{label}: {icao}"),
                    Some(if raw.is_empty() {
                        "(empty)".to_string()
                    } else {
                        raw
                    }),
                );
            }
            Err(e) => {
                tracing::warn!(error = %e, %icao, "metar fetch failed");
            }
        }
    });
}

/// Internal discriminator for the two METAR fetch directions.
#[derive(Debug, Clone, Copy)]
enum MetarKind {
    Departure,
    Arrival,
}

/// Emit the landing analyzer's verdict to the activity log exactly once,
/// the first time `step_flight` finalises a score. Called every tick;
/// idempotent by design — uses an extra "already announced" flag in
/// `FlightStats` so resumed sessions that already filed don't re-emit.
/// Returns `Some(<acars-log-message>)` exactly once (the first tick after
/// the touchdown analyzer locked in a score) so the streamer can mirror
/// the touchdown summary into `POST /pireps/{id}/acars/logs` for the
/// PIREP detail page. Subsequent ticks return None.
fn announce_landing_score(app: &AppHandle, flight: &ActiveFlight) -> Option<String> {
    let mut stats = flight.stats.lock().expect("flight stats");
    if stats.landing_score_announced {
        return None;
    }
    let score = stats.landing_score?;

    // v0.5.41: Auf Sampler-Finalisierung warten (= Buffer wurde 10 s post-TD
    // gedumpt + Score mit vs_at_edge neu berechnet). Verhindert dass der
    // Live-Monitor den ueberholten msfs_simvar_latched-Wert sieht.
    // Fallback-Timeout: 12 s post-TD ohne Finalisierung → trotzdem
    // emitten mit den vorhandenen Werten (= Buffer war evtl. leer wegen
    // Sample-Luecke, oder sampler ist abgestuerzt). Verhindert dass der
    // Touchdown bei einem fehlerhaften Buffer-Path nie gemeldet wird.
    if !stats.landing_score_finalized {
        if let Some(td_at) = stats.sampler_touchdown_at {
            let elapsed_ms = (Utc::now() - td_at).num_milliseconds();
            const FINALIZATION_TIMEOUT_MS: i64 = 12_000;
            if elapsed_ms < FINALIZATION_TIMEOUT_MS {
                return None; // weiter warten
            }
            // Timeout — trotzdem freigeben, mit Hinweis im Trace
            tracing::warn!(
                pirep_id = %flight.pirep_id,
                elapsed_ms,
                "score finalization timeout — emitting with sampler-only values (buffer dump may have failed)"
            );
            stats.landing_score_finalized = true;
        }
        // Wenn sampler_touchdown_at None ist (= Sampler hat keinen Edge
        // detektiert, FSM-Pfad scored stattdessen) → sofort freigeben.
    }
    let peak_vs = stats.landing_peak_vs_fpm.unwrap_or(0.0);
    let peak_g = stats.landing_peak_g_force.unwrap_or(0.0);
    let bounces = stats.bounce_count;
    // v0.12.3 (LE7/LE8): der gescorte G-Wert (EMA, sonst raw_fallback) —
    // für den Activity-/ACARS-Text UND das persistierte LandingScored-
    // Event. `peak_g` (oben) bleibt der rohe Wert für `peak_g_force`.
    let sg = score_g_for_stats(&stats);
    let level = match score {
        LandingScore::Smooth | LandingScore::Acceptable => ActivityLevel::Info,
        LandingScore::Firm => ActivityLevel::Info,
        LandingScore::Hard | LandingScore::Severe => ActivityLevel::Warn,
    };
    let bounce_part = if bounces > 0 {
        format!(", {} bounce{}", bounces, if bounces == 1 { "" } else { "s" })
    } else {
        String::new()
    };
    // v0.16.27: Das Aktivitäts-/ACARS-Log zeigt beim Touchdown nur noch die
    // MESSDATEN (V/S, G, Bounces) — KEINE Einstufung. Darum brauchen wir hier
    // weder die Aufprall-Note (`letter_grade`) noch den Aggregate-Master-Score:
    // der bewertete Score lebt ausschließlich im Landung-Tab + phpVMS-Feld
    // „Landing Score". (Vorher zeigte der Log-Titel die Note NUR des Aufpralls
    // [V/S+G], der Tab die Note des GANZEN Anflugs [Master] → zwei Metriken,
    // als nackter Buchstabe wirkten sie widersprüchlich: „Touchdown B" vs „A".)
    // v0.8.0: Per-Touchdown Navdata-Source + DDS-Warnung sammeln,
    // bevor wir `stats` droppen.
    let nav_source_msg: Option<(ActivityLevel, String)> = stats
        .runway_match
        .as_ref()
        .and_then(|rm| {
            let src = stats.runway_source?;
            let label = match src {
                runway::RunwaySource::Navigraph => format!(
                    "Runway {} {} matched via Navigraph (AIRAC {})",
                    rm.runway_ident,
                    rm.airport_ident,
                    stats.runway_nav_cycle.as_deref().unwrap_or("?")
                ),
                runway::RunwaySource::OurAirportsFallback => format!(
                    "Runway {} {} matched via OurAirports-Fallback",
                    rm.runway_ident, rm.airport_ident
                ),
            };
            let level = match src {
                runway::RunwaySource::Navigraph => ActivityLevel::Info,
                runway::RunwaySource::OurAirportsFallback => ActivityLevel::Warn,
            };
            Some((level, label))
        });
    let dds_warning_msg: Option<String> = stats
        .runway_nav_geometry
        .as_ref()
        .and_then(|g| {
            if g.displaced_threshold_ft == 0 {
                return None;
            }
            let rm = stats.runway_match.as_ref()?;
            let td_m = rm.touchdown_distance_from_threshold_ft / 3.280_839_895;
            let displaced_m = (g.displaced_threshold_ft as f64) / 3.280_839_895;
            if td_m < 0.0 && td_m > -displaced_m {
                Some(format!(
                    "⚠ Touchdown im Pre-Threshold-Bereich (DDS {:.0} m vor Landing-Threshold)",
                    displaced_m
                ))
            } else {
                None
            }
        });
    drop(stats);
    log_activity_handle(
        app,
        level,
        // nur Messdaten — keine Note/Einstufung (siehe Kommentar oben)
        format!(
            "Touchdown: V/S {:.0} fpm, G {:.2}{}",
            peak_vs, // signed: negative = descent, matches the PIREP
            sg.scored_g, // v0.12.3 (LE7): scored (EMA) G, not the raw peak
            bounce_part,
        ),
        None,
    );
    // v0.8.0: zusätzlich die Runway-Match-Source mitloggen damit der
    // Pilot weiß ob die Bewertung auf Jeppesen-Daten oder dem
    // OurAirports-Fallback beruht.
    if let Some((src_level, src_msg)) = nav_source_msg {
        log_activity_handle(app, src_level, src_msg, None);
    }
    if let Some(msg) = dds_warning_msg {
        log_activity_handle(app, ActivityLevel::Error, msg, None);
    }
    record_event(
        app,
        &flight.pirep_id,
        &FlightLogEvent::LandingScored {
            timestamp: Utc::now(),
            score: score.label().to_string(),
            peak_vs_fpm: peak_vs,
            peak_g_force: peak_g,
            bounce_count: bounces,
            // v0.12.3 (LE7): EMA-Scored-G additiv; peak_g_force bleibt roh.
            scored_g_force: Some(sg.scored_g),
            scored_g_method: Some(sg.method.as_str().to_string()),
        },
    );
    // Re-acquire to flag it as announced.
    let mut stats = flight.stats.lock().expect("flight stats");
    stats.landing_score_announced = true;
    // acars/logs-Spiegelung (phpVMS-Serverlog): ebenfalls nur Messdaten, keine
    // Einstufung — der bewertete Score steht im phpVMS-Feld „Landing Score".
    Some(format!(
        "Touchdown — V/S {:.0} fpm, G {:.2}{}",
        peak_vs,
        sg.scored_g, // v0.12.3 (LE7): scored (EMA) G, not the raw peak
        bounce_part,
    ))
}

/// Diff cockpit knob state against the last-logged values and emit one
/// activity-feed entry per real change. Called from the streamer loop on
/// every tick. The first call (after a fresh `flight_start` / `flight_adopt`)
/// also logs the aircraft + simulator identity, so the log opens with a
/// "Aircraft: …" line like smartcars does.
fn detect_telemetry_changes(app: &AppHandle, flight: &ActiveFlight, snap: &SimSnapshot) {
    let mut stats = flight.stats.lock().expect("flight stats");

    // ---- Aircraft + sim banner — first tick only.
    // Aircraft banner: gated on a dedicated per-flight flag rather
    // than the heuristic "all three diff fields are still None"
    // because the heuristic is too fragile (a stale resumed flight
    // could already have those fields set, suppressing the banner
    // when it should fire). The flag is persisted, so a Tauri
    // restart mid-flight doesn't re-fire — the banner belongs to
    // the flight, not the session.
    let first_tick = !stats.aircraft_banner_logged;
    if first_tick {
        stats.aircraft_banner_logged = true;
        let title = snap.aircraft_title.as_deref().unwrap_or("(unknown)");
        // Some aircraft (Fenix, FBW) return a localization key like
        // "ATCCOM.AC_MODEL A320.0.text" in `ATC MODEL` rather than the plain
        // ICAO. Filter that out — a stray dot in an ICAO never happens.
        let icao_raw = snap.aircraft_icao.as_deref().unwrap_or("");
        // v0.2.4: when the standard ICAO is unusable (empty, or a
        // localisation key like "ATCCOM.AC_MODEL_B738.0.text" that
        // MSFS 2024 hands out for some PMDG liveries), fall back to
        // the PMDG-variant family ICAO. That's accurate to the family
        // (B738/B77W) even if not to the sub-variant.
        let pmdg_fallback_icao: Option<&'static str> = snap
            .pmdg
            .as_ref()
            .and_then(|_| {
                // Aircraft path tells us which PMDG family is active.
                // We don't know it from snap.pmdg.variant_label alone,
                // but we do know "PMDG SDK is active" — so we fall
                // back via the variant_label string content.
                let label = &snap.pmdg.as_ref()?.variant_label;
                if label.contains("737") {
                    Some("B738")
                } else if label.contains("777") {
                    // Pick the most-common 777 variant as default;
                    // exact -200LR / -300ER / 777F can't be inferred
                    // from the variant label alone (that's a richer
                    // mapping we may add later).
                    Some("B77W")
                } else {
                    None
                }
            });
        let icao = if icao_raw.contains('.') || icao_raw.is_empty() {
            pmdg_fallback_icao.unwrap_or("?")
        } else {
            icao_raw
        };
        let reg = snap
            .aircraft_registration
            .as_deref()
            .map(|s| s.trim())
            .filter(|s| !s.is_empty())
            .unwrap_or("?");
        // NOTE: planned_registration vs sim-reg comparison removed for now
        // — MSFS 2024's pilot-profile tail number overrides the livery's
        // atc_id, so the comparison fired false-positive warnings. We keep
        // `flight.planned_registration` populated server-side (it's still
        // useful for PIREP audit), but the live banner just shows what
        // MSFS reports. Re-enable later via a WASM-based livery reader.
        let _ = &flight.planned_registration;
        // v0.2.4: when PMDG SDK is feeding us premium telemetry, surface
        // that in the profile string so the pilot doesn't see the
        // misleading "Default (standard SimVars)" right before the
        // "PMDG SDK aktiv" entry one tick later.
        let profile_label = if let Some(pmdg) = snap.pmdg.as_ref() {
            format!(
                "{} + {}",
                snap.aircraft_profile.label(),
                pmdg.variant_label
            )
        } else {
            snap.aircraft_profile.label().to_string()
        };
        log_activity_handle(
            app,
            ActivityLevel::Info,
            format!("Aircraft: {title}"),
            Some(format!(
                "Type {icao} · Reg {reg} · Sim {:?} · Profile: {}",
                snap.simulator, profile_label
            )),
        );
    }

    // ---- Profile change (after first tick) — pilot swapped airframes
    if stats.last_logged_profile != Some(snap.aircraft_profile) {
        if !first_tick {
            // v0.2.4: same Premium-First label suffix as the banner —
            // PMDG SDK active means the *premium* layer is doing the
            // heavy lifting even if the underlying SimVar profile
            // is still the generic "Default" one.
            let label = if let Some(pmdg) = snap.pmdg.as_ref() {
                format!("{} + {}", snap.aircraft_profile.label(), pmdg.variant_label)
            } else {
                snap.aircraft_profile.label().to_string()
            };
            log_activity_handle(
                app,
                ActivityLevel::Info,
                format!("Aircraft profile changed → {}", label),
                None,
            );
        }
        stats.last_logged_profile = Some(snap.aircraft_profile);
    }

    // ---- Squawk
    // Real-world squawks are always 4 octal digits ≥ 1000 — Fenix and a
    // few other study-level airbuses pump the active-edit-digit into
    // TRANSPONDER CODE:1 while the pilot keypad-types, which the FlyByWire
    // / Asobo aircraft don't do. Filter anything < 1000 so the log isn't
    // flooded with "Squawk set to 0004 / 0003 / 0002" while a value like
    // 2523 is being entered. The proper fix lives in the per-aircraft
    // LVar profile (Phase H.4 stage 2).
    if let Some(sq) = snap.transponder_code {
        let is_plausible = sq >= 1000;
        if is_plausible && stats.last_logged_squawk != Some(sq) {
            // Don't spam on the first tick if the value is the boring 1200/7000.
            if !first_tick || (sq != 1200 && sq != 7000) {
                log_activity_handle(
                    app,
                    ActivityLevel::Info,
                    format!("Squawk set to {:04}", sq),
                    None,
                );
            }
            stats.last_logged_squawk = Some(sq);
        }
    }

    // ---- XPDR mode (v0.2.4 PMDG + v0.3.0 X-Plane).
    // Cockpit exposes the actual transponder MODE selector
    // (STBY / ALT-OFF / XPNDR / TA / TA-RA) which the standard MSFS
    // SimVar `TRANSPONDER STATE` only exposes as a binary on/off.
    // Now sourced from `snap.xpdr_mode_label` which the MSFS adapter
    // fills from PMDG and the X-Plane adapter fills from the standard
    // `transponder_mode` DataRef. Logged as a separate entry so the
    // squawk-code log keeps its original semantics.
    if let Some(mode) = snap.xpdr_mode_label.as_ref() {
        if !mode.is_empty()
            && stats.last_logged_pmdg_xpdr_mode.as_deref() != Some(mode.as_str())
        {
            // Skip first tick on a "boring" STBY/OFF value to avoid noise
            // when the pilot loads cold-and-dark.
            if !first_tick || (mode != "STBY" && mode != "OFF") {
                log_activity_handle(
                    app,
                    ActivityLevel::Info,
                    format!("XPDR mode → {}", mode),
                    None,
                );
            }
            stats.last_logged_pmdg_xpdr_mode = Some(mode.clone());
        }
    }

    // ---- COM / NAV frequency logging removed (2026-05).
    // In practice frequencies change every sector handoff (Departure
    // → Center → Center → Approach → Tower → Ground), which fills
    // the log without telling the VA admin anything useful. Plus
    // Fenix's RMP doesn't write to the standard SimVars at all, so
    // for that aircraft we'd be logging stale defaults from the
    // sim's COM panel rather than what the pilot actually tuned.
    // Squawk stays in the log — that genuinely changes only ~1-2x
    // per flight at meaningful moments.
    //
    // The fields on the snapshot remain populated so the debug
    // panel and inspector keep working.
    let _ = (
        snap.com1_mhz,
        snap.com2_mhz,
        snap.nav1_mhz,
        snap.nav2_mhz,
        &stats.last_logged_com1,
        &stats.last_logged_com2,
        &stats.last_logged_nav1,
        &stats.last_logged_nav2,
    );

    // ---- Exterior lights
    // Strobe is special: when the aircraft profile gives us the
    // 3-state selector (`snap.strobe_state`), we log OFF/AUTO/ON so
    // the AUTO ↔ ON transition at runway entry/exit is preserved.
    // For aircraft that only expose the binary `light_strobe`, we
    // fall through to the LightsState path below with plain ON/OFF
    // labels.
    let strobe_three_state_active = snap.strobe_state.is_some();
    if let Some(state) = snap.strobe_state {
        if stats.last_logged_strobe_state != Some(state) {
            if stats.last_logged_strobe_state.is_some() {
                let label = match state {
                    0 => "OFF",
                    1 => "AUTO",
                    2 => "ON",
                    _ => return,
                };
                log_activity_handle(
                    app,
                    ActivityLevel::Info,
                    format!("Strobe lights {label}"),
                    None,
                );
            }
            stats.last_logged_strobe_state = Some(state);
        }
    }

    // Premium-First (v0.2.4 + v0.3.0): wing + wheel-well are
    // NG3/777-only via PMDG (MSFS) or laminar/B738-only via the
    // X-Plane 737 family (Zibo / LevelUp / default-738). Both
    // simulators now write into the top-level SimSnapshot fields,
    // so we read directly from snap.light_wing / snap.light_wheel_well.
    // Field is `Some(...)` when the source platform actually reports
    // the switch (kept None on aircraft that don't have it — generic
    // Airbus, Cessna, etc.).
    let has_wing = snap.light_wing.is_some();
    let has_wheel_well = snap.light_wheel_well.is_some();
    let lights = LightsState {
        landing: snap.light_landing.unwrap_or(false),
        beacon: snap.light_beacon.unwrap_or(false),
        // Keep the binary state in the struct so the pill UI still
        // works; the activity-log path below skips Strobe when the
        // 3-state path is active to avoid double entries.
        strobe: snap.light_strobe.unwrap_or(false),
        taxi: snap.light_taxi.unwrap_or(false),
        nav: snap.light_nav.unwrap_or(false),
        logo: snap.light_logo.unwrap_or(false),
        wing: snap.light_wing.unwrap_or(false),
        wheel_well: snap.light_wheel_well.unwrap_or(false),
    };
    if stats.last_logged_lights != Some(lights) {
        if let Some(prev) = stats.last_logged_lights {
            // Log per-light transitions so the pilot sees exactly what changed.
            let mut changes: Vec<(&str, bool, bool)> = vec![
                ("Landing", prev.landing, lights.landing),
                ("Beacon", prev.beacon, lights.beacon),
                ("Taxi", prev.taxi, lights.taxi),
                ("Nav", prev.nav, lights.nav),
                ("Logo", prev.logo, lights.logo),
            ];
            // Only include Strobe in the binary path when the 3-state
            // selector isn't available; otherwise the dedicated
            // OFF/AUTO/ON log entry above already covers it.
            if !strobe_three_state_active {
                changes.push(("Strobe", prev.strobe, lights.strobe));
            }
            // Wing + wheel-well only fire when the source platform
            // actually reports the switch (PMDG / laminar/B738) —
            // prevents bogus "Wing OFF" entries on generic aircraft.
            if has_wing {
                changes.push(("Wing", prev.wing, lights.wing));
            }
            if has_wheel_well {
                changes.push(("Wheel-well", prev.wheel_well, lights.wheel_well));
            }
            for (name, old, new) in changes {
                if old != new {
                    log_activity_handle(
                        app,
                        ActivityLevel::Info,
                        format!("{name} lights {}", if new { "ON" } else { "OFF" }),
                        None,
                    );
                }
            }
        }
        stats.last_logged_lights = Some(lights);
    }

    // ---- Autopilot
    let ap = ApState {
        master: snap.autopilot_master.unwrap_or(false),
        heading: snap.autopilot_heading.unwrap_or(false),
        altitude: snap.autopilot_altitude.unwrap_or(false),
        nav: snap.autopilot_nav.unwrap_or(false),
        approach: snap.autopilot_approach.unwrap_or(false),
    };
    if stats.last_logged_ap != Some(ap) {
        if let Some(prev) = stats.last_logged_ap {
            // Master toggle is debounced — see AP_DEBOUNCE_SECS comment.
            if prev.master != ap.master {
                let now = Utc::now();
                if stats.pending_ap_master != Some(ap.master) {
                    // First time we see this new state — start the timer.
                    stats.pending_ap_master = Some(ap.master);
                    stats.pending_ap_master_since = Some(now);
                } else if let Some(since) = stats.pending_ap_master_since {
                    // Same state held for AP_DEBOUNCE_SECS → publish.
                    if (now - since).num_seconds() >= AP_DEBOUNCE_SECS {
                        log_activity_handle(
                            app,
                            ActivityLevel::Info,
                            format!(
                                "Autopilot {}",
                                if ap.master { "ENGAGED" } else { "OFF" }
                            ),
                            None,
                        );
                        stats.last_logged_ap = Some(ap);
                        stats.pending_ap_master = None;
                        stats.pending_ap_master_since = None;
                        return;
                    }
                }
                // Don't update last_logged_ap yet — we're waiting for the
                // debounce. Mode flips below still get to flow through.
            } else {
                // Master agrees with prev → drop any pending debounce.
                stats.pending_ap_master = None;
                stats.pending_ap_master_since = None;
            }
            let modes = [
                ("HDG", prev.heading, ap.heading),
                ("ALT", prev.altitude, ap.altitude),
                ("NAV", prev.nav, ap.nav),
                ("APR", prev.approach, ap.approach),
            ];
            for (name, old, new) in modes {
                if old != new {
                    log_activity_handle(
                        app,
                        ActivityLevel::Info,
                        format!("AP {name} {}", if new { "ARMED" } else { "OFF" }),
                        None,
                    );
                }
            }
        }
        // Only update if master is stable (otherwise the debounce branch
        // above already returned). Mode-only changes still want to land.
        if stats
            .last_logged_ap
            .is_none_or(|prev| prev.master == ap.master)
        {
            stats.last_logged_ap = Some(ap);
        }
    }

    // ---- A/THR (v0.16.4 — generic autothrottle).
    // `snap.autothrottle_on` is only Some on profiles with a verified
    // state source (Aerosoft A346 `L:AB_AP_ATHR_LIGHT_ON` annunciator,
    // Fenix `L:S_FCU_ATHR`) — everything else stays None and logs
    // nothing. Same debounce as the AP master: the Fenix S_FCU_*
    // family is a known button-pulse candidate (B-008), so a 0→1→0
    // pulse shorter than AP_DEBOUNCE_SECS produces no entry at all
    // instead of a bogus ENGAGED/OFF pair.
    if let Some(athr) = snap.autothrottle_on {
        if stats.last_logged_autothrottle != Some(athr) {
            let now = Utc::now();
            if stats.pending_autothrottle != Some(athr) {
                // First time we see this new state — start the timer.
                stats.pending_autothrottle = Some(athr);
                stats.pending_autothrottle_since = Some(now);
            } else if let Some(since) = stats.pending_autothrottle_since {
                // Same state held for AP_DEBOUNCE_SECS → publish.
                if (now - since).num_seconds() >= AP_DEBOUNCE_SECS {
                    // First observation latches silently (no entry on
                    // the initial state, only on transitions).
                    if stats.last_logged_autothrottle.is_some() {
                        log_activity_handle(
                            app,
                            ActivityLevel::Info,
                            format!("A/THR {}", if athr { "ENGAGED" } else { "OFF" }),
                            None,
                        );
                    }
                    stats.last_logged_autothrottle = Some(athr);
                    stats.pending_autothrottle = None;
                    stats.pending_autothrottle_since = None;
                }
            }
        } else {
            // Snap matches last logged again — drop any pending change.
            stats.pending_autothrottle = None;
            stats.pending_autothrottle_since = None;
        }
    }

    // ---- Parking brake
    if stats.last_logged_parking_brake != Some(snap.parking_brake) {
        if stats.last_logged_parking_brake.is_some() {
            log_activity_handle(
                app,
                ActivityLevel::Info,
                format!(
                    "Parking brake {}",
                    if snap.parking_brake { "SET" } else { "RELEASED" }
                ),
                None,
            );
        }
        stats.last_logged_parking_brake = Some(snap.parking_brake);
    }

    // ---- Engines (count only — per-engine N1/N2 is a future extension)
    // Debounce 5 s: Fenix's GENERAL ENG COMBUSTION SimVar pulses
    // 0/1/0/1 during engine start and at idle, which produced phantom
    // "Engine shutdown / started" pairs in the activity log. We only
    // commit the change once the new count has held steady.
    if stats.last_logged_engines_running != Some(snap.engines_running) {
        let now = Utc::now();
        if stats.pending_engines_running != Some(snap.engines_running) {
            stats.pending_engines_running = Some(snap.engines_running);
            stats.pending_engines_running_since = Some(now);
        } else if let Some(since) = stats.pending_engines_running_since {
            if (now - since).num_seconds() >= 5 {
                if let Some(prev) = stats.last_logged_engines_running {
                    if prev < snap.engines_running {
                        log_activity_handle(
                            app,
                            ActivityLevel::Info,
                            format!(
                                "Engine started — {} running",
                                snap.engines_running
                            ),
                            None,
                        );
                    } else if prev > snap.engines_running {
                        log_activity_handle(
                            app,
                            ActivityLevel::Info,
                            format!(
                                "Engine shutdown — {} running",
                                snap.engines_running
                            ),
                            None,
                        );
                    }
                }
                stats.last_logged_engines_running = Some(snap.engines_running);
                stats.pending_engines_running = None;
                stats.pending_engines_running_since = None;
            }
        }
    } else {
        // Snap matches last logged again — drop any pending change.
        stats.pending_engines_running = None;
        stats.pending_engines_running_since = None;
    }

    // ---- Flaps detent
    // Premium-First (v0.2.4): if PMDG is loaded, use the cockpit-exact
    // Boeing handle label directly ("UP"/"1"/"5"/"15"/"30"/"40"). For
    // generic SimVars we map the normalised 0.0..1.0 position to a 0..5
    // detent — that's accurate for Airbus families (6 positions). For
    // Boeing without PMDG it's a known approximation; pilots flying
    // PMDG (the typical Boeing-study-level case) get the real labels.
    //
    // Detection: pmdg.flap_handle_label is non-empty when PMDG is the
    // source of truth. The pmdg-detent string itself is the activity-
    // log label (no detent_label() lookup needed).
    let pmdg_flap = snap
        .pmdg
        .as_ref()
        .map(|p| p.flap_handle_label.clone())
        .filter(|s| !s.is_empty());
    if let Some(label) = pmdg_flap {
        if stats.last_logged_flap_label.as_deref() != Some(label.as_str()) {
            if let Some(prev) = stats.last_logged_flap_label.as_ref() {
                // Direction: nominal numeric ordering of Boeing detents
                // ("UP" < "1" < "2" < "5" < "10" < "15" < "25" < "30" <
                // "40"). Mapping via boeing_detent_rank keeps the arrow
                // direction sensible for Boeing labels.
                let dir = if boeing_detent_rank(&label) > boeing_detent_rank(prev) {
                    "↓"
                } else {
                    "↑"
                };
                log_activity_handle(
                    app,
                    ActivityLevel::Info,
                    format!("Flaps {dir} {}", label),
                    Some(format!(
                        "IAS {:.0} kt, AGL {:.0} ft",
                        snap.indicated_airspeed_kt, snap.altitude_agl_ft
                    )),
                );
            }
            stats.last_logged_flap_label = Some(label);
            // Keep numeric path in sync to avoid double-firing if the
            // pilot swaps to a non-PMDG aircraft mid-session.
            stats.last_logged_flaps_detent = None;
        }
    } else {
        let flaps_detent = (snap.flaps_position.clamp(0.0, 1.0) * 5.0).round() as u8;
        if stats.last_logged_flaps_detent != Some(flaps_detent) {
            if let Some(prev) = stats.last_logged_flaps_detent {
                let dir = if flaps_detent > prev { "↓" } else { "↑" };
                log_activity_handle(
                    app,
                    ActivityLevel::Info,
                    format!("Flaps {dir} {}", detent_label(flaps_detent)),
                    Some(format!(
                        "IAS {:.0} kt, AGL {:.0} ft",
                        snap.indicated_airspeed_kt, snap.altitude_agl_ft
                    )),
                );
            }
            stats.last_logged_flaps_detent = Some(flaps_detent);
            stats.last_logged_flap_label = None;
        }
    }

    // ---- Stall / overspeed warnings (always loud)
    if stats.last_logged_stall != Some(snap.stall_warning) {
        if snap.stall_warning {
            log_activity_handle(
                app,
                ActivityLevel::Warn,
                "Stall warning".to_string(),
                Some(format!("IAS {:.0} kt, AGL {:.0} ft", snap.indicated_airspeed_kt, snap.altitude_agl_ft)),
            );
        }
        stats.last_logged_stall = Some(snap.stall_warning);
    }
    if stats.last_logged_overspeed != Some(snap.overspeed_warning) {
        if snap.overspeed_warning {
            log_activity_handle(
                app,
                ActivityLevel::Warn,
                "Overspeed warning".to_string(),
                Some(format!("IAS {:.0} kt", snap.indicated_airspeed_kt)),
            );
        }
        stats.last_logged_overspeed = Some(snap.overspeed_warning);
    }

    // ---- Gear handle (UP / DOWN — discretised so a moving handle
    //      doesn't fire mid-cycle entries).
    let gear_down = snap.gear_position >= 0.5;
    if stats.last_logged_gear_down != Some(gear_down) {
        if let Some(prev) = stats.last_logged_gear_down {
            if prev != gear_down {
                log_activity_handle(
                    app,
                    ActivityLevel::Info,
                    format!("Gear {}", if gear_down { "DOWN" } else { "UP" }),
                    Some(format!(
                        "AGL {:.0} ft, IAS {:.0} kt",
                        snap.altitude_agl_ft, snap.indicated_airspeed_kt
                    )),
                );
            }
        }
        stats.last_logged_gear_down = Some(gear_down);
    }

    // ---- Spoilers / speed brake.
    // We split into two events: armed (auto-deploy on touchdown) and
    // deployed (handle physically pulled back ≥5% — pilot using it
    // as speed brake or after touchdown).
    if let Some(armed) = snap.spoilers_armed {
        if stats.last_logged_spoilers_armed != Some(armed) {
            if let Some(prev) = stats.last_logged_spoilers_armed {
                if prev != armed {
                    log_activity_handle(
                        app,
                        ActivityLevel::Info,
                        format!("Speed brake {}", if armed { "ARMED" } else { "DISARMED" }),
                        None,
                    );
                }
            }
            stats.last_logged_spoilers_armed = Some(armed);
        }
    }
    if let Some(pos) = snap.spoilers_handle_position {
        let deployed = pos > 0.05;
        if stats.last_logged_spoilers_deployed != Some(deployed) {
            if let Some(prev) = stats.last_logged_spoilers_deployed {
                if prev != deployed {
                    log_activity_handle(
                        app,
                        ActivityLevel::Info,
                        format!(
                            "Spoilers {}",
                            if deployed { "DEPLOYED" } else { "RETRACTED" }
                        ),
                        if deployed {
                            Some(format!("Handle {:.0}%", pos * 100.0))
                        } else {
                            None
                        },
                    );
                }
            }
            stats.last_logged_spoilers_deployed = Some(deployed);
        }
    }

    // ---- APU. Bool-only "running" — combine the master-switch state
    //      with the RPM threshold so we log "APU started" only once
    //      the unit is actually up, not the moment the switch flips.
    if let Some(switch) = snap.apu_switch {
        let running = switch && snap.apu_pct_rpm.unwrap_or(0.0) >= 95.0;
        if stats.last_logged_apu_running != Some(running) {
            if let Some(prev) = stats.last_logged_apu_running {
                if prev != running {
                    log_activity_handle(
                        app,
                        ActivityLevel::Info,
                        format!("APU {}", if running { "started" } else { "shutdown" }),
                        None,
                    );
                }
            }
            stats.last_logged_apu_running = Some(running);
        }
    }

    // ---- Electrical / pneumatic systems.
    log_bool_change(
        app,
        snap.battery_master,
        &mut stats.last_logged_battery_master,
        "Battery master",
    );
    log_bool_change(
        app,
        snap.avionics_master,
        &mut stats.last_logged_avionics_master,
        "Avionics master",
    );
    log_bool_change(
        app,
        snap.pitot_heat,
        &mut stats.last_logged_pitot_heat,
        "Pitot heat",
    );
    log_bool_change(
        app,
        snap.engine_anti_ice,
        &mut stats.last_logged_engine_anti_ice,
        "Engine anti-ice",
    );
    log_bool_change(
        app,
        snap.wing_anti_ice,
        &mut stats.last_logged_wing_anti_ice,
        "Wing anti-ice",
    );

    // ---- Seat-belts (binary) and no-smoking (3-state).
    // Different value spaces: Fenix's `L:S_OH_SIGNS` is 0/1 (the
    // toggle uses logical-NOT) while `L:S_OH_SIGNS_SMOKING` is
    // 0/1/2 (the toggle branches between 0 and 2 explicitly).
    if let Some(v) = snap.seatbelts_sign {
        if stats.last_logged_seatbelts_sign != Some(v) {
            if stats.last_logged_seatbelts_sign.is_some() {
                let label = if v == 0 { "OFF" } else { "ON" };
                log_activity_handle(
                    app,
                    ActivityLevel::Info,
                    format!("Seat belts {label}"),
                    None,
                );
            }
            stats.last_logged_seatbelts_sign = Some(v);
        }
    }
    log_three_state_change(
        app,
        snap.no_smoking_sign,
        &mut stats.last_logged_no_smoking_sign,
        "No smoking",
    );

    // ---- Autobrake (string label).
    if let Some(ab) = snap.autobrake.as_ref() {
        if stats.last_logged_autobrake.as_ref() != Some(ab) {
            if let Some(prev) = stats.last_logged_autobrake.as_ref() {
                if prev != ab {
                    log_activity_handle(
                        app,
                        ActivityLevel::Info,
                        format!("Autobrake {ab}"),
                        None,
                    );
                }
            }
            stats.last_logged_autobrake = Some(ab.clone());
        }
    }

    // FCU encoder values (Selected ALT/HDG/SPD/V/S) intentionally
    // NOT logged. The Fenix LVars (`L:E_FCU_*`) are encoder click
    // counters, not real engineering values — Selected ALT 23 means
    // 23 clicks, not FL230 — so the log entries were misleading.
    // The standard `AUTOPILOT * VAR` SimVars give us the real values
    // already, but those don't update via LVar anyway. User feedback
    // (2026-05-02): "die brauchen wir doch nicht bekommen wir doch
    // eh schon aus dem standart" → drop entirely.

    // ---- PMDG SDK premium telemetry (Phase H.4 / v0.2.0) ----
    // Activity-log entries derived from snap.pmdg, the cockpit-
    // exact state we read via PMDG's SimConnect ClientData
    // channel. No-op if no PMDG aircraft is loaded or the SDK
    // isn't enabled (snap.pmdg is None in both cases).
    if let Some(p) = &snap.pmdg {
        // Capture variant label once for the PIREP custom fields.
        if stats.pmdg_variant_label.is_none() && !p.variant_label.is_empty() {
            stats.pmdg_variant_label = Some(p.variant_label.clone());
        }

        // Once-per-flight: aircraft identification banner.
        if !stats.pmdg_detected_logged {
            stats.pmdg_detected_logged = true;
            log_activity_handle(
                app,
                ActivityLevel::Info,
                format!("{} — PMDG SDK aktiv", p.variant_label),
                Some("Premium-Cockpit-Daten verfügbar (FMA, MCP, V-Speeds, FMC)".to_string()),
            );
        }

        // Once-per-flight: V-speeds banner when all four are set.
        // Pilots typically enter these via FMC PERF-INIT page; the
        // banner timestamps when the perf-init was completed.
        if !stats.pmdg_v_speeds_logged {
            if let (Some(v1), Some(vr), Some(v2), Some(vref)) = (
                p.fmc_v1_kt,
                p.fmc_vr_kt,
                p.fmc_v2_kt,
                p.fmc_vref_kt,
            ) {
                stats.pmdg_v_speeds_logged = true;
                log_activity_handle(
                    app,
                    ActivityLevel::Info,
                    format!("V-Speeds gesetzt: V1 {v1} · VR {vr} · V2 {v2} · VREF {vref}"),
                    None,
                );
            }
        }

        // FMA mode changes — single combined string so a switch from
        // "N1 / VNAV / LNAV" to "SPD / VNAV / LNAV" produces ONE log
        // entry, not three. Empty modes filtered out.
        let fma_combined = format_fma(&p.fma_speed_mode, &p.fma_pitch_mode, &p.fma_roll_mode);
        if stats.last_logged_pmdg_fma.as_deref() != Some(fma_combined.as_str()) {
            if let Some(prev) = stats.last_logged_pmdg_fma.as_deref() {
                if prev != fma_combined {
                    log_activity_handle(
                        app,
                        ActivityLevel::Info,
                        format!("FMA: {fma_combined}"),
                        None,
                    );
                }
            }
            stats.last_logged_pmdg_fma = Some(fma_combined);
        }

        // MCP selected speed — round to nearest knot (or .01 Mach).
        // We track as i16 so we get cheap equality. Value > 10 = knots,
        // ≤ 10 = Mach × 100. Both are valid pilot intents.
        if let Some(spd) = p.mcp_speed_raw {
            let spd_int = if spd > 10.0 {
                spd.round() as i16
            } else {
                (spd * 100.0).round() as i16
            };
            if stats.last_logged_pmdg_mcp_speed != Some(spd_int) {
                if stats.last_logged_pmdg_mcp_speed.is_some() {
                    let display = if spd > 10.0 {
                        format!("{spd:.0} kt")
                    } else {
                        format!("M {spd:.2}")
                    };
                    log_activity_handle(
                        app,
                        ActivityLevel::Info,
                        format!("MCP IAS → {display}"),
                        None,
                    );
                }
                stats.last_logged_pmdg_mcp_speed = Some(spd_int);
            }
        }

        // MCP heading — round to nearest degree.
        if let Some(hdg) = p.mcp_heading_deg {
            if stats.last_logged_pmdg_mcp_heading != Some(hdg) {
                if stats.last_logged_pmdg_mcp_heading.is_some() {
                    log_activity_handle(
                        app,
                        ActivityLevel::Info,
                        format!("MCP HDG → {hdg:03}°"),
                        None,
                    );
                }
                stats.last_logged_pmdg_mcp_heading = Some(hdg);
            }
        }

        // MCP altitude — log only on significant changes (≥ 100 ft)
        // so a moving knob doesn't spam.
        if let Some(alt) = p.mcp_altitude_ft {
            let last = stats.last_logged_pmdg_mcp_altitude;
            let significant = match last {
                Some(prev) => alt.abs_diff(prev) >= 100,
                None => true,
            };
            if significant && last != Some(alt) {
                if last.is_some() {
                    log_activity_handle(
                        app,
                        ActivityLevel::Info,
                        format!("MCP ALT → {alt} ft"),
                        None,
                    );
                }
                stats.last_logged_pmdg_mcp_altitude = Some(alt);
            }
        }

        // MCP V/S — log on changes ≥ 100 fpm.
        if let Some(vs) = p.mcp_vs_fpm {
            let last = stats.last_logged_pmdg_mcp_vs;
            let significant = match last {
                Some(prev) => (vs - prev).abs() >= 100,
                None => true,
            };
            if significant && last != Some(vs) {
                if last.is_some() {
                    log_activity_handle(
                        app,
                        ActivityLevel::Info,
                        format!("MCP V/S → {vs:+} fpm"),
                        None,
                    );
                }
                stats.last_logged_pmdg_mcp_vs = Some(vs);
            }
        }

        // A/T armed.
        if stats.last_logged_pmdg_at_armed != Some(p.at_armed) {
            if stats.last_logged_pmdg_at_armed.is_some() {
                log_activity_handle(
                    app,
                    ActivityLevel::Info,
                    format!("A/T {}", if p.at_armed { "armed" } else { "disarmed" }),
                    None,
                );
            }
            stats.last_logged_pmdg_at_armed = Some(p.at_armed);
        }

        // A/P engaged (CMD A or B).
        if stats.last_logged_pmdg_ap_engaged != Some(p.ap_engaged) {
            if stats.last_logged_pmdg_ap_engaged.is_some() {
                log_activity_handle(
                    app,
                    ActivityLevel::Info,
                    format!("A/P {}", if p.ap_engaged { "engaged" } else { "disengaged" }),
                    None,
                );
            }
            stats.last_logged_pmdg_ap_engaged = Some(p.ap_engaged);
        }

        // Takeoff config warning was here pre-v0.3.0 — moved out to a
        // simulator-agnostic block (after the PMDG `if let Some(p)`)
        // because both PMDG (MSFS) and X-Plane Zibo/LevelUp 737 fill
        // the universal `snap.takeoff_config_warning` field.

        // ---- v0.2.2 wider integration ----

        // FMC thrust-limit mode (777). Empty string = NG3 (no
        // thrust-limit field) — skip there, NG3 derives MCP_annunN1
        // for similar purpose elsewhere.
        if !p.thrust_limit_mode.is_empty()
            && stats.last_logged_pmdg_thrust_mode.as_deref()
                != Some(p.thrust_limit_mode.as_str())
        {
            if stats.last_logged_pmdg_thrust_mode.is_some() {
                log_activity_handle(
                    app,
                    ActivityLevel::Info,
                    format!("Thrust mode → {}", p.thrust_limit_mode),
                    None,
                );
            }
            stats.last_logged_pmdg_thrust_mode = Some(p.thrust_limit_mode.clone());
        }

        // 777 Electronic Checklist — log once per phase on rising
        // edge + capture for the PIREP custom field. Skips
        // silently for NG3 (ecl_complete = None).
        if let Some(ecl) = p.ecl_complete {
            // Capture for final PIREP — sticky union of all phases
            // ever ticked.
            let cap = stats.pmdg_ecl_phases_complete.get_or_insert([false; 10]);
            for (i, &done) in ecl.iter().enumerate() {
                if done {
                    cap[i] = true;
                }
            }
            for (idx, &done) in ecl.iter().enumerate() {
                if done && !stats.last_logged_pmdg_ecl[idx] {
                    let label = match idx {
                        0 => "Preflight",
                        1 => "Before Start",
                        2 => "Before Taxi",
                        3 => "Before Takeoff",
                        4 => "After Takeoff",
                        5 => "Descent",
                        6 => "Approach",
                        7 => "Landing",
                        8 => "Shutdown",
                        9 => "Secure",
                        _ => continue,
                    };
                    log_activity_handle(
                        app,
                        ActivityLevel::Info,
                        format!("ECL: {label} ✓ complete"),
                        None,
                    );
                    stats.last_logged_pmdg_ecl[idx] = true;
                }
            }
        }

        // PMDG-authoritative APU bit (777). More accurate than
        // the standard-SimVar APU_PCT_RPM heuristic. NG3 leaves
        // this None and falls back to the standard APU detection.
        if let Some(apu) = p.apu_running {
            if stats.last_logged_pmdg_apu != Some(apu) {
                if stats.last_logged_pmdg_apu.is_some() {
                    log_activity_handle(
                        app,
                        ActivityLevel::Info,
                        format!("APU {} (PMDG)", if apu { "started" } else { "shutdown" }),
                        None,
                    );
                }
                stats.last_logged_pmdg_apu = Some(apu);
            }
        }

        // Wheel chocks (777). Sets/removes around pushback time.
        if let Some(chocks) = p.wheel_chocks_set {
            if stats.last_logged_pmdg_chocks != Some(chocks) {
                if stats.last_logged_pmdg_chocks.is_some() {
                    log_activity_handle(
                        app,
                        ActivityLevel::Info,
                        format!("Chocks {}", if chocks { "ON" } else { "OFF" }),
                        None,
                    );
                }
                stats.last_logged_pmdg_chocks = Some(chocks);
            }
        }
    }

    // ---- Takeoff config warning (universal — PMDG + X-Plane 737)
    // Only on rising edge (warning turning ON). Falling edge
    // (pilot fixed it) doesn't warrant a log line. Source field
    // is filled by both adapters: MSFS via the PMDG snapshot()
    // merge, X-Plane via the `laminar/B738/annunciator/takeoff_config`
    // DataRef. None on aircraft that don't have an EICAS check.
    if let Some(to_warn) = snap.takeoff_config_warning {
        if stats.last_logged_pmdg_to_warning != Some(to_warn) {
            if to_warn {
                log_activity_handle(
                    app,
                    ActivityLevel::Warn,
                    "TAKEOFF CONFIG warning".to_string(),
                    Some("Cockpit zeigt rote Warnung — TO-Setup unvollständig".to_string()),
                );
            }
            stats.last_logged_pmdg_to_warning = Some(to_warn);
        }
    }

    // ---- v0.16.10 Premium-Cockpit-Daten (FMA, V-Speeds, Warnings, …) ----
    // Quellen: profile-gated LVar-Mapper (Fenix/FBW/INI-A350/INI-A340/
    // Aerosoft-A346/MD-11) + PMDG-Premium-Override. Felder sind None wenn
    // die Quelle sie nicht liefert — None loggt NIE. Latch-/Debounce-
    // Regeln pro Zeile: siehe Feld-Doku auf FlightStats.
    let now = Utc::now();

    // (0) v0.16.10 QS (M5): Connect-Grace — direkt nach einem Stream-
    // (Re-)Start lesen die Addon-LVars 0.0 bis das WASM sie befüllt;
    // ohne Grace latchte Tick 1 Bogus-Werte und Tick 2 loggte Phantom-
    // Transitionen ("Baro: STD gesetzt" / "MASTER CAUTION" beim
    // Connect/Resume). Während des Fensters wird KEIN Premium-Tracker
    // gefüttert (das Premium-Logging ist der letzte Abschnitt dieser
    // Funktion → early return überspringt nur Premium-Zeilen).
    {
        let FlightStats {
            premium_log_last_tick_at,
            premium_log_warmup_until,
            ..
        } = &mut *stats;
        if premium_log_warmup_active(premium_log_last_tick_at, premium_log_warmup_until, now) {
            return;
        }
    }

    // (1) Generic-FMA-Zeile — NUR ohne PMDG: das PMDG-FMA-Logging oben
    // ist für PMDG authoritativ, doppelt loggen wäre Spam. Erster Wert
    // latcht stumm (wie beim PMDG-Logger), Änderungen debounced 3 s.
    if snap.pmdg.is_none() {
        if let Some(line) = fmt_fma_line(
            snap.fma_lateral_mode.as_deref(),
            snap.fma_vertical_mode.as_deref(),
            snap.fma_thrust_mode.as_deref(),
        ) {
            if stats
                .premium_fma
                .update(line.clone(), now, PREMIUM_FMA_DEBOUNCE_SECS)
            {
                log_activity_handle(app, ActivityLevel::Info, format!("FMA: {line}"), None);
            }
        }
    }

    // (2) Takeoff-V-Speeds — loggt sobald V1+VR+V2 komplett sind
    // (= FMS-Perf-Init fertig, der erste Treffer ist der informative)
    // und bei jeder späteren Änderung. FLEX gehört zum Latch-Key
    // (Perf-Daten-Änderung), das "· TOGA"-Suffix nicht (Lever-Bewegung).
    // v0.16.10 QS (M3): NUR ohne PMDG — apply_pmdg_premium_override
    // mappt die FMC-V-Speeds in die generischen v1_kt/…-Felder, und
    // PMDG hat oben bereits sein eigenes "V-Speeds gesetzt:"-Banner
    // (pmdg_v_speeds_logged). Ohne Gate käme jede PMDG-Perf-Eingabe
    // doppelt ins Log.
    if snap.pmdg.is_none() {
        if let (Some(v1), Some(vr), Some(v2)) = (snap.v1_kt, snap.vr_kt, snap.v2_kt) {
            let key = (
                v1.round() as i64,
                vr.round() as i64,
                v2.round() as i64,
                snap.flex_temp_c.map(|t| t.round() as i64),
            );
            if stats.last_logged_vspeeds != Some(key) {
                stats.last_logged_vspeeds = Some(key);
                log_activity_handle(
                    app,
                    ActivityLevel::Info,
                    fmt_vspeeds_line(v1, vr, v2, snap.flex_temp_c, snap.thrust_gate.as_deref()),
                    None,
                );
            }
        }
    }

    // (3) Approach-Speeds — nur in Descent/Approach/Final (vorher sind
    // VAPP/VLS oft noch Climb-Artefakte bzw. nicht final berechnet).
    // Erster Some-Wert loggt sofort (update_first_logs), danach re-log
    // bei Änderung. v0.16.10 QS (B1): VLS/VAPP driften auf FBW/INI
    // laufend (Gewichts-/Konfig-Neuberechnung, Flap-Sweep) → Latch-Key
    // auf 5-kt-Buckets quantisiert + 10 s Debounce, sonst 20-70 Zeilen
    // pro Approach. v0.16.10 QS (M3): NUR ohne PMDG (VREF kommt dort
    // aus dem Override, das PMDG-Banner loggt sie bereits).
    if snap.pmdg.is_none()
        && matches!(
            stats.phase,
            FlightPhase::Descent | FlightPhase::Approach | FlightPhase::Final
        )
    {
        if let Some(line) = fmt_approach_speeds_line(snap.vapp_kt, snap.vls_kt, snap.vref_kt) {
            let bucket =
                |v: Option<f64>| v.map(|x| (x / APPROACH_SPEEDS_BUCKET_KT).round() as i64);
            let key = (
                bucket(snap.vapp_kt),
                bucket(snap.vls_kt),
                bucket(snap.vref_kt),
            );
            if stats
                .premium_approach_speeds
                .update_first_logs(key, now, APPROACH_SPEEDS_DEBOUNCE_SECS)
            {
                log_activity_handle(app, ActivityLevel::Info, line, None);
            }
        }
    }

    // (4) MASTER CAUTION / MASTER WARNING — Transitionen, debounced 2 s
    // (Annunciator-Tests am Boden flackern), erster Wert latcht stumm.
    // v0.16.10 QS (Minor 7): am Boden mit 0 laufenden Engines komplett
    // unterdrückt (Tracker wird NICHT gefüttert) — Cold&Dark-Preflight-
    // Self-Tests (Overhead-Tests, IRS-Align, Recall-Checks) zünden die
    // Lampen reihenweise, ohne dass es ein meldenswertes Ereignis wäre.
    // Nach Engine-Start latcht der erste Wert stumm (First-Silent).
    let preflight_self_test_window = snap.on_ground && snap.engines_running == 0;
    if let Some(mc) = snap.master_caution.filter(|_| !preflight_self_test_window) {
        if stats
            .premium_master_caution
            .update(mc, now, MASTER_ANNUNCIATOR_DEBOUNCE_SECS)
        {
            if mc {
                log_activity_handle(app, ActivityLevel::Warn, "⚠ MASTER CAUTION".to_string(), None);
            } else {
                log_activity_handle(app, ActivityLevel::Info, "MASTER CAUTION aus".to_string(), None);
            }
        }
    }
    if let Some(mw) = snap.master_warning.filter(|_| !preflight_self_test_window) {
        if stats
            .premium_master_warning
            .update(mw, now, MASTER_ANNUNCIATOR_DEBOUNCE_SECS)
        {
            if mw {
                log_activity_handle(app, ActivityLevel::Error, "🔴 MASTER WARNING".to_string(), None);
            } else {
                log_activity_handle(app, ActivityLevel::Info, "MASTER WARNING aus".to_string(), None);
            }
        }
    }

    // (5)+(6) Umkehrschub + Ground-Spoiler — je einmal pro Landung
    // (Rising-Edge am Boden), re-arm sobald airborne: ein Touch-and-Go
    // bekommt so für die nächste Landung wieder eigene Einträge.
    // v0.16.10 QS (Minor 6): zusätzlich Groundspeed > 40 kt an der
    // Rising-Edge verlangt — Lever-Checks beim Taxi (Reverser kurz
    // ziehen, Spoiler-Test am Stand) loggen sonst "Umkehrschub
    // aktiviert" ohne Landung. Echte Landungen/RTOs liegen weit drüber.
    // Borrow-Split: stats ist ein MutexGuard, Feld-Borrows splitten
    // nicht durch den Deref — also die Felder einzeln rausziehen.
    {
        let fast_enough = snap.groundspeed_kt > REVERSER_SPOILER_MIN_GS_KT;
        let FlightStats {
            last_seen_reverser,
            reverser_logged_this_landing,
            last_seen_ground_spoilers,
            ground_spoilers_logged_this_landing,
            ..
        } = &mut *stats;
        if once_per_landing_rising_edge(
            snap.reverser_deployed,
            snap.on_ground,
            fast_enough,
            last_seen_reverser,
            reverser_logged_this_landing,
        ) {
            log_activity_handle(
                app,
                ActivityLevel::Info,
                "Umkehrschub aktiviert".to_string(),
                None,
            );
        }
        if once_per_landing_rising_edge(
            snap.ground_spoilers_active,
            snap.on_ground,
            fast_enough,
            last_seen_ground_spoilers,
            ground_spoilers_logged_this_landing,
        ) {
            log_activity_handle(
                app,
                ActivityLevel::Info,
                "Ground Spoiler ausgefahren".to_string(),
                None,
            );
        }
    }

    // (7) Baro STD/QNH — erster Wert latcht stumm (beim Connect steht
    // der Baro halt irgendwie), danach loggt jede Transition.
    if let Some(std_set) = snap.baro_std {
        if stats.last_logged_baro_std != Some(std_set) {
            if stats.last_logged_baro_std.is_some() {
                log_activity_handle(
                    app,
                    ActivityLevel::Info,
                    if std_set {
                        "Baro: STD gesetzt"
                    } else {
                        "Baro: QNH gesetzt"
                    }
                    .to_string(),
                    None,
                );
            }
            stats.last_logged_baro_std = Some(std_set);
        }
    }

    // (8) Flugzeug-eigene FMGC/FWC-Phase — rein informativ, erster Wert
    // stumm, 5 s Debounce. Rohe "#n"-Labels werden bewusst mitgeloggt.
    if let Some(phase_label) = snap.flight_phase_aircraft.as_ref() {
        if stats.premium_aircraft_phase.update(
            phase_label.clone(),
            now,
            AIRCRAFT_PHASE_DEBOUNCE_SECS,
        ) {
            log_activity_handle(
                app,
                ActivityLevel::Info,
                format!("Flugzeug meldet Phase: {phase_label}"),
                None,
            );
        }
    }

    // (9) Below-G/S-Alert — einmal pro Approach; re-arm wenn der Alert
    // > BELOW_GS_REARM_SECS geklärt ist oder die FlightPhase wechselt
    // (Go-Around → neuer Approach darf wieder loggen). Erster Wert
    // latcht stumm — ein beim Connect bereits aktiver Alert zählt als
    // "schon geloggt".
    if stats.below_gs_armed_phase != Some(stats.phase) {
        stats.below_gs_armed_phase = Some(stats.phase);
        stats.below_gs_logged_this_approach = false;
    }
    if let Some(below) = snap.below_gs_alert {
        // Borrow-Split: Felder einzeln rausziehen damit der Helper
        // drei &mut auf disjunkte stats-Felder bekommt.
        let FlightStats {
            last_seen_below_gs,
            below_gs_logged_this_approach,
            below_gs_clear_since,
            ..
        } = &mut *stats;
        if below_gs_should_log(
            below,
            now,
            last_seen_below_gs,
            below_gs_logged_this_approach,
            below_gs_clear_since,
        ) {
            log_activity_handle(
                app,
                ActivityLevel::Warn,
                "⚠ Below Glideslope".to_string(),
                None,
            );
        }
    }

    // (10) Kabinenhöhen-Warnung — selten + ernst, nur Rising-Edge,
    // erster Wert latcht stumm.
    if let Some(cab) = snap.cabin_altitude_warning {
        if stats.last_logged_cabin_alt_warning != Some(cab) {
            if stats.last_logged_cabin_alt_warning.is_some() && cab {
                log_activity_handle(
                    app,
                    ActivityLevel::Error,
                    "🔴 Kabinenhöhe-Warnung".to_string(),
                    None,
                );
            }
            stats.last_logged_cabin_alt_warning = Some(cab);
        }
    }

    // (11) Stab-out-of-trim — debounced 5 s (Annunciator pulst während
    // Trim-Läufen), nur die Rising-Edge loggt.
    if let Some(oot) = snap.stab_out_of_trim {
        if stats
            .premium_stab_out_of_trim
            .update(oot, now, STAB_TRIM_DEBOUNCE_SECS)
            && oot
        {
            log_activity_handle(
                app,
                ActivityLevel::Warn,
                "⚠ Stabilizer out of trim".to_string(),
                None,
            );
        }
    }

    // (12) Schubhebel-Detent — nur INI-Profile liefern das Gate-Label;
    // generisches None loggt nie. Erster Wert latcht stumm (der Hebel
    // steht beim Connect irgendwo), Wechsel debounced 3 s.
    if let Some(gate) = snap.thrust_gate.as_ref() {
        if stats
            .premium_thrust_gate
            .update(gate.clone(), now, THRUST_GATE_DEBOUNCE_SECS)
        {
            log_activity_handle(app, ActivityLevel::Info, format!("Schubhebel: {gate}"), None);
        }
    }
}

/// Combine FMA sub-modes into a single human-readable string.
/// Empty sub-modes are filtered out so a partially-engaged FMA
/// reads "VNAV / LNAV" rather than " / VNAV / LNAV".
fn format_fma(speed: &str, pitch: &str, roll: &str) -> String {
    let parts: Vec<&str> = [speed, pitch, roll]
        .iter()
        .copied()
        .filter(|s| !s.is_empty())
        .collect();
    if parts.is_empty() {
        "—".to_string()
    } else {
        parts.join(" / ")
    }
}

/// v0.16.10: Generic-FMA-Zeile aus den drei normalisierten Sub-Modes
/// (lateral | vertical | thrust). None-/Leer-Teile werden weggelassen
/// ("NAV | SPEED" wenn vertical fehlt); alles None ⇒ None — der
/// Aufrufer loggt dann gar nicht (anders als das PMDG-`format_fma`,
/// das "—" liefert, weil dort ein leeres FMA selbst informativ ist).
fn fmt_fma_line(
    lateral: Option<&str>,
    vertical: Option<&str>,
    thrust: Option<&str>,
) -> Option<String> {
    let parts: Vec<&str> = [lateral, vertical, thrust]
        .into_iter()
        .flatten()
        .map(str::trim)
        .filter(|s| !s.is_empty())
        .collect();
    if parts.is_empty() {
        None
    } else {
        Some(parts.join(" | "))
    }
}

/// v0.16.10: Takeoff-V-Speeds-Zeile. FLEX-Suffix wenn eine Assumed-Temp
/// gesetzt ist, sonst "· TOGA" wenn der Schubhebel GERADE im
/// TOGA-Detent steht (nur INI-Profile liefern das Gate).
fn fmt_vspeeds_line(
    v1: f64,
    vr: f64,
    v2: f64,
    flex_temp_c: Option<f64>,
    thrust_gate: Option<&str>,
) -> String {
    let mut line = format!("V-Speeds: V1 {v1:.0} · VR {vr:.0} · V2 {v2:.0}");
    if let Some(flex) = flex_temp_c {
        line.push_str(&format!(" · FLEX {flex:.0}°C"));
    } else if thrust_gate == Some("TOGA") {
        line.push_str(" · TOGA");
    }
    line
}

/// v0.16.10: Approach-Speeds-Zeile (VAPP Airbus / VLS Airbus / VREF
/// Boeing) — None-Teile weggelassen, alles None ⇒ None (kein Log).
fn fmt_approach_speeds_line(
    vapp: Option<f64>,
    vls: Option<f64>,
    vref: Option<f64>,
) -> Option<String> {
    let mut parts: Vec<String> = Vec::new();
    if let Some(v) = vapp {
        parts.push(format!("VAPP {v:.0}"));
    }
    if let Some(v) = vls {
        parts.push(format!("VLS {v:.0}"));
    }
    if let Some(v) = vref {
        parts.push(format!("VREF {v:.0}"));
    }
    if parts.is_empty() {
        None
    } else {
        Some(format!("Approach-Speeds: {}", parts.join(" · ")))
    }
}

/// v0.16.10: Einmal-pro-Landung-Rising-Edge-Detektor (Umkehrschub,
/// Ground-Spoiler). `true` ⇒ jetzt loggen. Regeln:
///   * loggt nur eine false→true-Transition WÄHREND on_ground,
///   * v0.16.10 QS (Minor 6): nur wenn an der Rising-Edge auch
///     `fast_enough` gilt (Groundspeed > 40 kt) — Taxi-Lever-Checks
///     loggen nicht und VERBRAUCHEN den Einmal-Latch auch nicht
///     (eine echte spätere Landung loggt weiterhin),
///   * erster beobachteter Wert latcht stumm (Resume mitten im
///     Rollout produziert keinen nachträglichen Eintrag),
///   * einmal pro Landung — re-arm sobald airborne (Touch-and-Go
///     bekommt für die nächste Landung einen frischen Eintrag).
fn once_per_landing_rising_edge(
    value: Option<bool>,
    on_ground: bool,
    fast_enough: bool,
    last_seen: &mut Option<bool>,
    logged_this_landing: &mut bool,
) -> bool {
    if !on_ground {
        *logged_this_landing = false;
    }
    let Some(v) = value else { return false };
    let rising = *last_seen == Some(false) && v;
    *last_seen = Some(v);
    if rising && on_ground && fast_enough && !*logged_this_landing {
        *logged_this_landing = true;
        true
    } else {
        false
    }
}

/// v0.16.10: Below-G/S-Alert-Latch. `true` ⇒ "⚠ Below Glideslope"
/// jetzt loggen. Regeln:
///   * nur die false→true-Transition loggt,
///   * erster beobachteter Wert latcht stumm — ein beim Connect
///     bereits aktiver Alert zählt als "schon geloggt",
///   * einmal pro Approach — re-arm erst wenn der Alert
///     `BELOW_GS_REARM_SECS` am Stück geklärt war (der Phase-Wechsel-
///     Re-Arm sitzt im Aufrufer, der die FlightPhase kennt).
fn below_gs_should_log(
    below: bool,
    now: DateTime<Utc>,
    last_seen: &mut Option<bool>,
    logged_this_approach: &mut bool,
    clear_since: &mut Option<DateTime<Utc>>,
) -> bool {
    if below {
        *clear_since = None;
    } else {
        if clear_since.is_none() {
            *clear_since = Some(now);
        }
        if let Some(since) = *clear_since {
            if (now - since).num_seconds() >= BELOW_GS_REARM_SECS {
                *logged_this_approach = false;
            }
        }
    }
    let result = match *last_seen {
        None => {
            if below {
                *logged_this_approach = true;
            }
            false
        }
        Some(prev) => {
            if !prev && below && !*logged_this_approach {
                *logged_this_approach = true;
                true
            } else {
                false
            }
        }
    };
    *last_seen = Some(below);
    result
}

/// Activity-log helper for 3-state cabin signs (OFF / AUTO / ON).
fn log_three_state_change(
    app: &AppHandle,
    snap_value: Option<u8>,
    last_logged: &mut Option<u8>,
    label: &str,
) {
    let Some(v) = snap_value else { return };
    if *last_logged != Some(v) {
        if last_logged.is_some() {
            let state = match v {
                0 => "OFF",
                1 => "AUTO",
                2 => "ON",
                _ => return,
            };
            log_activity_handle(
                app,
                ActivityLevel::Info,
                format!("{label} {state}"),
                None,
            );
        }
        *last_logged = Some(v);
    }
}

// v0.7.13: `fcu_debounce()` entfernt — wurde fuer Fenix-LVar-Logging
// gebraucht, der Plan ist verworfen (Fenix-Encoder-Klicks sind nicht
// engineering-Werte). Falls revival fuer `AUTOPILOT * VAR`-SimVars:
// aus git history rausziehen. Audit Q4-2026-05.

/// Helper for bool-only telemetry change logging — checks Option,
/// initialises silently on first read, and emits an activity-log line
/// on every subsequent transition.
fn log_bool_change(
    app: &AppHandle,
    snap_value: Option<bool>,
    last_logged: &mut Option<bool>,
    label: &str,
) {
    let Some(v) = snap_value else { return };
    if *last_logged != Some(v) {
        if let Some(prev) = *last_logged {
            if prev != v {
                log_activity_handle(
                    app,
                    ActivityLevel::Info,
                    format!("{label} {}", if v { "ON" } else { "OFF" }),
                    None,
                );
            }
        }
        *last_logged = Some(v);
    }
}

fn snapshot_to_position(snap: &SimSnapshot) -> PositionEntry {
    PositionEntry {
        lat: snap.lat,
        lon: snap.lon,
        // v0.16.15: `altitude` = Altimeter-Anzeige (was der Pilot sieht,
        // PMDG-FL360-Befund KLM1540: GPS-Hoehe lag +1.100 ft drueber);
        // `altitude_msl` bleibt bewusst die geometrische Hoehe.
        altitude: snap.altitude_indicated_ft.unwrap_or(snap.altitude_msl_ft),
        altitude_agl: Some(snap.altitude_agl_ft),
        altitude_msl: Some(snap.altitude_msl_ft),
        heading: Some(snap.heading_deg_magnetic),
        gs: Some(snap.groundspeed_kt),
        vs: Some(snap.vertical_speed_fpm),
        ias: Some(snap.indicated_airspeed_kt),
        // phpVMS expects pounds for both the on-board total and the flow.
        fuel: Some((snap.fuel_total_kg as f64 * KG_TO_LB) as f32),
        fuel_flow: snap
            .fuel_flow_kg_per_h
            .map(|kgph| (kgph as f64 * KG_TO_LB) as f32),
        transponder: snap.transponder_code,
        autopilot: snap.autopilot_master,
        // distance-to-destination needs arrival airport coords; filled in
        // by `step_flight` once the airports cache has them. Leave None
        // for now so we don't send a misleading 0.
        distance: None,
        log: build_position_log(snap),
        sim_time: snap.timestamp.to_rfc3339(),
    }
}

/// v0.13.8: log-Blob fuer phpVMS-Positions deaktiviert.
///
/// Hintergrund: Bei einem 3.5h-Flug entstanden mit der vorherigen
/// vollen log-Payload ~400 KB JSON nur fuer das log-Feld (Lights,
/// COM/NAV, AP-Modi, State-Bits, Env, ATC, Profile) - 99% davon
/// duplizierten sich zwischen aufeinanderfolgenden Cruise-Samples.
/// Pilot-Befund: phpVMS-PIREP-Detail-Seite oeffnet sich langsam bei
/// grossen Fluegen.
///
/// Loesung: phpVMS bekommt nur noch die strukturierten Felder
/// (lat/lon/alt/gs/ias/vs/fuel/heading/transponder/autopilot/distance/
/// sim_time). Das log-Feld bleibt None.
///
/// Die volle Telemetrie (Lights, COM/NAV, AP-Modi, State, Env, ATC,
/// Profile) geht weiterhin **komplett** an den VPS-Recorder via MQTT
/// (separater Stream, anderer Code-Pfad). Forensik + Live-Map + Reply
/// sind unveraendert. Nur phpVMS sieht die schlankere Variante - das
/// PIREP-Detail-Page rendert dadurch zigfach schneller.
///
/// Wenn man jemals wieder ein paar Felder ans phpVMS schicken will
/// (z. B. nur Lights+State bei Phase-Wechsel) - hier wieder anbauen,
/// idealerweise mit einem Filter "nur emittieren wenn sich was vs.
/// last_sent geaendert hat".
fn build_position_log(_snap: &SimSnapshot) -> Option<String> {
    None
}

// ---- Simulator selection + status ----

#[derive(Debug, Clone, Serialize, Deserialize, Default)]
struct SimConfig {
    #[serde(default)]
    kind: SimKind,
}

fn sim_config_path(app: &AppHandle) -> Result<PathBuf, UiError> {
    app.path()
        .app_config_dir()
        .map(|dir| dir.join(SIM_CONFIG_FILE))
        .map_err(|e| UiError::new("config_path", e.to_string()))
}

fn read_sim_config(app: &AppHandle) -> SimConfig {
    let Ok(path) = sim_config_path(app) else {
        return SimConfig::default();
    };
    if !path.exists() {
        return SimConfig::default();
    }
    match std::fs::read(&path).map(|b| serde_json::from_slice::<SimConfig>(&b)) {
        Ok(Ok(cfg)) => cfg,
        _ => SimConfig::default(),
    }
}

fn write_sim_config(app: &AppHandle, cfg: &SimConfig) -> Result<(), UiError> {
    let path = sim_config_path(app)?;
    if let Some(parent) = path.parent() {
        std::fs::create_dir_all(parent)
            .map_err(|e| UiError::new("config_write", e.to_string()))?;
    }
    let json = serde_json::to_vec_pretty(cfg)
        .map_err(|e| UiError::new("config_serialize", e.to_string()))?;
    std::fs::write(&path, json).map_err(|e| UiError::new("config_write", e.to_string()))
}

/// Apply the selected kind to whichever adapter handles it. Always
/// stops the inactive adapter so we never have both listening
/// simultaneously (= duplicate snapshots in `current_snapshot`).
fn apply_sim_kind(state: &tauri::State<'_, AppState>, kind: SimKind) {
    // Stop both adapters first; we'll start exactly one (or none) below.
    #[cfg(target_os = "windows")]
    {
        let mut msfs = state.msfs.lock().expect("msfs lock");
        msfs.stop();
    }
    {
        let mut xp = state.xplane.lock().expect("xplane lock");
        xp.stop();
    }

    if kind.is_msfs() {
        #[cfg(target_os = "windows")]
        {
            let mut msfs = state.msfs.lock().expect("msfs lock");
            msfs.start(kind);
        }
    } else if kind.is_xplane() {
        let mut xp = state.xplane.lock().expect("xplane lock");
        xp.start(kind);
    }
    // SimKind::Off → both stay stopped.
}

#[derive(Serialize, Default)]
pub struct SimStatus {
    /// "disconnected" | "connecting" | "connected"
    state: String,
    /// User-selected sim ("off" | "msfs2020" | "msfs2024" | "xplane11" | "xplane12").
    kind: String,
    snapshot: Option<SimSnapshot>,
    last_error: Option<String>,
    /// Whether the selected kind is actually implemented in this build.
    available: bool,
}

fn kind_str(kind: SimKind) -> &'static str {
    match kind {
        SimKind::Off => "off",
        SimKind::Msfs2020 => "msfs2020",
        SimKind::Msfs2024 => "msfs2024",
        SimKind::XPlane11 => "xplane11",
        SimKind::XPlane12 => "xplane12",
    }
}

/// `GET` the persisted sim selection.
#[tauri::command]
fn sim_get_kind(app: AppHandle) -> String {
    kind_str(read_sim_config(&app).kind).to_string()
}

/// Persist a new sim selection AND apply it to the running adapter.
/// Accepts: "off" | "msfs2020" | "msfs2024" | "xplane11" | "xplane12".
#[tauri::command]
fn sim_set_kind(
    app: AppHandle,
    state: tauri::State<'_, AppState>,
    kind: String,
) -> Result<(), UiError> {
    let parsed = match kind.as_str() {
        "off" => SimKind::Off,
        "msfs2020" => SimKind::Msfs2020,
        "msfs2024" => SimKind::Msfs2024,
        "xplane11" => SimKind::XPlane11,
        "xplane12" => SimKind::XPlane12,
        _ => return Err(UiError::new("invalid_sim_kind", format!("unknown kind: {kind}"))),
    };
    write_sim_config(&app, &SimConfig { kind: parsed })?;
    apply_sim_kind(&state, parsed);
    tracing::info!(?parsed, "sim kind selected");
    Ok(())
}

#[tauri::command]
fn sim_status(app: AppHandle, state: tauri::State<'_, AppState>) -> SimStatus {
    let kind = read_sim_config(&app).kind;

    // X-Plane path is available on every platform (UDP, no platform-
    // specific deps).
    if kind.is_xplane() {
        let adapter = state.xplane.lock().expect("xplane lock");
        let s = match adapter.state() {
            sim_xplane::ConnectionState::Disconnected => "disconnected",
            sim_xplane::ConnectionState::Connecting => "connecting",
            sim_xplane::ConnectionState::Connected => "connected",
        };
        return SimStatus {
            state: s.into(),
            kind: kind_str(kind).into(),
            snapshot: adapter.snapshot(),
            last_error: adapter.last_error(),
            available: true,
        };
    }

    // MSFS path is Windows-only.
    #[cfg(target_os = "windows")]
    {
        let adapter = state.msfs.lock().expect("msfs lock");
        if kind.is_msfs() {
            let s = match adapter.state() {
                sim_msfs::ConnectionState::Disconnected => "disconnected",
                sim_msfs::ConnectionState::Connecting => "connecting",
                sim_msfs::ConnectionState::Connected => "connected",
            };
            return SimStatus {
                state: s.into(),
                kind: kind_str(kind).into(),
                snapshot: adapter.snapshot(),
                last_error: adapter.last_error(),
                available: true,
            };
        }
        // SimKind::Off
        return SimStatus {
            state: "disconnected".into(),
            kind: kind_str(kind).into(),
            snapshot: None,
            last_error: None,
            available: kind == SimKind::Off,
        };
    }

    #[cfg(not(target_os = "windows"))]
    {
        let _ = state;
        let last_error = if kind.is_msfs() {
            Some("MSFS adapter is Windows-only".into())
        } else {
            None
        };
        SimStatus {
            state: "disconnected".into(),
            kind: kind_str(kind).into(),
            snapshot: None,
            last_error,
            available: kind == SimKind::Off,
        }
    }
}

/// Pilot-initiated re-sync of the active sim adapter's cached
/// snapshot. Clears the lat/lon/etc. cache so `sim_status` returns
/// `state: "connecting"` + `snapshot: None` until the next genuine
/// frame arrives. Lets the briefing tab recover from edge cases the
/// automatic 5 s stale-timeout doesn't cover (sim paused while
/// changing flight, SimConnect trickles stale data, etc.) without
/// any "skip the gate" override semantics.
#[tauri::command]
fn sim_force_resync(app: AppHandle, state: tauri::State<'_, AppState>) {
    let kind = read_sim_config(&app).kind;
    if kind.is_xplane() {
        state.xplane.lock().expect("xplane lock").clear_snapshot();
        return;
    }
    #[cfg(target_os = "windows")]
    {
        if kind.is_msfs() {
            state.msfs.lock().expect("msfs lock").clear_snapshot();
        }
    }
}

// ---- PMDG SDK status (Phase H.4 / v0.2.0) ----
//
// The Settings tab needs to know:
//   * Is a PMDG aircraft loaded? (variant detected)
//   * Are we subscribed?
//   * Are we actually receiving data? (= SDK enabled in pilot's
//     options ini)
// to show the "SDK enabled?" hint when needed and to display the
// premium-telemetry status badge in the cockpit tab.

/// Minimal serializable PMDG status for the UI. Mirrors the
/// adapter's `PmdgStatus` but with the variant flattened to a
/// string so JSON parsing is trivial on the frontend side.
#[derive(serde::Serialize)]
struct PmdgStatusDto {
    /// `"ng3"`, `"x777"`, or `null` when no PMDG aircraft is loaded.
    variant: Option<&'static str>,
    /// True once SimConnect ClientData subscription has been
    /// successfully registered.
    subscribed: bool,
    /// True once at least one ClientData packet has actually arrived.
    /// `subscribed && !ever_received` (after a few seconds) is the
    /// signal that SDK isn't enabled in the pilot's options ini.
    ever_received: bool,
    /// Seconds since the last ClientData packet. `null` when never.
    stale_secs: Option<u64>,
    /// True when (variant detected, subscribed, but no data flowing
    /// for >5 s) — the heuristic for "SDK probably not enabled".
    /// UI shows the enable-hint modal when this is true.
    looks_like_sdk_disabled: bool,
}

#[tauri::command]
fn pmdg_status(state: tauri::State<'_, AppState>) -> PmdgStatusDto {
    #[cfg(target_os = "windows")]
    {
        let adapter = state.msfs.lock().expect("msfs lock");
        let s = adapter.pmdg_status();
        return PmdgStatusDto {
            variant: s.variant.map(|v| match v {
                sim_msfs::pmdg::PmdgVariant::Ng3 => "ng3",
                sim_msfs::pmdg::PmdgVariant::X777 => "x777",
            }),
            subscribed: s.subscribed,
            ever_received: s.ever_received,
            stale_secs: if s.stale_secs == u64::MAX {
                None
            } else {
                Some(s.stale_secs)
            },
            looks_like_sdk_disabled: s.looks_like_sdk_disabled(),
        };
    }
    #[cfg(not(target_os = "windows"))]
    {
        let _ = state;
        PmdgStatusDto {
            variant: None,
            subscribed: false,
            ever_received: false,
            stale_secs: None,
            looks_like_sdk_disabled: false,
        }
    }
}

// ---- Live SimVar / LVar inspector (Settings → Debug) ----
//
// These commands forward to the MsfsAdapter's inspector watchlist
// (Phase B). Non-Windows targets just return errors / empty lists
// since the adapter is Windows-only anyway.

#[derive(serde::Deserialize)]
pub(crate) struct InspectorAddArgs {
    name: String,
    unit: String,
    /// "number" | "bool" | "string" — matches sim_msfs::WatchKind.
    kind: String,
}

#[tauri::command]
fn inspector_add(
    _state: tauri::State<'_, AppState>,
    args: InspectorAddArgs,
) -> Result<u32, UiError> {
    #[cfg(target_os = "windows")]
    {
        let kind = match args.kind.as_str() {
            "number" => sim_msfs::WatchKind::Number,
            "bool" => sim_msfs::WatchKind::Bool,
            "string" => sim_msfs::WatchKind::String,
            _ => {
                return Err(UiError::new(
                    "invalid_watch_kind",
                    format!("unknown kind: {}", args.kind),
                ))
            }
        };
        let trimmed_name = args.name.trim().to_string();
        let trimmed_unit = args.unit.trim().to_string();
        if trimmed_name.is_empty() {
            return Err(UiError::new(
                "empty_name",
                "SimVar / LVar name cannot be empty",
            ));
        }
        let adapter = _state.msfs.lock().expect("msfs lock");
        let id = adapter.add_watch(trimmed_name, trimmed_unit, kind);
        Ok(id)
    }
    #[cfg(not(target_os = "windows"))]
    {
        let _ = args;
        Err(UiError::new("unsupported", "inspector is Windows-only"))
    }
}

#[tauri::command]
fn inspector_remove(
    _state: tauri::State<'_, AppState>,
    id: u32,
) -> Result<(), UiError> {
    #[cfg(target_os = "windows")]
    {
        let adapter = _state.msfs.lock().expect("msfs lock");
        adapter.remove_watch(id);
        Ok(())
    }
    #[cfg(not(target_os = "windows"))]
    {
        let _ = id;
        Err(UiError::new("unsupported", "inspector is Windows-only"))
    }
}

#[tauri::command]
fn inspector_list(_state: tauri::State<'_, AppState>) -> Vec<serde_json::Value> {
    #[cfg(target_os = "windows")]
    {
        let adapter = _state.msfs.lock().expect("msfs lock");
        adapter
            .watches()
            .into_iter()
            .map(|w| serde_json::to_value(w).unwrap_or(serde_json::Value::Null))
            .collect()
    }
    #[cfg(not(target_os = "windows"))]
    {
        Vec::new()
    }
}

// v0.7.16 introduced an opt-in `set_fenix_beta_enabled` / `get_fenix_beta_enabled`
// Tauri-Command-Paar fuer das Fenix-A32x-Profil. v0.7.17 (F-001) hat das wieder
// entfernt: die Fenix-Erkennung ist jetzt automatisch (siehe AircraftProfile::
// is_fenix()), die LVAR-Overrides werden bedingungslos fuer Fenix-Aircraft
// angewendet, ohne dass der Pilot in den Settings einen Haken setzen muss.

/// X-Plane DataRef inspector: returns the static catalog with the
/// most recent received value per entry. Unlike the MSFS Inspector
/// (where the user adds names manually) the X-Plane catalog is
/// fixed at compile time — every DataRef we subscribe is shown.
/// Pilots use this to verify the UDP feed is alive and the Sim is
/// responding to RREF subscriptions.
#[tauri::command]
fn xplane_inspector_list(state: tauri::State<'_, AppState>) -> Vec<serde_json::Value> {
    let adapter = state.xplane.lock().expect("xplane lock");
    adapter
        .subscribed_datarefs()
        .into_iter()
        .map(|s| serde_json::to_value(s).unwrap_or(serde_json::Value::Null))
        .collect()
}

/// Best-effort detection of the X-Plane install path. Returns the
/// absolute path as a string when found, or `null` when nothing
/// plausible exists — UI then falls back to a folder picker.
///
/// MUST be async + `spawn_blocking`: the Windows path runs
/// `reg.exe query` (sub-process spawn ~200-800ms cold-start) plus
/// up to 4 filesystem `is_dir` probes. Doing that on a sync
/// `#[tauri::command]` blocks the Tauri IPC bandwidth and freezes
/// the Settings panel during its first paint (v0.5.0 release-day
/// regression — pilot reported jerky scrolling + language-switcher
/// hang while the registry probe was running).
#[tauri::command]
async fn xplane_detect_install_path() -> Option<String> {
    tauri::async_runtime::spawn_blocking(|| {
        xplane_plugin_install::detect_install_path()
            .map(|p| p.to_string_lossy().into_owned())
    })
    .await
    .unwrap_or(None)
}

/// Download the matching plugin zip from this AeroACARS version's
/// GitHub release and extract it into `<install_dir>/Resources/
/// plugins/AeroACARS/`. Idempotent — overwrites in place. Returns
/// the install summary (path, bytes, files) on success, or an
/// error message string on failure.
#[tauri::command]
async fn xplane_install_plugin(
    install_dir: String,
) -> Result<xplane_plugin_install::PluginInstallResult, String> {
    let path = std::path::PathBuf::from(install_dir);
    xplane_plugin_install::install_plugin(&path).await
}

// v0.7.13: `xplane_uninstall_plugin` Tauri-Command entfernt — UI hat
// nie einen "Plugin deinstallieren"-Button gehabt. Manuell loescht der
// Pilot via Settings → X-Plane → Plugin-Ordner anzeigen → Loeschen.
// Helper `xplane_plugin_install::uninstall_plugin` ebenfalls entfernt.
// Audit Q4-2026-05.

/// Status of the optional AeroACARS X-Plane Plugin (v0.5.0+
/// "Premium Mode"). The Cockpit tab uses this to show a green
/// "X-PLANE PREMIUM" badge when frame-perfect telemetry is flowing.
///
/// Return shape (JSON):
///   {
///     "active":      bool,    // packets in last 3 s
///     "ever_seen":   bool,    // any packet this session
///     "packet_count": u64,    // total since adapter start
///     "last_error":  string?  // bind-failure reason, if any
///   }
///
/// Inert when the active sim isn't X-Plane (returns all-false).
#[tauri::command]
fn xplane_premium_status(state: tauri::State<'_, AppState>) -> serde_json::Value {
    let adapter = state.xplane.lock().expect("xplane lock");
    let s = adapter.premium_status();
    let err = adapter.premium_last_error();
    serde_json::json!({
        "active": s.active,
        "ever_seen": s.ever_seen,
        "packet_count": s.packet_count,
        "last_error": err,
    })
}

// v0.7.13: `detect_running_sim` Tauri-Command entfernt — geplanter
// "Detect Sim"-Button kam nie ins Settings-UI. Frontend zeigt die
// Sim-Kind-Picker manuell. Audit Q4-2026-05.

/// On login or session restore, check the on-disk active-flight file. If it's
/// recent enough, recreate the in-memory ActiveFlight and restart position
/// streaming — picks up exactly where the previous run left off.
async fn try_resume_flight(
    app: &AppHandle,
    state: &tauri::State<'_, AppState>,
    client: &Client,
) {
    let Some(persisted) = read_persisted_flight(app) else {
        return;
    };
    // Drop sessions that are clearly stale (e.g. a flight from days ago) so
    // we don't keep flogging a long-dead PIREP forever.
    let age = Utc::now() - persisted.started_at;
    if age > chrono::Duration::hours(RESUME_MAX_AGE_HOURS) {
        tracing::info!(
            pirep_id = %persisted.pirep_id,
            age_hours = age.num_hours(),
            "discarding stale persisted flight"
        );
        clear_persisted_flight(app);
        return;
    }

    // Verify the PIREP still exists server-side BEFORE rebuilding the
    // streamer. phpVMS's RemoveExpiredLiveFlights cron may have soft-deleted
    // it while the client was offline (heartbeat couldn't fire), in which
    // case adopting locally would just produce a wave of 404s. A 404 here
    // means the PIREP is gone — clear the disk record and let the user
    // re-prefile cleanly. Other errors (network, auth) are non-fatal —
    // we proceed and let the streamer's own error handling kick in.
    match client.get_pirep(&persisted.pirep_id).await {
        Ok(p) => {
            // State 0 = IN_PROGRESS. Anything else means the PIREP was
            // filed / cancelled / accepted elsewhere — there's nothing for
            // us to resume into.
            if p.state.is_some() && p.state != Some(0) {
                tracing::info!(
                    pirep_id = %persisted.pirep_id,
                    state = ?p.state,
                    status = ?p.status,
                    "persisted PIREP no longer in progress, discarding resume"
                );
                clear_persisted_flight(app);
                log_activity_handle(
                    app,
                    ActivityLevel::Warn,
                    "Gespeicherter Flug nicht mehr aktiv".to_string(),
                    Some(format!(
                        "PIREP {} hat serverseitig Status {:?} — Resume verworfen.",
                        persisted.pirep_id, p.status
                    )),
                );
                return;
            }
        }
        Err(ApiError::NotFound) => {
            tracing::info!(
                pirep_id = %persisted.pirep_id,
                "persisted PIREP no longer on server (likely soft-deleted by cron), discarding resume"
            );
            clear_persisted_flight(app);
            log_activity_handle(
                app,
                ActivityLevel::Warn,
                "Gespeicherter Flug existiert nicht mehr".to_string(),
                Some(
                    "phpVMS hat den PIREP entfernt (vermutlich Inaktivitäts-Timeout). \
                     Bitte den Flug neu starten oder als Manual-PIREP einreichen."
                        .to_string(),
                ),
            );
            return;
        }
        Err(e) => {
            tracing::warn!(
                pirep_id = %persisted.pirep_id,
                error = %e,
                "could not verify persisted PIREP — proceeding with resume anyway"
            );
        }
    }

    // Same guard as flight_start / flight_adopt: if another resume is
    // already running (StrictMode double-mount in dev fires
    // phpvms_load_session twice in close succession), bail silently.
    // Without this, the second resume would do a duplicate get_bids /
    // get_aircraft round-trip even though the first had already won.
    let _setup_guard = match FlightSetupGuard::try_acquire(&state.flight_setup_in_progress) {
        Ok(g) => g,
        Err(_) => {
            tracing::debug!("resume already in progress, skipping duplicate call");
            return;
        }
    };

    {
        let guard = state.active_flight.lock().expect("active_flight lock");
        if guard.is_some() {
            // Expected on second mount under React StrictMode (dev) — the
            // first mount already restored the flight. Idempotent, no WARN.
            tracing::debug!("active flight already in memory, skipping resume");
            return;
        }
    }

    tracing::info!(
        pirep_id = %persisted.pirep_id,
        age_minutes = age.num_minutes(),
        "resuming in-progress flight"
    );
    record_event(
        app,
        &persisted.pirep_id,
        &FlightLogEvent::FlightResumed {
            timestamp: Utc::now(),
            pirep_id: persisted.pirep_id.clone(),
            age_minutes: age.num_minutes(),
        },
    );

    // Backfill missing airline ICAO + planned registration. PersistedFlight
    // defaults to "" when the JSON pre-dates these fields, or when the flight
    // was originally adopted from a discovered PIREP that didn't have a
    // matching bid. Try get_bids() once on resume; if nothing matches we
    // leave them empty and the UI renders without them — same as before.
    let mut airline_icao = persisted.airline_icao.clone();
    let mut planned_registration = persisted.planned_registration.clone();
    if airline_icao.is_empty() || planned_registration.is_empty() {
        if let Ok(bids) = client.get_bids().await {
            if let Some(matching) = bids
                .iter()
                .find(|b| b.flight.flight_number == persisted.flight_number)
            {
                if airline_icao.is_empty() {
                    if let Some(a) = matching.flight.airline.as_ref() {
                        airline_icao = a.icao.clone();
                    }
                }
                if planned_registration.is_empty() {
                    if let Some(id) = matching
                        .flight
                        .simbrief
                        .as_ref()
                        .and_then(|sb| sb.aircraft_id)
                    {
                        if let Ok(details) = client.get_aircraft(id).await {
                            planned_registration = details
                                .registration
                                .unwrap_or_default()
                                .trim()
                                .to_string();
                        }
                    }
                }
            }
        }
    }

    // Restore stats so the resumed flight continues with the distance,
    // fuel-burn and phase the streamer had right before the crash.
    // Without this, every resume produces a "0 distance / 0 fuel" PIREP
    // because we'd start the stats from zero again.
    let mut restored_stats = FlightStats::new();
    persisted.stats.clone().apply_to(&mut restored_stats);
    tracing::info!(
        distance_nm = restored_stats.distance_nm,
        position_count = restored_stats.position_count,
        ?restored_stats.phase,
        "restored flight stats from disk"
    );

    // v0.15.25: reseed the in-app live-map track from phpVMS — the server holds
    // the authoritative SUPERSET of every position we ever posted. A mid-flight
    // app update/restart starts `FlightStats.track` empty (and a stale
    // localStorage seed-gate in the UI could hide a clean backend track), so we
    // replace the locally-persisted track with the complete server track here.
    // This runs inside the already-async fn, on a local `&mut` (no lock held
    // across the await), and strictly BEFORE `restored_stats` is moved into the
    // ActiveFlight Arc below — so there's no race with the streamer.
    match client.get_acars_positions(&persisted.pirep_id).await {
        Ok(pts) if !pts.is_empty() => {
            restored_stats.track.clear();
            for p in &pts {
                // Skip null-coordinate rows (lat/lon nullable in phpVMS).
                // on_ground=false (AIR threshold): the historical replay has no
                // reliable ground state, and the coarser AIR threshold keeps the
                // reseeded track light.
                if let (Some(lon), Some(lat)) = (p.lon, p.lat) {
                    record_track_point(&mut restored_stats, lon, lat, false);
                }
            }
            tracing::info!(
                pirep_id = %persisted.pirep_id,
                raw = pts.len(),
                thinned = restored_stats.track.len(),
                "seeded live-map track from server on resume"
            );
        }
        Ok(_) => {} // server has no rows yet → keep the persisted track from apply_to
        Err(e) => {
            tracing::warn!(
                pirep_id = %persisted.pirep_id,
                error = %e,
                "server track fetch failed — keeping local persisted track"
            );
        }
    }

    let flight = Arc::new(ActiveFlight {
        pirep_id: persisted.pirep_id.clone(),
        bid_id: persisted.bid_id,
        // v0.7.7: flight_id aus PersistedFlight wieder herholen. Bei
        // pre-v0.7.7-Resume-Files ist das Feld leer (String::new() via
        // serde(default)) — v0.7.8 muss diesen Fall als "legacy active
        // flight, direct refresh unavailable" behandeln.
        flight_id: persisted.flight_id.clone(),
        // v0.7.8 v1.5: Callsign-Felder aus PersistedFlight. None bei
        // pre-v0.7.8-Resume — Match faellt auf airline+flight_number
        // zurueck.
        bid_callsign: persisted.bid_callsign.clone(),
        pilot_callsign: persisted.pilot_callsign.clone(),
        started_at: persisted.started_at,
        airline_icao,
        // Resume-Pfad: Airline-Logo-URL aus der persisted Bid wieder
        // herholen. Wenn die Persisted-Snapshot-Version das Feld nicht
        // hatte (alter Build vor v0.4.0), bleibt None.
        airline_logo_url: persisted.airline_logo_url.clone(),
        planned_registration,
        // v0.3.0: Aircraft-Type bei Resume aus dem persisted Flight ist
        // nicht direkt verfügbar — der frühere Stand hatte das nicht.
        // Beim Resume bleibt der Custom-Field "Aircraft Type" daher
        // leer. Akzeptabel, weil Resume eh nur passiert wenn der
        // Pilot mitten im Flug die App neu startet — der ursprüngliche
        // PIREP hat die Aircraft-Daten phpVMS-seitig schon.
        aircraft_icao: String::new(),
        aircraft_name: String::new(),
        flight_number: persisted.flight_number.clone(),
        dpt_airport: persisted.dpt_airport.clone(),
        arr_airport: persisted.arr_airport.clone(),
        fares: persisted.fares.clone(),
        stats: Mutex::new(restored_stats),
        stop: AtomicBool::new(false),
        // Flag the UI to surface a 10-second confirmation banner before any
        // position posts go out. The streamer is intentionally NOT spawned
        // here — `flight_resume_confirm` does that once the user accepts (or
        // the timer expires), or `flight_cancel` aborts the PIREP.
        was_just_resumed: AtomicBool::new(true),
        streamer_spawned: AtomicBool::new(false),
        cancelled_remotely: AtomicBool::new(false),
        position_outbox: Mutex::new(std::collections::VecDeque::new()),
        phpvms_worker_spawned: AtomicBool::new(false),
        touchdown_sampler_spawned: AtomicBool::new(false),
        connection_state: std::sync::atomic::AtomicU8::new(CONN_STATE_LIVE),
        // v0.8.0: Navdata-Cache startet leer — wird von
        // `fetch_navdata_for_flight` (Slice B) parallel beim Flugstart
        // populiert. Leer = OurAirports-Fallback aktiv (= Verhalten
        // vor v0.8.0).
        navdata: Mutex::new(NavdataCache::default()),
    });

    // v0.8.0: vor dem move den Navdata-Fetch spawnen.
    // Resume-Pfad: Alternate kommt aus restored_stats.planned_alternate
    // (= via persisted JSON wiederhergestellt). Bei pre-v0.8.0-Resume-
    // Files ohne planned_alternate bleibt es bei dep+arr.
    {
        let mut icaos = vec![flight.dpt_airport.clone(), flight.arr_airport.clone()];
        let alt = flight
            .stats
            .lock()
            .expect("flight stats lock")
            .planned_alternate
            .clone();
        if let Some(a) = alt {
            if !a.trim().is_empty() {
                icaos.push(a);
            }
        }
        spawn_navdata_fetch(app, &flight, icaos);
    }
    {
        let mut guard = state.active_flight.lock().expect("active_flight lock");
        *guard = Some(flight);
    }
    // NOTE: do not spawn the streamer here. The frontend-driven
    // `flight_resume_confirm` does it after the resume banner is dismissed.
}

// ---- Bootstrap ----

// ---- Auto-start watcher ----
//
// Polls every AUTO_START_INTERVAL_SECS while enabled. When the
// aircraft is parked at the departure airport of one of the user's
// bids AND the loaded aircraft type/registration matches the bid,
// it fires `flight_start` for that bid. Stops re-firing for the
// same bid until the resulting flight ends (tracked via
// `AppState::auto_start_last_bid_id`).
const AUTO_START_INTERVAL_SECS: u64 = 3;
/// v0.15.13: Cooldown nach einem fehlgeschlagenen Auto-Start-`flight_start`.
/// Bevor derselbe Bid erneut gefeuert wird, müssen so viele Sekunden vergehen.
/// Stoppt den 3-s-Retry-Sturm (GlitchTip #10), bleibt aber selbst-korrigierend.
const AUTO_START_FAIL_COOLDOWN_SECS: i64 = 120;
/// How close to the departure airport (in meters) the aircraft must
/// be to trigger auto-start. 5 km is generous enough for any major
/// airport's stand area; tighter and we'd miss bids where the pilot
/// spawns at a distant gate.
const AUTO_START_PROXIMITY_M: f64 = 5_000.0;

#[tauri::command]
fn auto_start_get_enabled(state: tauri::State<'_, AppState>) -> bool {
    state.auto_start_enabled.load(Ordering::Relaxed)
}

/// v0.3.0: Persistenz-Pfad für Auto-Start-Setting. localStorage geht im
/// Tauri-Dev-Mode bzw. nach Force-Kill der App regelmäßig verloren —
/// Backend-File überlebt jeden Restart und ist die Source-of-Truth.
fn auto_start_settings_path(app: &AppHandle) -> Option<PathBuf> {
    app.path()
        .app_config_dir()
        .ok()
        .map(|p| p.join("auto_start.json"))
}

fn read_auto_start_persisted(app: &AppHandle) -> bool {
    let path = match auto_start_settings_path(app) {
        Some(p) => p,
        None => return false,
    };
    let text = match std::fs::read_to_string(&path) {
        Ok(t) => t,
        Err(_) => return false,
    };
    // Datei-Format ist trivial: `{"enabled": true}` oder `{"enabled": false}`.
    // Kein serde-Overkill, plain regex-style match.
    text.contains("\"enabled\":true") || text.contains("\"enabled\": true")
}

fn write_auto_start_persisted(app: &AppHandle, enabled: bool) {
    let Some(path) = auto_start_settings_path(app) else { return };
    if let Some(parent) = path.parent() {
        let _ = std::fs::create_dir_all(parent);
    }
    let body = format!("{{\"enabled\":{}}}", enabled);
    let _ = std::fs::write(&path, body);
}

/// v0.3.0: Frontend-API für den Auto-Start-Skip-Grund. Liefert den
/// aktuellen Reason-Code (engines_on / moving / airborne) plus das
/// Alter in Sekunden seit der Watcher den letzten Skip festgestellt
/// hat. Frontend rendert daraus einen Banner im Briefing-Tab — der
/// Pilot wartet ja nicht im Settings-Log auf Hinweise.
///
/// Liefert `None` wenn alles passt (kein Skip kürzlich) oder Auto-
/// Start aus ist.
#[tauri::command]
fn auto_start_skip_status(
    state: tauri::State<'_, AppState>,
) -> Option<AutoStartSkipDto> {
    if !state.auto_start_enabled.load(Ordering::Relaxed) {
        return None;
    }
    let g = state.auto_start_skip_reason.lock().unwrap();
    let (at, code) = g.as_ref()?;
    let age_secs = (Utc::now() - *at).num_seconds();
    // Älter als 10 s: vermutlich nicht mehr aktuell — Frontend soll
    // den Banner nicht zeigen.
    if age_secs > 10 {
        return None;
    }
    Some(AutoStartSkipDto {
        reason: code.clone(),
        age_secs,
    })
}

#[derive(Debug, Clone, Serialize)]
struct AutoStartSkipDto {
    reason: String,
    age_secs: i64,
}

#[tauri::command]
fn auto_start_set_enabled(
    enabled: bool,
    app: AppHandle,
    state: tauri::State<'_, AppState>,
) -> Result<(), UiError> {
    let was = state.auto_start_enabled.swap(enabled, Ordering::Relaxed);
    // v0.3.0: Persistieren in JSON-File damit der Toggle-Stand auch
    // nach App-Restart / Force-Kill / Dev-Build erhalten bleibt.
    write_auto_start_persisted(&app, enabled);
    // The watcher task itself runs for the entire app lifetime (spawned
    // once in `.setup()`); flipping this flag is enough — no need to
    // spawn or kill anything here. Earlier versions did spawn-on-toggle,
    // which had a first-launch failure mode on Mac where the watcher
    // never came up at all and toggling off→on didn't recover (because
    // the gate `!was` blocked re-spawn after an IPC race).
    if enabled && !was {
        log_activity_handle(
            &app,
            ActivityLevel::Info,
            "Auto-Start aktiviert".to_string(),
            Some("Watcher prüft alle 3 s ob ein Bid + Departure-Airport zueinander passen".to_string()),
        );
    } else if !enabled && was {
        log_activity_handle(
            &app,
            ActivityLevel::Info,
            "Auto-Start deaktiviert".to_string(),
            None,
        );
    }
    Ok(())
}

/// v0.12.6: Spiegelt das Frontend-Auto-File-Setting (localStorage) in
/// den Backend-State. Das Frontend ruft das bei Mount + bei jedem
/// Toggle. Der Position-Streamer liest das Flag beim Latch auf
/// `Arrived` und filet den PIREP dann selbst — fenster-unabhängig.
#[tauri::command]
fn set_auto_file_enabled(enabled: bool, state: tauri::State<'_, AppState>) {
    state.auto_file_enabled.store(enabled, Ordering::Relaxed);
}

/// Spawn the auto-start watcher task. Idempotent in practice:
/// the body checks `auto_start_enabled` on every tick and returns
/// when false, so spawning twice just means one drops out quickly.
fn spawn_auto_start_watcher(app: AppHandle) {
    tauri::async_runtime::spawn(async move {
        tracing::info!("auto-start watcher started");
        // v0.13.16 (Option C): Cache der erwarteten Aircraft-ICAO pro
        // phpVMS-aircraft_id. Der Typ eines Aircraft-Datensatzes ist
        // immutabel, also genügt EIN get_aircraft je Flieger — kein
        // API-Spam pro 3-s-Tick. Wird für den alias-bewussten Typ-
        // Vorabcheck genutzt (nur wenn ein Bid in Reichweite + warm ist).
        let mut expected_icao_cache: std::collections::HashMap<i64, Option<String>> =
            std::collections::HashMap::new();
        // v0.15.16: Zeitpunkt des letzten VPS-Alias-Warm-Versuchs. Der Watcher
        // prüft den Aircraft-Typ alias-bewusst (Option C), der Alias-Cache wurde
        // bisher aber NUR bei flight_start/spawn_navdata_fetch geladen — vor dem
        // ersten Flug war er leer → ein aliased Flugzeug (z.B. E55P↔"PHENOM 300")
        // konnte NIE auto-starten (Henne-Ei). Wir wärmen den Cache jetzt lazy.
        let mut alias_warm_attempt_at: Option<DateTime<Utc>> = None;
        loop {
            tokio::time::sleep(Duration::from_secs(AUTO_START_INTERVAL_SECS)).await;
            let state = app.state::<AppState>();
            // No-op when disabled — the watcher itself runs forever now
            // (spawned once at app start), the toggle just gates the
            // body. Used to `break` and rely on a re-spawn on next
            // toggle, which raced with first-launch IPC on Mac.
            if !state.auto_start_enabled.load(Ordering::Relaxed) {
                continue;
            }
            // Skip if a flight is already active.
            {
                let guard = state.active_flight.lock().expect("active_flight lock");
                if guard.is_some() {
                    continue;
                }
            }
            // v0.15.16: VPS-Alias-Cache lazy warm halten. Ohne das wäre er vor
            // dem ersten Flug leer → der alias-bewusste Typ-Vorabcheck unten
            // verwirft ein aliased Flugzeug (E55P↔"PHENOM 300E") fälschlich als
            // Mismatch und Auto-Start griffe NIE (Henne-Ei: Auto-Start braucht
            // den Alias, der Alias kam bisher erst bei flight_start). Nur wenn
            // der Cache leer ist + gedrosselt auf 60 s (Token evtl. erst nach
            // Provisioning verfügbar; bei Fehler/Timeout bleibt er leer und wird
            // in 60 s erneut versucht). Best-effort, 5 s-Timeout — hängt den
            // Watcher nie.
            {
                let cache_empty = state
                    .aircraft_aliases_vps
                    .lock()
                    .expect("aircraft_aliases_vps lock")
                    .is_empty();
                let now = Utc::now();
                // v0.16.19: NICHT mehr nur bei leerem Cache nachladen. Sonst
                // griff ein neu im VA-Admin angelegter Alias auf dem Auto-
                // Start-Pfad erst nach einem App-Neustart (der Cache war ja
                // schon einmal gewärmt → nie wieder gefetcht). Jetzt: leerer
                // Cache → schnelles Retry (60 s, Erst-Warmup unverändert),
                // gefüllter Cache → periodischer Refresh (5 min), damit
                // hinzugefügte/geänderte/gelöschte Aliase ohne Neustart
                // greifen. fetch_… macht cache.clear()+neu NUR bei Erfolg,
                // wischt also nie bei Netzfehler. Best-effort, 5 s-Timeout.
                let refresh_due_secs = if cache_empty { 60 } else { 300 };
                let due = alias_warm_attempt_at
                    .is_none_or(|at| (now - at).num_seconds() >= refresh_due_secs);
                if due {
                    alias_warm_attempt_at = Some(now);
                    let token =
                        secrets::load_api_key(MQTT_KEYRING_PASSWORD).ok().flatten();
                    let _ = tokio::time::timeout(
                        Duration::from_secs(5),
                        fetch_aircraft_aliases_into_state(app.clone(), None, token),
                    )
                    .await;
                }
            }
            // Skip if no sim snapshot yet, or the aircraft is moving /
            // engines on (= already taxiing or rolling, not "ready to
            // fire" anymore). v0.3.0: bei jedem Skip einen kurzen
            // Hint im Activity-Log, damit der Pilot weiß WARUM Auto-
            // Start nicht greift. Throttled auf 1× / 60 s pro reason
            // damit der Log nicht spamt.
            let Some(snap) = current_snapshot(&app) else {
                continue;
            };
            // v0.3.0: Race-Condition-Fix nach Sim-Reconnect. Wenn der
            // Sim gerade frisch connected ist (Pilot hat X-Plane neu
            // gestartet), hat der Snapshot kurz Default-0-Werte
            // (engines=0, on_ground=true, gs=0) — die ALLE die
            // Auto-Start-Bedingungen "scheinbar erfüllen" und der
            // Watcher fired BEVOR die echten Daten reinkommen
            // (Triebwerke an, Aircraft-Title gesetzt etc.). Pilot
            // hat dann ungewollt einen Auto-Start mit laufenden
            // Triebwerken bekommen.
            //
            // v0.7.17 (N-003a/b/c): Differenzierte Diagnose statt
            // pauschalem Skip. Bisher war der "nicht warm"-Skip stumm
            // (nur Debug-Log), was Piloten ohne X-Plane-Web-API ratlos
            // zurueckliess — siehe Michel's „Auto-Start funktioniert
            // nicht"-Report.
            //   * `aircraft_title` leer → bei XP12-Profil ist die
            //     Web-API nicht aktiviert (Settings → Network); bei
            //     MSFS der Sim noch im Boot.
            //   * `fuel_total_kg` ≤ 100 → Anti-Race-Sanity ist zu
            //     strikt fuer Light-GA. Wir lockern auf > 1 kg, was
            //     den Sim-Boot-Race weiter abfaengt (Default = 0) ohne
            //     legitime kleine Sprits auszuschliessen.
            let title_missing = snap
                .aircraft_title
                .as_deref()
                .map(|s| s.trim().is_empty())
                .unwrap_or(true);
            let fuel_zero = snap.fuel_total_kg <= 1.0;
            let warm_reason: Option<(&'static str, &'static str)> =
                if title_missing && matches!(snap.simulator, sim_core::Simulator::XPlane11 | sim_core::Simulator::XPlane12) {
                    Some((
                        "title_missing_xplane",
                        "Auto-Start wartet auf Sim-Daten: Aircraft-Titel fehlt. In X-Plane Settings → Network → Web API einschalten, damit AeroACARS den Flugzeug-Namen lesen kann.",
                    ))
                } else if title_missing {
                    Some((
                        "title_missing",
                        "Auto-Start wartet auf Sim-Daten: Aircraft-Titel fehlt. Sim ist noch im Boot oder das Flugzeug ist nicht voll geladen.",
                    ))
                } else if fuel_zero {
                    Some((
                        "fuel_zero",
                        "Auto-Start wartet auf Sim-Daten: Fuel = 0. Tank ist leer (Cold & Dark ohne Sprit) oder Sim noch im Boot.",
                    ))
                } else {
                    None
                };
            let skip_reason: Option<(&'static str, &'static str)> = if let Some(r) = warm_reason {
                Some(r)
            } else if !snap.on_ground {
                Some(("airborne", "Du bist in der Luft — Auto-Start funktioniert nur am Boden"))
            } else if snap.groundspeed_kt > 5.0 {
                Some(("moving", "Flugzeug rollt schon — Auto-Start greift nur am Stand"))
            } else if snap.engines_running > 0 {
                Some(("engines_on", "Triebwerke sind an — Auto-Start greift nur bei kalt/stehendem Flugzeug. Manuell 'Flug starten' nutzen."))
            } else {
                None
            };
            if let Some((reason_code, reason_msg)) = skip_reason {
                // Throttle: nur loggen wenn wir den Grund 60s+ nicht
                // gemeldet haben oder der Grund neu ist.
                let now = Utc::now();
                let should_log = {
                    let mut g = state.auto_start_skip_reason.lock().unwrap();
                    let log_it = match g.as_ref() {
                        None => true,
                        Some((_, last_code)) if last_code != reason_code => true,
                        Some((last_at, _))
                            if (now - *last_at).num_seconds() >= 60 =>
                        {
                            true
                        }
                        _ => false,
                    };
                    if log_it {
                        *g = Some((now, reason_code.to_string()));
                    }
                    log_it
                };
                if should_log {
                    log_activity_handle(
                        &app,
                        ActivityLevel::Info,
                        "Auto-Start: nicht möglich".to_string(),
                        Some(reason_msg.to_string()),
                    );
                }
                continue;
            }
            // v0.12.11: KEIN unbedingtes `*g = None` mehr hier. Der Reset
            // bei erfüllten Voraussetzungen löschte den Throttle-State
            // direkt VOR dem „no_bids"-Check — ein geparktes Flugzeug
            // ohne gebuchten Bid loggte die „keine Bids"-Zeile dadurch
            // bei JEDEM Poll (alle paar Sekunden, siehe Live-Log Sven M /
            // FDX1636: 150+ identische Einträge). Die Code-Wechsel-
            // Erkennung im skip_reason-Zweig liefert ohnehin einen
            // frischen Hint, sobald sich der Grund tatsächlich ändert.
            // Fetch the user's bids to find a match.
            let client = match {
                let g = state.client.lock().expect("client lock");
                g.clone()
            } {
                Some(c) => c,
                None => continue, // not logged in
            };
            let bids = match client.get_bids().await {
                Ok(v) => v,
                Err(_) => continue,
            };
            // v0.7.17 (N-003): Wenn die Bid-Liste leer ist, sagen wir
            // es dem Piloten — vorher Silent-Skip.
            if bids.is_empty() {
                let now = Utc::now();
                // v0.12.11: reine Edge-Detektion. „Keine Bids" ist ein
                // Dauerzustand, kein Ereignis — nur loggen, wenn der
                // Grund NEU auf „no_bids" wechselt, nicht bei jedem Poll.
                // (Vorher: `matches!(.., None | Some((_,_)))` war immer
                // true und die 60-s-Drossel wurde vom Reset oben außer
                // Kraft gesetzt → Sekundentakt-Spam.)
                let should_log = {
                    let mut g = state.auto_start_skip_reason.lock().unwrap();
                    let log_it = g
                        .as_ref()
                        .map_or(true, |(_, code)| code != "no_bids");
                    if log_it {
                        *g = Some((now, "no_bids".to_string()));
                    }
                    log_it
                };
                if should_log {
                    log_activity_handle(
                        &app,
                        ActivityLevel::Info,
                        "Auto-Start: keine Bids verfuegbar".to_string(),
                        Some("Im phpVMS-Bid-Tab steht aktuell nichts gebucht. Logged-in?".to_string()),
                    );
                }
                continue;
            }
            // Don't re-fire for the same bid within the same parked
            // session. Cleared in `flight_end` via the active_flight
            // guard above resetting on the next tick.
            let last_bid = {
                let g = state.auto_start_last_bid_id.lock().unwrap();
                *g
            };
            let mut any_match_attempt = false;
            let mut closest_nm: Option<f64> = None;
            let mut fired = false;
            // v0.13.16 (Option C): falls ein Bid in Reichweite + warm ist,
            // aber der Flugzeug-TYP nicht passt, merken wir das hier für den
            // Post-Loop-Hint (statt blind flight_start zu feuern). Tuple =
            // (flight_number, erwartete ICAO, Sim-ICAO).
            let mut mismatch_info: Option<(String, String, String)> = None;
            for bid in &bids {
                if Some(bid.id) == last_bid {
                    continue;
                }
                // v0.15.13: Fehler-Cooldown. Ist dieser Bid kürzlich an
                // flight_start gescheitert (missing_aircraft / flight_already_active
                // / …), feuern wir ihn AUTO_START_FAIL_COOLDOWN_SECS lang nicht
                // erneut — sonst Retry-Sturm alle 3 s (GlitchTip #10). Wie das
                // last_bid-Skip behandelt: zählt nicht als Match-Versuch, damit
                // der Post-Loop-Hint nicht fälschlich „kein Match" meldet.
                {
                    let g = state.auto_start_fail.lock().unwrap();
                    if let Some((at, fbid, _code)) = g.as_ref() {
                        if *fbid == bid.id
                            && (Utc::now() - *at).num_seconds()
                                < AUTO_START_FAIL_COOLDOWN_SECS
                        {
                            continue;
                        }
                    }
                }
                any_match_attempt = true;
                // v0.7.17 (N-003): Track nearest-bid distance fuer
                // den Aktivity-Log-Hint, wenn am Ende KEIN Bid matcht.
                if let Some((apt_lat, apt_lon)) =
                    runway::airport_position(&bid.flight.dpt_airport_id)
                {
                    let dist_nm = runway::distance_m(snap.lat, snap.lon, apt_lat, apt_lon)
                        / 1852.0;
                    closest_nm = Some(closest_nm.map_or(dist_nm, |c| c.min(dist_nm)));
                }
                if !bid_matches_current_state(bid, &snap) {
                    continue;
                }
                // v0.13.16 (Option C): alias-bewusster Aircraft-Typ-Vorabcheck
                // BEVOR wir feuern. Vorher feuerte der Watcher blind
                // flight_start; bei Aircraft-Mismatch (z.B. Bid E55P vs Sim
                // „PHENOM 300E", oder fehlender Alias) lief er in einen
                // 3-s-Dauer-Retry, der den `flight_setup_in_progress`-Lock
                // hielt und das manuelle „Trotzdem starten" des Piloten
                // blockierte (Live-Report Michael K / DWW306, 2026-06-03).
                // Jetzt prüfen wir den Typ vorab mit DERSELBEN Logik wie das
                // flight_start-Gate (`aircraft_type_matches_sim`, inkl. VPS-
                // Aliase) und feuern nur, wenn es matchen würde — selbst-
                // korrigierend: lädt der Pilot das passende Flugzeug ODER
                // wird der VPS-Alias ergänzt, matcht der nächste Tick und der
                // Auto-Start greift automatisch. Echter Wetlease: Watcher
                // überspringt korrekt, Lock bleibt frei fürs manuelle
                // Override. get_aircraft nur hier (Bid in Reichweite + warm)
                // und pro aircraft_id gecacht → kein Per-Tick-API-Spam.
                let expected_icao: Option<String> = match bid
                    .flight
                    .simbrief
                    .as_ref()
                    .and_then(|sb| sb.aircraft_id)
                {
                    Some(ac_id) => match expected_icao_cache.get(&ac_id) {
                        Some(cached) => cached.clone(),
                        None => match client.get_aircraft(ac_id).await {
                            Ok(ac) => {
                                let v = ac
                                    .icao
                                    .as_ref()
                                    .map(|s| s.trim().to_uppercase())
                                    .filter(|s| !s.is_empty());
                                expected_icao_cache.insert(ac_id, v.clone());
                                v
                            }
                            // Auflösung fehlgeschlagen → NICHT cachen (nächster
                            // Tick versucht's erneut), für jetzt permissiv.
                            Err(e) => {
                                tracing::debug!(
                                    ?e,
                                    ac_id,
                                    "auto-start: get_aircraft für Typ-Vorabcheck fehlgeschlagen — permissiv"
                                );
                                None
                            }
                        },
                    },
                    None => None,
                };
                let sim_icao = snap.aircraft_icao.as_deref().and_then(clean_atc_model);
                let sim_title = snap.aircraft_title.as_deref().unwrap_or("");
                let aliases_snapshot = state
                    .aircraft_aliases_vps
                    .lock()
                    .expect("aircraft_aliases_vps lock")
                    .clone();
                if !aircraft_type_matches_sim(
                    expected_icao.as_deref(),
                    sim_icao.as_deref(),
                    sim_title,
                    &aliases_snapshot,
                ) {
                    // Typ passt nicht → NICHT feuern, NICHT claimen. Der
                    // Post-Loop-Hint meldet es (gedrosselt). Pilot übersteuert
                    // manuell („Trotzdem starten") oder lädt das richtige
                    // Flugzeug → nächster Tick matcht.
                    mismatch_info = Some((
                        bid.flight.flight_number.clone(),
                        expected_icao.clone().unwrap_or_else(|| "?".to_string()),
                        sim_icao.clone().unwrap_or_else(|| "?".to_string()),
                    ));
                    continue;
                }
                // Match — fire flight_start.
                tracing::info!(
                    bid_id = bid.id,
                    flight = %bid.flight.flight_number,
                    "auto-start triggering flight_start"
                );
                log_activity_handle(
                    &app,
                    ActivityLevel::Info,
                    format!(
                        "Auto-Start: {} {} → {}",
                        bid.flight.flight_number,
                        bid.flight.dpt_airport_id,
                        bid.flight.arr_airport_id
                    ),
                    Some(format!(
                        "Aircraft {} matched bid {}",
                        snap.aircraft_title.as_deref().unwrap_or("(unknown)"),
                        bid.id
                    )),
                );
                {
                    let mut g = state.auto_start_last_bid_id.lock().unwrap();
                    *g = Some(bid.id);
                }
                let app_for_call = app.clone();
                let bid_id = bid.id;
                tauri::async_runtime::spawn(async move {
                    let state_ref = app_for_call.state::<AppState>();
                    // v0.8.3 (#7): Auto-Start liefert kein acknowledge mit —
                    // ein Aircraft-Mismatch ergäbe "aircraft_mismatch_warning"
                    // und der Pilot müsste manuell „Trotzdem starten" klicken.
                    // v0.13.16 (Option C): das fängt jetzt der Typ-Vorabcheck
                    // oben ab — wir feuern nur bei passendem (oder nicht
                    // auflösbarem) Typ. Ein Mismatch hier ist damit nur noch
                    // ein Race-Edge (Sim-Flugzeug zwischen Vorabcheck und
                    // flight_start gewechselt) → der Fehler-Pfad cleart
                    // last_bid_id, der nächste Tick prüft erneut vorab.
                    if let Err(e) =
                        flight_start(app_for_call.clone(), state_ref, bid_id, None).await
                    {
                        tracing::warn!(
                            ?e,
                            bid_id,
                            "auto-start: flight_start command failed"
                        );
                        let s = app_for_call.state::<AppState>();
                        // v0.15.13: Fehler-Cooldown setzen, BEVOR last_bid_id
                        // gecleart wird. Der Loop-Cooldown-Check verhindert
                        // damit ab dem nächsten Tick das sofortige Re-Fire
                        // (3-s-Retry-Sturm, GlitchTip #10). Das Log läuft dadurch
                        // nur noch ~1×/Cooldown statt ~20×/min.
                        {
                            let mut f = s.auto_start_fail.lock().unwrap();
                            *f = Some((Utc::now(), bid_id, e.code.clone()));
                        }
                        // v0.7.17 (N-003): nicht mehr silent — im Activity-Log,
                        // damit der Pilot sieht warum sein automatisch erkannter
                        // Flug nicht startete (z.B. „missing_aircraft",
                        // „not_at_departure", „flight_already_active").
                        let app_log = app_for_call.clone();
                        log_activity_handle(
                            &app_log,
                            ActivityLevel::Warn,
                            "Auto-Start: flight_start fehlgeschlagen".to_string(),
                            Some(format!("Bid {} – Fehler: {}", bid_id, e.code)),
                        );
                        // Clear the last_bid_id so the user can retry after the
                        // cooldown (or immediately by fixing the condition +
                        // toggling auto-start). The fail-cooldown above now gates
                        // the re-fire cadence, not this clear.
                        let mut g = s.auto_start_last_bid_id.lock().unwrap();
                        *g = None;
                    }
                });
                fired = true;
                break;
            }
            // v0.7.17 (N-003): Wenn die for-Schleife ohne Match endet
            // (kein break), gib dem Piloten einen Hint mit dem nähesten
            // Departure-Airport. Vorher silent.
            if !fired {
                let now = Utc::now();
                // v0.13.16 (Option C): ein Typ-Mismatch (Bid in Reichweite +
                // warm, aber Flugzeug passt nicht) hat Vorrang vor dem
                // generischen „kein Match"-Hint — sonst stünde irreführend
                // „Kein Bid passt zur Position", obwohl die Position passt.
                let (reason_code, title, reason_msg) = if let Some((flight_no, exp, act)) =
                    &mismatch_info
                {
                    (
                        "aircraft_mismatch",
                        "Auto-Start: Flugzeug passt nicht",
                        format!(
                            "Bid {flight_no} erwartet {exp}, im Sim ist {act} geladen. \
                             Auto-Start greift hier nicht — bitte manuell „Trotzdem starten\" \
                             (Wetlease) oder das passende Flugzeug laden. Tipp: passt der Typ \
                             eigentlich (nur anderer Name)? Dann fehlt ein Aircraft-Type-Alias \
                             auf dem VPS.",
                        ),
                    )
                } else if !any_match_attempt {
                    // Bid-Liste war zwar nicht leer, aber das einzige Bid
                    // ist bereits durchs last_bid_id-Lock blockiert.
                    (
                        "bid_already_started",
                        "Auto-Start: kein Match",
                        format!(
                            "Bid {} wurde diese Session schon mal auto-gestartet. \
                             Neu-Starten via Manual-Toggle oder anderem Bid.",
                            last_bid.map_or("?".to_string(), |id| id.to_string())
                        ),
                    )
                } else {
                    let dist_text = closest_nm
                        .map(|nm| format!("{:.1} nm zum naechsten Departure-Airport", nm))
                        .unwrap_or_else(|| "kein Departure-Airport in Reichweite".to_string());
                    (
                        "no_bid_match",
                        "Auto-Start: kein Match",
                        format!(
                            "Kein Bid passt zur aktuellen Position ({}). Auto-Start \
                             greift nur am Stand des Departure-Airports.",
                            dist_text
                        ),
                    )
                };
                let should_log = {
                    let mut g = state.auto_start_skip_reason.lock().unwrap();
                    let log_it = g.as_ref().map_or(true, |(at, code)| {
                        code != reason_code || (now - *at).num_seconds() >= 60
                    });
                    if log_it {
                        *g = Some((now, reason_code.to_string()));
                    }
                    log_it
                };
                if should_log {
                    log_activity_handle(
                        &app,
                        ActivityLevel::Info,
                        title.to_string(),
                        Some(reason_msg),
                    );
                }
            }
        }
    });
}

/// Does the loaded aircraft + position match this bid's expectations?
///
/// MVP version: airport-proximity match only — pilot must be parked
/// within `AUTO_START_PROXIMITY_M` of the bid's departure airport.
/// Aircraft-type matching is not required because resolving the
/// bid's planned aircraft requires an extra `get_aircraft` API call,
/// and shipping that on every 3 s tick is too much. If multiple bids
/// match the same airport, the first one wins; pilot can cancel
/// the auto-started flight to fall through to the next.
fn bid_matches_current_state(bid: &Bid, snap: &SimSnapshot) -> bool {
    let Some((apt_lat, apt_lon)) = runway::airport_position(&bid.flight.dpt_airport_id) else {
        return false;
    };
    let dist = runway::distance_m(snap.lat, snap.lon, apt_lat, apt_lon);
    dist <= AUTO_START_PROXIMITY_M
}

/// What state the tray icon is currently expressing — drives the
/// icon color, tooltip text, and the "status" header item in the
/// right-click menu. Computed from the active flight's stats every
/// `TRAY_UPDATE_INTERVAL_SECS` so the pilot can glance at the
/// taskbar/menubar and immediately tell what AeroACARS is doing.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum TrayState {
    /// No active flight. Default app icon (template-friendly).
    Idle,
    /// Active flight, heartbeat fresh, no offline backlog.
    Active,
    /// Active flight but heartbeat is stale OR position queue is
    /// piling up. Visible warning so pilot can investigate.
    Warning,
    /// Critical: PIREP cancelled remotely (404 from heartbeat) or
    /// streamer hasn't posted in a long time. Plus a one-shot
    /// system notification when first transitioning into this state.
    Error,
}

const TRAY_UPDATE_INTERVAL_SECS: u64 = 5;
/// Heartbeat older than this → tray flips to Warning.
const TRAY_HEARTBEAT_STALE_SECS: i64 = 60;
/// Position queue with more than this many pending → Warning.
const TRAY_QUEUE_WARN_THRESHOLD: u32 = 5;

/// Snapshot of what the tray should currently show. Held by
/// `AppState` so the periodic updater can diff against the previous
/// state to (a) avoid pointless icon swaps and (b) detect
/// transitions that warrant a system notification.
#[derive(Debug, Clone)]
struct TrayDisplay {
    state: TrayState,
    tooltip: String,
    /// Human-readable header to show as the first (disabled) menu
    /// entry, or `None` to omit the header (idle case).
    menu_header: Option<String>,
}

fn compute_tray_display(app: &AppHandle) -> TrayDisplay {
    let state = app.state::<AppState>();
    let guard = state.active_flight.lock().expect("active_flight lock");
    let Some(flight) = guard.as_ref() else {
        return TrayDisplay {
            state: TrayState::Idle,
            tooltip: "AeroACARS".to_string(),
            menu_header: None,
        };
    };
    let stats = flight.stats.lock().expect("flight stats");

    // Detect critical conditions first.
    let cancelled = flight.cancelled_remotely.load(Ordering::Relaxed);
    let now = Utc::now();
    let heartbeat_age_s = stats
        .last_heartbeat_at
        .map(|t| (now - t).num_seconds())
        .unwrap_or(i64::MAX);
    let queue = stats.queued_position_count;
    // #phase-v2 Cutover: Tray-Tooltip zeigt die v2-Phase.
    let phase_label = phase_human_label(effective_phase(&stats));
    let callsign = format_callsign(&flight.airline_icao, &flight.flight_number);
    let route = format!("{} → {}", flight.dpt_airport, flight.arr_airport);

    let s = if cancelled {
        TrayState::Error
    } else if heartbeat_age_s > TRAY_HEARTBEAT_STALE_SECS
        || queue >= TRAY_QUEUE_WARN_THRESHOLD
    {
        TrayState::Warning
    } else {
        TrayState::Active
    };

    let tooltip = match s {
        TrayState::Error => format!(
            "AeroACARS — {} {}\nPIREP serverseitig gecancelt",
            callsign, route
        ),
        TrayState::Warning => {
            let mut parts = vec![format!("AeroACARS — {} {}", callsign, route)];
            if heartbeat_age_s > TRAY_HEARTBEAT_STALE_SECS && stats.last_heartbeat_at.is_some() {
                parts.push(format!("Heartbeat stale ({}s)", heartbeat_age_s));
            } else if stats.last_heartbeat_at.is_none() {
                parts.push("Warte auf ersten Heartbeat".to_string());
            }
            if queue >= TRAY_QUEUE_WARN_THRESHOLD {
                parts.push(format!("{} Positionen offline gestaut", queue));
            }
            parts.join("\n")
        }
        TrayState::Active => {
            let mut t = format!("AeroACARS — {} {} · {}", callsign, route, phase_label);
            if let Some(t0) = stats.last_heartbeat_at {
                let age = (now - t0).num_seconds();
                t.push_str(&format!("\nHeartbeat vor {}s", age));
            }
            t
        }
        TrayState::Idle => "AeroACARS".to_string(),
    };

    let menu_header = Some(format!("✈ {} · {}", callsign, phase_label));

    TrayDisplay {
        state: s,
        tooltip,
        menu_header,
    }
}

/// Build the system-tray icon with a Show / Quit context menu and
/// click-to-toggle behaviour. Called once during Tauri setup; the
/// resulting tray lives for the app lifetime — when the window is
/// hidden via the minimize-to-tray feature this icon is the only
/// way back to the app.
///
/// On Windows the icon shows in the system tray (bottom-right);
/// on macOS in the menubar (top-right) — same code, the OS routes
/// it to the platform-native location.
/// Build the tray context menu with the given status-header label.
/// Extracted so the periodic tray updater can rebuild and swap it
/// when the active flight's state changes (Tauri 2's TrayIcon has
/// `set_menu` but no menu getter, so we build fresh each time).
fn build_tray_menu(
    app: &AppHandle,
    status_label: &str,
) -> Result<tauri::menu::Menu<tauri::Wry>, Box<dyn std::error::Error>> {
    use tauri::menu::{Menu, MenuItem, PredefinedMenuItem};
    let status_item = MenuItem::with_id(app, "status", status_label, false, None::<&str>)?;
    let separator = PredefinedMenuItem::separator(app)?;
    let show_item = MenuItem::with_id(app, "show", "Anzeigen / Show", true, None::<&str>)?;
    let quit_item = MenuItem::with_id(app, "quit", "Beenden / Quit", true, None::<&str>)?;
    Ok(Menu::with_items(
        app,
        &[&status_item, &separator, &show_item, &quit_item],
    )?)
}

fn build_tray_icon(app: &AppHandle) -> Result<(), Box<dyn std::error::Error>> {
    use tauri::tray::{MouseButton, MouseButtonState, TrayIconBuilder, TrayIconEvent};
    use tauri::Manager;

    let menu = build_tray_menu(app, "AeroACARS — kein aktiver Flug")?;

    // Idle icon = the default app icon, untouched. The periodic
    // tray-updater swaps to a status-badged variant when there's an
    // active flight (see `make_status_icon`).
    let icon = app
        .default_window_icon()
        .ok_or("no default window icon")?
        .clone();

    TrayIconBuilder::with_id("aeroacars-tray")
        .tooltip("AeroACARS")
        .icon(icon)
        .menu(&menu)
        .show_menu_on_left_click(false)
        .on_menu_event(|app, event| match event.id().as_ref() {
            "show" => {
                if let Some(w) = app.get_webview_window("main") {
                    let _ = w.show();
                    let _ = w.unminimize();
                    let _ = w.set_focus();
                }
            }
            "quit" => {
                // Bypass the CloseRequested → hide path by calling
                // app.exit() directly. Same effect as toggling
                // minimize-to-tray off and clicking X, but explicit.
                app.exit(0);
            }
            _ => {}
        })
        .on_tray_icon_event(|tray, event| {
            // Left-click on the tray icon toggles the main window's
            // visibility. Right-click opens the context menu (handled
            // by Tauri itself because show_menu_on_left_click=false).
            if let TrayIconEvent::Click {
                button: MouseButton::Left,
                button_state: MouseButtonState::Up,
                ..
            } = event
            {
                let app = tray.app_handle();
                if let Some(w) = app.get_webview_window("main") {
                    if w.is_visible().unwrap_or(false) {
                        let _ = w.hide();
                    } else {
                        let _ = w.show();
                        let _ = w.unminimize();
                        let _ = w.set_focus();
                    }
                }
            }
        })
        .build(app)?;

    Ok(())
}

/// Color used for the status badge in the bottom-right corner of the
/// tray icon. RGBA. Idle has no badge — falls through to default
/// app icon.
fn tray_state_color(state: TrayState) -> Option<[u8; 4]> {
    match state {
        TrayState::Idle => None,
        // Calm Apple-system green for "all good".
        TrayState::Active => Some([0x30, 0xD1, 0x58, 0xFF]),
        // Warm amber for "look at me".
        TrayState::Warning => Some([0xFF, 0x9F, 0x0A, 0xFF]),
        // Strong Apple-system red for "PIREP gone".
        TrayState::Error => Some([0xFF, 0x45, 0x3A, 0xFF]),
    }
}

/// Produce a tray-icon variant of `base` with a colored status circle
/// painted in the bottom-right corner. The badge is sized to the
/// lower-right ~35 % of the icon and has a 1-pixel transparent ring
/// around it so it visually pops off the underlying logo.
///
/// Returns `None` for `TrayState::Idle` — caller uses the unmodified
/// base icon in that case.
fn make_status_icon<'a>(
    base: &tauri::image::Image<'a>,
    state: TrayState,
) -> Option<tauri::image::Image<'static>> {
    let color = tray_state_color(state)?;
    let w = base.width();
    let h = base.height();
    let mut rgba: Vec<u8> = base.rgba().to_vec();

    // Badge geometry — bottom-right circle covering ~35 % of the icon.
    let badge_d = (w.min(h) as f32 * 0.55) as i32;
    let r = badge_d / 2;
    let cx = w as i32 - r - 1;
    let cy = h as i32 - r - 1;
    // 1-pixel transparent halo for visual separation.
    let r_outer = r + 1;

    for y in 0..h as i32 {
        for x in 0..w as i32 {
            let dx = x - cx;
            let dy = y - cy;
            let d2 = dx * dx + dy * dy;
            let idx = ((y as u32 * w + x as u32) * 4) as usize;
            if d2 <= r * r {
                // Solid badge color.
                rgba[idx] = color[0];
                rgba[idx + 1] = color[1];
                rgba[idx + 2] = color[2];
                rgba[idx + 3] = color[3];
            } else if d2 <= r_outer * r_outer {
                // Halo — clear to transparent.
                rgba[idx + 3] = 0;
            }
        }
    }
    Some(tauri::image::Image::new_owned(rgba, w, h))
}

/// Periodic background task: every `TRAY_UPDATE_INTERVAL_SECS`,
/// recompute the desired tray display from the active flight's
/// stats and push it to the live `TrayIcon`. Diff against the
/// previous state to avoid pointless icon-repaints AND to detect
/// the transition into `Error` (which triggers a one-shot system
/// notification so a tray-only pilot can't miss it).
fn spawn_tray_updater(app: AppHandle) {
    use std::sync::Mutex;
    use tauri::tray::TrayIconId;
    let tray_id = TrayIconId::new("aeroacars-tray");
    let last_state: std::sync::Arc<Mutex<Option<TrayState>>> =
        std::sync::Arc::new(Mutex::new(None));
    tauri::async_runtime::spawn(async move {
        // Cache the colored icon variants once at startup so we
        // don't recompute the pixel buffer on every 5 s tick.
        let base_icon = match app.default_window_icon() {
            Some(i) => i.clone(),
            None => {
                tracing::warn!("no default window icon — tray-updater giving up");
                return;
            }
        };
        let active_icon = make_status_icon(&base_icon, TrayState::Active);
        let warning_icon = make_status_icon(&base_icon, TrayState::Warning);
        let error_icon = make_status_icon(&base_icon, TrayState::Error);

        loop {
            tokio::time::sleep(Duration::from_secs(TRAY_UPDATE_INTERVAL_SECS)).await;

            let display = compute_tray_display(&app);
            let prev = {
                let g = last_state.lock().unwrap();
                *g
            };
            let mut g = last_state.lock().unwrap();
            *g = Some(display.state);
            drop(g);

            // Push tooltip + (rebuilt) menu so the status header
            // reflects the current flight info. Tauri 2's TrayIcon
            // exposes set_menu() but not a getter, so we rebuild the
            // menu structure each tick — cheap (3 native menu items)
            // and avoids storing MenuItem<Wry> lifetimes in AppState.
            if let Some(tray) = app.tray_by_id(&tray_id) {
                let _ = tray.set_tooltip(Some(&display.tooltip));

                let header_label = display
                    .menu_header
                    .clone()
                    .unwrap_or_else(|| "AeroACARS — kein aktiver Flug".to_string());
                if let Ok(new_menu) = build_tray_menu(&app, &header_label) {
                    let _ = tray.set_menu(Some(new_menu));
                }

                // Icon swap only on state change (it's a relatively
                // expensive call on Win, and Mac sometimes flickers).
                if prev != Some(display.state) {
                    let new_icon = match display.state {
                        TrayState::Idle => Some(base_icon.clone()),
                        TrayState::Active => active_icon.clone(),
                        TrayState::Warning => warning_icon.clone(),
                        TrayState::Error => error_icon.clone(),
                    };
                    if let Some(icon) = new_icon {
                        let _ = tray.set_icon(Some(icon));
                    }
                }
            }

            // Fire a one-shot system notification when we just
            // entered Error. Pilots running in tray-only mode would
            // otherwise miss the "PIREP cancelled" event entirely
            // (the activity-log entry is invisible until they
            // re-open the window).
            if prev != Some(TrayState::Error) && display.state == TrayState::Error {
                use tauri_plugin_notification::NotificationExt;
                let _ = app
                    .notification()
                    .builder()
                    .title("AeroACARS")
                    .body(&display.tooltip)
                    .show();
            }
        }
    });
}

fn init_tracing() {
    let filter = EnvFilter::try_from_default_env()
        .unwrap_or_else(|_| EnvFilter::new("info,aeroacars=debug"));
    let _ = tracing_subscriber::fmt().with_env_filter(filter).try_init();
}

#[cfg_attr(mobile, tauri::mobile_entry_point)]
pub fn run() {
    // v0.15.10: rustls-Crypto-Provider EINMAL explizit als Process-Default
    // setzen, GANZ am Anfang vor jedem TLS-Use. Im Dep-Tree sind aws-lc-rs UND
    // ring verlinkt → rustls 0.23 würde sonst beim Auto-Wählen paniken
    // („Could not automatically determine the process-level CryptoProvider …",
    // GlitchTip aeroacars-client). install_default ist idempotent → Err = schon
    // gesetzt, das ignorieren wir.
    let _ = rustls::crypto::aws_lc_rs::default_provider().install_default();

    init_tracing();
    // v0.9.0 (#GlitchTip): Sentry-Init MUSS vor allem anderen passieren, damit
    // Bootstrap-Panics gefangen werden. No-Op wenn DSN nicht in build-time env.
    // Pilot-Consent wird im Setup-Hook bzw. vom Frontend per Command gesetzt;
    // bis dahin verwirft before_send alle Events (Default-Consent = aus).
    sentry_init::init();
    tracing::info!(version = env!("CARGO_PKG_VERSION"), "AeroACARS starting");

    // Restore the activity log from disk before anything else uses
    // AppState. v0.15.26: the activity-log restore + boot banner moved into the
    // Tauri setup hook (after init_activity_log_path), so the persisted log is
    // resolved cross-platform via ACTIVITY_LOG_PATH. Doing it here (before the
    // AppHandle exists) forced a Windows-only APPDATA path → the log restored
    // empty on macOS/Linux every launch.
    let app_state = AppState::default();

    tauri::Builder::default()
        // v0.18.x: MUSS das erste registrierte Plugin sein (Tauri-Doku).
        // Verhindert einen zweiten AeroACARS-Prozess fuer denselben Piloten
        // (z. B. erneuter Doppelklick aufs App-Icon, waehrend die App via
        // Minimize-to-Tray im Hintergrund weiterlaeuft) — sonst tracken
        // ZWEI unabhaengige Prozesse denselben aktiven Flug und posten
        // Phase-/Touchdown-ACARS-Logs doppelt an dieselbe PIREP-ID (Live-
        // Befund Thomas K., 05.07.2026: doppelte Zeilen im Fluglogbuch).
        // Der zweite Start-Versuch fokussiert hier nur das bestehende
        // Fenster, statt eine eigene Instanz hochzufahren.
        .plugin(tauri_plugin_single_instance::init(|app, _argv, _cwd| {
            if let Some(w) = app.get_webview_window("main") {
                let _ = w.show();
                let _ = w.unminimize();
                let _ = w.set_focus();
            }
        }))
        .plugin(tauri_plugin_opener::init())
        .plugin(tauri_plugin_updater::Builder::new().build())
        .plugin(tauri_plugin_process::init())
        .plugin(tauri_plugin_notification::init())
        .plugin(tauri_plugin_dialog::init())
        .manage(app_state)
        .manage(aircraft_scan::AircraftScanState::default())
        .on_window_event(|window, event| {
            // CloseRequested fires when the user clicks the red X
            // (Mac) or the title-bar X (Win). When the
            // minimize-to-tray toggle is on, we suppress the close
            // and just hide the window — the pilot keeps using it
            // via the tray icon. When the toggle is off, the close
            // proceeds normally and the app exits.
            //
            // Critically: we ONLY override the main "AeroACARS"
            // window, not any future child windows. Child windows
            // close as expected.
            if let tauri::WindowEvent::CloseRequested { api, .. } = event {
                if window.label() != "main" {
                    return;
                }
                let state = window.app_handle().state::<AppState>();
                let minimize = state
                    .minimize_to_tray_enabled
                    .load(std::sync::atomic::Ordering::Relaxed);
                if minimize {
                    api.prevent_close();
                    if let Err(e) = window.hide() {
                        tracing::warn!(error = %e, "failed to hide main window");
                    } else {
                        tracing::info!("main window hidden to tray");
                    }
                }
            }
        })
        .setup(|app| {
            // v0.5.15: initialize file-based secrets storage BEFORE
            // anything else touches the secrets API. We resolve the
            // app data dir from the Tauri PathResolver. If this fails
            // (extremely unlikely — only if the OS denies the user's
            // own appdata dir), secret reads/writes will return
            // SecretError::NotInitialized and the app degrades to
            // "no persistent login" but keeps running.
            //
            // v0.7.13: Der `migrate_from_keyring`-Aufruf ist entfernt
            // (Audit CC1) — die v0.5.15-Einmal-Migration ist 30+ Releases
            // her; verbleibende Pilots ohne JSON-Datei loggen sich frisch
            // ein. Keyring-Dep ist ebenfalls raus.
            match app.path().app_data_dir() {
                Ok(dir) => {
                    if let Err(e) = secrets::init(&dir) {
                        tracing::error!(error = %e, "secrets init failed");
                    }
                }
                Err(e) => {
                    tracing::error!(error = %e, "could not resolve app_data_dir for secrets");
                }
            }

            // v0.7.14: alte Pilot-Local-Webhook-Datei `discord-webhook.txt`
            // aus v0.7.13 loeschen. Discord-Posts macht ab v0.7.14 der
            // Recorder auf live.kant.ovh zentral (Webapp-Admin-Settings).
            // Audit Q4-2026-05 (C1).
            migrate_remove_discord_webhook_file(&app.handle());

            // Resolve the activity-log persistence path now that we
            // have an AppHandle. After this, save_activity_log() can
            // run without a handle (uses the OnceLock cache).
            init_activity_log_path(&app.handle());

            // v0.15.26: restore the activity log from disk now that the path is
            // resolved cross-platform (ACTIVITY_LOG_PATH), so a mid-flight client
            // close/crash/update keeps the full flight history on the next launch
            // (was Windows-only via APPDATA before → empty on macOS/Linux). Then
            // append the boot banner on top; the save block below persists it.
            {
                let state = app.state::<AppState>();
                let mut log = state.activity_log.lock().expect("activity_log lock");
                for entry in load_persisted_activity_log() {
                    log.push_back(entry);
                    while log.len() > ACTIVITY_LOG_CAPACITY {
                        log.pop_front();
                    }
                }
                let banner = ActivityEntry {
                    timestamp: Utc::now(),
                    level: ActivityLevel::Info,
                    message: format!("AeroACARS v{} gestartet", env!("CARGO_PKG_VERSION")),
                    // Tiny credit line — keeps the tool feeling human-made.
                    detail: Some("Made with ❤️ in Gifhorn — by Thomas Kant".into()),
                };
                tracing::info!(message = %banner.message, "activity");
                log.push_back(banner);
                while log.len() > ACTIVITY_LOG_CAPACITY {
                    log.pop_front();
                }
            }

            // v0.9.0 (#Discord-RPC): Manager initialisieren + ggf. die
            // persistente Pilot-Entscheidung anwenden. Default = aus, also
            // nichts passiert solang der Pilot nicht in Settings zustimmt.
            discord_rpc::init(&app.handle());
            // Persist the boot-time state (restored log + banner)
            // immediately so a crash before any activity event still
            // keeps the banner visible on next launch.
            let state = app.state::<AppState>();
            let log = state.activity_log.lock().expect("activity_log lock");
            save_activity_log(&log);
            drop(log);
            // Spawn the auto-start watcher exactly once, here, for the
            // lifetime of the app. The watcher itself short-circuits when
            // the toggle flag is off — flipping the flag at runtime is
            // enough, no need to spawn-on-toggle. Earlier versions did
            // spawn-on-toggle; that had a Mac-first-launch failure mode
            // where the very first toggle's IPC call lost the spawn race
            // and the user had to restart the app to recover.
            // v0.3.0: Persistierten Auto-Start-Stand laden bevor der
            // Watcher startet. Ohne diesen Read würde der AppState
            // mit Default-`false` initialisiert und der Frontend-Hook
            // `auto_start_get_enabled` würde immer `false` zurückgeben,
            // egal ob der Pilot ihn vorher aktiviert hatte.
            {
                let persisted = read_auto_start_persisted(&app.handle());
                let state = app.state::<AppState>();
                state
                    .auto_start_enabled
                    .store(persisted, Ordering::Relaxed);
                if persisted {
                    tracing::info!("auto-start restored from persisted settings");
                }
                // v0.12.6: Auto-File default-on, passend zum Frontend-
                // Default. Das Frontend überschreibt das beim Mount mit
                // dem echten localStorage-Wert via `set_auto_file_enabled`.
                state.auto_file_enabled.store(true, Ordering::Relaxed);
            }
            spawn_auto_start_watcher(app.handle().clone());
            // Build the system-tray icon + menu. On Windows this lands
            // in the system tray (bottom-right); on Mac in the menubar
            // (top-right). The icon click toggles window visibility,
            // and the right-click context menu has Show / Quit. See
            // `minimize_to_tray_enabled` for the behaviour gate.
            if let Err(e) = build_tray_icon(&app.handle()) {
                tracing::warn!(error = %e, "tray icon setup failed — minimize-to-tray will not work");
            } else {
                // Periodic updater for the tray's tooltip / status
                // header / colored badge. Reads active flight stats
                // every TRAY_UPDATE_INTERVAL_SECS, fires a system
                // notification on critical-state transitions.
                spawn_tray_updater(app.handle().clone());
            }
            // v0.5.11: try to start MQTT live-tracking publisher in
            // the background. Non-fatal — if no API key is present
            // yet (fresh install, user hasn't logged in) it just
            // returns and we'll retry after login.
            {
                let app_for_mqtt = app.handle().clone();
                tauri::async_runtime::spawn(async move {
                    init_mqtt_publisher_via_provisioning(app_for_mqtt).await;
                });
            }
            // v0.5.49 — Background-Worker für den persistenten PIREP-
            // Queue. Tickt alle 60s, versucht jeden in pending_pireps/
            // liegenden PIREP einzureichen sobald die Verbindung wieder
            // steht. Persistiert Attempt-Count pro PIREP damit nach App-
            // Restart einfach weiter retried wird.
            spawn_pirep_queue_worker(app.handle().clone());

            // v0.16.0 (#LAN-Remote): headless autostart hook. If
            // `AEROACARS_LAN_AUTOSTART` parses as a port, start the LAN
            // remote-control server on launch on that port — same start
            // path as the `remote_server_start` command, just driven by an
            // env var instead of the GUI toggle. Lets the server be tested
            // (and run) without touching the window, and doubles as a small
            // power-user feature. No env var → no-op (the normal case;
            // pilots never set it, so production is unaffected).
            //
            // v0.16.16: calls `remote::start_server` (the shared path)
            // instead of the `remote_server_start` command, because the
            // command now also persists the Settings toggle ON — a
            // test/headless env hook must not silently flip the pilot's
            // stored preference.
            if let Some(port) = std::env::var("AEROACARS_LAN_AUTOSTART")
                .ok()
                .and_then(|v| v.trim().parse::<u16>().ok())
            {
                let app_for_lan = app.handle().clone();
                tauri::async_runtime::spawn(async move {
                    // Persist the requested port so the shared start path
                    // (which reads the persisted port) binds it, then start.
                    let _ = remote::remote_server_set_port(
                        port,
                        app_for_lan.clone(),
                        app_for_lan.state::<AppState>(),
                    )
                    .await;
                    match remote::start_server(&app_for_lan).await {
                        Ok(status) => tracing::info!(
                            port = status.port,
                            "LAN remote-control server autostarted (AEROACARS_LAN_AUTOSTART)"
                        ),
                        Err(e) => tracing::error!(
                            error = %e.message,
                            "LAN autostart failed"
                        ),
                    }
                });
            }

            // v0.16.16 (#LAN-Remote): the Settings toggle persists. If the
            // pilot left the LAN remote-control server switched ON, start
            // it again automatically — paired tablets keep working across
            // restarts/updates because the bearer token persists in the
            // secrets store. Goes through the SAME shared start path as
            // the `remote_server_start` command (mirroring how the bridge
            // calls commands outside IPC via `app.state()`), spawned async
            // so a slow/failed bind can never delay or crash startup. A
            // failure (e.g. port already busy) is only logged; the stored
            // `enabled` flag stays untouched, and the Settings toggle
            // simply shows OFF because it reads the live running state
            // via `remote_server_status` on mount.
            if remote::read_persisted_enabled(app.handle()) {
                let app_for_lan = app.handle().clone();
                tauri::async_runtime::spawn(async move {
                    match remote::start_server(&app_for_lan).await {
                        Ok(status) => log_activity_handle(
                            &app_for_lan,
                            ActivityLevel::Info,
                            format!(
                                "LAN-Fernbedienung automatisch gestartet (Port {})",
                                status.port
                            ),
                            None,
                        ),
                        Err(e) => log_activity_handle(
                            &app_for_lan,
                            ActivityLevel::Warn,
                            "LAN-Fernbedienung konnte nicht automatisch starten",
                            Some(e.message.clone()),
                        ),
                    }
                });
            }

            Ok(())
        })
        .invoke_handler(tauri::generate_handler![
            app_info,
            aircraft_scan::ascan_list_aircraft,
            aircraft_scan::ascan_collect,
            aircraft_scan::ascan_submit,
            phpvms_login,
            phpvms_logout,
            phpvms_load_session,
            phpvms_get_bids,
            news_fetch,
            fetch_simbrief_preview,
            flight_refresh_simbrief,
            flight_refresh_route_only,
            bid_simbrief_preview,
            ofp_callsign_warning_get,
            flight_resume_after_disconnect,
            phpvms_get_aircraft,
            auto_start_skip_status,
            phpvms_refresh_profile,
            divert_nearest_airports,
            fetch_release_notes,
            set_minimize_to_tray,
            set_auto_file_enabled,
            // v0.9.0 (#GlitchTip): Opt-In fuer anonyme Fehler-Telemetrie.
            error_reporting_set_consent,
            // v0.9.0 (#Discord-RPC): Settings + Status + Push-State + Test.
            discord_rpc::discord_rpc_get_settings,
            discord_rpc::discord_rpc_set_settings,
            discord_rpc::discord_rpc_get_status,
            discord_rpc::discord_rpc_send_test,
            discord_rpc::discord_rpc_push_state,
            discord_rpc::discord_rpc_clear_flight,
            // v0.9.1 F7: LE8-Suffix "⚠ Sim getrennt" verdrahten
            discord_rpc::discord_rpc_set_sim_lost,
            // v0.7.14: Discord-Posts macht der Recorder zentral — keine
            // Pilot-Client-Commands mehr fuer Webhook-URL. Audit C1.
            // v0.7.8 SimBrief Integration (Spec §4)
            set_simbrief_settings,
            verify_simbrief_identifier,
            sim_get_kind,
            sim_set_kind,
            sim_status,
            sim_force_resync,
            pmdg_status,
            airport_get,
            flight_status,
            flight_get_route_fixes,
            flight_get_track,
            va_live_flights,
            logbook_pireps,
            logbook_stats,
            logbook_pirep,
            flight_start,
            flight_start_manual,
            fleet_list_at_airport,
            flight_end,
            flight_end_manual,
            flight_cancel,
            flight_resume_check_position,
            activity_log_get,
            activity_log_clear,
            landing_list,
            landing_get_current,
            landing_delete,
            metar_get,
            flight_forget,
            // v0.7.18 (B-011) Orphan-Flight-Cleanup
            flight_list_orphans,
            flight_cancel_orphan,
            flight_forget_remote,
            flight_discover_resumable,
            flight_adopt,
            flight_resume_confirm,
            inspector_add,
            inspector_remove,
            inspector_list,
            xplane_inspector_list,
            xplane_premium_status,
            xplane_detect_install_path,
            xplane_install_plugin,
            auto_start_set_enabled,
            auto_start_get_enabled,
            flight_logs_stats,
            flight_logs_delete_all,
            flight_logs_purge_older_than,
            // v0.16.0 (#LAN-Remote): LAN remote-control server controls.
            // The server is opt-in (started here, never at boot) and
            // serves the real SPA + bridges every safe command to a paired
            // tablet over HTTP/WS. Port is user-configurable + persisted.
            remote::remote_server_start,
            remote::remote_server_stop,
            remote::remote_server_status,
            remote::remote_server_set_port,
        ])
        .build(tauri::generate_context!())
        .expect("error while building AeroACARS")
        .run(|app_handle, event| {
            // v0.5.11: clean MQTT publisher shutdown on app exit.
            // ExitRequested fires once before the process tears down;
            // we send the LWT-replacement OFFLINE status, give the
            // network thread a brief moment to flush, then return so
            // Tauri continues the exit. If we don't do this, the
            // last-will-and-testament eventually publishes OFFLINE
            // anyway when the broker times the connection out (~60 s),
            // but the explicit shutdown is faster and cleaner.
            if matches!(event, tauri::RunEvent::ExitRequested { .. }) {
                let app_for_mqtt = app_handle.clone();
                tauri::async_runtime::block_on(async move {
                    let state = app_for_mqtt.state::<AppState>();
                    let handle = state.mqtt.lock().await.take();
                    if let Some(handle) = handle {
                        handle.shutdown();
                        // Brief flush window so the publisher task can
                        // post the OFFLINE status before tokio shuts
                        // down. 200 ms is the spec recommendation.
                        tokio::time::sleep(std::time::Duration::from_millis(200))
                            .await;
                    }
                });
            }
        });
}

// ----------------------------------------------------------------------
// Unit tests for Touch-and-Go + Go-Around helpers (v0.1.26).
//
// These cover the two pure-ish helpers that drive the FSM-side
// detectors. Tests construct minimal SimSnapshot values via Default
// (provided by sim-core) and walk the helpers through synthetic
// telemetry sequences. They DON'T exercise the FSM end-to-end —
// `step_flight` has many side-channels that are hard to fake without
// a full `ActiveFlight` setup. The integration coverage comes from
// real in-sim flights against a dev-server PIREP.
// ----------------------------------------------------------------------

// ----------------------------------------------------------------------
// v0.7.18 (B-014 / R2-3): FlightCancelOutcome wire-format guard.
//
// Das tagged-union JSON-Format (`{ "kind": "filed_instead", "pirep_id": ... }`)
// ist die Schnittstelle zur Tauri-Frontend. ActiveFlightPanel.tsx machted
// auf den `kind`-Strings — wenn jemand die Serde-Attribute ändert (Tag-
// Name, snake_case, Variant-Renames) bricht das stillschweigend die
// Cancel-Flow-UX. Dieser Test hält die drei Wire-Shapes fest.
// ----------------------------------------------------------------------
// ----------------------------------------------------------------------
// v0.7.19 GAF-707 (QS-R3 Finding 1+3): Bid-Cleanup-Path-Selection Tests.
//
// `consume_bid_best_effort` selbst macht HTTP-IO und braucht einen
// echten phpVMS-`Client`. Die ID-Selection-Logik ist aber pure und
// wurde nach `resolve_bid_cleanup_args` extrahiert — diese Tests
// halten den Edge-Case "bid_id<=0 + flight_id Some" fest, damit der
// Pfad nicht wieder still verschluckt wird wie in QS-R2.
// ----------------------------------------------------------------------
// ----------------------------------------------------------------------
// v0.7.20 (QS-Nebenfund GSG219): Final-Landing-Push Bedingungs-Logik.
//
// Der eigentliche Push lebt im step_flight-Body und ist HTTP-/State-frei
// — der Path ist aber tief in einer FSM verschachtelt und nicht
// trivial isoliert testbar. Wir extrahieren stattdessen die Bedingung
// als pure function und testen die Edge-Cases, damit die Race aus dem
// GSG219-Log (else-if + Phase-Transition + B-005-Guard) nicht wieder
// zurueckkehrt.
// ----------------------------------------------------------------------
#[cfg(test)]
mod takeoff_roll_demote_tests {
    use super::*;
    use chrono::Duration;

    /// Backtrack trippt TakeoffRoll, dann Ausrichten (GS → 0): nach dem
    /// Dwell zurück zu TaxiOut, nicht ewig „Takeoff Roll".
    #[test]
    fn demotes_to_taxi_after_dwell() {
        let t0 = Utc::now();
        // Erster langsamer Tick am Boden: Dwell startet, noch KEIN Demote.
        let (demote, slow) = takeoff_roll_demote(true, 0.0, None, t0);
        assert_eq!(demote, None, "erster langsamer Tick darf nicht sofort demoten");
        assert!(slow.is_some(), "Dwell-Start muss gestempelt sein");
        // Innerhalb des Dwells (2 s): weiter TakeoffRoll.
        let (demote, slow) =
            takeoff_roll_demote(true, 3.0, slow, t0 + Duration::seconds(2));
        assert_eq!(demote, None);
        // Nach dem Dwell (4 s ≥ 3 s): zurück zu TaxiOut + Dwell zurückgesetzt.
        let (demote, slow2) =
            takeoff_roll_demote(true, 1.0, slow, t0 + Duration::seconds(4));
        assert_eq!(demote, Some(FlightPhase::TaxiOut));
        assert_eq!(slow2, None, "Dwell nach Demote zurückgesetzt");
    }

    /// Echte Startrolle: GS steigt monoton, nie unter 20 → NIE demote
    /// (der Kern-Regressionsschutz), Dwell bleibt leer.
    #[test]
    fn real_takeoff_roll_never_demotes() {
        let t0 = Utc::now();
        let mut slow = None;
        for (i, gs) in [35.0f32, 60.0, 90.0, 140.0].iter().enumerate() {
            let (demote, s) =
                takeoff_roll_demote(true, *gs, slow, t0 + Duration::seconds(i as i64));
            assert_eq!(demote, None, "Startrolle darf nie demoten (gs={gs})");
            slow = s;
        }
        assert_eq!(slow, None, "über der Schwelle bleibt der Dwell leer");
    }

    /// Ein einzelner GS-Glitch-Tick (<20) reicht NICHT: erholt sich die GS
    /// vor Ablauf des Dwells, wird der Dwell verworfen.
    #[test]
    fn single_glitch_tick_does_not_demote() {
        let t0 = Utc::now();
        let (demote, slow) = takeoff_roll_demote(true, 5.0, None, t0); // Glitch
        assert_eq!(demote, None);
        assert!(slow.is_some());
        // Nächster Tick: GS wieder hoch → Dwell verworfen, kein Demote.
        let (demote, slow) =
            takeoff_roll_demote(true, 80.0, slow, t0 + Duration::seconds(1));
        assert_eq!(demote, None);
        assert_eq!(slow, None, "GS-Erholung verwirft den Dwell");
    }

    /// Liftoff (!on_ground) verwirft den Dwell — die Vorwärtskante zu
    /// Takeoff übernimmt separat im Arm.
    #[test]
    fn airborne_resets_dwell() {
        let t0 = Utc::now();
        let (demote, slow) = takeoff_roll_demote(false, 5.0, Some(t0), t0);
        assert_eq!(demote, None);
        assert_eq!(slow, None);
    }
}

#[cfg(test)]
mod final_landing_push_condition_tests {
    use super::*;

    /// Spiegel der `step_flight`-Bedingung fuer den FinalLanding-Push.
    /// Dieselbe Form wie im Original-Code:
    ///
    /// ```ignore
    /// if !tg_in_window
    ///     && stats.landing_at == Some(touchdown)
    ///     && stats.touchdown_events.last()
    ///         .map(|e| e.timestamp != touchdown)
    ///         .unwrap_or(true)
    /// { push }
    /// ```
    fn should_push(
        tg_in_window: bool,
        touchdown: DateTime<Utc>,
        landing_at: Option<DateTime<Utc>>,
        last_event_ts: Option<DateTime<Utc>>,
    ) -> bool {
        !tg_in_window
            && landing_at == Some(touchdown)
            && last_event_ts.map(|ts| ts != touchdown).unwrap_or(true)
    }

    fn t(secs: i64) -> DateTime<Utc> {
        DateTime::<Utc>::from_timestamp(secs, 0).expect("valid ts")
    }

    #[test]
    fn pushes_when_tg_window_expired_and_landing_active_and_no_prior_event() {
        // GSG219-Fall: kein T&G im Window, landing_at zeigt auf den
        // aktiven Touchdown, touchdown_events ist leer → push.
        assert!(should_push(false, t(100), Some(t(100)), None));
    }

    #[test]
    fn pushes_when_prior_event_has_different_timestamp() {
        // Dedup-Bedingung: ein frueheres TouchdownEvent (z.B. ein
        // verworfener T&G-Versuch) darf den FinalLanding-Push nicht
        // blocken, solange der Timestamp anders ist.
        assert!(should_push(false, t(200), Some(t(200)), Some(t(180))));
    }

    #[test]
    fn does_not_push_inside_tg_window() {
        // Klassischer T&G-Schutz: solange das T&G-Watch-Fenster offen
        // ist, darf der FinalLanding-Push nicht feuern (sonst wuerde
        // ein T&G faelschlich als FinalLanding klassifiziert).
        assert!(!should_push(true, t(100), Some(t(100)), None));
    }

    #[test]
    fn does_not_push_when_landing_at_is_none() {
        // Z.B. nach einem T&G das `stats.landing_at = None` setzt.
        assert!(!should_push(false, t(100), None, None));
    }

    #[test]
    fn does_not_push_when_landing_at_belongs_to_a_different_touchdown() {
        // Defensiv: falls landing_at irgendwie auf einen anderen
        // Touchdown zeigt (race condition), nicht pushen.
        assert!(!should_push(false, t(100), Some(t(99)), None));
    }

    #[test]
    fn does_not_double_push_on_same_timestamp() {
        // Wenn der gleiche Touchdown schon mal gepusht wurde, kein
        // zweiter Push im selben Tick oder Folge-Tick.
        assert!(!should_push(false, t(100), Some(t(100)), Some(t(100))));
    }
}

// ----------------------------------------------------------------------
// v0.7.21 SSoT-Konsistenz fuer canonical_landing_rate_fpm.
//
// Anchor-Case: MS713 (HECA→OLBA, B738, X-Plane 12, 13.5.2026). Pilot-
// Client zeigte -194 (Engineering-Edge), Webapp Live-Touchdown zeigte
// -194, Discord-Bot zeigte -194 — ABER phpVMS PIREP zeigte -204/-205
// (Streamer-Tick-Snapshot via FileBody.landing_rate, das einzige
// vergessene Stueck aus dem v0.7.17 B-015a-Sweep).
//
// Ab v0.7.21 ist `FlightStats::canonical_landing_rate_fpm()` die
// einzige Quelle fuer Anzeige/Filing. Diese Tests halten die Cascade
// fest, damit niemand mehr stillschweigend eine neue Anzeige-Stelle
// einbauen kann die direkt `stats.landing_rate_fpm` liest.
// ----------------------------------------------------------------------
#[cfg(test)]
mod canonical_landing_rate_fpm_tests {
    use super::*;
    use serde_json::json;

    fn ms713_live_stats() -> FlightStats {
        // Echte Werte aus der VPS-DB fuer MS713 touchdown id 134:
        //   vs_at_edge_fpm: -194.057
        //   vs_smoothed_500ms_fpm: -204.7
        //   landing_rate_fpm: -204 (streamer-tick snapshot)
        //   landing_peak_vs_fpm: -204 (touchdown-window peak)
        let mut stats = FlightStats::default();
        stats.landing_rate_fpm = Some(-204.69882);
        stats.landing_peak_vs_fpm = Some(-204.69882);
        stats.landing_analysis = Some(json!({
            "vs_at_edge_fpm": -194.057,
            "vs_smoothed_500ms_fpm": -204.7,
        }));
        stats
    }

    #[test]
    fn ms713_canonical_returns_edge_value_not_streamer_tick() {
        // Der Bug-Anchor: vor v0.7.21 lieferten manche Stellen -204
        // (Streamer-Tick), andere -194 (Edge). canonical MUSS jetzt
        // ueberall -194 sein.
        let stats = ms713_live_stats();
        let v = stats.canonical_landing_rate_fpm().expect("some");
        assert!(
            (v - (-194.057)).abs() < 0.001,
            "expected Engineering-Edge -194.057, got {v}",
        );
    }

    #[test]
    fn ms713_round_to_int_matches_pilot_client_display() {
        // Das ist der Wert der bei phpVMS als "Landungsrate" landen
        // soll, und derselbe den der Pilot-Client Tab "Landung" zeigt.
        let stats = ms713_live_stats();
        let rounded = stats
            .canonical_landing_rate_fpm()
            .map(|v| v.round() as i32);
        assert_eq!(rounded, Some(-194));
    }

    #[test]
    fn shim_score_basis_vs_fpm_delegates_to_canonical() {
        // Der alte freistehende `score_basis_vs_fpm()` ist ab v0.7.21
        // nur noch ein Shim auf die Methode. Beide muessen IMMER
        // dasselbe liefern.
        let stats = ms713_live_stats();
        assert_eq!(
            score_basis_vs_fpm(&stats),
            stats.canonical_landing_rate_fpm()
        );
    }

    #[test]
    fn no_edge_falls_back_to_peak_then_rate() {
        // Ohne 50-Hz-Buffer-Dump (= GSG219-Fall): Cascade soll auf
        // landing_peak_vs_fpm fallen.
        let mut stats = FlightStats::default();
        stats.landing_rate_fpm = Some(-300.0);
        stats.landing_peak_vs_fpm = Some(-450.0);
        stats.landing_analysis = None;
        assert_eq!(stats.canonical_landing_rate_fpm(), Some(-450.0));

        // Ohne Peak: auf landing_rate_fpm.
        let mut stats = FlightStats::default();
        stats.landing_rate_fpm = Some(-300.0);
        stats.landing_peak_vs_fpm = None;
        stats.landing_analysis = None;
        assert_eq!(stats.canonical_landing_rate_fpm(), Some(-300.0));
    }

    #[test]
    fn positive_edge_value_is_ignored_falls_to_cascade() {
        // Defensiver Guard: edge < 0.0 ist Pflicht (negative = Sinken).
        // Ein positiver Edge waere ein Sim-Bug → wir nehmen den nicht.
        let mut stats = FlightStats::default();
        stats.landing_rate_fpm = Some(-200.0);
        stats.landing_peak_vs_fpm = Some(-180.0);
        stats.landing_analysis = Some(json!({
            "vs_at_edge_fpm": 42.0, // bogus positive
        }));
        // Edge wird verworfen → Peak gewinnt.
        assert_eq!(stats.canonical_landing_rate_fpm(), Some(-180.0));
    }

    #[test]
    fn none_when_nothing_set() {
        let stats = FlightStats::default();
        assert_eq!(stats.canonical_landing_rate_fpm(), None);
    }

    #[test]
    fn b005_anchor_smooth_with_high_g_spike() {
        // v0.7.17 B-009-Anchor: -116 fpm aber 2.30 G — vor dem Fix
        // wurde der spurious Edge nicht erkannt. canonical MUSS hier
        // den Edge liefern, NICHT den Peak.
        let mut stats = FlightStats::default();
        stats.landing_rate_fpm = Some(-116.0);
        stats.landing_peak_vs_fpm = Some(-200.0); // sim strut spike
        stats.landing_analysis = Some(json!({
            "vs_at_edge_fpm": -116.0,
        }));
        assert_eq!(stats.canonical_landing_rate_fpm(), Some(-116.0));
    }
}

#[cfg(test)]
mod resolve_bid_cleanup_args_tests {
    use super::*;

    #[test]
    fn both_empty_returns_none() {
        // Caller hat weder bid noch flight_id → consume_bid_best_effort
        // skipt komplett (kein delete_bid, kein Queue-Eintrag).
        assert_eq!(resolve_bid_cleanup_args(0, None), None);
        assert_eq!(resolve_bid_cleanup_args(-5, Some("")), None);
        assert_eq!(resolve_bid_cleanup_args(0, Some("")), None);
    }

    #[test]
    fn only_bid_id_passes_bid_id() {
        let r = resolve_bid_cleanup_args(42, None);
        assert_eq!(r, Some((Some(42), None)));
    }

    #[test]
    fn only_flight_id_passes_flight_id() {
        // QS-R3 Finding 1 anchor: bid_id<=0 darf NICHT mehr early-out
        // sein wenn flight_id present ist.
        let r = resolve_bid_cleanup_args(0, Some("flightid_42"));
        assert_eq!(r, Some((None, Some("flightid_42".to_string()))));
    }

    #[test]
    fn negative_bid_id_with_flight_id_passes_flight_only() {
        let r = resolve_bid_cleanup_args(-1, Some("flightid_42"));
        assert_eq!(r, Some((None, Some("flightid_42".to_string()))));
    }

    #[test]
    fn both_ids_pass_both() {
        // delete_bid baut intern die Cascade (bid_id zuerst, bei 400/
        // 404/422 → flight_id-Fallback). Hier nur die Path-Selection
        // pruefen.
        let r = resolve_bid_cleanup_args(7, Some("flightid_7"));
        assert_eq!(r, Some((Some(7), Some("flightid_7".to_string()))));
    }

    #[test]
    fn empty_string_flight_id_treated_as_none() {
        // Pre-v0.7.7-Resume-Files persistieren `flight_id: String`
        // ohne Inhalt. Der wird als None behandelt.
        let r = resolve_bid_cleanup_args(0, Some(""));
        assert_eq!(r, None);
        let r2 = resolve_bid_cleanup_args(42, Some(""));
        assert_eq!(r2, Some((Some(42), None)));
    }
}

